fn filesystemPathError(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.InvalidFilesystemPath, error.InvalidFilesystemRoot => json.errorResponse(ctx.allocator, 400, "bad_request", "Filesystem path must be relative to the configured filesystem root"),
        else => serverError(ctx),
    };
}

fn markdownExportFilePath(allocator: std.mem.Allocator, root_path: []const u8, filename: []const u8) ![]u8 {
    _ = try api_filesystem.validateRequestPath(filename);
    if (std.mem.indexOfAny(u8, filename, "/\\") != null) return error.InvalidFilesystemPath;
    return std.fs.path.join(allocator, &.{ root_path, filename });
}

pub fn handleRequest(ctx: *Context, method: []const u8, target: []const u8, body: []const u8, raw_request: []const u8) HttpResponse {
    var target_view = api_dispatch.Target.parse(ctx.allocator, target) catch return serverError(ctx);
    defer target_view.deinit();

    const is_health = target_view.isHealth(method);
    if (!is_health and !authorized(ctx, raw_request)) {
        return json.errorResponse(ctx.allocator, 401, "unauthorized", "Missing or invalid Authorization header");
    }
    if (is_health) return api_health.health(ctx);

    const principal_snapshot = applyRequestPrincipal(ctx, raw_request) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid actor scope or capability headers");
    defer restoreRequestPrincipal(ctx, principal_snapshot);

    if (!target_view.hasV1Prefix()) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
    const catalog_operation = switch (api_catalog.decision(ctx.allocator, method, target_view.path)) {
        .operation => |operation| operation,
        .reject => |response| return response,
    };
    if (dispatchCatalogOperation(ctx, .{
        .operation = catalog_operation,
        .method = method,
        .query = target_view.query,
        .body = body,
        .seg2 = target_view.seg2,
        .seg3 = target_view.seg3,
        .seg4 = target_view.seg4,
    })) |response| return response;

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn dispatchCatalogOperation(ctx: *Context, input: api_catalog.DispatchInput) ?HttpResponse {
    if (dispatchRegistryOperation(ctx, input)) |response| return response;
    if (dispatchConnectorOperation(ctx, input)) |response| return response;
    if (dispatchGovernanceOperation(ctx, input)) |response| return response;
    if (dispatchKnowledgeOperation(ctx, input)) |response| return response;
    if (dispatchGraphSearchOperation(ctx, input)) |response| return response;
    if (dispatchLifecycleOperation(ctx, input)) |response| return response;
    if (dispatchAgentMemoryOperation(ctx, input)) |response| return response;
    if (dispatchAgentSessionOperation(ctx, input)) |response| return response;
    if (dispatchNullClawOperation(ctx, input)) |response| return response;
    if (dispatchFeedMemoryOperation(ctx, input)) |response| return response;
    return null;
}

fn dispatchRegistryOperation(ctx: *Context, input: api_catalog.DispatchInput) ?HttpResponse {
    return switch (input.operation) {
        .listEngines => api_registry.engineRegistry(ctx),
        .openApiDocument, .openApiDocumentAlias => api_registry.openApiDocument(ctx),
        .capabilities => api_registry.capabilities(ctx),
        .listProviders => api_registry.providerRegistry(ctx),
        .listConnectors => api_connectors.list(ctx),
        .listArtifactTypes => api_registry.artifactTypes(ctx),
        .sdkManifest => api_registry.sdkManifest(ctx),
        else => null,
    };
}

fn dispatchConnectorOperation(ctx: *Context, input: api_catalog.DispatchInput) ?HttpResponse {
    return switch (input.operation) {
        .connectorGetCursor => if (input.seg2) |connector| connectorCursorGet(ctx, connector, input.query) else null,
        .connectorUpsertCursor => if (input.seg2) |connector| connectorCursorUpsert(ctx, connector, input.body) else null,
        .connectorIngest => if (input.seg2) |connector| connectorIngest(ctx, connector, input.body, input.query) else null,
        .qmdExportAgentSessions => blk: {
            if (!build_options.enable_engine_qmd) break :blk engineNotCompiled(ctx, "qmd");
            break :blk qmdSessionExport(ctx, input.body, input.query);
        },
        .qmdPruneAgentSessionExports => blk: {
            if (!build_options.enable_engine_qmd) break :blk engineNotCompiled(ctx, "qmd");
            break :blk qmdSessionPrune(ctx, input.body);
        },
        .importMarkdown => blk: {
            if (!build_options.enable_engine_markdown) break :blk engineNotCompiled(ctx, "markdown");
            break :blk markdownImport(ctx, input.body, input.query);
        },
        .importMarkdownDirectory => blk: {
            if (!build_options.enable_engine_markdown) break :blk engineNotCompiled(ctx, "markdown");
            break :blk markdownImportDirectory(ctx, input.body, input.query);
        },
        .exportMarkdown => blk: {
            if (!build_options.enable_engine_markdown) break :blk engineNotCompiled(ctx, "markdown");
            break :blk markdownExport(ctx, input.body);
        },
        .exportMarkdownDirectory => blk: {
            if (!build_options.enable_engine_markdown) break :blk engineNotCompiled(ctx, "markdown");
            break :blk markdownExportDirectory(ctx, input.body);
        },
        .bootstrapPromptsList => bootstrapPromptsList(ctx, input.query),
        .bootstrapPromptsFingerprint => bootstrapPromptsFingerprint(ctx, input.query),
        .bootstrapPromptsImportDirectory => bootstrapPromptsImportDirectory(ctx, input.body, input.query),
        .bootstrapPromptsReset => bootstrapPromptsReset(ctx, input.body, input.query),
        .bootstrapPromptExists => if (input.seg3) |filename| bootstrapPromptExists(ctx, filename, input.query) else null,
        .bootstrapPromptGet => if (input.seg3) |filename| bootstrapPromptGet(ctx, filename, input.query) else null,
        .bootstrapPromptPut, .bootstrapPromptPost => if (input.seg3) |filename| bootstrapPromptStore(ctx, filename, input.body, input.query) else null,
        .bootstrapPromptDelete => if (input.seg3) |filename| bootstrapPromptDelete(ctx, filename, input.query) else null,
        else => null,
    };
}

