fn dispatchNullClawOperation(ctx: *Context, input: api_catalog.DispatchInput) ?HttpResponse {
    return switch (input.operation) {
        .nullClawAgentApiHealth,
        .nullClawAgentApiListMemories,
        .nullClawAgentApiGetMemory,
        .nullClawAgentApiPutMemory,
        .nullClawAgentApiPostMemory,
        .nullClawAgentApiDeleteMemory,
        .nullClawAgentApiSearchMemories,
        .nullClawAgentApiCountMemories,
        .nullClawAgentApiListSessions,
        .nullClawAgentApiDeleteSession,
        .nullClawAgentApiTerminateSession,
        .nullClawAgentApiCompactSession,
        .nullClawAgentApiLoadSessionMessages,
        .nullClawAgentApiSaveSessionMessage,
        .nullClawAgentApiClearSessionMessages,
        .nullClawAgentApiLoadSessionUsage,
        .nullClawAgentApiSaveSessionUsage,
        .nullClawAgentApiDeleteSessionUsage,
        .nullClawAgentApiClearAutoSaved,
        .nullClawAgentApiListHistory,
        .nullClawAgentApiShowHistory,
        .nullClawAgentApiFeed,
        .nullClawAgentApiFeedEvents,
        .nullClawAgentApiFeedStatus,
        .nullClawAgentApiMemoryStats,
        .nullClawAgentApiMemoryReindex,
        .nullClawAgentApiMemoryDrainOutbox,
        .nullClawAgentApiFeedCompact,
        .nullClawAgentApiExportCheckpoint,
        .nullClawAgentApiRestoreCheckpoint,
        .nullClawAgentApiApplyFeedEvent,
        .nullClawApiMemoryParity,
        => blk: {
            if (!build_options.enable_nullclaw_adapter) break :blk json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
            break :blk handleNullClawAgentAdapter(ctx, input.method, input.query, input.seg2, input.seg3, input.seg4, input.body);
        },
        .nullClawApiListMemories,
        .nullClawApiGetMemory,
        .nullClawApiPutMemory,
        .nullClawApiPostMemory,
        .nullClawApiDeleteMemory,
        .nullClawApiSearchMemories,
        .nullClawApiCountMemories,
        => blk: {
            if (!build_options.enable_nullclaw_adapter) break :blk json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
            break :blk handleNullClawMemoryAlias(ctx, input.method, input.query, input.seg2, input.seg3, input.body);
        },
        .nullClawApiClearSessionMessages => blk: {
            if (!build_options.enable_nullclaw_adapter) break :blk json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
            if (input.seg2) |id| break :blk nullClawAgentClearMessages(ctx, id, input.query);
            break :blk null;
        },
        .nullClawApiListSessions,
        .nullClawApiGetSessionHistory,
        .nullClawApiTerminateSession,
        .nullClawApiCompactSession,
        .nullClawApiLoadSessionMessages,
        .nullClawApiSaveSessionMessage,
        .nullClawApiLoadSessionUsage,
        .nullClawApiSaveSessionUsage,
        .nullClawApiDeleteSessionUsage,
        .nullClawApiClearAutoSaved,
        .nullClawApiListHistory,
        .nullClawApiShowHistory,
        => blk: {
            if (!build_options.enable_nullclaw_adapter) break :blk json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
            break :blk handleAgentSessions(ctx, input.method, input.query, input.seg2, input.seg3, input.body);
        },
        else => null,
    };
}

fn dispatchFeedMemoryOperation(ctx: *Context, input: api_catalog.DispatchInput) ?HttpResponse {
    return switch (input.operation) {
        .listNativeFeed,
        .appendNativeFeed,
        .listNativeFeedEvents,
        .appendNativeFeedEvent,
        .nativeFeedStatus,
        .compactNativeFeed,
        .exportNativeFeedCheckpoint,
        .restoreNativeFeedCheckpoint,
        .applyNativeFeedEvent,
        => handleFeedSurface(ctx, input.method, input.query, input.seg2, input.seg3, input.body),
        .memoryToolsList => api_memory_providers.toolsList(ctx),
        .memoryProvidersList => api_memory_providers.providersList(ctx),
        .memoryProviderGet => if (input.seg3) |name| api_memory_providers.providerGet(ctx, name) else null,
        .memoryProviderTools => if (input.seg3) |name| api_memory_providers.providerTools(ctx, name) else null,
        .memoryProviderConfigSchema => if (input.seg3) |name| api_memory_providers.providerConfigSchema(ctx, name) else null,
        .memoryToolCall => memoryToolCall(ctx, input.body, input.query),
        .memoryContextBlock => api_memory_providers.contextBlock(ctx, input.body),
        .memoryPrefetch => memoryPrefetch(ctx, input.body, input.query),
        .memoryCurated => memoryCurated(ctx, input.body, input.query),
        .memorySessionSearch => memorySessionSearch(ctx, input.body, input.query),
        .memoryRecallSignals => memoryRecallSignals(ctx, input.query),
        .nullClawMemoryParity,
        .listFeed,
        .appendFeed,
        .listFeedEvents,
        .appendFeedEvent,
        .feedStatus,
        .memoryStats,
        .memoryCount,
        .memoryList,
        .memorySearch,
        .memoryGet,
        .memoryStore,
        .putMemoryStoreByKey,
        .postMemoryStoreByKey,
        .memoryUpdate,
        .putMemoryUpdateByKey,
        .postMemoryUpdateByKey,
        .memoryDelete,
        .deleteMemoryByKey,
        .postMemoryDeleteByKey,
        .memoryForget,
        .forgetMemoryByKey,
        .postMemoryForgetByKey,
        .memoryExportJsonl,
        .memoryHygiene,
        .memoryHygieneReport,
        .memoryReindex,
        .memoryDrainOutbox,
        .compactFeed,
        .exportFeedCheckpoint,
        .restoreFeedCheckpoint,
        .applyFeedEvent,
        => handleMemorySurface(ctx, input.method, input.query, input.seg2, input.seg3, input.seg4, input.body),
        else => null,
    };
}

fn handleAgentSessions(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (seg2 == null and is_get) {
        if (!api_session_access.allReadAllowed(ctx)) return forbidden(ctx);
        const limit = parseLimit(json.queryParam(query, "limit"), 50);
        const offset = parseLimit(json.queryParam(query, "offset"), 0);
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
        const result = ctx.store.listSessionsRoutedWithAuth(ctx.allocator, limit, offset, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return writeHistoryList(ctx, result, limit, offset);
    }

    if (eql(seg2, "auto-saved") and seg3 == null and is_delete) {
        const session_id = json.queryParamDecoded(ctx.allocator, query, "session_id") catch return serverError(ctx);
        if (session_id) |sid| {
            if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
        } else if (!api_session_access.allWriteAllowed(ctx)) {
            return forbidden(ctx);
        }
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
        ctx.store.clearAutoSavedRoutedWithAuth(session_id, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        clearAgentMemoryAutosaves(ctx, session_id, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return ok(ctx, "{\"ok\":true}");
    }

    if (seg2 != null and seg3 == null and is_get) {
        if (!api_session_access.readAllowed(ctx, seg2.?)) return forbidden(ctx);
        const limit = parseLimit(json.queryParam(query, "limit"), 100);
        const offset = parseLimit(json.queryParam(query, "offset"), 0);
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
        const result = ctx.store.historyRoutedWithAuth(ctx.allocator, seg2.?, limit, offset, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return writeHistoryShow(ctx, seg2.?, result, limit, offset);
    }

    if (seg2 != null and seg3 == null and is_delete) {
        return agentSessionTerminate(ctx, seg2.?, query, body);
    }

    if (seg2 != null and eql(seg3, "terminate") and is_post) {
        return agentSessionTerminate(ctx, seg2.?, query, body);
    }

    if (seg2 != null and eql(seg3, "compact") and is_post) {
        return lifecycleCompactSession(ctx, seg2.?, body, query);
    }

    if (seg2 != null and eql(seg3, "messages")) {
        if ((is_post or is_delete) and !api_session_access.writeAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_get and !api_session_access.readAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_post) return saveMessage(ctx, seg2.?, body, query);
        if (is_get) return loadMessages(ctx, seg2.?, query);
        if (is_delete) {
            const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
            ctx.store.clearMessagesRoutedWithAuth(seg2.?, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            return ok(ctx, "{\"ok\":true}");
        }
    }

    if (seg2 != null and eql(seg3, "usage")) {
        if ((is_put or is_delete) and !api_session_access.writeAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_get and !api_session_access.readAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_put) return saveUsage(ctx, seg2.?, body, query);
        if (is_get) return loadUsage(ctx, seg2.?, query);
        if (is_delete) {
            const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
            _ = ctx.store.deleteUsageRoutedWithAuth(seg2.?, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            return ok(ctx, "{\"ok\":true}");
        }
    }

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn clearAgentMemoryAutosaves(ctx: *Context, session_id: ?[]const u8, storage_target: store_mod.AgentMemoryStorageRoute) !void {
    const auth = api_agent_memory_store.contextAuth(ctx);
    const entries = if (session_id) |sid|
        try api_agent_memory_store.listByInput(ctx, .{
            .route = storage_target,
            .session_id = sid,
            .auth = auth,
        })
    else
        try api_agent_memory_store.listByInput(ctx, .{
            .route = storage_target,
            .auth = auth,
            .access = .any_visible,
        });
    defer {
        for (entries) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
        ctx.allocator.free(entries);
    }

    const admin = domain.hasActorScope(ctx.actor_scopes_json, "admin");
    for (entries) |entry| {
        if (!domain.isAutosaveMemoryKey(entry.key)) continue;
        if (!admin and !std.mem.eql(u8, entry.actor_id, ctx.actor_id)) continue;
        _ = try api_agent_memory_store.delete(ctx, .{
            .key = entry.key,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .route = storage_target,
        });
    }
}

fn agentSessionTerminate(ctx: *Context, session_id: []const u8, query: []const u8, body: []const u8) HttpResponse {
    if (!api_session_access.writeAllowed(ctx, session_id)) return forbidden(ctx);
    const storage_target = if (std.mem.trim(u8, body, " \t\r\n").len == 0)
        storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err)
    else blk: {
        var parsed = parseBody(ctx, body) catch return badJson(ctx);
        defer parsed.deinit();
        break :blk storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, query) catch |err| return storageRouteError(ctx, err);
    };
    const actor_filter = actorFilter(ctx);

    const history = ctx.store.historyRoutedWithAuth(ctx.allocator, session_id, 500, 0, actor_filter, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage = ctx.store.loadUsageRoutedWithAuth(session_id, actor_filter, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const memory_entries = api_agent_memory_store.listByInput(ctx, .{
        .route = storage_target,
        .session_id = session_id,
    }) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    if (history.total == 0 and usage == null and memory_entries.len == 0) {
        return json.errorResponse(ctx.allocator, 404, "session_not_found", "No session with that key");
    }

    var memory_deleted: usize = 0;
    for (memory_entries) |entry| {
        if (!agentMemoryEntryDeletable(ctx, entry)) return forbidden(ctx);
        if (api_agent_memory_store.delete(ctx, .{
            .key = entry.key,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .route = storage_target,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }) {
            memory_deleted += 1;
        }
    }

    ctx.store.clearMessagesRoutedWithAuth(session_id, actor_filter, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    ctx.store.clearAutoSavedRoutedWithAuth(session_id, actor_filter, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage_deleted_now = ctx.store.deleteUsageRoutedWithAuth(session_id, actor_filter, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage_deleted = usage != null or usage_deleted_now;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"session_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"session_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"terminated\":true") catch return serverError(ctx);
    out.print(ctx.allocator, ",\"messages_deleted\":{d},\"memory_entries_deleted\":{d},\"usage_deleted\":{s},\"storage_route\":", .{
        history.total,
        memory_deleted,
        if (usage_deleted) "true" else "false",
    }) catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, storage_target) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn handleNullClawAgentAdapter(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, seg4: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (is_get and eql(seg2, "health") and seg3 == null) {
        return ok(ctx, "{\"ok\":true,\"service\":\"nullpantry\",\"adapter\":\"nullclaw-api-memory\"}");
    }

    if (eql(seg2, "memories")) {
        if (is_post and eql(seg3, "search") and seg4 == null) return nullClawAgentMemorySearch(ctx, body, query);
        if ((is_put or is_post) and seg3 != null and seg4 == null) return nullClawAgentMemoryStore(ctx, seg3.?, body, query);
        if (is_get and seg3 == null) return nullClawAgentMemoryList(ctx, query);
        if (is_get and eql(seg3, "count") and seg4 == null) return agentMemoryCount(ctx, query);
        if (is_get and seg3 != null and seg4 == null) return nullClawAgentMemoryGet(ctx, seg3.?, query);
        if (is_delete and seg3 != null and seg4 == null) return nullClawAgentMemoryDelete(ctx, seg3.?, query);
    }

    if (eql(seg2, "memory")) {
        if ((eql(seg3, "feed") or eql(seg3, "events")) and is_get and seg4 == null) return nullClawMemoryFeed(ctx, query);
        if (eql(seg3, "parity") and is_get and seg4 == null) return api_registry.nullClawMemoryParity(ctx);
        if (eql(seg3, "status") and is_get and seg4 == null) return nullClawMemoryFeedStatus(ctx, query);
        if (eql(seg3, "stats") and is_get and seg4 == null) return memoryStats(ctx);
        if (eql(seg3, "reindex") and is_post and seg4 == null) return memoryReindex(ctx, body);
        if (eql(seg3, "drain-outbox") and is_post and seg4 == null) return memoryDrainOutbox(ctx, body);
        if (eql(seg3, "compact") and is_post and seg4 == null) return nullClawMemoryFeedCompact(ctx, body, query);
        if (eql(seg3, "checkpoint") and is_get and seg4 == null) return nullClawMemoryFeedCheckpoint(ctx, query);
        if (eql(seg3, "checkpoint") and is_post and seg4 == null) return nullClawMemoryFeedCheckpointRestore(ctx, body, query);
        if (eql(seg3, "apply") and is_post and seg4 == null) return nullClawMemoryFeedApply(ctx, body, query);
    }

    if (eql(seg2, "sessions")) {
        if (eql(seg3, "auto-saved") and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
        if (is_delete and seg3 != null and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
        if (is_delete and seg3 != null and eql(seg4, "messages")) return nullClawAgentClearMessages(ctx, seg3.?, query);
        if (seg3 != null and seg4 != null) return handleAgentSessions(ctx, method, query, seg3, seg4, body);
        if (seg3 == null and is_get) return handleAgentSessions(ctx, method, query, null, null, body);
    }

    if (eql(seg2, "history")) {
        if (is_get and seg3 == null) return handleAgentSessions(ctx, method, query, null, null, body);
        if (is_get and seg3 != null and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
    }

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn handleNullClawMemoryAlias(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (is_post and eql(seg2, "search") and seg3 == null) return nullClawAgentMemorySearch(ctx, body, query);
    if (is_get and eql(seg2, "count") and seg3 == null) return agentMemoryCount(ctx, query);
    if ((is_put or is_post) and seg2 != null and seg3 == null) return nullClawAgentMemoryStore(ctx, seg2.?, body, query);
    if (is_get and seg2 == null) return nullClawAgentMemoryList(ctx, query);
    if (is_get and seg2 != null and seg3 == null) return nullClawAgentMemoryGet(ctx, seg2.?, query);
    if (is_delete and seg2 != null and seg3 == null) return nullClawAgentMemoryDelete(ctx, seg2.?, query);

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn handleFeedSurface(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");

    if (seg2 == null) {
        if (is_get) return memoryFeed(ctx, query);
        if (is_post) return appendMemoryFeed(ctx, body, query);
    }
    if ((eql(seg2, "events") or eql(seg2, "feed")) and seg3 == null) {
        if (is_get) return memoryFeed(ctx, query);
        if (is_post) return appendMemoryFeed(ctx, body, query);
    }
    if (eql(seg2, "status") and is_get and seg3 == null) return memoryFeedStatus(ctx, query);
    if (eql(seg2, "compact") and is_post and seg3 == null) return memoryFeedCompact(ctx, body, query);
    if (eql(seg2, "checkpoint") and is_get and seg3 == null) return memoryFeedCheckpoint(ctx, query);
    if (eql(seg2, "checkpoint") and is_post and seg3 == null) return memoryFeedCheckpointRestore(ctx, body, query);
    if (eql(seg2, "apply") and is_post and seg3 == null) return applyMemoryEvent(ctx, body, query);

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn handleMemorySurface(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, seg4: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if ((eql(seg2, "feed") or eql(seg2, "events")) and is_get and seg3 == null) return memoryFeed(ctx, query);
    if ((eql(seg2, "feed") or eql(seg2, "events")) and is_post and seg3 == null) return appendMemoryFeed(ctx, body, query);
    if (eql(seg2, "parity") and is_get and seg3 == null) return api_registry.nullClawMemoryParity(ctx);
    if (eql(seg2, "status") and is_get and seg3 == null) return memoryFeedStatus(ctx, query);
    if (eql(seg2, "stats") and is_get and seg3 == null) return memoryStats(ctx);
    if (eql(seg2, "recall-signals") and is_get and seg3 == null) return memoryRecallSignals(ctx, query);
    if (eql(seg2, "reindex") and is_post and seg3 == null) return memoryReindex(ctx, body);
    if (eql(seg2, "drain-outbox") and is_post and seg3 == null) return memoryDrainOutbox(ctx, body);
    if (eql(seg2, "compact") and is_post and seg3 == null) return memoryFeedCompact(ctx, body, query);
    if (eql(seg2, "checkpoint") and is_get and seg3 == null) return memoryFeedCheckpoint(ctx, query);
    if (eql(seg2, "checkpoint") and is_post and seg3 == null) return memoryFeedCheckpointRestore(ctx, body, query);
    if (eql(seg2, "apply") and is_post and seg3 == null) return applyMemoryEvent(ctx, body, query);

    if (eql(seg2, "count") and is_get and seg3 == null) return agentMemoryCount(ctx, query);
    if (eql(seg2, "list") and is_get and seg3 == null) return nullClawAgentMemoryList(ctx, query);
    if (eql(seg2, "search") and is_post and seg3 == null) return nullClawAgentMemorySearch(ctx, body, query);
    if (eql(seg2, "get") and is_get and seg3 != null and seg4 == null) return nullClawAgentMemoryGet(ctx, seg3.?, query);
    if (eql(seg2, "store") and (is_post or is_put)) {
        if (seg3 != null and seg4 == null) return memoryCommandStoreKey(ctx, seg3.?, body, query);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        return memoryCommandStoreBody(ctx, body, query);
    }
    if (eql(seg2, "update") and (is_post or is_put)) {
        if (seg3 != null and seg4 == null) return memoryCommandUpdateKey(ctx, seg3.?, body, query);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        return memoryCommandUpdateBody(ctx, body, query);
    }
    if ((eql(seg2, "delete") or eql(seg2, "forget")) and (is_delete or is_post)) {
        if (seg3 != null and seg4 == null) return memoryCommandDeleteKey(ctx, seg3.?, query);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        if (is_post) return memoryCommandDeleteBody(ctx, body, query);
    }
    if (eql(seg2, "export-jsonl") and is_post and seg3 == null) return memoryCommandExportJsonl(ctx, body, query);
    if (eql(seg2, "hygiene") and is_post and seg3 == null) return lifecycleHygiene(ctx, body, query);
    if (eql(seg2, "hygiene-report") and is_post and seg3 == null) return lifecycleHygieneReport(ctx, body, query);

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn nullClawAgentClearMessages(ctx: *Context, session_id: []const u8, query: []const u8) HttpResponse {
    if (!api_session_access.writeAllowed(ctx, session_id)) return forbidden(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    ctx.store.clearMessagesRoutedWithAuth(session_id, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    _ = ctx.store.deleteUsageRoutedWithAuth(session_id, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn bootstrapPromptsList(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"prefix\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, bootstrap_prompts.key_prefix) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"prompts\":[") catch return serverError(ctx);
    for (bootstrap_prompts.docs, 0..) |doc, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        const entry = loadAgentMemoryForRequest(ctx, doc.memory_key, null, requested_scope, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.filename) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.memory_key) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"exists\":") catch return serverError(ctx);
        out.appendSlice(ctx.allocator, if (entry != null) "true" else "false") catch return serverError(ctx);
        if (entry) |value| {
            out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
            out.print(ctx.allocator, "{d}", .{value.content.len}) catch return serverError(ctx);
            if (value.store.len > 0) {
                out.appendSlice(ctx.allocator, ",\"store\":") catch return serverError(ctx);
                json.appendString(&out, ctx.allocator, value.store) catch return serverError(ctx);
            }
        }
        out.append(ctx.allocator, '}') catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptsFingerprint(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    var entries = ctx.allocator.alloc(?[]const u8, bootstrap_prompts.docs.len) catch return serverError(ctx);
    @memset(entries, null);
    for (bootstrap_prompts.docs, 0..) |doc, i| {
        const entry = loadAgentMemoryForRequest(ctx, doc.memory_key, null, requested_scope, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (entry) |value| {
            entries[i] = value.content;
        }
    }
    const fp = bootstrap_prompts.fingerprint(entries);
    const body = std.fmt.allocPrint(ctx.allocator, "{{\"fingerprint\":{d},\"fingerprint_hex\":\"{x}\",\"present\":{d},\"total\":{d}}}", .{ fp.value, fp.value, fp.present, fp.total }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn bootstrapPromptGet(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    const max_bytes = if (json.queryParam(query, "max_bytes")) |value| parseLimit(value, 0) else 0;
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt not found");
    return bootstrapPromptResponse(ctx, filename, key, entry.?, max_bytes);
}

fn bootstrapPromptExists(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, filename) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"exists\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (entry != null) "true" else "false") catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptStore(ctx: *Context, filename: []const u8, body: []const u8, route_query: []const u8) HttpResponse {
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const stored = agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx, key, parsed.value.object, "core", route_query);
    if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;
    const requested_scope = json.nullableStringField(parsed.value.object, "scope");
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, route_query) catch |err| return storageRouteError(ctx, err);
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (entry == null) return ok(ctx, "{\"ok\":true}");
    return bootstrapPromptResponse(ctx, filename, key, entry.?, 0);
}

fn bootstrapPromptDelete(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    return agentMemoryDelete(ctx, key, query);
}

fn bootstrapPromptsReset(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const scope = json.nullableStringField(obj, "scope");
    const permissions_json = bootstrapPromptArrayJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = "Reset bootstrap prompt defaults", .scope = requested_scope, .permissions_json = permissions_json, .created_by = "agent", .actor_id = ctx.actor_id })) return forbidden(ctx);
    } else if (!domain.permissionsAreOpen(permissions_json) and !domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) {
        return forbidden(ctx);
    }

    const dry_run = (json.boolField(obj, "dry_run") orelse false) or queryBool(route_query, "dry_run", false);
    const include_bootstrap = json.boolField(obj, "include_bootstrap") orelse false;
    const clear_memory = (json.boolField(obj, "clear_memory_md") orelse false) or
        (json.boolField(obj, "clear_memory_markdown") orelse false) or
        (json.boolField(obj, "clear_memory") orelse false);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx);
    defer ctx.allocator.free(owner_actor_id);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"reset\":{\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"scope\":") catch return serverError(ctx);
    json.appendNullableString(&out, ctx.allocator, scope) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"owner_actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, owner_actor_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"storage\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"prompts\":[") catch return serverError(ctx);

    var rewritten: usize = 0;
    var first = true;
    for (bootstrap_prompts.reset_doc_filenames) |filename| {
        const content = bootstrap_prompts.defaultContent(filename) orelse continue;
        const key = bootstrap_prompts.memoryKey(filename) orelse continue;
        if (!dry_run) {
            _ = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                .key = key,
                .content = content,
                .category = "core",
                .scope = scope,
                .permissions_json = permissions_json,
                .actor_id = owner_actor_id,
                .writer_actor_id = ctx.actor_id,
                .actor_scopes_json = ctx.actor_scopes_json,
                .actor_capabilities_json = ctx.actor_capabilities_json,
            }, storage_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        }
        appendBootstrapPromptResetItem(ctx, &out, &first, filename, key, content.len, "rewritten") catch return serverError(ctx);
        rewritten += 1;
    }

    if (include_bootstrap) {
        const filename = "BOOTSTRAP.md";
        const content = bootstrap_prompts.defaultContent(filename) orelse "";
        const key = bootstrap_prompts.memoryKey(filename) orelse return serverError(ctx);
        if (!dry_run) {
            _ = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                .key = key,
                .content = content,
                .category = "core",
                .scope = scope,
                .permissions_json = permissions_json,
                .actor_id = owner_actor_id,
                .writer_actor_id = ctx.actor_id,
                .actor_scopes_json = ctx.actor_scopes_json,
                .actor_capabilities_json = ctx.actor_capabilities_json,
            }, storage_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        }
        appendBootstrapPromptResetItem(ctx, &out, &first, filename, key, content.len, "rewritten") catch return serverError(ctx);
        rewritten += 1;
    }

    out.appendSlice(ctx.allocator, "],\"removed\":[") catch return serverError(ctx);
    var removed: usize = 0;
    var first_removed = true;
    if (clear_memory) {
        removed += bootstrapPromptResetDelete(ctx, &out, &first_removed, "MEMORY.md", "__bootstrap.prompt.MEMORY.md", scope, owner_actor_id, storage_route, dry_run) catch return serverError(ctx);
        removed += bootstrapPromptResetDelete(ctx, &out, &first_removed, "memory.md", "__bootstrap.prompt.memory.md", scope, owner_actor_id, storage_route, dry_run) catch return serverError(ctx);
    }

    out.print(ctx.allocator, "],\"rewritten_count\":{d},\"removed_count\":{d},\"include_bootstrap\":{s},\"clear_memory_md\":{s}}}", .{
        rewritten,
        removed,
        if (include_bootstrap) "true" else "false",
        if (clear_memory) "true" else "false",
    }) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendBootstrapPromptResetItem(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, filename: []const u8, key: []const u8, content_bytes: usize, action: []const u8) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try out.appendSlice(ctx.allocator, "{\"filename\":");
    try json.appendString(out, ctx.allocator, filename);
    try out.appendSlice(ctx.allocator, ",\"memory_key\":");
    try json.appendString(out, ctx.allocator, key);
    try out.appendSlice(ctx.allocator, ",\"action\":");
    try json.appendString(out, ctx.allocator, action);
    try out.print(ctx.allocator, ",\"content_bytes\":{d}}}", .{content_bytes});
}

fn bootstrapPromptResetDelete(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, filename: []const u8, key: []const u8, scope: ?[]const u8, owner_actor_id: []const u8, storage_route: store_mod.AgentMemoryStorageRoute, dry_run: bool) !usize {
    const existing = loadAgentMemoryForRequest(ctx, key, null, scope, storage_route) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return error.AgentMemoryStorageUnavailable,
        else => return err,
    };
    if (existing == null) return 0;
    if (!dry_run) {
        _ = try api_agent_memory_store.delete(ctx, .{
            .key = key,
            .owner_actor_id = owner_actor_id,
            .route = storage_route,
            .all_owners = true,
        });
    }
    try appendBootstrapPromptResetItem(ctx, out, first, filename, key, existing.?.content.len, "removed");
    return 1;
}

fn bootstrapPromptsImportDirectory(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const root_path = json.stringField(obj, "path") orelse json.stringField(obj, "directory") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    if (root_path.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    const filesystem_root_path = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, root_path) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_root_path);
    const max_file_bytes = positiveBounded(json.intField(obj, "max_file_bytes"), 10 * 1024 * 1024, 100 * 1024 * 1024);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"imported\":[") catch return serverError(ctx);
    var imported: usize = 0;
    for (bootstrap_prompts.docs) |doc| {
        const file_path = std.fs.path.join(ctx.allocator, &.{ filesystem_root_path, doc.filename }) catch return serverError(ctx);
        const content = std.Io.Dir.cwd().readFileAlloc(compat.io(), file_path, ctx.allocator, .limited(max_file_bytes)) catch |err| switch (err) {
            error.FileNotFound => continue,
            error.StreamTooLong => return json.errorResponse(ctx.allocator, 413, "payload_too_large", "Bootstrap prompt file exceeds max_file_bytes"),
            else => return serverError(ctx),
        };
        const store_body = bootstrapPromptStoreBody(ctx, obj, content) catch |err| return rawJsonRequestError(ctx, err);
        const stored = agentMemoryStoreKey(ctx, doc.memory_key, store_body, route_query);
        if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;
        if (imported > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.filename) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.memory_key) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
        out.print(ctx.allocator, "{d}", .{content.len}) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        imported += 1;
    }
    out.print(ctx.allocator, "],\"imported_count\":{d}}}", .{imported}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptStoreBody(ctx: *Context, obj: std.json.ObjectMap, content: []const u8) ![]const u8 {
    return bootstrap_prompts.buildStoreBody(ctx.allocator, content, .{
        .scope = json.nullableStringField(obj, "scope"),
        .permissions_json = try bootstrapPromptArrayJson(ctx, obj, &.{"permissions"}, "[]"),
        .storage = json.stringField(obj, "storage"),
        .store = json.stringField(obj, "store"),
        .target_store = json.stringField(obj, "target_store"),
        .stores_json = if (obj.get("stores") != null) try bootstrapPromptArrayJson(ctx, obj, &.{"stores"}, "[]") else null,
    });
}

fn bootstrapPromptArrayJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn bootstrapPromptResponse(ctx: *Context, filename: []const u8, key: []const u8, entry: domain.AgentMemory, max_bytes: usize) HttpResponse {
    const excerpt = bootstrap_prompts.excerpt(ctx.allocator, entry.content, max_bytes) catch return serverError(ctx);
    const content = excerpt.content;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"prompt\":{\"filename\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, filename) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"content\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, content) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
    out.print(ctx.allocator, "{d}", .{entry.content.len}) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (excerpt.truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory\":") catch return serverError(ctx);
    if (max_bytes > 0) {
        appendBootstrapPromptMemoryJson(ctx, &out, entry, content) catch return serverError(ctx);
    } else {
        entry.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendBootstrapPromptMemoryJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), entry: domain.AgentMemory, content: []const u8) !void {
    return entry.writeJsonWithOptions(ctx.allocator, out, .{ .content_override = content, .include_status = false });
}

fn nullClawAgentMemoryStore(ctx: *Context, key: []const u8, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryStoreEntry(ctx, key, obj, "core") catch |err| return kgMemoryErrorResponse(ctx, err);
        return nullClawAgentMemoryEntryResponse(ctx, entry);
    }

    const stored = agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx, key, obj, "core", route_query);
    if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;

    const session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
    const requested_scope = json.nullableStringField(obj, "scope");
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var entry = if (non_kg_storage_target) |route| loadAgentMemoryForRequest(ctx, key, session_id, requested_scope, route) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    } else null;
    if (entry == null and api_storage_route.includesKg(storage_target)) {
        entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
    }
    if (entry == null) return ok(ctx, "{\"ok\":true}");
    return nullClawAgentMemoryEntryResponse(ctx, entry.?);
}

fn nullClawAgentMemoryGet(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return nullClawAgentMemoryEntryResponse(ctx, entry.?);
    }
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var entry = if (non_kg_storage_target) |route| loadAgentMemoryForRequest(ctx, key, session_id, requested_scope, route) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    } else null;
    const effective_entry = if (entry == null and session_id == null and requested_scope == null and queryBool(query, "include_sessions", false))
        if (non_kg_storage_target) |route| api_agent_memory_store.getByInput(ctx, .{
            .key = key,
            .route = route,
            .access = .any_visible,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        } else null
    else
        entry;
    if (effective_entry == null and api_storage_route.includesKg(storage_target)) {
        entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
    } else {
        entry = effective_entry;
    }
    if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return nullClawAgentMemoryEntryResponse(ctx, entry.?);
}

fn nullClawAgentMemoryList(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const category = json.queryParamDecoded(ctx.allocator, query, "category") catch return serverError(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const include_global = queryBool(query, "include_global", false);
    const include_internal = queryBool(query, "include_internal", false);
    const include_content = queryBool(query, "include_content", true);
    const limit = parseLimit(json.queryParam(query, "limit"), std.math.maxInt(usize));
    const offset = parseLimit(json.queryParam(query, "offset"), 0);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.targetsKg(storage_target)) {
        const entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    if (!requestedAgentMemoryScopeReadable(ctx, requested_scope)) {
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, &[_]domain.AgentMemory{}, include_internal, include_content, limit, offset);
    }
    const exact_owner = if (requested_scope) |scope| access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx) else null;
    defer if (exact_owner) |owner| ctx.allocator.free(owner);
    if (!route_includes_kg and !include_global and agentMemoryListSupportsDirectWindow(storage_target)) {
        const windowed = loadAgentMemoryListRoutedFilteredWindow(ctx, category, session_id, exact_owner, storage_target, true, include_internal, limit, offset) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, windowed, true, include_content, std.math.maxInt(usize), 0);
    }
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (non_kg_storage_target) |route| {
        const auth = api_agent_memory_store.contextAuth(ctx);
        const primary = if (exact_owner) |owner|
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .session_id = session_id,
                .owner_actor_id = owner,
                .access = .exact_owner,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else if (session_id == null)
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .auth = auth,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .session_id = session_id,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    }
    if (include_global and session_id != null) {
        if (non_kg_storage_target) |route| {
            const auth = api_agent_memory_store.contextAuth(ctx);
            const global = if (exact_owner) |owner| api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .owner_actor_id = owner,
                .access = .exact_owner,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            } else api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
        }
    }
    if (route_includes_kg) {
        const kg_entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, kg_entries) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries.items, include_internal, include_content, limit, offset);
}

fn nullClawAgentMemorySearch(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "";
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const limit = agentMemorySearchLimit(json.intField(obj, "limit"), 10);
    const offset = searchOffset(json.intField(obj, "offset") orelse queryInt(route_query, "offset"));
    const search_limit = agentMemorySearchWindowLimit(limit, offset);
    const include_global = nullClawSessionRecallIncludesGlobal(obj, session_id);
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_content = json.boolField(obj, "include_content") orelse true;
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const graph_entries = graphCommandAgentMemoryEntriesFromObject(ctx, obj, query, search_limit) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand => return badJson(ctx),
        else => return serverError(ctx),
    };
    if (graph_entries) |entries| {
        recordReturnedAgentMemoryRecallSignals(ctx, query, entries, include_internal, limit, offset);
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    if (api_storage_route.targetsKg(storage_target)) {
        const entries = kgMemorySearchEntries(ctx, obj, query, search_limit) catch |err| switch (err) {
            else => return kgMemoryErrorResponse(ctx, err),
        };
        recordReturnedAgentMemoryRecallSignals(ctx, query, entries, include_internal, limit, offset);
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (non_kg_storage_target) |route| {
        const auth = api_agent_memory_store.scopedAuth(ctx, scopes_json);
        const primary = if (session_id == null)
            api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .auth = auth,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else
            api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .session_id = session_id,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    }
    if (include_global and session_id != null) {
        if (non_kg_storage_target) |route| {
            const global = api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .auth = api_agent_memory_store.scopedAuth(ctx, scopes_json),
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
        }
    }
    if (route_includes_kg) {
        const kg_entries = kgMemorySearchEntries(ctx, obj, query, search_limit) catch |err| switch (err) {
            else => return kgMemoryErrorResponse(ctx, err),
        };
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, kg_entries) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    recordReturnedAgentMemoryRecallSignals(ctx, query, entries.items, include_internal, limit, offset);
    return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries.items, include_internal, include_content, limit, offset);
}

fn nullClawSessionRecallIncludesGlobal(obj: std.json.ObjectMap, session_id: ?[]const u8) bool {
    return json.boolField(obj, "include_global") orelse (session_id != null);
}

fn nullClawAgentMemoryDelete(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (!queryDeleteAll(query) and (session_id != null or requested_scope != null)) return agentMemoryDelete(ctx, key, query);

    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
    }
    if (requested_scope) |scope| {
        if (!domain.scopeDeletable(scope, ctx.actor_scopes_json)) return forbidden(ctx);
    }
    const owner_actor_id = if (requested_scope) |scope|
        access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx)
    else
        ctx.actor_id;
    defer if (requested_scope != null) ctx.allocator.free(owner_actor_id);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const deleted = kgMemoryDeleteKey(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return ok(ctx, "{\"ok\":true}");
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var deleted = false;
    if (route_includes_kg) {
        deleted = (kgMemoryDeleteKey(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err)) or deleted;
    }
    if (non_kg_storage_target) |route| {
        deleted = (api_agent_memory_store.delete(ctx, .{
            .key = key,
            .owner_actor_id = owner_actor_id,
            .route = route,
            .all_owners = true,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }) or deleted;
    }
    if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return ok(ctx, "{\"ok\":true}");
}

fn memoryCommandStoreBody(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const key = json.stringField(parsed.value.object, "key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing key");
    return memoryCommandMutationParsed(ctx, "store", key, parsed.value.object, false, route_query);
}

fn memoryCommandStoreKey(ctx: *Context, key: []const u8, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    return memoryCommandMutationParsed(ctx, "store", key, parsed.value.object, false, route_query);
}

fn memoryCommandUpdateBody(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const key = json.stringField(parsed.value.object, "key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing key");
    return memoryCommandMutationParsed(ctx, "update", key, parsed.value.object, true, route_query);
