fn listSources(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const input = primitiveListInputFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    const sources = ctx.store.listSourcesVisible(ctx.allocator, input) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"sources\":[") catch return serverError(ctx);
    for (sources, 0..) |source, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    appendPrimitiveListMeta(ctx, &out, "sources", sources.len, input) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn createSource(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const title = json.stringField(obj, "title") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing title");
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const input = store_mod.SourceInput{
        .source_type = json.stringField(obj, "type") orelse "manual",
        .title = title,
        .raw_content_uri = json.nullableStringField(obj, "raw_content_uri"),
        .content = json.stringField(obj, "content") orelse "",
        .author = json.nullableStringField(obj, "author"),
        .participants_json = payloadArrayJson(ctx, obj, &.{ "participants", "participants_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .scope = json.stringField(obj, "scope") orelse "workspace",
        .checksum = json.nullableStringField(obj, "checksum"),
        .language = json.nullableStringField(obj, "language"),
        .related_entities_json = payloadArrayJson(ctx, obj, &.{ "related_entities", "related_entities_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .metadata_json = payloadObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{}") catch |err| return rawJsonRequestError(ctx, err),
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    };
    if (!canWriteRecord(ctx, input.scope, input.permissions_json)) return forbidden(ctx);
    const source = ctx.store.createSource(ctx.allocator, input) catch |err| switch (err) {
        error.InvalidPayload => return badJson(ctx),
        error.RelatedEntityNotFound, error.RecordAclBroaderThanRelatedEntity => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    _ = upsertAutoVector(ctx, "source", source.id, source.content, source.scope, source.permissions_json) catch 0;
    return sourceResponse(ctx, source);
}

fn getSource(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const source = ctx.store.getSource(ctx.allocator, id) catch return serverError(ctx);
    if (source == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!recordVisibleToActor(ctx, source.?.scope, source.?.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    return sourceResponse(ctx, source.?);
}

fn patchSource(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    if (!validPrimitiveLifecycleStatus(status)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid source status");
    const source = (ctx.store.getSource(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!canChangeGraphPrimitiveStatus(ctx, source.scope, source.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "source", id, status, ctx.actor_id, payload_json) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "source", id, source.scope, source.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    return sourceResponse(ctx, source);
}

fn deleteSource(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const source = (ctx.store.getSource(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!canChangeGraphPrimitiveStatus(ctx, source.scope, source.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "source", id, "deprecated", ctx.actor_id, "{\"deleted\":true}") catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "source", id, source.scope, source.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

