fn patchArtifact(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    const artifact = (ctx.store.getArtifact(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    if (!artifacts.validStatus(artifact.artifact_type, status)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid artifact status for this artifact type");
    }
    if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    if (!canChangeGraphPrimitiveStatus(ctx, artifact.scope, artifact.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchArtifactStatusActor(id, status, ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "artifact", id, artifact.scope, artifact.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    const updated = (ctx.store.getArtifact(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    return artifactResponse(ctx, updated);
}

fn deleteArtifact(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const artifact = (ctx.store.getArtifact(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    if (!artifacts.validStatus(artifact.artifact_type, "deprecated")) return json.errorResponse(ctx.allocator, 400, "bad_request", "Artifact type cannot be deprecated");
    if (!canChangeGraphPrimitiveStatus(ctx, artifact.scope, artifact.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchArtifactStatusActor(id, "deprecated", ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "artifact", id, artifact.scope, artifact.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn resolveEntity(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const name = json.stringField(obj, "name") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing name");
    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const canonical_artifact_id = json.nullableStringField(obj, "canonical_artifact_id");
    if (!artifactCanBackRecord(ctx, canonical_artifact_id, scope, permissions_json)) return forbidden(ctx);
    const entity = ctx.store.resolveEntity(ctx.allocator, .{
        .entity_type = json.stringField(obj, "type") orelse "concept",
        .name = name,
        .aliases_json = payloadArrayJson(ctx, obj, &.{ "aliases", "aliases_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .description = json.nullableStringField(obj, "description"),
        .canonical_artifact_id = canonical_artifact_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .metadata_json = payloadObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{}") catch |err| return rawJsonRequestError(ctx, err),
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    }) catch |err| switch (err) {
        error.CanonicalArtifactNotFound, error.EntityAclBroaderThanCanonicalArtifact => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const text = vector_text.entity(ctx.allocator, entity) catch return serverError(ctx);
    _ = upsertAutoVector(ctx, "entity", entity.id, text, entity.scope, entity.permissions_json) catch 0;
    return objectResponse(ctx, "entity", entity);
}

fn createRelation(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const from_entity_id = json.stringField(obj, "from_entity_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing from_entity_id");
    const to_entity_id = json.stringField(obj, "to_entity_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing to_entity_id");
    const source_ids_json = payloadArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    if (!sourceIdsCanBackRecord(ctx, source_ids_json, scope, permissions_json)) return forbidden(ctx);
    if (!entityCanBackRecord(ctx, from_entity_id, scope, permissions_json)) return forbidden(ctx);
    if (!entityCanBackRecord(ctx, to_entity_id, scope, permissions_json)) return forbidden(ctx);
    const relation = ctx.store.createRelation(ctx.allocator, .{
        .from_entity_id = from_entity_id,
        .relation_type = json.stringField(obj, "relation_type") orelse "related_to",
        .to_entity_id = to_entity_id,
        .source_ids_json = source_ids_json,
        .scope = scope,
        .permissions_json = permissions_json,
        .confidence = json.floatField(obj, "confidence") orelse 0.5,
        .status = json.stringField(obj, "status") orelse "proposed",
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    }) catch |err| switch (err) {
        error.EntityNotFound => return json.errorResponse(ctx.allocator, 400, "bad_request", "Relation endpoints must reference existing entities"),
        error.RelationAclBroaderThanEntity => return json.errorResponse(ctx.allocator, 400, "bad_request", "Relation ACL cannot be broader than endpoint entity ACL"),
        error.InvalidRelationSchema => return json.errorResponse(ctx.allocator, 400, "bad_request", "Relation type is not valid for the endpoint entity types"),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const text = vector_text.relation(ctx.allocator, relation) catch return serverError(ctx);
    _ = upsertAutoVector(ctx, "relation", relation.id, text, relation.scope, relation.permissions_json) catch 0;
    return objectResponse(ctx, "relation", relation);
}

