fn patchEntity(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    const entity = (ctx.store.getEntity(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    if (!recordVisibleToActor(ctx, entity.scope, entity.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    if (!canChangeGraphPrimitiveStatus(ctx, entity.scope, entity.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "entity", id, status, ctx.actor_id, payload_json) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "entity", id, entity.scope, entity.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    if (graphLifecycleStatusDeletesRelations(status)) {
        cascadeDeprecatedEntityRelations(ctx, entity.id, operation, false) catch return serverError(ctx);
    }
    return entityResponse(ctx, entity);
}

fn deleteEntity(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const entity = (ctx.store.getEntity(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    if (!recordVisibleToActor(ctx, entity.scope, entity.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    if (!canChangeGraphPrimitiveStatus(ctx, entity.scope, entity.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "entity", id, "deprecated", ctx.actor_id, "{\"deleted\":true}") catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "entity", id, entity.scope, entity.permissions_json, "delete", payload_json) catch return serverError(ctx);
    cascadeDeprecatedEntityRelations(ctx, entity.id, "delete", false) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn listRelations(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const input = primitiveListInputFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    const relations_list = ctx.store.listRelationsVisible(ctx.allocator, input) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"relations\":[") catch return serverError(ctx);
    for (relations_list, 0..) |relation, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendRelationForActor(ctx, &out, relation) catch return serverError(ctx);
    }
    appendPrimitiveListMeta(ctx, &out, "relations", relations_list.len, input) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn getRelation(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const relation = (ctx.store.getRelation(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    const visible = visibleGraphRelation(ctx, relation, true) catch return serverError(ctx);
    if (visible == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    return relationResponse(ctx, visible.?.relation);
}

fn patchRelation(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    const relation = (ctx.store.getRelation(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    const visible = visibleGraphRelation(ctx, relation, true) catch return serverError(ctx);
    if (visible == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchRelationStatusActor(id, status, ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "relation", id, relation.scope, relation.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    const updated = (ctx.store.getRelation(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    return relationResponse(ctx, updated);
}

fn deleteRelation(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const relation = (ctx.store.getRelation(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    const visible = visibleGraphRelation(ctx, relation, true) catch return serverError(ctx);
    if (visible == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchRelationStatusActor(id, "deprecated", ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Relation not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "relation", id, relation.scope, relation.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn graphSchema(ctx: *Context) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    graph_mod.appendSchemaJson(ctx.allocator, &out) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn graphNeighbors(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const entity_id = json.stringField(obj, "entity_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing entity_id");
    const options = graphTraversalOptions(ctx, obj) catch |err| switch (err) {
        error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        else => return serverError(ctx),
    };
    const depth = graphDepth(json.intField(obj, "depth"));
    const limit = resultLimit(json.intField(obj, "limit"), 50);
    const root = (ctx.store.getEntity(ctx.allocator, entity_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");
    const root_visible = visibleGraphEntityWithOptions(ctx, root, options) catch return serverError(ctx);
    if (!root_visible) return json.errorResponse(ctx.allocator, 404, "not_found", "Entity not found");

    var entities: std.ArrayListUnmanaged(domain.Entity) = .empty;
    var relations: std.ArrayListUnmanaged(domain.Relation) = .empty;
    var frontier: std.ArrayListUnmanaged([]const u8) = .empty;
    entities.append(ctx.allocator, root) catch return serverError(ctx);
    frontier.append(ctx.allocator, root.id) catch return serverError(ctx);

    var current_depth: usize = 0;
    while (current_depth < depth and frontier.items.len > 0 and relations.items.len < limit) : (current_depth += 1) {
        var next: std.ArrayListUnmanaged([]const u8) = .empty;
        for (frontier.items) |current_entity_id| {
            const raw_relations = ctx.store.listEntityRelations(ctx.allocator, current_entity_id, limit) catch return serverError(ctx);
            for (raw_relations) |relation| {
                const visible = visibleGraphRelationWithOptions(ctx, relation, options) catch return serverError(ctx);
                if (visible == null) continue;
                if (!graphRelationAllowed(visible.?.relation, options)) continue;
                if (relationInList(relations.items, relation.id)) continue;
                const other = otherEntityForTraversal(visible.?, current_entity_id, options) orelse continue;
                relations.append(ctx.allocator, visible.?.relation) catch return serverError(ctx);
                if (!entityInList(entities.items, other.id)) {
                    entities.append(ctx.allocator, other) catch return serverError(ctx);
                    if (!stringInList(next.items, other.id)) next.append(ctx.allocator, other.id) catch return serverError(ctx);
                }
                if (relations.items.len >= limit) break;
            }
            if (relations.items.len >= limit) break;
        }
        frontier = next;
    }

    return graphNeighborsResponse(ctx, root, entities.items, relations.items, depth, limit);
}

fn graphQuery(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (json.stringField(obj, "query") orelse json.stringField(obj, "q")) |command_text| {
        var command_opt = graph_mod.parseCommand(ctx.allocator, command_text) catch return badJson(ctx);
        if (command_opt) |*command| {
            defer command.deinit(ctx.allocator);
            return graphCommandQuery(ctx, command.*, obj);
        }
    }
    const root_ids = graphRootEntityIds(ctx, obj) catch return badJson(ctx);
    if (root_ids.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing entity_id or entity_ids");
    const options = graphTraversalOptions(ctx, obj) catch |err| switch (err) {
        error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        else => return serverError(ctx),
    };
    const depth = graphDepth(json.intField(obj, "depth"));
    const limit = resultLimit(json.intField(obj, "limit"), 50);
    return graphQueryFromRoots(ctx, root_ids, options, depth, limit);
}

fn graphCommandQuery(ctx: *Context, command: graph_mod.Command, obj: std.json.ObjectMap) HttpResponse {
    var options = graphTraversalOptions(ctx, obj) catch |err| switch (err) {
        error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        else => return serverError(ctx),
    };
    const limit = resultLimit(json.intField(obj, "limit"), 50);
    return switch (command.kind) {
        .traverse => blk: {
            const entity_id = command.entity_id orelse return badJson(ctx);
            if (json.stringField(obj, "direction") == null) options.direction = .outbound;
            const root_ids = [_][]const u8{entity_id};
            break :blk graphQueryFromRoots(ctx, &root_ids, options, graphDepthFromSize(command.max_depth), limit);
        },
        .relations => blk: {
            const entity_id = command.entity_id orelse return badJson(ctx);
            const root_ids = [_][]const u8{entity_id};
            break :blk graphQueryFromRoots(ctx, &root_ids, options, 1, limit);
        },
        .path => graphPathBetween(
            ctx,
            command.from_entity_id orelse return badJson(ctx),
            command.to_entity_id orelse return badJson(ctx),
            options,
            graphDepthFromSize(command.max_depth),
            resultLimit(json.intField(obj, "limit"), 100),
        ),
    };
}

fn graphQueryFromRoots(ctx: *Context, root_ids: []const []const u8, options: GraphTraversalOptions, depth: usize, limit: usize) HttpResponse {
    if (limit == 0) {
        const empty_entities = [_]domain.Entity{};
        const empty_relations = [_]domain.Relation{};
        return graphQueryResponse(ctx, &empty_entities, &empty_entities, &empty_relations, options, depth, limit);
    }

    var roots: std.ArrayListUnmanaged(domain.Entity) = .empty;
    var entities: std.ArrayListUnmanaged(domain.Entity) = .empty;
    var relations: std.ArrayListUnmanaged(domain.Relation) = .empty;
    var frontier: std.ArrayListUnmanaged([]const u8) = .empty;
    for (root_ids) |entity_id| {
        const entity = (ctx.store.getEntity(ctx.allocator, entity_id) catch return serverError(ctx)) orelse continue;
        const entity_visible = visibleGraphEntityWithOptions(ctx, entity, options) catch return serverError(ctx);
        if (!entity_visible) continue;
        if (!graph_mod.entityMatchesTypeFilter(entity.entity_type, options.entity_types)) continue;
        if (!entityInList(entities.items, entity.id)) entities.append(ctx.allocator, entity) catch return serverError(ctx);
        if (!entityInList(roots.items, entity.id)) roots.append(ctx.allocator, entity) catch return serverError(ctx);
        if (!stringInList(frontier.items, entity.id)) frontier.append(ctx.allocator, entity.id) catch return serverError(ctx);
    }
    if (roots.items.len == 0) return json.errorResponse(ctx.allocator, 404, "not_found", "No visible root entities found");

    var current_depth: usize = 0;
    while (current_depth < depth and frontier.items.len > 0 and relations.items.len < limit) : (current_depth += 1) {
        var next: std.ArrayListUnmanaged([]const u8) = .empty;
        for (frontier.items) |current_entity_id| {
            const raw_relations = ctx.store.listEntityRelations(ctx.allocator, current_entity_id, limit) catch return serverError(ctx);
            for (raw_relations) |relation| {
                const visible = visibleGraphRelationWithOptions(ctx, relation, options) catch return serverError(ctx);
                if (visible == null) continue;
                if (!graphRelationAllowed(visible.?.relation, options)) continue;
                if (relationInList(relations.items, relation.id)) continue;
                const other = otherEntityForTraversal(visible.?, current_entity_id, options) orelse continue;
                relations.append(ctx.allocator, visible.?.relation) catch return serverError(ctx);
                if (!entityInList(entities.items, other.id)) {
                    entities.append(ctx.allocator, other) catch return serverError(ctx);
                    if (!stringInList(next.items, other.id)) next.append(ctx.allocator, other.id) catch return serverError(ctx);
                }
                if (relations.items.len >= limit) break;
            }
            if (relations.items.len >= limit) break;
        }
        frontier = next;
    }

    return graphQueryResponse(ctx, roots.items, entities.items, relations.items, options, depth, limit);
}

fn graphPath(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (json.stringField(obj, "query") orelse json.stringField(obj, "q")) |command_text| {
        var command_opt = graph_mod.parseCommand(ctx.allocator, command_text) catch return badJson(ctx);
        if (command_opt) |*command| {
            defer command.deinit(ctx.allocator);
            if (command.kind != .path) return badJson(ctx);
            return graphPathBetween(
                ctx,
                command.from_entity_id orelse return badJson(ctx),
                command.to_entity_id orelse return badJson(ctx),
                graphTraversalOptions(ctx, obj) catch |err| switch (err) {
                    error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
                    else => return serverError(ctx),
                },
                graphDepthFromSize(command.max_depth),
                resultLimit(json.intField(obj, "limit"), 100),
            );
        }
    }
    const from_entity_id = json.stringField(obj, "from_entity_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing from_entity_id");
    const to_entity_id = json.stringField(obj, "to_entity_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing to_entity_id");
    const options = graphTraversalOptions(ctx, obj) catch |err| switch (err) {
        error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        else => return serverError(ctx),
    };
    const max_depth = graphDepth(json.intField(obj, "max_depth"));
    const limit = resultLimit(json.intField(obj, "limit"), 100);
    return graphPathBetween(ctx, from_entity_id, to_entity_id, options, max_depth, limit);
}

fn graphPathBetween(ctx: *Context, from_entity_id: []const u8, to_entity_id: []const u8, options: GraphTraversalOptions, max_depth: usize, limit: usize) HttpResponse {
    const from = (ctx.store.getEntity(ctx.allocator, from_entity_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "From entity not found");
    const to = (ctx.store.getEntity(ctx.allocator, to_entity_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "To entity not found");
    const from_visible = visibleGraphEntityWithOptions(ctx, from, options) catch return serverError(ctx);
    const to_visible = visibleGraphEntityWithOptions(ctx, to, options) catch return serverError(ctx);
    if (!from_visible) return json.errorResponse(ctx.allocator, 404, "not_found", "From entity not found");
    if (!to_visible) return json.errorResponse(ctx.allocator, 404, "not_found", "To entity not found");
    if (!graph_mod.entityMatchesTypeFilter(from.entity_type, options.entity_types) or !graph_mod.entityMatchesTypeFilter(to.entity_type, options.entity_types)) return graphPathNotFoundResponse(ctx, from.id, to.id, max_depth);

    var parents: std.ArrayListUnmanaged(GraphParent) = .empty;
    var frontier: std.ArrayListUnmanaged([]const u8) = .empty;
    parents.append(ctx.allocator, .{ .entity_id = from.id }) catch return serverError(ctx);
    frontier.append(ctx.allocator, from.id) catch return serverError(ctx);
    var found = std.mem.eql(u8, from.id, to.id);

    search: for (0..max_depth) |_| {
        if (found or frontier.items.len == 0 or parents.items.len >= limit) break;
        var next: std.ArrayListUnmanaged([]const u8) = .empty;
        for (frontier.items) |current_entity_id| {
            const raw_relations = ctx.store.listEntityRelations(ctx.allocator, current_entity_id, limit) catch return serverError(ctx);
            for (raw_relations) |relation| {
                const visible = visibleGraphRelationWithOptions(ctx, relation, options) catch return serverError(ctx);
                if (visible == null) continue;
                if (!graphRelationAllowed(visible.?.relation, options)) continue;
                const other = otherEntityForTraversal(visible.?, current_entity_id, options) orelse continue;
                if (parentIndex(parents.items, other.id) != null) continue;
                parents.append(ctx.allocator, .{ .entity_id = other.id, .previous_entity_id = current_entity_id, .relation_id = visible.?.relation.id }) catch return serverError(ctx);
                if (std.mem.eql(u8, other.id, to.id)) {
                    found = true;
                    break :search;
                }
                next.append(ctx.allocator, other.id) catch return serverError(ctx);
                if (parents.items.len >= limit) break :search;
            }
        }
        frontier = next;
    }

    if (!found) return graphPathNotFoundResponse(ctx, from.id, to.id, max_depth);
    return graphPathFoundResponse(ctx, parents.items, from.id, to.id, max_depth);
}

const VisibleGraphRelation = struct {
    relation: domain.Relation,
    from: domain.Entity,
    to: domain.Entity,
};

const GraphParent = struct {
    entity_id: []const u8,
    previous_entity_id: ?[]const u8 = null,
    relation_id: ?[]const u8 = null,
};

const GraphTraversalOptions = struct {
    direction: graph_mod.Direction = .both,
    relation_types: []const []const u8 = &[_][]const u8{},
    entity_types: []const []const u8 = &[_][]const u8{},
    scopes_json: []const u8 = "",
    min_confidence: f64 = 0,
    include_deprecated: bool = false,
};

fn graphTraversalOptions(ctx: *Context, obj: std.json.ObjectMap) !GraphTraversalOptions {
    return .{
        .direction = try graph_mod.parseDirection(json.stringField(obj, "direction")),
        .relation_types = try graphStringListField(ctx.allocator, obj, "relation_types", "relation_type"),
        .entity_types = try graphStringListField(ctx.allocator, obj, "entity_types", "entity_type"),
        .scopes_json = try effectiveScopes(ctx, obj),
        .min_confidence = json.floatField(obj, "min_confidence") orelse 0,
        .include_deprecated = json.boolField(obj, "include_deprecated") orelse false,
    };
}

fn graphRootEntityIds(ctx: *Context, obj: std.json.ObjectMap) ![]const []const u8 {
    if (json.stringField(obj, "entity_id")) |entity_id| {
        const out = try ctx.allocator.alloc([]const u8, 1);
        out[0] = entity_id;
        return out;
    }
    return graphStringListField(ctx.allocator, obj, "entity_ids", "ids");
}

fn graphStringListField(allocator: std.mem.Allocator, obj: std.json.ObjectMap, array_name: []const u8, singular_name: []const u8) ![]const []const u8 {
    if (obj.get(array_name)) |value| return graphStringListFromValue(allocator, value);
    if (json.stringField(obj, singular_name)) |single| {
        const out = try allocator.alloc([]const u8, 1);
        out[0] = single;
        return out;
    }
    return &[_][]const u8{};
}

fn graphStringListFromValue(allocator: std.mem.Allocator, value: std.json.Value) ![]const []const u8 {
    return switch (value) {
        .string => |single| blk: {
            const out = try allocator.alloc([]const u8, 1);
            out[0] = single;
            break :blk out;
        },
        .array => |items| blk: {
            var out = try allocator.alloc([]const u8, items.items.len);
            var count: usize = 0;
            for (items.items) |item| {
                if (item != .string) return error.InvalidGraphFilter;
                out[count] = item.string;
                count += 1;
            }
            break :blk out[0..count];
        },
        else => error.InvalidGraphFilter,
    };
}

fn graphRelationAllowed(relation: domain.Relation, options: GraphTraversalOptions) bool {
    if (relation.confidence < options.min_confidence) return false;
    return graph_mod.relationMatchesTypeFilter(relation.relation_type, options.relation_types);
}

fn visibleGraphEntity(ctx: *Context, entity: domain.Entity, include_deprecated: bool) !bool {
    return visibleGraphEntityInScopes(ctx, entity, include_deprecated, ctx.actor_scopes_json);
}

fn visibleGraphEntityWithOptions(ctx: *Context, entity: domain.Entity, options: GraphTraversalOptions) !bool {
    return visibleGraphEntityInScopes(ctx, entity, options.include_deprecated, graphOptionScopes(ctx, options));
}

fn visibleGraphEntityInScopes(ctx: *Context, entity: domain.Entity, include_deprecated: bool, scopes_json: []const u8) !bool {
    if (!recordVisibleToScopes(ctx, entity.scope, entity.permissions_json, scopes_json)) return false;
    if (include_deprecated) return true;
    const status = try ctx.store.primitiveLifecycleStatus(ctx.allocator, "entity", entity.id);
    return domain.isDefaultVisibleStatus(status);
}

fn visibleGraphRelation(ctx: *Context, relation: domain.Relation, include_deprecated: bool) !?VisibleGraphRelation {
    return visibleGraphRelationInScopes(ctx, relation, include_deprecated, ctx.actor_scopes_json);
}

fn visibleGraphRelationWithOptions(ctx: *Context, relation: domain.Relation, options: GraphTraversalOptions) !?VisibleGraphRelation {
    return visibleGraphRelationInScopes(ctx, relation, options.include_deprecated, graphOptionScopes(ctx, options));
}

fn visibleGraphRelationInScopes(ctx: *Context, relation: domain.Relation, include_deprecated: bool, scopes_json: []const u8) !?VisibleGraphRelation {
    if (!include_deprecated and !domain.isDefaultVisibleStatus(relation.status)) return null;
    if (!recordVisibleToScopes(ctx, relation.scope, relation.permissions_json, scopes_json)) return null;
    const from = (try ctx.store.getEntity(ctx.allocator, relation.from_entity_id)) orelse return null;
    const to = (try ctx.store.getEntity(ctx.allocator, relation.to_entity_id)) orelse return null;
    if (!try visibleGraphEntityInScopes(ctx, from, include_deprecated, scopes_json)) return null;
    if (!try visibleGraphEntityInScopes(ctx, to, include_deprecated, scopes_json)) return null;
    return .{ .relation = relation, .from = from, .to = to };
}

fn graphOptionScopes(ctx: *Context, options: GraphTraversalOptions) []const u8 {
    return if (options.scopes_json.len > 0) options.scopes_json else ctx.actor_scopes_json;
}

fn otherEntityForTraversal(visible: VisibleGraphRelation, current_entity_id: []const u8, options: GraphTraversalOptions) ?domain.Entity {
    const direction = if (graph_mod.relationTypeSpec(visible.relation.relation_type)) |spec|
        if (spec.directed) options.direction else graph_mod.Direction.both
    else
        options.direction;
    const other_id = graph_mod.otherEntityIdForDirection(visible.relation.from_entity_id, visible.relation.to_entity_id, current_entity_id, direction) orelse return null;
    const other = if (std.mem.eql(u8, visible.from.id, other_id)) visible.from else if (std.mem.eql(u8, visible.to.id, other_id)) visible.to else return null;
    if (!graph_mod.entityMatchesTypeFilter(other.entity_type, options.entity_types)) return null;
    return other;
}

fn graphDepth(value: ?i64) usize {
    const raw = value orelse return 1;
    if (raw <= 0) return 1;
    return @intCast(@min(raw, 6));
}

fn graphDepthFromSize(value: usize) usize {
    return @min(@max(value, @as(usize, 1)), @as(usize, 6));
}

fn graphCommandSearchResultsFromObject(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, limit: usize) anyerror!?[]domain.SearchResult {
    var command_opt = try graph_mod.parseCommand(ctx.allocator, query);
    if (command_opt == null) return null;
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    defer command_opt.?.deinit(ctx.allocator);

    var options = try graphTraversalOptions(ctx, obj);
    if (command_opt.?.kind == .traverse and json.stringField(obj, "direction") == null) {
        options.direction = .outbound;
    }
    return try graphCommandSearchResults(ctx, command_opt.?, options, graphDepthFromSize(command_opt.?.max_depth), limit);
}

fn graphCommandSearchResultsFromInput(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, input: store_mod.SearchInput) anyerror!?[]domain.SearchResult {
    const window_limit = graphCommandSearchWindowLimit(input.limit, input.offset);
    const results = (try graphCommandSearchResultsFromObject(ctx, obj, query, window_limit)) orelse return null;
    defer ctx.allocator.free(results);
    const filtered = try filterGraphCommandSearchResults(ctx, results, input.min_relevance);
    return try api_search_window.trimResultsToWindowAlloc(ctx.allocator, filtered, input.offset, input.limit);
}

const graph_command_search_window_max: usize = 5000;
const graph_command_min_discovery_window: usize = 100;

fn graphCommandSearchWindowLimit(limit: usize, offset: usize) usize {
    if (limit == 0) return 0;
    const page_window = api_search_window.boundedWindowEnd(limit, offset, graph_command_search_window_max);
    return @max(page_window, @min(graph_command_search_window_max, graph_command_min_discovery_window));
}

test "api graph command search window keeps discovery floor within bounded page window" {
    try std.testing.expectEqual(@as(usize, 0), graphCommandSearchWindowLimit(0, 10));
    try std.testing.expectEqual(@as(usize, graph_command_min_discovery_window), graphCommandSearchWindowLimit(1, 0));
    try std.testing.expectEqual(@as(usize, 250), graphCommandSearchWindowLimit(50, 200));
    try std.testing.expectEqual(@as(usize, graph_command_search_window_max), graphCommandSearchWindowLimit(100, std.math.maxInt(usize)));
}

fn filterGraphCommandSearchResults(ctx: *Context, results: []const domain.SearchResult, min_relevance_raw: f64) ![]domain.SearchResult {
    const min_relevance = if (std.math.isNan(min_relevance_raw) or min_relevance_raw < 0) 0 else min_relevance_raw;
    if (min_relevance <= 0) return ctx.allocator.dupe(domain.SearchResult, results);
    var out: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
    errdefer out.deinit(ctx.allocator);
    for (results) |result| {
        if (std.math.isNan(result.score) or result.score < min_relevance) continue;
        try out.append(ctx.allocator, result);
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn graphCommandAgentMemoryEntriesFromObject(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, limit: usize) anyerror!?[]domain.AgentMemory {
    const results = (try graphCommandSearchResultsFromObject(ctx, obj, query, limit)) orelse return null;
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer {
        for (entries.items) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
        entries.deinit(ctx.allocator);
    }
    for (results) |result| {
        try entries.append(ctx.allocator, try graphSearchResultToAgentMemory(ctx, result));
    }
    return try entries.toOwnedSlice(ctx.allocator);
}

fn graphSearchResultToAgentMemory(ctx: *Context, result: domain.SearchResult) !domain.AgentMemory {
    const permissions_json = try access.permissionsJsonFromRequiredAccessJson(ctx.allocator, result.scope, result.required_scopes_json);
    errdefer ctx.allocator.free(permissions_json);
    return .{
        .id = try std.fmt.allocPrint(ctx.allocator, "graph:{s}:{s}", .{ result.result_type, result.id }),
        .key = try std.fmt.allocPrint(ctx.allocator, "graph.{s}.{s}", .{ result.result_type, result.id }),
        .content = try ctx.allocator.dupe(u8, result.text),
        .category = try std.fmt.allocPrint(ctx.allocator, "knowledge_graph:{s}", .{result.result_type}),
        .timestamp = try std.fmt.allocPrint(ctx.allocator, "{d}", .{result.created_at_ms}),
        .session_id = null,
        .actor_id = try ctx.allocator.dupe(u8, ctx.actor_id),
        .writer_actor_id = try ctx.allocator.dupe(u8, ctx.actor_id),
        .scope = try ctx.allocator.dupe(u8, result.scope),
        .permissions_json = permissions_json,
        .store = try ctx.allocator.dupe(u8, "graph"),
        .score = result.score,
    };
}

test "api graph command agent memory preserves required access gates" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{ .allocator = alloc, .store = &store, .actor_id = "agent:graph" };
    var entry = try graphSearchResultToAgentMemory(&ctx, .{
        .id = "secret-node",
        .result_type = "entity",
        .title = "Secret Node",
        .text = "Secret graph memory",
        .scope = "project:secret",
        .status = "verified",
        .score = 0.91,
        .source_ids_json = "[]",
        .required_scopes_json = "[\"project:secret\",\"team:secret\"]",
        .created_at_ms = 123,
    });
    defer agent_memory_runtime.freeAgentMemory(alloc, &entry);

    try std.testing.expectEqualStrings("[\"team:secret\"]", entry.permissions_json);
    try std.testing.expectEqualStrings("project:secret", entry.scope);
}

fn kgAgentMemoryResultType(entry: domain.AgentMemory) []const u8 {
    if (std.mem.eql(u8, entry.category, kg_compat.relation_category) or std.mem.eql(u8, entry.category, "knowledge_graph:relation")) return "relation";
    return "entity";
}

fn kgAgentMemoryToSearchResult(ctx: *Context, entry: domain.AgentMemory) !domain.SearchResult {
    const result_type = kgAgentMemoryResultType(entry);
    return .{
        .id = try ctx.allocator.dupe(u8, if (std.mem.eql(u8, result_type, "relation")) kg_compat.relationIdForKey(entry.key) else kg_compat.entityIdForKey(entry.key)),
        .result_type = result_type,
        .title = try ctx.allocator.dupe(u8, entry.key),
        .text = try ctx.allocator.dupe(u8, entry.content),
        .scope = try ctx.allocator.dupe(u8, entry.scope),
        .status = try ctx.allocator.dupe(u8, entry.status),
        .score = entry.score orelse 0.5,
        .source_ids_json = try extraction.sourceIdsJson(ctx.allocator, entry.id),
        .required_scopes_json = try access.requiredAccessJsonForActor(ctx.allocator, entry.scope, entry.permissions_json, ctx.actor_id),
        .actor_isolated = !access.isSharedAgentMemoryOwner(entry.actor_id),
        .created_at_ms = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0,
        .confidence = 0.75,
        .store = "kg",
    };
}

fn kgMemorySearchResultsFromInput(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, input: store_mod.SearchInput) ![]domain.SearchResult {
    const entries = try kgMemorySearchEntries(ctx, obj, query, api_search_window.mergeWindowLimit(input));
    var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
    errdefer results.deinit(ctx.allocator);
    for (entries) |entry| {
        try results.append(ctx.allocator, try kgAgentMemoryToSearchResult(ctx, entry));
    }
    return results.toOwnedSlice(ctx.allocator);
}

const SearchPipelineOutcome = struct {
    results: []domain.SearchResult,
    rerank_attempted: bool = false,
    rerank_applied: bool = false,
};

fn searchWithKgRoute(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, input: store_mod.SearchInput) ![]domain.SearchResult {
    if (try graphCommandSearchResultsFromInput(ctx, obj, query, input)) |graph_results| return graph_results;
    if (!api_storage_route.includesKg(input.agent_memory_route)) {
        return ctx.store.search(ctx.allocator, input);
    }

    var result_lists: std.ArrayListUnmanaged([]domain.SearchResult) = .empty;
    defer {
        for (result_lists.items) |list| ctx.allocator.free(list);
        result_lists.deinit(ctx.allocator);
    }

    if (try api_storage_route.withoutKg(ctx.allocator, input.agent_memory_route)) |route| {
        const routed = try ctx.store.search(ctx.allocator, api_search_window.inputForMergeWindow(input, route));
        try result_lists.append(ctx.allocator, routed);
    }

    const kg_results = try kgMemorySearchResultsFromInput(ctx, obj, query, input);
    try result_lists.append(ctx.allocator, kg_results);

    return try store_mod.finalizeSearchResultLists(ctx.allocator, input, result_lists.items);
}

fn runSearchPipeline(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, input: store_mod.SearchInput) !SearchPipelineOutcome {
    const rerank_enabled = api_search_window.llmRerankEffective(ctx.provider, input);
    const route_input = if (rerank_enabled) api_search_window.inputForLlmRerankWindow(input) else input;
    var results = try searchWithKgRoute(ctx, obj, query, route_input);
    maybeRunShadowVectorSearch(ctx, input, results);
    if (!rerank_enabled) return .{ .results = results };

    const rerank = try maybeLlmRerankResults(ctx, query, results, input);
    results = try api_search_window.trimResultsToFinalPageAlloc(ctx.allocator, rerank.results, input);
    return .{
        .results = results,
        .rerank_attempted = rerank.attempted,
        .rerank_applied = rerank.applied,
    };
}

fn kgMemoryListEntries(ctx: *Context, category: ?[]const u8, requested_scope: ?[]const u8) ![]domain.AgentMemory {
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    if (!hasCapability(ctx, "read")) return error.Forbidden;
    if (!requestedAgentMemoryScopeReadable(ctx, requested_scope)) return ctx.allocator.alloc(domain.AgentMemory, 0);
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer entries.deinit(ctx.allocator);

    const include_entities = if (category) |cat| !kgGraphRelationCategory(cat) else true;
    const include_relations = if (category) |cat| kgGraphRelationCategory(cat) else true;

    if (include_entities) {
        const entities = try ctx.store.listEntities(ctx.allocator, null);
        for (entities) |entity| {
            if (requested_scope) |scope| {
                if (!std.mem.eql(u8, entity.scope, scope)) continue;
            }
            if (category) |cat| {
                if (!std.mem.eql(u8, entity.entity_type, cat)) continue;
            }
            if (!try visibleGraphEntity(ctx, entity, false)) continue;
            try entries.append(ctx.allocator, try kgEntityToAgentMemory(ctx, entity));
        }
    }

    if (include_relations) {
        const relations = try ctx.store.listRelations(ctx.allocator, null);
        for (relations) |relation| {
            if (requested_scope) |scope| {
                if (!std.mem.eql(u8, relation.scope, scope)) continue;
            }
            const visible = try visibleGraphRelation(ctx, relation, false);
            if (visible == null) continue;
            try entries.append(ctx.allocator, try kgRelationToAgentMemory(ctx, visible.?.relation));
        }
    }

    sortAgentMemoryEntriesByTimestamp(entries.items);
    return entries.toOwnedSlice(ctx.allocator);
}

fn kgGraphRelationCategory(category: []const u8) bool {
    return std.mem.eql(u8, category, kg_compat.relation_category) or std.mem.eql(u8, category, "knowledge_graph:relation");
}

fn kgMemorySearchEntries(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, limit: usize) ![]domain.AgentMemory {
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    if (!hasCapability(ctx, "read")) return error.Forbidden;
    const trimmed = std.mem.trim(u8, query, " \t\r\n");
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer entries.deinit(ctx.allocator);
    if (trimmed.len == 0 or limit == 0) return entries.toOwnedSlice(ctx.allocator);

    const options = try graphTraversalOptions(ctx, obj);
    const category = json.stringField(obj, "category");
    const include_entities = if (category) |cat| !kgGraphRelationCategory(cat) else true;
    const include_relations = if (category) |cat| kgGraphRelationCategory(cat) else true;

    if (include_entities) {
        const entities = try ctx.store.listEntities(ctx.allocator, null);
        for (entities) |entity| {
            if (category) |cat| {
                if (!std.ascii.eqlIgnoreCase(entity.entity_type, cat)) continue;
            }
            if (!try visibleGraphEntityWithOptions(ctx, entity, options)) continue;
            const score = kgEntitySearchScore(entity, trimmed) orelse continue;
            var entry = try kgEntityToAgentMemory(ctx, entity);
            entry.score = score;
            try entries.append(ctx.allocator, entry);
        }
    }

    if (include_relations) {
        const relations = try ctx.store.listRelations(ctx.allocator, null);
        for (relations) |relation| {
            const visible = try visibleGraphRelationWithOptions(ctx, relation, options);
            if (visible == null) continue;
            const score = kgRelationSearchScore(visible.?.relation, trimmed) orelse continue;
            var entry = try kgRelationToAgentMemory(ctx, visible.?.relation);
            entry.score = score;
            try entries.append(ctx.allocator, entry);
        }
    }

    sortKgSearchEntries(entries.items);
    return entries.toOwnedSlice(ctx.allocator);
}

fn kgEntitySearchScore(entity: domain.Entity, query: []const u8) ?f64 {
    if (std.ascii.eqlIgnoreCase(entity.id, query) or std.ascii.eqlIgnoreCase(entity.name, query)) return 1.0;
    if (containsIgnoreCase(entity.id, query) or containsIgnoreCase(entity.name, query)) return 0.9;
    if (containsIgnoreCase(entity.entity_type, query)) return 0.8;
    if (entity.description) |description| {
        if (containsIgnoreCase(description, query)) return 0.75;
    }
    if (containsIgnoreCase(entity.aliases_json, query) or containsIgnoreCase(entity.metadata_json, query)) return 0.65;
    return null;
}

fn kgRelationSearchScore(relation: domain.Relation, query: []const u8) ?f64 {
    if (std.ascii.eqlIgnoreCase(relation.id, query) or std.ascii.eqlIgnoreCase(relation.relation_type, query)) return 0.95;
    if (containsIgnoreCase(relation.id, query) or containsIgnoreCase(relation.relation_type, query)) return 0.8;
    if (containsIgnoreCase(relation.from_entity_id, query) or containsIgnoreCase(relation.to_entity_id, query)) return 0.72;
    if (containsIgnoreCase(relation.status, query)) return 0.55;
    return null;
}

fn containsIgnoreCase(haystack: []const u8, needle: []const u8) bool {
    return needle.len == 0 or std.ascii.indexOfIgnoreCase(haystack, needle) != null;
}

fn sortKgSearchEntries(items: []domain.AgentMemory) void {
    std.mem.sort(domain.AgentMemory, items, {}, struct {
        fn lessThan(_: void, a: domain.AgentMemory, b: domain.AgentMemory) bool {
            const a_score = a.score orelse 0;
            const b_score = b.score orelse 0;
            if (a_score != b_score) return a_score > b_score;
            const a_ts = std.fmt.parseInt(i64, a.timestamp, 10) catch 0;
            const b_ts = std.fmt.parseInt(i64, b.timestamp, 10) catch 0;
            if (a_ts == b_ts) return std.mem.lessThan(u8, a.key, b.key);
            return a_ts > b_ts;
        }
    }.lessThan);
}

fn kgEntityToAgentMemory(ctx: *Context, entity: domain.Entity) !domain.AgentMemory {
    const status = try ctx.store.primitiveLifecycleStatus(ctx.allocator, "entity", entity.id);
    return try kg_compat.entityToAgentMemoryWithStatus(ctx.allocator, entity, ctx.actor_id, status);
}

fn kgRelationToAgentMemory(ctx: *Context, relation: domain.Relation) !domain.AgentMemory {
    return try kg_compat.relationToAgentMemory(ctx.allocator, relation, ctx.actor_id);
}

fn sortAgentMemoryEntriesByTimestamp(items: []domain.AgentMemory) void {
    std.mem.sort(domain.AgentMemory, items, {}, struct {
        fn lessThan(_: void, a: domain.AgentMemory, b: domain.AgentMemory) bool {
            const a_ts = std.fmt.parseInt(i64, a.timestamp, 10) catch 0;
            const b_ts = std.fmt.parseInt(i64, b.timestamp, 10) catch 0;
            if (a_ts == b_ts) return std.mem.lessThan(u8, a.key, b.key);
            return a_ts > b_ts;
        }
    }.lessThan);
}

fn kgMemoryStoreEntry(ctx: *Context, key: []const u8, obj: std.json.ObjectMap, default_category: []const u8) !domain.AgentMemory {
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    const operation = json.stringField(obj, "operation") orelse "put";
    if (feed_contract.isLifecycleOperation(operation)) return try kgMemoryLifecycleEntry(ctx, key, obj, operation);

    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return error.Forbidden;
    if (!std.ascii.eqlIgnoreCase(operation, "put")) return error.UnsupportedKgOperation;

    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions = try kgPermissionsJson(ctx, obj, &.{"permissions"}, "[]");
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;

    if (kg_compat.isRelationKey(key)) {
        const parsed = try kg_compat.parseRelationKey(ctx.allocator, key);
        defer parsed.deinit(ctx.allocator);

        try kgEnsureEndpointEntity(ctx, parsed.subject_id, scope, permissions);
        try kgEnsureEndpointEntity(ctx, parsed.object_id, scope, permissions);

        const relation = try ctx.store.upsertRelation(ctx.allocator, .{
            .id = parsed.id,
            .from_entity_id = parsed.subject_id,
            .relation_type = parsed.predicate,
            .to_entity_id = parsed.object_id,
            .scope = scope,
            .permissions_json = permissions,
            .confidence = json.floatField(obj, "confidence") orelse 0.5,
            .status = json.stringField(obj, "status") orelse "proposed",
            .actor_id = ctx.actor_id,
        });
        const text = vector_text.relation(ctx.allocator, relation) catch "";
        _ = upsertAutoVector(ctx, "relation", relation.id, text, relation.scope, relation.permissions_json) catch 0;
        return try kgRelationToAgentMemory(ctx, relation);
    }

    const entity_id = kg_compat.entityIdForKey(key);
    if (entity_id.len == 0) return error.InvalidKgKey;
    const content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse entity_id;
    const entity = try ctx.store.upsertEntity(ctx.allocator, .{
        .id = entity_id,
        .entity_type = json.stringField(obj, "category") orelse json.stringField(obj, "type") orelse default_category,
        .name = entity_id,
        .description = content,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try kgObjectJson(ctx, obj, &.{"metadata"}, "{}"),
        .actor_id = ctx.actor_id,
    });
    _ = try ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "entity", entity.id, "active", ctx.actor_id, "{\"compat\":\"kg\"}");
    const text = vector_text.entity(ctx.allocator, entity) catch "";
    _ = upsertAutoVector(ctx, "entity", entity.id, text, entity.scope, entity.permissions_json) catch 0;
    return try kgEntityToAgentMemory(ctx, entity);
}

fn kgPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn kgObjectJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn kgMemoryLifecycleEntry(ctx: *Context, key: []const u8, obj: std.json.ObjectMap, operation: []const u8) !domain.AgentMemory {
    const status = feed_contract.statusFromLifecycleOperation(operation, obj);
    const payload_json = try kgLifecyclePayloadJson(ctx, obj, operation, status);
    const causality_json = try kgObjectJson(ctx, obj, &.{"causality"}, "{}");

    if (kg_compat.isRelationKey(key)) {
        const relation_id = kg_compat.relationIdForKey(key);
        const relation = (try ctx.store.getRelation(ctx.allocator, relation_id)) orelse return error.NotFound;
        const visible = try visibleGraphRelation(ctx, relation, true);
        if (visible == null) return error.NotFound;
        if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, status)) return error.Forbidden;
        if (!(try ctx.store.patchRelationStatusActor(relation.id, status, ctx.actor_id))) return error.NotFound;
        const event_type = try std.fmt.allocPrint(ctx.allocator, "relation.{s}", .{operation});
        _ = try applyOrAppendFeedEventRecord(ctx, obj, event_type, operation, "relation", relation.id, relation.scope, relation.permissions_json, ctx.actor_id, causality_json, payload_json);
        const updated = (try ctx.store.getRelation(ctx.allocator, relation.id)) orelse return error.NotFound;
        return try kgRelationToAgentMemory(ctx, updated);
    }

    const entity_id = kg_compat.entityIdForKey(key);
    if (entity_id.len == 0) return error.InvalidKgKey;
    const entity = (try ctx.store.getEntity(ctx.allocator, entity_id)) orelse return error.NotFound;
    if (!try visibleGraphEntity(ctx, entity, true)) return error.NotFound;
    if (!canChangeGraphPrimitiveStatus(ctx, entity.scope, entity.permissions_json, status)) return error.Forbidden;
    if (!(try ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "entity", entity.id, status, ctx.actor_id, payload_json))) return error.NotFound;
    if (std.mem.eql(u8, status, "deprecated")) {
        try cascadeDeprecatedEntityRelations(ctx, entity.id, operation, true);
    }
    const event_type = try std.fmt.allocPrint(ctx.allocator, "entity.{s}", .{operation});
    _ = try applyOrAppendFeedEventRecord(ctx, obj, event_type, operation, "entity", entity.id, entity.scope, entity.permissions_json, ctx.actor_id, causality_json, payload_json);
    return try kgEntityToAgentMemory(ctx, entity);
}

fn kgLifecyclePayloadJson(ctx: *Context, obj: std.json.ObjectMap, operation: []const u8, status: []const u8) ![]const u8 {
    if (obj.get("payload") != null) return try kgObjectJson(ctx, obj, &.{"payload"}, "{}");
    return try kgLifecycleSyntheticPayloadJson(ctx, operation, status, json.stringField(obj, "reason"));
}

fn kgLifecycleSyntheticPayloadJson(ctx: *Context, operation: []const u8, status: []const u8, reason: ?[]const u8) ![]const u8 {
    return try primitiveLifecyclePayloadJson(ctx, operation, status, reason, null, "kg");
}

fn primitiveLifecycleOperationForStatus(status: []const u8) []const u8 {
    if (std.mem.eql(u8, status, "verified") or std.mem.eql(u8, status, "accepted")) return "verify";
    if (std.mem.eql(u8, status, "stale")) return "mark_stale";
    if (std.mem.eql(u8, status, "superseded")) return "supersede";
    if (std.mem.eql(u8, status, "deprecated") or std.mem.eql(u8, status, "rejected")) return "delete";
    return "put";
}

fn validPrimitiveLifecycleStatus(status: []const u8) bool {
    return std.mem.eql(u8, status, "active") or
        std.mem.eql(u8, status, "draft") or
        std.mem.eql(u8, status, "proposed") or
        std.mem.eql(u8, status, "review") or
        std.mem.eql(u8, status, "verified") or
        std.mem.eql(u8, status, "accepted") or
        std.mem.eql(u8, status, "stale") or
        std.mem.eql(u8, status, "superseded") or
        std.mem.eql(u8, status, "deprecated") or
        std.mem.eql(u8, status, "rejected");
}

fn graphLifecycleStatusDeletesRelations(status: []const u8) bool {
    return std.mem.eql(u8, status, "deprecated") or std.mem.eql(u8, status, "rejected");
}

fn primitiveLifecyclePayloadJson(ctx: *Context, operation: []const u8, status: []const u8, reason: ?[]const u8, original_payload_json: ?[]const u8, compat_tag: ?[]const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '{');
    if (compat_tag) |tag| {
        try out.appendSlice(ctx.allocator, "\"compat\":");
        try json.appendString(&out, ctx.allocator, tag);
        try out.append(ctx.allocator, ',');
    }
    try out.appendSlice(ctx.allocator, "\"operation\":");
    try json.appendString(&out, ctx.allocator, operation);
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(&out, ctx.allocator, status);
    if (std.mem.eql(u8, status, "deprecated")) try out.appendSlice(ctx.allocator, ",\"deleted\":true");
    if (reason) |value| {
        try out.appendSlice(ctx.allocator, ",\"reason\":");
        try json.appendString(&out, ctx.allocator, value);
    }
    if (original_payload_json) |value| {
        try out.appendSlice(ctx.allocator, ",\"payload\":");
        try json.appendRawJsonObject(&out, ctx.allocator, value);
    }
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

test "api primitive lifecycle payload preserves original payload object" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    const payload = try primitiveLifecyclePayloadJson(&ctx, "verify", "verified", "reviewed", "{\"source\":\"human\"}", null);
    defer std.testing.allocator.free(payload);

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, payload, .{});
    defer parsed.deinit();

    const root = parsed.value.object;
    try std.testing.expectEqualStrings("verify", root.get("operation").?.string);
    try std.testing.expectEqualStrings("verified", root.get("status").?.string);
    try std.testing.expectEqualStrings("reviewed", root.get("reason").?.string);
    try std.testing.expectEqualStrings("human", root.get("payload").?.object.get("source").?.string);
}

test "api primitive lifecycle payload rejects non-object original payload" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    try std.testing.expectError(error.InvalidRawJson, primitiveLifecyclePayloadJson(&ctx, "verify", "verified", null, "[\"not-object\"]", null));
}

fn primitiveLifecycleInputPayloadJson(ctx: *Context, obj: std.json.ObjectMap) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, &.{"payload"}, "{}");
}

fn appendKgLifecycleFeedEvent(ctx: *Context, object_type: []const u8, object_id: []const u8, scope: []const u8, permissions_json: []const u8, operation: []const u8, status: []const u8) !void {
    const payload_json = try kgLifecycleSyntheticPayloadJson(ctx, operation, status, null);
    try appendPrimitiveLifecycleFeedEvent(ctx, object_type, object_id, scope, permissions_json, operation, payload_json);
}

fn appendPrimitiveLifecycleFeedEvent(ctx: *Context, object_type: []const u8, object_id: []const u8, scope: []const u8, permissions_json: []const u8, operation: []const u8, payload_json: []const u8) !void {
    const event_type = try std.fmt.allocPrint(ctx.allocator, "{s}.{s}", .{ object_type, operation });
    _ = try ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = operation,
        .object_type = object_type,
        .object_id = object_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .actor_id = ctx.actor_id,
        .causality_json = "{}",
        .payload_json = payload_json,
        .status = "applied",
    });
}

fn cascadeDeprecatedEntityRelations(ctx: *Context, entity_id: []const u8, operation: []const u8, compat_kg: bool) !void {
    const relations = try ctx.store.listEntityRelations(ctx.allocator, entity_id, 500);
    for (relations) |relation| {
        const visible = try visibleGraphRelation(ctx, relation, true);
        if (visible == null) continue;
        if (std.mem.eql(u8, relation.status, "deprecated")) continue;
        if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, "deprecated")) continue;
        if (try ctx.store.patchRelationStatusActor(relation.id, "deprecated", ctx.actor_id)) {
            if (compat_kg) {
                try appendKgLifecycleFeedEvent(ctx, "relation", relation.id, relation.scope, relation.permissions_json, operation, "deprecated");
            } else {
                const payload_json = try primitiveLifecyclePayloadJson(ctx, operation, "deprecated", null, null, null);
                try appendPrimitiveLifecycleFeedEvent(ctx, "relation", relation.id, relation.scope, relation.permissions_json, operation, payload_json);
            }
        }
    }
}

fn kgEnsureEndpointEntity(ctx: *Context, entity_id: []const u8, scope: []const u8, permissions: []const u8) !void {
    if (try ctx.store.getEntity(ctx.allocator, entity_id)) |_| {
        if (!entityCanBackRecord(ctx, entity_id, scope, permissions)) return error.Forbidden;
        return;
    }
    _ = try ctx.store.resolveEntity(ctx.allocator, .{
        .id = entity_id,
        .entity_type = "concept",
        .name = entity_id,
        .description = entity_id,
        .scope = scope,
        .permissions_json = permissions,
        .actor_id = ctx.actor_id,
    });
}

fn kgMemoryGetEntry(ctx: *Context, key: []const u8) !?domain.AgentMemory {
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    if (!hasCapability(ctx, "read")) return error.Forbidden;

    if (kg_compat.isRelationKey(key)) {
        const relation_id = kg_compat.relationIdForKey(key);
        if (try ctx.store.getRelation(ctx.allocator, relation_id)) |relation| {
            const visible = try visibleGraphRelation(ctx, relation, false);
            if (visible == null) return null;
            return try kgRelationToAgentMemory(ctx, visible.?.relation);
        }
        return null;
    }

    const entity_id = kg_compat.entityIdForKey(key);
    if (try ctx.store.getEntity(ctx.allocator, entity_id)) |entity| {
        if (!try visibleGraphEntity(ctx, entity, false)) return null;
        return try kgEntityToAgentMemory(ctx, entity);
    }

    if (kg_compat.isEntityKey(key)) return null;

    const relation_id = kg_compat.relationIdForKey(key);
    if (try ctx.store.getRelation(ctx.allocator, relation_id)) |relation| {
        const visible = try visibleGraphRelation(ctx, relation, false);
        if (visible == null) return null;
        return try kgRelationToAgentMemory(ctx, visible.?.relation);
    }

    return null;
}

fn kgMemoryDeleteKey(ctx: *Context, key: []const u8) !bool {
    if (!build_options.enable_engine_kg) return error.EngineNotCompiled;
    if (!hasCapability(ctx, "delete")) return error.Forbidden;

    if (kg_compat.isRelationKey(key)) {
        const relation_id = kg_compat.relationIdForKey(key);
        if (try ctx.store.getRelation(ctx.allocator, relation_id)) |relation| {
            const visible = try visibleGraphRelation(ctx, relation, true);
            if (visible == null) return false;
            if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, "deprecated")) return error.Forbidden;
            const changed = try ctx.store.patchRelationStatusActor(relation.id, "deprecated", ctx.actor_id);
            if (changed) try appendKgLifecycleFeedEvent(ctx, "relation", relation.id, relation.scope, relation.permissions_json, "delete", "deprecated");
            return changed;
        }
        return false;
    }

    const entity_id = kg_compat.entityIdForKey(key);
    if (try ctx.store.getEntity(ctx.allocator, entity_id)) |entity| {
        if (!try visibleGraphEntity(ctx, entity, true)) return false;
        if (!canChangeGraphPrimitiveStatus(ctx, entity.scope, entity.permissions_json, "deprecated")) return error.Forbidden;
        const changed = try ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "entity", entity.id, "deprecated", ctx.actor_id, "{\"deleted\":true,\"compat\":\"kg\"}");
        try cascadeDeprecatedEntityRelations(ctx, entity.id, "delete", true);
        if (changed) try appendKgLifecycleFeedEvent(ctx, "entity", entity.id, entity.scope, entity.permissions_json, "delete", "deprecated");
        return changed;
    }

    if (kg_compat.isEntityKey(key)) return false;

    const relation_id = kg_compat.relationIdForKey(key);
    if (try ctx.store.getRelation(ctx.allocator, relation_id)) |relation| {
        const visible = try visibleGraphRelation(ctx, relation, true);
        if (visible == null) return false;
        if (!canChangeGraphPrimitiveStatus(ctx, relation.scope, relation.permissions_json, "deprecated")) return error.Forbidden;
        const changed = try ctx.store.patchRelationStatusActor(relation.id, "deprecated", ctx.actor_id);
        if (changed) try appendKgLifecycleFeedEvent(ctx, "relation", relation.id, relation.scope, relation.permissions_json, "delete", "deprecated");
        return changed;
    }

    return false;
}

fn kgMemoryErrorResponse(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.EngineNotCompiled => engineNotCompiled(ctx, "kg"),
        error.Forbidden => forbidden(ctx),
        error.InvalidKgKey, error.InvalidRelationKey, error.UnsupportedKgOperation => json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid knowledge graph memory key or operation"),
        error.InvalidRawJson => badJson(ctx),
        error.InvalidRelationSchema => json.errorResponse(ctx.allocator, 400, "bad_request", "Relation type is not valid for the endpoint entity types"),
        error.RelationAclBroaderThanEntity => json.errorResponse(ctx.allocator, 400, "bad_request", "Relation ACL cannot be broader than endpoint entity ACL"),
        error.NotFound => json.errorResponse(ctx.allocator, 404, "not_found", "Knowledge graph memory not found"),
        error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
        else => serverError(ctx),
    };
}

fn graphCommandSearchResults(ctx: *Context, command: graph_mod.Command, options: GraphTraversalOptions, depth: usize, limit: usize) ![]domain.SearchResult {
    return switch (command.kind) {
        .traverse => blk: {
            const entity_id = command.entity_id orelse return error.InvalidGraphCommand;
            const root_ids = [_][]const u8{entity_id};
            break :blk try graphSearchFromRoots(ctx, &root_ids, options, depth, limit);
        },
        .relations => blk: {
            const entity_id = command.entity_id orelse return error.InvalidGraphCommand;
            break :blk try graphRelationsSearchResults(ctx, entity_id, options, limit);
        },
        .path => try graphPathSearchResults(
            ctx,
            command.from_entity_id orelse return error.InvalidGraphCommand,
            command.to_entity_id orelse return error.InvalidGraphCommand,
            options,
            depth,
            limit,
        ),
    };
}

fn graphSearchFromRoots(ctx: *Context, root_ids: []const []const u8, options: GraphTraversalOptions, depth: usize, limit: usize) ![]domain.SearchResult {
    var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
    errdefer results.deinit(ctx.allocator);
    var frontier: std.ArrayListUnmanaged([]const u8) = .empty;
    errdefer frontier.deinit(ctx.allocator);

    for (root_ids) |entity_id| {
        const entity = (try ctx.store.getEntity(ctx.allocator, entity_id)) orelse continue;
        if (!try visibleGraphEntityWithOptions(ctx, entity, options)) continue;
        if (!graph_mod.entityMatchesTypeFilter(entity.entity_type, options.entity_types)) continue;
        try appendGraphEntitySearchResult(ctx, &results, entity, 1.0, limit);
        if (!stringInList(frontier.items, entity.id)) try frontier.append(ctx.allocator, entity.id);
    }

    var current_depth: usize = 0;
    while (current_depth < depth and frontier.items.len > 0 and results.items.len < limit) : (current_depth += 1) {
        var next: std.ArrayListUnmanaged([]const u8) = .empty;
        for (frontier.items) |current_entity_id| {
            const raw_relations = try ctx.store.listEntityRelations(ctx.allocator, current_entity_id, limit);
            for (raw_relations) |relation| {
                const visible = try visibleGraphRelationWithOptions(ctx, relation, options);
                if (visible == null) continue;
                if (!graphRelationAllowed(visible.?.relation, options)) continue;
                const other = otherEntityForTraversal(visible.?, current_entity_id, options) orelse continue;
                const seen_other = graphSearchResultContains(results.items, "entity", other.id);
                try appendGraphRelationSearchResult(ctx, &results, visible.?, 0.9, limit);
                try appendGraphEntitySearchResult(ctx, &results, other, 0.85, limit);
                if (!seen_other and results.items.len < limit and !stringInList(next.items, other.id)) {
                    try next.append(ctx.allocator, other.id);
                }
                if (results.items.len >= limit) break;
            }
            if (results.items.len >= limit) break;
        }
        frontier = next;
    }

    return results.toOwnedSlice(ctx.allocator);
}

fn graphRelationsSearchResults(ctx: *Context, entity_id: []const u8, options: GraphTraversalOptions, limit: usize) ![]domain.SearchResult {
    var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
    errdefer results.deinit(ctx.allocator);

    const root = (try ctx.store.getEntity(ctx.allocator, entity_id)) orelse return results.toOwnedSlice(ctx.allocator);
    if (!try visibleGraphEntityWithOptions(ctx, root, options)) return results.toOwnedSlice(ctx.allocator);
    if (!graph_mod.entityMatchesTypeFilter(root.entity_type, options.entity_types)) return results.toOwnedSlice(ctx.allocator);

    const raw_relations = try ctx.store.listEntityRelations(ctx.allocator, entity_id, limit);
    for (raw_relations) |relation| {
        const visible = try visibleGraphRelationWithOptions(ctx, relation, options);
        if (visible == null) continue;
        if (!graphRelationAllowed(visible.?.relation, options)) continue;
        if (otherEntityForTraversal(visible.?, entity_id, options) == null) continue;
        try appendGraphRelationSearchResult(ctx, &results, visible.?, 0.9, limit);
        if (results.items.len >= limit) break;
    }

    return results.toOwnedSlice(ctx.allocator);
}

fn graphPathSearchResults(ctx: *Context, from_entity_id: []const u8, to_entity_id: []const u8, options: GraphTraversalOptions, max_depth: usize, limit: usize) ![]domain.SearchResult {
    var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
    errdefer results.deinit(ctx.allocator);

    const from = (try ctx.store.getEntity(ctx.allocator, from_entity_id)) orelse return results.toOwnedSlice(ctx.allocator);
    const to = (try ctx.store.getEntity(ctx.allocator, to_entity_id)) orelse return results.toOwnedSlice(ctx.allocator);
    if (!try visibleGraphEntityWithOptions(ctx, from, options)) return results.toOwnedSlice(ctx.allocator);
    if (!try visibleGraphEntityWithOptions(ctx, to, options)) return results.toOwnedSlice(ctx.allocator);
    if (!graph_mod.entityMatchesTypeFilter(from.entity_type, options.entity_types) or !graph_mod.entityMatchesTypeFilter(to.entity_type, options.entity_types)) return results.toOwnedSlice(ctx.allocator);

    var parents: std.ArrayListUnmanaged(GraphParent) = .empty;
    var frontier: std.ArrayListUnmanaged([]const u8) = .empty;
    try parents.append(ctx.allocator, .{ .entity_id = from.id });
    try frontier.append(ctx.allocator, from.id);
    var found = std.mem.eql(u8, from.id, to.id);

    search_path: for (0..max_depth) |_| {
        if (found or frontier.items.len == 0 or parents.items.len >= limit) break;
        var next: std.ArrayListUnmanaged([]const u8) = .empty;
        for (frontier.items) |current_entity_id| {
            const raw_relations = try ctx.store.listEntityRelations(ctx.allocator, current_entity_id, limit);
            for (raw_relations) |relation| {
                const visible = try visibleGraphRelationWithOptions(ctx, relation, options);
                if (visible == null) continue;
                if (!graphRelationAllowed(visible.?.relation, options)) continue;
                const other = otherEntityForTraversal(visible.?, current_entity_id, options) orelse continue;
                if (parentIndex(parents.items, other.id) != null) continue;
                try parents.append(ctx.allocator, .{ .entity_id = other.id, .previous_entity_id = current_entity_id, .relation_id = visible.?.relation.id });
                if (std.mem.eql(u8, other.id, to.id)) {
                    found = true;
                    break :search_path;
                }
                try next.append(ctx.allocator, other.id);
                if (parents.items.len >= limit) break :search_path;
            }
        }
        frontier = next;
    }
    if (!found) return results.toOwnedSlice(ctx.allocator);

    var entity_ids_rev: std.ArrayListUnmanaged([]const u8) = .empty;
    var relation_ids_rev: std.ArrayListUnmanaged([]const u8) = .empty;
    var current = to.id;
    while (true) {
        try entity_ids_rev.append(ctx.allocator, current);
        const idx = parentIndex(parents.items, current) orelse break;
        const parent = parents.items[idx];
        if (parent.previous_entity_id == null) break;
        if (parent.relation_id) |relation_id| try relation_ids_rev.append(ctx.allocator, relation_id);
        current = parent.previous_entity_id.?;
    }

    var i = entity_ids_rev.items.len;
    while (i > 0 and results.items.len < limit) {
        i -= 1;
        const entity = (try ctx.store.getEntity(ctx.allocator, entity_ids_rev.items[i])) orelse continue;
        if (!try visibleGraphEntityWithOptions(ctx, entity, options)) continue;
        try appendGraphEntitySearchResult(ctx, &results, entity, 1.0, limit);
    }
    i = relation_ids_rev.items.len;
    while (i > 0 and results.items.len < limit) {
        i -= 1;
        const relation = (try ctx.store.getRelation(ctx.allocator, relation_ids_rev.items[i])) orelse continue;
        const visible = try visibleGraphRelationWithOptions(ctx, relation, options);
        if (visible == null) continue;
        try appendGraphRelationSearchResult(ctx, &results, visible.?, 0.9, limit);
    }

    return results.toOwnedSlice(ctx.allocator);
}

fn appendGraphEntitySearchResult(ctx: *Context, out: *std.ArrayListUnmanaged(domain.SearchResult), entity: domain.Entity, score: f64, limit: usize) !void {
    if (out.items.len >= limit or graphSearchResultContains(out.items, "entity", entity.id)) return;
    const status = try ctx.store.primitiveLifecycleStatus(ctx.allocator, "entity", entity.id);
    try out.append(ctx.allocator, .{
        .id = try ctx.allocator.dupe(u8, entity.id),
        .result_type = try ctx.allocator.dupe(u8, "entity"),
        .title = try ctx.allocator.dupe(u8, entity.name),
        .text = try ctx.allocator.dupe(u8, entity.description orelse entity.name),
        .scope = try ctx.allocator.dupe(u8, entity.scope),
        .status = try ctx.allocator.dupe(u8, status),
        .score = score,
        .source_ids_json = try ctx.allocator.dupe(u8, "[]"),
        .created_at_ms = entity.updated_at_ms,
        .confidence = 1.0,
    });
}

fn appendGraphRelationSearchResult(ctx: *Context, out: *std.ArrayListUnmanaged(domain.SearchResult), visible: VisibleGraphRelation, score: f64, limit: usize) !void {
    const relation = visible.relation;
    if (out.items.len >= limit or graphSearchResultContains(out.items, "relation", relation.id)) return;
    const text = try std.fmt.allocPrint(ctx.allocator, "{s} --{s}--> {s}", .{ visible.from.name, relation.relation_type, visible.to.name });
    try out.append(ctx.allocator, .{
        .id = try ctx.allocator.dupe(u8, relation.id),
        .result_type = try ctx.allocator.dupe(u8, "relation"),
        .title = try ctx.allocator.dupe(u8, relation.relation_type),
        .text = text,
        .scope = try ctx.allocator.dupe(u8, relation.scope),
        .status = try ctx.allocator.dupe(u8, relation.status),
        .score = score,
        .source_ids_json = try sanitizeSourceIdsForActor(ctx, relation.source_ids_json),
        .created_at_ms = ids.nowMs(),
        .confidence = relation.confidence,
    });
}

fn graphSearchResultContains(items: []const domain.SearchResult, result_type: []const u8, id: []const u8) bool {
    for (items) |item| {
        if (std.mem.eql(u8, item.result_type, result_type) and std.mem.eql(u8, item.id, id)) return true;
    }
    return false;
}

fn entityInList(items: []const domain.Entity, id: []const u8) bool {
    for (items) |item| {
        if (std.mem.eql(u8, item.id, id)) return true;
    }
    return false;
}

fn relationInList(items: []const domain.Relation, id: []const u8) bool {
    for (items) |item| {
        if (std.mem.eql(u8, item.id, id)) return true;
    }
    return false;
}

fn stringInList(items: []const []const u8, id: []const u8) bool {
    for (items) |item| {
        if (std.mem.eql(u8, item, id)) return true;
    }
    return false;
}

fn parentIndex(items: []const GraphParent, id: []const u8) ?usize {
    for (items, 0..) |item, i| {
        if (std.mem.eql(u8, item.entity_id, id)) return i;
    }
    return null;
}

fn graphNeighborsResponse(ctx: *Context, root: domain.Entity, entities: []const domain.Entity, relations: []const domain.Relation, depth: usize, limit: usize) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"root\":") catch return serverError(ctx);
    root.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"depth\":{d},\"limit\":{d},\"entities\":[", .{ depth, limit }) catch return serverError(ctx);
    appendGraphEntities(ctx, &out, entities) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"relations\":[") catch return serverError(ctx);
    appendGraphRelations(ctx, &out, relations) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn graphQueryResponse(ctx: *Context, roots: []const domain.Entity, entities: []const domain.Entity, relations: []const domain.Relation, options: GraphTraversalOptions, depth: usize, limit: usize) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"roots\":[") catch return serverError(ctx);
    appendGraphEntities(ctx, &out, roots) catch return serverError(ctx);
    out.print(ctx.allocator, "],\"depth\":{d},\"limit\":{d},\"direction\":", .{ depth, limit }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, graph_mod.directionName(options.direction)) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"relation_types\":[") catch return serverError(ctx);
    appendStringList(ctx, &out, options.relation_types) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"entity_types\":[") catch return serverError(ctx);
    appendStringList(ctx, &out, options.entity_types) catch return serverError(ctx);
    out.print(ctx.allocator, "],\"min_confidence\":{d},\"entities\":[", .{options.min_confidence}) catch return serverError(ctx);
    appendGraphEntities(ctx, &out, entities) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"relations\":[") catch return serverError(ctx);
    appendGraphRelations(ctx, &out, relations) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendStringList(ctx: *Context, out: *std.ArrayListUnmanaged(u8), values: []const []const u8) !void {
    for (values, 0..) |value, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try json.appendString(out, ctx.allocator, value);
    }
}

fn graphPathNotFoundResponse(ctx: *Context, from_entity_id: []const u8, to_entity_id: []const u8, max_depth: usize) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"found\":false,\"from_entity_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, from_entity_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"to_entity_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, to_entity_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"max_depth\":{d}}}", .{max_depth}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn graphPathFoundResponse(ctx: *Context, parents: []const GraphParent, from_entity_id: []const u8, to_entity_id: []const u8, max_depth: usize) HttpResponse {
    var entity_ids_rev: std.ArrayListUnmanaged([]const u8) = .empty;
    var relation_ids_rev: std.ArrayListUnmanaged([]const u8) = .empty;
    var current = to_entity_id;
    while (true) {
        entity_ids_rev.append(ctx.allocator, current) catch return serverError(ctx);
        const idx = parentIndex(parents, current) orelse break;
        const parent = parents[idx];
        if (parent.previous_entity_id == null) break;
        if (parent.relation_id) |relation_id| relation_ids_rev.append(ctx.allocator, relation_id) catch return serverError(ctx);
        current = parent.previous_entity_id.?;
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"found\":true,\"from_entity_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, from_entity_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"to_entity_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, to_entity_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"max_depth\":{d},\"entity_ids\":[", .{max_depth}) catch return serverError(ctx);
    appendReversedStringIds(ctx, &out, entity_ids_rev.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"relation_ids\":[") catch return serverError(ctx);
    appendReversedStringIds(ctx, &out, relation_ids_rev.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"entities\":[") catch return serverError(ctx);
    appendPathEntities(ctx, &out, entity_ids_rev.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"relations\":[") catch return serverError(ctx);
    appendPathRelations(ctx, &out, relation_ids_rev.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendGraphEntities(ctx: *Context, out: *std.ArrayListUnmanaged(u8), entities: []const domain.Entity) !void {
    for (entities, 0..) |entity, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try entity.writeJson(ctx.allocator, out);
    }
}

fn appendGraphRelations(ctx: *Context, out: *std.ArrayListUnmanaged(u8), relations: []const domain.Relation) !void {
    for (relations, 0..) |relation, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try appendRelationForActor(ctx, out, relation);
    }
}

fn appendRelationForActor(ctx: *Context, out: *std.ArrayListUnmanaged(u8), relation: domain.Relation) !void {
    var copy = relation;
    copy.source_ids_json = try sanitizeSourceIdsForActor(ctx, relation.source_ids_json);
    try copy.writeJson(ctx.allocator, out);
}

fn appendReversedStringIds(ctx: *Context, out: *std.ArrayListUnmanaged(u8), ids_list: []const []const u8) !void {
    var first = true;
    var i = ids_list.len;
    while (i > 0) {
        i -= 1;
        if (!first) try out.append(ctx.allocator, ',');
        first = false;
        try json.appendString(out, ctx.allocator, ids_list[i]);
    }
}

fn appendPathEntities(ctx: *Context, out: *std.ArrayListUnmanaged(u8), entity_ids_rev: []const []const u8) !void {
    var first = true;
    var i = entity_ids_rev.len;
    while (i > 0) {
        i -= 1;
        const entity = (try ctx.store.getEntity(ctx.allocator, entity_ids_rev[i])) orelse continue;
        if (!recordVisibleToActor(ctx, entity.scope, entity.permissions_json)) continue;
        if (!first) try out.append(ctx.allocator, ',');
        first = false;
        try entity.writeJson(ctx.allocator, out);
    }
}

fn appendPathRelations(ctx: *Context, out: *std.ArrayListUnmanaged(u8), relation_ids_rev: []const []const u8) !void {
    var first = true;
    var i = relation_ids_rev.len;
    while (i > 0) {
        i -= 1;
        const relation = (try ctx.store.getRelation(ctx.allocator, relation_ids_rev[i])) orelse continue;
        const visible = try visibleGraphRelation(ctx, relation, true);
        if (visible == null) continue;
        if (!first) try out.append(ctx.allocator, ',');
        first = false;
        try appendRelationForActor(ctx, out, visible.?.relation);
    }
}

fn relationResponse(ctx: *Context, relation: domain.Relation) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"relation\":") catch return serverError(ctx);
    appendRelationForActor(ctx, &out, relation) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn entityResponse(ctx: *Context, entity: domain.Entity) HttpResponse {
    const status = ctx.store.primitiveLifecycleStatus(ctx.allocator, "entity", entity.id) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"entity\":") catch return serverError(ctx);
    entity.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"status\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, status) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn connectorCursorGet(ctx: *Context, connector: []const u8, query: []const u8) HttpResponse {
    if (api_connectors.engineUnavailable(ctx, connector)) |response| return response;
    const decoded_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const scope = if (decoded_scope) |value| value else "workspace";
    const cursor = ctx.store.getConnectorCursor(ctx.allocator, connector, scope) catch return serverError(ctx);
    const loaded = cursor orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Connector cursor not found");
    if (!recordVisibleToActor(ctx, loaded.scope, loaded.permissions_json)) return forbidden(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"cursor\":") catch return serverError(ctx);
    loaded.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn connectorCursorUpsert(ctx: *Context, connector: []const u8, body: []const u8) HttpResponse {
    if (api_connectors.engineUnavailable(ctx, connector)) |response| return response;
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions_json = connectorPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const cursor_value = json.stringField(obj, "cursor") orelse json.stringField(obj, "next_cursor") orelse "";
    const config_json = connectorObjectJson(ctx, obj, &.{"config"}, "{}") catch |err| return rawJsonRequestError(ctx, err);
    const cursor = ctx.store.upsertConnectorCursor(ctx.allocator, .{
        .connector = connector,
        .scope = scope,
        .cursor = cursor_value,
        .config_json = config_json,
        .permissions_json = permissions_json,
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"cursor\":") catch return serverError(ctx);
    cursor.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn connectorIngest(ctx: *Context, connector: []const u8, body: []const u8, route_query: []const u8) HttpResponse {
    if (api_connectors.engineUnavailable(ctx, connector)) |response| return response;
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (std.mem.eql(u8, connector, "qmd")) return qmdConnectorIngest(ctx, connector, obj, body, route_query);
    const default_scope = json.stringField(obj, "scope") orelse "workspace";
    const default_permissions = connectorPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const run_now = json.boolField(obj, "run_now") orelse false;
    const default_storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const cursor_input = connectorCursorInputFromIngest(ctx, connector, obj, default_scope, default_permissions) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.InvalidPayload => return badJson(ctx),
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"connector\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, connector) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"sources\":[") catch return serverError(ctx);

    var count: usize = 0;
    if (obj.get("items")) |items_value| {
        if (items_value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "items must be an array");
        for (items_value.array.items) |item| {
            if (item != .object) return json.errorResponse(ctx.allocator, 400, "bad_request", "connector item must be an object");
            const item_storage_route = storage_routes.fromObjectOrFallback(ctx.allocator, item.object, default_storage_route) catch |err| return storageRouteError(ctx, err);
            const source = connectorIngestOne(ctx, connector, item.object, default_scope, default_permissions, item_storage_route) catch |err| switch (err) {
                error.Forbidden => return forbidden(ctx),
                error.InvalidPayload => return badJson(ctx),
                else => return serverError(ctx),
            };
            if (count > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
            source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
            if (run_now) {
                _ = runExtraction(ctx, source, extractionOptionsFromObjectOrFallback(ctx, item.object, true, true, item_storage_route) catch return serverError(ctx)) catch return serverError(ctx);
            } else {
                const item_job_input = store_mod.payloadWithStorageRouteJson(ctx.allocator, body, item_storage_route) catch return serverError(ctx);
                _ = ctx.store.createJob(ctx.allocator, .{ .job_type = "ingest", .scope = source.scope, .permissions_json = source.permissions_json, .object_type = "source", .object_id = source.id, .input_json = item_job_input, .actor_id = ctx.actor_id }) catch return serverError(ctx);
            }
            count += 1;
        }
    } else {
        const source = connectorIngestOne(ctx, connector, obj, default_scope, default_permissions, default_storage_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.InvalidPayload => return badJson(ctx),
            else => return serverError(ctx),
        };
        source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
        if (run_now) {
            _ = runExtraction(ctx, source, extractionOptionsFromObjectOrFallback(ctx, obj, true, true, default_storage_route) catch return serverError(ctx)) catch return serverError(ctx);
        } else {
            const job_input = store_mod.payloadWithStorageRouteJson(ctx.allocator, body, default_storage_route) catch return serverError(ctx);
            _ = ctx.store.createJob(ctx.allocator, .{ .job_type = "ingest", .scope = source.scope, .permissions_json = source.permissions_json, .object_type = "source", .object_id = source.id, .input_json = job_input, .actor_id = ctx.actor_id }) catch return serverError(ctx);
        }
        count = 1;
    }

    out.print(ctx.allocator, "],\"count\":{d},\"run_now\":", .{count}) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (run_now) "true" else "false") catch return serverError(ctx);
    if (cursor_input) |input| {
        const cursor = ctx.store.upsertConnectorCursor(ctx.allocator, input) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"cursor\":") catch return serverError(ctx);
        cursor.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn qmdConnectorIngest(ctx: *Context, connector: []const u8, obj: std.json.ObjectMap, body: []const u8, route_query: []const u8) HttpResponse {
    if (!build_options.enable_engine_qmd) return engineNotCompiled(ctx, "qmd");
    const default_scope = json.stringField(obj, "scope") orelse "workspace";
    const default_permissions = connectorPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!canProposeRecord(ctx, default_scope, default_permissions)) return forbidden(ctx);

    const result_value = obj.get("results") orelse obj.get("items") orelse std.json.Value{ .object = obj };
    const items = qmd_adapter.normalizeValue(ctx.allocator, result_value, qmd_adapter.limitsFromObject(obj)) catch return badJson(ctx);
    defer qmd_adapter.deinitItems(ctx.allocator, items);
    if (items.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing QMD results");

    const run_now = json.boolField(obj, "run_now") orelse false;
    const cursor_input = connectorCursorInputFromIngest(ctx, connector, obj, default_scope, default_permissions) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.InvalidPayload => return badJson(ctx),
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"connector\":\"qmd\",\"sources\":[") catch return serverError(ctx);

    var jobs_queued: usize = 0;
    var atoms_extracted: usize = 0;
    var vector_chunks: usize = 0;
    for (items, 0..) |item, i| {
        const source = ctx.store.createSource(ctx.allocator, .{
            .source_type = json.stringField(obj, "type") orelse "qmd",
            .title = item.title,
            .raw_content_uri = item.raw_content_uri,
            .content = item.content,
            .author = json.nullableStringField(obj, "author"),
            .participants_json = connectorArrayJson(ctx, obj, &.{"participants"}, "[]") catch |err| return rawJsonRequestError(ctx, err),
            .permissions_json = default_permissions,
            .scope = default_scope,
            .checksum = item.checksum,
            .language = json.nullableStringField(obj, "language") orelse "markdown",
            .related_entities_json = connectorArrayJson(ctx, obj, &.{"related_entities"}, "[]") catch |err| return rawJsonRequestError(ctx, err),
            .metadata_json = item.metadata_json,
            .actor_id = ctx.actor_id,
            .storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err),
        }) catch return serverError(ctx);

        var source_atoms: usize = 0;
        var source_vectors: usize = 0;
        if (run_now) {
            const extraction_options = extractionOptionsFromObject(ctx, obj, true, true, route_query) catch |err| return storageRouteError(ctx, err);
            const output = runExtraction(ctx, source, extraction_options) catch return serverError(ctx);
            source_atoms = output.atoms.len;
            source_vectors = output.vector_chunks;
            atoms_extracted += source_atoms;
            addVectorChunkTotal(&vector_chunks, source_vectors);
        } else {
            const job_input = store_mod.payloadWithStorageRouteJson(ctx.allocator, body, storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err)) catch |err| return storageRouteError(ctx, err);
            _ = ctx.store.createJob(ctx.allocator, .{ .job_type = "ingest", .scope = source.scope, .permissions_json = source.permissions_json, .object_type = "source", .object_id = source.id, .input_json = job_input, .actor_id = ctx.actor_id }) catch return serverError(ctx);
            jobs_queued += 1;
        }

        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "{\"source\":") catch return serverError(ctx);
        source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
        out.print(ctx.allocator, ",\"job_queued\":{s},\"atoms_extracted\":{d},\"vector_chunks\":{d}}}", .{ if (run_now) "false" else "true", source_atoms, source_vectors }) catch return serverError(ctx);
    }

    out.print(ctx.allocator, "],\"count\":{d},\"run_now\":{s},\"jobs_queued\":{d},\"atoms_extracted\":{d},\"vector_chunks\":{d}", .{ items.len, if (run_now) "true" else "false", jobs_queued, atoms_extracted, vector_chunks }) catch return serverError(ctx);
    if (cursor_input) |input| {
        const cursor = ctx.store.upsertConnectorCursor(ctx.allocator, input) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"cursor\":") catch return serverError(ctx);
        cursor.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn qmdSessionExport(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!build_options.enable_engine_qmd) return engineNotCompiled(ctx, "qmd");
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const directory = json.stringField(obj, "directory") orelse json.stringField(obj, "path") orelse json.stringField(obj, "export_dir") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing directory");
    if (directory.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing directory");
    const filesystem_directory = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, directory) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_directory);

    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const session_limit = positiveBounded(json.intField(obj, "session_limit") orelse json.intField(obj, "limit"), 100, 5000);
    const session_offset = positiveBounded(json.intField(obj, "offset"), 0, 1000000);
    const message_limit = positiveBounded(json.intField(obj, "message_limit") orelse json.intField(obj, "max_messages"), 10000, 50000);
    const max_message_chars = positiveBounded(json.intField(obj, "max_message_chars"), 64 * 1024, 1024 * 1024);
    const max_existing_bytes = positiveBounded(json.intField(obj, "max_existing_bytes"), 16 * 1024 * 1024, 128 * 1024 * 1024);
    const markdown_options = qmd_adapter.SessionMarkdownOptions{
        .include_internal = json.boolField(obj, "include_internal") orelse false,
        .max_message_chars = max_message_chars,
    };

    var session_ids: std.ArrayListUnmanaged([]const u8) = .empty;
    defer session_ids.deinit(ctx.allocator);
    if (json.stringField(obj, "session_id")) |sid| {
        tryAppendVisibleQmdSession(ctx, &session_ids, sid) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            else => return serverError(ctx),
        };
    }
    if (obj.get("session_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must be an array");
        for (value.array.items) |item| {
            if (item != .string) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must contain strings");
            tryAppendVisibleQmdSession(ctx, &session_ids, item.string) catch |err| switch (err) {
                error.Forbidden => return forbidden(ctx),
                else => return serverError(ctx),
            };
        }
    }
    if (session_ids.items.len == 0) {
        if (!api_session_access.allReadAllowed(ctx)) return forbidden(ctx);
        const listed = ctx.store.listSessionsRoutedWithAuth(ctx.allocator, session_limit, session_offset, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        for (listed.sessions) |session| {
            tryAppendVisibleQmdSession(ctx, &session_ids, session.session_id) catch |err| switch (err) {
                error.Forbidden => return forbidden(ctx),
                else => return serverError(ctx),
            };
        }
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"connector\":\"qmd\",\"directory\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, directory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"files\":[") catch return serverError(ctx);

    var exported: usize = 0;
    var written: usize = 0;
    var unchanged: usize = 0;
    var skipped: usize = 0;
    var first = true;
    for (session_ids.items) |session_id| {
        const history = ctx.store.historyRoutedWithAuth(ctx.allocator, session_id, message_limit, 0, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };

        var markdown: std.ArrayListUnmanaged(u8) = .empty;
        qmd_adapter.appendSessionHeader(ctx.allocator, &markdown, session_id) catch return serverError(ctx);
        var exported_messages: usize = 0;
        for (history.messages) |message| {
            if (qmd_adapter.appendSessionMessage(ctx.allocator, &markdown, message.role, message.content, message.created_at_ms, markdown_options) catch return serverError(ctx)) {
                exported_messages += 1;
            }
        }
        if (exported_messages == 0) {
            skipped += 1;
            continue;
        }

        const file = qmd_adapter.writeSessionExport(ctx.allocator, filesystem_directory, session_id, markdown.items, max_existing_bytes) catch return serverError(ctx);
        if (!first) out.append(ctx.allocator, ',') catch return serverError(ctx);
        first = false;
        out.appendSlice(ctx.allocator, "{\"session_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"path\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, file.path) catch return serverError(ctx);
        out.print(ctx.allocator, ",\"messages\":{d},\"total_messages\":{d},\"truncated\":{s},\"written\":{s},\"unchanged\":{s},\"bytes\":{d}}}", .{
            exported_messages,
            history.total,
            if (history.total > history.messages.len) "true" else "false",
            if (file.written) "true" else "false",
            if (file.unchanged) "true" else "false",
            file.bytes,
        }) catch return serverError(ctx);
        exported += 1;
        if (file.written) written += 1;
        if (file.unchanged) unchanged += 1;
    }

    out.print(ctx.allocator, "],\"exported\":{d},\"written\":{d},\"unchanged\":{d},\"skipped\":{d},\"message_limit\":{d}}}", .{ exported, written, unchanged, skipped, message_limit }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn qmdSessionPrune(ctx: *Context, body: []const u8) HttpResponse {
    if (!build_options.enable_engine_qmd) return engineNotCompiled(ctx, "qmd");
    if (!hasCapability(ctx, "export") or !hasCapability(ctx, "delete")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const directory = json.stringField(obj, "directory") orelse json.stringField(obj, "path") orelse json.stringField(obj, "export_dir") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing directory");
    if (directory.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing directory");
    const filesystem_directory = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, directory) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_directory);
    var retention_raw = json.intField(obj, "retention_days") orelse 30;
    if (retention_raw < 0) retention_raw = 0;
    if (retention_raw > 36500) retention_raw = 36500;
    const retention_days: u32 = @intCast(retention_raw);
    const pruned = qmd_adapter.pruneSessionExports(filesystem_directory, retention_days) catch |err| switch (err) {
        error.FileNotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "QMD session export directory not found"),
        error.NotDir => return json.errorResponse(ctx.allocator, 400, "bad_request", "QMD session export path is not a directory"),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"connector\":\"qmd\",\"directory\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, directory) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"retention_days\":{d},\"deleted\":{d},\"skipped\":{d}}}", .{ retention_days, pruned.deleted, pruned.skipped }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn tryAppendVisibleQmdSession(ctx: *Context, out: *std.ArrayListUnmanaged([]const u8), session_id: []const u8) !void {
    if (!api_session_access.readAllowed(ctx, session_id)) return error.Forbidden;
    try out.append(ctx.allocator, session_id);
}

fn connectorCursorInputFromIngest(ctx: *Context, connector: []const u8, obj: std.json.ObjectMap, default_scope: []const u8, default_permissions: []const u8) !?store_mod.ConnectorCursorInput {
    const cursor_value = json.stringField(obj, "next_cursor") orelse json.stringField(obj, "cursor") orelse return null;
    const scope = json.stringField(obj, "cursor_scope") orelse default_scope;
    const permissions_json = connectorPermissionsJson(ctx, obj, &.{"cursor_permissions"}, default_permissions) catch return error.InvalidPayload;
    if (!canWriteRecord(ctx, scope, permissions_json)) return error.Forbidden;
    return .{
        .connector = connector,
        .scope = scope,
        .cursor = cursor_value,
        .config_json = connectorObjectJson(ctx, obj, &.{"config"}, "{}") catch return error.InvalidPayload,
        .permissions_json = permissions_json,
        .actor_id = ctx.actor_id,
    };
}

fn connectorIngestOne(ctx: *Context, connector: []const u8, obj: std.json.ObjectMap, default_scope: []const u8, default_permissions: []const u8, storage_route: store_mod.AgentMemoryStorageRoute) !domain.Source {
    const scope = json.stringField(obj, "scope") orelse default_scope;
    const permissions_json = connectorPermissionsJson(ctx, obj, &.{"permissions"}, default_permissions) catch return error.InvalidPayload;
    if (!canProposeRecord(ctx, scope, permissions_json)) return error.Forbidden;
    const title = json.stringField(obj, "title") orelse json.stringField(obj, "key") orelse connector;
    const metadata_json = connectorObjectJson(ctx, obj, &.{"metadata"}, "{}") catch return error.InvalidPayload;
    return try ctx.store.createSource(ctx.allocator, .{
        .source_type = json.stringField(obj, "type") orelse api_connectors.defaultSourceType(connector),
        .title = title,
        .raw_content_uri = json.nullableStringField(obj, "raw_content_uri"),
        .content = json.stringField(obj, "content") orelse json.stringField(obj, "body") orelse "",
        .author = json.nullableStringField(obj, "author"),
        .participants_json = connectorArrayJson(ctx, obj, &.{"participants"}, "[]") catch return error.InvalidPayload,
        .permissions_json = permissions_json,
        .scope = scope,
        .checksum = json.nullableStringField(obj, "checksum"),
        .language = json.nullableStringField(obj, "language"),
        .related_entities_json = connectorArrayJson(ctx, obj, &.{"related_entities"}, "[]") catch return error.InvalidPayload,
        .metadata_json = try api_connectors.metadataJson(ctx.allocator, connector, metadata_json),
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    });
}

fn connectorArrayJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn connectorObjectJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn connectorPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return connectorArrayJson(ctx, obj, names, fallback);
}

fn markdownArrayJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn markdownPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return markdownArrayJson(ctx, obj, names, fallback);
}

fn markdownImport(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const content = json.stringField(obj, "content") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing content");
    const default_scope = json.stringField(obj, "scope") orelse "workspace";
    const default_permissions = markdownPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const fallback_title = json.stringField(obj, "title") orelse "Markdown import";

    const imported = markdown_adapter.parseImport(ctx.allocator, content, fallback_title, default_scope, default_permissions) catch return badJson(ctx);
    defer imported.deinit(ctx.allocator);
    const created = createMarkdownObjects(ctx, obj, route_query, imported, content, imported.path, firstNonNullString(json.nullableStringField(obj, "checksum"), imported.checksum)) catch |err| switch (err) {
        error.InvalidArtifactStatus => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid artifact status for this artifact type"),
        error.InvalidPayload => return badJson(ctx),
        error.InvalidRawJson => return rawJsonRequestError(ctx, err),
        error.RelatedEntityNotFound, error.RecordAclBroaderThanRelatedEntity => return forbidden(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    const source = created.source;
    const artifact = created.artifact;

    const run_now = json.boolField(obj, "run_now") orelse false;
    if (!run_now) {
        const job_input = markdownExtractionJobInputJson(ctx.allocator, json.boolField(obj, "extract_memory") orelse true, json.boolField(obj, "use_llm_extraction") orelse json.boolField(obj, "structured_extraction") orelse false, json.boolField(obj, "strict_llm_extraction") orelse false, storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err)) catch |err| return storageRouteError(ctx, err);
        const job = ctx.store.createJob(ctx.allocator, .{
            .job_type = "extract_memory",
            .scope = source.scope,
            .permissions_json = source.permissions_json,
            .object_type = "source",
            .object_id = source.id,
            .input_json = job_input,
            .actor_id = ctx.actor_id,
        }) catch return serverError(ctx);
        return markdownImportQueuedResponse(ctx, job, source, artifact);
    }

    const extraction_options = extractionOptionsFromObject(ctx, obj, false, json.boolField(obj, "extract_memory") orelse true, route_query) catch |err| return storageRouteError(ctx, err);
    var output = runExtraction(ctx, source, extraction_options) catch |err| {
        return json.errorResponse(ctx.allocator, 500, "internal_error", @errorName(err));
    };
    attachArtifactVector(ctx, &output, artifact) catch return serverError(ctx);
    return markdownImportResponse(ctx, source, artifact, output);
}

fn markdownExport(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    if (json.stringField(obj, "artifact_id")) |artifact_id| {
        const artifact = (ctx.store.getArtifact(ctx.allocator, artifact_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
        if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return forbidden(ctx);
        var markdown: std.ArrayListUnmanaged(u8) = .empty;
        markdown_adapter.appendArtifactMarkdown(ctx.allocator, &markdown, artifact) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "{\"object_type\":\"artifact\",\"object_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, artifact.id) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"markdown\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, markdown.items) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }

    if (json.stringField(obj, "source_id")) |source_id| {
        const source = (ctx.store.getSource(ctx.allocator, source_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
        if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return forbidden(ctx);
        var markdown: std.ArrayListUnmanaged(u8) = .empty;
        markdown_adapter.appendSourceMarkdown(ctx.allocator, &markdown, source) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "{\"object_type\":\"source\",\"object_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, source.id) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"markdown\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, markdown.items) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }

    return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing artifact_id or source_id");
}

fn markdownImportDirectory(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const root_path = json.stringField(obj, "path") orelse json.stringField(obj, "directory") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    if (root_path.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    const filesystem_root_path = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, root_path) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_root_path);

    const default_scope = json.stringField(obj, "scope") orelse "workspace";
    const default_permissions = markdownPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const max_files = positiveBounded(json.intField(obj, "max_files"), 1000, 10000);
    const max_file_bytes = positiveBounded(json.intField(obj, "max_file_bytes"), 5 * 1024 * 1024, 25 * 1024 * 1024);
    const max_total_bytes = positiveBounded(json.intField(obj, "max_total_bytes"), 25 * 1024 * 1024, 100 * 1024 * 1024);
    const queue_extraction = json.boolField(obj, "queue_extraction") orelse true;
    const run_now = json.boolField(obj, "run_now") orelse false;
    const extract_memory = json.boolField(obj, "extract_memory") orelse true;
    const skip_unchanged = json.boolField(obj, "skip_unchanged") orelse true;

    const discovered = markdown_filesystem.readDirectory(ctx.allocator, filesystem_root_path, max_files, max_file_bytes, max_total_bytes) catch |err| switch (err) {
        error.FileNotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Markdown directory not found"),
        error.NotDir => return json.errorResponse(ctx.allocator, 400, "bad_request", "Path is not a directory"),
        error.StreamTooLong => return json.errorResponse(ctx.allocator, 413, "payload_too_large", "Markdown import exceeds max_file_bytes or max_total_bytes"),
        else => return serverError(ctx),
    };
    defer markdown_filesystem.deinitDirectoryReadResult(ctx.allocator, discovered);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"path\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, root_path) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"files\":[") catch return serverError(ctx);

    var imported_count: usize = 0;
    const skipped_count: usize = discovered.skipped;
    var jobs_queued: usize = 0;
    var atoms_extracted: usize = 0;
    var vector_chunks: usize = 0;
    var unchanged_count: usize = 0;
    var first_file = true;
    for (discovered.files) |file| {
        const imported = markdown_adapter.parseImport(ctx.allocator, file.content, file.fallback_title, default_scope, default_permissions) catch return badJson(ctx);
        defer imported.deinit(ctx.allocator);

        if (skip_unchanged) {
            if (ctx.store.findSourceByRawContentUri(ctx.allocator, file.path, imported.scope) catch return serverError(ctx)) |existing| {
                if (stringMatchesOptional(existing.checksum, file.checksum)) {
                    unchanged_count += 1;
                    continue;
                }
            }
        }

        const created = createMarkdownObjects(ctx, obj, route_query, imported, file.content, file.path, file.checksum) catch |err| switch (err) {
            error.InvalidArtifactStatus => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid artifact status for this artifact type"),
            error.InvalidPayload => return badJson(ctx),
            error.RelatedEntityNotFound, error.RecordAclBroaderThanRelatedEntity => return forbidden(ctx),
            error.Forbidden => return forbidden(ctx),
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            error.InvalidStorageSelector => return storageRouteError(ctx, err),
            else => return serverError(ctx),
        };

        var file_atoms: usize = 0;
        var file_vector_chunks: usize = 0;
        var queued = false;
        if (run_now) {
            const extraction_options = extractionOptionsFromObject(ctx, obj, false, extract_memory, route_query) catch |err| return storageRouteError(ctx, err);
            var output = runExtraction(ctx, created.source, extraction_options) catch |err| {
                return json.errorResponse(ctx.allocator, 500, "internal_error", @errorName(err));
            };
            attachArtifactVector(ctx, &output, created.artifact) catch return serverError(ctx);
            file_atoms = output.atoms.len;
            file_vector_chunks = output.vector_chunks;
            atoms_extracted += file_atoms;
            addVectorChunkTotal(&vector_chunks, file_vector_chunks);
        } else if (queue_extraction and extract_memory) {
            queueMarkdownExtractionJob(ctx, obj, route_query, created.source) catch return serverError(ctx);
            jobs_queued += 1;
            queued = true;
        }

        if (!first_file) out.append(ctx.allocator, ',') catch return serverError(ctx);
        first_file = false;
        appendMarkdownDirectoryImportFile(ctx, &out, file.path, created.source, created.artifact, queued, file_atoms, file_vector_chunks) catch return serverError(ctx);
        imported_count += 1;
    }

    out.print(ctx.allocator, "],\"imported\":{d},\"unchanged\":{d},\"skipped\":{d},\"jobs_queued\":{d},\"atoms_extracted\":{d},\"vector_chunks\":{d}}}", .{ imported_count, unchanged_count, skipped_count, jobs_queued, atoms_extracted, vector_chunks }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn markdownExportDirectory(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const root_path = json.stringField(obj, "path") orelse json.stringField(obj, "directory") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    if (root_path.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    const filesystem_root_path = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, root_path) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_root_path);
    const overwrite = json.boolField(obj, "overwrite") orelse false;

    std.Io.Dir.cwd().createDirPath(compat.io(), filesystem_root_path) catch return serverError(ctx);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"path\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, root_path) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"files\":[") catch return serverError(ctx);

    var exported_count: usize = 0;
    var first_file = true;
    if (obj.get("artifact_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "artifact_ids must be an array");
        for (value.array.items) |id_value| {
            if (id_value != .string) continue;
            const artifact = (ctx.store.getArtifact(ctx.allocator, id_value.string) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Artifact not found");
            if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return forbidden(ctx);
            var markdown: std.ArrayListUnmanaged(u8) = .empty;
            markdown_adapter.appendArtifactMarkdown(ctx.allocator, &markdown, artifact) catch return serverError(ctx);
            const filename = markdown_adapter.exportFileName(ctx.allocator, artifact.title, artifact.id, "artifact") catch return serverError(ctx);
            const file_path = markdownExportFilePath(ctx.allocator, filesystem_root_path, filename) catch |err| return filesystemPathError(ctx, err);
            markdown_filesystem.writeFile(file_path, markdown.items, overwrite) catch |err| switch (err) {
                error.PathAlreadyExists => return json.errorResponse(ctx.allocator, 409, "conflict", "Markdown export target already exists"),
                else => return serverError(ctx),
            };
            if (!first_file) out.append(ctx.allocator, ',') catch return serverError(ctx);
            first_file = false;
            appendMarkdownDirectoryExportFile(ctx, &out, file_path, "artifact", artifact.id) catch return serverError(ctx);
            exported_count += 1;
        }
    }

    if (obj.get("source_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "source_ids must be an array");
        for (value.array.items) |id_value| {
            if (id_value != .string) continue;
            const source = (ctx.store.getSource(ctx.allocator, id_value.string) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
            if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return forbidden(ctx);
            var markdown: std.ArrayListUnmanaged(u8) = .empty;
            markdown_adapter.appendSourceMarkdown(ctx.allocator, &markdown, source) catch return serverError(ctx);
            const filename = markdown_adapter.exportFileName(ctx.allocator, source.title, source.id, "source") catch return serverError(ctx);
            const file_path = markdownExportFilePath(ctx.allocator, filesystem_root_path, filename) catch |err| return filesystemPathError(ctx, err);
            markdown_filesystem.writeFile(file_path, markdown.items, overwrite) catch |err| switch (err) {
                error.PathAlreadyExists => return json.errorResponse(ctx.allocator, 409, "conflict", "Markdown export target already exists"),
                else => return serverError(ctx),
            };
            if (!first_file) out.append(ctx.allocator, ',') catch return serverError(ctx);
            first_file = false;
            appendMarkdownDirectoryExportFile(ctx, &out, file_path, "source", source.id) catch return serverError(ctx);
            exported_count += 1;
        }
    }

    if (exported_count == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing artifact_ids or source_ids");
    out.print(ctx.allocator, "],\"exported\":{d},\"overwrite\":{s}}}", .{ exported_count, if (overwrite) "true" else "false" }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

const MarkdownCreated = struct {
    source: domain.Source,
    artifact: domain.Artifact,
};

fn createMarkdownObjects(
    ctx: *Context,
    obj: std.json.ObjectMap,
    route_query: []const u8,
    imported: markdown_adapter.ParsedMarkdown,
    content: []const u8,
    file_path: ?[]const u8,
    checksum: ?[]const u8,
) !MarkdownCreated {
    if (!artifacts.validStatus(imported.artifact_type, imported.status)) return error.InvalidArtifactStatus;
    if (!canProposeRecord(ctx, imported.scope, imported.permissions_json)) return error.Forbidden;
    if (!markdownStatusCanBeProposed(imported.status) and !canWriteRecord(ctx, imported.scope, imported.permissions_json)) return error.Forbidden;

    const storage_route = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query);
    const related_entities_json = if (jsonArrayIsEmpty(imported.related_entities_json))
        try extraction.extractEntityNamesJson(ctx.allocator, imported.body)
    else
        imported.related_entities_json;
    const source_checksum = firstNonNullString(checksum, imported.checksum);
    const source_path = firstNonNullString(file_path, imported.path);
    const metadata_json = try markdownImportMetadataJson(ctx.allocator, imported.metadata_json, source_path, source_checksum);
    const artifact_space_id = firstNonNullString(imported.space_id, json.nullableStringField(obj, "space_id"));
    if (!spaceCanContainRecord(ctx, artifact_space_id, imported.scope, imported.permissions_json)) return error.Forbidden;

    const source = try ctx.store.createSource(ctx.allocator, .{
        .source_type = imported.source_type,
        .title = imported.title,
        .raw_content_uri = firstNonNullString(source_path, firstNonNullString(imported.raw_content_uri, json.nullableStringField(obj, "raw_content_uri"))),
        .content = content,
        .author = firstNonNullString(imported.author, json.nullableStringField(obj, "author")),
        .participants_json = markdownArrayJson(ctx, obj, &.{"participants"}, "[]") catch return error.InvalidPayload,
        .permissions_json = imported.permissions_json,
        .scope = imported.scope,
        .checksum = source_checksum,
        .language = json.nullableStringField(obj, "language") orelse "markdown",
        .related_entities_json = related_entities_json,
        .metadata_json = metadata_json,
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    });

    const actual_source_ids_json = try extraction.sourceIdsJson(ctx.allocator, source.id);
    const artifact = try ctx.store.createArtifact(ctx.allocator, .{
        .artifact_type = imported.artifact_type,
        .title = imported.title,
        .body = imported.body,
        .status = imported.status,
        .owner = firstNonNullString(imported.owner, firstNonNullString(imported.author, firstNonNullString(json.nullableStringField(obj, "owner"), json.nullableStringField(obj, "author")))),
        .space_id = artifact_space_id,
        .scope = imported.scope,
        .source_ids_json = actual_source_ids_json,
        .related_entities_json = related_entities_json,
        .permissions_json = imported.permissions_json,
        .fields_json = imported.fields_json,
        .summary = try extraction.summarize(ctx.allocator, imported.body, 512),
        .agent_summary = try extraction.summarize(ctx.allocator, imported.body, 1024),
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    });

    return .{ .source = source, .artifact = artifact };
}

fn markdownStatusCanBeProposed(status: []const u8) bool {
    return std.mem.eql(u8, status, "draft") or std.mem.eql(u8, status, "proposed");
}

fn firstNonNullString(primary: ?[]const u8, fallback: ?[]const u8) ?[]const u8 {
    if (primary) |value| return value;
    return fallback;
}

fn stringMatchesOptional(value: ?[]const u8, expected: []const u8) bool {
    return if (value) |actual| std.mem.eql(u8, actual, expected) else false;
}

fn markdownImportMetadataJson(allocator: std.mem.Allocator, metadata_json: []const u8, file_path: ?[]const u8, checksum: ?[]const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);

    try out.appendSlice(allocator, "{\"connector\":\"markdown\",\"metadata\":");
    try json.appendRawJsonObject(&out, allocator, metadata_json);
    if (file_path) |value| {
        try out.appendSlice(allocator, ",\"path\":");
        try json.appendString(&out, allocator, value);
    }
    if (checksum) |value| {
        try out.appendSlice(allocator, ",\"checksum\":");
        try json.appendString(&out, allocator, value);
    }
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

test "api markdown import metadata preserves shaped raw JSON" {
    const metadata = try markdownImportMetadataJson(std.testing.allocator, "{\"source\":\"docs\"}", "docs/adr.md", "sha256:test");
    defer std.testing.allocator.free(metadata);

    try std.testing.expect(std.mem.indexOf(u8, metadata, "\"connector\":\"markdown\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, metadata, "\"metadata\":{\"source\":\"docs\"}") != null);
    try std.testing.expect(std.mem.indexOf(u8, metadata, "\"path\":\"docs/adr.md\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, metadata, "\"checksum\":\"sha256:test\"") != null);
}

test "api markdown import metadata rejects malformed raw JSON" {
    try std.testing.expectError(error.InvalidRawJson, markdownImportMetadataJson(std.testing.allocator, "[]", null, null));
    try std.testing.expectError(error.InvalidRawJson, markdownImportMetadataJson(std.testing.allocator, "{\"source\":\"docs\"", null, null));
}

fn jsonArrayIsEmpty(raw: []const u8) bool {
    const trimmed = std.mem.trim(u8, raw, " \t\r\n");
    return trimmed.len == 0 or std.mem.eql(u8, trimmed, "[]");
}

fn appendMarkdownDirectoryImportFile(
    ctx: *Context,
    out: *std.ArrayListUnmanaged(u8),
    path: []const u8,
    source: domain.Source,
    artifact: domain.Artifact,
    job_queued: bool,
    atoms_extracted: usize,
    vector_chunks: usize,
) !void {
    try out.appendSlice(ctx.allocator, "{\"path\":");
    try json.appendString(out, ctx.allocator, path);
    try out.appendSlice(ctx.allocator, ",\"source_id\":");
    try json.appendString(out, ctx.allocator, source.id);
    try out.appendSlice(ctx.allocator, ",\"artifact_id\":");
    try json.appendString(out, ctx.allocator, artifact.id);
    try out.appendSlice(ctx.allocator, ",\"artifact_type\":");
    try json.appendString(out, ctx.allocator, artifact.artifact_type);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, artifact.scope);
    try out.print(ctx.allocator, ",\"job_queued\":{s},\"atoms_extracted\":{d},\"vector_chunks\":{d}}}", .{ if (job_queued) "true" else "false", atoms_extracted, vector_chunks });
}

fn attachArtifactVector(ctx: *Context, output: *ExtractionOutput, artifact: domain.Artifact) !void {
    output.artifact = artifact;
    output.addVectorChunks(try upsertAutoVector(ctx, "artifact", artifact.id, artifact.body, artifact.scope, artifact.permissions_json));
}

fn addVectorChunkTotal(total: *usize, delta: usize) void {
    var counts = extraction.ResultCounts{ .vector_chunk_count = total.* };
    counts.addVectorChunks(delta);
    total.* = counts.vector_chunk_count;
}

fn appendMarkdownDirectoryExportFile(
    ctx: *Context,
    out: *std.ArrayListUnmanaged(u8),
    path: []const u8,
    object_type: []const u8,
    object_id: []const u8,
) !void {
    try out.appendSlice(ctx.allocator, "{\"path\":");
    try json.appendString(out, ctx.allocator, path);
    try out.appendSlice(ctx.allocator, ",\"object_type\":");
    try json.appendString(out, ctx.allocator, object_type);
    try out.appendSlice(ctx.allocator, ",\"object_id\":");
    try json.appendString(out, ctx.allocator, object_id);
    try out.append(ctx.allocator, '}');
}

fn queueMarkdownExtractionJob(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8, source: domain.Source) !void {
    const job_input = try markdownExtractionJobInputJson(
        ctx.allocator,
        json.boolField(obj, "extract_memory") orelse true,
        json.boolField(obj, "use_llm_extraction") orelse json.boolField(obj, "structured_extraction") orelse false,
        json.boolField(obj, "strict_llm_extraction") orelse false,
        try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query),
    );
    _ = try ctx.store.createJob(ctx.allocator, .{
        .job_type = "extract_memory",
        .scope = source.scope,
        .permissions_json = source.permissions_json,
        .object_type = "source",
        .object_id = source.id,
        .input_json = job_input,
        .actor_id = ctx.actor_id,
    });
}

fn positiveBounded(value: ?i64, default_value: usize, max_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return default_value;
    return bounded_int.positiveI64ToUsizeBounded(raw, max_value);
}

test "api positive bounded helper preserves defaults and caps request values" {
    try std.testing.expectEqual(@as(usize, 25), positiveBounded(null, 25, 100));
    try std.testing.expectEqual(@as(usize, 25), positiveBounded(0, 25, 100));
    try std.testing.expectEqual(@as(usize, 42), positiveBounded(42, 25, 100));
    try std.testing.expectEqual(@as(usize, 100), positiveBounded(std.math.maxInt(i64), 25, 100));
}

fn markdownExtractionJobInputJson(allocator: std.mem.Allocator, extract_memory: bool, use_llm_extraction: bool, strict_llm_extraction: bool, route: store_mod.AgentMemoryStorageRoute) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"create_artifact\":false,\"extract_memory\":");
    try out.appendSlice(allocator, if (extract_memory) "true" else "false");
    try out.appendSlice(allocator, ",\"use_llm_extraction\":");
    try out.appendSlice(allocator, if (use_llm_extraction) "true" else "false");
    try out.appendSlice(allocator, ",\"strict_llm_extraction\":");
    try out.appendSlice(allocator, if (strict_llm_extraction) "true" else "false");
    if (route.target != .primary) {
        try storage_routes.appendExtractionJson(allocator, &out, route);
    }
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn markdownImportQueuedResponse(ctx: *Context, job: store_mod.Job, source: domain.Source, artifact: domain.Artifact) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"queued\":true,\"job\":") catch return serverError(ctx);
    job.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source\":") catch return serverError(ctx);
    source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"artifact\":") catch return serverError(ctx);
    artifact.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"run_endpoint\":\"/v1/workers/run\"}") catch return serverError(ctx);
    return .{ .status = "202 Accepted", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn markdownImportResponse(ctx: *Context, source: domain.Source, artifact: domain.Artifact, output: ExtractionOutput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"source\":") catch return serverError(ctx);
    source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"artifact\":") catch return serverError(ctx);
    artifact.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_atoms\":[") catch return serverError(ctx);
    for (output.atoms, 0..) |atom, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        atom.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "],\"entities\":[") catch return serverError(ctx);
    for (output.entities, 0..) |entity, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        entity.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "],\"relations\":[") catch return serverError(ctx);
    for (output.relations, 0..) |relation, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        relation.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.print(ctx.allocator, "],\"vector_chunk_count\":{d},\"extraction_provider\":", .{output.vector_chunks}) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, output.extraction_provider) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"extraction_fallback\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (output.extraction_fallback) "true}" else "false}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn governancePermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn governanceMetadataJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn createSpace(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const name = json.stringField(obj, "name") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing name");
    const title = json.stringField(obj, "title") orelse name;
    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions_json = governancePermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const space = ctx.store.createSpace(ctx.allocator, .{
        .name = name,
        .title = title,
        .description = json.nullableStringField(obj, "description"),
        .scope = scope,
        .permissions_json = permissions_json,
        .metadata_json = governanceMetadataJson(ctx, obj, &.{"metadata"}, "{}") catch |err| return rawJsonRequestError(ctx, err),
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    const text = vector_text.space(ctx.allocator, space) catch return serverError(ctx);
    _ = upsertAutoVector(ctx, "space", space.id, text, space.scope, space.permissions_json) catch 0;
    return spaceResponse(ctx, space);
}

fn getSpace(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const space = ctx.store.getSpace(ctx.allocator, id) catch return serverError(ctx);
    if (space == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    if (!recordVisibleToActor(ctx, space.?.scope, space.?.permissions_json)) return forbidden(ctx);
    return spaceResponse(ctx, space.?);
}

fn patchSpace(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    if (!validPrimitiveLifecycleStatus(status)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid space status");
    const space = (ctx.store.getSpace(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    if (!recordVisibleToActor(ctx, space.scope, space.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    if (!canChangeGraphPrimitiveStatus(ctx, space.scope, space.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "space", space.id, status, ctx.actor_id, payload_json) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "space", space.id, space.scope, space.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    return spaceResponse(ctx, space);
}

fn deleteSpace(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const space = (ctx.store.getSpace(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    if (!recordVisibleToActor(ctx, space.scope, space.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    if (!canChangeGraphPrimitiveStatus(ctx, space.scope, space.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "space", space.id, "deprecated", ctx.actor_id, "{\"deleted\":true}") catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Space not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "space", space.id, space.scope, space.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn listSpaces(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const scope_filter = effectiveScopesFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    if (scope_filter.empty) return ok(ctx, "{\"spaces\":[]}");
    const spaces = ctx.store.listSpaces(ctx.allocator, scope_filter.scopes_json, limit) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"spaces\":[") catch return serverError(ctx);
    for (spaces, 0..) |space, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        space.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn upsertPolicyScope(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const scope = json.stringField(obj, "scope") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing scope");
    const permissions_json = governancePermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const policy = ctx.store.upsertPolicyScope(ctx.allocator, .{
        .scope = scope,
        .visibility = json.stringField(obj, "visibility") orelse "workspace",
        .permissions_json = permissions_json,
        .owner = json.nullableStringField(obj, "owner"),
        .ttl_ms = json.intField(obj, "ttl_ms"),
        .review_after_ms = json.intField(obj, "review_after_ms"),
        .metadata_json = governanceMetadataJson(ctx, obj, &.{"metadata"}, "{}") catch |err| return rawJsonRequestError(ctx, err),
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    const text = vector_text.policyScope(ctx.allocator, policy) catch return serverError(ctx);
    _ = upsertAutoVector(ctx, "policy_scope", policy.scope, text, policy.scope, policy.permissions_json) catch 0;
    return policyScopeResponse(ctx, policy);
}

