const RolloutPolicyRecord = struct {
    artifact: domain.Artifact,
    name: []const u8,
    feature: []const u8,
    policy: lifecycle.RolloutPolicy,
};

fn rolloutPolicyArtifactId(allocator: std.mem.Allocator, name: []const u8) ![]u8 {
    const hash = std.hash.Wyhash.hash(0, name);
    return std.fmt.allocPrint(allocator, "rpol_{x}", .{hash});
}

fn rolloutPolicyNotFound(ctx: *Context) HttpResponse {
    return json.errorResponse(ctx.allocator, 404, "not_found", "Rollout policy not found");
}

fn rolloutPolicyBase(feature: []const u8) lifecycle.RolloutPolicy {
    return .{ .mode = .off, .salt = feature };
}

fn rolloutPolicyFromObject(ctx: *Context, obj: std.json.ObjectMap, base: lifecycle.RolloutPolicy) !lifecycle.RolloutPolicy {
    var policy = base;
    const percent_raw = intFieldAny(obj, &.{ "percent", "canary_percent", "rollout_percent" });
    const shadow_percent_raw = intFieldAny(obj, &.{ "shadow_percent", "shadow_hybrid_percent", "rollout_shadow_percent" });
    if (stringFieldAny(obj, &.{ "mode", "rollout_mode" })) |mode| {
        policy.mode = try lifecycle.RolloutMode.parse(mode, percent_raw != null);
    } else if (percent_raw != null and policy.mode == .off) {
        policy.mode = try lifecycle.RolloutMode.parse(null, true);
    }
    if (percent_raw) |value| policy.percent = clampPercent(value);
    if (shadow_percent_raw) |value| policy.shadow_percent = clampPercent(value);
    if (policy.mode == .shadow and shadow_percent_raw == null) policy.shadow_percent = @max(policy.shadow_percent, 100);
    if (stringFieldAny(obj, &.{ "salt", "rollout_salt" })) |salt| policy.salt = salt;
    if (boolFieldAny(obj, &.{ "disabled", "rollout_disabled", "kill_switch" })) |disabled| policy.disabled = policy.disabled or disabled;
    policy.required_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "required_scopes", "rollout_required_scopes" }, policy.required_scopes_json);
    policy.blocked_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "blocked_scopes", "rollout_blocked_scopes" }, policy.blocked_scopes_json);
    policy.target_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "target_scopes", "rollout_target_scopes" }, policy.target_scopes_json);
    policy.required_capabilities_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "required_capabilities", "rollout_required_capabilities" }, policy.required_capabilities_json);
    policy.blocked_capabilities_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "blocked_capabilities", "rollout_blocked_capabilities" }, policy.blocked_capabilities_json);
    try policy.validateUsable();
    return policy;
}

fn dupeRolloutPolicy(ctx: *Context, policy: lifecycle.RolloutPolicy) !lifecycle.RolloutPolicy {
    return .{
        .mode = policy.mode,
        .percent = policy.percent,
        .shadow_percent = policy.shadow_percent,
        .salt = try ctx.allocator.dupe(u8, policy.salt),
        .disabled = policy.disabled,
        .required_scopes_json = try ctx.allocator.dupe(u8, policy.required_scopes_json),
        .blocked_scopes_json = try ctx.allocator.dupe(u8, policy.blocked_scopes_json),
        .target_scopes_json = try ctx.allocator.dupe(u8, policy.target_scopes_json),
        .required_capabilities_json = try ctx.allocator.dupe(u8, policy.required_capabilities_json),
        .blocked_capabilities_json = try ctx.allocator.dupe(u8, policy.blocked_capabilities_json),
    };
}

fn rolloutPolicyFieldsJson(ctx: *Context, name: []const u8, feature: []const u8, policy: lifecycle.RolloutPolicy) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.appendSlice(ctx.allocator, "{\"name\":");
    try json.appendString(&out, ctx.allocator, name);
    try out.appendSlice(ctx.allocator, ",\"feature\":");
    try json.appendString(&out, ctx.allocator, feature);
    try out.append(ctx.allocator, ',');
    try api_rollout.appendPolicyJsonFields(ctx, &out, policy);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

test "api rollout policy fields JSON uses strict gate arrays" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    const fields_json = try rolloutPolicyFieldsJson(&ctx, "retrieval", "retrieval", .{
        .mode = .on,
        .required_scopes_json = "[\"team:alpha\"]",
        .required_capabilities_json = "[\"read\"]",
    });
    defer std.testing.allocator.free(fields_json);

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, fields_json, .{});
    defer parsed.deinit();

    const fields = parsed.value.object;
    try std.testing.expectEqualStrings("retrieval", fields.get("name").?.string);
    try std.testing.expectEqualStrings("on", fields.get("mode").?.string);
    try std.testing.expectEqualStrings("team:alpha", fields.get("required_scopes").?.array.items[0].string);
    try std.testing.expectEqualStrings("read", fields.get("required_capabilities").?.array.items[0].string);

    try std.testing.expectError(error.InvalidRawJson, rolloutPolicyFieldsJson(&ctx, "bad", "bad", .{
        .required_scopes_json = "{\"scope\":\"team:alpha\"}",
    }));
}

fn loadRolloutPolicyRecord(ctx: *Context, name: []const u8) !?RolloutPolicyRecord {
    const id = try rolloutPolicyArtifactId(ctx.allocator, name);
    const artifact = (try ctx.store.getArtifact(ctx.allocator, id)) orelse return null;
    if (!std.mem.eql(u8, artifact.artifact_type, rollout_policy_artifact_type)) return null;
    if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return null;

    var parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, artifact.fields_json, .{}) catch return error.InvalidPayload;
    defer parsed.deinit();
    if (parsed.value != .object) return error.InvalidPayload;
    const obj = parsed.value.object;
    const policy_name = stringFieldAny(obj, &.{"name"}) orelse name;
    const feature = stringFieldAny(obj, &.{"feature"}) orelse policy_name;
    var policy = try rolloutPolicyFromObject(ctx, obj, rolloutPolicyBase(feature));
    if (!std.mem.eql(u8, artifact.status, "active")) policy.disabled = true;
    policy = try dupeRolloutPolicy(ctx, policy);
    return .{
        .artifact = artifact,
        .name = try ctx.allocator.dupe(u8, policy_name),
        .feature = try ctx.allocator.dupe(u8, feature),
        .policy = policy,
    };
}

fn appendRolloutPolicyRecordJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), record: RolloutPolicyRecord) !void {
    try out.appendSlice(ctx.allocator, "{\"name\":");
    try json.appendString(out, ctx.allocator, record.name);
    try out.appendSlice(ctx.allocator, ",\"feature\":");
    try json.appendString(out, ctx.allocator, record.feature);
    try out.appendSlice(ctx.allocator, ",\"artifact_id\":");
    try json.appendString(out, ctx.allocator, record.artifact.id);
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(out, ctx.allocator, record.artifact.status);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, record.artifact.scope);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonArray(out, ctx.allocator, record.artifact.permissions_json);
    try out.appendSlice(ctx.allocator, ",\"policy\":");
    try api_rollout.appendPolicyJson(ctx, out, record.policy);
    try out.appendSlice(ctx.allocator, ",\"artifact\":");
    var artifact = record.artifact;
    artifact.source_ids_json = sanitizeSourceIdsForActor(ctx, artifact.source_ids_json) catch return error.InvalidPayload;
    try artifact.writeJson(ctx.allocator, out);
    try out.append(ctx.allocator, '}');
}

test "api rollout policy record JSON rejects malformed artifact permissions" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);

    try std.testing.expectError(error.InvalidRawJson, appendRolloutPolicyRecordJson(&ctx, &out, .{
        .name = "retrieval",
        .feature = "retrieval",
        .policy = .{ .mode = .on },
        .artifact = .{
            .id = "rpol_test",
            .artifact_type = rollout_policy_artifact_type,
            .title = "Rollout policy: retrieval",
            .body = "body",
            .status = "active",
            .owner = null,
            .space_id = null,
            .version = 1,
            .created_at_ms = 1,
            .updated_at_ms = 1,
            .last_verified_at_ms = null,
            .scope = "public",
            .source_ids_json = "[]",
            .related_entities_json = "[]",
            .permissions_json = "{\"scope\":\"public\"}",
            .fields_json = "{}",
            .summary = null,
            .agent_summary = null,
        },
    }));
}

fn rolloutPolicyResponse(ctx: *Context, record: RolloutPolicyRecord) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"rollout_policy\":") catch return serverError(ctx);
    appendRolloutPolicyRecordJson(ctx, &out, record) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn upsertRolloutPolicy(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const name = json.stringField(obj, "name") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing name");
    return upsertRolloutPolicyParsed(ctx, name, obj);
}

fn upsertRolloutPolicyNamed(ctx: *Context, name: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    return upsertRolloutPolicyParsed(ctx, name, parsed.value.object);
}

fn upsertRolloutPolicyParsed(ctx: *Context, name: []const u8, obj: std.json.ObjectMap) HttpResponse {
    const id = rolloutPolicyArtifactId(ctx.allocator, name) catch return serverError(ctx);
    const existing = ctx.store.getArtifact(ctx.allocator, id) catch return serverError(ctx);
    if (existing) |artifact| {
        if (!std.mem.eql(u8, artifact.artifact_type, rollout_policy_artifact_type)) return json.errorResponse(ctx.allocator, 409, "conflict", "Artifact id is already used by a different type");
        if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return rolloutPolicyNotFound(ctx);
    }
    const existing_record = if (existing != null) (loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx)) else null;
    const feature = json.stringField(obj, "feature") orelse if (existing_record) |record| record.feature else name;
    const scope = json.stringField(obj, "scope") orelse if (existing) |artifact| artifact.scope else "workspace";
    const permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, if (existing) |artifact| artifact.permissions_json else "[]") catch |err| return rawJsonRequestError(ctx, err);
    const status = json.stringField(obj, "status") orelse if (existing) |artifact| artifact.status else "active";
    if (!artifacts.validStatus(rollout_policy_artifact_type, status)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid rollout policy status");
    }
    if (!canWriteRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const source_ids_json = payloadArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json" }, if (existing) |artifact| artifact.source_ids_json else "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!sourceIdsCanBackRecord(ctx, source_ids_json, scope, permissions_json)) return forbidden(ctx);
    const space_id = json.nullableStringField(obj, "space_id") orelse if (existing) |artifact| artifact.space_id else null;
    if (!spaceCanContainRecord(ctx, space_id, scope, permissions_json)) return forbidden(ctx);
    const related_entities_json = payloadArrayJson(ctx, obj, &.{ "related_entities", "related_entities_json" }, if (existing) |artifact| artifact.related_entities_json else "[]") catch |err| return rawJsonRequestError(ctx, err);
    const base = if (existing_record) |record| record.policy else rolloutPolicyBase(feature);
    const policy = rolloutPolicyFromObject(ctx, obj, base) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        else => return serverError(ctx),
    };
    const fields_json = rolloutPolicyFieldsJson(ctx, name, feature, policy) catch return serverError(ctx);
    const title = json.stringField(obj, "title") orelse std.fmt.allocPrint(ctx.allocator, "Rollout policy: {s}", .{name}) catch return serverError(ctx);
    const body = json.stringField(obj, "body") orelse "Artifact-backed rollout policy for NullPantry lifecycle and retrieval decisions.";
    const artifact = ctx.store.upsertArtifact(ctx.allocator, .{
        .id = id,
        .artifact_type = rollout_policy_artifact_type,
        .title = title,
        .body = body,
        .status = status,
        .owner = json.nullableStringField(obj, "owner") orelse if (existing) |artifact| artifact.owner else null,
        .space_id = space_id,
        .scope = scope,
        .source_ids_json = source_ids_json,
        .related_entities_json = related_entities_json,
        .permissions_json = permissions_json,
        .fields_json = fields_json,
        .summary = json.nullableStringField(obj, "summary") orelse if (existing) |artifact| artifact.summary else null,
        .agent_summary = json.nullableStringField(obj, "agent_summary") orelse if (existing) |artifact| artifact.agent_summary else null,
        .actor_id = ctx.actor_id,
    }) catch |err| switch (err) {
        error.SpaceNotFound, error.ArtifactAclBroaderThanSpace => return forbidden(ctx),
        error.InvalidPayload => return badJson(ctx),
        error.RelatedEntityNotFound, error.RecordAclBroaderThanRelatedEntity => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    _ = upsertAutoVector(ctx, "artifact", artifact.id, artifact.body, artifact.scope, artifact.permissions_json) catch 0;
    const record = loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx);
    return rolloutPolicyResponse(ctx, record.?);
}

fn getRolloutPolicy(ctx: *Context, name: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const record = loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx);
    if (record == null) return rolloutPolicyNotFound(ctx);
    return rolloutPolicyResponse(ctx, record.?);
}

fn listRolloutPolicies(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const input = primitiveListInputFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    const artifacts_list = ctx.store.listArtifactsVisible(ctx.allocator, input) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"rollout_policies\":[") catch return serverError(ctx);
    var count: usize = 0;
    for (artifacts_list) |artifact| {
        if (!std.mem.eql(u8, artifact.artifact_type, rollout_policy_artifact_type)) continue;
        if (count > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        var parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, artifact.fields_json, .{}) catch return serverError(ctx);
        defer parsed.deinit();
        if (parsed.value != .object) return badJson(ctx);
        const obj = parsed.value.object;
        const name = stringFieldAny(obj, &.{"name"}) orelse artifact.id;
        const feature = stringFieldAny(obj, &.{"feature"}) orelse name;
        var policy = rolloutPolicyFromObject(ctx, obj, rolloutPolicyBase(feature)) catch |err| switch (err) {
            error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
            else => return serverError(ctx),
        };
        if (!std.mem.eql(u8, artifact.status, "active")) policy.disabled = true;
        appendRolloutPolicyRecordJson(ctx, &out, .{ .artifact = artifact, .name = name, .feature = feature, .policy = policy }) catch return serverError(ctx);
        count += 1;
    }
    out.print(ctx.allocator, "],\"count\":{d}}}", .{count}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn deleteRolloutPolicy(ctx: *Context, name: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const record = loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx);
    if (record == null) return rolloutPolicyNotFound(ctx);
    if (!canChangeGraphPrimitiveStatus(ctx, record.?.artifact.scope, record.?.artifact.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchArtifactStatusActor(record.?.artifact.id, "deprecated", ctx.actor_id) catch return serverError(ctx);
    if (!changed) return rolloutPolicyNotFound(ctx);
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "artifact", record.?.artifact.id, record.?.artifact.scope, record.?.artifact.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn evaluateRolloutPolicyEndpoint(ctx: *Context, name: []const u8, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const record = loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx);
    if (record == null) return rolloutPolicyNotFound(ctx);
    const policy = rolloutPolicyFromObject(ctx, obj, record.?.policy) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        else => return serverError(ctx),
    };
    const key = stringFieldAny(obj, &.{ "key", "rollout_key" }) orelse record.?.feature;
    const session_id = nullableStringFieldAny(obj, &.{ "session_id", "session" });
    const result = lifecycle.evaluateRollout(policy, .{
        .key = key,
        .actor_id = ctx.actor_id,
        .session_id = session_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
    });
    auditRolloutDecision(ctx, record.?.artifact.id, record.?.feature, key, session_id, policy, result, "named_policy") catch return serverError(ctx);
    return rolloutDecisionResponse(ctx, record.?.feature, key, session_id, policy, result, record.?.artifact.id);
}

const ExtractionOutput = struct {
    artifact: ?domain.Artifact = null,
    atoms: []domain.MemoryAtom,
    entities: []domain.Entity,
    relations: []domain.Relation = &.{},
    vector_chunks: usize = 0,
    extraction_provider: []const u8 = "heuristic",
    extraction_fallback: bool = false,

    fn addVectorChunks(self: *ExtractionOutput, delta: usize) void {
        var counts = extraction.ResultCounts{ .vector_chunk_count = self.vector_chunks };
        counts.addVectorChunks(delta);
        self.vector_chunks = counts.vector_chunk_count;
    }
};

const ExtractionOptions = struct {
    create_artifact: bool = true,
    extract_memory: bool = true,
    use_llm_extraction: bool = false,
    strict_llm_extraction: bool = false,
    storage_route: store_mod.AgentMemoryStorageRoute = .{},
};

fn extractionOptionsFromObject(ctx: *Context, obj: std.json.ObjectMap, create_artifact_default: bool, extract_memory_default: bool, route_query: []const u8) !ExtractionOptions {
    return extractionOptionsFromObjectOrFallback(ctx, obj, create_artifact_default, extract_memory_default, try storage_routes.fromQuery(ctx.allocator, route_query));
}

fn extractionOptionsFromObjectOrFallback(ctx: *Context, obj: std.json.ObjectMap, create_artifact_default: bool, extract_memory_default: bool, fallback_route: store_mod.AgentMemoryStorageRoute) !ExtractionOptions {
    return .{
        .create_artifact = json.boolField(obj, "create_artifact") orelse create_artifact_default,
        .extract_memory = json.boolField(obj, "extract_memory") orelse extract_memory_default,
        .use_llm_extraction = json.boolField(obj, "use_llm_extraction") orelse json.boolField(obj, "structured_extraction") orelse false,
        .strict_llm_extraction = json.boolField(obj, "strict_llm_extraction") orelse false,
        .storage_route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route),
    };
}

fn ingest(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const title = json.stringField(obj, "title") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing title");
    const scope = json.stringField(obj, "scope") orelse "workspace";
    const permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (!canProposeRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const job_input_json = store_mod.payloadWithStorageRouteJson(ctx.allocator, body, storage_route) catch return serverError(ctx);

    const source = ctx.store.createSource(ctx.allocator, .{
        .source_type = json.stringField(obj, "type") orelse "manual",
        .title = title,
        .raw_content_uri = json.nullableStringField(obj, "raw_content_uri"),
        .content = json.stringField(obj, "content") orelse "",
        .author = json.nullableStringField(obj, "author"),
        .participants_json = payloadArrayJson(ctx, obj, &.{ "participants", "participants_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .permissions_json = permissions_json,
        .scope = scope,
        .checksum = json.nullableStringField(obj, "checksum"),
        .language = json.nullableStringField(obj, "language"),
        .related_entities_json = payloadArrayJson(ctx, obj, &.{ "related_entities", "related_entities_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err),
        .metadata_json = payloadObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{}") catch |err| return rawJsonRequestError(ctx, err),
        .actor_id = ctx.actor_id,
        .storage_route = storage_route,
    }) catch return serverError(ctx);
    const job = ctx.store.createJob(ctx.allocator, .{
        .job_type = "ingest",
        .scope = scope,
        .permissions_json = permissions_json,
        .object_type = "source",
        .object_id = source.id,
        .input_json = job_input_json,
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);

    if (!(json.boolField(obj, "run_now") orelse false)) {
        return queuedExtractionResponse(ctx, job, source);
    }

    const extraction_options = extractionOptionsFromObject(ctx, obj, true, true, route_query) catch |err| return storageRouteError(ctx, err);
    return runExtractionJobNow(ctx, job, source, extraction_options);
}

fn extractMemory(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const source_id = json.stringField(obj, "source_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing source_id");
    const source = (ctx.store.getSource(ctx.allocator, source_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Source not found");
    if (!canProposeRecord(ctx, source.scope, source.permissions_json)) return forbidden(ctx);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const job_input_json = store_mod.payloadWithStorageRouteJson(ctx.allocator, body, storage_route) catch return serverError(ctx);

    const job = ctx.store.createJob(ctx.allocator, .{
        .job_type = "extract_memory",
        .scope = source.scope,
        .permissions_json = source.permissions_json,
        .object_type = "source",
        .object_id = source.id,
        .input_json = job_input_json,
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    if (!(json.boolField(obj, "run_now") orelse false)) {
        return queuedExtractionResponse(ctx, job, source);
    }

    const extraction_options = extractionOptionsFromObject(ctx, obj, true, true, route_query) catch |err| return storageRouteError(ctx, err);
    return runExtractionJobNow(ctx, job, source, extraction_options);
}

fn runExtractionJobNow(ctx: *Context, job: store_mod.Job, source: domain.Source, options: ExtractionOptions) HttpResponse {
    const worker_id = std.fmt.allocPrint(ctx.allocator, "run_now:{s}:{s}", .{ ctx.actor_id, job.id }) catch return serverError(ctx);
    const claimed = ctx.store.claimJobAs(job.id, worker_id) catch return serverError(ctx);
    if (!claimed) return json.errorResponse(ctx.allocator, 409, "job_unavailable", "Job was already claimed");

    const output = runExtraction(ctx, source, options) catch |err| {
        _ = ctx.store.finishJobAs(job.id, "failed", "{}", @errorName(err), worker_id) catch {};
        return serverError(ctx);
    };
    const result_json = extraction.resultJson(
        ctx.allocator,
        source.id,
        .{
            .artifact_count = if (output.artifact == null) @as(usize, 0) else 1,
            .memory_atom_count = output.atoms.len,
            .entity_count = output.entities.len,
            .relation_count = output.relations.len,
            .vector_chunk_count = output.vector_chunks,
        },
        output.extraction_provider,
        output.extraction_fallback,
    ) catch return serverError(ctx);
    if (!(ctx.store.finishJobAs(job.id, "succeeded", result_json, null, worker_id) catch return serverError(ctx))) {
        return json.errorResponse(ctx.allocator, 409, "job_lease_lost", "Job lease was lost before completion");
    }
    const finished = (ctx.store.getJob(ctx.allocator, job.id) catch return serverError(ctx)) orelse job;
    return extractionResponse(ctx, finished, source, output);
}

fn runExtraction(ctx: *Context, source: domain.Source, options: ExtractionOptions) !ExtractionOutput {
    const source_ids_json = try extraction.sourceIdsJson(ctx.allocator, source.id);
    const entity_names_json = try extraction.extractEntityNamesJson(ctx.allocator, source.content);

    var artifact_input: ?store_mod.ArtifactInput = null;
    if (options.create_artifact) {
        const artifact_title = try extraction.sourceTitleForArtifact(ctx.allocator, source.title, source.source_type);
        const summary = try extraction.summarize(ctx.allocator, source.content, 512);
        const agent_summary = try extraction.summarize(ctx.allocator, source.content, 1024);
        artifact_input = .{
            .artifact_type = extraction.artifactTypeForSource(source.source_type),
            .title = artifact_title,
            .body = source.content,
            .status = "draft",
            .owner = source.author,
            .scope = source.scope,
            .source_ids_json = source_ids_json,
            .related_entities_json = entity_names_json,
            .permissions_json = source.permissions_json,
            .summary = summary,
            .agent_summary = agent_summary,
            .actor_id = ctx.actor_id,
            .storage_route = options.storage_route,
        };
    }

    var atom_inputs: std.ArrayListUnmanaged(store_mod.MemoryAtomInput) = .empty;
    var relation_inputs: std.ArrayListUnmanaged(store_mod.ExtractedRelationInput) = .empty;
    var extraction_provider: []const u8 = "heuristic";
    var extraction_fallback = false;
    if (options.extract_memory) {
        var structured_done = false;
        if (options.use_llm_extraction) {
            const prompt = try extraction.memoryExtractionPrompt(ctx.allocator, source.title, source.source_type, source.content);
            defer ctx.allocator.free(prompt);
            const completion: ?providers.CompletionResult = blk: {
                const result = providers.completeWithSystem(ctx.allocator, .{
                    .base_url = ctx.provider.completion.base_url,
                    .api_key = ctx.provider.completion.api_key,
                    .model = ctx.provider.completion.model,
                    .timeout_secs = ctx.provider.completion.timeout_secs,
                    .max_response_bytes = ctx.provider.completion.max_response_bytes,
                    .allow_insecure_http = ctx.provider.completion.allow_insecure_http,
                    .runtime = ctx.provider.runtime(),
                }, "Return only valid JSON for the requested NullPantry extraction schema. Do not include markdown fences unless the model cannot avoid them. Extract only source-grounded memory atoms and relations.", prompt) catch |err| {
                    if (options.strict_llm_extraction) return err;
                    extraction_fallback = true;
                    break :blk null;
                };
                break :blk result;
            };
            defer if (completion) |result| {
                var owned_result = result;
                providers.freeCompletionResult(ctx.allocator, &owned_result);
            };
            if (completion) |result| {
                var maybe_grounded: ?extraction.GroundedStructuredExtraction = null;
                if (extraction.parseGroundedStructuredResponse(ctx.allocator, source.content, result.content, options.strict_llm_extraction)) |grounded_result| {
                    maybe_grounded = grounded_result;
                } else |err| switch (err) {
                    error.InvalidStructuredMemory => {
                        if (options.strict_llm_extraction) return err;
                        extraction_fallback = true;
                    },
                    error.UngroundedEvidence => return err,
                    else => return err,
                }
                if (maybe_grounded) |*grounded| {
                    defer grounded.deinit(ctx.allocator);
                    if (grounded.skipped_ungrounded > 0) extraction_fallback = true;
                    extraction_provider = result.provider;
                    for (grounded.memories) |parsed| {
                        const evidence_ranges_json = try extraction.groundedEvidenceRangeForText(ctx.allocator, source.id, source.content, parsed.evidence orelse parsed.text);
                        try atom_inputs.append(ctx.allocator, .{
                            .subject_entity_id = null,
                            .predicate = parsed.predicate,
                            .object = parsed.object,
                            .text = parsed.text,
                            .scope = source.scope,
                            .confidence = parsed.confidence,
                            .source_ids_json = source_ids_json,
                            .evidence_ranges_json = evidence_ranges_json,
                            .created_by = "agent",
                            .permissions_json = source.permissions_json,
                            .tags_json = parsed.tags_json,
                            .actor_id = ctx.actor_id,
                            .storage_route = options.storage_route,
                        });
                    }
                    for (grounded.relations) |parsed| {
                        try relation_inputs.append(ctx.allocator, .{
                            .from_entity_name = parsed.from_name,
                            .relation_type = parsed.relation_type,
                            .to_entity_name = parsed.to_name,
                            .source_ids_json = source_ids_json,
                            .scope = source.scope,
                            .permissions_json = source.permissions_json,
                            .confidence = parsed.confidence,
                            .status = "proposed",
                            .actor_id = ctx.actor_id,
                        });
                    }
                    structured_done = grounded.acceptedCount() > 0;
                }
            }
        }
        if (!structured_done) {
            extraction_provider = "heuristic";
            var lines = extraction.sourceLineIterator(source.content);
            while (lines.next()) |line| {
                if (extraction.parseMemoryLine(line.text)) |parsed| {
                    const evidence_ranges_json = try extraction.evidenceRangeJson(ctx.allocator, source.id, line.start, line.end, line.line_no);
                    try atom_inputs.append(ctx.allocator, .{
                        .subject_entity_id = null,
                        .predicate = parsed.predicate,
                        .object = parsed.object,
                        .text = parsed.text,
                        .scope = source.scope,
                        .confidence = parsed.confidence,
                        .source_ids_json = source_ids_json,
                        .evidence_ranges_json = evidence_ranges_json,
                        .created_by = "agent",
                        .permissions_json = source.permissions_json,
                        .tags_json = parsed.tags_json,
                        .actor_id = ctx.actor_id,
                        .storage_route = options.storage_route,
                    });
                }
                if (extraction.parseRelationLine(line.text)) |relation| {
                    try relation_inputs.append(ctx.allocator, .{
                        .from_entity_name = relation.from_name,
                        .relation_type = relation.relation_type,
                        .to_entity_name = relation.to_name,
                        .source_ids_json = source_ids_json,
                        .scope = source.scope,
                        .permissions_json = source.permissions_json,
                        .confidence = relation.confidence,
                        .status = "proposed",
                        .actor_id = ctx.actor_id,
                    });
                }
            }
        }
    }

    const applied = try ctx.store.applyExtractedKnowledge(ctx.allocator, .{
        .source = source,
        .source_ids_json = source_ids_json,
        .entity_names_json = entity_names_json,
        .artifact = artifact_input,
        .atoms = atom_inputs.items,
        .relations = relation_inputs.items,
        .actor_id = ctx.actor_id,
    });

    var vector_counts = extraction.ResultCounts{};
    vector_counts.addVectorChunks(try upsertAutoVector(ctx, "source", source.id, source.content, source.scope, source.permissions_json));
    if (applied.artifact) |artifact| {
        vector_counts.addVectorChunks(try upsertAutoVector(ctx, "artifact", artifact.id, artifact.body, artifact.scope, artifact.permissions_json));
    }
    for (applied.entities) |entity| {
        const text = try vector_text.entity(ctx.allocator, entity);
        defer ctx.allocator.free(text);
        vector_counts.addVectorChunks(try upsertAutoVector(ctx, "entity", entity.id, text, entity.scope, entity.permissions_json));
    }
    for (applied.relations) |relation| {
        const text = try vector_text.relation(ctx.allocator, relation);
        defer ctx.allocator.free(text);
        vector_counts.addVectorChunks(try upsertAutoVector(ctx, "relation", relation.id, text, relation.scope, relation.permissions_json));
    }
    for (applied.atoms) |atom| {
        vector_counts.addVectorChunks(try upsertAutoVector(ctx, "memory_atom", atom.id, atom.text, atom.scope, atom.permissions_json));
    }

    return .{ .artifact = applied.artifact, .atoms = applied.atoms, .entities = applied.entities, .relations = applied.relations, .vector_chunks = vector_counts.vector_chunk_count, .extraction_provider = extraction_provider, .extraction_fallback = extraction_fallback };
}

fn resolveExtractedEntities(ctx: *Context, names_json: []const u8, scope: []const u8, permissions_json: []const u8) ![]domain.Entity {
    const parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, names_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return ctx.allocator.alloc(domain.Entity, 0);
    var out: std.ArrayListUnmanaged(domain.Entity) = .empty;
    for (parsed.value.array.items) |item| {
        const name = switch (item) {
            .string => |s| s,
            else => continue,
        };
        try out.append(ctx.allocator, try ctx.store.resolveEntity(ctx.allocator, .{ .entity_type = "project", .name = name, .scope = scope, .permissions_json = permissions_json, .actor_id = ctx.actor_id }));
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn upsertAutoVector(ctx: *Context, object_type: []const u8, object_id: []const u8, text: []const u8, scope: []const u8, permissions_json: []const u8) !usize {
    if (text.len == 0) return 0;
    var count: usize = 0;
    const chunks = try vector_mod.chunkTextWithConfig(ctx.allocator, text, ctx.chunker);
    defer ctx.allocator.free(chunks);
    if (chunks.len == 0) return 0;
    _ = try ctx.store.deleteVectorChunksForObject(ctx.allocator, object_type, object_id, ctx.actor_id);
    for (chunks) |chunk| {
        const chunk_text = chunk.text;
        if (chunk_text.len > 0) {
            const embedding_dimensions = vector_mod.boundedEmbeddingDimensions(null, ctx.provider.embedding.dimensions);
            const heading_path_json = try vector_mod.chunkHeadingPathJson(ctx.allocator, text, chunk);
            defer ctx.allocator.free(heading_path_json);
            const content_hash = try vector_mod.contentHashHex(ctx.allocator, chunk_text);
            defer ctx.allocator.free(content_hash);
            const payload = try store_mod.vectorEmbedPayloadJsonEx(ctx.allocator, .{
                .chunk_ordinal = vector_mod.chunkOrdinalFromIndex(count),
                .text = chunk_text,
                .scope = scope,
                .permissions_json = permissions_json,
                .heading_path_json = heading_path_json,
                .start_byte = @intCast(chunk.start),
                .end_byte = @intCast(chunk.end),
                .content_hash = content_hash,
                .chunk_strategy = chunk.strategy.name(),
                .estimated_tokens = @intCast(chunk.estimated_tokens),
                .transcript_timestamp = chunk.transcript_timestamp,
                .transcript_speaker = chunk.transcript_speaker,
                .model = ctx.provider.embedding.model,
                .dimensions = embedding_dimensions,
            });
            defer ctx.allocator.free(payload);
            const outbox_id = try ctx.store.enqueueVectorOutbox(.{ .action = "embed", .object_type = object_type, .object_id = object_id, .payload_json = payload });
            if (!try ctx.store.claimVectorOutboxAs(outbox_id, ctx.actor_id)) return count;
            var embedding_result = embedTextCachedForPurpose(ctx, embeddingConfigFromContext(ctx, embedding_dimensions), chunk_text, embedding_dimensions, true, api_embedding.default_cache_max_entries, .document) catch {
                _ = try ctx.store.finishVectorOutboxAs(outbox_id, "pending", ctx.actor_id);
                return count;
            };
            defer embedding_result.deinit(ctx.allocator);
            const embedding_json = try vector_mod.embeddingToJson(ctx.allocator, embedding_result.embedding);
            defer ctx.allocator.free(embedding_json);
            const stored_chunk = try ctx.store.upsertVectorChunk(ctx.allocator, .{
                .object_type = object_type,
                .object_id = object_id,
                .chunk_ordinal = vector_mod.chunkOrdinalFromIndex(count),
                .text = chunk_text,
                .scope = scope,
                .permissions_json = permissions_json,
                .heading_path_json = heading_path_json,
                .start_byte = @intCast(chunk.start),
                .end_byte = @intCast(chunk.end),
                .content_hash = content_hash,
                .chunk_strategy = chunk.strategy.name(),
                .estimated_tokens = @intCast(chunk.estimated_tokens),
                .transcript_timestamp = chunk.transcript_timestamp,
                .transcript_speaker = chunk.transcript_speaker,
                .embedding_json = embedding_json,
                .model = embedding_result.model,
                .dimensions = vector_mod.embeddingDimensionsFromLength(embedding_result.embedding.len),
                .actor_id = ctx.actor_id,
            });
            ctx.allocator.free(stored_chunk.id);
            _ = try ctx.store.finishVectorOutboxAs(outbox_id, "embedded", ctx.actor_id);
            count += 1;
        }
    }
    return count;
}

fn extractionResponse(ctx: *Context, job: store_mod.Job, source: domain.Source, output: ExtractionOutput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"job\":") catch return serverError(ctx);
    job.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source\":") catch return serverError(ctx);
    source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"artifact\":") catch return serverError(ctx);
    if (output.artifact) |artifact| artifact.writeJson(ctx.allocator, &out) catch return serverError(ctx) else out.appendSlice(ctx.allocator, "null") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_atoms\":[") catch return serverError(ctx);
    for (output.atoms, 0..) |atom, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        atom.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "],\"entities\":[") catch return serverError(ctx);
    for (output.entities, 0..) |entity, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        entity.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "],\"relations\":[") catch return serverError(ctx);
    for (output.relations, 0..) |relation, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        relation.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.print(ctx.allocator, "],\"vector_chunk_count\":{d},\"extraction_provider\":", .{output.vector_chunks}) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, output.extraction_provider) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"extraction_fallback\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (output.extraction_fallback) "true}" else "false}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn createJob(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const job_type = json.stringField(obj, "type") orelse json.stringField(obj, "job_type") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing job type");
    const job_class = job_types.classify(job_type) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported job type");
    const scope = json.stringField(obj, "scope") orelse defaultJobScope(job_class);
    const permissions_json = jobPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const input_json = jobInputJson(ctx, obj, &.{"input"}, "{}") catch |err| return rawJsonRequestError(ctx, err);
    const allowed = jobMutationAllowed(ctx, job_class, scope, permissions_json, input_json);
    if (!allowed) return forbidden(ctx);
    const object_type = json.stringField(obj, "object_type") orelse "";
    const object_id = json.stringField(obj, "object_id") orelse "";
    if (job_types.isSummarize(job_type)) {
        const input_value = obj.get("input") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Summarize jobs require input object");
        const input_obj = switch (input_value) {
            .object => |input| input,
            else => return json.errorResponse(ctx.allocator, 400, "bad_request", "Summarize jobs require input object"),
        };
        if (summarizeJobInputHasProviderOverride(input_obj)) {
            return json.errorResponse(ctx.allocator, 400, "bad_request", "Provider overrides are not allowed; configure providers on the server");
        }
        if (input_obj.get("messages") == null and json.stringField(input_obj, "session_id") == null and json.stringField(input_obj, "session") == null) {
            return json.errorResponse(ctx.allocator, 400, "bad_request", "Summarize jobs require messages or session_id");
        }
        validateSummarizeJobInput(ctx, input_obj) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.BadRequest => return badJson(ctx),
        };
    }
    validateJobTarget(ctx, job_class, object_type, object_id, scope, permissions_json) catch |err| switch (err) {
        error.InvalidJobTarget => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid job target"),
        error.JobTargetNotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Job target object not found"),
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };
    const job = ctx.store.createJob(ctx.allocator, .{
        .job_type = job_type,
        .scope = scope,
        .permissions_json = permissions_json,
        .object_type = object_type,
        .object_id = object_id,
        .input_json = input_json,
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    return objectResponse(ctx, "job", job);
}

fn jobPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn jobInputJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn defaultJobScope(job_class: job_types.Class) []const u8 {
    return switch (job_class) {
        .vector_outbox, .memory_drain_outbox, .memory_reindex, .vector_rebuild, .vector_reconcile => "admin",
        else => "workspace",
    };
}

fn jobMutationAllowed(ctx: *Context, job_class: job_types.Class, scope: []const u8, permissions_json: []const u8, input_json: []const u8) bool {
    return switch (job_class) {
        .summarize, .ingest => canProposeRecord(ctx, scope, permissions_json),
        .vector_outbox, .memory_drain_outbox, .memory_reindex, .vector_rebuild, .vector_reconcile => vectorMaintenanceJobAllowed(ctx, scope, permissions_json),
        .hygiene => hygieneJobMutationAllowed(ctx, scope, permissions_json, input_json),
        .scan_conflicts, .lucid_projection, .graph_projection => scopedMaintenanceAllowed(ctx, scope, permissions_json, "verify") or scopedMaintenanceAllowed(ctx, scope, permissions_json, "write"),
        .agent_memory_mirror => domain.hasActorScope(ctx.actor_scopes_json, "admin"),
    };
}

fn vectorMaintenanceJobAllowed(ctx: *Context, scope: []const u8, permissions_json: []const u8) bool {
    return domain.hasActorScope(ctx.actor_scopes_json, "admin") and
        std.mem.eql(u8, scope, "admin") and
        domain.permissionsWritable(permissions_json, ctx.actor_scopes_json);
}

fn validateJobTarget(
    ctx: *Context,
    job_class: job_types.Class,
    object_type: []const u8,
    object_id: []const u8,
    job_scope: []const u8,
    job_permissions_json: []const u8,
) !void {
    switch (job_class) {
        .ingest => {
            if (object_id.len == 0 or !std.mem.eql(u8, object_type, "source")) return error.InvalidJobTarget;
            try validateObjectBoundJobTarget(ctx, object_type, object_id, job_scope, job_permissions_json);
        },
        .agent_memory_mirror => {
            if (object_id.len == 0 or !jobMirrorObjectTypeSupported(object_type)) return error.InvalidJobTarget;
            try validateObjectBoundJobTarget(ctx, object_type, object_id, job_scope, job_permissions_json);
        },
        else => {},
    }
}

fn jobMirrorObjectTypeSupported(object_type: []const u8) bool {
    return std.mem.eql(u8, object_type, "source") or
        std.mem.eql(u8, object_type, "artifact") or
        std.mem.eql(u8, object_type, "memory_atom") or
        std.mem.eql(u8, object_type, "entity") or
        std.mem.eql(u8, object_type, "relation") or
        std.mem.eql(u8, object_type, "context_pack");
}

fn validateObjectBoundJobTarget(
    ctx: *Context,
    object_type: []const u8,
    object_id: []const u8,
    job_scope: []const u8,
    job_permissions_json: []const u8,
) !void {
    var acl = (try ctx.store.vectorObjectAcl(ctx.allocator, object_type, object_id, ctx.actor_id)) orelse return error.JobTargetNotFound;
    defer store_mod.freeVectorObjectAcl(ctx.allocator, &acl);
    if (!recordVisibleToActor(ctx, acl.scope, acl.permissions_json)) return error.Forbidden;
    if (!sourceAclCoversTarget(ctx.allocator, acl.scope, acl.permissions_json, job_scope, job_permissions_json)) return error.Forbidden;
}

fn hygieneJobMutationAllowed(ctx: *Context, scope: []const u8, permissions_json: []const u8, input_json: []const u8) bool {
    if (jobInputBool(ctx.allocator, input_json, "hard_delete", false)) {
        return scopedMaintenanceAllowed(ctx, scope, permissions_json, "delete");
    }
    return scopedMaintenanceAllowed(ctx, scope, permissions_json, "verify") or scopedMaintenanceAllowed(ctx, scope, permissions_json, "delete");
}

fn scopedMaintenanceAllowed(ctx: *Context, scope: []const u8, permissions_json: []const u8, capability: []const u8) bool {
    if (!hasCapability(ctx, capability)) return false;
    if (!domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) return false;
    if (std.mem.eql(u8, capability, "write")) return domain.scopeWritable(scope, ctx.actor_scopes_json);
    if (std.mem.eql(u8, capability, "verify")) return domain.scopeVerifiable(scope, ctx.actor_scopes_json);
    if (std.mem.eql(u8, capability, "delete")) return domain.scopeDeletable(scope, ctx.actor_scopes_json);
    return false;
}

fn jobInputBool(allocator: std.mem.Allocator, input_json: []const u8, name: []const u8, fallback: bool) bool {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, input_json, .{}) catch return fallback;
    defer parsed.deinit();
    if (parsed.value != .object) return fallback;
    return json.boolField(parsed.value.object, name) orelse fallback;
}

fn summarizeJobInputHasProviderOverride(obj: std.json.ObjectMap) bool {
    return obj.get("llm_base_url") != null or
        obj.get("llm_api_key") != null or
        obj.get("llm_model") != null or
        obj.get("timeout_secs") != null or
        obj.get("llm_allow_insecure_http") != null or
        obj.get("allow_insecure_http") != null;
}

fn validateSummarizeJobInput(ctx: *Context, obj: std.json.ObjectMap) !void {
    _ = try lifecycleSummarizeSubjectActorId(ctx, obj);

    const has_messages = obj.get("messages") != null;
    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!has_messages and !api_session_access.readAllowed(ctx, sid)) return error.Forbidden;
        const persist = (json.boolField(obj, "persist") orelse false) or (json.boolField(obj, "remember") orelse false);
        if (persist and !api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }
}

fn listJobs(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const status = json.queryParamDecoded(ctx.allocator, query, "status") catch return serverError(ctx);
    const effective_status = if (status != null and std.mem.eql(u8, status.?, "all")) null else status;
    const jobs = ctx.store.listJobs(ctx.allocator, .{
        .scopes_json = ctx.actor_scopes_json,
        .status = effective_status,
        .limit = parseLimit(json.queryParam(query, "limit"), 100),
    }) catch return serverError(ctx);
    return jobsResponse(ctx, jobs);
}

fn getJob(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const job = (ctx.store.getJob(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Job not found");
    if (!recordVisibleToActor(ctx, job.scope, job.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Job not found");
    return objectResponse(ctx, "job", job);
}

fn runJob(ctx: *Context, id: []const u8) HttpResponse {
    const job = (ctx.store.getJob(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Job not found");
    if (!recordVisibleToActor(ctx, job.scope, job.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Job not found");
    const job_class = job_types.classify(job.job_type) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported job type");
    const allowed = jobMutationAllowed(ctx, job_class, job.scope, job.permissions_json, job.input_json);
    if (!allowed) return forbidden(ctx);
    const finished = worker.runJobById(ctx.allocator, ctx.store, id, .{
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
        .provider = ctx.provider,
        .actor_id = ctx.actor_id,
    }) catch |err| switch (err) {
        error.JobNotQueued => return json.errorResponse(ctx.allocator, 409, "conflict", "Job is not queued"),
        else => return serverError(ctx),
    };
    return objectResponse(ctx, "job", finished);
}

fn jobsResponse(ctx: *Context, jobs: []store_mod.Job) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"jobs\":[") catch return serverError(ctx);
    for (jobs, 0..) |job, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        job.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn queuedExtractionResponse(ctx: *Context, job: store_mod.Job, source: domain.Source) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"queued\":true,\"job\":") catch return serverError(ctx);
    job.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source\":") catch return serverError(ctx);
    source.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"run_endpoint\":\"/v1/workers/run\"}") catch return serverError(ctx);
    return .{ .status = "202 Accepted", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn listConflicts(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const status = json.queryParamDecoded(ctx.allocator, query, "status") catch return serverError(ctx);
    const effective_status = if (status != null and std.mem.eql(u8, status.?, "all")) null else (status orelse "open");
    const conflicts = ctx.store.listConflicts(ctx.allocator, .{
        .scopes_json = ctx.actor_scopes_json,
        .status = effective_status,
        .limit = parseLimit(json.queryParam(query, "limit"), 100),
    }) catch return serverError(ctx);
    return conflictsResponse(ctx, conflicts);
}

fn scanConflicts(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "verify") and !hasCapability(ctx, "write")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const conflicts = ctx.store.scanConflicts(ctx.allocator, .{
        .scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx),
        .status = json.nullableStringField(obj, "status") orelse "open",
        .limit = positiveLimit(json.intField(obj, "limit"), 100),
    }) catch return serverError(ctx);
    return conflictsResponse(ctx, conflicts);
}

fn conflictsResponse(ctx: *Context, conflicts: []store_mod.KnowledgeConflict) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"conflicts\":[") catch return serverError(ctx);
    for (conflicts, 0..) |conflict, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        conflict.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn listMemoryAtoms(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const input = primitiveListInputFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    if (input.limit == 0) return emptyPrimitiveList(ctx, "memory_atoms", "memory_atoms", input);
    const atoms = ctx.store.listMemoryAtomsVisible(ctx.allocator, .{
        .limit = input.limit,
        .scopes_json = input.scopes_json,
        .scope_filter_empty = input.scope_filter_empty,
        .actor_id = input.actor_id,
        .include_deprecated = input.include_deprecated,
    }) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"memory_atoms\":[") catch return serverError(ctx);
    for (atoms, 0..) |atom, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        var copy = atom;
        copy.source_ids_json = sanitizeSourceIdsForActor(ctx, atom.source_ids_json) catch return serverError(ctx);
        copy.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    appendPrimitiveListMeta(ctx, &out, "memory_atoms", atoms.len, input) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn getMemoryAtom(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const atom = (ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    if (!recordVisibleToActor(ctx, atom.scope, atom.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    var visible_atom = atom;
    visible_atom.source_ids_json = sanitizeSourceIdsForActor(ctx, atom.source_ids_json) catch return serverError(ctx);
    return objectResponse(ctx, "memory_atom", visible_atom);
}

fn createMemoryAtom(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    const parsed_input = parseMemoryAtomInput(ctx, body, route_query) catch return badJson(ctx);
    var input = parsed_input;
    input.actor_id = ctx.actor_id;
    if (!canCreateMemoryAtom(ctx, input)) return forbidden(ctx);
    input = ensureMemoryProvenance(ctx, input) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };
    const atom = ctx.store.createMemoryAtom(ctx.allocator, input) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    _ = upsertAutoVector(ctx, "memory_atom", atom.id, atom.text, atom.scope, atom.permissions_json) catch 0;
    return objectResponse(ctx, "memory_atom", atom);
}

fn remember(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    return createMemoryAtom(ctx, body, route_query);
}

fn patchMemoryAtom(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    if (!canChangeMemoryStatus(ctx, id, status)) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    const existing = (ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchMemoryAtomStatusActor(id, status, std.mem.eql(u8, status, "verified"), ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    appendMemoryAtomLifecycleFeedEvent(ctx, existing, status, json.stringField(parsed.value.object, "reason"), payload_json) catch return serverError(ctx);
    const atom = ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx);
    return objectResponse(ctx, "memory_atom", atom.?);
}

fn deleteMemoryAtom(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const existing = (ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    if (!canChangeMemoryStatus(ctx, id, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchMemoryAtomStatusActor(id, "deprecated", false, ctx.actor_id) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    appendMemoryAtomLifecycleFeedEvent(ctx, existing, "deprecated", null, "{\"deleted\":true}") catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

const StatusActionResponseField = enum {
    forgotten,
    verified,
    stale,
    superseded,

    fn name(self: StatusActionResponseField) []const u8 {
        return switch (self) {
            .forgotten => "forgotten",
            .verified => "verified",
            .stale => "stale",
            .superseded => "superseded",
        };
    }
};

fn appendStatusActionField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), field: StatusActionResponseField, changed: bool) !void {
    try out.append(allocator, '{');
    try json.appendString(out, allocator, field.name());
    try out.append(allocator, ':');
    try out.appendSlice(allocator, if (changed) "true" else "false");
}

fn statusAction(ctx: *Context, body: []const u8, status: []const u8, verified: bool, response_field: StatusActionResponseField, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (json.stringField(obj, "object_type")) |object_type| {
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            return statusActionAgentMemory(ctx, obj, body, status, response_field, route_query);
        }
    }
    const id = json.stringField(obj, "id") orelse json.stringField(obj, "memory_atom_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing id");
    if (!canChangeMemoryStatus(ctx, id, status)) return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    const existing = (ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Memory atom not found");
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, obj) catch return badJson(ctx);
    const changed = ctx.store.patchMemoryAtomStatusActor(id, status, verified, ctx.actor_id) catch return serverError(ctx);
    if (changed) {
        appendMemoryAtomLifecycleFeedEvent(ctx, existing, status, json.stringField(obj, "reason"), payload_json) catch return serverError(ctx);
    }
    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendStatusActionField(ctx.allocator, &out, response_field, changed) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, id) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendMemoryAtomLifecycleFeedEvent(ctx: *Context, atom: domain.MemoryAtom, status: []const u8, reason: ?[]const u8, original_payload_json: []const u8) !void {
    const operation = primitiveLifecycleOperationForStatus(status);
    const payload_json = try primitiveLifecyclePayloadJson(ctx, operation, status, reason, original_payload_json, null);
    try appendPrimitiveLifecycleFeedEvent(ctx, "memory_atom", atom.id, atom.scope, atom.permissions_json, operation, payload_json);
}

fn statusActionAgentMemory(ctx: *Context, obj: std.json.ObjectMap, body: []const u8, status: []const u8, response_field: StatusActionResponseField, route_query: []const u8) HttpResponse {
    const operation = feed_contract.agentMemoryLifecycleOperationForStatus(status);
    const object_id = json.stringField(obj, "object_id") orelse json.stringField(obj, "key") orelse json.stringField(obj, "id");
    const request_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const input = buildAppliedAgentMemoryLifecycleInput(ctx, operation, body, object_id, ctx.actor_id, request_route, .fallback_authoritative, null) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found"),
        error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be changed through lifecycle endpoints"),
        error.MissingKey, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory lifecycle payload must include key/object_id"),
        else => return serverError(ctx),
    };
    const changed = ctx.store.patchAgentMemoryStatusRoutedOrderedWithAuth(ctx.allocator, input.key, input.session_id, input.owner_actor_id, input.status, ctx.actor_id, ctx.actor_scopes_json, ctx.actor_capabilities_json, input.route, null) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found");

    const payload_json = agentMemoryLifecyclePayloadJson(ctx, input) catch return serverError(ctx);
    const event_type = std.fmt.allocPrint(ctx.allocator, "agent_memory.{s}", .{operation}) catch return serverError(ctx);
    const event_id = applyOrAppendFeedEventRecord(ctx, obj, event_type, operation, "agent_memory", input.key, input.scope, input.permissions_json, ctx.actor_id, "{}", payload_json) catch |err| switch (err) {
        error.FeedConflict => return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying"),
        error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendStatusActionField(ctx.allocator, &out, response_field, true) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"object_type\":\"agent_memory\",\"key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"status\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.status) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"event_id\":{d}}}", .{event_id}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn agentMemoryLifecyclePayloadJson(ctx: *Context, input: AgentMemoryLifecycleApplyInput) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '{');
    try appendJsonStringField(ctx.allocator, &out, "key", input.key, true);
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(&out, ctx.allocator, input.session_id);
    try appendJsonStringField(ctx.allocator, &out, "scope", input.scope, false);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonArray(&out, ctx.allocator, input.permissions_json);
    try appendJsonStringField(ctx.allocator, &out, "owner_id", input.owner_actor_id, false);
    try appendJsonStringField(ctx.allocator, &out, "status", input.status, false);
    try storage_routes.appendExtractionJson(ctx.allocator, &out, input.route);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

test "api agent memory lifecycle payload preserves permissions ACL" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    const payload = try agentMemoryLifecyclePayloadJson(&ctx, .{
        .key = "agent.lifecycle.pref",
        .session_id = "sess_1",
        .owner_actor_id = "agent:a",
        .scope = "agent:agent:a",
        .permissions_json = "[\"actor:agent:a\"]",
        .status = "verified",
    });
    defer std.testing.allocator.free(payload);

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, payload, .{});
    defer parsed.deinit();

    const root = parsed.value.object;
    try std.testing.expectEqualStrings("agent.lifecycle.pref", root.get("key").?.string);
    try std.testing.expectEqualStrings("sess_1", root.get("session_id").?.string);
    try std.testing.expectEqualStrings("actor:agent:a", root.get("permissions").?.array.items[0].string);
    try std.testing.expectEqualStrings("agent:a", root.get("owner_id").?.string);
    try std.testing.expectEqualStrings("verified", root.get("status").?.string);
}

test "api agent memory lifecycle payload rejects malformed permissions" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    try std.testing.expectError(error.InvalidRawJson, agentMemoryLifecyclePayloadJson(&ctx, .{
        .key = "agent.lifecycle.bad_acl",
        .session_id = null,
        .owner_actor_id = "agent:a",
        .scope = "agent:agent:a",
        .permissions_json = "{\"actor\":\"agent:a\"}",
        .status = "verified",
    }));
}

fn parseMemoryAtomInput(ctx: *Context, body: []const u8, route_query: []const u8) !store_mod.MemoryAtomInput {
    var parsed = try parseBody(ctx, body);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const text = json.stringField(obj, "text") orelse json.stringField(obj, "content") orelse return error.MissingText;
    return .{
        .subject_entity_id = try dupOptional(ctx.allocator, json.nullableStringField(obj, "subject_entity_id")),
        .predicate = try ctx.allocator.dupe(u8, json.stringField(obj, "predicate") orelse "states"),
        .object = try ctx.allocator.dupe(u8, json.stringField(obj, "object") orelse ""),
        .text = try ctx.allocator.dupe(u8, text),
        .scope = try ctx.allocator.dupe(u8, json.stringField(obj, "scope") orelse "workspace"),
        .confidence = json.floatField(obj, "confidence") orelse 0.5,
        .status = try dupOptional(ctx.allocator, json.nullableStringField(obj, "status")),
        .source_ids_json = try payloadArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json" }, "[]"),
        .evidence_ranges_json = try payloadArrayJson(ctx, obj, &.{ "evidence_ranges", "evidence_ranges_json" }, "[]"),
        .created_by = try ctx.allocator.dupe(u8, json.stringField(obj, "created_by") orelse "human"),
        .valid_from_ms = json.intField(obj, "valid_from_ms"),
        .valid_until_ms = json.intField(obj, "valid_until_ms"),
        .owner = try dupOptional(ctx.allocator, json.nullableStringField(obj, "owner")),
        .permissions_json = try payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]"),
        .tags_json = try payloadArrayJson(ctx, obj, &.{ "tags", "tags_json" }, "[]"),
        .storage_route = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query),
    };
}

fn search(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "";
    const input = buildSearchInput(ctx, obj, query, searchLimit(json.intField(obj, "limit"), 10), false, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    const use_cache = json.boolField(obj, "use_cache") orelse true;
    const use_semantic_cache = json.boolField(obj, "use_semantic_cache") orelse false;
    const cache_ttl_ms = json.intField(obj, "cache_ttl_ms") orelse 0;
    const cache_key = api_cache_keys.responseKey(ctx, "search", body, input) catch return serverError(ctx);
    const semantic_embedding = if (use_semantic_cache) api_cache.optionalSemanticEmbedding(ctx, obj, query) else null;
    const semantic_cache_prefix = if (use_semantic_cache) blk: {
        var semantic_input = input;
        if (semantic_embedding) |embedding| {
            semantic_input.query_embedding_provider = embedding.provider;
            semantic_input.embedding_dimensions = embedding.dimensions;
        }
        break :blk api_cache_keys.semanticPrefix(ctx, "search", semantic_input, false, false, "none") catch return serverError(ctx);
    } else null;
    if (use_cache) {
        if (ctx.store.getResponseCacheForScopes(ctx.allocator, cache_key, ids.nowMs(), input.scopes_json, ctx.actor_id) catch return serverError(ctx)) |hit| {
            return .{ .status = "200 OK", .body = hit.response_json };
        }
        if (use_semantic_cache) {
            if (semantic_embedding) |embedding| {
                if (ctx.store.searchSemanticCache(ctx.allocator, .{
                    .embedding_json = embedding.embedding_json,
                    .embedding_provider = embedding.provider,
                    .embedding_model = embedding.model,
                    .embedding_dimensions = embedding.dimensions,
                    .scopes_json = input.scopes_json,
                    .actor_id = ctx.actor_id,
                    .cache_key_prefix = semantic_cache_prefix,
                    .min_score = @floatCast(json.floatField(obj, "semantic_cache_min_score") orelse 0.94),
                    .candidate_limit = api_cache.semanticCacheCandidateLimit(obj, "semantic_cache_candidate_limit"),
                }) catch return serverError(ctx)) |hit| {
                    return .{ .status = "200 OK", .body = hit.response_json };
                }
            }
        }
    }
    const pipeline = runSearchPipeline(ctx, obj, query, input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const response = searchResponse(ctx, pipeline.results);
    if (cache_ttl_ms > 0 and hasCapability(ctx, "write")) {
        ctx.store.putResponseCache(.{ .cache_key = cache_key, .response_json = response.body, .scopes_json = input.scopes_json, .actor_id = ctx.actor_id, .ttl_ms = cache_ttl_ms, .token_count = api_cache.estimateTokenCount(response.body), .max_entries = api_cache.maxEntries(obj, "cache_max_entries") }) catch return serverError(ctx);
        if (use_semantic_cache) {
            if (semantic_embedding) |embedding| {
                const semantic_cache_key = if (semantic_cache_prefix) |prefix|
                    std.fmt.allocPrint(ctx.allocator, "{s}{s}", .{ prefix, cache_key }) catch return serverError(ctx)
                else
                    cache_key;
                ctx.store.putSemanticCache(.{
                    .cache_key = semantic_cache_key,
                    .query = query,
                    .response_json = response.body,
                    .embedding_json = embedding.embedding_json,
                    .embedding_provider = embedding.provider,
                    .embedding_model = embedding.model,
                    .embedding_dimensions = embedding.dimensions,
                    .scopes_json = input.scopes_json,
                    .actor_id = ctx.actor_id,
                    .ttl_ms = cache_ttl_ms,
                    .token_count = api_cache.estimateTokenCount(response.body),
                    .max_entries = api_cache.maxEntries(obj, "cache_max_entries"),
                }) catch return serverError(ctx);
            }
        }
    }
    return response;
}

fn vectorUpsert(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const object_id = json.stringField(obj, "object_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing object_id");
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    const requested_scope = json.stringField(obj, "scope") orelse "workspace";
    const requested_permissions = vectorArrayJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const heading_path_json = vectorArrayJson(ctx, obj, &.{ "heading_path", "heading_path_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
    var acl = resolveVectorAcl(ctx, object_type, object_id, requested_scope, requested_permissions) catch |err| switch (err) {
        error.NotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Vector target object not found"),
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };
    defer store_mod.freeVectorObjectAcl(ctx.allocator, &acl);
    const embedding_json = vectorArrayJson(ctx, obj, &.{"embedding"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const dims = json.intField(obj, "dimensions") orelse blk: {
        const parsed_embedding = vector_mod.embeddingFromJson(ctx.allocator, embedding_json) catch return badJson(ctx);
        defer ctx.allocator.free(parsed_embedding);
        break :blk vector_mod.embeddingDimensionsFromLength(parsed_embedding.len);
    };
    const chunk = ctx.store.upsertVectorChunk(ctx.allocator, .{
        .object_type = object_type,
        .object_id = object_id,
        .chunk_ordinal = json.intField(obj, "chunk_ordinal") orelse 0,
        .text = json.stringField(obj, "text") orelse "",
        .scope = acl.scope,
        .permissions_json = acl.permissions_json,
        .heading_path_json = heading_path_json,
        .start_byte = json.intField(obj, "start_byte") orelse json.intField(obj, "chunk_start_byte") orelse 0,
        .end_byte = json.intField(obj, "end_byte") orelse json.intField(obj, "chunk_end_byte") orelse 0,
        .content_hash = json.stringField(obj, "content_hash") orelse "",
        .chunk_strategy = json.stringField(obj, "chunk_strategy") orelse json.stringField(obj, "strategy") orelse "manual",
        .estimated_tokens = json.intField(obj, "estimated_tokens") orelse 0,
        .transcript_timestamp = json.nullableStringField(obj, "transcript_timestamp"),
        .transcript_speaker = json.nullableStringField(obj, "transcript_speaker"),
        .embedding_json = embedding_json,
        .model = json.nullableStringField(obj, "model"),
        .dimensions = dims,
        .actor_id = ctx.actor_id,
    }) catch |err| switch (err) {
        error.InvalidVectorTarget => return json.errorResponse(ctx.allocator, 404, "not_found", "Vector target object not found"),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendVectorChunkUpsertResponse(ctx, &out, chunk) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendVectorChunkUpsertResponse(ctx: *Context, out: *std.ArrayListUnmanaged(u8), chunk: store_mod.VectorChunk) !void {
    try out.appendSlice(ctx.allocator, "{\"vector_chunk\":{\"id\":");
    try json.appendString(out, ctx.allocator, chunk.id);
    try out.appendSlice(ctx.allocator, ",\"object_id\":");
    try json.appendString(out, ctx.allocator, chunk.object_id);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, chunk.scope);
    try out.appendSlice(ctx.allocator, ",\"heading_path\":");
    try json.appendRawJsonArray(out, ctx.allocator, chunk.heading_path_json);
    try out.print(ctx.allocator, ",\"start_byte\":{d},\"end_byte\":{d},\"content_hash\":", .{ chunk.start_byte, chunk.end_byte });
    try json.appendString(out, ctx.allocator, chunk.content_hash);
    try out.appendSlice(ctx.allocator, ",\"chunk_strategy\":");
    try json.appendString(out, ctx.allocator, chunk.chunk_strategy);
    try out.print(ctx.allocator, ",\"estimated_tokens\":{d},\"transcript_timestamp\":", .{chunk.estimated_tokens});
    try json.appendNullableString(out, ctx.allocator, chunk.transcript_timestamp);
    try out.appendSlice(ctx.allocator, ",\"transcript_speaker\":");
    try json.appendNullableString(out, ctx.allocator, chunk.transcript_speaker);
    try out.print(ctx.allocator, ",\"dimensions\":{d}", .{chunk.dimensions});
    try out.appendSlice(ctx.allocator, "}}");
}

test "api vector upsert response rejects malformed stored heading path" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);

    try std.testing.expectError(error.InvalidRawJson, appendVectorChunkUpsertResponse(&ctx, &out, .{
        .id = "vec_bad_heading",
        .object_type = "memory_atom",
        .object_id = "mem_1",
        .chunk_ordinal = 0,
        .text = "body",
        .scope = "public",
        .permissions_json = "[]",
        .heading_path_json = "{\"heading\":\"Intro\"}",
        .embedding_json = "[1,0]",
        .model = null,
        .dimensions = 2,
        .created_at_ms = 1,
        .updated_at_ms = 1,
    }));
