fn vectorSearch(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const embedding_json = vectorArrayJson(ctx, obj, &.{"embedding"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const matches = ctx.store.vectorSearch(ctx.allocator, .{
        .embedding_json = embedding_json,
        .scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx),
        .limit = positiveLimit(json.intField(obj, "limit"), 10),
        .min_score = @floatCast(minRelevanceFromObject(obj)),
        .include_deprecated = json.boolField(obj, "include_deprecated") orelse false,
        .strict_external = json.boolField(obj, "strict_external") orelse json.boolField(obj, "strict_vector") orelse false,
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    defer vector_mod.freeMatches(ctx.allocator, matches);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"matches\":[") catch return serverError(ctx);
    for (matches, 0..) |match, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        match.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn vectorArrayJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn vectorDelete(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const vector_id = json.stringField(obj, "vector_id") orelse json.stringField(obj, "id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing vector_id");
    var chunk = (ctx.store.getVectorChunk(ctx.allocator, vector_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Vector chunk not found");
    defer store_mod.freeVectorChunk(ctx.allocator, &chunk);
    if (!vectorChunkDeletable(ctx, chunk)) return forbidden(ctx);
    const deleted = ctx.store.deleteVectorChunk(ctx.allocator, vector_id, ctx.actor_id) catch return serverError(ctx);
    if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Vector chunk not found");
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"vector_delete\":{\"vector_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, vector_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"deleted\":true,\"external_delete_enqueued\":true}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn vectorChunkDeletable(ctx: *Context, chunk: store_mod.VectorChunk) bool {
    if (!aclDeletable(ctx, chunk.scope, chunk.permissions_json)) return false;
    var target_acl = (ctx.store.vectorObjectAcl(ctx.allocator, chunk.object_type, chunk.object_id, ctx.actor_id) catch return false) orelse return domain.hasActorScope(ctx.actor_scopes_json, "admin");
    defer store_mod.freeVectorObjectAcl(ctx.allocator, &target_acl);
    return aclDeletable(ctx, target_acl.scope, target_acl.permissions_json);
}

fn aclDeletable(ctx: *Context, scope: []const u8, permissions_json: []const u8) bool {
    if (!domain.scopeDeletable(scope, ctx.actor_scopes_json)) return false;
    if (!domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) return false;
    const policy = ctx.store.getPolicyScope(ctx.allocator, scope) catch return false;
    if (policy) |p| return domain.permissionsWritable(p.permissions_json, ctx.actor_scopes_json);
    return true;
}

fn memoryReindex(ctx: *Context, body: []const u8) HttpResponse {
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin")) return forbidden(ctx);
    const effective_body = optionalJsonObjectBody(body);
    var parsed = parseBody(ctx, effective_body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const result = ctx.store.rebuildVectorIndex(ctx.allocator, .{
        .limit = api_vector.maintenanceLimit(json.intField(obj, "limit")),
        .reset_external = json.boolField(obj, "reset_external") orelse false,
        .retry_failed = json.boolField(obj, "retry_failed") orelse false,
    }) catch return serverError(ctx);
    return memoryReindexResponse(ctx, result);
}

fn memoryReindexResponse(ctx: *Context, result: store_mod.VectorMaintenanceResult) HttpResponse {
    const external_sinks = ctx.store.vectorExternalSinksJson(ctx.allocator) catch return serverError(ctx);
    defer ctx.allocator.free(external_sinks);
    const body = std.fmt.allocPrint(
        ctx.allocator,
        "{{\"reindexed\":{d},\"skipped\":false,\"memory_reindex\":{{\"canonical_chunks\":{d},\"enqueued_upserts\":{d},\"requeued_failed\":{d},\"external_enabled\":{s},\"active_sink\":\"{s}\",\"local_engine\":\"{s}\",\"search_engine\":\"{s}\",\"external_sinks\":{s}}}}}",
        .{
            result.enqueued_upserts,
            result.canonical_chunks,
            result.enqueued_upserts,
            result.requeued_failed,
            if (result.external_enabled) "true" else "false",
            ctx.store.vectorBackendName(),
            ctx.store.localVectorEngineName(),
            ctx.store.effectiveVectorSearchEngineName(),
            external_sinks,
        },
    ) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn memoryDrainOutbox(ctx: *Context, body: []const u8) HttpResponse {
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin")) return forbidden(ctx);
    const effective_body = optionalJsonObjectBody(body);
    var parsed = parseBody(ctx, effective_body) catch return badJson(ctx);
    defer parsed.deinit();
    const limit = worker.requestOutboxLimit(json.intField(parsed.value.object, "limit"));
    const result = worker.runVectorOutboxOnce(ctx.allocator, ctx.store, .{
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
        .outbox_limit = limit,
        .provider = ctx.provider,
        .use_embedding_cache = json.boolField(parsed.value.object, "use_embedding_cache") orelse json.boolField(parsed.value.object, "use_cache") orelse true,
        .embedding_cache_max_entries = embeddingCacheMaxEntries(parsed.value.object),
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    const pending = ctx.store.countVectorOutbox("pending") catch return serverError(ctx);
    const embedded = ctx.store.countVectorOutbox("embedded") catch return serverError(ctx);
    const indexed_local = ctx.store.countVectorOutbox("indexed_local") catch return serverError(ctx);
    const indexed_external = ctx.store.countVectorOutbox("indexed_external") catch return serverError(ctx);
    const deleted_external = ctx.store.countVectorOutbox("deleted_external") catch return serverError(ctx);
    const external_sinks = ctx.store.vectorExternalSinksJson(ctx.allocator) catch return serverError(ctx);
    defer ctx.allocator.free(external_sinks);
    const response = std.fmt.allocPrint(
        ctx.allocator,
        "{{\"drained\":{d},\"failed\":{d},\"memory_outbox\":{{\"processed\":{d},\"pending\":{d},\"embedded\":{d},\"indexed_local\":{d},\"indexed_external\":{d},\"deleted_external\":{d},\"active_sink\":\"{s}\",\"local_engine\":\"{s}\",\"search_engine\":\"{s}\",\"external_sinks\":{s}}}}}",
        .{ result.processed, result.failed, result.processed, pending, embedded, indexed_local, indexed_external, deleted_external, ctx.store.vectorBackendName(), ctx.store.localVectorEngineName(), ctx.store.effectiveVectorSearchEngineName(), external_sinks },
    ) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn retrievalPlan(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing query");
    const use_vector_requested = json.boolField(obj, "use_vector") orelse true;
    const session_id = nullableStringFieldAny(obj, &.{"session_id"});
    const rollout = evaluateRetrievalRollout(ctx, obj, query, session_id) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        else => return serverError(ctx),
    };
    const has_vector_index = (ctx.store.countVectorChunks() catch 0) > 0 and use_vector_requested and rollout.enabled;
    const adaptive_config = adaptiveConfigFromObject(ctx, obj);
    const rrf_config = rrfConfigFromObject(obj);
    const allow_reranker = (json.boolField(obj, "allow_reranker") orelse false) and ctx.provider.completion.base_url != null and ctx.provider.completion.model != null;
    var plan = retrieval.buildPlanWithAdaptive(ctx.allocator, query, has_vector_index, allow_reranker, adaptive_config) catch return serverError(ctx);
    plan.min_relevance = minRelevanceFromObject(obj);
    applyRrfConfigToPlan(&plan, rrf_config);
    plan.mmr_lambda = mmrLambdaFromObject(obj);
    plan.mmr_candidate_multiplier = mmrCandidateMultiplierFromObject(obj);
    if (!build_options.enable_engine_kg) plan.use_graph = false;
    defer plan.deinit(ctx.allocator);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"plan\":{") catch return serverError(ctx);
    appendRetrievalPlanFields(ctx, &out, plan, rerankCandidateLimitFromObject(obj), strictRerankerFromObject(obj)) catch return serverError(ctx);
    appendRetrievalRolloutFields(ctx, &out, .{
        .query = query,
        .use_vector = has_vector_index,
        .rollout_mode = rollout.mode,
        .rollout_decision = rollout.decision,
        .rollout_reason = rollout.reason,
        .rollout_bucket = rollout.bucket,
        .rollout_vector_requested = use_vector_requested,
        .rollout_shadow_vector = rollout.shadow and use_vector_requested,
    }, plan.use_vector) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendRetrievalPlanFields(ctx: *Context, out: *std.ArrayListUnmanaged(u8), plan: retrieval.RetrievalPlan, rerank_candidate_limit: u32, strict_reranker: bool) !void {
    try out.appendSlice(ctx.allocator, "\"use_keyword\":");
    try out.appendSlice(ctx.allocator, if (plan.use_keyword) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"use_vector\":");
    try out.appendSlice(ctx.allocator, if (plan.use_vector) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"use_graph\":");
    try out.appendSlice(ctx.allocator, if (plan.use_graph) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"use_reranker\":");
    try out.appendSlice(ctx.allocator, if (plan.use_reranker) "true" else "false");
    try out.print(ctx.allocator, ",\"rerank_candidate_limit\":{d}", .{rerank_candidate_limit});
    try out.appendSlice(ctx.allocator, ",\"strict_reranker\":");
    try out.appendSlice(ctx.allocator, if (strict_reranker) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"adaptive_enabled\":");
    try out.appendSlice(ctx.allocator, if (plan.adaptive_enabled) "true" else "false");
    try out.print(ctx.allocator, ",\"adaptive_keyword_max_tokens\":{d}", .{plan.adaptive_keyword_max_tokens});
    try out.print(ctx.allocator, ",\"adaptive_vector_min_tokens\":{d}", .{plan.adaptive_vector_min_tokens});
    try out.appendSlice(ctx.allocator, ",\"strategy\":");
    try json.appendString(out, ctx.allocator, plan.strategy.name());
    try out.print(ctx.allocator, ",\"token_count\":{d}", .{plan.token_count});
    try out.appendSlice(ctx.allocator, ",\"has_special_chars\":");
    try out.appendSlice(ctx.allocator, if (plan.has_special_chars) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"is_question\":");
    try out.appendSlice(ctx.allocator, if (plan.is_question) "true" else "false");
    try out.print(ctx.allocator, ",\"avg_token_length\":{d:.3}", .{plan.avg_token_length});
    try out.print(ctx.allocator, ",\"min_relevance\":{d:.6}", .{plan.min_relevance});
    try out.print(ctx.allocator, ",\"rrf_k\":{d:.6}", .{plan.rrf_k});
    try out.print(ctx.allocator, ",\"rrf_weight\":{d:.6}", .{plan.rrf_weight});
    try out.print(ctx.allocator, ",\"raw_score_weight\":{d:.6}", .{plan.raw_score_weight});
    try out.print(ctx.allocator, ",\"rrf_window_multiplier\":{d}", .{plan.rrf_window_multiplier});
    try out.print(ctx.allocator, ",\"mmr_lambda\":{d:.6}", .{plan.mmr_lambda});
    try out.print(ctx.allocator, ",\"mmr_candidate_multiplier\":{d}", .{plan.mmr_candidate_multiplier});
    try out.appendSlice(ctx.allocator, ",\"query_expanded\":");
    try out.appendSlice(ctx.allocator, if (plan.query_expanded) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"expanded_query\":");
    try json.appendString(out, ctx.allocator, plan.expanded_query);
    try out.appendSlice(ctx.allocator, ",\"keyword_query\":");
    try json.appendString(out, ctx.allocator, plan.keyword_query);
    try out.appendSlice(ctx.allocator, ",\"websearch_query\":");
    try json.appendString(out, ctx.allocator, plan.websearch_query);
    try out.appendSlice(ctx.allocator, ",\"expansion_terms\":");
    try out.appendSlice(ctx.allocator, plan.expansion_terms_json);
    try out.appendSlice(ctx.allocator, ",\"expansion_reasons\":");
    try out.appendSlice(ctx.allocator, plan.expansion_reasons_json);
    try out.appendSlice(ctx.allocator, ",\"intent_hints\":");
    try out.appendSlice(ctx.allocator, plan.intent_hints_json);
}

fn appendRetrievalRolloutFields(ctx: *Context, out: *std.ArrayListUnmanaged(u8), input: store_mod.SearchInput, plan_use_vector: bool) !void {
    try out.appendSlice(ctx.allocator, ",\"rollout\":{\"mode\":");
    try json.appendString(out, ctx.allocator, input.rollout_mode.name());
    try out.appendSlice(ctx.allocator, ",\"decision\":");
    try json.appendString(out, ctx.allocator, input.rollout_decision.name());
    try out.appendSlice(ctx.allocator, ",\"reason\":");
    try json.appendString(out, ctx.allocator, input.rollout_reason);
    try out.print(ctx.allocator, ",\"bucket\":{d}", .{input.rollout_bucket});
    try out.appendSlice(ctx.allocator, ",\"vector_requested\":");
    try out.appendSlice(ctx.allocator, if (input.rollout_vector_requested) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"vector_allowed\":");
    try out.appendSlice(ctx.allocator, if (input.use_vector and input.rollout_decision == .enabled) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"vector_served\":");
    try out.appendSlice(ctx.allocator, if (plan_use_vector) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"shadow_vector\":");
    try out.appendSlice(ctx.allocator, if (input.rollout_shadow_vector) "true" else "false");
    try out.append(ctx.allocator, '}');
}

fn rolloutDecisionResponse(ctx: *Context, feature: []const u8, key: []const u8, session_id: ?[]const u8, policy: lifecycle.RolloutPolicy, result: lifecycle.RolloutResult, policy_artifact_id: ?[]const u8) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"rollout\":{\"feature\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, feature) catch return serverError(ctx);
    if (policy_artifact_id) |id| {
        out.appendSlice(ctx.allocator, ",\"policy_artifact_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, id) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, ",\"key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.actor_id) catch return serverError(ctx);
    if (session_id) |sid| {
        out.appendSlice(ctx.allocator, ",\"session_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, sid) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, ",\"mode\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, result.mode.name()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"decision\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, result.decision.name()) catch return serverError(ctx);
    out.print(
        ctx.allocator,
        ",\"enabled\":{s},\"shadow\":{s},\"percent\":{d},\"shadow_percent\":{d},\"bucket\":{d},\"reason\":",
        .{ if (result.enabled) "true" else "false", if (result.shadow) "true" else "false", result.percent, result.shadow_percent, result.bucket },
    ) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, result.reason) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"policy\":") catch return serverError(ctx);
    api_rollout.appendPolicyJson(ctx, &out, policy) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"subject\":{\"key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.actor_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"session_id\":") catch return serverError(ctx);
    json.appendNullableString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn rolloutDecisionAuditPayloadJson(ctx: *Context, feature: []const u8, key: []const u8, session_id: ?[]const u8, policy: lifecycle.RolloutPolicy, result: lifecycle.RolloutResult, source: ?[]const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.appendSlice(ctx.allocator, "{\"feature\":");
    try json.appendString(&out, ctx.allocator, feature);
    try out.appendSlice(ctx.allocator, ",\"key\":");
    try json.appendString(&out, ctx.allocator, key);
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(&out, ctx.allocator, session_id);
    if (source) |value| {
        try out.appendSlice(ctx.allocator, ",\"source\":");
        try json.appendString(&out, ctx.allocator, value);
    }
    try out.appendSlice(ctx.allocator, ",\"mode\":");
    try json.appendString(&out, ctx.allocator, result.mode.name());
    try out.appendSlice(ctx.allocator, ",\"decision\":");
    try json.appendString(&out, ctx.allocator, result.decision.name());
    try out.print(ctx.allocator, ",\"enabled\":{s},\"shadow\":{s},\"bucket\":{d},\"reason\":", .{ if (result.enabled) "true" else "false", if (result.shadow) "true" else "false", result.bucket });
    try json.appendString(&out, ctx.allocator, result.reason);
    try out.appendSlice(ctx.allocator, ",\"policy\":");
    try api_rollout.appendPolicyJson(ctx, &out, policy);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn auditRolloutDecision(ctx: *Context, object_id: []const u8, feature: []const u8, key: []const u8, session_id: ?[]const u8, policy: lifecycle.RolloutPolicy, result: lifecycle.RolloutResult, source: ?[]const u8) !void {
    const payload_json = try rolloutDecisionAuditPayloadJson(ctx, feature, key, session_id, policy, result, source);
    try ctx.store.appendAuditEvent(ctx.allocator, "rollout.decision", ctx.actor_id, "rollout_policy", object_id, payload_json);
}

fn appendActualRerankFields(ctx: *Context, out: *std.ArrayListUnmanaged(u8), llm_rerank_eligible: bool, rerank_attempted: bool, rerank_applied: bool) !void {
    try out.appendSlice(ctx.allocator, ",\"llm_rerank_eligible\":");
    try out.appendSlice(ctx.allocator, if (llm_rerank_eligible) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"llm_rerank_attempted\":");
    try out.appendSlice(ctx.allocator, if (rerank_attempted) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"llm_rerank_applied\":");
    try out.appendSlice(ctx.allocator, if (rerank_applied) "true" else "false");
}

fn appendRetrievalStages(ctx: *Context, out: *std.ArrayListUnmanaged(u8), input: store_mod.SearchInput, plan: retrieval.RetrievalPlan, llm_rerank_attempted: bool, llm_rerank_applied: bool) !void {
    try out.appendSlice(ctx.allocator, ",\"stages\":[");
    var first = true;
    try appendStage(ctx, out, &first, "acl_filter");
    if (input.rollout_decision != .enabled) try appendStage(ctx, out, &first, "rollout_gate");
    if (input.rollout_shadow_vector) try appendStage(ctx, out, &first, "shadow_vector");
    if (plan.query_expanded) try appendStage(ctx, out, &first, "query_expansion");
    if (plan.use_keyword) try appendStage(ctx, out, &first, "keyword");
    if (input.use_vector and input.query_embedding_json != null and plan.use_vector) {
        try appendStage(ctx, out, &first, "vector_ann");
        try appendStage(ctx, out, &first, "rrf");
    }
    if (plan.use_graph) try appendStage(ctx, out, &first, "graph_expansion");
    if (input.min_relevance > 0) try appendStage(ctx, out, &first, "min_relevance");
    if (input.use_temporal_decay) try appendStage(ctx, out, &first, "temporal_decay");
    if (input.use_mmr) try appendStage(ctx, out, &first, "mmr");
    if (llm_rerank_applied) {
        try appendStage(ctx, out, &first, "llm_rerank");
    } else if (llm_rerank_attempted) {
        try appendStage(ctx, out, &first, "llm_rerank_fallback");
    }
    try appendStage(ctx, out, &first, "limit");
    try appendStage(ctx, out, &first, "citation_assembly");
    try out.append(ctx.allocator, ']');
}

fn appendStage(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, stage: []const u8) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try json.appendString(out, ctx.allocator, stage);
}

fn searchResultSameIdentity(a: domain.SearchResult, b: domain.SearchResult) bool {
    return std.mem.eql(u8, a.result_type, b.result_type) and std.mem.eql(u8, a.id, b.id) and std.mem.eql(u8, a.store, b.store);
}

fn searchResultOverlap(left: []const domain.SearchResult, right: []const domain.SearchResult) usize {
    var overlap: usize = 0;
    for (left) |a| {
        for (right) |b| {
            if (searchResultSameIdentity(a, b)) {
                overlap += 1;
                break;
            }
        }
    }
    return overlap;
}

fn shadowVectorAuditPayloadJson(ctx: *Context, input: store_mod.SearchInput, baseline_count: usize, shadow_count: usize, overlap: usize) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.appendSlice(ctx.allocator, "{\"query_hash\":");
    const hash = std.hash.Wyhash.hash(0, input.query);
    try out.append(ctx.allocator, '"');
    try out.print(ctx.allocator, "{x}", .{hash});
    try out.append(ctx.allocator, '"');
    try out.print(ctx.allocator, ",\"baseline_count\":{d},\"shadow_count\":{d},\"overlap\":{d},\"limit\":{d}", .{ baseline_count, shadow_count, overlap, input.limit });
    try out.appendSlice(ctx.allocator, ",\"rollout_mode\":");
    try json.appendString(&out, ctx.allocator, input.rollout_mode.name());
    try out.appendSlice(ctx.allocator, ",\"rollout_reason\":");
    try json.appendString(&out, ctx.allocator, input.rollout_reason);
    try out.appendSlice(ctx.allocator, ",\"scopes\":");
    try json.appendRawJsonArray(&out, ctx.allocator, input.scopes_json);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

test "api shadow vector audit payload preserves scopes" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    const payload = try shadowVectorAuditPayloadJson(&ctx, .{
        .query = "shadow query",
        .limit = 7,
        .scopes_json = "[\"team:alpha\"]",
        .rollout_mode = .shadow,
        .rollout_reason = "shadow_percent",
    }, 3, 4, 2);
    defer std.testing.allocator.free(payload);

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, payload, .{});
    defer parsed.deinit();

    const root = parsed.value.object;
    try std.testing.expectEqual(@as(i64, 3), root.get("baseline_count").?.integer);
    try std.testing.expectEqual(@as(i64, 4), root.get("shadow_count").?.integer);
    try std.testing.expectEqual(@as(i64, 2), root.get("overlap").?.integer);
    try std.testing.expectEqual(@as(i64, 7), root.get("limit").?.integer);
    try std.testing.expectEqualStrings("shadow", root.get("rollout_mode").?.string);
    try std.testing.expectEqualStrings("team:alpha", root.get("scopes").?.array.items[0].string);
}

test "api shadow vector audit payload rejects malformed scopes" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    try std.testing.expectError(error.InvalidRawJson, shadowVectorAuditPayloadJson(&ctx, .{
        .query = "shadow query",
        .scopes_json = "{\"scope\":\"team:alpha\"}",
        .rollout_mode = .shadow,
    }, 1, 1, 1));
}

fn maybeRunShadowVectorSearch(ctx: *Context, input: store_mod.SearchInput, baseline_results: []const domain.SearchResult) void {
    if (!input.rollout_shadow_vector or input.query.len == 0) return;
    var shadow_input = input;
    shadow_input.use_vector = true;
    shadow_input.strict_vector = false;
    shadow_input.rollout_shadow_vector = false;
    shadow_input.rollout_decision = .enabled;
    shadow_input.rollout_reason = "shadow_side_run";
    const shadow_results = ctx.store.search(ctx.allocator, shadow_input) catch return;
    const overlap = searchResultOverlap(baseline_results, shadow_results);
    const payload_json = shadowVectorAuditPayloadJson(ctx, input, baseline_results.len, shadow_results.len, overlap) catch return;
    ctx.store.appendAuditEvent(ctx.allocator, "rollout.shadow_vector", ctx.actor_id, "rollout_policy", "retrieval", payload_json) catch return;
}

fn retrievalSearch(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing query");
    const limit = resultLimit(json.intField(obj, "limit"), 10);
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const include_deprecated = json.boolField(obj, "include_deprecated") orelse false;
    const use_vector = json.boolField(obj, "use_vector") orelse true;
    const allow_reranker = json.boolField(obj, "allow_reranker") orelse true;
    var input = buildSearchInput(ctx, obj, query, limit, false, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    const has_vector_index = (ctx.store.countVectorChunks() catch 0) > 0;
    input.scopes_json = scopes_json;
    input.include_deprecated = include_deprecated;
    input.use_vector = input.use_vector and use_vector and has_vector_index;
    input.allow_reranker = allow_reranker;
    const llm_rerank_eligible = api_search_window.llmRerankEffective(ctx.provider, input);
    var plan = retrieval.buildPlanWithAdaptive(ctx.allocator, query, input.use_vector, llm_rerank_eligible, .{
        .enabled = input.adaptive_retrieval,
        .keyword_max_tokens = input.adaptive_keyword_max_tokens,
        .vector_min_tokens = input.adaptive_vector_min_tokens,
    }) catch return serverError(ctx);
    plan.min_relevance = input.min_relevance;
    applyRrfConfigToPlan(&plan, .{
        .k = input.rrf_k,
        .rrf_weight = input.rrf_weight,
        .raw_score_weight = input.raw_score_weight,
        .window_multiplier = input.rrf_window_multiplier,
    });
    defer plan.deinit(ctx.allocator);
    var graph_command = graph_mod.parseCommand(ctx.allocator, query) catch |err| switch (err) {
        error.InvalidGraphCommand => return badJson(ctx),
        else => return serverError(ctx),
    };
    defer if (graph_command) |*command| command.deinit(ctx.allocator);
    if (graph_command != null) {
        plan.use_keyword = false;
        plan.use_vector = false;
        plan.use_graph = true;
    } else if (api_storage_route.includesKg(input.agent_memory_route)) {
        plan.use_graph = true;
    }
    const pipeline = runSearchPipeline(ctx, obj, query, input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"plan\":{") catch return serverError(ctx);
    appendRetrievalPlanFields(ctx, &out, plan, input.rerank_candidate_limit, input.strict_reranker) catch return serverError(ctx);
    appendActualRerankFields(ctx, &out, llm_rerank_eligible, pipeline.rerank_attempted, pipeline.rerank_applied) catch return serverError(ctx);
    appendRetrievalRolloutFields(ctx, &out, input, plan.use_vector) catch return serverError(ctx);
    appendRetrievalStages(ctx, &out, input, plan, pipeline.rerank_attempted, pipeline.rerank_applied) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "},\"results\":") catch return serverError(ctx);
    appendSearchArray(ctx, &out, pipeline.results) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"groups\":") catch return serverError(ctx);
    appendSearchGroups(ctx, &out, pipeline.results) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn workersRun(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "verify")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const result = worker.runOnce(ctx.allocator, ctx.store, .{
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
        .job_limit = worker.requestJobLimit(json.intField(parsed.value.object, "job_limit")),
        .outbox_limit = worker.requestOutboxLimit(json.intField(parsed.value.object, "outbox_limit")),
        .provider = ctx.provider,
        .use_embedding_cache = json.boolField(parsed.value.object, "use_embedding_cache") orelse json.boolField(parsed.value.object, "use_cache") orelse true,
        .embedding_cache_max_entries = embeddingCacheMaxEntries(parsed.value.object),
        .actor_id = ctx.actor_id,
    }) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"worker_run\":{{\"jobs_checked\":{d},\"jobs_succeeded\":{d},\"jobs_failed\":{d},\"vector_outbox_processed\":{d},\"vector_outbox_failed\":{d},\"lucid_projection_processed\":{d},\"lucid_projection_failed\":{d}}}}}", .{ result.jobs_checked, result.jobs_succeeded, result.jobs_failed, result.vector_outbox_processed, result.vector_outbox_failed, result.lucid_projection_processed, result.lucid_projection_failed }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn nullClawMemoryFeed(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    if (since_id < effective_floor) return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted projection cursor floor; request a checkpoint");
    const events = listCentralFeedEventsByObjectTypeRouteMode(ctx, since_id, limit, feed_scopes, true, "agent_memory", storage_route, .nullclaw_agent_memory) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor; request a checkpoint"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    return nullClawFeedEventsResponse(ctx, events);
}

fn nullClawMemoryFeedStatus(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    var status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, "agent_memory", storage_route, effective_floor, .nullclaw_agent_memory) catch return serverError(ctx);
    status = feedStatusWithLocalOriginSequence(ctx, status, projection.name) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    status.writeJsonWithInstance(ctx.allocator, &out, ctx.feed_instance_id) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn nullClawMemoryFeedCompact(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "feed_apply") and (hasCapability(ctx, "export") or hasCapability(ctx, "delete")))) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const requested_before_id = feedCompactCursorFromObject(parsed.value.object);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    const status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, "agent_memory", storage_route, effective_floor, .nullclaw_agent_memory) catch return serverError(ctx);
    const before_id = requested_before_id orelse status.max_event_id;
    const result = if (projection.object_type) |object_type|
        ctx.store.compactFeedProjection(projection.name, object_type, before_id, ctx.actor_id) catch return serverError(ctx)
    else
        ctx.store.compactFeedCursorProjection(projection.name, before_id, ctx.actor_id) catch return serverError(ctx);
    const response_floor = @max(result.cursor_floor, effective_floor);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d},\"projection\":", .{ response_floor, response_floor, store_mod.feedSequenceAfter(response_floor), result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, if (projection.object_type != null) nullclaw_agent_memory_projection else "storage_route") catch return serverError(ctx);
    if (projection.object_type == null) {
        out.appendSlice(ctx.allocator, ",\"route\":") catch return serverError(ctx);
        storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn nullClawMemoryFeedCheckpoint(ctx: *Context, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "read") and hasCapability(ctx, "export"))) return forbidden(ctx);
    if (wantsNullClawCheckpointNdjson(query)) return nullClawAgentMemoryCheckpointNdjson(ctx, query);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    const status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, "agent_memory", storage_route, effective_floor, .nullclaw_agent_memory) catch return serverError(ctx);
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 500);
    const events = listCentralFeedEventsByObjectTypeRouteMode(ctx, since_id, limit, feed_scopes, true, "agent_memory", storage_route, .nullclaw_agent_memory) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"instance_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.feed_instance_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ status.cursor_floor, status.cursor_floor, status.max_event_id, status.max_event_id }) catch return serverError(ctx);
    var frontiers_written: usize = 0;
    appendNativeCheckpointFrontierProjection(ctx, &out, projection.name, &frontiers_written) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"events\":[") catch return serverError(ctx);
    _ = appendFeedEventsForActorMode(ctx, &out, events, .nullclaw_agent_memory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn nullClawMemoryFeedCheckpointRestore(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    if (isNullClawNdjsonCheckpointPayload(ctx.allocator, body)) {
        return memoryFeedCheckpointRestoreInternal(ctx, body, query, projection);
    }
    const transformed = nullClawCheckpointToNativeFeedCheckpoint(ctx, body) catch |err| switch (err) {
        error.NotNullClawCheckpoint => return memoryFeedCheckpointRestoreInternal(ctx, body, query, projection),
        else => return badJson(ctx),
    };
    defer ctx.allocator.free(transformed);
    return memoryFeedCheckpointRestoreInternal(ctx, transformed, query, projection);
}

fn feedProjectionCursorName(ctx: *Context, projection: []const u8) ![]const u8 {
    return std.fmt.allocPrint(ctx.allocator, "{s}:actor:{s}", .{ projection, ctx.actor_id });
}

fn objectTypeProjectionEffectiveCursorFloor(ctx: *Context, scopes_json: []const u8, projection_name: []const u8) !i64 {
    const projection_floor = try ctx.store.feedProjectionCursorFloor(ctx.allocator, projection_name);
    const global_status = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    return @max(projection_floor, global_status.cursor_floor);
}

fn nullClawFeedProjectionForRoute(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !FeedProjectionCompaction {
    if (try nullClawFeedRouteProjectionName(ctx, route)) |projection| return .{ .name = projection };
    return .{ .name = try feedProjectionCursorName(ctx, nullclaw_agent_memory_projection), .object_type = "agent_memory" };
}

fn projectionEffectiveCursorFloor(ctx: *Context, scopes_json: []const u8, projection: FeedProjectionCompaction) !i64 {
    const projection_floor = try ctx.store.feedProjectionCursorFloor(ctx.allocator, projection.name);
    const global_status = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    return @max(projection_floor, global_status.cursor_floor);
}

fn centralRuntimeFeedProjectionForRoute(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !FeedProjectionCompaction {
    if (try feedRouteProjectionNameWithKind(ctx, runtime_object_types_projection, route)) |projection| return .{ .name = projection };
    return .{ .name = try feedProjectionCursorName(ctx, runtime_object_types_projection) };
}

fn centralRuntimeFeedProjectionName(name: []const u8) bool {
    return std.mem.startsWith(u8, name, runtime_object_types_projection);
}

fn nullClawMemoryFeedApply(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    if (isNullClawNdjsonCheckpointPayload(ctx.allocator, body)) return nullClawMemoryFeedCheckpointRestore(ctx, body, query);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (checkpointEventsValue(obj) != null) return nullClawMemoryFeedCheckpointRestore(ctx, body, query);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    if (json.stringField(obj, "key") != null and json.stringField(obj, "object_type") == null) {
        const transformed = nullClawEventToNativeFeedEvent(ctx, obj) catch return badJson(ctx);
        defer ctx.allocator.free(transformed);
        return applyMemoryEventWithOriginProjection(ctx, transformed, query, projection.name);
    }
    return applyMemoryEventWithOriginProjection(ctx, body, query, projection.name);
}

fn memoryFeed(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeed(ctx, runtime, query);
    }
    if (runtimeFeedQuerySelected(query)) {
        return centralRuntimeMemoryFeed(ctx, storage_route, query);
    }
    const wire_mode = feedWireModeFromQuery(query);
    if (feedObjectTypeFromQuery(query, wire_mode)) |object_type| {
        if (feedObjectTypeSelectionError(ctx, object_type, wire_mode)) |response| return response;
        const since_id = feedCursorFromQuery(query);
        const limit = parseLimit(json.queryParam(query, "limit"), 100);
        const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
        defer ctx.allocator.free(feed_scopes);
        const projection = feedProjectionForObjectTypeRoute(ctx, object_type, storage_route, wire_mode) catch return serverError(ctx);
        defer if (projection) |p| ctx.allocator.free(p.name);
        var ignore_cursor_floor = false;
        const effective_floor = if (projection) |p| blk: {
            ignore_cursor_floor = true;
            break :blk projectionEffectiveCursorFloor(ctx, feed_scopes, p) catch return serverError(ctx);
        } else if (routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx)) |floor| blk: {
            ignore_cursor_floor = true;
            break :blk floor;
        } else null;
        if (effective_floor) |floor| {
            if (since_id < floor) return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Filtered feed cursor is older than the compacted cursor floor; request a checkpoint");
        }
        const events = listCentralFeedEventsByObjectTypeRouteMode(ctx, since_id, limit, feed_scopes, ignore_cursor_floor, object_type, storage_route, wire_mode) catch |err| switch (err) {
            error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Filtered feed cursor is older than the compacted cursor floor; request a checkpoint"),
            else => return serverError(ctx),
        };
        defer store_mod.freeFeedEvents(ctx.allocator, events);
        return if (wire_mode == .nullclaw_agent_memory) nullClawFeedEventsResponse(ctx, events) else feedEventsResponse(ctx, events);
    }
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const effective_floor = routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx);
    if (effective_floor) |floor| {
        if (since_id < floor) return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted storage-route cursor floor; request a checkpoint");
    }
    const events = listCentralFeedEventsForRoute(ctx, since_id, limit, feed_scopes, effective_floor != null, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor; request a checkpoint"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    return feedEventsResponse(ctx, events);
}

fn memoryFeedStatus(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedStatus(ctx, runtime);
    }
    if (runtimeFeedQuerySelected(query)) {
        return centralRuntimeMemoryFeedStatus(ctx, storage_route);
    }
    const wire_mode = feedWireModeFromQuery(query);
    if (feedObjectTypeFromQuery(query, wire_mode)) |object_type| {
        if (feedObjectTypeSelectionError(ctx, object_type, wire_mode)) |response| return response;
        const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
        defer ctx.allocator.free(feed_scopes);
        const projection = feedProjectionForObjectTypeRoute(ctx, object_type, storage_route, wire_mode) catch return serverError(ctx);
        defer if (projection) |p| ctx.allocator.free(p.name);
        const effective_floor = if (projection) |p|
            projectionEffectiveCursorFloor(ctx, feed_scopes, p) catch return serverError(ctx)
        else if (routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx)) |floor|
            floor
        else blk: {
            const base = ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
            break :blk base.cursor_floor;
        };
        var status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, object_type, storage_route, effective_floor, wire_mode) catch return serverError(ctx);
        var owned_origin_projection: ?[]const u8 = null;
        defer if (owned_origin_projection) |value| ctx.allocator.free(value);
        const origin_projection = if (projection) |p| p.name else blk: {
            owned_origin_projection = feedOriginProjectionForMemoryStatus(ctx, storage_route) catch return serverError(ctx);
            break :blk owned_origin_projection.?;
        };
        status = feedStatusWithLocalOriginSequence(ctx, status, origin_projection) catch return serverError(ctx);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        status.writeJsonWithInstance(ctx.allocator, &out, ctx.feed_instance_id) catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    var status = if (routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx)) |floor|
        centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, floor) catch return serverError(ctx)
    else
        centralFeedStatusForRoute(ctx, feed_scopes, storage_route) catch return serverError(ctx);
    const origin_projection = feedOriginProjectionForMemoryStatus(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(origin_projection);
    status = feedStatusWithLocalOriginSequence(ctx, status, origin_projection) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    status.writeJsonWithInstance(ctx.allocator, &out, ctx.feed_instance_id) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memoryFeedCompact(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "feed_apply") and (hasCapability(ctx, "export") or hasCapability(ctx, "delete")))) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const requested_before_id = feedCompactCursorFromObject(parsed.value.object);
    if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedCompact(ctx, runtime, requested_before_id);
    }
    if (runtimeFeedQuerySelected(query)) {
        return centralRuntimeMemoryFeedCompact(ctx, storage_route, requested_before_id);
    }
    const wire_mode = feedWireModeFromQuery(query);
    const selected_object_type = json.stringField(parsed.value.object, "object_type") orelse feedObjectTypeFromQuery(query, wire_mode);
    if (selected_object_type) |object_type| {
        if (feedObjectTypeSelectionError(ctx, object_type, wire_mode)) |response| return response;
        const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
        defer ctx.allocator.free(feed_scopes);
        const projection = (feedProjectionForObjectTypeRoute(ctx, object_type, storage_route, wire_mode) catch return serverError(ctx)) orelse
            return json.errorResponse(ctx.allocator, 400, "bad_request", "Object-type feed compaction requires a compactable projection");
        defer ctx.allocator.free(projection.name);
        const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
        const status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, object_type, storage_route, effective_floor, wire_mode) catch return serverError(ctx);
        const before_id = requested_before_id orelse status.max_event_id;
        const result = if (projection.object_type) |projection_object_type|
            ctx.store.compactFeedProjection(projection.name, projection_object_type, before_id, ctx.actor_id) catch return serverError(ctx)
        else
            ctx.store.compactFeedCursorProjection(projection.name, before_id, ctx.actor_id) catch return serverError(ctx);
        const response_floor = @max(result.cursor_floor, effective_floor);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d},\"projection\":", .{ response_floor, response_floor, store_mod.feedSequenceAfter(response_floor), result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, if (projection.object_type != null) object_type else "storage_route") catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"object_type\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, object_type) catch return serverError(ctx);
        if (projection.object_type == null) {
            out.appendSlice(ctx.allocator, ",\"route\":") catch return serverError(ctx);
            storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
        }
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    if (feedRouteProjectionName(ctx, storage_route) catch return serverError(ctx)) |projection_name| {
        defer ctx.allocator.free(projection_name);
        const projection_floor = ctx.store.feedProjectionCursorFloor(ctx.allocator, projection_name) catch return serverError(ctx);
        const status = centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, projection_floor) catch return serverError(ctx);
        const before_id = requested_before_id orelse status.max_event_id;
        const result = ctx.store.compactFeedCursorProjection(projection_name, before_id, ctx.actor_id) catch return serverError(ctx);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d},\"projection\":\"storage_route\",\"route\":", .{ result.cursor_floor, result.cursor_floor, store_mod.feedSequenceAfter(result.cursor_floor), result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
        storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }
    const status = ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
    const before_id = requested_before_id orelse status.max_event_id;
    const result = ctx.store.compactFeed(before_id, ctx.actor_id) catch return serverError(ctx);
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d}}}", .{ result.cursor_floor, result.cursor_floor, result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn feedCompactCursorFromObject(obj: std.json.ObjectMap) ?i64 {
    return json.intField(obj, "before_id") orelse
        json.intField(obj, "before_event_id") orelse
        json.intField(obj, "before_sequence") orelse
        json.intField(obj, "through_id") orelse
        json.intField(obj, "through_sequence");
}

fn memoryFeedCheckpoint(ctx: *Context, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "read") and hasCapability(ctx, "export"))) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    if (wantsNullClawCheckpointNdjson(query)) return agentMemoryCheckpointNdjsonForRoute(ctx, query, storage_route);
    if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedCheckpoint(ctx, runtime, query);
    }
    if (runtimeFeedQuerySelected(query)) {
        return centralRuntimeMemoryFeedCheckpoint(ctx, storage_route, query);
    }
    const wire_mode = feedWireModeFromQuery(query);
    if (feedObjectTypeFromQuery(query, wire_mode)) |object_type| {
        if (feedObjectTypeSelectionError(ctx, object_type, wire_mode)) |response| return response;
        const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
        defer ctx.allocator.free(feed_scopes);
        const projection = feedProjectionForObjectTypeRoute(ctx, object_type, storage_route, wire_mode) catch return serverError(ctx);
        defer if (projection) |p| ctx.allocator.free(p.name);
        const effective_floor = if (projection) |p|
            projectionEffectiveCursorFloor(ctx, feed_scopes, p) catch return serverError(ctx)
        else if (routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx)) |floor|
            floor
        else blk: {
            const base = ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
            break :blk base.cursor_floor;
        };
        const status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, object_type, storage_route, effective_floor, wire_mode) catch return serverError(ctx);
        const since_id = feedCursorFromQuery(query);
        const limit = parseLimit(json.queryParam(query, "limit"), 500);
        const events = listCentralFeedEventsByObjectTypeRouteMode(ctx, since_id, limit, feed_scopes, true, object_type, storage_route, wire_mode) catch |err| switch (err) {
            error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Filtered feed cursor is older than the compacted cursor floor"),
            else => return serverError(ctx),
        };
        defer store_mod.freeFeedEvents(ctx.allocator, events);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        out.appendSlice(ctx.allocator, "{\"instance_id\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, ctx.feed_instance_id) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"object_type\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, object_type) catch return serverError(ctx);
        out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ status.cursor_floor, status.cursor_floor, status.max_event_id, status.max_event_id }) catch return serverError(ctx);
        var frontiers_written: usize = 0;
        if (projection) |p| {
            appendNativeCheckpointFrontierProjection(ctx, &out, p.name, &frontiers_written) catch return serverError(ctx);
        } else {
            frontiers_written = appendNativeCheckpointFrontiersForRoute(ctx, &out, storage_route, false) catch return serverError(ctx);
        }
        out.appendSlice(ctx.allocator, "],\"events\":[") catch return serverError(ctx);
        _ = appendFeedEventsForActorMode(ctx, &out, events, wire_mode) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const status = if (routeEffectiveCursorFloor(ctx, storage_route, feed_scopes) catch return serverError(ctx)) |floor|
        centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, floor) catch return serverError(ctx)
    else
        ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 500);
    const events = listCentralFeedEventsForRoute(ctx, since_id, limit, feed_scopes, true, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"instance_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.feed_instance_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ status.cursor_floor, status.cursor_floor, status.max_event_id, status.max_event_id }) catch return serverError(ctx);
    _ = appendNativeCheckpointFrontiersForRoute(ctx, &out, storage_route, false) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"events\":[") catch return serverError(ctx);
    _ = appendFeedEventsForActor(ctx, &out, events) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendNativeCheckpointFrontiersForRoute(ctx: *Context, out: *std.ArrayListUnmanaged(u8), route: store_mod.AgentMemoryStorageRoute, agent_memory_only: bool) !usize {
    var written: usize = 0;
    if (try feedRouteProjectionName(ctx, route)) |projection_name| {
        defer ctx.allocator.free(projection_name);
        try appendNativeCheckpointFrontierProjection(ctx, out, projection_name, &written);
        return written;
    }
    if (!agent_memory_only) {
        try appendNativeCheckpointFrontierProjection(ctx, out, global_feed_origin_projection, &written);
    }
    const agent_projection = try feedProjectionCursorName(ctx, nullclaw_agent_memory_projection);
    defer ctx.allocator.free(agent_projection);
    try appendNativeCheckpointFrontierProjection(ctx, out, agent_projection, &written);
    const route_projection_prefix = try feedRouteProjectionPrefix(ctx);
    defer ctx.allocator.free(route_projection_prefix);
    try appendNativeCheckpointFrontierProjectionPrefix(ctx, out, route_projection_prefix, &written);
    return written;
}

fn appendNativeCheckpointFrontierProjection(ctx: *Context, out: *std.ArrayListUnmanaged(u8), projection: []const u8, written: *usize) !void {
    const frontiers = try ctx.store.listFeedOriginFrontiers(ctx.allocator, projection);
    defer store_mod.freeFeedOriginFrontiers(ctx.allocator, frontiers);
    for (frontiers) |frontier| {
        if (written.* > 0) try out.append(ctx.allocator, ',');
        try appendNativeCheckpointFrontierObject(ctx, out, frontier);
        written.* += 1;
    }
}

fn appendNativeCheckpointFrontierProjectionPrefix(ctx: *Context, out: *std.ArrayListUnmanaged(u8), projection_prefix: []const u8, written: *usize) !void {
    const frontiers = try ctx.store.listFeedOriginFrontiersByProjectionPrefix(ctx.allocator, projection_prefix);
    defer store_mod.freeFeedOriginFrontiers(ctx.allocator, frontiers);
    for (frontiers) |frontier| {
        if (written.* > 0) try out.append(ctx.allocator, ',');
        try appendNativeCheckpointFrontierObject(ctx, out, frontier);
        written.* += 1;
    }
}

fn appendNativeCheckpointFrontierObject(ctx: *Context, out: *std.ArrayListUnmanaged(u8), frontier: store_mod.FeedOriginFrontier) !void {
    try out.append(ctx.allocator, '{');
    try json.appendString(out, ctx.allocator, "projection");
    try out.append(ctx.allocator, ':');
    try json.appendString(out, ctx.allocator, frontier.projection);
    try out.appendSlice(ctx.allocator, ",\"origin_instance_id\":");
    try json.appendString(out, ctx.allocator, frontier.origin_instance_id);
    try out.print(ctx.allocator, ",\"origin_sequence\":{d},\"updated_at_ms\":{d}", .{ frontier.origin_sequence, frontier.updated_at_ms });
    try out.append(ctx.allocator, '}');
}

fn feedRouteProjectionPrefix(ctx: *Context) ![]const u8 {
    return feedRouteProjectionPrefixWithKind(ctx, "memory_feed_route");
}

fn feedRouteProjectionPrefixWithKind(ctx: *Context, kind: []const u8) ![]const u8 {
    return std.fmt.allocPrint(ctx.allocator, "{s}:actor:{s}:", .{ kind, ctx.actor_id });
}

fn agentMemoryEventOrderFromFeedObject(obj: std.json.ObjectMap) ?store_mod.AgentMemoryEventOrder {
    const timestamp_ms = json.intField(obj, "timestamp_ms") orelse return null;
    const origin_instance_id = json.stringField(obj, "origin_instance_id") orelse
        json.stringField(obj, "source_instance_id") orelse
        return null;
    const origin_sequence = json.intField(obj, "origin_sequence") orelse
        json.intField(obj, "source_sequence") orelse
        return null;
    return .{
        .timestamp_ms = timestamp_ms,
        .origin_instance_id = origin_instance_id,
        .origin_sequence = origin_sequence,
    };
}

fn feedRuntimeForRoute(ctx: *Context, route: store_mod.AgentMemoryStorageRoute, query: []const u8) !?*agent_memory_runtime.Runtime {
    return switch (route.target) {
        .primary, .native => null,
        .runtime => if (ctx.store.agent_memory.isExternal() and runtimeFeedSelected(&ctx.store.agent_memory, query)) &ctx.store.agent_memory else null,
        .named => blk: {
            const name = route.name orelse return error.AgentMemoryStorageUnavailable;
            const runtime = ctx.store.agent_memory_stores.get(name) orelse return error.AgentMemoryStorageUnavailable;
            break :blk if (runtimeFeedSelected(runtime, query)) runtime else null;
        },
        .subset, .all => null,
    };
}

fn runtimeFeedSelected(runtime: *const agent_memory_runtime.Runtime, query: []const u8) bool {
    if (!runtime.supportsFeed()) return false;
    if (std.mem.eql(u8, runtime.backendName(), "api")) return true;
    return runtimeFeedQuerySelected(query);
}

fn runtimeFeedQuerySelected(query: []const u8) bool {
    return queryBool(query, "runtime_feed", false) or queryBool(query, "native_runtime_feed", false) or if (json.queryParam(query, "feed_backend")) |backend|
        (std.ascii.eqlIgnoreCase(backend, "runtime") or std.ascii.eqlIgnoreCase(backend, "backend"))
    else
        false;
}

fn feedWireModeFromQuery(query: []const u8) FeedWireMode {
    const raw = json.queryParam(query, "wire_mode") orelse
        json.queryParam(query, "wire") orelse
        json.queryParam(query, "compat") orelse
        json.queryParam(query, "feed_format") orelse
        json.queryParam(query, "format") orelse
        return .native;
    if (std.ascii.eqlIgnoreCase(raw, "nullclaw") or
        std.ascii.eqlIgnoreCase(raw, "nullclaw_json") or
        std.ascii.eqlIgnoreCase(raw, "nullclaw_agent_memory") or
        std.ascii.eqlIgnoreCase(raw, "agent_memory"))
    {
        return .nullclaw_agent_memory;
    }
    return .native;
}

fn feedObjectTypeFromQuery(query: []const u8, mode: FeedWireMode) ?[]const u8 {
    return json.queryParam(query, "object_type") orelse
        json.queryParam(query, "feed_object_type") orelse
        json.queryParam(query, "type") orelse
        if (mode == .nullclaw_agent_memory) "agent_memory" else null;
}

fn feedObjectTypeSelectionError(ctx: *Context, object_type: []const u8, mode: FeedWireMode) ?HttpResponse {
    if (!feed_contract.objectTypeSupported(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type");
    }
    if (mode == .nullclaw_agent_memory and !std.mem.eql(u8, object_type, "agent_memory")) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "NullClaw wire mode only supports agent_memory feed events");
    }
    return null;
}

fn feedProjectionForObjectTypeRoute(ctx: *Context, object_type: []const u8, route: store_mod.AgentMemoryStorageRoute, mode: FeedWireMode) !?FeedProjectionCompaction {
    if (mode == .nullclaw_agent_memory or std.mem.eql(u8, object_type, "agent_memory")) {
        return try nullClawFeedProjectionForRoute(ctx, route);
    }
    if (feed_contract.isAgentSessionObject(object_type)) {
        return try centralRuntimeFeedProjectionForRoute(ctx, route);
    }
    return null;
}

fn centralFeedRouteNeedsFilter(route: store_mod.AgentMemoryStorageRoute) bool {
    return switch (route.target) {
        .primary, .all => false,
        .native, .runtime, .named, .subset => true,
    };
}

fn routeEffectiveCursorFloor(ctx: *Context, route: store_mod.AgentMemoryStorageRoute, scopes_json: []const u8) !?i64 {
    const projection_name = (try feedRouteProjectionName(ctx, route)) orelse return null;
    defer ctx.allocator.free(projection_name);
    const projection_floor = try ctx.store.feedProjectionCursorFloor(ctx.allocator, projection_name);
    const global_status = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    return @max(projection_floor, global_status.cursor_floor);
}

fn feedRouteProjectionName(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !?[]const u8 {
    return feedRouteProjectionNameWithKind(ctx, "memory_feed_route", route);
}

fn nullClawFeedRouteProjectionName(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !?[]const u8 {
    return feedRouteProjectionNameWithKind(ctx, "nullclaw_agent_memory_route", route);
}

fn feedRouteProjectionNameWithKind(ctx: *Context, kind: []const u8, route: store_mod.AgentMemoryStorageRoute) !?[]const u8 {
    if (!centralFeedRouteNeedsFilter(route)) return null;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    const prefix = try feedRouteProjectionPrefixWithKind(ctx, kind);
    defer ctx.allocator.free(prefix);
    try out.appendSlice(ctx.allocator, prefix);
    switch (route.target) {
        .primary, .all => {
            out.deinit(ctx.allocator);
            return null;
        },
        .native => try out.appendSlice(ctx.allocator, "native"),
        .runtime => try out.appendSlice(ctx.allocator, "runtime"),
        .named => {
            try out.appendSlice(ctx.allocator, "named:");
            try out.appendSlice(ctx.allocator, route.name orelse "runtime");
        },
        .subset => {
            try out.appendSlice(ctx.allocator, "subset:");
            const stores = try ctx.allocator.dupe([]const u8, route.stores);
            defer ctx.allocator.free(stores);
            std.mem.sort([]const u8, stores, {}, struct {
                fn lessThan(_: void, a: []const u8, b: []const u8) bool {
                    return std.mem.lessThan(u8, a, b);
                }
            }.lessThan);
            var written: usize = 0;
            var previous: ?[]const u8 = null;
            for (stores) |store_name| {
                if (previous) |prev| {
                    if (std.mem.eql(u8, prev, store_name)) continue;
                }
                previous = store_name;
                if (written > 0) try out.append(ctx.allocator, ',');
                try out.appendSlice(ctx.allocator, store_name);
                written += 1;
            }
        },
    }
    const projection_name = try out.toOwnedSlice(ctx.allocator);
    return projection_name;
}

fn feedOriginProjectionForNullClawNdjsonRestore(ctx: *Context, projection_compaction: ?FeedProjectionCompaction, route: store_mod.AgentMemoryStorageRoute) ![]const u8 {
    if (projection_compaction) |projection| return try ctx.allocator.dupe(u8, projection.name);
    if (try feedRouteProjectionName(ctx, route)) |projection| return projection;
    return feedProjectionCursorName(ctx, nullclaw_agent_memory_projection);
}

fn feedOriginProjectionForEvent(ctx: *Context, object_type: []const u8, route: store_mod.AgentMemoryStorageRoute) ![]const u8 {
    if (try feedRouteProjectionName(ctx, route)) |projection| return projection;
    if (std.mem.eql(u8, object_type, "agent_memory") or feed_contract.isAgentSessionObject(object_type)) {
        return feedProjectionCursorName(ctx, nullclaw_agent_memory_projection);
    }
    return ctx.allocator.dupe(u8, global_feed_origin_projection);
}

fn feedOriginProjectionForMemoryStatus(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) ![]const u8 {
    if (try feedRouteProjectionName(ctx, route)) |projection| return projection;
    return ctx.allocator.dupe(u8, global_feed_origin_projection);
}

fn feedStatusWithLocalOriginSequence(ctx: *Context, status: store_mod.FeedStatus, projection: []const u8) !store_mod.FeedStatus {
    var out = status;
    const frontier = try ctx.store.feedOriginFrontier(ctx.allocator, projection, ctx.feed_instance_id);
    const frontier_next = if (frontier > 0) store_mod.feedSequenceAfter(frontier) else 0;
    out.next_local_origin_sequence = store_mod.feedNextLocalOriginSequence(frontier_next, status.max_event_id);
    return out;
}

fn listCentralFeedEventsForRoute(ctx: *Context, since_id: i64, limit: usize, scopes_json: []const u8, ignore_cursor_floor: bool, route: store_mod.AgentMemoryStorageRoute) ![]store_mod.FeedEvent {
    if (!centralFeedRouteNeedsFilter(route)) {
        return ctx.store.listFeedEvents(ctx.allocator, .{ .since_id = since_id, .limit = limit, .scopes_json = scopes_json, .ignore_cursor_floor = ignore_cursor_floor, .actor_id = ctx.actor_id });
    }

    const target_limit = @max(@as(usize, 1), @min(limit, 500));
    var cursor = since_id;
    var out: std.ArrayListUnmanaged(store_mod.FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(ctx.allocator);
        out.deinit(ctx.allocator);
    }
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (out.items.len < target_limit) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = ignore_cursor_floor,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!api_feed_route.matchesStorageRoute(batch_allocator, event, route)) continue;
            var cloned = try event.clone(ctx.allocator);
            errdefer cloned.deinit(ctx.allocator);
            try out.append(ctx.allocator, cloned);
            if (out.items.len >= target_limit) break;
        }
        if (batch.len < 500) break;
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn centralFeedStatusForRoute(ctx: *Context, scopes_json: []const u8, route: store_mod.AgentMemoryStorageRoute) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    if (!centralFeedRouteNeedsFilter(route)) return base;

    return centralFeedStatusForRouteFromFloor(ctx, scopes_json, route, base.cursor_floor);
}

fn centralFeedStatusForRouteFromFloor(ctx: *Context, scopes_json: []const u8, route: store_mod.AgentMemoryStorageRoute, cursor_floor: i64) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    var filtered = store_mod.FeedStatus{
        .cursor_floor = cursor_floor,
        .max_event_id = base.max_event_id,
        .visible_events = 0,
        .pending_events = 0,
        .applying_events = 0,
        .applied_events = 0,
    };
    var cursor = cursor_floor;
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (true) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = true,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!api_feed_route.matchesStorageRoute(batch_allocator, event, route)) continue;
            filtered.visible_events += 1;
            if (std.mem.eql(u8, event.status, "pending")) {
                filtered.pending_events += 1;
            } else if (std.mem.eql(u8, event.status, "applying")) {
                filtered.applying_events += 1;
            } else if (std.mem.eql(u8, event.status, "applied")) {
                filtered.applied_events += 1;
            }
        }
        if (batch.len < 500) break;
    }
    return filtered;
}

