fn runtimeMemoryFeed(ctx: *Context, runtime: *agent_memory_runtime.Runtime, query: []const u8) HttpResponse {
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const events = runtime.listFeedEventsByInput(ctx.allocator, .{
        .since_id = since_id,
        .limit = limit,
        .scopes_json = feed_scopes,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor; request a checkpoint"),
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    defer {
        for (events) |*event| event.deinit(ctx.allocator);
        ctx.allocator.free(events);
    }
    return runtimeFeedEventsResponse(ctx, events);
}

fn runtimeMemoryFeedStatus(ctx: *Context, runtime: *agent_memory_runtime.Runtime) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    var status = runtime.feedStatusByInput(ctx.allocator, .{
        .scopes_json = feed_scopes,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    defer status.deinit(ctx.allocator);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendRuntimeFeedStatusJson(ctx.allocator, &out, status) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn runtimeMemoryFeedCompact(ctx: *Context, runtime: *agent_memory_runtime.Runtime, before_id: ?i64) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const result = runtime.compactFeedByInput(ctx.allocator, .{
        .scopes_json = feed_scopes,
        .before_id = before_id,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d}}}", .{ result.cursor_floor, result.compacted_through_sequence, result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn runtimeMemoryFeedCheckpoint(ctx: *Context, runtime: *agent_memory_runtime.Runtime, query: []const u8) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const since_id = feedCursorFromQuery(query);
    const limit = if (json.queryParam(query, "limit")) |raw| parseLimit(raw, 500) else null;
    const body = runtime.exportFeedCheckpointByInput(ctx.allocator, .{
        .scopes_json = feed_scopes,
        .since_id = since_id,
        .limit = limit,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return .{ .status = "200 OK", .body = body };
}

fn runtimeMemoryFeedCheckpointRestore(ctx: *Context, runtime: *agent_memory_runtime.Runtime, body: []const u8) HttpResponse {
    runtimeFeedApplyPreflight(ctx, body) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotSupported => return agentMemoryStorageUnavailable(ctx),
        error.InvalidPayload, error.InvalidRawJson, error.AgentMemoryStorageUnavailable => return badJson(ctx),
        else => return serverError(ctx),
    };
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    runtime.restoreFeedCheckpointByInput(ctx.allocator, .{
        .checkpoint_json = body,
        .scopes_json = feed_scopes,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn centralRuntimeMemoryFeed(ctx: *Context, storage_route: store_mod.AgentMemoryStorageRoute, query: []const u8) HttpResponse {
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    if (since_id < effective_floor) return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Runtime feed cursor is older than the compacted projection cursor floor; request a checkpoint");
    const events = listCentralRuntimeFeedEventsForRoute(ctx, since_id, limit, feed_scopes, true, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Runtime feed cursor is older than the compacted cursor floor; request a checkpoint"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    return feedEventsResponse(ctx, events);
}

fn centralRuntimeMemoryFeedStatus(ctx: *Context, storage_route: store_mod.AgentMemoryStorageRoute) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    var status = centralRuntimeFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, effective_floor) catch return serverError(ctx);
    status = feedStatusWithLocalOriginSequence(ctx, status, projection.name) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendCentralRuntimeFeedStatusJson(ctx, &out, status) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn centralRuntimeMemoryFeedCompact(ctx: *Context, storage_route: store_mod.AgentMemoryStorageRoute, requested_before_id: ?i64) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    const status = centralRuntimeFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, effective_floor) catch return serverError(ctx);
    const before_id = requested_before_id orelse status.max_event_id;
    const result = ctx.store.compactFeedCursorProjection(projection.name, before_id, ctx.actor_id) catch return serverError(ctx);
    const response_floor = @max(result.cursor_floor, effective_floor);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d},\"projection\":\"runtime_object_types\"", .{ response_floor, response_floor, store_mod.feedSequenceAfter(response_floor), result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    if (centralFeedRouteNeedsFilter(storage_route)) {
        out.appendSlice(ctx.allocator, ",\"route\":") catch return serverError(ctx);
        storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn centralRuntimeMemoryFeedCheckpoint(ctx: *Context, storage_route: store_mod.AgentMemoryStorageRoute, query: []const u8) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const effective_floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    const status = centralRuntimeFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, effective_floor) catch return serverError(ctx);
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 500);
    const events = listCentralRuntimeFeedEventsForRoute(ctx, since_id, limit, feed_scopes, true, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Runtime feed cursor is older than the compacted cursor floor"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"instance_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.feed_instance_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"storage_kind\":\"native\",\"feed_object_types\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, agent_memory_runtime.feed_object_types_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"lifecycle_object_types\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, agent_memory_runtime.lifecycle_object_types_json) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ status.cursor_floor, status.cursor_floor, status.max_event_id, status.max_event_id }) catch return serverError(ctx);
    var frontiers_written: usize = 0;
    appendNativeCheckpointFrontierProjection(ctx, &out, projection.name, &frontiers_written) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "],\"events\":[") catch return serverError(ctx);
    _ = appendFeedEventsForActor(ctx, &out, events) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn runtimeMemoryFeedApply(ctx: *Context, runtime: *agent_memory_runtime.Runtime, body: []const u8) HttpResponse {
    runtimeFeedApplyPreflight(ctx, body) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotSupported => return agentMemoryStorageUnavailable(ctx),
        error.InvalidPayload, error.InvalidRawJson, error.AgentMemoryStorageUnavailable => return badJson(ctx),
        else => return serverError(ctx),
    };
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    runtime.applyFeedEventByInput(ctx.allocator, .{
        .event_json = body,
        .scopes_json = feed_scopes,
        .actor_id = ctx.actor_id,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn runtimeFeedApplyPreflight(ctx: *Context, body: []const u8) !void {
    var parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, body, .{}) catch return error.InvalidPayload;
    defer parsed.deinit();
    if (parsed.value != .object) return error.InvalidPayload;
    if (agent_memory_runtime.runtimeCheckpointEventsValue(parsed.value.object)) |events_value| {
        if (events_value != .array) return error.InvalidPayload;
        for (events_value.array.items) |event_value| {
            if (event_value != .object) return error.InvalidPayload;
            try runtimeFeedEventPreflight(ctx, event_value.object);
        }
        return;
    }
    try runtimeFeedEventPreflight(ctx, parsed.value.object);
}

fn runtimeFeedEventPreflight(ctx: *Context, obj: std.json.ObjectMap) !void {
    var event = try agent_memory_runtime.parseLooseFeedEventValue(ctx.allocator, obj, ctx.actor_id);
    defer event.deinit(ctx.allocator);
    if (!feed_contract.objectTypeUsesAgentMemoryStorageRoute(event.object_type)) return error.NotSupported;
    const event_actor_id = event.actor_id orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return error.Forbidden;

    var payload = std.json.parseFromSlice(std.json.Value, ctx.allocator, event.payload_json, .{}) catch return error.InvalidPayload;
    defer payload.deinit();
    if (payload.value != .object) return error.InvalidPayload;
    const payload_obj = payload.value.object;

    if (std.mem.eql(u8, event.object_type, "agent_memory")) {
        if (!try runtimeAgentMemoryFeedMutationAllowed(ctx, event, payload_obj, event_actor_id)) return error.Forbidden;
        return;
    }
    if (feed_contract.isAgentSessionObject(event.object_type)) {
        if (!try runtimeAgentSessionFeedMutationAllowed(ctx, event, payload_obj, event_actor_id)) return error.Forbidden;
        return;
    }
    return error.NotSupported;
}

fn runtimeFeedPermissionsJson(ctx: *Context, payload_obj: std.json.ObjectMap, event_permissions_json: []const u8) ![]const u8 {
    return try rawArrayFieldAny(ctx.allocator, payload_obj, &.{ "permissions", "permissions_json" }, event_permissions_json);
}

fn runtimeAgentMemoryFeedMutationAllowed(ctx: *Context, event: agent_memory_runtime.FeedEvent, payload_obj: std.json.ObjectMap, event_actor_id: []const u8) !bool {
    const requested_owner = nullableStringFieldAny(payload_obj, &.{ "owner_id", "actor_id" }) orelse event_actor_id;
    const requested_scope = nullableStringFieldAny(payload_obj, &.{"scope"}) orelse event.scope;
    const session_id = nullableStringFieldAlias(payload_obj, "session_id", "session");
    const effective_scope = try access.agentMemoryScope(ctx.allocator, requested_owner, session_id, requested_scope);
    defer ctx.allocator.free(effective_scope);
    const requested_permissions = try runtimeFeedPermissionsJson(ctx, payload_obj, event.permissions_json);
    defer ctx.allocator.free(requested_permissions);
    const effective_permissions = try access.agentMemoryPermissions(ctx.allocator, requested_owner, requested_scope, requested_permissions);
    defer ctx.allocator.free(effective_permissions);

    if (feed_contract.isAgentMemoryDeleteOperation(event.operation)) {
        return canDeleteAgentMemoryScope(ctx, event_actor_id, event.operation, effective_scope, effective_permissions);
    }
    if (isAgentMemoryStatusLifecycleOperation(event.operation)) {
        return feedLifecycleMutationAllowed(ctx, event.operation, effective_scope, effective_permissions);
    }
    return canApplyAgentMemoryScope(ctx, event_actor_id, effective_scope, effective_permissions);
}

fn runtimeAgentSessionFeedMutationAllowed(ctx: *Context, event: agent_memory_runtime.FeedEvent, payload_obj: std.json.ObjectMap, event_actor_id: []const u8) !bool {
    const payload_actor = nullableStringFieldAny(payload_obj, &.{"actor_id"}) orelse event_actor_id;
    if (!std.mem.eql(u8, payload_actor, event_actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return false;
    const permissions_json = try runtimeFeedPermissionsJson(ctx, payload_obj, event.permissions_json);
    defer ctx.allocator.free(permissions_json);
    if (nullableStringFieldAlias(payload_obj, "session_id", "session")) |session_id| {
        const scope = try std.fmt.allocPrint(ctx.allocator, "session:{s}", .{session_id});
        defer ctx.allocator.free(scope);
        return canApplyAgentSessionEvent(ctx, event_actor_id, scope, permissions_json);
    }
    if (std.mem.eql(u8, event.operation, "delete_autosaved")) {
        return api_session_access.allWriteAllowed(ctx) and access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
    }
    return false;
}

const FeedProjectionCompaction = struct {
    name: []const u8,
    object_type: ?[]const u8 = null,
};

fn memoryFeedCheckpointRestore(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    return memoryFeedCheckpointRestoreInternal(ctx, body, query, null);
}

fn memoryFeedCheckpointRestoreInternal(ctx: *Context, body: []const u8, query: []const u8, projection_compaction: ?FeedProjectionCompaction) HttpResponse {
    if (!canApplyFeed(ctx)) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const query_route_authoritative = storage_routes.queryHasSelector(query);
    if (isNullClawNdjsonCheckpointPayload(ctx.allocator, body)) {
        const origin_projection = feedOriginProjectionForNullClawNdjsonRestore(ctx, projection_compaction, storage_route) catch return serverError(ctx);
        defer ctx.allocator.free(origin_projection);
        const transformed = nullClawNdjsonCheckpointToNativeFeedCheckpoint(ctx, body) catch return badJson(ctx);
        defer ctx.allocator.free(transformed);
        const response = memoryFeedCheckpointRestoreInternal(ctx, transformed, query, projection_compaction);
        if (!std.mem.eql(u8, response.status, "200 OK")) return response;
        _ = restoreNullClawNdjsonFrontiers(ctx, body, origin_projection) catch return badJson(ctx);
        return response;
    }
    if (projection_compaction == null) {
        if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
            return runtimeMemoryFeedCheckpointRestore(ctx, runtime, body);
        }
    }
    var owned_projection_name: ?[]const u8 = null;
    defer if (owned_projection_name) |value| ctx.allocator.free(value);
    const effective_projection = projection_compaction orelse blk: {
        if (runtimeFeedQuerySelected(query)) {
            const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
            owned_projection_name = projection.name;
            break :blk projection;
        }
        const projection_name = (feedRouteProjectionName(ctx, storage_route) catch return serverError(ctx)) orelse break :blk null;
        owned_projection_name = projection_name;
        break :blk FeedProjectionCompaction{ .name = projection_name };
    };
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const events_value = checkpointEventsValue(parsed.value.object) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint restore requires an events array");
    if (events_value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint restore requires an events array");
    const frontiers_value = checkpointFrontiersValue(parsed.value.object);
    validateRuntimeFeedCheckpointEvents(events_value, runtimeFeedQuerySelected(query)) catch |err| switch (err) {
        error.UnsupportedObjectType => return json.errorResponse(ctx.allocator, 400, "bad_request", "Runtime feed backend only supports agent runtime object types"),
        error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid checkpoint event"),
    };
    validateNativeCheckpointFrontiers(ctx, frontiers_value, effective_projection) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint frontiers must be visible for the current actor and contain valid origin identity"),
        else => return serverError(ctx),
    };
    validateNativeCheckpointEvents(ctx, events_value) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.UnsupportedObjectType => return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type"),
        error.InvalidPayload, error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid checkpoint event"),
        else => return serverError(ctx),
    };
    const checkpoint_compacted_through = checkpointCompactedThrough(parsed.value.object);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const status_before_restore = if (effective_projection) |projection| blk: {
        const projection_floor = ctx.store.feedProjectionCursorFloor(ctx.allocator, projection.name) catch return serverError(ctx);
        break :blk if (centralRuntimeFeedProjectionName(projection.name))
            centralRuntimeFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, projection_floor) catch return serverError(ctx)
        else if (projection.object_type) |object_type|
            centralFeedStatusByObjectTypeFromFloor(ctx, feed_scopes, object_type, projection_floor) catch return serverError(ctx)
        else
            centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, projection_floor) catch return serverError(ctx);
    } else ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);

    var restored: usize = 0;
    var applied: usize = 0;
    var queued: usize = 0;
    var skipped: usize = 0;
    var local_compact_floor: i64 = 0;
    for (events_value.array.items) |event_value| {
        if (event_value != .object) return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint events must be JSON objects");
        const event_obj = event_value.object;
        const status = json.stringField(event_obj, "status") orelse "applied";
        var local_event_id: ?i64 = null;
        if (std.mem.eql(u8, status, "pending")) {
            local_event_id = restorePendingCheckpointEvent(ctx, event_obj, storage_route, query_route_authoritative) catch |err| switch (err) {
                error.Forbidden => return forbidden(ctx),
                error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
                error.UnsupportedObjectType => return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type"),
                error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be restored through the feed"),
                error.InternalAgentSessionMessage => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be restored through the feed"),
                error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid checkpoint event"),
                else => return serverError(ctx),
            };
            queued += 1;
        } else if (std.mem.eql(u8, status, "applied") or std.mem.eql(u8, status, "applying")) {
            const event_body = json.jsonFromValue(ctx.allocator, event_value) catch return serverError(ctx);
            const response = if (effective_projection) |projection|
                applyMemoryEventWithOriginProjection(ctx, event_body, query, projection.name)
            else
                applyMemoryEvent(ctx, event_body, query);
            ctx.allocator.free(event_body);
            if (!std.mem.eql(u8, response.status, "200 OK")) return response;
            local_event_id = responseEventId(ctx.allocator, response.body);
            ctx.allocator.free(response.body);
            applied += 1;
        } else {
            skipped += 1;
        }
        if (local_event_id) |event_id| {
            if (checkpointEventSequence(event_obj)) |source_sequence| {
                if (source_sequence <= checkpoint_compacted_through and event_id > local_compact_floor) {
                    local_compact_floor = event_id;
                }
            }
        }
        restored += 1;
    }

    var restored_cursor_floor: i64 = 0;
    var cursor_floor_restored = false;
    var cursor_floor_restore_skipped = false;
    if (checkpoint_compacted_through > 0 and local_compact_floor > 0) {
        const can_restore_floor = if (effective_projection != null)
            (status_before_restore.visible_events == 0 or status_before_restore.cursor_floor >= local_compact_floor)
        else
            (status_before_restore.max_event_id == 0 or status_before_restore.cursor_floor >= local_compact_floor);
        if (can_restore_floor) {
            const compacted = if (effective_projection) |projection| blk: {
                break :blk if (projection.object_type) |object_type|
                    ctx.store.compactFeedProjection(projection.name, object_type, local_compact_floor, ctx.actor_id) catch return serverError(ctx)
                else
                    ctx.store.compactFeedCursorProjection(projection.name, local_compact_floor, ctx.actor_id) catch return serverError(ctx);
            } else ctx.store.compactFeed(local_compact_floor, ctx.actor_id) catch return serverError(ctx);
            restored_cursor_floor = compacted.cursor_floor;
            cursor_floor_restored = true;
        } else {
            cursor_floor_restore_skipped = true;
        }
    }

    const restored_frontiers = restoreNativeCheckpointFrontiers(ctx, frontiers_value, effective_projection) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint frontiers must be visible for the current actor and contain valid origin identity"),
        else => return serverError(ctx),
    };

    const response = std.fmt.allocPrint(ctx.allocator, "{{\"restored_events\":{d},\"applied_events\":{d},\"queued_events\":{d},\"skipped_events\":{d},\"restored_frontiers\":{d},\"checkpoint_compacted_through_sequence\":{d},\"restored_cursor_floor\":{d},\"cursor_floor_restored\":{s},\"cursor_floor_restore_skipped\":{s}}}", .{ restored, applied, queued, skipped, restored_frontiers, checkpoint_compacted_through, restored_cursor_floor, if (cursor_floor_restored) "true" else "false", if (cursor_floor_restore_skipped) "true" else "false" }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn checkpointEventsValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("events")) |events| return events;
    if (obj.get("checkpoint")) |checkpoint| {
        if (checkpoint == .object) return checkpoint.object.get("events");
    }
    return null;
}

fn checkpointFrontiersValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("frontiers")) |frontiers| return frontiers;
    if (obj.get("checkpoint")) |checkpoint| {
        if (checkpoint == .object) return checkpoint.object.get("frontiers");
    }
    return null;
}

fn validateNativeCheckpointFrontiers(ctx: *Context, frontiers_value: ?std.json.Value, effective_projection: ?FeedProjectionCompaction) !void {
    const frontiers = frontiers_value orelse return;
    if (frontiers != .array) return error.InvalidPayload;
    for (frontiers.array.items) |frontier_value| {
        if (frontier_value != .object) return error.InvalidPayload;
        const frontier = try nativeCheckpointFrontierFields(frontier_value.object, effective_projection);
        if (!try nativeCheckpointFrontierProjectionAllowed(ctx, frontier.projection, effective_projection)) return error.Forbidden;
    }
}

fn restoreNativeCheckpointFrontiers(ctx: *Context, frontiers_value: ?std.json.Value, effective_projection: ?FeedProjectionCompaction) !usize {
    const frontiers = frontiers_value orelse return 0;
    if (frontiers != .array) return error.InvalidPayload;
    var restored: usize = 0;
    for (frontiers.array.items) |frontier_value| {
        if (frontier_value != .object) return error.InvalidPayload;
        const frontier = try nativeCheckpointFrontierFields(frontier_value.object, effective_projection);
        if (!try nativeCheckpointFrontierProjectionAllowed(ctx, frontier.projection, effective_projection)) return error.Forbidden;
        try ctx.store.advanceFeedOriginFrontier(frontier.projection, frontier.origin_instance_id, frontier.origin_sequence);
        restored += 1;
    }
    return restored;
}

fn validateNativeCheckpointEvents(ctx: *Context, events_value: std.json.Value) !void {
    if (events_value != .array) return error.InvalidPayload;
    for (events_value.array.items) |event_value| {
        if (event_value != .object) return error.InvalidPayload;
        try validateNativeCheckpointEvent(ctx, event_value.object);
    }
}

fn validateRuntimeFeedCheckpointEvents(events_value: std.json.Value, runtime_only: bool) !void {
    if (!runtime_only) return;
    if (events_value != .array) return error.InvalidPayload;
    for (events_value.array.items) |event_value| {
        if (event_value != .object) return error.InvalidPayload;
        const status = json.stringField(event_value.object, "status") orelse "applied";
        if (!std.mem.eql(u8, status, "pending") and
            !std.mem.eql(u8, status, "applied") and
            !std.mem.eql(u8, status, "applying"))
        {
            continue;
        }
        const object_type = json.stringField(event_value.object, "object_type") orelse return error.UnsupportedObjectType;
        if (!feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) return error.UnsupportedObjectType;
    }
}

fn validateNativeCheckpointEvent(ctx: *Context, obj: std.json.ObjectMap) !void {
    const status = json.stringField(obj, "status") orelse "applied";
    if (!std.mem.eql(u8, status, "pending") and
        !std.mem.eql(u8, status, "applied") and
        !std.mem.eql(u8, status, "applying"))
    {
        return;
    }
    const event_type = json.stringField(obj, "event_type") orelse if (std.mem.eql(u8, status, "pending"))
        return error.InvalidPayload
    else
        "memory_atom.upsert";
    const operation = json.stringField(obj, "operation") orelse feed_contract.operationFromEventType(event_type);
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    if (!feed_contract.objectTypeSupported(object_type)) return error.UnsupportedObjectType;
    if (std.mem.eql(u8, status, "pending") and json.stringField(obj, "object_id") == null) return error.InvalidPayload;
    const event_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return error.Forbidden;
    try validateNativeCheckpointPayloadShape(ctx, obj, operation, object_type);
}

fn validateNativeCheckpointPayloadShape(ctx: *Context, obj: std.json.ObjectMap, operation: []const u8, object_type: []const u8) !void {
    var checkpoint_payload = try checkpointEventPayloadObject(ctx.allocator, obj);
    defer checkpoint_payload.deinit();
    const payload = checkpoint_payload.object;
    if (feed_contract.isLifecycleOperation(operation)) {
        try validateNativeCheckpointLifecyclePayload(obj, payload);
        return;
    }
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        try validateNativeCheckpointAgentMemoryPayload(obj, payload, operation);
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        try validateNativeCheckpointSessionMessagePayload(payload, operation);
    } else if (std.mem.eql(u8, object_type, "agent_session_usage")) {
        try validateNativeCheckpointSessionUsagePayload(payload, operation);
    } else if (std.mem.eql(u8, object_type, "memory_atom")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (checkpointStringFieldAny(payload_obj, &.{ "text", "content" }) == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "source")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (json.stringField(payload_obj, "title") == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "artifact")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (json.stringField(payload_obj, "title") == null) return error.InvalidPayload;
        const artifact_type = json.stringField(payload_obj, "type") orelse json.stringField(payload_obj, "artifact_type") orelse "page";
        const status = json.stringField(payload_obj, "status") orelse if (std.mem.eql(u8, artifact_type, "decision")) "proposed" else "draft";
        if (!artifacts.validStatus(artifact_type, status)) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "entity")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (json.stringField(payload_obj, "name") == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "relation")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (json.stringField(payload_obj, "from_entity_id") == null) return error.InvalidPayload;
        if (json.stringField(payload_obj, "to_entity_id") == null) return error.InvalidPayload;
        if (checkpointStringFieldAny(payload_obj, &.{ "relation_type", "type" }) == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "context_pack")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (checkpointStringFieldAny(payload_obj, &.{ "query", "task" }) == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "space")) {
        const payload_obj = payload orelse return error.InvalidPayload;
        if (json.stringField(payload_obj, "name") == null) return error.InvalidPayload;
    } else if (std.mem.eql(u8, object_type, "policy_scope")) {
        if (payload) |payload_obj| {
            if (payload_obj.get("permissions")) |value| {
                if (value != .array) return error.InvalidPayload;
            }
        }
    }
}

fn validateNativeCheckpointLifecyclePayload(obj: std.json.ObjectMap, payload: ?std.json.ObjectMap) !void {
    if (json.stringField(obj, "object_id") != null) return;
    const payload_obj = payload orelse return error.InvalidPayload;
    if (checkpointStringFieldAny(payload_obj, &.{ "id", "object_id", "key" }) == null) return error.InvalidPayload;
}

fn validateNativeCheckpointAgentMemoryPayload(obj: std.json.ObjectMap, payload: ?std.json.ObjectMap, operation: []const u8) !void {
    const payload_obj = payload orelse return error.InvalidPayload;
    const key = json.stringField(payload_obj, "key") orelse json.stringField(obj, "object_id") orelse return error.InvalidPayload;
    if (domain.isInternalMemoryKey(key)) return error.InvalidPayload;
    _ = try agentMemoryValueKindField(payload_obj);
    if (std.mem.eql(u8, operation, "merge_object")) {
        const patch = payload_obj.get("object") orelse payload_obj.get("value") orelse return error.InvalidPayload;
        if (patch != .object) return error.InvalidPayload;
    } else if (std.mem.eql(u8, operation, "merge_string_set")) {
        if (payload_obj.get("values")) |value| {
            if (!checkpointStringSetPatchValue(value)) return error.InvalidPayload;
        } else if (payload_obj.get("value")) |value| {
            if (!checkpointStringSetPatchValue(value)) return error.InvalidPayload;
        } else if (checkpointStringFieldAny(payload_obj, &.{ "content", "text" }) == null) {
            return error.InvalidPayload;
        }
    }
}

fn validateNativeCheckpointSessionMessagePayload(payload: ?std.json.ObjectMap, operation: []const u8) !void {
    const payload_obj = payload orelse return error.InvalidPayload;
    if (std.mem.eql(u8, operation, "delete_autosaved")) return;
    if (json.stringField(payload_obj, "session_id") == null) return error.InvalidPayload;
    if (feed_contract.isAgentSessionDeleteOperation(operation)) return;
    const role = sessionMessageRoleField(payload_obj) orelse return error.InvalidPayload;
    if (domain.isRuntimeCommandRole(role)) return error.InvalidPayload;
    if (json.stringField(payload_obj, "content") == null) return error.InvalidPayload;
}

fn sessionMessageRoleField(obj: std.json.ObjectMap) ?[]const u8 {
    return json.stringField(obj, "role");
}

fn validateNativeCheckpointSessionUsagePayload(payload: ?std.json.ObjectMap, operation: []const u8) !void {
    const payload_obj = payload orelse return error.InvalidPayload;
    if (json.stringField(payload_obj, "session_id") == null) return error.InvalidPayload;
    if (feed_contract.isAgentSessionDeleteOperation(operation)) return;
    if (json.intField(payload_obj, "total_tokens") == null) return error.InvalidPayload;
}

const CheckpointPayloadObject = struct {
    object: ?std.json.ObjectMap = null,
    parsed: ?std.json.Parsed(std.json.Value) = null,

    fn deinit(self: *CheckpointPayloadObject) void {
        if (self.parsed) |*parsed| parsed.deinit();
    }
};

fn checkpointEventPayloadObject(allocator: std.mem.Allocator, obj: std.json.ObjectMap) !CheckpointPayloadObject {
    const payload_json = try checkpointEventPayloadJson(allocator, obj) orelse return .{};
    defer allocator.free(payload_json);

    var parsed = std.json.parseFromSlice(std.json.Value, allocator, payload_json, .{}) catch return error.InvalidPayload;
    errdefer parsed.deinit();
    return switch (parsed.value) {
        .object => |payload_obj| .{ .object = payload_obj, .parsed = parsed },
        .null => blk: {
            parsed.deinit();
            break :blk .{};
        },
        else => error.InvalidPayload,
    };
}

fn memoryEventPayloadObjectJsonField(allocator: std.mem.Allocator, name: []const u8, value: std.json.Value) !?[]const u8 {
    if (value == .null) return null;
    const raw = try rawJsonFieldValue(allocator, name, value, "{}");
    errdefer allocator.free(raw);
    if (!json.rawJsonRootIs(allocator, raw, .object)) return error.InvalidRawJson;
    return raw;
}

fn checkpointEventPayloadJson(allocator: std.mem.Allocator, obj: std.json.ObjectMap) !?[]const u8 {
    if (obj.get("payload")) |payload| {
        if (try memoryEventPayloadObjectJsonField(allocator, "payload", payload)) |payload_json| return payload_json;
    }
    if (obj.get("payload_json")) |payload| {
        if (try memoryEventPayloadObjectJsonField(allocator, "payload_json", payload)) |payload_json| return payload_json;
    }
    return null;
}

fn checkpointStringFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?[]const u8 {
    for (names) |name| {
        if (json.stringField(obj, name)) |value| return value;
    }
    return null;
}

fn checkpointStringSetPatchValue(value: std.json.Value) bool {
    switch (value) {
        .string => return true,
        .array => |items| {
            for (items.items) |item| {
                if (item != .string) return false;
            }
            return true;
        },
        else => return false,
    }
}

const NativeCheckpointFrontierFields = struct {
    projection: []const u8,
    origin_instance_id: []const u8,
    origin_sequence: i64,
};

fn nativeCheckpointFrontierFields(obj: std.json.ObjectMap, effective_projection: ?FeedProjectionCompaction) !NativeCheckpointFrontierFields {
    const projection = json.stringField(obj, "projection") orelse if (effective_projection) |projection_value| projection_value.name else global_feed_origin_projection;
    const origin_instance_id = json.stringField(obj, "origin_instance_id") orelse
        json.stringField(obj, "source_instance_id") orelse
        return error.InvalidPayload;
    const origin_sequence = json.intField(obj, "origin_sequence") orelse
        json.intField(obj, "source_sequence") orelse
        return error.InvalidPayload;
    if (origin_sequence < 0) return error.InvalidPayload;
    return .{
        .projection = projection,
        .origin_instance_id = origin_instance_id,
        .origin_sequence = origin_sequence,
    };
}

fn nativeCheckpointFrontierProjectionAllowed(ctx: *Context, projection: []const u8, effective_projection: ?FeedProjectionCompaction) !bool {
    if (effective_projection) |projection_value| return std.mem.eql(u8, projection, projection_value.name);
    if (std.mem.eql(u8, projection, global_feed_origin_projection)) return true;
    const agent_projection = try feedProjectionCursorName(ctx, nullclaw_agent_memory_projection);
    defer ctx.allocator.free(agent_projection);
    if (std.mem.eql(u8, projection, agent_projection)) return true;
    const route_prefix = try feedRouteProjectionPrefix(ctx);
    defer ctx.allocator.free(route_prefix);
    return std.mem.startsWith(u8, projection, route_prefix);
}

fn checkpointCompactedThrough(obj: std.json.ObjectMap) i64 {
    if (json.intField(obj, "compacted_through_sequence")) |value| return value;
    if (json.intField(obj, "cursor_floor")) |value| return value;
    if (obj.get("checkpoint")) |checkpoint| {
        if (checkpoint == .object) {
            if (json.intField(checkpoint.object, "compacted_through_sequence")) |value| return value;
            if (json.intField(checkpoint.object, "cursor_floor")) |value| return value;
        }
    }
    return 0;
}

fn checkpointEventSequence(obj: std.json.ObjectMap) ?i64 {
    return json.intField(obj, "id") orelse
        json.intField(obj, "sequence") orelse
        json.intField(obj, "event_id");
}

fn nullClawCheckpointToNativeFeedCheckpoint(ctx: *Context, body: []const u8) ![]const u8 {
    var parsed = try parseBody(ctx, body);
    defer parsed.deinit();
    const events_value = checkpointEventsValue(parsed.value.object) orelse return error.NotNullClawCheckpoint;
    if (events_value != .array) return error.InvalidPayload;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    const compacted_through = checkpointCompactedThrough(parsed.value.object);
    try out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"events\":[", .{ compacted_through, compacted_through });
    var transformed_any = false;
    for (events_value.array.items, 0..) |event_value, i| {
        if (event_value != .object) return error.InvalidPayload;
        if (i > 0) try out.append(ctx.allocator, ',');
        if (isNullClawTopLevelMemoryEvent(event_value.object)) {
            const native = try nullClawEventToNativeFeedEvent(ctx, event_value.object);
            defer ctx.allocator.free(native);
            try out.appendSlice(ctx.allocator, native);
            transformed_any = true;
        } else {
            const raw = try json.jsonFromValue(ctx.allocator, event_value);
            defer ctx.allocator.free(raw);
            try out.appendSlice(ctx.allocator, raw);
        }
    }
    try out.appendSlice(ctx.allocator, "]}");
    if (!transformed_any) return error.NotNullClawCheckpoint;
    return out.toOwnedSlice(ctx.allocator);
}

fn wantsNullClawCheckpointNdjson(query: []const u8) bool {
    const format = json.queryParam(query, "format") orelse json.queryParam(query, "checkpoint_format") orelse return false;
    return std.ascii.eqlIgnoreCase(format, "ndjson") or
        std.ascii.eqlIgnoreCase(format, "nullclaw") or
        std.ascii.eqlIgnoreCase(format, "nullclaw_ndjson");
}

fn nullClawAgentMemoryCheckpointNdjson(ctx: *Context, query: []const u8) HttpResponse {
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    return agentMemoryCheckpointNdjsonForRoute(ctx, query, storage_route);
}

fn agentMemoryCheckpointNdjsonForRoute(ctx: *Context, query: []const u8, storage_route: store_mod.AgentMemoryStorageRoute) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection = nullClawFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
    defer ctx.allocator.free(projection.name);
    const floor = projectionEffectiveCursorFloor(ctx, feed_scopes, projection) catch return serverError(ctx);
    const status = centralFeedStatusByObjectTypeRouteFromFloorMode(ctx, feed_scopes, "agent_memory", storage_route, floor, .nullclaw_agent_memory) catch return serverError(ctx);
    const entries = api_agent_memory_store.listByInput(ctx, .{
        .route = storage_route,
        .access = .any_visible,
    }) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    defer {
        for (entries) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
        ctx.allocator.free(entries);
    }
    std.mem.sort(domain.AgentMemory, entries, {}, agentMemoryCheckpointLessThan);

    var max_timestamp_ms: i64 = 0;
    for (entries) |entry| {
        if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
        max_timestamp_ms = @max(max_timestamp_ms, parseAgentMemoryTimestampMs(entry.timestamp));
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.append(ctx.allocator, '{') catch return serverError(ctx);
    appendNdjsonStringField(ctx.allocator, &out, "kind", "meta", true) catch return serverError(ctx);
    appendNdjsonIntField(ctx.allocator, &out, "schema_version", 1, false) catch return serverError(ctx);
    appendNdjsonIntField(ctx.allocator, &out, "last_sequence", status.max_event_id, false) catch return serverError(ctx);
    appendNdjsonIntField(ctx.allocator, &out, "last_timestamp_ms", max_timestamp_ms, false) catch return serverError(ctx);
    appendNdjsonIntField(ctx.allocator, &out, "compacted_through_sequence", status.cursor_floor, false) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}\n") catch return serverError(ctx);

    const frontiers = ctx.store.listFeedOriginFrontiers(ctx.allocator, projection.name) catch return serverError(ctx);
    defer store_mod.freeFeedOriginFrontiers(ctx.allocator, frontiers);
    for (frontiers) |frontier| {
        appendNullClawCheckpointFrontierLine(ctx, &out, frontier) catch return serverError(ctx);
    }

    var origin_sequence: i64 = 1;
    for (entries) |entry| {
        if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
        appendAgentMemoryCheckpointStateLine(ctx, &out, entry, origin_sequence) catch return serverError(ctx);
        origin_sequence += 1;
    }
    _ = query;
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendNullClawCheckpointFrontierLine(ctx: *Context, out: *std.ArrayListUnmanaged(u8), frontier: store_mod.FeedOriginFrontier) !void {
    try out.append(ctx.allocator, '{');
    try appendNdjsonStringField(ctx.allocator, out, "kind", "frontier", true);
    try appendNdjsonStringField(ctx.allocator, out, "origin_instance_id", frontier.origin_instance_id, false);
    try appendNdjsonIntField(ctx.allocator, out, "origin_sequence", frontier.origin_sequence, false);
    try out.appendSlice(ctx.allocator, "}\n");
}

fn agentMemoryCheckpointLessThan(_: void, a: domain.AgentMemory, b: domain.AgentMemory) bool {
    const key_order = std.mem.order(u8, a.key, b.key);
    if (key_order != .eq) return key_order == .lt;
    const a_session = a.session_id orelse "";
    const b_session = b.session_id orelse "";
    const session_order = std.mem.order(u8, a_session, b_session);
    if (session_order != .eq) return session_order == .lt;
    return std.mem.order(u8, a.store, b.store) == .lt;
}

fn parseAgentMemoryTimestampMs(timestamp: []const u8) i64 {
    return std.fmt.parseInt(i64, timestamp, 10) catch 0;
}

fn appendAgentMemoryCheckpointStateLine(ctx: *Context, out: *std.ArrayListUnmanaged(u8), entry: domain.AgentMemory, origin_sequence: i64) !void {
    try out.append(ctx.allocator, '{');
    try appendNdjsonStringField(ctx.allocator, out, "kind", "state", true);
    try appendNdjsonStringField(ctx.allocator, out, "key", entry.key, false);
    try appendNdjsonNullableStringField(ctx.allocator, out, "session_id", entry.session_id, false);
    try appendNdjsonStringField(ctx.allocator, out, "category", if (entry.category.len > 0) entry.category else "core", false);
    try appendNdjsonNullableStringField(ctx.allocator, out, "value_kind", null, false);
    try appendNdjsonStringField(ctx.allocator, out, "content", entry.content, false);
    try appendNdjsonIntField(ctx.allocator, out, "timestamp_ms", parseAgentMemoryTimestampMs(entry.timestamp), false);
    try appendNdjsonStringField(ctx.allocator, out, "origin_instance_id", ctx.feed_instance_id, false);
    try appendNdjsonIntField(ctx.allocator, out, "origin_sequence", origin_sequence, false);
    try appendNdjsonStringField(ctx.allocator, out, "scope", entry.scope, false);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonArray(out, ctx.allocator, entry.permissions_json);
    try appendNdjsonStringField(ctx.allocator, out, "owner_id", entry.actor_id, false);
    if (entry.store.len > 0) try appendNdjsonStringField(ctx.allocator, out, "store", entry.store, false);
    try out.appendSlice(ctx.allocator, "}\n");
}

test "api agent memory checkpoint state preserves permissions" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
        .feed_instance_id = "pantry-test",
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);

    try appendAgentMemoryCheckpointStateLine(&ctx, &out, .{
        .id = "am_test",
        .key = "pref.editor",
        .content = "Use Zig",
        .category = "preference",
        .timestamp = "1700000000100",
        .session_id = null,
        .actor_id = "agent:test",
        .scope = "project:nullpantry",
        .permissions_json = "[\"team:zig\"]",
    }, 7);

    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"permissions\":[\"team:zig\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"origin_instance_id\":\"pantry-test\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"origin_sequence\":7") != null);
}

test "api agent memory checkpoint state rejects malformed permissions" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);

    try std.testing.expectError(error.InvalidRawJson, appendAgentMemoryCheckpointStateLine(&ctx, &out, .{
        .id = "am_bad",
        .key = "pref.bad",
        .content = "Bad ACL",
        .category = "preference",
        .timestamp = "1700000000100",
        .session_id = null,
        .actor_id = "agent:test",
        .scope = "project:nullpantry",
        .permissions_json = "{\"team\":\"zig\"}",
    }, 1));
}

fn appendNdjsonStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: []const u8, first: bool) !void {
    if (!first) try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendString(out, allocator, value);
}

fn appendNdjsonNullableStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: ?[]const u8, first: bool) !void {
    if (!first) try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendNullableString(out, allocator, value);
}

fn appendNdjsonIntField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: i64, first: bool) !void {
    if (!first) try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.print(allocator, ":{d}", .{value});
}

fn isNullClawNdjsonCheckpointPayload(allocator: std.mem.Allocator, payload: []const u8) bool {
    const trimmed = std.mem.trim(u8, payload, " \t\r\n");
    if (trimmed.len == 0 or trimmed[0] != '{') return false;
    const first_line_end = std.mem.indexOfScalar(u8, trimmed, '\n') orelse trimmed.len;
    const first_line = std.mem.trim(u8, trimmed[0..first_line_end], " \t\r\n");
    if (first_line.len == 0) return false;
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, first_line, .{}) catch return false;
    defer parsed.deinit();
    if (parsed.value != .object) return false;
    const kind = json.stringField(parsed.value.object, "kind") orelse return false;
    if (!std.mem.eql(u8, kind, "meta")) return false;
    return (json.intField(parsed.value.object, "schema_version") orelse 0) == 1;
}

fn restoreNullClawNdjsonFrontiers(ctx: *Context, payload: []const u8, projection: []const u8) !usize {
    var restored: usize = 0;
    var lines = std.mem.splitScalar(u8, payload, '\n');
    while (lines.next()) |raw_line| {
        const line = std.mem.trim(u8, raw_line, " \t\r\n");
        if (line.len == 0) continue;
        var parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, line, .{});
        defer parsed.deinit();
        if (parsed.value != .object) return error.InvalidPayload;
        const obj = parsed.value.object;
        const kind = json.stringField(obj, "kind") orelse return error.InvalidPayload;
        if (!std.mem.eql(u8, kind, "frontier")) continue;
        const origin_instance_id = json.stringField(obj, "origin_instance_id") orelse return error.InvalidPayload;
        const origin_sequence = json.intField(obj, "origin_sequence") orelse return error.InvalidPayload;
        if (origin_sequence < 0) return error.InvalidPayload;
        try ctx.store.advanceFeedOriginFrontier(projection, origin_instance_id, origin_sequence);
        restored += 1;
    }
    return restored;
}

fn nullClawNdjsonCheckpointToNativeFeedCheckpoint(ctx: *Context, payload: []const u8) ![]const u8 {
    var events: std.ArrayListUnmanaged(u8) = .empty;
    errdefer events.deinit(ctx.allocator);
    var event_count: usize = 0;
    var compacted_through: i64 = 0;
    var saw_meta = false;

    var lines = std.mem.splitScalar(u8, payload, '\n');
    while (lines.next()) |raw_line| {
        const line = std.mem.trim(u8, raw_line, " \t\r\n");
        if (line.len == 0) continue;
        var parsed = try std.json.parseFromSlice(std.json.Value, ctx.allocator, line, .{});
        defer parsed.deinit();
        if (parsed.value != .object) return error.InvalidPayload;
        const obj = parsed.value.object;
        const kind = json.stringField(obj, "kind") orelse return error.InvalidPayload;
        if (std.mem.eql(u8, kind, "meta")) {
            const schema_version = json.intField(obj, "schema_version") orelse return error.InvalidPayload;
            if (schema_version != 1) return error.InvalidPayload;
            compacted_through = json.intField(obj, "compacted_through_sequence") orelse json.intField(obj, "last_sequence") orelse 0;
            saw_meta = true;
        } else if (std.mem.eql(u8, kind, "frontier")) {
            continue;
        } else if (std.mem.eql(u8, kind, "state")) {
            try appendNullClawCheckpointStateEvent(ctx, &events, obj, &event_count);
        } else if (std.mem.eql(u8, kind, "scoped_tombstone")) {
            try appendNullClawCheckpointTombstoneEvent(ctx, &events, obj, "delete_scoped", &event_count);
        } else if (std.mem.eql(u8, kind, "key_tombstone")) {
            try appendNullClawCheckpointTombstoneEvent(ctx, &events, obj, "delete_all", &event_count);
        } else {
            return error.InvalidPayload;
        }
    }
    if (!saw_meta) return error.InvalidPayload;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"events\":[", .{ compacted_through, compacted_through });
    try out.appendSlice(ctx.allocator, events.items);
    try out.appendSlice(ctx.allocator, "]}");
    events.deinit(ctx.allocator);
    return out.toOwnedSlice(ctx.allocator);
}

fn appendNullClawCheckpointStateEvent(ctx: *Context, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, event_count: *usize) !void {
    const key = json.stringField(obj, "key") orelse return error.InvalidPayload;
    const content = json.stringField(obj, "content") orelse return error.InvalidPayload;
    const category = json.stringField(obj, "category") orelse "core";
    const timestamp_ms = json.intField(obj, "timestamp_ms") orelse return error.InvalidPayload;
    const origin_instance_id = json.stringField(obj, "origin_instance_id") orelse return error.InvalidPayload;
    const origin_sequence = json.intField(obj, "origin_sequence") orelse return error.InvalidPayload;
    if (event_count.* > 0) try out.append(ctx.allocator, ',');
    event_count.* += 1;
    try out.append(ctx.allocator, '{');
    try appendNdjsonStringField(ctx.allocator, out, "event_type", "agent_memory.put", true);
    try appendNdjsonStringField(ctx.allocator, out, "operation", "put", false);
    try appendNdjsonStringField(ctx.allocator, out, "object_type", "agent_memory", false);
    try appendNdjsonStringField(ctx.allocator, out, "object_id", key, false);
    try appendNdjsonStringField(ctx.allocator, out, "actor_id", ctx.actor_id, false);
    try appendNdjsonStringField(ctx.allocator, out, "origin_instance_id", origin_instance_id, false);
    try appendNdjsonIntField(ctx.allocator, out, "origin_sequence", origin_sequence, false);
    try appendNdjsonIntField(ctx.allocator, out, "sequence", origin_sequence, false);
    try appendNdjsonIntField(ctx.allocator, out, "schema_version", 1, false);
    try appendNdjsonIntField(ctx.allocator, out, "timestamp_ms", timestamp_ms, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "store");
    try appendOptionalRawField(ctx.allocator, out, obj, "storage");
    try appendOptionalRawField(ctx.allocator, out, obj, "stores");
    try appendOptionalRawField(ctx.allocator, out, obj, "dedupe_key");
    try out.appendSlice(ctx.allocator, ",\"causality\":{\"origin_timestamp_ms\":");
    try out.print(ctx.allocator, "{d}", .{timestamp_ms});
    try out.append(ctx.allocator, '}');
    try out.appendSlice(ctx.allocator, ",\"payload\":{");
    try appendNdjsonStringField(ctx.allocator, out, "key", key, true);
    try appendNdjsonNullableStringField(ctx.allocator, out, "session_id", json.nullableStringField(obj, "session_id"), false);
    try appendNdjsonStringField(ctx.allocator, out, "category", category, false);
    if (json.stringField(obj, "value_kind")) |value_kind| try appendNdjsonStringField(ctx.allocator, out, "value_kind", value_kind, false);
    try appendNdjsonStringField(ctx.allocator, out, "content", content, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "owner_id");
    try appendOptionalRawField(ctx.allocator, out, obj, "store");
    try appendOptionalRawField(ctx.allocator, out, obj, "storage");
    try out.appendSlice(ctx.allocator, "}}");
}

const NullClawCheckpointKey = struct {
    logical_key: []const u8,
    session_id: ?[]const u8,
};

fn decodeNullClawCheckpointKey(key: []const u8) NullClawCheckpointKey {
    if (std.mem.startsWith(u8, key, "g:")) return .{ .logical_key = key[2..], .session_id = null };
    if (!std.mem.startsWith(u8, key, "s:")) return .{ .logical_key = key, .session_id = null };
    const rest = key[2..];
    const len_sep = std.mem.indexOfScalar(u8, rest, ':') orelse return .{ .logical_key = key, .session_id = null };
    const sid_len = std.fmt.parseInt(usize, rest[0..len_sep], 10) catch return .{ .logical_key = key, .session_id = null };
    const sid_start = 2 + len_sep + 1;
    if (sid_start > key.len or sid_len > key.len - sid_start) return .{ .logical_key = key, .session_id = null };
    const key_start = sid_start + sid_len;
    if (sid_len == 0 or key_start >= key.len or key[key_start] != ':') return .{ .logical_key = key, .session_id = null };
    return .{ .logical_key = key[key_start + 1 ..], .session_id = key[sid_start..key_start] };
}

test "api nullclaw checkpoint key decode treats oversized lengths as legacy" {
    const decoded = decodeNullClawCheckpointKey("s:18446744073709551615:a:key");
    try std.testing.expectEqualStrings("s:18446744073709551615:a:key", decoded.logical_key);
    try std.testing.expect(decoded.session_id == null);
}

fn appendNullClawCheckpointTombstoneEvent(ctx: *Context, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, operation: []const u8, event_count: *usize) !void {
    const raw_key = json.stringField(obj, "key") orelse return error.InvalidPayload;
    const decoded = decodeNullClawCheckpointKey(raw_key);
    const timestamp_ms = json.intField(obj, "timestamp_ms") orelse return error.InvalidPayload;
    const origin_instance_id = json.stringField(obj, "origin_instance_id") orelse return error.InvalidPayload;
    const origin_sequence = json.intField(obj, "origin_sequence") orelse return error.InvalidPayload;
    const event_type = if (std.mem.eql(u8, operation, "delete_all")) "agent_memory.delete_all" else "agent_memory.delete_scoped";
    if (event_count.* > 0) try out.append(ctx.allocator, ',');
    event_count.* += 1;
    try out.append(ctx.allocator, '{');
    try appendNdjsonStringField(ctx.allocator, out, "event_type", event_type, true);
    try appendNdjsonStringField(ctx.allocator, out, "operation", operation, false);
    try appendNdjsonStringField(ctx.allocator, out, "object_type", "agent_memory", false);
    try appendNdjsonStringField(ctx.allocator, out, "object_id", decoded.logical_key, false);
    try appendNdjsonStringField(ctx.allocator, out, "actor_id", ctx.actor_id, false);
    try appendNdjsonStringField(ctx.allocator, out, "origin_instance_id", origin_instance_id, false);
    try appendNdjsonIntField(ctx.allocator, out, "origin_sequence", origin_sequence, false);
    try appendNdjsonIntField(ctx.allocator, out, "sequence", origin_sequence, false);
    try appendNdjsonIntField(ctx.allocator, out, "schema_version", 1, false);
    try appendNdjsonIntField(ctx.allocator, out, "timestamp_ms", timestamp_ms, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "dedupe_key");
    try out.appendSlice(ctx.allocator, ",\"causality\":{\"origin_timestamp_ms\":");
    try out.print(ctx.allocator, "{d}", .{timestamp_ms});
    try out.append(ctx.allocator, '}');
    try out.appendSlice(ctx.allocator, ",\"payload\":{");
    try appendNdjsonStringField(ctx.allocator, out, "key", decoded.logical_key, true);
    try appendNdjsonNullableStringField(ctx.allocator, out, "session_id", if (std.mem.eql(u8, operation, "delete_all")) null else decoded.session_id, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "owner_id");
    try appendOptionalRawField(ctx.allocator, out, obj, "store");
    try appendOptionalRawField(ctx.allocator, out, obj, "storage");
    try out.appendSlice(ctx.allocator, "}}");
}

fn isNullClawTopLevelMemoryEvent(obj: std.json.ObjectMap) bool {
    return json.stringField(obj, "key") != null and obj.get("payload") == null and json.stringField(obj, "object_type") == null;
}

fn nullClawEventToNativeFeedEvent(ctx: *Context, obj: std.json.ObjectMap) ![]const u8 {
    const key = json.stringField(obj, "key") orelse return error.InvalidPayload;
    const operation = json.stringField(obj, "operation") orelse "put";
    if (!feed_contract.nullClawMemoryApplyOperationSupported(operation)) return error.InvalidPayload;
    const event_type = try std.fmt.allocPrint(ctx.allocator, "agent_memory.{s}", .{operation});
    defer ctx.allocator.free(event_type);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '{');
    try appendJsonStringField(ctx.allocator, &out, "event_type", event_type, true);
    try appendJsonStringField(ctx.allocator, &out, "operation", operation, false);
    try appendJsonStringField(ctx.allocator, &out, "object_type", "agent_memory", false);
    try appendJsonStringField(ctx.allocator, &out, "object_id", key, false);
    try appendJsonStringField(ctx.allocator, &out, "actor_id", json.stringField(obj, "actor_id") orelse ctx.actor_id, false);
    try appendOptionalStringField(ctx.allocator, &out, obj, "origin_instance_id");
    try appendOptionalRawField(ctx.allocator, &out, obj, "origin_sequence");
    try appendOptionalRawField(ctx.allocator, &out, obj, "sequence");
    try appendOptionalRawField(ctx.allocator, &out, obj, "timestamp_ms");
    try appendOptionalRawField(ctx.allocator, &out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, &out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, &out, obj, "store");
    try appendOptionalRawField(ctx.allocator, &out, obj, "storage");
    try appendOptionalRawField(ctx.allocator, &out, obj, "stores");
    try appendOptionalRawField(ctx.allocator, &out, obj, "dedupe_key");
    try appendNullClawCausalityField(ctx.allocator, &out, obj);
    try out.appendSlice(ctx.allocator, ",\"payload\":{");
    try appendNullClawEventPayload(ctx, &out, obj, operation, key);
    try out.append(ctx.allocator, '}');
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn appendNullClawEventPayload(ctx: *Context, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, operation: []const u8, key: []const u8) !void {
    try appendJsonStringField(ctx.allocator, out, "key", key, true);
    if (json.stringField(obj, "category")) |category| try appendJsonStringField(ctx.allocator, out, "category", category, false);
    if (nullableStringFieldAlias(obj, "session_id", "session")) |session_id| try appendJsonStringField(ctx.allocator, out, "session_id", session_id, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "store");
    try appendOptionalRawField(ctx.allocator, out, obj, "storage");
    try appendOptionalRawField(ctx.allocator, out, obj, "stores");
    try appendOptionalRawField(ctx.allocator, out, obj, "value_kind");

    if (std.mem.eql(u8, operation, "merge_string_set")) {
        if (obj.get("values")) |values| {
            try out.appendSlice(ctx.allocator, ",\"values\":");
            try appendRawJsonValue(ctx.allocator, out, values);
        } else if (json.stringField(obj, "content")) |content| {
            try out.appendSlice(ctx.allocator, ",\"values\":");
            try appendNullClawContentAsRawJsonOrString(ctx.allocator, out, content);
        } else if (obj.get("value")) |value| {
            try out.appendSlice(ctx.allocator, ",\"value\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    } else if (std.mem.eql(u8, operation, "merge_object")) {
        if (obj.get("object")) |object| {
            if (object != .object) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try appendRawJsonValue(ctx.allocator, out, object);
        } else if (json.stringField(obj, "content")) |content| {
            if (!jsonStringIsObject(ctx.allocator, content)) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try out.appendSlice(ctx.allocator, content);
        } else if (obj.get("value")) |value| {
            if (value != .object) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    } else if (std.mem.eql(u8, operation, "put")) {
        if (json.stringField(obj, "content")) |content| {
            try appendJsonStringField(ctx.allocator, out, "content", content, false);
        } else if (json.stringField(obj, "text")) |text| {
            try appendJsonStringField(ctx.allocator, out, "content", text, false);
        } else if (obj.get("value")) |value| {
            try out.appendSlice(ctx.allocator, ",\"value\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    }
}

fn appendJsonStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: []const u8, first: bool) !void {
    if (!first) try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendString(out, allocator, value);
}

fn appendOptionalStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, name: []const u8) !void {
    if (json.stringField(obj, name)) |value| try appendJsonStringField(allocator, out, name, value, false);
}

fn appendOptionalRawField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, name: []const u8) !void {
    const value = obj.get(name) orelse return;
    try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try appendRawJsonValue(allocator, out, value);
}

fn appendNullClawCausalityField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap) !void {
    if (obj.get("causality")) |value| {
        try out.append(allocator, ',');
        try json.appendString(out, allocator, "causality");
        try out.append(allocator, ':');
        try appendRawJsonValue(allocator, out, value);
        return;
    }
    const timestamp_value = obj.get("timestamp_ms") orelse return;
    try out.appendSlice(allocator, ",\"causality\":{\"origin_timestamp_ms\":");
    try appendRawJsonValue(allocator, out, timestamp_value);
    try out.append(allocator, '}');
}

fn appendRawJsonValue(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), value: std.json.Value) !void {
    const raw = try json.jsonFromValue(allocator, value);
    defer allocator.free(raw);
    try out.appendSlice(allocator, raw);
}

fn appendNullClawContentAsRawJsonOrString(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), content: []const u8) !void {
    if (std.json.validate(allocator, content) catch false) {
        try out.appendSlice(allocator, content);
    } else {
        try json.appendString(out, allocator, content);
    }
}

fn jsonStringIsObject(allocator: std.mem.Allocator, content: []const u8) bool {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, content, .{}) catch return false;
    defer parsed.deinit();
    return parsed.value == .object;
}

fn responseEventId(allocator: std.mem.Allocator, body: []const u8) ?i64 {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return null;
    defer parsed.deinit();
    if (parsed.value != .object) return null;
    return json.intField(parsed.value.object, "event_id");
}

fn feedPayloadWithRoute(ctx: *Context, payload_json: []const u8, route: store_mod.AgentMemoryStorageRoute, route_authoritative: bool) ![]const u8 {
    return if (route_authoritative)
        feed_contract.withStorageRouteOverride(ctx.allocator, payload_json, route)
    else
        store_mod.payloadWithStorageRouteJson(ctx.allocator, payload_json, route);
}

fn feedCausalityJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn restorePendingCheckpointEvent(ctx: *Context, obj: std.json.ObjectMap, fallback_route: store_mod.AgentMemoryStorageRoute, fallback_route_authoritative: bool) !i64 {
    const event_type = json.stringField(obj, "event_type") orelse return error.InvalidPayload;
    const operation = json.stringField(obj, "operation") orelse feed_contract.operationFromEventType(event_type);
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    if (!feed_contract.objectTypeSupported(object_type)) return error.UnsupportedObjectType;
    const object_id = json.stringField(obj, "object_id") orelse return error.InvalidPayload;
    const event_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return error.Forbidden;
    const payload_json = feedPayloadJson(ctx.allocator, obj) catch return error.InvalidPayload;
    const explicit_or_fallback_route = storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route) catch return error.InvalidPayload;
    const payload_route = feedObjectPayloadRoute(ctx, object_type, explicit_or_fallback_route);
    const event_payload_json = feedPayloadWithRoute(ctx, payload_json, payload_route, storage_routes.objectHasSelector(obj) or fallback_route_authoritative) catch return error.InvalidPayload;
    defer ctx.allocator.free(event_payload_json);
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return error.InvalidPayload;
    const permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return error.InvalidPayload;
    const dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return error.InvalidPayload;
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        if (try feed_contract.agentMemoryPayloadIsInternal(ctx.allocator, event_payload_json)) return error.InternalAgentMemory;
        if (!canApplyAgentMemoryScope(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        if (try feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json)) return error.InternalAgentSessionMessage;
        if (!canProposeAgentSessionEvent(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canProposeAgentSessionEvent(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (!canWriteRecord(ctx, scope, permissions_json)) return error.Forbidden;
    const causality_json = feedCausalityJson(ctx, obj, &.{"causality"}, "{}") catch return error.InvalidPayload;

    if (dedupe_key) |key| {
        if (try ctx.store.getFeedEventByDedupeKey(ctx.allocator, key)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return error.Forbidden;
            if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = object_id, .scope = scope, .permissions_json = permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return error.FeedDedupeMismatch;
            return event.id;
        }
    }

    return try ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = operation,
        .object_type = object_type,
        .object_id = object_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .actor_id = event_actor_id,
        .dedupe_key = dedupe_key,
        .causality_json = causality_json,
        .payload_json = event_payload_json,
        .status = "pending",
    });
}

fn appendMemoryFeed(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (isNullClawTopLevelMemoryEvent(obj)) {
        const transformed = nullClawEventToNativeFeedEvent(ctx, obj) catch return badJson(ctx);
        defer ctx.allocator.free(transformed);
        return appendMemoryFeed(ctx, transformed, query);
    }
    const event_type = json.stringField(obj, "event_type") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing event_type");
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    if (!feed_contract.objectTypeSupported(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type");
    }
    if (runtimeFeedQuerySelected(query) and !feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Runtime feed backend only supports agent runtime object types");
    }
    const payload_json = feedPayloadJson(ctx.allocator, obj) catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload"),
        else => return serverError(ctx),
    };
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch |err| return storageRouteError(ctx, err);
    const payload_route = feedObjectPayloadRoute(ctx, object_type, storage_route);
    const event_payload_json = feedPayloadWithRoute(ctx, payload_json, payload_route, storage_routes.objectHasSelector(obj) or storage_routes.queryHasSelector(query)) catch return serverError(ctx);
    defer ctx.allocator.free(event_payload_json);
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, ctx.actor_id) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload");
    const permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, ctx.actor_id) catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed permissions"),
        else => return serverError(ctx),
    };
    const dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return serverError(ctx);
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        const internal_payload = feed_contract.agentMemoryPayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx);
        if (internal_payload) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be queued through the feed");
        if (!canProposeRecord(ctx, scope, permissions_json) and !canApplyAgentMemoryScope(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        const internal_payload = feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx);
        if (internal_payload) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be queued through the feed");
        if (!canProposeAgentSessionEvent(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canProposeAgentSessionEvent(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (!canProposeRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const event_object_id = json.stringField(obj, "object_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing object_id");
    const causality_json = feedCausalityJson(ctx, obj, &.{"causality"}, "{}") catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed causality"),
        else => return serverError(ctx),
    };
    if (dedupe_key) |key| {
        if (ctx.store.getFeedEventByDedupeKey(ctx.allocator, key) catch return serverError(ctx)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return forbidden(ctx);
            if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = json.stringField(obj, "operation") orelse "put", .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = permissions_json, .actor_id = ctx.actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) {
                return feedDedupeConflict(ctx);
            }
            const response = std.fmt.allocPrint(ctx.allocator, "{{\"event_id\":{d},\"queued\":true}}", .{event.id}) catch return serverError(ctx);
            return .{ .status = "200 OK", .body = response };
        }
    }
    const id = ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = json.stringField(obj, "operation") orelse "put",
        .object_type = object_type,
        .object_id = event_object_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .actor_id = ctx.actor_id,
        .dedupe_key = dedupe_key,
        .causality_json = causality_json,
        .payload_json = event_payload_json,
        .status = "pending",
    }) catch |err| switch (err) {
        error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
        else => return serverError(ctx),
    };
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"event_id\":{d},\"queued\":true}}", .{id}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn applyMemoryEvent(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    return applyMemoryEventInternal(ctx, body, query, null);
}

fn applyMemoryEventWithOriginProjection(ctx: *Context, body: []const u8, query: []const u8, origin_projection_override: []const u8) HttpResponse {
    return applyMemoryEventInternal(ctx, body, query, origin_projection_override);
}

fn applyMemoryEventInternal(ctx: *Context, body: []const u8, query: []const u8, origin_projection_override: ?[]const u8) HttpResponse {
    if (!canApplyFeed(ctx)) return forbidden(ctx);
    if (isNullClawNdjsonCheckpointPayload(ctx.allocator, body)) return if (origin_projection_override) |projection|
        memoryFeedCheckpointRestoreInternal(ctx, body, query, .{ .name = projection })
    else
        memoryFeedCheckpointRestoreInternal(ctx, body, query, null);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (checkpointEventsValue(obj) != null) return if (origin_projection_override) |projection|
        memoryFeedCheckpointRestoreInternal(ctx, body, query, .{ .name = projection })
    else
        memoryFeedCheckpointRestoreInternal(ctx, body, query, null);
    if (isNullClawTopLevelMemoryEvent(obj)) {
        const transformed = nullClawEventToNativeFeedEvent(ctx, obj) catch return badJson(ctx);
        defer ctx.allocator.free(transformed);
        return applyMemoryEventInternal(ctx, transformed, query, origin_projection_override);
    }
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route, query) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedApply(ctx, runtime, body);
    }
    const event_type = json.stringField(obj, "event_type") orelse "memory_atom.upsert";
    const operation = json.stringField(obj, "operation") orelse feed_contract.operationFromEventType(event_type);
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    const event_object_id = json.nullableStringField(obj, "object_id");
    if (!feed_contract.objectTypeSupported(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type");
    }
    if (runtimeFeedQuerySelected(query) and !feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Runtime feed backend only supports agent runtime object types");
    }
    const event_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return forbidden(ctx);
    const event_order = agentMemoryEventOrderFromFeedObject(obj);
    const payload_json = feedPayloadJson(ctx.allocator, obj) catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload"),
        else => return serverError(ctx),
    };
    const event_payload_route = feedObjectPayloadRoute(ctx, object_type, storage_route);
    const event_payload_json = feedPayloadWithRoute(ctx, payload_json, event_payload_route, storage_routes.objectHasSelector(obj) or storage_routes.queryHasSelector(query)) catch return serverError(ctx);
    defer ctx.allocator.free(event_payload_json);
    const causality_json = feedCausalityJson(ctx, obj, &.{"causality"}, "{}") catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed causality"),
        else => return serverError(ctx),
    };
    const event_dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return serverError(ctx);
    const origin_identity = if (event_dedupe_key) |key| feed_contract.parseOriginDedupeKey(key) else null;
    var owned_origin_projection: ?[]const u8 = null;
    defer if (owned_origin_projection) |projection| ctx.allocator.free(projection);
    const origin_projection = origin_projection_override orelse blk: {
        if (runtimeFeedQuerySelected(query) and feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) {
            const projection = centralRuntimeFeedProjectionForRoute(ctx, storage_route) catch return serverError(ctx);
            owned_origin_projection = projection.name;
            break :blk owned_origin_projection.?;
        }
        owned_origin_projection = feedOriginProjectionForEvent(ctx, object_type, storage_route) catch return serverError(ctx);
        break :blk owned_origin_projection.?;
    };
    if (feedOriginEventAlreadyApplied(ctx, origin_projection, origin_identity) catch return serverError(ctx)) {
        return skippedOriginFrontierResponse(ctx, object_type, event_object_id orelse "unknown");
    }
    if (std.mem.eql(u8, object_type, "agent_memory") and isAgentMemoryStatusLifecycleOperation(operation)) {
        const response = applyAgentMemoryLifecycleMutation(ctx, obj, event_type, operation, event_actor_id, event_payload_json, event_payload_route, causality_json, event_order);
        return feedApplyResponseWithOriginFrontier(ctx, response, origin_projection, origin_identity);
    }
    if (feed_contract.isLifecycleOperation(operation) and !feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) {
        const response = applyFeedLifecycleMutation(ctx, obj, event_type, operation, object_type, event_actor_id, event_payload_json, causality_json);
        return feedApplyResponseWithOriginFrontier(ctx, response, origin_projection, origin_identity);
    }
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch |err| switch (err) {
        error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload"),
        else => return serverError(ctx),
    };
    const event_permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch |err| switch (err) {
        error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed permissions"),
        else => return serverError(ctx),
    };
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        if (feed_contract.isAgentMemoryDeleteOperation(operation)) {
            if (!canDeleteAgentMemoryScope(ctx, event_actor_id, operation, scope, event_permissions_json)) return forbidden(ctx);
        } else if (!canApplyAgentMemoryScope(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        if (feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be applied through the feed");
        if (!canApplyAgentSessionEvent(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canApplyAgentSessionEvent(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (!canWriteRecord(ctx, scope, event_permissions_json)) return forbidden(ctx);
    var memory_input: ?store_mod.MemoryAtomInput = null;
    if (std.mem.eql(u8, object_type, "memory_atom")) {
        memory_input = buildAppliedMemoryAtomInput(ctx, event_payload_json, scope, event_object_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.MissingText => return json.errorResponse(ctx.allocator, 400, "bad_request", "Memory apply payload must include text/content"),
            error.InvalidPayload, error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid memory apply payload"),
            else => return serverError(ctx),
        };
    }
    var agent_memory_input: ?store_mod.AgentMemoryInput = null;
    var agent_memory_delete_key: ?[]const u8 = null;
    var agent_memory_delete_session_id: ?[]const u8 = null;
    var agent_memory_delete_actor_id: ?[]const u8 = null;
    var agent_memory_delete_all = false;
    var agent_memory_route: store_mod.AgentMemoryStorageRoute = .{};
    var agent_memory_prepared: ?AgentMemoryApplyInput = null;
    defer {
        if (agent_memory_prepared) |*prepared| prepared.deinit(ctx.allocator);
    }
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        agent_memory_prepared = buildAppliedAgentMemoryInput(ctx, operation, event_payload_json, event_object_id, event_actor_id, event_payload_route, event_order) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be applied through the feed"),
            error.MissingKey, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory apply payload must include key/object_id and valid merge content"),
            else => return serverError(ctx),
        };
        const prepared = agent_memory_prepared.?;
        agent_memory_route = prepared.route;
        if (prepared.delete_key) |key| {
            agent_memory_delete_key = key;
            agent_memory_delete_session_id = prepared.delete_session_id;
            agent_memory_delete_actor_id = prepared.delete_actor_id;
            agent_memory_delete_all = prepared.delete_all;
        } else {
            agent_memory_input = prepared.input;
        }
    }
    var session_message_input: ?AgentSessionMessageApplyInput = null;
    if (std.mem.eql(u8, object_type, "agent_session_message")) {
        session_message_input = buildAppliedAgentSessionMessageInput(ctx, operation, event_payload_json, event_actor_id, event_payload_route, event_order) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.InternalAgentSessionMessage => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be applied through the feed"),
            error.MissingRequiredField, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Session message feed payload must include session_id, role and content"),
            else => return serverError(ctx),
        };
    }
    var session_usage_input: ?AgentSessionUsageApplyInput = null;
    if (std.mem.eql(u8, object_type, "agent_session_usage")) {
        session_usage_input = buildAppliedAgentSessionUsageInput(ctx, operation, event_payload_json, event_actor_id, event_payload_route, event_order) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.MissingRequiredField, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Session usage feed payload must include session_id and total_tokens"),
            else => return serverError(ctx),
        };
    }
    var reserved_event_id: ?i64 = null;
    if (event_dedupe_key) |dedupe_key| {
        if (ctx.store.getFeedEventByDedupeKey(ctx.allocator, dedupe_key) catch return serverError(ctx)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return forbidden(ctx);
            if (!std.mem.eql(u8, event.status, "applied")) {
                if (std.mem.eql(u8, event.status, "applying") and feedApplyReservationIsStale(ids.nowMs(), event.created_at_ms)) {
                    _ = ctx.store.releaseFeedEventReservation(event.id) catch return serverError(ctx);
                } else {
                    return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying");
                }
            } else {
                if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = event_permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return feedDedupeConflict(ctx);
                return appliedFeedObjectResponseWithOriginFrontier(ctx, event.id, event.object_type, event.object_id, if (std.mem.eql(u8, event.object_type, "memory_atom")) event.object_id else null, origin_projection, origin_identity);
            }
        }
        const reservation_id = ids.make(ctx.allocator, "apply_") catch return serverError(ctx);
        reserved_event_id = ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = reservation_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applying",
        }) catch return serverError(ctx);
        const reservation = (ctx.store.getFeedEventByDedupeKey(ctx.allocator, dedupe_key) catch return serverError(ctx)) orelse return serverError(ctx);
        if (reservation.id != reserved_event_id.? or !std.mem.eql(u8, reservation.status, "applying") or !std.mem.eql(u8, reservation.object_id, reservation_id)) {
            if (std.mem.eql(u8, reservation.status, "applied")) {
                if (!feed_contract.dedupeMatches(reservation, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = event_permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return feedDedupeConflict(ctx);
                return appliedFeedObjectResponseWithOriginFrontier(ctx, reservation.id, reservation.object_type, reservation.object_id, if (std.mem.eql(u8, reservation.object_type, "memory_atom")) reservation.object_id else null, origin_projection, origin_identity);
            }
            return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying");
        }
    }
    const memory_atom_id: ?[]const u8 = null;
    if (memory_input) |input| {
        var prepared = prepareAppliedMemoryProvenance(ctx, input) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            else => return serverError(ctx),
        };
        prepared.atom.actor_id = event_actor_id;
        if (prepared.generated_source) |source_input| {
            var auditable_source = source_input;
            auditable_source.actor_id = event_actor_id;
            prepared.generated_source = auditable_source;
        }
        const applied = ctx.store.applyFeedMemoryAtomAtomic(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = "pending",
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .prepared = prepared,
        }) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                else => serverError(ctx),
            };
        };
        return appliedFeedResponseWithOriginFrontier(ctx, applied.event_id, applied.atom.id, origin_projection, origin_identity);
    }
    if (agent_memory_input) |input| {
        const applied = ctx.store.applyFeedAgentMemoryRouted(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = "pending",
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .input = input,
            .writer_actor_id = event_actor_id,
            .actor_scopes_json = ctx.actor_scopes_json,
            .actor_capabilities_json = ctx.actor_capabilities_json,
            .event_order = event_order,
        }, agent_memory_route) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.MissingActorId => json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory events require an actor"),
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                else => serverError(ctx),
            };
        };
        const response = appliedFeedObjectResponseWithOriginFrontier(ctx, applied.event_id, object_type, applied.object_id, null, origin_projection, origin_identity);
        var applied_entry = applied.entry;
        if (applied_entry) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
        return response;
    }
    if (agent_memory_delete_key) |delete_key| {
        const applied = ctx.store.applyFeedAgentMemoryRouted(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = delete_key,
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .delete_key = delete_key,
            .delete_session_id = agent_memory_delete_session_id,
            .delete_owner_actor_id = agent_memory_delete_actor_id orelse event_actor_id,
            .delete_all = agent_memory_delete_all,
            .writer_actor_id = event_actor_id,
            .actor_scopes_json = ctx.actor_scopes_json,
            .actor_capabilities_json = ctx.actor_capabilities_json,
            .event_order = event_order,
        }, agent_memory_route) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                else => serverError(ctx),
            };
        };
        return appliedFeedObjectResponseWithOriginFrontier(ctx, applied.event_id, object_type, applied.object_id, null, origin_projection, origin_identity);
    }
    if (session_message_input) |input| {
        const object_id = event_object_id orelse blk: {
            if (input.delete_autosaved) break :blk store_mod.agentSessionAutosaveSetObjectId(ctx.allocator, input.session_id, input.actor_id) catch return serverError(ctx);
            const sid = input.session_id orelse return serverError(ctx);
            if (input.delete_all) break :blk store_mod.agentSessionMessageSetObjectId(ctx.allocator, sid, input.actor_id) catch return serverError(ctx);
            break :blk store_mod.agentSessionMessageObjectId(ctx.allocator, sid, input.role, input.content, input.created_at_ms, input.actor_id) catch return serverError(ctx);
        };
        if (input.delete_autosaved) {
            ctx.store.clearAutoSavedRoutedSuppressFeedWithAuth(input.session_id, input.actor_id, ctx.actor_capabilities_json, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else if (input.delete_all) {
            const sid = input.session_id orelse return serverError(ctx);
            ctx.store.clearMessagesRoutedSuppressFeedOrderedWithAuth(sid, input.actor_id, ctx.actor_capabilities_json, input.route, input.event_order) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else {
            const sid = input.session_id orelse return serverError(ctx);
            ctx.store.saveMessageRoutedAtSuppressFeedOrderedWithAuth(sid, input.role, input.content, input.created_at_ms, input.actor_id, ctx.actor_capabilities_json, input.route, input.event_order) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        }
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponseWithOriginFrontier(ctx, event_id, object_type, object_id, null, origin_projection, origin_identity);
    }
    if (session_usage_input) |input| {
        const object_id = event_object_id orelse (store_mod.agentSessionUsageObjectId(ctx.allocator, input.session_id, input.actor_id) catch return serverError(ctx));
        if (input.delete_usage) {
            _ = ctx.store.deleteUsageRoutedSuppressFeedOrderedWithAuth(input.session_id, input.actor_id, ctx.actor_capabilities_json, input.route, input.event_order) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else {
            ctx.store.saveUsageRoutedSuppressFeedOrderedWithAuth(input.session_id, input.total_tokens, input.actor_id, ctx.actor_capabilities_json, input.route, input.event_order) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        }
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponseWithOriginFrontier(ctx, event_id, object_type, object_id, null, origin_projection, origin_identity);
    }
    if (!std.mem.eql(u8, object_type, "memory_atom") and !std.mem.eql(u8, object_type, "agent_memory")) {
        const object_id = applyFeedObjectPut(ctx, object_type, event_payload_json, scope, event_permissions_json, event_actor_id, event_object_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden,
            error.RelatedEntityNotFound,
            error.RecordAclBroaderThanRelatedEntity,
            error.SpaceNotFound,
            error.ArtifactAclBroaderThanSpace,
            error.CanonicalArtifactNotFound,
            error.EntityAclBroaderThanCanonicalArtifact,
            error.ContextPackReferenceNotFound,
            error.ContextPackAclBroaderThanRefs,
            => return forbidden(ctx),
            error.InvalidPayload, error.MissingRequiredField, error.InvalidRawJson => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload for object_type"),
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponseWithOriginFrontier(ctx, event_id, object_type, object_id, null, origin_projection, origin_identity);
    }
    if (reserved_event_id) |event_id| {
        const object_id = memory_atom_id orelse (event_object_id orelse "unknown");
        if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
            return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
        }
        return appliedFeedResponseWithOriginFrontier(ctx, event_id, memory_atom_id, origin_projection, origin_identity);
    }
    const id = ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = operation,
        .object_type = object_type,
        .object_id = memory_atom_id orelse (event_object_id orelse "unknown"),
        .scope = scope,
        .permissions_json = event_permissions_json,
        .actor_id = event_actor_id,
        .dedupe_key = event_dedupe_key,
        .causality_json = causality_json,
        .payload_json = event_payload_json,
        .status = "applied",
    }) catch return serverError(ctx);
    return appliedFeedResponseWithOriginFrontier(ctx, id, memory_atom_id, origin_projection, origin_identity);
}

fn feedIdOverride(obj: std.json.ObjectMap, event_object_id: ?[]const u8, prefix: []const u8) !?[]const u8 {
    if (json.stringField(obj, "id")) |id| {
        if (std.mem.startsWith(u8, id, prefix) and id.len > prefix.len) return id;
        return error.InvalidPayload;
    }
    if (event_object_id) |id| {
        if (std.mem.startsWith(u8, id, prefix) and id.len > prefix.len) return id;
    }
    return null;
}

fn buildAppliedMemoryAtomInput(ctx: *Context, payload_json: []const u8, fallback_scope: []const u8, event_object_id: ?[]const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !store_mod.MemoryAtomInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const text = json.stringField(obj, "text") orelse json.stringField(obj, "content") orelse return error.MissingText;
    const atom_scope = json.stringField(obj, "scope") orelse fallback_scope;
    const permissions_json = payloadArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, "[]") catch return error.InvalidRawJson;
    const input = store_mod.MemoryAtomInput{
        .id = try feedIdOverride(obj, event_object_id, "mem_"),
        .subject_entity_id = json.nullableStringField(obj, "subject_entity_id"),
        .text = text,
        .scope = atom_scope,
        .predicate = json.stringField(obj, "predicate") orelse "states",
        .object = json.stringField(obj, "object") orelse "",
        .confidence = json.floatField(obj, "confidence") orelse 0.7,
        .status = json.nullableStringField(obj, "status"),
        .source_ids_json = try payloadArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json" }, "[]"),
        .evidence_ranges_json = try payloadArrayJson(ctx, obj, &.{ "evidence_ranges", "evidence_ranges_json" }, "[]"),
        .created_by = json.stringField(obj, "created_by") orelse "agent",
        .valid_from_ms = json.intField(obj, "valid_from_ms"),
        .valid_until_ms = json.intField(obj, "valid_until_ms"),
        .owner = json.nullableStringField(obj, "owner"),
        .permissions_json = permissions_json,
        .tags_json = try payloadArrayJson(ctx, obj, &.{ "tags", "tags_json" }, "[\"feed\"]"),
        .storage_route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route),
        .suppress_feed = true,
    };
    if (!canCreateMemoryAtom(ctx, input)) return error.Forbidden;
    return input;
}

const AgentMemoryApplyInput = struct {
    input: ?store_mod.AgentMemoryInput = null,
    delete_key: ?[]const u8 = null,
    delete_session_id: ?[]const u8 = null,
    delete_actor_id: ?[]const u8 = null,
    delete_all: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
    owned_owner_actor_id: ?[]const u8 = null,

    fn deinit(self: *AgentMemoryApplyInput, allocator: std.mem.Allocator) void {
        if (self.input) |input| allocator.free(input.content);
        if (self.owned_owner_actor_id) |owner| allocator.free(owner);
        self.owned_owner_actor_id = null;
    }
};

const AgentMemoryOwnerLease = struct {
    value: []const u8,
    owned: ?[]const u8 = null,

    fn deinit(self: *AgentMemoryOwnerLease, allocator: std.mem.Allocator) void {
        if (self.owned) |owner| allocator.free(owner);
        self.owned = null;
    }

    fn transfer(self: *AgentMemoryOwnerLease) ?[]const u8 {
        const owned = self.owned;
        self.owned = null;
        return owned;
    }
};

fn agentMemoryOwnerLease(ctx: *Context, event_actor_id: []const u8, scope: ?[]const u8, obj: std.json.ObjectMap) !AgentMemoryOwnerLease {
    const computed_owner_id = try access.agentMemoryOwner(ctx.allocator, event_actor_id, scope);
    errdefer ctx.allocator.free(computed_owner_id);
    if (json.stringField(obj, "owner_id")) |explicit_owner_id| {
        if (!std.mem.eql(u8, explicit_owner_id, computed_owner_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
        ctx.allocator.free(computed_owner_id);
        return .{ .value = explicit_owner_id };
    }
    return .{ .value = computed_owner_id, .owned = computed_owner_id };
}

fn agentMemoryValueKindField(obj: std.json.ObjectMap) !?[]const u8 {
    const value = obj.get("value_kind") orelse return null;
    if (value != .string) return error.InvalidPayload;
    if (agent_memory_reducer.ValueKind.parse(value.string) == null) return error.InvalidPayload;
    return value.string;
}

test "agent memory owner lease owns computed shared owner and rejects spoofed owner" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();

    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = &store,
        .actor_id = "agent:a",
        .actor_scopes_json = "[\"team:alpha\",\"write:team:alpha\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"feed_apply\"]",
    };

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"scope\":\"team:alpha\"}", .{});
    defer parsed.deinit();

    var lease = try agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", parsed.value.object);
    defer lease.deinit(std.testing.allocator);
    try std.testing.expectEqualStrings("shared:team:alpha", lease.value);
    try std.testing.expect(lease.owned != null);

    var explicit = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"owner_id\":\"shared:team:alpha\"}", .{});
    defer explicit.deinit();

    var explicit_lease = try agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", explicit.value.object);
    defer explicit_lease.deinit(std.testing.allocator);
    try std.testing.expectEqualStrings("shared:team:alpha", explicit_lease.value);
    try std.testing.expect(explicit_lease.owned == null);

    var spoofed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"owner_id\":\"shared:team:beta\"}", .{});
    defer spoofed.deinit();

    try std.testing.expectError(error.Forbidden, agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", spoofed.value.object));
}

const AgentMemoryLifecycleApplyInput = struct {
    key: []const u8,
    session_id: ?[]const u8,
    owner_actor_id: []const u8,
    scope: []const u8,
    permissions_json: []const u8,
    status: []const u8,
    route: store_mod.AgentMemoryStorageRoute = .{},
    event_order: ?store_mod.AgentMemoryEventOrder = null,
    replay_blocked_by_tombstone: bool = false,
};

const AgentMemoryLifecycleRouteMode = enum {
    payload_or_fallback,
    fallback_authoritative,
};

fn buildMissingAgentMemoryLifecycleInput(ctx: *Context, operation: []const u8, obj: std.json.ObjectMap, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, scope: ?[]const u8, requested_permissions_json: []const u8, route: store_mod.AgentMemoryStorageRoute, event_order: ?store_mod.AgentMemoryEventOrder, replay_blocked_by_tombstone: bool) !AgentMemoryLifecycleApplyInput {
    const effective_scope = try access.agentMemoryScope(ctx.allocator, owner_actor_id, session_id, scope);
    errdefer ctx.allocator.free(effective_scope);
    const effective_permissions = try access.agentMemoryPermissions(ctx.allocator, owner_actor_id, scope, requested_permissions_json);
    errdefer ctx.allocator.free(effective_permissions);
    if (!feedLifecycleMutationAllowed(ctx, operation, effective_scope, effective_permissions)) return error.Forbidden;
    const payload_status = feed_contract.statusFromLifecycleOperation(operation, obj);
    return .{
        .key = try ctx.allocator.dupe(u8, key),
        .session_id = if (session_id) |sid| try ctx.allocator.dupe(u8, sid) else null,
        .owner_actor_id = try ctx.allocator.dupe(u8, owner_actor_id),
        .scope = effective_scope,
        .permissions_json = effective_permissions,
        .status = try ctx.allocator.dupe(u8, payload_status),
        .route = route,
        .event_order = event_order,
        .replay_blocked_by_tombstone = replay_blocked_by_tombstone,
    };
}

const AgentSessionMessageApplyInput = struct {
    session_id: ?[]const u8,
