    content: []const u8 = "",
    created_at_ms: i64 = 0,
    actor_id: ?[]const u8,
    delete_all: bool = false,
    delete_autosaved: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
    event_order: ?store_mod.AgentMemoryEventOrder = null,
};

const AgentSessionUsageApplyInput = struct {
    session_id: []const u8,
    total_tokens: u64 = 0,
    actor_id: ?[]const u8,
    delete_usage: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
    event_order: ?store_mod.AgentMemoryEventOrder = null,
};

const stale_feed_apply_reservation_ms: i64 = 5 * 60 * 1000;

fn feedApplyReservationIsStale(now_ms: i64, created_at_ms: i64) bool {
    return time_math.elapsedSinceMs(now_ms, created_at_ms) > stale_feed_apply_reservation_ms;
}

test "api feed apply reservation stale check is overflow safe" {
    try std.testing.expect(!feedApplyReservationIsStale(1_000 + stale_feed_apply_reservation_ms, 1_000));
    try std.testing.expect(feedApplyReservationIsStale(1_001 + stale_feed_apply_reservation_ms, 1_000));
    try std.testing.expect(!feedApplyReservationIsStale(1_000, 2_000));
    try std.testing.expect(feedApplyReservationIsStale(std.math.maxInt(i64), std.math.minInt(i64)));
}

fn canApplyAsActor(ctx: *Context, event_actor_id: []const u8) bool {
    return std.mem.eql(u8, event_actor_id, ctx.actor_id) or domain.hasActorScope(ctx.actor_scopes_json, "admin");
}

fn canApplyAgentMemoryScope(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (canWriteRecord(ctx, scope, permissions_json)) return true;
    if (!domain.isActorOwnedAgentMemoryScope(scope, event_actor_id)) return false;
    return (hasCapability(ctx, "write") or hasCapability(ctx, "propose")) and
        access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn canDeleteAgentMemoryScope(ctx: *Context, event_actor_id: []const u8, operation: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (feedLifecycleMutationAllowed(ctx, operation, scope, permissions_json)) return true;
    if (!domain.isActorOwnedAgentMemoryScope(scope, event_actor_id)) return false;
    return hasCapability(ctx, "delete") and
        access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn isAgentMemoryStatusLifecycleOperation(operation: []const u8) bool {
    return std.mem.eql(u8, operation, "verify") or
        std.mem.eql(u8, operation, "mark_stale") or
        std.mem.eql(u8, operation, "stale") or
        std.mem.eql(u8, operation, "supersede") or
        std.mem.eql(u8, operation, "forget");
}

fn applyAgentMemoryLifecycleMutation(ctx: *Context, obj: std.json.ObjectMap, event_type: []const u8, operation: []const u8, event_actor_id: []const u8, payload_json: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, causality_json: []const u8, event_order: ?store_mod.AgentMemoryEventOrder) HttpResponse {
    const input = buildAppliedAgentMemoryLifecycleInput(ctx, operation, payload_json, json.nullableStringField(obj, "object_id"), event_actor_id, fallback_route, .payload_or_fallback, event_order) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found"),
        error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be applied through the feed"),
        error.MissingKey, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory lifecycle payload must include key/object_id"),
        else => return serverError(ctx),
    };
    if (!input.replay_blocked_by_tombstone) {
        if (!(ctx.store.patchAgentMemoryStatusRoutedOrderedWithAuth(ctx.allocator, input.key, input.session_id, input.owner_actor_id, input.status, event_actor_id, ctx.actor_scopes_json, ctx.actor_capabilities_json, input.route, input.event_order) catch return serverError(ctx))) {
            return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found");
        }
    }
    const event_id = applyOrAppendFeedEventRecord(ctx, obj, event_type, operation, "agent_memory", input.key, input.scope, input.permissions_json, event_actor_id, causality_json, payload_json) catch |err| switch (err) {
        error.FeedConflict => return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying"),
        error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };
    return appliedFeedObjectResponse(ctx, event_id, "agent_memory", input.key, null);
}

fn canApplyAgentSessionEvent(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (!std.mem.startsWith(u8, scope, "session:")) return false;
    if (!hasCapability(ctx, "write")) return false;
    if (!domain.scopeWritable(scope, ctx.actor_scopes_json)) return false;
    return access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn canProposeAgentSessionEvent(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (!std.mem.startsWith(u8, scope, "session:")) return false;
    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return false;
    if (!domain.scopeVisible(scope, ctx.actor_scopes_json)) return false;
    return access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn buildAppliedAgentMemoryInput(ctx: *Context, operation: []const u8, payload_json: []const u8, object_id: ?[]const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, event_order: ?store_mod.AgentMemoryEventOrder) !AgentMemoryApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const key = json.stringField(obj, "key") orelse object_id orelse return error.MissingKey;
    if (domain.isInternalMemoryKey(key)) return error.InternalAgentMemory;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    const scope = json.nullableStringField(obj, "scope");
    var owner = try agentMemoryOwnerLease(ctx, event_actor_id, scope, obj);
    defer owner.deinit(ctx.allocator);
    if (feed_contract.isDeleteAllOperation(operation)) {
        const owner_value = owner.value;
        const owned_owner_actor_id = owner.transfer();
        return .{ .delete_key = key, .delete_session_id = null, .delete_actor_id = owner_value, .delete_all = true, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
    }
    if (feed_contract.isDeleteOperation(operation) or feed_contract.isDeleteScopedOperation(operation)) {
        const owner_value = owner.value;
        const owned_owner_actor_id = owner.transfer();
        return .{ .delete_key = key, .delete_session_id = session_id, .delete_actor_id = owner_value, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
    }
    const permissions_json = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch return error.InvalidPayload;
    if (scope) |requested_scope| {
        const probe_content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse "";
        if (!canCreateMemoryAtom(ctx, .{ .text = probe_content, .scope = requested_scope, .permissions_json = permissions_json, .created_by = "agent", .actor_id = event_actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions_json) and !domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }

    const memory_operation = domain.AgentMemoryOperation.parse(operation);
    const content = switch (memory_operation) {
        .put => blk: {
            const raw_content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse try rawField(ctx.allocator, obj, "value", "{}");
            break :blk try agent_memory_reducer.canonicalizePutContent(ctx.allocator, raw_content, try agentMemoryValueKindField(obj));
        },
        .merge_string_set => try agent_memory_reducer.stringSetPatchFromObject(ctx.allocator, obj),
        .merge_object => try agent_memory_reducer.objectPatchFromObject(ctx.allocator, obj),
    };
    if (domain.isInternalMemoryEntryKeyOrContent(key, content)) return error.InternalAgentMemory;

    const owner_value = owner.value;
    const owned_owner_actor_id = owner.transfer();
    return .{ .input = .{
        .key = key,
        .content = content,
        .category = json.stringField(obj, "category") orelse "core",
        .session_id = session_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .metadata_json = agentMemoryObjectJson(ctx, obj, &.{"metadata"}, "{}") catch return error.InvalidPayload,
        .actor_id = owner_value,
        .writer_actor_id = event_actor_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
        .operation = memory_operation,
        .event_order = event_order,
    }, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
}

fn buildAppliedAgentMemoryLifecycleInput(ctx: *Context, operation: []const u8, payload_json: []const u8, object_id: ?[]const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, route_mode: AgentMemoryLifecycleRouteMode, event_order: ?store_mod.AgentMemoryEventOrder) !AgentMemoryLifecycleApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const key = json.stringField(obj, "key") orelse object_id orelse return error.MissingKey;
    if (domain.isInternalMemoryKey(key)) return error.InternalAgentMemory;
    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }
    const route = switch (route_mode) {
        .payload_or_fallback => try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route),
        .fallback_authoritative => fallback_route,
    };
    const scope = json.nullableStringField(obj, "scope");
    var owner = try agentMemoryOwnerLease(ctx, event_actor_id, scope, obj);
    defer owner.deinit(ctx.allocator);

    const requested_permissions_json = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch return error.InvalidPayload;
    const use_remote_target_resolution = try ctx.store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(route);
    const maybe_existing = if (use_remote_target_resolution)
        null
    else
        try api_agent_memory_store.getByInput(ctx, .{
            .key = key,
            .route = route,
            .session_id = session_id,
            .owner_actor_id = owner.value,
            .access = .exact_owner,
        });
    if (maybe_existing == null) {
        if (event_order) |order| {
            if (try ctx.store.agentMemoryReplayBlockedByTombstoneRouted(ctx.allocator, key, session_id, owner.value, route, order)) {
                return buildMissingAgentMemoryLifecycleInput(ctx, operation, obj, key, session_id, owner.value, scope, requested_permissions_json, route, event_order, true);
            }
        }
        if (use_remote_target_resolution or try ctx.store.agentMemoryLifecycleCanDelegateMissingTargetRouted(route)) {
            return buildMissingAgentMemoryLifecycleInput(ctx, operation, obj, key, session_id, owner.value, scope, requested_permissions_json, route, event_order, false);
        }
        return error.NotFound;
    }
    var existing = maybe_existing.?;
    defer agent_memory_runtime.freeAgentMemory(ctx.allocator, &existing);
    const visible = access.agentMemoryVisible(ctx.allocator, .{
        .owner_actor_id = existing.actor_id,
        .scope = existing.scope,
        .permissions_json = existing.permissions_json,
        .session_id = existing.session_id,
        .request_actor_id = event_actor_id,
        .request_scopes_json = ctx.actor_scopes_json,
        .record_visible = recordVisibleToActor(ctx, existing.scope, existing.permissions_json),
        .session_visible = if (existing.session_id) |sid| access.sessionVisibleForScopes(ctx.allocator, sid, ctx.actor_scopes_json) else true,
    });
    if (!visible) return error.Forbidden;
    if (!feedLifecycleMutationAllowed(ctx, operation, existing.scope, existing.permissions_json)) return error.Forbidden;
    const payload_status = feed_contract.statusFromLifecycleOperation(operation, obj);
    return .{
        .key = try ctx.allocator.dupe(u8, key),
        .session_id = if (session_id) |sid| try ctx.allocator.dupe(u8, sid) else null,
        .owner_actor_id = try ctx.allocator.dupe(u8, owner.value),
        .scope = try ctx.allocator.dupe(u8, existing.scope),
        .permissions_json = try ctx.allocator.dupe(u8, existing.permissions_json),
        .status = try ctx.allocator.dupe(u8, payload_status),
        .route = route,
        .event_order = event_order,
    };
}

fn buildAppliedAgentSessionMessageInput(ctx: *Context, operation: []const u8, payload_json: []const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, event_order: ?store_mod.AgentMemoryEventOrder) !AgentSessionMessageApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    } else if (!std.mem.eql(u8, operation, "delete_autosaved") or !api_session_access.allWriteAllowed(ctx)) {
        return error.Forbidden;
    }
    const payload_actor = json.nullableStringField(obj, "actor_id") orelse event_actor_id;
    if (!std.mem.eql(u8, payload_actor, event_actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    if (std.mem.eql(u8, operation, "delete_autosaved")) {
        return .{ .session_id = session_id, .actor_id = payload_actor, .delete_autosaved = true, .route = route, .event_order = event_order };
    }
    const concrete_session_id = session_id orelse return error.MissingRequiredField;
    if (feed_contract.isAgentSessionDeleteOperation(operation)) {
        return .{ .session_id = concrete_session_id, .actor_id = payload_actor, .delete_all = true, .route = route, .event_order = event_order };
    }
    const role = sessionMessageRoleField(obj) orelse return error.MissingRequiredField;
    if (domain.isRuntimeCommandRole(role)) return error.InternalAgentSessionMessage;
    const content = json.stringField(obj, "content") orelse return error.MissingRequiredField;
    return .{
        .session_id = concrete_session_id,
        .role = role,
        .content = content,
        .created_at_ms = json.intField(obj, "created_at_ms") orelse ids.nowMs(),
        .actor_id = payload_actor,
        .route = route,
        .event_order = event_order,
    };
}

fn buildAppliedAgentSessionUsageInput(ctx: *Context, operation: []const u8, payload_json: []const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, event_order: ?store_mod.AgentMemoryEventOrder) !AgentSessionUsageApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const session_id = json.stringField(obj, "session_id") orelse return error.MissingRequiredField;
    if (!api_session_access.writeAllowed(ctx, session_id)) return error.Forbidden;
    const payload_actor = json.nullableStringField(obj, "actor_id") orelse event_actor_id;
    if (!std.mem.eql(u8, payload_actor, event_actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    if (feed_contract.isAgentSessionDeleteOperation(operation)) {
        return .{ .session_id = session_id, .actor_id = payload_actor, .delete_usage = true, .route = route, .event_order = event_order };
    }
    const total = json.intField(obj, "total_tokens") orelse return error.MissingRequiredField;
    return .{
        .session_id = session_id,
        .total_tokens = agentSessionTotalTokensFromSigned(total),
        .actor_id = payload_actor,
        .route = route,
        .event_order = event_order,
    };
}

fn memoryStats(ctx: *Context) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const store_diag = ctx.store.lifecycleDiagnostics() catch return serverError(ctx);
    const visible_sources = ctx.store.countSourcesVisible(ctx.allocator, ctx.actor_scopes_json, ctx.actor_id) catch return serverError(ctx);
    const visible_entries = ctx.store.agentMemoryCountByInput(.{
        .actor_id = ctx.actor_id,
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch return serverError(ctx);
    const vector_entries = ctx.store.countVectorChunks() catch return serverError(ctx);
    const outbox_pending = ctx.store.countVectorOutbox("pending") catch return serverError(ctx);
    const embedding_name = if (embeddingProviderConfigured(ctx)) ctx.provider.embedding.provider.name() else "local-deterministic";
    const llm_rerank_configured = llmRerankConfigured(ctx);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"agent_memory_store\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.agentMemoryBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"retrieval\":\"hybrid\",\"vector_index\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.effectiveVectorSearchEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"embedding\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, embedding_name) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"rollout\":\"policy\",\"sync\":\"central_feed\"") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"rollout_policy\":") catch return serverError(ctx);
    api_rollout.appendPolicyJson(ctx, &out, ctx.retrieval_rollout_policy) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"sources\":{d},\"fallback\":\"permission_filtered_keyword_graph\",\"entries\":{d},\"vector_entries\":{d},\"outbox_pending\":{d},\"nullpantry\":{{\"record_store\":", .{ visible_sources, visible_entries, vector_entries, outbox_pending }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.backendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_memory_store\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.agentMemoryBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"vector_index\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.vectorBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"local_vector_engine\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.localVectorEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"search_engine\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.effectiveVectorSearchEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"embedding_provider\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.provider.embedding.provider.name()) catch return serverError(ctx);
    out.print(
        ctx.allocator,
        ",\"embedding_external_configured\":{s},\"llm_rerank_configured\":{s},\"quality_rerank_configured\":{s},\"rerank_candidate_limit_default\":{d},\"rerank_candidate_limit_max\":{d},\"visible_sources\":{d},\"visible_agent_memories\":{d},\"total_memory_atoms\":{d},\"stale_memory_atoms\":{d},\"native_agent_memories\":{d},\"memory_recall_signals\":{d},\"sessions\":{d},\"cache_entries\":{d},\"queued_jobs\":{d},\"running_jobs\":{d},\"failed_jobs\":{d},\"pending_feed_events\":{d},\"open_conflicts\":{d}",
        .{
            if (embeddingProviderConfigured(ctx)) "true" else "false",
            if (llm_rerank_configured) "true" else "false",
            if (llm_rerank_configured) "true" else "false",
            retrieval.default_rerank_candidate_limit,
            retrieval.max_rerank_candidate_limit,
            visible_sources,
            visible_entries,
            store_diag.total_memory_atoms,
            store_diag.stale_memory_atoms,
            store_diag.agent_memories,
            store_diag.memory_recall_signals,
            store_diag.sessions,
            store_diag.cache_entries,
            store_diag.queued_jobs,
            store_diag.running_jobs,
            store_diag.failed_jobs,
            store_diag.pending_feed_events,
            store_diag.open_conflicts,
        },
    ) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memoryRecallSignals(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const limit = @min(parseLimit(json.queryParam(query, "limit"), 20), @as(usize, 100));
    const min_recall_count = positiveLimit(queryInt(query, "min_recall_count"), 2);
    const min_unique_queries = positiveLimit(queryInt(query, "min_unique_queries"), 1);
    const min_score = queryFloat(query, "min_score", 0);
    const candidates = ctx.store.listMemoryRecallCandidates(ctx.allocator, .{
        .scopes_json = ctx.actor_scopes_json,
        .actor_id = ctx.actor_id,
        .limit = limit,
        .min_recall_count = min_recall_count,
        .min_unique_queries = min_unique_queries,
        .min_score = min_score,
    }) catch return serverError(ctx);
    defer store_mod.freeMemoryRecallCandidates(ctx.allocator, candidates);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"recall_signals\":{{\"candidate_count\":{d},\"min_recall_count\":{d},\"min_unique_queries\":{d},\"min_score\":{d}}},\"candidates\":[", .{
        candidates.len,
        min_recall_count,
        min_unique_queries,
        min_score,
    }) catch return serverError(ctx);
    for (candidates, 0..) |candidate, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendMemoryRecallCandidateJson(ctx, &out, candidate) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendMemoryRecallCandidateJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), candidate: store_mod.MemoryRecallCandidate) !void {
    try out.appendSlice(ctx.allocator, "{\"object_type\":");
    try json.appendString(out, ctx.allocator, candidate.object_type);
    try out.appendSlice(ctx.allocator, ",\"object_id\":");
    try json.appendString(out, ctx.allocator, candidate.object_id);
    try out.appendSlice(ctx.allocator, ",\"object_key\":");
    try json.appendString(out, ctx.allocator, candidate.object_key);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, candidate.scope);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonArray(out, ctx.allocator, candidate.permissions_json);
    try out.appendSlice(ctx.allocator, ",\"actor_id\":");
    try json.appendNullableString(out, ctx.allocator, if (candidate.actor_id.len > 0) candidate.actor_id else null);
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(out, ctx.allocator, if (candidate.session_id.len > 0) candidate.session_id else null);
    try out.appendSlice(ctx.allocator, ",\"store\":");
    try json.appendNullableString(out, ctx.allocator, if (candidate.store.len > 0) candidate.store else null);
    try out.print(ctx.allocator, ",\"recall_count\":{d},\"unique_queries\":{d},\"max_score\":{d},\"avg_score\":{d},\"first_recalled_at_ms\":{d},\"last_recalled_at_ms\":{d},\"promotion_score\":{d}}}", .{
        candidate.recall_count,
        candidate.unique_queries,
        candidate.max_score,
        candidate.avg_score,
        candidate.first_recalled_at_ms,
        candidate.last_recalled_at_ms,
        candidate.promotion_score,
    });
}

test "api memory recall candidate preserves and validates permissions" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    const candidate = store_mod.MemoryRecallCandidate{
        .object_type = "agent_memory",
        .object_id = "ami_recall",
        .object_key = "pref.editor",
        .scope = "project:nullpantry",
        .permissions_json = "[\"team:recall\"]",
        .actor_id = "agent:recall",
        .session_id = "",
        .store = "native",
        .recall_count = 3,
        .unique_queries = 2,
        .max_score = 0.9,
        .avg_score = 0.7,
        .first_recalled_at_ms = 10,
        .last_recalled_at_ms = 20,
        .promotion_score = 1.2,
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);
    try appendMemoryRecallCandidateJson(&ctx, &out, candidate);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"permissions\":[\"team:recall\"]") != null);

    var bad = candidate;
    bad.permissions_json = "{\"team\":\"recall\"}";
    var bad_out: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendMemoryRecallCandidateJson(&ctx, &bad_out, bad));
}

fn lifecycleMigrate(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "write")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;

    const kind = json.stringField(obj, "object_type") orelse json.stringField(obj, "kind") orelse "agent_memory";
    const source_route = (storage_routes.fromAliasedObject(ctx.allocator, obj, &.{
        "from",
        "source",
        "from_storage",
        "source_storage",
        "from_store",
        "source_store",
        "from_stores",
        "source_stores",
    }) catch return serverError(ctx)) orelse store_mod.AgentMemoryStorageRoute{};
    const target_route = (storage_routes.fromAliasedObject(ctx.allocator, obj, &.{
        "to",
        "target",
        "to_storage",
        "target_storage",
        "to_store",
        "target_store",
        "to_stores",
        "target_stores",
    }) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 400, "missing_target_storage", "Migration target storage is required");

    const execute = json.boolField(obj, "execute") orelse false;
    const dry_run = json.boolField(obj, "dry_run") orelse !execute;
    const delete_source = json.boolField(obj, "delete_source") orelse false;
    if (delete_source and !hasCapability(ctx, "delete")) return forbidden(ctx);

    if (isAllMigrationKind(kind)) {
        return lifecycleMigrateAll(ctx, obj, source_route, target_route, dry_run, delete_source);
    }
    if (isAgentSessionMigrationKind(kind)) {
        return lifecycleMigrateAgentSessions(ctx, obj, kind, source_route, target_route, dry_run, delete_source);
    }
    if (!isAgentMemoryMigrationKind(kind)) {
        return json.errorResponse(ctx.allocator, 400, "unsupported_migration_kind", "Supported migration kinds are agent_memory, agent_sessions, and all");
    }

    return lifecycleMigrateAgentMemory(ctx, obj, kind, source_route, target_route, dry_run, delete_source);
}

fn lifecycleImportBrainDb(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    if (!hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const path = stringFieldAny(obj, &.{ "path", "db_path", "brain_db_path" }) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    if (std.mem.trim(u8, path, " \t\r\n").len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    const filesystem_path = api_filesystem.resolvePath(ctx.allocator, ctx.filesystem_root, path) catch |err| return filesystemPathError(ctx, err);
    defer ctx.allocator.free(filesystem_path);

    const scope_raw = nullableStringFieldAny(obj, &.{ "scope", "target_scope" });
    const scope: ?[]const u8 = if (scope_raw) |value| blk: {
        const trimmed = std.mem.trim(u8, value, " \t\r\n");
        break :blk if (trimmed.len == 0) null else value;
    } else null;
    const permissions_json = brainDbImportPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = "NullClaw brain.db import", .scope = requested_scope, .permissions_json = permissions_json, .created_by = "agent", .actor_id = ctx.actor_id })) return forbidden(ctx);
    } else if (!domain.permissionsAreOpen(permissions_json) and !domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) {
        return forbidden(ctx);
    }

    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
    }

    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const dry_run = (boolFieldAny(obj, &.{ "dry_run", "preflight", "preflight_only" }) orelse false) or queryBool(route_query, "dry_run", false);
    const include_content = json.boolField(obj, "include_content") orelse false;
    const limit = positiveBounded(intFieldAny(obj, &.{ "limit", "max_entries" }), 10_000, 100_000);
    const max_value_bytes = positiveBounded(intFieldAny(obj, &.{ "max_value_bytes", "max_entry_bytes" }), 4 * 1024 * 1024, 32 * 1024 * 1024);
    const max_total_bytes = positiveBounded(intFieldAny(obj, &.{ "max_total_bytes", "max_import_bytes" }), 64 * 1024 * 1024, 512 * 1024 * 1024);
    const preview_limit = positiveBounded(intFieldAny(obj, &.{ "preview_limit", "response_limit" }), 50, 500);
    const key_prefix = json.stringField(obj, "key_prefix") orelse "";
    const category_override = json.nullableStringField(obj, "category");
    const metadata_json = brainDbImportMetadataRootJson(ctx, obj, &.{"metadata"}, "{}") catch |err| return rawJsonRequestError(ctx, err);
    const include_sessions = boolFieldAny(obj, &.{ "include_sessions", "include_session_history", "include_messages" }) orelse true;
    const include_usage = boolFieldAny(obj, &.{ "include_usage", "include_session_usage" }) orelse include_sessions;
    const include_session_metadata = boolFieldAny(obj, &.{ "include_session_metadata", "include_sessions_table" }) orelse include_sessions;
    const session_metadata_key = json.stringField(obj, "session_metadata_key") orelse "session_metadata";
    const session_metadata_category = json.stringField(obj, "session_metadata_category") orelse "session_state";
    const include_kv = boolFieldAny(obj, &.{ "include_kv", "include_state", "include_legacy_state" }) orelse true;
    const kv_key_prefix = json.stringField(obj, "kv_key_prefix") orelse key_prefix;
    const kv_category = json.stringField(obj, "kv_category") orelse "state";
    const vectorize_kv = boolFieldAny(obj, &.{ "vectorize_kv", "embed_kv" }) orelse false;
    const include_embedding_cache = boolFieldAny(obj, &.{ "include_embedding_cache", "include_legacy_embedding_cache" }) orelse true;
    const include_memory_embeddings = boolFieldAny(obj, &.{ "include_memory_embeddings", "include_legacy_vectors", "include_vectors" }) orelse true;
    const legacy_embedding_provider = json.stringField(obj, "legacy_embedding_provider") orelse "nullclaw-legacy";
    const legacy_embedding_model = json.stringField(obj, "legacy_embedding_model") orelse "unknown";

    const read_result = brain_db_import.read(ctx.allocator, filesystem_path, .{ .limit = limit, .max_value_bytes = max_value_bytes, .max_total_bytes = max_total_bytes }) catch |err| switch (err) {
        error.OpenFailed => return json.errorResponse(ctx.allocator, 400, "brain_db_open_failed", "Cannot open NullClaw brain.db"),
        error.NoMemoriesTable => return json.errorResponse(ctx.allocator, 400, "brain_db_missing_memories_table", "brain.db does not contain a memories table"),
        error.NoContentColumn => return json.errorResponse(ctx.allocator, 400, "brain_db_missing_content_column", "memories table does not contain content/value/text/memory column"),
        error.QueryFailed => return json.errorResponse(ctx.allocator, 400, "brain_db_query_failed", "Cannot read memories from brain.db"),
        error.ValueTooLarge => return json.errorResponse(ctx.allocator, 413, "payload_too_large", "brain.db import exceeds max_value_bytes or max_total_bytes"),
        else => return serverError(ctx),
    };
    defer read_result.deinit(ctx.allocator);

    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx);
    defer ctx.allocator.free(owner_actor_id);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"importer\":\"nullclaw_brain_db\",\"path\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, path) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"scope\":") catch return serverError(ctx);
    json.appendNullableString(&out, ctx.allocator, scope) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"owner_actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, owner_actor_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"permissions\":") catch return serverError(ctx);
    json.appendRawJsonArray(&out, ctx.allocator, permissions_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"storage\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);

    var imported: usize = 0;
    var previewed: usize = 0;
    var session_scoped: usize = 0;
    const ImportedVectorTarget = struct {
        id: []const u8,
        content: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
    };
    var imported_vector_targets: std.StringHashMapUnmanaged(ImportedVectorTarget) = .empty;
    defer imported_vector_targets.deinit(ctx.allocator);
    out.appendSlice(ctx.allocator, ",\"entries\":[") catch return serverError(ctx);
    for (read_result.entries) |entry| {
        const key = if (key_prefix.len > 0)
            std.fmt.allocPrint(ctx.allocator, "{s}{s}", .{ key_prefix, entry.key }) catch return serverError(ctx)
        else
            entry.key;
        const category = category_override orelse entry.category;
        const effective_session_id = session_id orelse entry.session_id;
        if (effective_session_id) |sid| {
            if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
            session_scoped += 1;
        }
        const import_metadata_json = brainDbImportMetadataJson(ctx, path, metadata_json, entry) catch return serverError(ctx);

        if (!dry_run) {
            const saved = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                .key = key,
                .content = entry.content,
                .category = category,
                .session_id = effective_session_id,
                .scope = scope,
                .permissions_json = permissions_json,
                .metadata_json = import_metadata_json,
                .actor_id = owner_actor_id,
                .writer_actor_id = ctx.actor_id,
                .actor_scopes_json = ctx.actor_scopes_json,
                .actor_capabilities_json = ctx.actor_capabilities_json,
            }, storage_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            _ = upsertAutoVector(ctx, "agent_memory", saved.id, saved.content, saved.scope, saved.permissions_json) catch 0;
            imported_vector_targets.put(ctx.allocator, entry.key, .{
                .id = saved.id,
                .content = saved.content,
                .scope = saved.scope,
                .permissions_json = saved.permissions_json,
            }) catch return serverError(ctx);
            imported += 1;
        }

        if (previewed < preview_limit) {
            if (previewed > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
            appendBrainDbImportPreview(ctx, &out, key, category, effective_session_id, entry.content, include_content) catch return serverError(ctx);
            previewed += 1;
        }
    }
    out.append(ctx.allocator, ']') catch return serverError(ctx);

    var imported_session_metadata: usize = 0;
    var session_metadata_previewed: usize = 0;
    if (include_session_metadata) {
        out.appendSlice(ctx.allocator, ",\"session_entries\":[") catch return serverError(ctx);
        for (read_result.sessions) |legacy_session| {
            const effective_session_id = session_id orelse legacy_session.session_id;
            if (!api_session_access.writeAllowed(ctx, effective_session_id)) return forbidden(ctx);
            const key = if (key_prefix.len > 0)
                std.fmt.allocPrint(ctx.allocator, "{s}{s}", .{ key_prefix, session_metadata_key }) catch return serverError(ctx)
            else
                session_metadata_key;
            const content_json = brainDbSessionMetadataContentJson(ctx, legacy_session) catch return serverError(ctx);
            const import_metadata_json = brainDbSessionMetadataImportJson(ctx, path, metadata_json, legacy_session) catch return serverError(ctx);
            if (!dry_run) {
                _ = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                    .key = key,
                    .content = content_json,
                    .category = session_metadata_category,
                    .session_id = effective_session_id,
                    .scope = scope,
                    .permissions_json = permissions_json,
                    .metadata_json = import_metadata_json,
                    .actor_id = owner_actor_id,
                    .writer_actor_id = ctx.actor_id,
                    .actor_scopes_json = ctx.actor_scopes_json,
                    .actor_capabilities_json = ctx.actor_capabilities_json,
                }, storage_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                imported_session_metadata += 1;
            }

            if (session_metadata_previewed < preview_limit) {
                if (session_metadata_previewed > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
                appendBrainDbImportPreview(ctx, &out, key, session_metadata_category, effective_session_id, content_json, include_content) catch return serverError(ctx);
                session_metadata_previewed += 1;
            }
        }
        out.append(ctx.allocator, ']') catch return serverError(ctx);
    } else {
        out.appendSlice(ctx.allocator, ",\"session_entries\":[]") catch return serverError(ctx);
    }

    var imported_kvs: usize = 0;
    var kv_previewed: usize = 0;
    if (include_kv) {
        out.appendSlice(ctx.allocator, ",\"kv_entries\":[") catch return serverError(ctx);
        for (read_result.kvs) |kv| {
            const key = if (kv_key_prefix.len > 0)
                std.fmt.allocPrint(ctx.allocator, "{s}{s}", .{ kv_key_prefix, kv.key }) catch return serverError(ctx)
            else
                kv.key;
            const import_metadata_json = brainDbKvImportMetadataJson(ctx, path, metadata_json, kv) catch return serverError(ctx);
            if (!dry_run) {
                const saved = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                    .key = key,
                    .content = kv.value,
                    .category = kv_category,
                    .session_id = null,
                    .scope = scope,
                    .permissions_json = permissions_json,
                    .metadata_json = import_metadata_json,
                    .actor_id = owner_actor_id,
                    .writer_actor_id = ctx.actor_id,
                    .actor_scopes_json = ctx.actor_scopes_json,
                    .actor_capabilities_json = ctx.actor_capabilities_json,
                }, storage_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                if (vectorize_kv) _ = upsertAutoVector(ctx, "agent_memory", saved.id, saved.content, saved.scope, saved.permissions_json) catch 0;
                imported_kvs += 1;
            }

            if (kv_previewed < preview_limit) {
                if (kv_previewed > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
                appendBrainDbImportPreview(ctx, &out, key, kv_category, null, kv.value, include_content) catch return serverError(ctx);
                kv_previewed += 1;
            }
        }
        out.append(ctx.allocator, ']') catch return serverError(ctx);
    } else {
        out.appendSlice(ctx.allocator, ",\"kv_entries\":[]") catch return serverError(ctx);
    }

    var imported_embedding_cache: usize = 0;
    if (include_embedding_cache and !dry_run) {
        for (read_result.embedding_cache_entries) |legacy_cache| {
            ctx.store.putEmbeddingCache(.{
                .cache_key = legacy_cache.content_hash,
                .provider = legacy_embedding_provider,
                .model = legacy_embedding_model,
                .dimensions = legacy_cache.dimensions,
                .embedding_json = legacy_cache.embedding_json,
            }) catch return serverError(ctx);
            imported_embedding_cache += 1;
        }
    }

    var imported_memory_embeddings: usize = 0;
    var skipped_unmatched_memory_embeddings: usize = 0;
    var skipped_noncanonical_memory_embeddings: usize = 0;
    if (include_memory_embeddings and !dry_run) {
        for (read_result.memory_embeddings) |legacy_embedding| {
            const target = imported_vector_targets.get(legacy_embedding.memory_key) orelse {
                skipped_unmatched_memory_embeddings += 1;
                continue;
            };
            _ = ctx.store.upsertVectorChunk(ctx.allocator, .{
                .object_type = "agent_memory",
                .object_id = target.id,
                .chunk_ordinal = 0,
                .text = target.content,
                .scope = target.scope,
                .permissions_json = target.permissions_json,
                .heading_path_json = "[\"nullclaw_brain_db\",\"memory_embeddings\"]",
                .embedding_json = legacy_embedding.embedding_json,
                .model = legacy_embedding_model,
                .dimensions = @intCast(legacy_embedding.dimensions),
                .actor_id = ctx.actor_id,
            }) catch |err| switch (err) {
                error.InvalidVectorTarget => {
                    skipped_noncanonical_memory_embeddings += 1;
                    continue;
                },
                else => return serverError(ctx),
            };
            imported_memory_embeddings += 1;
        }
    }

    var imported_messages: usize = 0;
    if (include_sessions) {
        for (read_result.messages, 0..) |message, index| {
            const effective_session_id = session_id orelse message.session_id;
            if (!api_session_access.writeAllowed(ctx, effective_session_id)) return forbidden(ctx);
            if (!dry_run) {
                ctx.store.saveMessageRoutedAtWithAuth(effective_session_id, message.role, message.content, brainDbImportTimestampMs(message.created_at, index), ctx.actor_id, ctx.actor_capabilities_json, storage_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                imported_messages += 1;
            }
        }
    }

    var imported_usages: usize = 0;
    if (include_usage) {
        for (read_result.usages) |usage| {
            const effective_session_id = session_id orelse usage.session_id;
            if (!api_session_access.writeAllowed(ctx, effective_session_id)) return forbidden(ctx);
            if (!dry_run) {
                ctx.store.saveUsageRoutedWithAuth(effective_session_id, usage.total_tokens, ctx.actor_id, ctx.actor_capabilities_json, storage_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                imported_usages += 1;
            }
        }
    }

    out.print(ctx.allocator, ",\"validated_count\":{d},\"imported_count\":{d},\"preview_count\":{d},\"session_scoped_count\":{d},\"session_metadata_count\":{d},\"imported_session_metadata_count\":{d},\"session_metadata_preview_count\":{d},\"message_count\":{d},\"imported_message_count\":{d},\"usage_count\":{d},\"imported_usage_count\":{d},\"kv_count\":{d},\"imported_kv_count\":{d},\"kv_preview_count\":{d},\"embedding_cache_count\":{d},\"imported_embedding_cache_count\":{d},\"memory_embedding_count\":{d},\"imported_memory_embedding_count\":{d},\"skipped_unmatched_memory_embedding_count\":{d},\"skipped_noncanonical_memory_embedding_count\":{d},\"skipped_empty_content\":{d},\"skipped_empty_messages\":{d},\"skipped_empty_sessions\":{d},\"skipped_empty_kv\":{d},\"skipped_empty_embedding_cache\":{d},\"skipped_invalid_embedding_cache\":{d},\"skipped_empty_memory_embeddings\":{d},\"skipped_invalid_memory_embeddings\":{d},\"truncated\":", .{
        read_result.entries.len,
        imported,
        previewed,
        session_scoped,
        if (include_session_metadata) read_result.sessions.len else 0,
        imported_session_metadata,
        session_metadata_previewed,
        if (include_sessions) read_result.messages.len else 0,
        imported_messages,
        if (include_usage) read_result.usages.len else 0,
        imported_usages,
        if (include_kv) read_result.kvs.len else 0,
        imported_kvs,
        kv_previewed,
        if (include_embedding_cache) read_result.embedding_cache_entries.len else 0,
        imported_embedding_cache,
        if (include_memory_embeddings) read_result.memory_embeddings.len else 0,
        imported_memory_embeddings,
        skipped_unmatched_memory_embeddings,
        skipped_noncanonical_memory_embeddings,
        read_result.skipped_empty_content,
        read_result.skipped_empty_messages,
        read_result.skipped_empty_sessions,
        read_result.skipped_empty_kv,
        read_result.skipped_empty_embedding_cache,
        read_result.skipped_invalid_embedding_cache,
        read_result.skipped_empty_memory_embeddings,
        read_result.skipped_invalid_memory_embeddings,
    }) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"messages_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.messages_truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"usages_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.usages_truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"sessions_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.sessions_truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"kvs_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.kvs_truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"embedding_cache_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.embedding_cache_truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_embeddings_truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (read_result.memory_embeddings_truncated) "true" else "false") catch return serverError(ctx);
    out.print(ctx.allocator, ",\"limit\":{d},\"preview_limit\":{d},\"include_sessions\":{s},\"include_usage\":{s},\"include_session_metadata\":{s},\"include_kv\":{s},\"include_embedding_cache\":{s},\"include_memory_embeddings\":{s},\"session_metadata_category\":", .{
        limit,
        preview_limit,
        if (include_sessions) "true" else "false",
        if (include_usage) "true" else "false",
        if (include_session_metadata) "true" else "false",
        if (include_kv) "true" else "false",
        if (include_embedding_cache) "true" else "false",
        if (include_memory_embeddings) "true" else "false",
    }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_metadata_category) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"kv_category\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, kv_category) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"vectorize_kv\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (vectorize_kv) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

