    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn brainDbImportTimestampMs(raw: ?[]const u8, fallback_offset: usize) i64 {
    return brainDbImportTimestampMsFromNow(raw, ids.nowMs(), fallback_offset);
}

fn brainDbImportTimestampMsFromNow(raw: ?[]const u8, now_ms: i64, fallback_offset: usize) i64 {
    const delta_ms = std.math.cast(i64, fallback_offset) orelse std.math.maxInt(i64);
    const fallback = time_math.saturatingAddMs(now_ms, delta_ms);
    const value = raw orelse return fallback;
    const trimmed = std.mem.trim(u8, value, " \t\r\n");
    if (trimmed.len == 0) return fallback;
    const parsed = std.fmt.parseInt(i64, trimmed, 10) catch return fallback;
    if (parsed > 0 and parsed < 10_000_000_000) return parsed * 1000;
    return parsed;
}

test "brain db import timestamp bounds fallback offsets" {
    try std.testing.expectEqual(@as(i64, 1_000), brainDbImportTimestampMsFromNow(null, 1_000, 0));
    try std.testing.expectEqual(@as(i64, 1_005), brainDbImportTimestampMsFromNow("", 1_000, 5));
    try std.testing.expectEqual(std.math.maxInt(i64), brainDbImportTimestampMsFromNow("invalid", std.math.maxInt(i64) - 2, 10));
}

test "brain db import timestamp preserves parsed legacy values" {
    try std.testing.expectEqual(@as(i64, 1_700_000_000_000), brainDbImportTimestampMsFromNow("1700000000", 1_000, 5));
    try std.testing.expectEqual(@as(i64, 10_000_000_000), brainDbImportTimestampMsFromNow("10000000000", 1_000, 5));
}

