test "brain db import metadata writers preserve user metadata" {
    const allocator = std.testing.allocator;
    var ctx = Context{
        .allocator = allocator,
        .store = undefined,
    };
    const user_metadata = "{\"source\":\"legacy\",\"labels\":[\"brain\"]}";

    var entry_key = "pref.editor".*;
    var entry_content = "Use Zig".*;
    var entry_category = "preference".*;
    const entry_json = try brainDbImportMetadataJson(&ctx, "/tmp/brain.db", user_metadata, .{
        .key = entry_key[0..],
        .content = entry_content[0..],
        .category = entry_category[0..],
    });
    defer allocator.free(entry_json);
    try std.testing.expect(std.mem.indexOf(u8, entry_json, "\"user\":{\"source\":\"legacy\",\"labels\":[\"brain\"]}") != null);

    var session_id = "session-1".*;
    const session_json = try brainDbSessionMetadataImportJson(&ctx, "/tmp/brain.db", user_metadata, .{
        .session_id = session_id[0..],
    });
    defer allocator.free(session_json);
    try std.testing.expect(std.mem.indexOf(u8, session_json, "\"user\":{\"source\":\"legacy\",\"labels\":[\"brain\"]}") != null);

    var kv_key = "legacy.pref".*;
    var kv_value = "dark".*;
    const kv_json = try brainDbKvImportMetadataJson(&ctx, "/tmp/brain.db", user_metadata, .{
        .key = kv_key[0..],
        .value = kv_value[0..],
    });
    defer allocator.free(kv_json);
    try std.testing.expect(std.mem.indexOf(u8, kv_json, "\"user\":{\"source\":\"legacy\",\"labels\":[\"brain\"]}") != null);
}

test "brain db import metadata writers reject malformed user metadata" {
