fn appendBrainDbImportPreview(ctx: *Context, out: *std.ArrayListUnmanaged(u8), key: []const u8, category: []const u8, session_id: ?[]const u8, content: []const u8, include_content: bool) !void {
    try out.appendSlice(ctx.allocator, "{\"key\":");
    try json.appendString(out, ctx.allocator, key);
    try out.appendSlice(ctx.allocator, ",\"category\":");
    try json.appendString(out, ctx.allocator, category);
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(out, ctx.allocator, session_id);
    try out.print(ctx.allocator, ",\"content_bytes\":{d}", .{content.len});
    if (include_content) {
        try out.appendSlice(ctx.allocator, ",\"content\":");
        try json.appendString(out, ctx.allocator, content);
    }
    try out.append(ctx.allocator, '}');
}

fn lifecycleMigrateAgentMemory(
    ctx: *Context,
    obj: std.json.ObjectMap,
    kind: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
        if (!dry_run and !api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
    }
    const category = json.nullableStringField(obj, "category");
    const query = std.mem.trim(u8, json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "", " \t\r\n");
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const include_global = json.boolField(obj, "include_global") orelse false;
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const suppress_feed = json.boolField(obj, "suppress_feed") orelse false;

    var candidates: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    const fetch_limit = api_search_window.boundedWindowEnd(limit, offset, 500);
    const auth = api_agent_memory_store.scopedAuth(ctx, scopes_json);
    if (query.len > 0) {
        const primary = api_agent_memory_store.searchByInput(ctx, .{
            .query = query,
            .route = source_route,
            .limit = fetch_limit,
            .session_id = session_id,
            .auth = auth,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendAgentMemoryEntries(ctx.allocator, &candidates, primary) catch return serverError(ctx);
        if (include_global and session_id != null) {
            const global = api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = source_route,
                .limit = fetch_limit,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &candidates, global) catch return serverError(ctx);
        }
    } else {
        const primary = api_agent_memory_store.listByInput(ctx, .{
            .route = source_route,
            .category = category,
            .session_id = session_id,
            .auth = auth,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendAgentMemoryEntries(ctx.allocator, &candidates, primary) catch return serverError(ctx);
        if (include_global and session_id != null) {
            const global = api_agent_memory_store.listByInput(ctx, .{
                .route = source_route,
                .category = category,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &candidates, global) catch return serverError(ctx);
        }
    }
    dedupeAgentMemoryEntries(ctx.allocator, &candidates);

    var selected: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    var skipped: usize = 0;
    var visible_seen: usize = 0;
    for (candidates.items) |entry| {
        if (!agentMemoryEntryVisible(ctx, entry)) {
            skipped += 1;
            continue;
        }
        if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) {
            skipped += 1;
            continue;
        }
        if (visible_seen < offset) {
            visible_seen += 1;
            skipped += 1;
            continue;
        }
        if (selected.items.len >= limit) {
            skipped += 1;
            continue;
        }
        visible_seen += 1;
        if (!agentMemoryEntryMigratable(ctx, entry)) return forbidden(ctx);
        if (delete_source and !agentMemoryEntryDeletable(ctx, entry)) return forbidden(ctx);
        selected.append(ctx.allocator, entry) catch return serverError(ctx);
    }

    var migrated: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (!dry_run) {
        for (selected.items) |entry| {
            const saved = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                .key = entry.key,
                .content = entry.content,
                .category = entry.category,
                .session_id = entry.session_id,
                .scope = entry.scope,
                .permissions_json = entry.permissions_json,
                .actor_id = entry.actor_id,
                .writer_actor_id = ctx.actor_id,
                .actor_scopes_json = ctx.actor_scopes_json,
                .actor_capabilities_json = ctx.actor_capabilities_json,
                .suppress_feed = suppress_feed,
            }, target_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            migrated.append(ctx.allocator, saved) catch return serverError(ctx);
            if (delete_source) {
                _ = api_agent_memory_store.delete(ctx, .{
                    .key = entry.key,
                    .session_id = entry.session_id,
                    .owner_actor_id = entry.actor_id,
                    .route = source_route,
                    .suppress_feed = suppress_feed,
                }) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }
        }
    }

    return lifecycleMigrationResponse(ctx, .{
        .kind = kind,
        .dry_run = dry_run,
        .delete_source = delete_source,
        .source_route = source_route,
        .target_route = target_route,
        .matched = candidates.items.len,
        .selected = selected.items,
        .migrated = migrated.items,
        .skipped = skipped,
        .limit = limit,
        .offset = offset,
    });
}

const AgentMemoryMigrationResponseInput = struct {
    kind: []const u8,
    dry_run: bool,
    delete_source: bool,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    matched: usize,
    selected: []const domain.AgentMemory,
    migrated: []const domain.AgentMemory,
    skipped: usize,
    limit: usize,
    offset: usize,
};

fn lifecycleMigrationResponse(ctx: *Context, input: AgentMemoryMigrationResponseInput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.kind) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"matched\":{d},\"selected\":{d},\"migrated\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"entries\":[", .{
        input.matched,
        input.selected.len,
        input.migrated.len,
        input.skipped,
        input.limit,
        input.offset,
    }) catch return serverError(ctx);
    for (input.selected, 0..) |entry, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        const saved: ?domain.AgentMemory = if (i < input.migrated.len) input.migrated[i] else null;
        appendAgentMemoryMigrationEntryJson(ctx.allocator, &out, entry, saved) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendAgentMemoryMigrationEntryJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), entry: domain.AgentMemory, migrated: ?domain.AgentMemory) !void {
    try out.appendSlice(allocator, "{\"key\":");
    try json.appendString(out, allocator, entry.key);
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(out, allocator, entry.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(out, allocator, entry.session_id);
    try out.appendSlice(allocator, ",\"actor_id\":");
    try json.appendString(out, allocator, entry.actor_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(out, allocator, entry.scope);
    try out.appendSlice(allocator, ",\"source_store\":");
    try json.appendString(out, allocator, if (entry.store.len > 0) entry.store else "primary");
    if (migrated) |saved| {
        try out.appendSlice(allocator, ",\"migrated_id\":");
        try json.appendString(out, allocator, saved.id);
        try out.appendSlice(allocator, ",\"target_store\":");
        try json.appendString(out, allocator, if (saved.store.len > 0) saved.store else "primary");
    }
    try out.append(allocator, '}');
}

fn isAgentMemoryMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "agent_memory") or std.mem.eql(u8, kind, "agent_memories") or std.mem.eql(u8, kind, "memory");
}

fn isAgentSessionMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "agent_session") or std.mem.eql(u8, kind, "agent_sessions") or std.mem.eql(u8, kind, "session") or std.mem.eql(u8, kind, "sessions");
}

fn isAllMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "all") or std.mem.eql(u8, kind, "agent_runtime") or std.mem.eql(u8, kind, "agent_state");
}

fn lifecycleMigrateAll(
    ctx: *Context,
    obj: std.json.ObjectMap,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const memory_preflight = lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, true, delete_source);
    if (!isOkResponse(memory_preflight)) return memory_preflight;
    const session_preflight = lifecycleMigrateAgentSessions(ctx, obj, "agent_sessions", source_route, target_route, true, delete_source);
    if (!isOkResponse(session_preflight)) return session_preflight;

    if (dry_run) {
        return lifecycleAllMigrationResponse(ctx, .{
            .dry_run = true,
            .delete_source = delete_source,
            .preflight = true,
            .source_route = source_route,
            .target_route = target_route,
            .agent_memory = memory_preflight.body,
            .agent_sessions = session_preflight.body,
        });
    }

    const memory_execute = lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, false, false);
    if (!isOkResponse(memory_execute)) return memory_execute;
    const session_execute = lifecycleMigrateAgentSessions(ctx, obj, "agent_sessions", source_route, target_route, false, false);
    if (!isOkResponse(session_execute)) return session_execute;

    const cleanup_memory = if (delete_source)
        lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, false, true)
    else
        nullResponse(ctx);
    if (!isOkResponse(cleanup_memory)) return cleanup_memory;
    const cleanup_sessions = if (delete_source)
        lifecycleDeleteSourceAgentSessions(ctx, obj, source_route)
    else
        nullResponse(ctx);
    if (!isOkResponse(cleanup_sessions)) return cleanup_sessions;

    return lifecycleAllMigrationResponse(ctx, .{
        .dry_run = false,
        .delete_source = delete_source,
        .preflight = true,
        .source_route = source_route,
        .target_route = target_route,
        .agent_memory = memory_execute.body,
        .agent_sessions = session_execute.body,
        .source_cleanup_memory = cleanup_memory.body,
        .source_cleanup_sessions = cleanup_sessions.body,
    });
}

const LifecycleAllMigrationResponseInput = struct {
    dry_run: bool,
    delete_source: bool,
    preflight: bool,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    agent_memory: []const u8,
    agent_sessions: []const u8,
    source_cleanup_memory: []const u8 = "null",
    source_cleanup_sessions: []const u8 = "null",
};

fn lifecycleAllMigrationResponse(ctx: *Context, input: LifecycleAllMigrationResponseInput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":\"all\",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"preflight\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.preflight) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"results\":{\"agent_memory\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.agent_memory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_sessions\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.agent_sessions) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "},\"source_cleanup\":{\"agent_memory\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.source_cleanup_memory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_sessions\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.source_cleanup_sessions) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn isOkResponse(response: HttpResponse) bool {
    return std.mem.eql(u8, response.status, "200 OK");
}

fn nullResponse(ctx: *Context) HttpResponse {
    return .{ .status = "200 OK", .body = ctx.allocator.dupe(u8, "null") catch return serverError(ctx) };
}

const AgentSessionMigrationEntry = struct {
    session_id: []const u8,
    source_message_count: u64,
    target_message_count: u64,
    source_usage_tokens: ?u64,
    target_usage_exists: bool,
    action: []const u8,
    messages_copied: usize = 0,
    usage_copied: bool = false,
};

const AgentSessionMigrationResponseInput = struct {
    kind: []const u8,
    dry_run: bool,
    delete_source: bool,
    append: bool,
    overwrite: bool,
    actor_id: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    matched: usize,
    skipped: usize,
    limit: usize,
    offset: usize,
    message_limit: usize,
    entries: []const AgentSessionMigrationEntry,
};

fn lifecycleMigrateAgentSessions(
    ctx: *Context,
    obj: std.json.ObjectMap,
    kind: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const migration_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin") and !std.mem.eql(u8, migration_actor_id, ctx.actor_id)) return forbidden(ctx);

    const append = json.boolField(obj, "append") orelse false;
    const overwrite = json.boolField(obj, "overwrite") orelse false;
    if (append and overwrite) return json.errorResponse(ctx.allocator, 400, "bad_request", "append and overwrite cannot both be true");

    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const message_limit = agentSessionMigrationMessageLimit(obj);

    var requested: std.ArrayListUnmanaged([]const u8) = .empty;
    if (json.stringField(obj, "session_id")) |sid| {
        tryAppendUniqueSessionId(ctx.allocator, &requested, sid) catch return serverError(ctx);
    }
    if (obj.get("session_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must be an array");
        for (value.array.items) |item| {
            if (item != .string) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must contain strings");
            tryAppendUniqueSessionId(ctx.allocator, &requested, item.string) catch return serverError(ctx);
        }
    }

    var candidates: std.ArrayListUnmanaged(store_mod.SessionInfo) = .empty;
    var matched: usize = 0;
    if (requested.items.len > 0) {
        matched = requested.items.len;
        const window = requestedSessionPageWindow(requested.items.len, limit, offset);
        for (requested.items[window.start..window.end]) |sid| {
            if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
            const history = ctx.store.historyRoutedWithAuth(ctx.allocator, sid, 1, 0, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            const usage = ctx.store.loadUsageRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (history.total == 0 and usage == null) continue;
            const first = if (history.messages.len > 0) history.messages[0].created_at_ms else 0;
            candidates.append(ctx.allocator, .{
                .session_id = sid,
                .message_count = history.total,
                .first_message_at = first,
                .last_message_at = first,
            }) catch return serverError(ctx);
        }
    } else {
        if (!api_session_access.allReadAllowed(ctx)) return forbidden(ctx);
        const listed = ctx.store.listSessionsRoutedWithAuth(ctx.allocator, limit, offset, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        matched = @intCast(listed.total);
        candidates.appendSlice(ctx.allocator, listed.sessions) catch return serverError(ctx);
    }

    var entries: std.ArrayListUnmanaged(AgentSessionMigrationEntry) = .empty;
    var skipped: usize = if (requested.items.len > 0) @min(offset, requested.items.len) else offset;
    const message_limit_u64: u64 = @intCast(message_limit);

    for (candidates.items) |candidate| {
        const sid = candidate.session_id;
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
        if (!dry_run and !api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
        if (delete_source and !api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);

        const source_history = ctx.store.historyRoutedWithAuth(ctx.allocator, sid, message_limit, 0, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (source_history.total > message_limit_u64) {
            return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before migrating");
        }
        const source_usage = ctx.store.loadUsageRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (source_history.total == 0 and source_usage == null) {
            skipped += 1;
            continue;
        }

        const target_history = ctx.store.historyRoutedWithAuth(ctx.allocator, sid, 1, 0, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        const target_usage = ctx.store.loadUsageRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (!append and !overwrite and (target_history.total > 0 or target_usage != null)) {
            return json.errorResponse(ctx.allocator, 409, "target_session_exists", "Target session already contains messages or usage; use overwrite or append");
        }

        entries.append(ctx.allocator, .{
            .session_id = sid,
            .source_message_count = source_history.total,
            .target_message_count = target_history.total,
            .source_usage_tokens = source_usage,
            .target_usage_exists = target_usage != null,
            .action = if (dry_run) "dry_run" else if (overwrite) "overwrite" else if (append) "append" else "copy",
        }) catch return serverError(ctx);
    }

    if (!dry_run) {
        for (entries.items) |*entry| {
            if (overwrite) {
                ctx.store.clearMessagesRoutedWithAuth(entry.session_id, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                _ = ctx.store.deleteUsageRoutedWithAuth(entry.session_id, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }

            const source_history = ctx.store.historyRoutedWithAuth(ctx.allocator, entry.session_id, message_limit, 0, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (source_history.total > message_limit_u64) {
                return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before migrating");
            }
            for (source_history.messages) |message| {
                ctx.store.saveMessageRoutedAtWithAuth(entry.session_id, message.role, message.content, message.created_at_ms, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                entry.messages_copied += 1;
            }
            if (entry.source_usage_tokens) |total| {
                ctx.store.saveUsageRoutedWithAuth(entry.session_id, total, migration_actor_id, ctx.actor_capabilities_json, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                entry.usage_copied = true;
            }
            if (delete_source) {
                ctx.store.clearMessagesRoutedWithAuth(entry.session_id, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                _ = ctx.store.deleteUsageRoutedWithAuth(entry.session_id, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }
        }
    }

    return lifecycleSessionMigrationResponse(ctx, .{
        .kind = kind,
        .dry_run = dry_run,
        .delete_source = delete_source,
        .append = append,
        .overwrite = overwrite,
        .actor_id = migration_actor_id,
        .source_route = source_route,
        .target_route = target_route,
        .matched = matched,
        .skipped = skipped,
        .limit = limit,
        .offset = offset,
        .message_limit = message_limit,
        .entries = entries.items,
    });
}

fn tryAppendUniqueSessionId(allocator: std.mem.Allocator, ids_list: *std.ArrayListUnmanaged([]const u8), session_id: []const u8) !void {
    for (ids_list.items) |existing| {
        if (std.mem.eql(u8, existing, session_id)) return;
    }
    try ids_list.append(allocator, session_id);
}

fn lifecycleSessionMigrationResponse(ctx: *Context, input: AgentSessionMigrationResponseInput) HttpResponse {
    var migrated: usize = 0;
    var messages_copied: usize = 0;
    var usage_copied: usize = 0;
    for (input.entries) |entry| {
        if (!input.dry_run) migrated += 1;
        messages_copied += entry.messages_copied;
        if (entry.usage_copied) usage_copied += 1;
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.kind) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"append\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.append) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"overwrite\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.overwrite) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.actor_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"matched\":{d},\"selected\":{d},\"migrated\":{d},\"messages_copied\":{d},\"usage_copied\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"message_limit\":{d},\"entries\":[", .{
        input.matched,
        input.entries.len,
        migrated,
        messages_copied,
        usage_copied,
        input.skipped,
        input.limit,
        input.offset,
        input.message_limit,
    }) catch return serverError(ctx);
    for (input.entries, 0..) |entry, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendAgentSessionMigrationEntryJson(ctx.allocator, &out, entry) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleDeleteSourceAgentSessions(ctx: *Context, obj: std.json.ObjectMap, source_route: store_mod.AgentMemoryStorageRoute) HttpResponse {
    const migration_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin") and !std.mem.eql(u8, migration_actor_id, ctx.actor_id)) return forbidden(ctx);

    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const message_limit = agentSessionMigrationMessageLimit(obj);

    var requested: std.ArrayListUnmanaged([]const u8) = .empty;
    if (json.stringField(obj, "session_id")) |sid| {
        tryAppendUniqueSessionId(ctx.allocator, &requested, sid) catch return serverError(ctx);
    }
    if (obj.get("session_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must be an array");
        for (value.array.items) |item| {
            if (item != .string) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must contain strings");
            tryAppendUniqueSessionId(ctx.allocator, &requested, item.string) catch return serverError(ctx);
        }
    }

    var candidates: std.ArrayListUnmanaged([]const u8) = .empty;
    var matched: usize = 0;
    if (requested.items.len > 0) {
        matched = requested.items.len;
        const window = requestedSessionPageWindow(requested.items.len, limit, offset);
        for (requested.items[window.start..window.end]) |sid| {
            if (!api_session_access.readAllowed(ctx, sid) or !api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
            candidates.append(ctx.allocator, sid) catch return serverError(ctx);
        }
    } else {
        if (!api_session_access.allReadAllowed(ctx) or !api_session_access.allWriteAllowed(ctx)) return forbidden(ctx);
        const listed = ctx.store.listSessionsRoutedWithAuth(ctx.allocator, limit, offset, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        matched = @intCast(listed.total);
        for (listed.sessions) |session| {
            candidates.append(ctx.allocator, session.session_id) catch return serverError(ctx);
        }
    }

    const message_limit_u64: u64 = @intCast(message_limit);
    var sessions_deleted: usize = 0;
    var messages_deleted: usize = 0;
    var usage_deleted: usize = 0;
    var skipped: usize = if (requested.items.len > 0) @min(offset, requested.items.len) else offset;

    for (candidates.items) |sid| {
        if (!api_session_access.readAllowed(ctx, sid) or !api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
        const history = ctx.store.historyRoutedWithAuth(ctx.allocator, sid, message_limit, 0, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (history.total > message_limit_u64) {
            return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before deleting migrated source sessions");
        }
        const usage = ctx.store.loadUsageRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (history.total == 0 and usage == null) {
            skipped += 1;
            continue;
        }
        if (usage != null) {
            const deleted = ctx.store.deleteUsageRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (deleted) usage_deleted += 1;
        }
        ctx.store.clearMessagesRoutedWithAuth(sid, migration_actor_id, ctx.actor_capabilities_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        sessions_deleted += 1;
        messages_deleted += @intCast(history.total);
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"ok\":true,\"cleanup\":{{\"kind\":\"agent_sessions\",\"matched\":{d},\"selected\":{d},\"sessions_deleted\":{d},\"messages_deleted\":{d},\"usage_deleted\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"message_limit\":{d}}}}}", .{
        matched,
        candidates.items.len,
        sessions_deleted,
        messages_deleted,
        usage_deleted,
        skipped,
        limit,
        offset,
        message_limit,
    }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

const RequestedSessionPageWindow = struct {
    start: usize,
    len: usize,
    end: usize,
};

fn requestedSessionPageWindow(total: usize, limit: usize, offset: usize) RequestedSessionPageWindow {
    const start = @min(offset, total);
    const len = @min(limit, total - start);
    return .{
        .start = start,
        .len = len,
        .end = bounded_int.saturatingUsizeAdd(start, len),
    };
}

test "api requested session page window is bounded" {
    const page = requestedSessionPageWindow(10, 4, 3);
    try std.testing.expectEqual(@as(usize, 3), page.start);
    try std.testing.expectEqual(@as(usize, 4), page.len);
    try std.testing.expectEqual(@as(usize, 7), page.end);

    const tail = requestedSessionPageWindow(10, 4, 8);
    try std.testing.expectEqual(@as(usize, 8), tail.start);
    try std.testing.expectEqual(@as(usize, 2), tail.len);
    try std.testing.expectEqual(@as(usize, 10), tail.end);

    const empty = requestedSessionPageWindow(10, 4, std.math.maxInt(usize));
    try std.testing.expectEqual(@as(usize, 10), empty.start);
    try std.testing.expectEqual(@as(usize, 0), empty.len);
    try std.testing.expectEqual(@as(usize, 10), empty.end);

    const max_window = requestedSessionPageWindow(std.math.maxInt(usize), std.math.maxInt(usize), std.math.maxInt(usize) - 1);
    try std.testing.expectEqual(std.math.maxInt(usize) - 1, max_window.start);
    try std.testing.expectEqual(@as(usize, 1), max_window.len);
    try std.testing.expectEqual(std.math.maxInt(usize), max_window.end);
}

fn appendAgentSessionMigrationEntryJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), entry: AgentSessionMigrationEntry) !void {
    try out.appendSlice(allocator, "{\"session_id\":");
    try json.appendString(out, allocator, entry.session_id);
    try out.print(allocator, ",\"source_message_count\":{d},\"target_message_count\":{d},\"source_usage_tokens\":", .{ entry.source_message_count, entry.target_message_count });
    if (entry.source_usage_tokens) |total| {
        try out.print(allocator, "{d}", .{total});
    } else {
        try out.appendSlice(allocator, "null");
    }
    try out.appendSlice(allocator, ",\"target_usage_exists\":");
    try out.appendSlice(allocator, if (entry.target_usage_exists) "true" else "false");
    try out.appendSlice(allocator, ",\"action\":");
    try json.appendString(out, allocator, entry.action);
    try out.print(allocator, ",\"messages_copied\":{d},\"usage_copied\":{s}}}", .{ entry.messages_copied, if (entry.usage_copied) "true" else "false" });
}

