fn lifecycleSnapshotExport(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const persist_snapshot = json.boolField(obj, "persist") orelse json.boolField(obj, "record_snapshot") orelse (hasCapability(ctx, "write") or hasCapability(ctx, "propose"));
    if (persist_snapshot and !hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    if (snapshotExportFullMode(obj)) return lifecycleSnapshotFullExport(ctx, obj, persist_snapshot, route_query);
    const query = json.stringField(obj, "query") orelse "";
    var input = buildSearchInput(ctx, obj, query, searchLimit(json.intField(obj, "limit"), 100), true, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    input.include_deprecated = json.boolField(obj, "include_deprecated") orelse true;
    input.use_vector = json.boolField(obj, "use_vector") orelse false;
    const pipeline = runSearchPipeline(ctx, obj, query, input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const results = pipeline.results;
    const summary_json = snapshotSummaryJson(ctx, input.scopes_json, query, results) catch return serverError(ctx);
    const snapshot_type = json.stringField(obj, "type") orelse "export";
    const snapshot = if (persist_snapshot)
        ctx.store.createLifecycleSnapshot(ctx.allocator, snapshot_type, summary_json) catch return serverError(ctx)
    else
        store_mod.LifecycleSnapshot{ .id = ids.make(ctx.allocator, "snap_preview_") catch return serverError(ctx), .snapshot_type = snapshot_type, .summary_json = summary_json, .created_at_ms = ids.nowMs() };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"snapshot\":{\"id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"type\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.snapshot_type) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"scopes\":") catch return serverError(ctx);
    json.appendRawJsonArray(&out, ctx.allocator, input.scopes_json) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"schema_version\":\"nullpantry.snapshot.v1\",\"mode\":\"query\",\"persisted\":{s},\"created_at_ms\":{d},\"object_count\":{d},\"summary\":", .{ if (persist_snapshot) "true" else "false", snapshot.created_at_ms, results.len }) catch return serverError(ctx);
    json.appendRawJsonObject(&out, ctx.allocator, summary_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"manifest\":") catch return serverError(ctx);
    appendSnapshotManifest(ctx, &out, "query", snapshot.id, snapshot.snapshot_type, input.scopes_json, results.len, false, summary_json, null) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"objects\":") catch return serverError(ctx);
    appendSnapshotObjects(ctx, &out, results) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn snapshotExportFullMode(obj: std.json.ObjectMap) bool {
    if (json.boolField(obj, "full") orelse json.boolField(obj, "full_export") orelse false) return true;
    if (json.stringField(obj, "mode")) |mode| {
        return std.mem.eql(u8, mode, "full") or std.mem.eql(u8, mode, "scope") or std.mem.eql(u8, mode, "package");
    }
    return false;
}

fn lifecycleSnapshotFullExport(ctx: *Context, obj: std.json.ObjectMap, persist_snapshot: bool, route_query: []const u8) HttpResponse {
    const limit = snapshotPackageLimit(json.intField(obj, "limit"));
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const scope_filter_empty = jsonStringListIsEmpty(scopes_json);
    const input = store_mod.PrimitiveListInput{
        .limit = limit,
        .scopes_json = scopes_json,
        .scope_filter_empty = scope_filter_empty,
        .actor_id = ctx.actor_id,
        .include_deprecated = json.boolField(obj, "include_deprecated") orelse true,
    };
    var objects: std.ArrayListUnmanaged(u8) = .empty;
    var counts = SnapshotTypeCounts{};
    appendFullSnapshotObjects(ctx, &objects, input, obj, route_query, &counts) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const object_count = counts.total();
    const truncated = limit > 0 and object_count >= limit;
    const checksum = snapshotPackageChecksum(ctx.allocator, objects.items) catch return serverError(ctx);
    const counts_json = counts.toJson(ctx.allocator) catch return serverError(ctx);
    const summary_json = snapshotFullSummaryJson(ctx, scopes_json, object_count, truncated, counts_json, checksum) catch return serverError(ctx);
    const snapshot_type = json.stringField(obj, "type") orelse "full_export";
    const snapshot = if (persist_snapshot)
        ctx.store.createLifecycleSnapshot(ctx.allocator, snapshot_type, summary_json) catch return serverError(ctx)
    else
        store_mod.LifecycleSnapshot{ .id = ids.make(ctx.allocator, "snap_preview_") catch return serverError(ctx), .snapshot_type = snapshot_type, .summary_json = summary_json, .created_at_ms = ids.nowMs() };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"snapshot\":{\"id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"type\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.snapshot_type) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"schema_version\":\"nullpantry.snapshot.v1\",\"mode\":\"full\",\"scopes\":") catch return serverError(ctx);
    json.appendRawJsonArray(&out, ctx.allocator, scopes_json) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"persisted\":{s},\"created_at_ms\":{d},\"object_count\":{d},\"truncated\":{s},\"package_checksum\":", .{ if (persist_snapshot) "true" else "false", snapshot.created_at_ms, object_count, if (truncated) "true" else "false" }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, checksum) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"summary\":") catch return serverError(ctx);
    json.appendRawJsonObject(&out, ctx.allocator, summary_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"manifest\":") catch return serverError(ctx);
    appendSnapshotManifest(ctx, &out, "full", snapshot.id, snapshot.snapshot_type, scopes_json, object_count, truncated, summary_json, checksum) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"objects\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, objects.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleExportJsonl(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse "";
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_pii = json.boolField(obj, "include_pii") orelse false;
    var input = buildSearchInput(ctx, obj, query, searchLimit(json.intField(obj, "limit"), 1000), true, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    input.include_deprecated = json.boolField(obj, "include_deprecated") orelse true;
    input.use_vector = json.boolField(obj, "use_vector") orelse false;
    const pipeline = runSearchPipeline(ctx, obj, query, input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const results = pipeline.results;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    var written: usize = 0;
    for (results) |result| {
        if (!include_internal and exportResultIsInternal(result)) continue;
        if (written > 0) out.append(ctx.allocator, '\n') catch return serverError(ctx);
        appendJsonlExportRecord(ctx, &out, result, include_pii) catch return serverError(ctx);
        written += 1;
    }
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleImportJsonl(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    const trimmed = std.mem.trim(u8, body, " \t\r\n");
    if (trimmed.len == 0) return badJson(ctx);

    if (std.json.parseFromSlice(std.json.Value, ctx.allocator, trimmed, .{})) |parsed_value| {
        var parsed = parsed_value;
        defer parsed.deinit();
        if (parsed.value == .array) {
            const options = buildSnapshotImportOptions(ctx, null, route_query) catch |err| switch (err) {
                error.InvalidPayload => return badJson(ctx),
                else => return serverError(ctx),
            };
            return lifecycleSnapshotImportStructured(ctx, parsed.value.array.items, options);
        }
        if (parsed.value != .object) return badJson(ctx);
        const obj = parsed.value.object;
        if (snapshotObjectsValue(obj) != null) {
            return lifecycleSnapshotImport(ctx, body, route_query);
        }
        if (json.stringField(obj, "jsonl") orelse json.stringField(obj, "ndjson")) |lines| {
            return lifecycleImportJsonlLines(ctx, lines, obj, route_query);
        }
        if (snapshotObjectType(obj, snapshotRecordObject(obj)) != null) {
            const options = buildSnapshotImportOptions(ctx, obj, route_query) catch |err| switch (err) {
                error.InvalidPayload => return badJson(ctx),
                else => return serverError(ctx),
            };
            const items = [_]std.json.Value{parsed.value};
            return lifecycleSnapshotImportStructured(ctx, items[0..], options);
        }
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing jsonl, objects, or object_type");
    } else |_| {
        return lifecycleImportJsonlLines(ctx, trimmed, null, route_query);
    }
}

fn lifecycleImportJsonlLines(ctx: *Context, body: []const u8, root_obj: ?std.json.ObjectMap, route_query: []const u8) HttpResponse {
    var parsed_lines: std.ArrayListUnmanaged(std.json.Parsed(std.json.Value)) = .empty;
    defer {
        for (parsed_lines.items) |*parsed| parsed.deinit();
        parsed_lines.deinit(ctx.allocator);
    }
    var items: std.ArrayListUnmanaged(std.json.Value) = .empty;
    defer items.deinit(ctx.allocator);

    var lines = std.mem.splitScalar(u8, body, '\n');
    while (lines.next()) |line_raw| {
        const line = std.mem.trim(u8, line_raw, " \t\r\n");
        if (line.len == 0) continue;
        var parsed_line = std.json.parseFromSlice(std.json.Value, ctx.allocator, line, .{}) catch return badJson(ctx);
        if (parsed_line.value != .object) {
            parsed_line.deinit();
            return badJson(ctx);
        }
        parsed_lines.append(ctx.allocator, parsed_line) catch {
            parsed_line.deinit();
            return serverError(ctx);
        };
        items.append(ctx.allocator, parsed_lines.items[parsed_lines.items.len - 1].value) catch return serverError(ctx);
    }
    if (items.items.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing JSONL records");

    const options = buildSnapshotImportOptions(ctx, root_obj, route_query) catch |err| switch (err) {
        error.InvalidPayload, error.InvalidRawJson => return badJson(ctx),
        else => return serverError(ctx),
    };
    return lifecycleSnapshotImportStructured(ctx, items.items, options);
}

fn lifecycleSnapshotImport(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, if (body.len == 0) "{}" else body, .{}) catch return badJson(ctx);
    defer parsed.deinit();
    const root_obj: ?std.json.ObjectMap = switch (parsed.value) {
        .object => |obj| obj,
        .array => null,
        else => return badJson(ctx),
    };
    const objects_value = switch (parsed.value) {
        .object => |obj| snapshotObjectsValue(obj) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing objects"),
        .array => parsed.value,
        else => return badJson(ctx),
    };
    const objects = switch (objects_value) {
        .array => |a| a,
        else => return badJson(ctx),
    };
    const options = buildSnapshotImportOptions(ctx, root_obj, route_query) catch |err| switch (err) {
        error.InvalidPayload, error.InvalidRawJson => return badJson(ctx),
        else => return serverError(ctx),
    };
    verifySnapshotManifest(ctx, root_obj, objects_value, options) catch |err| switch (err) {
        error.InvalidPayload => return badJson(ctx),
        else => return serverError(ctx),
    };

    var memory_only = true;
    for (objects.items) |item| {
        if (item != .object) {
            continue;
        }
        const flat = snapshotRecordObject(item.object);
        const kind = snapshotObjectType(item.object, flat) orelse {
            memory_only = false;
            break;
        };
        if (!std.mem.eql(u8, kind, "memory_atom")) {
            memory_only = false;
            break;
        }
    }
    if (!memory_only) return lifecycleSnapshotImportStructured(ctx, objects.items, options);

    var prepared: std.ArrayListUnmanaged(store_mod.PreparedMemoryImport) = .empty;
    errdefer prepared.deinit(ctx.allocator);
    var skipped: usize = 0;
    for (objects.items) |item| {
        if (item != .object) {
            skipped += 1;
            continue;
        }
        const source_obj = snapshotRecordObject(item.object);
        const text = json.stringField(source_obj, "text") orelse {
            skipped += 1;
            continue;
        };
        if (options.preserve_ids and options.conflict_policy == .fail) {
            if (json.stringField(source_obj, "id")) |id| {
                if (ctx.store.getMemoryAtom(ctx.allocator, id) catch return serverError(ctx)) |existing| {
                    if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return forbidden(ctx);
                    return json.errorResponse(ctx.allocator, 409, "snapshot_conflict", "Snapshot memory atom already exists and conflict_policy=fail");
                }
            }
        }
        const title = json.stringField(source_obj, "title") orelse json.stringField(source_obj, "id") orelse "snapshot object";
        const result_type = json.stringField(source_obj, "type") orelse json.stringField(source_obj, "result_type") orelse "snapshot";
        const scope = json.stringField(source_obj, "scope") orelse options.default_scope;
        const permissions_json = snapshotPermissionsJson(ctx, source_obj, options) catch |err| return rawJsonRequestError(ctx, err);
        var source_ids_json = snapshotArrayJson(ctx, source_obj, &.{ "source_ids", "source_ids_json", "citations", "citations_json" }, "[]") catch |err| return rawJsonRequestError(ctx, err);
        const has_valid_sources = jsonArrayHasStringItems(ctx.allocator, source_ids_json) and sourceIdsCanBackRecord(ctx, source_ids_json, scope, permissions_json);
        if (!has_valid_sources) source_ids_json = "[]";
        const status = normalizedImportedMemoryStatus(json.stringField(source_obj, "status"));
        const predicate = std.fmt.allocPrint(ctx.allocator, "imported:{s}", .{result_type}) catch return serverError(ctx);
        const item_storage_route = snapshotHydrateStorageRoute(ctx, source_obj, options) catch return serverError(ctx);
        var input = store_mod.MemoryAtomInput{
            .predicate = predicate,
            .object = title,
            .text = text,
            .scope = scope,
            .confidence = json.floatField(source_obj, "confidence") orelse 0.55,
            .status = status,
            .source_ids_json = source_ids_json,
            .created_by = options.created_by,
            .permissions_json = permissions_json,
            .tags_json = "[\"snapshot_import\"]",
            .storage_route = item_storage_route,
        };
        var generated_source: ?store_mod.SourceInput = null;
        if (has_valid_sources) {
            if (!jsonArrayHasStringItems(ctx.allocator, input.evidence_ranges_json) and !jsonArrayHasObjectItems(ctx.allocator, input.evidence_ranges_json)) {
                const first_source = firstJsonStringDup(ctx.allocator, input.source_ids_json) catch return serverError(ctx);
                input.evidence_ranges_json = evidenceJson(ctx.allocator, first_source orelse "", input.text.len, "snapshot_import") catch return serverError(ctx);
            }
        } else {
            generated_source = .{
                .source_type = "snapshot_import",
                .title = title,
                .content = text,
                .author = json.nullableStringField(source_obj, "owner"),
                .permissions_json = permissions_json,
                .scope = scope,
                .metadata_json = "{\"generated_for\":\"snapshot_import\"}",
                .storage_route = item_storage_route,
            };
        }
        if (!canCreateMemoryAtom(ctx, input)) return forbidden(ctx);
        prepared.append(ctx.allocator, .{ .atom = input, .generated_source = generated_source }) catch return serverError(ctx);
    }
    if (options.dry_run) {
        return snapshotHydrateResponse(ctx, 0, 0, prepared.items.len, skipped, true, true, "[]", "[]", "{}");
    }
    const atoms = ctx.store.importMemoryAtomsAtomic(ctx.allocator, prepared.items) catch return serverError(ctx);
    var imported_ids: std.ArrayListUnmanaged(u8) = .empty;
    imported_ids.append(ctx.allocator, '[') catch return serverError(ctx);
    for (atoms, 0..) |atom, i| {
        if (i > 0) imported_ids.append(ctx.allocator, ',') catch return serverError(ctx);
        json.appendString(&imported_ids, ctx.allocator, atom.id) catch return serverError(ctx);
    }
    imported_ids.append(ctx.allocator, ']') catch return serverError(ctx);
    return snapshotHydrateResponse(ctx, atoms.len, atoms.len, prepared.items.len, skipped, false, true, imported_ids.items, "[]", "{}");
}

const SnapshotImportOptions = struct {
    default_scope: []const u8,
    default_permissions_json: []const u8,
    created_by: []const u8,
    dry_run: bool,
    preserve_ids: bool = true,
    default_scope_explicit: bool = false,
    storage_route: store_mod.AgentMemoryStorageRoute = .{},
    storage_route_overrides_record: bool = false,
    conflict_policy: SnapshotConflictPolicy = .skip,
    strict_manifest: bool = false,
};

const SnapshotConflictPolicy = enum {
    skip,
    fail,
};

fn buildSnapshotImportOptions(ctx: *Context, root_obj: ?std.json.ObjectMap, route_query: []const u8) !SnapshotImportOptions {
    const query_default_scope = try json.queryParamDecoded(ctx.allocator, route_query, "default_scope");
    const query_scope_alias = if (query_default_scope == null) try json.queryParamDecoded(ctx.allocator, route_query, "scope") else null;
    const query_scope = query_default_scope orelse query_scope_alias;
    if (root_obj) |obj| {
        const body_scope = json.stringField(obj, "default_scope") orelse json.stringField(obj, "scope");
        const explicit_scope = body_scope != null or query_scope != null;
        return .{
            .default_scope = body_scope orelse query_scope orelse "workspace",
            .default_permissions_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "default_permissions", "default_permissions_json" }, "[]"),
            .created_by = json.stringField(obj, "created_by") orelse "agent",
            .dry_run = (json.boolField(obj, "dry_run") orelse queryBool(route_query, "dry_run", false)) or
                (json.boolField(obj, "preflight") orelse queryBool(route_query, "preflight", false)) or
                (json.boolField(obj, "preflight_only") orelse queryBool(route_query, "preflight_only", false)),
            .preserve_ids = json.boolField(obj, "preserve_ids") orelse true,
            .default_scope_explicit = explicit_scope,
            .storage_route = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query),
            .storage_route_overrides_record = storage_routes.queryHasSelector(route_query) or storage_routes.objectHasSelector(obj),
            .conflict_policy = try parseSnapshotConflictPolicy(json.stringField(obj, "conflict_policy") orelse try json.queryParamDecoded(ctx.allocator, route_query, "conflict_policy") orelse "skip"),
            .strict_manifest = (json.boolField(obj, "strict_manifest") orelse queryBool(route_query, "strict_manifest", false)) or
                (json.boolField(obj, "verify_checksum") orelse queryBool(route_query, "verify_checksum", false)),
        };
    }
    return .{
        .default_scope = query_scope orelse "workspace",
        .default_permissions_json = "[]",
        .created_by = "agent",
        .dry_run = queryBool(route_query, "dry_run", false) or queryBool(route_query, "preflight", false) or queryBool(route_query, "preflight_only", false),
        .preserve_ids = true,
        .default_scope_explicit = query_scope != null,
        .storage_route = try storage_routes.fromQuery(ctx.allocator, route_query),
        .storage_route_overrides_record = storage_routes.queryHasSelector(route_query),
        .conflict_policy = try parseSnapshotConflictPolicy((try json.queryParamDecoded(ctx.allocator, route_query, "conflict_policy")) orelse "skip"),
        .strict_manifest = queryBool(route_query, "strict_manifest", false) or queryBool(route_query, "verify_checksum", false),
    };
}

fn parseSnapshotConflictPolicy(raw: []const u8) !SnapshotConflictPolicy {
    if (std.mem.eql(u8, raw, "skip") or std.mem.eql(u8, raw, "skip_existing") or std.mem.eql(u8, raw, "idempotent")) return .skip;
    if (std.mem.eql(u8, raw, "fail") or std.mem.eql(u8, raw, "error") or std.mem.eql(u8, raw, "fail_existing")) return .fail;
    return error.InvalidPayload;
}

fn verifySnapshotManifest(ctx: *Context, root_obj: ?std.json.ObjectMap, objects_value: std.json.Value, options: SnapshotImportOptions) !void {
    const root = root_obj orelse return;
    const manifest_obj = snapshotManifestObject(root);
    const expected_checksum = if (manifest_obj) |manifest|
        json.stringField(manifest, "package_checksum") orelse json.stringField(root, "package_checksum")
    else
        json.stringField(root, "package_checksum");
    if (manifest_obj) |manifest| {
        if (json.stringField(manifest, "schema_version")) |schema| {
            if (!std.mem.eql(u8, schema, "nullpantry.snapshot.v1")) return error.InvalidPayload;
        } else if (options.strict_manifest) return error.InvalidPayload;
    } else if (options.strict_manifest) return error.InvalidPayload;
    const expected = expected_checksum orelse {
        if (options.strict_manifest) return error.InvalidPayload;
        return;
    };
    const objects_json = try json.jsonFromValue(ctx.allocator, objects_value);
    defer ctx.allocator.free(objects_json);
    const actual = try snapshotPackageChecksum(ctx.allocator, objects_json);
    defer ctx.allocator.free(actual);
    if (!std.mem.eql(u8, expected, actual)) return error.InvalidPayload;
}

fn snapshotManifestObject(root: std.json.ObjectMap) ?std.json.ObjectMap {
    if (root.get("manifest")) |manifest| {
        if (manifest == .object) return manifest.object;
    }
    if (root.get("snapshot")) |snapshot_value| {
        if (snapshot_value == .object) {
            if (snapshot_value.object.get("manifest")) |manifest| {
                if (manifest == .object) return manifest.object;
            }
        }
    }
    return null;
}

fn snapshotHydrateStorageRoute(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !store_mod.AgentMemoryStorageRoute {
    if (options.storage_route_overrides_record) return options.storage_route;
    return try storage_routes.fromObjectOrFallback(ctx.allocator, obj, options.storage_route);
}

fn snapshotArrayJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn snapshotObjectJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn snapshotPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) ![]const u8 {
    return snapshotArrayJson(ctx, obj, &.{ "permissions", "permissions_json" }, options.default_permissions_json);
}

const SnapshotHydratedObject = struct {
    object_type: []const u8,
    id: []const u8,
    created: bool = true,
};

const ContextPackSnapshotJsonFields = struct {
    sections_json: []const u8,
    citations_json: []const u8,
    forbidden_assumptions_json: []const u8,
    suggested_next_steps_json: []const u8,
    included_sources_json: []const u8,
    included_artifacts_json: []const u8,
    included_memory_atoms_json: []const u8,
    included_result_refs_json: []const u8,
};

fn contextPackSnapshotJsonFields(ctx: *Context, obj: std.json.ObjectMap) !ContextPackSnapshotJsonFields {
    return .{
        .sections_json = try rawObjectFieldAny(ctx.allocator, obj, &.{ "sections", "sections_json" }, "{}"),
        .citations_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "citations", "citations_json", "included_sources", "included_sources_json" }, "[]"),
        .forbidden_assumptions_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "forbidden_assumptions", "forbidden_assumptions_json" }, context_pack.forbidden_assumptions_json),
        .suggested_next_steps_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "suggested_next_steps", "suggested_next_steps_json" }, context_pack.suggested_next_steps_json),
        .included_sources_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "included_sources", "included_sources_json", "citations" }, "[]"),
        .included_artifacts_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "included_artifacts", "included_artifacts_json" }, "[]"),
        .included_memory_atoms_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "included_memory_atoms", "included_memory_atoms_json" }, "[]"),
        .included_result_refs_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "included_result_refs", "included_result_refs_json" }, "[]"),
    };
}

fn lifecycleSnapshotImportStructured(ctx: *Context, items: []const std.json.Value, options: SnapshotImportOptions) HttpResponse {
    var validated: usize = 0;
    var skipped: usize = 0;
    var imported: usize = 0;
    var hydrated_count: usize = 0;
    var ids_out: std.ArrayListUnmanaged(u8) = .empty;
    ids_out.append(ctx.allocator, '[') catch return serverError(ctx);
    var first_id = true;
    var counts = SnapshotTypeCounts{};

    const phases = [_][]const u8{ "policy_scope", "space", "source", "entity", "artifact", "memory_atom", "relation", "agent_memory", "context_pack" };
    for (phases) |phase| {
        for (items) |item| {
            if (item != .object) {
                if (std.mem.eql(u8, phase, phases[0])) skipped += 1;
                continue;
            }
            const outer = item.object;
            const record = snapshotRecordObject(outer);
            const kind = snapshotObjectType(outer, record) orelse {
                if (std.mem.eql(u8, phase, phases[0])) skipped += 1;
                continue;
            };
            if (!std.mem.eql(u8, kind, phase)) continue;
            validated += 1;
            const hydrated = snapshotHydrateStructuredObject(ctx, kind, record, options) catch |err| switch (err) {
                error.Forbidden,
                error.RelatedEntityNotFound,
                error.RecordAclBroaderThanRelatedEntity,
                error.SpaceNotFound,
                error.ArtifactAclBroaderThanSpace,
                error.CanonicalArtifactNotFound,
                error.EntityAclBroaderThanCanonicalArtifact,
                error.ContextPackReferenceNotFound,
                error.ContextPackAclBroaderThanRefs,
                => return forbidden(ctx),
                error.InvalidPayload,
                error.InvalidStorageSelector,
                error.InvalidRawJson,
                => return badJson(ctx),
                error.SnapshotConflict => return json.errorResponse(ctx.allocator, 409, "snapshot_conflict", "Snapshot object already exists and conflict_policy=fail"),
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                error.Skipped => {
                    skipped += 1;
                    continue;
                },
                else => return serverError(ctx),
            };
            if (!options.dry_run) {
                hydrated_count += 1;
                if (hydrated.created) imported += 1;
            }
            counts.add(kind);
            if (!first_id) ids_out.append(ctx.allocator, ',') catch return serverError(ctx);
            first_id = false;
            appendSnapshotHydratedObjectJson(ctx, &ids_out, hydrated) catch return serverError(ctx);
        }
    }
    ids_out.append(ctx.allocator, ']') catch return serverError(ctx);
    const counts_json = counts.toJson(ctx.allocator) catch return serverError(ctx);
    return snapshotHydrateResponse(ctx, imported, hydrated_count, validated, skipped, options.dry_run, false, "[]", ids_out.items, counts_json);
}

fn snapshotObjectsValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("objects")) |objects| return objects;
    if (obj.get("snapshot")) |snapshot_value| {
        if (snapshot_value == .object) return snapshot_value.object.get("objects");
    }
    return null;
}

fn snapshotHydrateResponse(ctx: *Context, imported: usize, hydrated: usize, validated: usize, skipped: usize, dry_run: bool, atomic: bool, memory_atom_ids_json: []const u8, object_ids_json: []const u8, counts_json: []const u8) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"imported\":{d},\"hydrated\":{d},\"validated\":{d},\"skipped\":{d},\"dry_run\":{s},\"atomic\":{s},\"memory_atom_ids\":", .{ imported, hydrated, validated, skipped, if (dry_run) "true" else "false", if (atomic) "true" else "false" }) catch return serverError(ctx);
    json.appendRawJsonArray(&out, ctx.allocator, memory_atom_ids_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"object_ids\":") catch return serverError(ctx);
    json.appendRawJsonArray(&out, ctx.allocator, object_ids_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"counts\":") catch return serverError(ctx);
    json.appendRawJsonObject(&out, ctx.allocator, counts_json) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"import_plan\":") catch return serverError(ctx);
    appendSnapshotHydratePlan(ctx, &out, atomic) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"reindex_required\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (dry_run or imported == 0) "false" else "true") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"post_hydrate_actions\":[\"run /v1/vector/reconcile for restored knowledge primitives before relying on vector retrieval\",\"request /v1/memory/checkpoint separately for feed/session runtime state\"],\"unsupported_state\":[\"vector_chunks\",\"external_vector_store_state\",\"response_cache\",\"semantic_cache\",\"embedding_cache\",\"feed_events\",\"feed_checkpoints\",\"jobs\",\"connector_cursors\",\"sessions\",\"usage\",\"conflicts\",\"analytics_projection\",\"lifecycle_snapshot_records\",\"attachments_blob_payloads\"]") catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendSnapshotHydratePlan(ctx: *Context, out: *std.ArrayListUnmanaged(u8), atomic: bool) !void {
    try out.appendSlice(ctx.allocator, "{\"schema_version\":\"nullpantry.snapshot.import_plan.v1\",\"hydrate_order\":[\"policy_scope\",\"space\",\"source\",\"entity\",\"artifact\",\"memory_atom\",\"relation\",\"agent_memory\",\"context_pack\"],\"dependency_checks\":[\"source_ids_acl\",\"space_scope_acl\",\"entity_endpoint_visibility\",\"context_pack_refs_visibility\",\"agent_memory_owner_isolation\"],\"conflict_policies\":[\"skip\",\"fail\"],\"atomic_multi_type\":");
    try out.appendSlice(ctx.allocator, if (atomic) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"atomic_memory_atom_batch\":true,\"manifest_checksum_supported\":true}");
}

fn snapshotRecordObject(outer: std.json.ObjectMap) std.json.ObjectMap {
    if (outer.get("record")) |record| {
        if (record == .object) return record.object;
    }
    if (outer.get("search_result")) |search_result| {
        if (search_result == .object) return search_result.object;
    }
    return outer;
}

fn snapshotObjectType(outer: std.json.ObjectMap, record: std.json.ObjectMap) ?[]const u8 {
    if (json.stringField(outer, "object_type")) |value| return value;
    if (json.stringField(outer, "snapshot_object_type")) |value| return value;
    if (json.stringField(record, "object_type")) |value| return value;
    if (json.stringField(record, "result_type")) |value| return value;
    if (isLegacyNullClawMemoryRecord(record)) return "agent_memory";
    const type_value = json.stringField(record, "type") orelse return null;
    if (snapshotPrimitiveSupported(type_value)) return type_value;
    return null;
}

fn isLegacyNullClawMemoryRecord(record: std.json.ObjectMap) bool {
    if (json.stringField(record, "key") == null) return false;
    if (json.stringField(record, "content") == null and json.stringField(record, "text") == null) return false;
    if (record.get("schema_version")) |schema_version| {
        return switch (schema_version) {
            .integer => |value| value == 1,
            .string => |value| std.mem.eql(u8, value, "1"),
            else => false,
        };
    }
    return record.get("timestamp") != null or record.get("category") != null or record.get("session_id") != null;
}

fn snapshotPrimitiveSupported(value: []const u8) bool {
    return std.mem.eql(u8, value, "source") or
        std.mem.eql(u8, value, "artifact") or
        std.mem.eql(u8, value, "memory_atom") or
        std.mem.eql(u8, value, "entity") or
        std.mem.eql(u8, value, "relation") or
        std.mem.eql(u8, value, "space") or
        std.mem.eql(u8, value, "policy_scope") or
        std.mem.eql(u8, value, "context_pack") or
        std.mem.eql(u8, value, "agent_memory");
}

const SnapshotTypeCounts = struct {
    policy_scope: usize = 0,
    space: usize = 0,
    source: usize = 0,
    artifact: usize = 0,
    memory_atom: usize = 0,
    entity: usize = 0,
    relation: usize = 0,
    context_pack: usize = 0,
    agent_memory: usize = 0,

    fn add(self: *SnapshotTypeCounts, object_type: []const u8) void {
        if (std.mem.eql(u8, object_type, "policy_scope")) self.policy_scope += 1 else if (std.mem.eql(u8, object_type, "space")) self.space += 1 else if (std.mem.eql(u8, object_type, "source")) self.source += 1 else if (std.mem.eql(u8, object_type, "artifact")) self.artifact += 1 else if (std.mem.eql(u8, object_type, "memory_atom")) self.memory_atom += 1 else if (std.mem.eql(u8, object_type, "entity")) self.entity += 1 else if (std.mem.eql(u8, object_type, "relation")) self.relation += 1 else if (std.mem.eql(u8, object_type, "context_pack")) self.context_pack += 1 else if (std.mem.eql(u8, object_type, "agent_memory")) self.agent_memory += 1;
    }

    fn toJson(self: SnapshotTypeCounts, allocator: std.mem.Allocator) ![]const u8 {
        return std.fmt.allocPrint(allocator, "{{\"policy_scope\":{d},\"space\":{d},\"source\":{d},\"artifact\":{d},\"memory_atom\":{d},\"entity\":{d},\"relation\":{d},\"context_pack\":{d},\"agent_memory\":{d}}}", .{ self.policy_scope, self.space, self.source, self.artifact, self.memory_atom, self.entity, self.relation, self.context_pack, self.agent_memory });
    }

    fn total(self: SnapshotTypeCounts) usize {
        return self.policy_scope + self.space + self.source + self.artifact + self.memory_atom + self.entity + self.relation + self.context_pack + self.agent_memory;
    }
};

fn appendSnapshotHydratedObjectJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), hydrated: SnapshotHydratedObject) !void {
    try out.appendSlice(ctx.allocator, "{\"type\":");
    try json.appendString(out, ctx.allocator, hydrated.object_type);
    try out.appendSlice(ctx.allocator, ",\"id\":");
    try json.appendString(out, ctx.allocator, hydrated.id);
    try out.append(ctx.allocator, '}');
}

fn snapshotHydrateStructuredObject(ctx: *Context, object_type: []const u8, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    if (std.mem.eql(u8, object_type, "policy_scope")) return try snapshotHydratePolicyScope(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "space")) return try snapshotHydrateSpace(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "source")) return try snapshotHydrateSource(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "artifact")) return try snapshotHydrateArtifact(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "entity")) return try snapshotHydrateEntity(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "relation")) return try snapshotHydrateRelation(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "memory_atom")) return try snapshotHydrateMemoryAtom(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "agent_memory")) return try snapshotHydrateAgentMemory(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "context_pack")) return try snapshotHydrateContextPack(ctx, obj, options);
    return error.Skipped;
}

fn snapshotHydratePolicyScope(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const scope = json.stringField(obj, "scope") orelse json.stringField(obj, "id") orelse json.stringField(obj, "title") orelse return error.Skipped;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "policy_scope", .id = scope };
    const existing = try ctx.store.getPolicyScope(ctx.allocator, scope);
    if (existing) |policy| {
        if (!recordVisibleToActor(ctx, policy.scope, policy.permissions_json)) return error.Forbidden;
        if (options.conflict_policy == .fail) return error.SnapshotConflict;
        return .{ .object_type = "policy_scope", .id = policy.scope, .created = false };
    }
    const policy = try ctx.store.upsertPolicyScope(ctx.allocator, .{
        .scope = scope,
        .visibility = json.stringField(obj, "visibility") orelse "workspace",
        .permissions_json = permissions,
        .owner = json.nullableStringField(obj, "owner"),
        .ttl_ms = json.intField(obj, "ttl_ms"),
        .review_after_ms = json.intField(obj, "review_after_ms"),
        .metadata_json = try snapshotObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{\"snapshot_import\":true}"),
        .actor_id = ctx.actor_id,
        .suppress_feed = true,
    });
    return .{ .object_type = "policy_scope", .id = policy.scope, .created = existing == null };
}

fn snapshotHydrateSpace(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const name = json.stringField(obj, "name") orelse json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const title = json.stringField(obj, "title") orelse name;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "space", .id = json.stringField(obj, "id") orelse name };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getSpace(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "space", .id = existing.id, .created = false };
            }
        }
    }
    if (try ctx.store.getSpace(ctx.allocator, name)) |existing| {
        if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
        return .{ .object_type = "space", .id = existing.id, .created = false };
    }
    const space = try ctx.store.createSpace(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .name = name,
        .title = title,
        .description = json.nullableStringField(obj, "description") orelse json.nullableStringField(obj, "text"),
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try snapshotObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{\"snapshot_import\":true}"),
        .actor_id = ctx.actor_id,
        .suppress_feed = true,
    });
    return .{ .object_type = "space", .id = space.id };
}

fn snapshotHydrateSource(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "source", .id = json.stringField(obj, "id") orelse title };
    const route = try snapshotHydrateStorageRoute(ctx, obj, options);
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getSource(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "source", .id = existing.id, .created = false };
            }
        }
    }
    const source_type = json.stringField(obj, "source_type") orelse blk: {
        const raw_type = json.stringField(obj, "type") orelse "manual";
        break :blk if (std.mem.eql(u8, raw_type, "source")) "manual" else raw_type;
    };
    const source = try ctx.store.createSource(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .source_type = source_type,
        .title = title,
        .raw_content_uri = json.nullableStringField(obj, "raw_content_uri"),
        .content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse "",
        .author = json.nullableStringField(obj, "author"),
        .participants_json = try snapshotArrayJson(ctx, obj, &.{ "participants", "participants_json" }, "[]"),
        .permissions_json = permissions,
        .scope = scope,
        .checksum = json.nullableStringField(obj, "checksum"),
        .language = json.nullableStringField(obj, "language"),
        .related_entities_json = try snapshotArrayJson(ctx, obj, &.{ "related_entities", "related_entities_json" }, "[]"),
        .metadata_json = try snapshotObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{\"snapshot_import\":true}"),
        .actor_id = ctx.actor_id,
        .storage_route = route,
    });
    return .{ .object_type = "source", .id = source.id };
}

fn snapshotHydrateArtifact(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    const status = json.stringField(obj, "status") orelse "draft";
    if (!canChangeGraphPrimitiveStatus(ctx, scope, permissions, status)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "artifact", .id = json.stringField(obj, "id") orelse title };
    const route = try snapshotHydrateStorageRoute(ctx, obj, options);
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getArtifact(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "artifact", .id = existing.id, .created = false };
            }
        }
    }
    var source_ids = try snapshotArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json", "citations", "citations_json" }, "[]");
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const space_id = json.nullableStringField(obj, "space_id");
    if (!spaceCanContainRecord(ctx, space_id, scope, permissions)) return error.Forbidden;
    const artifact_type = json.stringField(obj, "artifact_type") orelse blk: {
        const raw_type = json.stringField(obj, "type") orelse "page";
        break :blk if (std.mem.eql(u8, raw_type, "artifact")) "page" else raw_type;
    };
    const artifact = try ctx.store.createArtifact(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .artifact_type = artifact_type,
        .title = title,
        .body = json.stringField(obj, "body") orelse json.stringField(obj, "text") orelse "",
        .status = status,
        .owner = json.nullableStringField(obj, "owner"),
        .space_id = space_id,
        .scope = scope,
        .source_ids_json = source_ids,
        .related_entities_json = try snapshotArrayJson(ctx, obj, &.{ "related_entities", "related_entities_json" }, "[]"),
        .permissions_json = permissions,
        .fields_json = try snapshotObjectJson(ctx, obj, &.{ "fields", "fields_json" }, "{}"),
        .summary = json.nullableStringField(obj, "summary"),
        .agent_summary = json.nullableStringField(obj, "agent_summary"),
        .actor_id = ctx.actor_id,
        .storage_route = route,
    });
    return .{ .object_type = "artifact", .id = artifact.id };
}

fn snapshotHydrateEntity(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "name") orelse json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const name = snapshotEntityName(ctx.allocator, title) catch return error.OutOfMemory;
    const entity_type = json.stringField(obj, "entity_type") orelse snapshotEntityType(title);
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "entity", .id = json.stringField(obj, "id") orelse name };
    const route = try snapshotHydrateStorageRoute(ctx, obj, options);
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getEntity(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "entity", .id = existing.id, .created = false };
            }
        }
    }
    const canonical_artifact_id = json.nullableStringField(obj, "canonical_artifact_id");
    if (!artifactCanBackRecord(ctx, canonical_artifact_id, scope, permissions)) return error.Forbidden;
    const entity = try ctx.store.resolveEntity(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .entity_type = entity_type,
        .name = name,
        .aliases_json = try snapshotArrayJson(ctx, obj, &.{ "aliases", "aliases_json" }, "[]"),
        .description = json.nullableStringField(obj, "description") orelse json.nullableStringField(obj, "text"),
        .canonical_artifact_id = canonical_artifact_id,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try snapshotObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{}"),
        .actor_id = ctx.actor_id,
        .storage_route = route,
    });
    return .{ .object_type = "entity", .id = entity.id };
}

fn snapshotHydrateRelation(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const from_entity_id = json.stringField(obj, "from_entity_id") orelse return error.Skipped;
    const to_entity_id = json.stringField(obj, "to_entity_id") orelse return error.Skipped;
    const relation_type = json.stringField(obj, "relation_type") orelse json.stringField(obj, "title") orelse "related_to";
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    const status = json.stringField(obj, "status") orelse "proposed";
    if (!canChangeGraphPrimitiveStatus(ctx, scope, permissions, status)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "relation", .id = json.stringField(obj, "id") orelse relation_type };
    const route = try snapshotHydrateStorageRoute(ctx, obj, options);
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getRelation(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "relation", .id = existing.id, .created = false };
            }
        }
    }
    var source_ids = try snapshotArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json", "citations", "citations_json" }, "[]");
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const relation = ctx.store.createRelation(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .from_entity_id = from_entity_id,
        .relation_type = relation_type,
        .to_entity_id = to_entity_id,
        .source_ids_json = source_ids,
        .scope = scope,
        .permissions_json = permissions,
        .confidence = json.floatField(obj, "confidence") orelse 0.5,
        .status = status,
        .actor_id = ctx.actor_id,
        .storage_route = route,
    }) catch |err| switch (err) {
        error.EntityNotFound => return error.Skipped,
        else => return err,
    };
    return .{ .object_type = "relation", .id = relation.id };
}

fn snapshotHydrateMemoryAtom(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const text = json.stringField(obj, "text") orelse json.stringField(obj, "content") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    var source_ids = try snapshotArrayJson(ctx, obj, &.{ "source_ids", "source_ids_json", "citations", "citations_json" }, "[]");
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const input = store_mod.MemoryAtomInput{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .subject_entity_id = json.nullableStringField(obj, "subject_entity_id"),
        .predicate = json.stringField(obj, "predicate") orelse "imported:snapshot",
        .object = json.stringField(obj, "object") orelse json.stringField(obj, "title") orelse "",
        .text = text,
        .scope = scope,
        .confidence = json.floatField(obj, "confidence") orelse 0.55,
        .status = normalizedImportedMemoryStatus(json.stringField(obj, "status")),
        .source_ids_json = source_ids,
        .evidence_ranges_json = try snapshotArrayJson(ctx, obj, &.{ "evidence_ranges", "evidence_ranges_json" }, "[]"),
        .created_by = json.stringField(obj, "created_by") orelse options.created_by,
        .valid_from_ms = json.intField(obj, "valid_from_ms"),
        .valid_until_ms = json.intField(obj, "valid_until_ms"),
        .owner = json.nullableStringField(obj, "owner"),
        .permissions_json = permissions,
        .tags_json = try snapshotArrayJson(ctx, obj, &.{ "tags", "tags_json" }, "[\"snapshot_import\"]"),
        .actor_id = ctx.actor_id,
        .storage_route = try snapshotHydrateStorageRoute(ctx, obj, options),
    };
    if (!canCreateMemoryAtom(ctx, input)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "memory_atom", .id = json.stringField(obj, "id") orelse text };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getMemoryAtom(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "memory_atom", .id = existing.id, .created = false };
            }
        }
    }
    const atom = try ctx.store.createMemoryAtom(ctx.allocator, input);
    return .{ .object_type = "memory_atom", .id = atom.id };
}

fn snapshotAgentMemoryOwnerLease(ctx: *Context, scope: ?[]const u8, obj: std.json.ObjectMap) !AgentMemoryOwnerLease {
    const computed_owner_id = try access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope);
    errdefer ctx.allocator.free(computed_owner_id);
    if (json.stringField(obj, "owner_id") orelse json.stringField(obj, "actor_id")) |explicit_owner_id| {
        if (!std.mem.eql(u8, explicit_owner_id, computed_owner_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
        ctx.allocator.free(computed_owner_id);
        return .{ .value = explicit_owner_id };
    }
    return .{ .value = computed_owner_id, .owned = computed_owner_id };
}

fn snapshotHydrateAgentMemory(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const category = json.stringField(obj, "category") orelse snapshotAgentMemoryCategory(obj);
    const key = json.stringField(obj, "key") orelse try snapshotAgentMemoryKey(ctx.allocator, json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped, category);
    const content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse return error.Skipped;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    const explicit_scope = json.nullableStringField(obj, "scope");
    const scope = explicit_scope orelse if (options.default_scope_explicit) options.default_scope else null;
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = content, .scope = requested_scope, .permissions_json = permissions, .created_by = "agent", .actor_id = ctx.actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }
    if (options.dry_run) return .{ .object_type = "agent_memory", .id = json.stringField(obj, "id") orelse key };
    var owner = try snapshotAgentMemoryOwnerLease(ctx, scope, obj);
    defer owner.deinit(ctx.allocator);
    const owner_actor_id = owner.value;
    const route = try snapshotHydrateStorageRoute(ctx, obj, options);
    if (try api_agent_memory_store.getByInput(ctx, .{
        .key = key,
        .route = route,
        .session_id = session_id,
        .owner_actor_id = owner_actor_id,
        .access = .exact_owner,
    })) |existing| {
        if (options.conflict_policy == .fail) return error.SnapshotConflict;
        if (std.mem.eql(u8, existing.content, content) and std.mem.eql(u8, existing.category, category)) {
            return .{ .object_type = "agent_memory", .id = existing.id, .created = false };
        }
        return .{ .object_type = "agent_memory", .id = existing.id, .created = false };
    }
    const entry = try ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
        .key = key,
        .content = content,
        .category = category,
        .session_id = session_id,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try snapshotObjectJson(ctx, obj, &.{ "metadata", "metadata_json" }, "{\"snapshot_import\":true}"),
        .actor_id = owner_actor_id,
        .writer_actor_id = ctx.actor_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
        .event_order = snapshotAgentMemoryEventOrder(obj),
    }, route);
    return .{ .object_type = "agent_memory", .id = entry.id };
}

fn snapshotAgentMemoryEventOrder(obj: std.json.ObjectMap) ?store_mod.AgentMemoryEventOrder {
    const timestamp_ms = snapshotTimestampMs(obj) orelse return null;
    return .{
        .timestamp_ms = timestamp_ms,
        .origin_instance_id = "nullclaw_snapshot_import",
        .origin_sequence = timestamp_ms,
    };
}

fn snapshotTimestampMs(obj: std.json.ObjectMap) ?i64 {
    if (json.intField(obj, "timestamp_ms")) |value| return value;
    if (json.intField(obj, "created_at_ms")) |value| return value;
    if (json.intField(obj, "timestamp")) |value| return value;
    if (json.stringField(obj, "timestamp")) |value| return std.fmt.parseInt(i64, value, 10) catch null;
    return null;
}

fn snapshotHydrateContextPack(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "task") orelse json.stringField(obj, "title") orelse json.stringField(obj, "text") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try snapshotPermissionsJson(ctx, obj, options);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "context_pack", .id = json.stringField(obj, "id") orelse query };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.contextPackLifecycleTarget(ctx.allocator, id, ctx.actor_id, ctx.actor_scopes_json)) |_| {
                if (options.conflict_policy == .fail) return error.SnapshotConflict;
                return .{ .object_type = "context_pack", .id = id, .created = false };
            }
        }
    }
    const default_scopes_json = try singleStringArrayJson(ctx.allocator, scope);
    const scopes_json = try snapshotArrayJson(ctx, obj, &.{ "scopes", "scopes_json", "required_scopes", "required_scopes_json" }, default_scopes_json);
    if (json.stringField(obj, "generated_summary") != null or
        obj.get("included_sources") != null or
        obj.get("included_sources_json") != null or
        obj.get("included_artifacts") != null or
        obj.get("included_artifacts_json") != null or
        obj.get("included_memory_atoms") != null or
        obj.get("included_memory_atoms_json") != null or
        obj.get("included_result_refs") != null or
        obj.get("included_result_refs_json") != null)
    {
        const requested_actor_id = json.nullableStringField(obj, "actor_id");
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        const restore_actor_id = try snapshotContextPackActorId(ctx, requested_actor_id, actor_isolated);
        const fields = try contextPackSnapshotJsonFields(ctx, obj);
        const pack = try ctx.store.importContextPackSnapshot(ctx.allocator, .{
            .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
            .purpose = json.stringField(obj, "purpose") orelse "snapshot_hydrate",
            .target = json.stringField(obj, "target") orelse "agent",
            .query = query,
            .generated_summary = json.stringField(obj, "generated_summary") orelse json.stringField(obj, "summary") orelse query,
            .sections_json = fields.sections_json,
            .citations_json = fields.citations_json,
            .forbidden_assumptions_json = fields.forbidden_assumptions_json,
            .suggested_next_steps_json = fields.suggested_next_steps_json,
            .included_sources_json = fields.included_sources_json,
            .included_artifacts_json = fields.included_artifacts_json,
            .included_memory_atoms_json = fields.included_memory_atoms_json,
            .included_result_refs_json = fields.included_result_refs_json,
            .required_scopes_json = scopes_json,
            .actor_id = restore_actor_id,
            .actor_isolated = actor_isolated,
            .token_budget = json.intField(obj, "token_budget") orelse 12000,
            .actor_id_for_audit = ctx.actor_id,
        });
        return .{ .object_type = "context_pack", .id = pack.id };
    }
    const pack = try ctx.store.createContextPack(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .purpose = json.stringField(obj, "purpose") orelse "snapshot_hydrate",
        .target = json.stringField(obj, "target") orelse "agent",
        .query = query,
        .token_budget = json.intField(obj, "token_budget") orelse 12000,
        .scopes_json = scopes_json,
        .persist = true,
        .include_deprecated = true,
        .use_vector = false,
        .actor_id = ctx.actor_id,
    });
    return .{ .object_type = "context_pack", .id = pack.id };
}

fn snapshotContextPackActorId(ctx: *Context, requested_actor_id: ?[]const u8, actor_isolated: bool) !?[]const u8 {
    if (requested_actor_id) |actor| {
        if (actor_isolated and !std.mem.eql(u8, actor, ctx.actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
        if (!actor_isolated and (std.mem.eql(u8, actor, ctx.actor_id) or access.isSharedAgentMemoryOwner(actor) or domain.hasActorScope(ctx.actor_scopes_json, "admin"))) return actor;
        if (actor_isolated) return actor;
    }
    return ctx.actor_id;
}

fn snapshotEntityType(title: []const u8) []const u8 {
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx > 0) return title[0..idx];
    }
    return "concept";
}

fn snapshotEntityName(allocator: std.mem.Allocator, title: []const u8) ![]const u8 {
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx + 1 < title.len) return allocator.dupe(u8, title[idx + 1 ..]);
    }
    return allocator.dupe(u8, title);
}

fn snapshotAgentMemoryCategory(obj: std.json.ObjectMap) []const u8 {
    const title = json.stringField(obj, "title") orelse return "core";
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx > 0 and !std.mem.eql(u8, title[0..idx], "agent_memory")) return title[0..idx];
    }
    return "core";
}

fn snapshotAgentMemoryKey(allocator: std.mem.Allocator, title: []const u8, category: []const u8) ![]const u8 {
    const prefixes = [_][]const u8{ "agent_memory:", category };
    for (prefixes) |prefix| {
        if (prefix.len == 0) continue;
        if (std.mem.startsWith(u8, title, prefix)) {
            const offset = prefix.len + if (std.mem.endsWith(u8, prefix, ":")) @as(usize, 0) else @as(usize, 1);
            if (offset < title.len and title[prefix.len] == ':') return allocator.dupe(u8, title[offset..]);
            if (std.mem.endsWith(u8, prefix, ":") and prefix.len < title.len) return allocator.dupe(u8, title[prefix.len..]);
        }
    }
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx + 1 < title.len) return allocator.dupe(u8, title[idx + 1 ..]);
    }
    return allocator.dupe(u8, title);
}

fn normalizedImportedMemoryStatus(status: ?[]const u8) ?[]const u8 {
    const value = status orelse return null;
    if (std.mem.eql(u8, value, "accepted")) return "verified";
    if (std.mem.eql(u8, value, "verified") or
        std.mem.eql(u8, value, "proposed") or
        std.mem.eql(u8, value, "stale") or
        std.mem.eql(u8, value, "deprecated") or
        std.mem.eql(u8, value, "rejected") or
        std.mem.eql(u8, value, "superseded"))
    {
        return value;
    }
    return null;
}

fn snapshotSummaryJson(ctx: *Context, scopes_json: []const u8, query: []const u8, results: []const domain.SearchResult) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);

    try out.appendSlice(ctx.allocator, "{\"query\":");
    try json.appendString(&out, ctx.allocator, query);
    try out.appendSlice(ctx.allocator, ",\"scopes\":");
    try json.appendRawJsonArray(&out, ctx.allocator, scopes_json);
    try out.print(ctx.allocator, ",\"object_count\":{d},\"counts\":{{", .{results.len});
    const types = [_][]const u8{ "memory_atom", "space", "policy_scope", "source", "artifact", "entity", "relation", "context_pack", "feed_event", "session_message" };
    for (types, 0..) |kind, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try json.appendString(&out, ctx.allocator, kind);
        try out.append(ctx.allocator, ':');
        try out.print(ctx.allocator, "{d}", .{countSearchResultsOfType(results, kind)});
    }
    try out.appendSlice(ctx.allocator, "}}");
    return out.toOwnedSlice(ctx.allocator);
}

test "api snapshot summary preserves and rejects raw scopes JSON" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    const results = [_]domain.SearchResult{.{
        .id = "mem_1",
        .result_type = "memory_atom",
        .title = "Decision",
        .text = "Decision: snapshot scopes are strict.",
        .scope = "public",
        .status = "verified",
        .score = 1.0,
        .source_ids_json = "[]",
        .required_scopes_json = "[\"public\"]",
    }};

    const summary = try snapshotSummaryJson(&ctx, "[\"public\"]", "memory", results[0..]);
    defer std.testing.allocator.free(summary);
    try std.testing.expect(std.mem.indexOf(u8, summary, "\"scopes\":[\"public\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, summary, "\"object_count\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, summary, "\"memory_atom\":1") != null);

    try std.testing.expectError(error.InvalidRawJson, snapshotSummaryJson(&ctx, "{\"scope\":\"public\"}", "memory", results[0..]));
    try std.testing.expectError(error.InvalidRawJson, snapshotSummaryJson(&ctx, "[\"public\"", "memory", results[0..]));
}

fn countSearchResultsOfType(results: []const domain.SearchResult, result_type: []const u8) usize {
    var count: usize = 0;
    for (results) |result| {
        if (std.mem.eql(u8, result.result_type, result_type)) count += 1;
    }
    return count;
}

fn lifecycleHygiene(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "verify") and !hasCapability(ctx, "delete")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const dedupe_agent_memory = json.boolField(obj, "dedupe_agent_memory") orelse false;
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    defer storage_route.deinit(ctx.allocator);
    const native_agent_memory_dedupe = dedupe_agent_memory and ctx.store.agentMemoryRouteIncludesNative(storage_route);
    const dedupe_limit = lifecycleHygieneDedupeLimit(obj);
    var result = ctx.store.runHygiene(.{
        .stale_after_ms = json.intField(obj, "stale_after_ms") orelse 30 * 24 * 60 * 60 * 1000,
        .archive_after_ms = json.intField(obj, "archive_after_ms") orelse 90 * 24 * 60 * 60 * 1000,
        .purge_after_ms = json.intField(obj, "purge_after_ms") orelse 0,
        .hard_delete = json.boolField(obj, "hard_delete") orelse false,
        .dedupe_memory_atoms = json.boolField(obj, "dedupe_memory_atoms") orelse (json.boolField(obj, "dedupe") orelse false),
        .dedupe_agent_memory = native_agent_memory_dedupe,
        .dedupe_normalized = json.boolField(obj, "dedupe_normalized") orelse true,
        .dedupe_limit = dedupe_limit,
        .actor_id = ctx.actor_id,
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
    }) catch return serverError(ctx);
    if (dedupe_agent_memory) {
        ctx.store.runRoutedAgentMemoryDedupe(ctx.allocator, .{
            .hard_delete = json.boolField(obj, "hard_delete") orelse false,
            .dedupe_normalized = json.boolField(obj, "dedupe_normalized") orelse true,
            .dedupe_limit = dedupe_limit,
            .actor_id = ctx.actor_id,
            .scopes_json = ctx.actor_scopes_json,
            .capabilities_json = ctx.actor_capabilities_json,
        }, storage_route, .{
            .category = json.stringField(obj, "category"),
            .session_id = json.stringField(obj, "session_id") orelse json.stringField(obj, "session"),
            .include_internal = json.boolField(obj, "include_internal") orelse false,
        }, &result) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    }
    const response = std.fmt.allocPrint(
        ctx.allocator,
        "{{\"hygiene\":{{\"checked\":{d},\"marked_stale\":{d},\"archived\":{d},\"purged\":{d},\"expired_cache_entries\":{d},\"dedupe_checked\":{d},\"dedupe_groups\":{d},\"dedupe_deprecated\":{d},\"dedupe_purged\":{d},\"agent_memory_dedupe_checked\":{d},\"agent_memory_dedupe_groups\":{d},\"agent_memory_dedupe_deprecated\":{d},\"agent_memory_dedupe_purged\":{d}}}}}",
        .{ result.checked, result.marked_stale, result.archived, result.purged, result.expired_cache_entries, result.dedupe_checked, result.dedupe_groups, result.dedupe_deprecated, result.dedupe_purged, result.agent_memory_dedupe_checked, result.agent_memory_dedupe_groups, result.agent_memory_dedupe_deprecated, result.agent_memory_dedupe_purged },
    ) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn lifecycleHygieneReport(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const limit = lifecycleHygieneReportLimit(obj);
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_deprecated = json.boolField(obj, "include_deprecated") orelse false;
    const include_agent_memory = json.boolField(obj, "include_agent_memory") orelse true;
    const include_memory_atoms = json.boolField(obj, "include_memory_atoms") orelse true;
    const category = json.stringField(obj, "category");
    const session_id = json.stringField(obj, "session_id") orelse json.stringField(obj, "session");
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);

    var exact_map: std.StringHashMapUnmanaged(usize) = .{};
    defer freeStringCountMap(ctx.allocator, &exact_map);
    var normalized_map: std.StringHashMapUnmanaged(usize) = .{};
    defer freeStringCountMap(ctx.allocator, &normalized_map);

    var agent_scanned: usize = 0;
    var atom_scanned: usize = 0;
    var remaining = limit;

    if (include_agent_memory and remaining > 0) {
        const auth = api_agent_memory_store.contextAuth(ctx);
        const entries = if (session_id) |sid|
            api_agent_memory_store.listByInput(ctx, .{
                .route = storage_route,
                .category = category,
                .session_id = sid,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else
            api_agent_memory_store.listByInput(ctx, .{
                .route = storage_route,
                .category = category,
                .auth = auth,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        defer {
            for (entries) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
            ctx.allocator.free(entries);
        }
        for (entries) |entry| {
            if (remaining == 0) break;
            if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
            tryAddHygieneDedupEntry(ctx.allocator, &exact_map, &normalized_map, .{
                .object_type = "agent_memory",
                .scope = entry.scope,
                .category = entry.category,
                .session_id = entry.session_id,
                .store = if (entry.store.len > 0) entry.store else "native",
                .content = entry.content,
            }) catch return serverError(ctx);
            agent_scanned += 1;
            remaining -= 1;
        }
    }

    if (include_memory_atoms and remaining > 0) {
        const atoms = ctx.store.listMemoryAtomsVisible(ctx.allocator, .{
            .limit = remaining,
            .scopes_json = ctx.actor_scopes_json,
            .actor_id = ctx.actor_id,
            .include_deprecated = include_deprecated,
        }) catch return serverError(ctx);
        defer {
            for (atoms) |*atom| freeHygieneMemoryAtom(ctx.allocator, atom);
            ctx.allocator.free(atoms);
        }
        for (atoms) |atom| {
            tryAddHygieneDedupEntry(ctx.allocator, &exact_map, &normalized_map, .{
                .object_type = "memory_atom",
                .scope = atom.scope,
                .category = atom.predicate,
                .session_id = null,
                .store = "native",
                .content = atom.text,
            }) catch return serverError(ctx);
            atom_scanned += 1;
        }
    }

    const exact = duplicateStats(&exact_map);
    const normalized = duplicateStats(&normalized_map);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"hygiene_report\":{{\"dry_run\":true,\"changes_made\":0,\"limit\":{d},\"scanned_entries\":{d},\"agent_memory_scanned\":{d},\"memory_atoms_scanned\":{d},\"exact_duplicate_groups\":{d},\"exact_duplicate_extra_entries\":{d},\"normalized_duplicate_groups\":{d},\"normalized_duplicate_extra_entries\":{d},\"exact_duplicates\":{{\"groups\":{d},\"extra_entries\":{d}}},\"normalized_duplicates\":{{\"groups\":{d},\"extra_entries\":{d}}},\"include_internal\":{s},\"include_deprecated\":{s},\"storage_route\":", .{ limit, agent_scanned + atom_scanned, agent_scanned, atom_scanned, exact.groups, exact.extra_entries, normalized.groups, normalized.extra_entries, exact.groups, exact.extra_entries, normalized.groups, normalized.extra_entries, if (include_internal) "true" else "false", if (include_deprecated) "true" else "false" }) catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleSummarize(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (lifecycleSummarizeHasProviderOverride(obj)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Provider overrides are not allowed; configure providers on the server");
    }

    const subject_actor_id = lifecycleSummarizeSubjectActorId(ctx, obj) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.BadRequest => return badJson(ctx),
    };
    const messages = lifecycleSummarizeMessages(ctx, obj, subject_actor_id) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.BadRequest => return badJson(ctx),
        error.MissingMessages => return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing messages or session_id"),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const max_chars = lifecycleSummaryMaxChars(obj);
    const selected = lifecycleSummarizeWindow(obj, messages);
    const built_summary = lifecycleBuildSummary(ctx, obj, selected.messages, max_chars) catch |err| switch (err) {
        error.UngroundedLlmSummary => return json.errorResponse(ctx.allocator, 502, "ungrounded_llm_summary", "LLM summarizer response did not cite the supplied messages"),
        error.ProviderUnavailable => return json.errorResponse(ctx.allocator, 502, "provider_unavailable", "LLM summarizer provider is unavailable"),
        else => return serverError(ctx),
    };

    const persist = (json.boolField(obj, "persist") orelse false) or (json.boolField(obj, "remember") orelse false);
    const persisted_entry = if (persist)
        lifecyclePersistSummary(ctx, obj, subject_actor_id, built_summary.text, built_summary.provider, selected.messages_summarized, built_summary.sections_json, built_summary.quality_json, built_summary.profile, built_summary.strategy, built_summary.segment_count) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.BadRequest => return badJson(ctx),
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else
        null;
    const semantic_facts = if (persist)
        lifecyclePersistSemanticFacts(ctx, obj, subject_actor_id, built_summary.text, built_summary.provider) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.BadRequest => return badJson(ctx),
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else
        &[_]domain.AgentMemory{};

    const response_body = lifecycleSummarizeResponseBody(ctx, built_summary, selected, persisted_entry, semantic_facts) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response_body };
}

fn lifecycleSummarizeResponseBody(ctx: *Context, built_summary: LifecycleBuiltSummary, selected: LifecycleSummarizeWindow, persisted_entry: ?domain.AgentMemory, semantic_facts: []const domain.AgentMemory) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);

    try out.appendSlice(ctx.allocator, "{\"summary\":");
    try json.appendString(&out, ctx.allocator, built_summary.text);
    try out.appendSlice(ctx.allocator, ",\"summary_provider\":");
    try json.appendString(&out, ctx.allocator, built_summary.provider);
    try out.appendSlice(ctx.allocator, ",\"profile\":");
    try json.appendString(&out, ctx.allocator, built_summary.profile.name());
    try out.appendSlice(ctx.allocator, ",\"summary_strategy\":");
    try json.appendString(&out, ctx.allocator, built_summary.strategy);
    try out.appendSlice(ctx.allocator, ",\"message_count\":");
    try out.print(ctx.allocator, "{d}", .{built_summary.message_count});
    try out.appendSlice(ctx.allocator, ",\"segment_count\":");
    try out.print(ctx.allocator, "{d}", .{built_summary.segment_count});
    try out.appendSlice(ctx.allocator, ",\"messages_summarized\":");
    try out.print(ctx.allocator, "{d}", .{selected.messages_summarized});
    try out.appendSlice(ctx.allocator, ",\"messages_kept\":");
    try out.print(ctx.allocator, "{d}", .{selected.messages_kept});
    try out.appendSlice(ctx.allocator, ",\"truncated\":");
    try out.appendSlice(ctx.allocator, if (built_summary.truncated) "true" else "false");
    try appendLifecycleSummaryRawObjects(ctx.allocator, &out, built_summary.sections_json, built_summary.quality_json);
    try out.appendSlice(ctx.allocator, ",\"persisted\":");
    try out.appendSlice(ctx.allocator, if (persisted_entry != null) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"semantic_fact_count\":");
    try out.print(ctx.allocator, "{d}", .{semantic_facts.len});
    try out.appendSlice(ctx.allocator, ",\"semantic_facts\":[");
    for (semantic_facts, 0..) |fact, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try appendNullClawAgentMemoryEntry(ctx, &out, fact);
    }
    try out.append(ctx.allocator, ']');
    if (persisted_entry) |entry| {
        try out.appendSlice(ctx.allocator, ",\"memory\":");
        try appendNullClawAgentMemoryEntry(ctx, &out, entry);
    }
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn appendLifecycleSummaryRawObjects(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), sections_json: []const u8, quality_json: []const u8) !void {
    try out.appendSlice(allocator, ",\"sections\":");
    try json.appendRawJsonObject(out, allocator, sections_json);
    try out.appendSlice(allocator, ",\"quality\":");
    try json.appendRawJsonObject(out, allocator, quality_json);
}

const BoundedUsizeOption = struct {
    default_value: usize,
    min_value: usize,
    max_value: usize,
};

const lifecycle_summary_chars_bounds = BoundedUsizeOption{ .default_value = 4000, .min_value = 1, .max_value = 100_000 };
const lifecycle_summary_items_per_section_bounds = BoundedUsizeOption{ .default_value = 8, .min_value = 1, .max_value = 100 };
const lifecycle_summary_window_tokens_bounds = BoundedUsizeOption{ .default_value = 0, .min_value = 0, .max_value = 1_000_000 };
const lifecycle_session_message_limit_bounds = BoundedUsizeOption{ .default_value = 500, .min_value = 1, .max_value = 5000 };
const lifecycle_window_size_tokens_bounds = BoundedUsizeOption{ .default_value = 1, .min_value = 1, .max_value = 1_000_000 };
const lifecycle_lucid_rebuild_limit_bounds = BoundedUsizeOption{ .default_value = 1000, .min_value = 1, .max_value = 5000 };
const lifecycle_hygiene_dedupe_limit_bounds = BoundedUsizeOption{ .default_value = 5000, .min_value = 1, .max_value = 20_000 };
const lifecycle_hygiene_report_limit_bounds = BoundedUsizeOption{ .default_value = 1000, .min_value = 1, .max_value = 5000 };
const agent_session_migration_message_limit_bounds = BoundedUsizeOption{ .default_value = 10_000, .min_value = 1, .max_value = 100_000 };
const compact_session_message_limit_bounds = BoundedUsizeOption{ .default_value = 5000, .min_value = 1, .max_value = 10_000 };
const compact_session_keep_recent_bounds = BoundedUsizeOption{ .default_value = 20, .min_value = 0, .max_value = 1000 };
const compact_session_summary_chars_bounds = BoundedUsizeOption{ .default_value = 2000, .min_value = 1, .max_value = 100_000 };

fn boundedUsizeOption(value: ?i64, bounds: BoundedUsizeOption) usize {
    std.debug.assert(bounds.min_value <= bounds.default_value);
    std.debug.assert(bounds.default_value <= bounds.max_value);
    const raw = value orelse return bounds.default_value;
    if (raw <= bounded_int.usizeToI64Saturating(bounds.min_value)) return bounds.min_value;
    return bounded_int.positiveI64ToUsizeBounded(raw, bounds.max_value);
}

test "api bounded usize option preserves policy and caps request values" {
    const bounds = BoundedUsizeOption{ .default_value = 10, .min_value = 2, .max_value = 50 };
    try std.testing.expectEqual(@as(usize, 10), boundedUsizeOption(null, bounds));
    try std.testing.expectEqual(@as(usize, 2), boundedUsizeOption(-1, bounds));
    try std.testing.expectEqual(@as(usize, 2), boundedUsizeOption(2, bounds));
    try std.testing.expectEqual(@as(usize, 42), boundedUsizeOption(42, bounds));
    try std.testing.expectEqual(@as(usize, 50), boundedUsizeOption(std.math.maxInt(i64), bounds));

    const zero_min = BoundedUsizeOption{ .default_value = 0, .min_value = 0, .max_value = 100 };
    try std.testing.expectEqual(@as(usize, 0), boundedUsizeOption(-1, zero_min));
    try std.testing.expectEqual(@as(usize, 0), boundedUsizeOption(0, zero_min));
}

