}

fn lifecycleHygieneDedupeLimit(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "dedupe_limit"), lifecycle_hygiene_dedupe_limit_bounds);
}

fn lifecycleHygieneReportLimit(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "limit"), lifecycle_hygiene_report_limit_bounds);
}

fn lifecycleSummaryMaxChars(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "max_chars"), lifecycle_summary_chars_bounds);
}

const LifecycleSummarizeWindow = struct {
    messages: []const summarizer.Message,
    messages_summarized: usize,
    messages_kept: usize,
};

const LifecycleBuiltSummary = struct {
    text: []const u8,
    provider: []const u8,
    sections_json: []const u8,
    quality_json: []const u8,
    profile: summarizer.Profile,
    strategy: []const u8,
    message_count: usize,
    segment_count: usize,
    truncated: bool,
};

fn lifecycleBuildSummary(ctx: *Context, obj: std.json.ObjectMap, messages: []const summarizer.Message, max_chars: usize) !LifecycleBuiltSummary {
    const summary_options = lifecycleSummaryOptions(obj, max_chars);
    const summary = try summarizer.summarizeMessages(ctx.allocator, messages, summary_options);
    var summary_text = summary.text;
    var summary_provider = summary.provider;
    var sections_json = summary.sections_json;
    var quality_json = summary.quality_json;
    var strategy = summary.strategy;
    const segment_count = summary.segment_count;
    var truncated = summary.truncated;

    if (json.boolField(obj, "use_llm") orelse false) {
        const prompt = try summarizer.buildLlmPrompt(ctx.allocator, messages, max_chars, summary_options.profile);
        defer ctx.allocator.free(prompt);
        const system =
            "Summarize only the supplied NullPantry messages. Preserve decisions, constraints, risks, action items, open questions, and durable facts. Cite message indexes as [message:N]. Say I don't know when the messages do not support a claim.";
        if (providers.completeWithSystem(ctx.allocator, .{
            .base_url = ctx.provider.completion.base_url,
            .api_key = ctx.provider.completion.api_key,
            .model = ctx.provider.completion.model,
            .timeout_secs = ctx.provider.completion.timeout_secs,
            .max_response_bytes = ctx.provider.completion.max_response_bytes,
            .allow_insecure_http = ctx.provider.completion.allow_insecure_http,
            .runtime = ctx.provider.runtime(),
        }, system, prompt)) |completion_result| {
            var completion = completion_result;
            defer providers.freeCompletionResult(ctx.allocator, &completion);
            const grounded = try summarizer.groundedLlmSummaryAgainstMessages(ctx.allocator, completion.content, max_chars, messages);
            if (grounded) |trimmed| {
                summary_text = trimmed.text;
                summary_provider = completion.provider;
                sections_json = try summarizer.sectionsFromGroundedSummary(ctx.allocator, trimmed.text, messages, summary_options.max_items_per_section);
                strategy = "llm_grounded";
                const grounded_lines = summarizer.countGroundedSummaryLines(trimmed.text, messages.len);
                quality_json = try summarizer.buildQualityJson(ctx.allocator, .{
                    .profile = summary_options.profile,
                    .strategy = strategy,
                    .message_count = messages.len,
                    .segment_count = segment_count,
                    .item_count = grounded_lines,
                    .cited_item_count = grounded_lines,
                    .truncated = trimmed.truncated,
                });
                truncated = trimmed.truncated;
            } else if (json.boolField(obj, "strict_llm") orelse false) {
                return error.UngroundedLlmSummary;
            }
        } else |_| {
            if (json.boolField(obj, "strict_llm") orelse false) {
                return error.ProviderUnavailable;
            }
        }
    }

    return .{
        .text = summary_text,
        .provider = summary_provider,
        .sections_json = sections_json,
        .quality_json = quality_json,
        .profile = summary.profile,
        .strategy = strategy,
        .message_count = summary.message_count,
        .segment_count = segment_count,
        .truncated = truncated,
    };
}

fn lifecycleSummaryOptions(obj: std.json.ObjectMap, max_chars: usize) summarizer.Options {
    const profile = summarizer.Profile.parse(stringFieldAny(obj, &.{ "summary_profile", "profile", "summary_type", "type" }));
    const max_items_per_section = boundedUsizeOption(
        json.intField(obj, "max_items_per_section") orelse json.intField(obj, "summary_max_items_per_section"),
        lifecycle_summary_items_per_section_bounds,
    );
    const map_reduce = (json.boolField(obj, "map_reduce") orelse false) or (json.boolField(obj, "recursive") orelse false);
    var raw_window = json.intField(obj, "summary_window_tokens");
    if (raw_window == null) raw_window = json.intField(obj, "map_reduce_window_tokens");
    if (raw_window == null and map_reduce) {
        raw_window = json.intField(obj, "window_size_tokens");
        if (raw_window == null) raw_window = json.intField(obj, "window_tokens");
    }
    return .{
        .max_chars = max_chars,
        .profile = profile,
        .window_size_tokens = boundedUsizeOption(raw_window, lifecycle_summary_window_tokens_bounds),
        .max_items_per_section = max_items_per_section,
    };
}

const CompactSessionPlan = struct {
    preserve_count: usize,
    summarize_start: usize,
    summarize_end: usize,

    fn messagesSummarized(self: CompactSessionPlan) usize {
        return self.summarize_end - self.summarize_start;
    }

    fn messagesKept(self: CompactSessionPlan, total: usize) usize {
        return total - self.summarize_end;
    }

    fn messagesAfter(self: CompactSessionPlan, total: usize) usize {
        return self.preserve_count + 1 + self.messagesKept(total);
    }
};

const CompactSessionResponse = struct {
    session_id: []const u8,
    actor_id: []const u8,
    compacted: bool,
    message_count_before: usize,
    messages_summarized: usize,
    messages_kept: usize,
    messages_after: usize,
    keep_recent: usize,
    preserved_system_messages: usize,
    summary: ?[]const u8 = null,
    summary_provider: ?[]const u8 = null,
    sections_json: []const u8 = "{}",
    quality_json: []const u8 = "{}",
    profile: summarizer.Profile = .generic,
    strategy: []const u8 = "",
    segment_count: usize = 0,
    truncated: bool = false,
};

fn lifecycleCompactSession(ctx: *Context, path_session_id: ?[]const u8, body: []const u8, route_query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "read") and hasCapability(ctx, "write"))) return forbidden(ctx);
    var parsed = parseBody(ctx, optionalJsonObjectBody(body)) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (lifecycleSummarizeHasProviderOverride(obj)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Provider overrides are not allowed; configure providers on the server");
    }

    const session_id = compactSessionId(path_session_id, obj) catch |err| switch (err) {
        error.BadRequest => return badJson(ctx),
    };
    const subject_actor_id = lifecycleSummarizeSubjectActorId(ctx, obj) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.BadRequest => return badJson(ctx),
    };
    if (!api_session_access.readAllowed(ctx, session_id) or !api_session_access.writeAllowed(ctx, session_id)) return forbidden(ctx);

    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    defer storage_target.deinit(ctx.allocator);
    const message_limit = compactSessionMessageLimit(obj);
    const history = ctx.store.historyRoutedWithAuth(ctx.allocator, session_id, message_limit, 0, subject_actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (history.total > @as(u64, @intCast(history.messages.len))) {
        return json.errorResponse(ctx.allocator, 400, "history_too_large", "Session history exceeds message_limit; retry with a larger limit before compacting");
    }

    const keep_recent = compactSessionKeepRecent(obj);
    const preserve_system = json.boolField(obj, "preserve_system") orelse true;
    const plan = compactSessionPlan(history.messages, keep_recent, preserve_system);
    if (plan == null) {
        return compactSessionResponse(ctx, .{
            .session_id = session_id,
            .actor_id = subject_actor_id,
            .compacted = false,
            .message_count_before = history.messages.len,
            .messages_summarized = 0,
            .messages_kept = history.messages.len,
            .messages_after = history.messages.len,
            .keep_recent = keep_recent,
            .preserved_system_messages = compactSessionPreserveCount(history.messages, preserve_system),
        });
    }

    const active_plan = plan.?;
    const summary_messages = compactSessionSummaryMessages(ctx.allocator, history.messages[active_plan.summarize_start..active_plan.summarize_end]) catch return serverError(ctx);
    const max_chars = compactSessionMaxSummaryChars(obj);
    const built_summary = lifecycleBuildSummary(ctx, obj, summary_messages, max_chars) catch |err| switch (err) {
        error.UngroundedLlmSummary => return json.errorResponse(ctx.allocator, 502, "ungrounded_llm_summary", "LLM summarizer response did not cite the supplied messages"),
        error.ProviderUnavailable => return json.errorResponse(ctx.allocator, 502, "provider_unavailable", "LLM summarizer provider is unavailable"),
        else => return serverError(ctx),
    };
    const summary_content = std.fmt.allocPrint(ctx.allocator, "[Compaction summary]\n{s}", .{built_summary.text}) catch return serverError(ctx);
    const summary_role = json.stringField(obj, "summary_role") orelse "assistant";
    if (summary_role.len == 0 or domain.isRuntimeCommandRole(summary_role)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid summary_role");
    const summary_created_at_ms = history.messages[active_plan.summarize_start].created_at_ms;

    ctx.store.clearMessagesRoutedWithAuth(session_id, subject_actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    for (history.messages[0..active_plan.preserve_count]) |message| {
        ctx.store.saveMessageRoutedAtWithAuth(session_id, message.role, message.content, message.created_at_ms, subject_actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    }
    ctx.store.saveMessageRoutedAtWithAuth(session_id, summary_role, summary_content, summary_created_at_ms, subject_actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    for (history.messages[active_plan.summarize_end..]) |message| {
        ctx.store.saveMessageRoutedAtWithAuth(session_id, message.role, message.content, message.created_at_ms, subject_actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    }

    return compactSessionResponse(ctx, .{
        .session_id = session_id,
        .actor_id = subject_actor_id,
        .compacted = true,
        .message_count_before = history.messages.len,
        .messages_summarized = active_plan.messagesSummarized(),
        .messages_kept = active_plan.messagesKept(history.messages.len),
        .messages_after = active_plan.messagesAfter(history.messages.len),
        .keep_recent = keep_recent,
        .preserved_system_messages = active_plan.preserve_count,
        .summary = built_summary.text,
        .summary_provider = built_summary.provider,
        .sections_json = built_summary.sections_json,
        .quality_json = built_summary.quality_json,
        .profile = built_summary.profile,
        .strategy = built_summary.strategy,
        .segment_count = built_summary.segment_count,
        .truncated = built_summary.truncated,
    });
}

fn compactSessionId(path_session_id: ?[]const u8, obj: std.json.ObjectMap) ![]const u8 {
    const body_session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
    if (path_session_id) |path_id| {
        if (body_session_id) |body_id| {
            if (!std.mem.eql(u8, path_id, body_id)) return error.BadRequest;
        }
        if (path_id.len == 0) return error.BadRequest;
        return path_id;
    }
    const session_id = body_session_id orelse return error.BadRequest;
    if (session_id.len == 0) return error.BadRequest;
    return session_id;
}

fn compactSessionMessageLimit(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "message_limit") orelse json.intField(obj, "limit"), compact_session_message_limit_bounds);
}

fn compactSessionKeepRecent(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "keep_recent") orelse json.intField(obj, "compaction_keep_recent"), compact_session_keep_recent_bounds);
}

fn compactSessionMaxSummaryChars(obj: std.json.ObjectMap) usize {
    return boundedUsizeOption(json.intField(obj, "max_chars") orelse json.intField(obj, "compaction_max_summary_chars"), compact_session_summary_chars_bounds);
}

fn compactSessionPlan(messages: []const store_mod.Message, keep_recent: usize, preserve_system: bool) ?CompactSessionPlan {
    const preserve_count = compactSessionPreserveCount(messages, preserve_system);
    if (messages.len <= preserve_count) return null;
    const compactable = messages.len - preserve_count;
    const requested_keep = @min(keep_recent, compactable);
    var summarize_end = preserve_count + (compactable - requested_keep);
    if (summarize_end == preserve_count) return null;
    summarize_end = compactSessionAdjustedSummarizeEnd(messages, preserve_count, summarize_end);
    if (summarize_end == preserve_count) return null;
    return .{
        .preserve_count = preserve_count,
        .summarize_start = preserve_count,
        .summarize_end = summarize_end,
    };
}

fn compactSessionPreserveCount(messages: []const store_mod.Message, preserve_system: bool) usize {
    if (!preserve_system) return 0;
    var count: usize = 0;
    while (count < messages.len and std.mem.eql(u8, messages[count].role, "system")) : (count += 1) {}
    return count;
}

fn compactSessionAdjustedSummarizeEnd(messages: []const store_mod.Message, start: usize, proposed_end: usize) usize {
    var adjusted = proposed_end;
    while (adjusted > start and adjusted < messages.len and std.mem.eql(u8, messages[adjusted].role, "tool")) {
        adjusted -= 1;
    }
    return adjusted;
}

fn compactSessionSummaryMessages(allocator: std.mem.Allocator, messages: []const store_mod.Message) ![]summarizer.Message {
    var out: std.ArrayListUnmanaged(summarizer.Message) = .empty;
    errdefer out.deinit(allocator);
    for (messages) |message| {
        try out.append(allocator, .{
            .role = message.role,
            .content = message.content,
        });
    }
    return out.toOwnedSlice(allocator);
}

fn compactSessionResponse(ctx: *Context, input: CompactSessionResponse) HttpResponse {
    const body = compactSessionResponseBody(ctx, input) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn compactSessionResponseBody(ctx: *Context, input: CompactSessionResponse) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);

    try out.appendSlice(ctx.allocator, "{\"session_id\":");
    try json.appendString(&out, ctx.allocator, input.session_id);
    try out.appendSlice(ctx.allocator, ",\"actor_id\":");
    try json.appendString(&out, ctx.allocator, input.actor_id);
    try out.appendSlice(ctx.allocator, ",\"compacted\":");
    try out.appendSlice(ctx.allocator, if (input.compacted) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"message_count_before\":");
    try out.print(ctx.allocator, "{d}", .{input.message_count_before});
    try out.appendSlice(ctx.allocator, ",\"messages_summarized\":");
    try out.print(ctx.allocator, "{d}", .{input.messages_summarized});
    try out.appendSlice(ctx.allocator, ",\"messages_kept\":");
    try out.print(ctx.allocator, "{d}", .{input.messages_kept});
    try out.appendSlice(ctx.allocator, ",\"messages_after\":");
    try out.print(ctx.allocator, "{d}", .{input.messages_after});
    try out.appendSlice(ctx.allocator, ",\"keep_recent\":");
    try out.print(ctx.allocator, "{d}", .{input.keep_recent});
    try out.appendSlice(ctx.allocator, ",\"preserved_system_messages\":");
    try out.print(ctx.allocator, "{d}", .{input.preserved_system_messages});
    try out.appendSlice(ctx.allocator, ",\"summary\":");
    try json.appendNullableString(&out, ctx.allocator, input.summary);
    try out.appendSlice(ctx.allocator, ",\"summary_provider\":");
    try json.appendNullableString(&out, ctx.allocator, input.summary_provider);
    try out.appendSlice(ctx.allocator, ",\"profile\":");
    try json.appendString(&out, ctx.allocator, input.profile.name());
    try out.appendSlice(ctx.allocator, ",\"summary_strategy\":");
    try json.appendString(&out, ctx.allocator, input.strategy);
    try out.appendSlice(ctx.allocator, ",\"segment_count\":");
    try out.print(ctx.allocator, "{d}", .{input.segment_count});
    try out.appendSlice(ctx.allocator, ",\"truncated\":");
    try out.appendSlice(ctx.allocator, if (input.truncated) "true" else "false");
    try appendLifecycleSummaryRawObjects(ctx.allocator, &out, input.sections_json, input.quality_json);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn lifecycleSummarizeHasProviderOverride(obj: std.json.ObjectMap) bool {
    return obj.get("llm_base_url") != null or
        obj.get("llm_api_key") != null or
        obj.get("llm_model") != null or
        obj.get("timeout_secs") != null or
        obj.get("llm_allow_insecure_http") != null or
        obj.get("allow_insecure_http") != null;
}

fn lifecycleSummarizeSubjectActorId(ctx: *Context, obj: std.json.ObjectMap) ![]const u8 {
    const requested = json.stringField(obj, "target_actor_id") orelse
        json.stringField(obj, "subject_actor_id") orelse
        json.stringField(obj, "actor_id");
    const actor = requested orelse ctx.actor_id;
    if (actor.len == 0) return error.BadRequest;
    if (requested != null and !domain.hasActorScope(ctx.actor_scopes_json, "admin") and !std.mem.eql(u8, actor, ctx.actor_id)) return error.Forbidden;
    return actor;
}

fn lifecycleSummarizeMessages(ctx: *Context, obj: std.json.ObjectMap, subject_actor_id: []const u8) ![]summarizer.Message {
    var messages: std.ArrayListUnmanaged(summarizer.Message) = .empty;
    errdefer messages.deinit(ctx.allocator);

    if (obj.get("messages")) |messages_value| {
        if (messages_value != .array) return error.BadRequest;
        for (messages_value.array.items) |item| {
            switch (item) {
                .string => |content| try messages.append(ctx.allocator, .{ .content = content }),
                .object => |message_obj| if (json.stringField(message_obj, "content")) |content| {
                    try messages.append(ctx.allocator, .{
                        .role = sessionMessageRoleField(message_obj) orelse "",
                        .speaker = json.stringField(message_obj, "speaker") orelse json.stringField(message_obj, "author") orelse "",
                        .content = content,
                    });
                },
                else => {},
            }
        }
        return try messages.toOwnedSlice(ctx.allocator);
    }

    const session_id = nullableStringFieldAlias(obj, "session_id", "session") orelse return error.MissingMessages;
    if (!api_session_access.readAllowed(ctx, session_id)) return error.Forbidden;
    const message_limit = boundedUsizeOption(json.intField(obj, "message_limit") orelse json.intField(obj, "limit"), lifecycle_session_message_limit_bounds);
    const storage_target = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, "");
    defer storage_target.deinit(ctx.allocator);
    const history = try ctx.store.historyRoutedWithAuth(ctx.allocator, session_id, message_limit, 0, subject_actor_id, ctx.actor_capabilities_json, storage_target);
    for (history.messages) |message| {
        try messages.append(ctx.allocator, .{
            .role = message.role,
            .content = message.content,
        });
    }
    return try messages.toOwnedSlice(ctx.allocator);
}

fn lifecycleSummarizeWindow(obj: std.json.ObjectMap, messages: []const summarizer.Message) LifecycleSummarizeWindow {
    const window_size = lifecycleSummarizeWindowSize(obj) orelse return lifecycleFullSummarizeWindow(messages);
    if (!summarizer.shouldSummarize(messages, window_size)) {
        return lifecycleFullSummarizeWindow(messages);
    }
    const partition = summarizer.partitionMessages(messages, window_size);
    if (partition.to_summarize == 0) return lifecycleFullSummarizeWindow(messages);
    return .{
        .messages = messages[0..partition.to_summarize],
        .messages_summarized = partition.to_summarize,
        .messages_kept = partition.to_keep,
    };
}

fn lifecycleSummarizeWindowSize(obj: std.json.ObjectMap) ?usize {
    const raw = json.intField(obj, "window_size_tokens") orelse json.intField(obj, "window_tokens");
    return boundedUsizeOption(raw orelse return null, lifecycle_window_size_tokens_bounds);
}

fn lifecycleFullSummarizeWindow(messages: []const summarizer.Message) LifecycleSummarizeWindow {
    return .{
        .messages = messages,
        .messages_summarized = messages.len,
        .messages_kept = 0,
    };
}

test "api lifecycle summary numeric options clamp request controlled bounds" {
    const allocator = std.testing.allocator;

    var empty = try std.json.parseFromSlice(std.json.Value, allocator, "{}", .{});
    defer empty.deinit();
    try std.testing.expectEqual(lifecycle_summary_chars_bounds.default_value, lifecycleSummaryMaxChars(empty.value.object));
    const default_options = lifecycleSummaryOptions(empty.value.object, lifecycleSummaryMaxChars(empty.value.object));
    try std.testing.expectEqual(lifecycle_summary_items_per_section_bounds.default_value, default_options.max_items_per_section);
    try std.testing.expectEqual(lifecycle_summary_window_tokens_bounds.default_value, default_options.window_size_tokens);
    try std.testing.expect(lifecycleSummarizeWindowSize(empty.value.object) == null);

    var huge = try std.json.parseFromSlice(
        std.json.Value,
        allocator,
        "{\"max_chars\":9223372036854775807,\"max_items_per_section\":9223372036854775807,\"summary_window_tokens\":9223372036854775807,\"window_size_tokens\":9223372036854775807}",
        .{},
    );
    defer huge.deinit();
    const huge_max_chars = lifecycleSummaryMaxChars(huge.value.object);
    const huge_options = lifecycleSummaryOptions(huge.value.object, huge_max_chars);
    try std.testing.expectEqual(lifecycle_summary_chars_bounds.max_value, huge_max_chars);
    try std.testing.expectEqual(lifecycle_summary_items_per_section_bounds.max_value, huge_options.max_items_per_section);
    try std.testing.expectEqual(lifecycle_summary_window_tokens_bounds.max_value, huge_options.window_size_tokens);
    try std.testing.expectEqual(lifecycle_window_size_tokens_bounds.max_value, lifecycleSummarizeWindowSize(huge.value.object).?);

    var low = try std.json.parseFromSlice(std.json.Value, allocator, "{\"max_chars\":0,\"max_items_per_section\":-5,\"summary_window_tokens\":-10,\"window_size_tokens\":0}", .{});
    defer low.deinit();
    const low_max_chars = lifecycleSummaryMaxChars(low.value.object);
    const low_options = lifecycleSummaryOptions(low.value.object, low_max_chars);
    try std.testing.expectEqual(lifecycle_summary_chars_bounds.min_value, low_max_chars);
    try std.testing.expectEqual(lifecycle_summary_items_per_section_bounds.min_value, low_options.max_items_per_section);
    try std.testing.expectEqual(lifecycle_summary_window_tokens_bounds.min_value, low_options.window_size_tokens);
    try std.testing.expectEqual(lifecycle_window_size_tokens_bounds.min_value, lifecycleSummarizeWindowSize(low.value.object).?);
}

test "api lifecycle summarize rejects malformed permissions roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:summary-raw-roots",
        .actor_scopes_json = "[\"public\",\"write:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\"]",
    };

    const bad_permissions = handleRequest(&ctx, "POST", "/v1/lifecycle/summarize", "{\"messages\":[\"Decision: malformed summary permissions\"],\"persist\":true,\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"},\"key\":\"summary.raw\",\"auto_extract_semantic\":false}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_permissions.status);

    const missing_summary = handleRequest(&ctx, "GET", "/v1/agent-memory/summary.raw?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_summary.status);

    const accepted = handleRequest(&ctx, "POST", "/v1/lifecycle/summarize", "{\"messages\":[\"Decision: shaped summary permissions\"],\"persist\":true,\"scope\":\"public\",\"permissions\":[],\"key\":\"summary.raw\",\"auto_extract_semantic\":false}", "");
    try std.testing.expectEqualStrings("200 OK", accepted.status);
    try std.testing.expect(std.mem.indexOf(u8, accepted.body, "\"persisted\":true") != null);
}

