fn lifecyclePersistSummary(
    ctx: *Context,
    obj: std.json.ObjectMap,
    subject_actor_id: []const u8,
    summary_text: []const u8,
    summary_provider: []const u8,
    message_count: usize,
    sections_json: []const u8,
    quality_json: []const u8,
    profile: summarizer.Profile,
    strategy: []const u8,
    segment_count: usize,
) !domain.AgentMemory {
    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return error.Forbidden;
    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }

    const scope = json.nullableStringField(obj, "scope");
    const permissions = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch return error.BadRequest;
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = summary_text, .scope = requested_scope, .permissions_json = permissions, .created_by = "agent", .actor_id = subject_actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }

    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, "") catch return error.BadRequest;
    defer storage_target.deinit(ctx.allocator);

    var owned_key: ?[]u8 = null;
    defer if (owned_key) |value| ctx.allocator.free(value);
    const key = json.stringField(obj, "key") orelse
        json.stringField(obj, "memory_key") orelse
        json.stringField(obj, "summary_key") orelse blk: {
        if (session_id) |sid| {
            owned_key = try std.fmt.allocPrint(ctx.allocator, "summary.session.{s}", .{sid});
        } else {
            owned_key = try ids.make(ctx.allocator, "summary.");
        }
        break :blk owned_key.?;
    };

    const metadata_json = try lifecycleSummaryMetadataJson(ctx.allocator, summary_provider, message_count, sections_json, quality_json, profile, strategy, segment_count);
    defer ctx.allocator.free(metadata_json);

    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, subject_actor_id, scope) catch return error.BadRequest;
    defer ctx.allocator.free(owner_actor_id);

    return ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
        .key = key,
        .content = summary_text,
        .category = json.stringField(obj, "category") orelse "summary",
        .session_id = session_id,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = metadata_json,
        .actor_id = owner_actor_id,
        .writer_actor_id = ctx.actor_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
    }, storage_target);
}

fn lifecyclePersistSemanticFacts(ctx: *Context, obj: std.json.ObjectMap, subject_actor_id: []const u8, summary_text: []const u8, summary_provider: []const u8) ![]const domain.AgentMemory {
    if (!summarizeAutoExtractSemantic(obj)) return &[_]domain.AgentMemory{};
    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return error.Forbidden;

    const facts = try summarizer.extractSemanticFacts(ctx.allocator, summary_text, "fact.");
    if (facts.len == 0) return &[_]domain.AgentMemory{};

    const scope = json.nullableStringField(obj, "scope");
    const permissions = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch return error.BadRequest;
    if (nullableStringFieldAlias(obj, "session_id", "session")) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return error.Forbidden;
    }
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = summary_text, .scope = requested_scope, .permissions_json = permissions, .created_by = "agent", .actor_id = subject_actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }

    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, "") catch return error.BadRequest;
    defer storage_target.deinit(ctx.allocator);

    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, subject_actor_id, scope) catch return error.BadRequest;
    defer ctx.allocator.free(owner_actor_id);
    const key_prefix = try lifecycleSemanticFactKeyPrefix(ctx.allocator, obj);
    defer ctx.allocator.free(key_prefix);

    var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer out.deinit(ctx.allocator);
    for (facts, 0..) |fact, i| {
        const key = try std.fmt.allocPrint(ctx.allocator, "{s}{d}", .{ key_prefix, i });
        const metadata_json = try lifecycleSemanticFactMetadataJson(ctx.allocator, summary_provider, i);
        const entry = try ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
            .key = key,
            .content = fact.content,
            .category = json.stringField(obj, "semantic_fact_category") orelse json.stringField(obj, "fact_category") orelse "core",
            .session_id = null,
            .scope = scope,
            .permissions_json = permissions,
            .metadata_json = metadata_json,
            .actor_id = owner_actor_id,
            .writer_actor_id = ctx.actor_id,
            .actor_scopes_json = ctx.actor_scopes_json,
            .actor_capabilities_json = ctx.actor_capabilities_json,
        }, storage_target);
        try out.append(ctx.allocator, entry);
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn summarizeAutoExtractSemantic(obj: std.json.ObjectMap) bool {
    if (json.boolField(obj, "extract_semantic_facts")) |value| return value;
    if (json.boolField(obj, "auto_extract_semantic")) |value| return value;
    return true;
}

fn lifecycleSemanticFactKeyPrefix(allocator: std.mem.Allocator, obj: std.json.ObjectMap) ![]const u8 {
    if (json.stringField(obj, "semantic_fact_key_prefix")) |prefix| return allocator.dupe(u8, prefix);
    if (json.stringField(obj, "fact_key_prefix")) |prefix| return allocator.dupe(u8, prefix);
    if (json.stringField(obj, "key") orelse json.stringField(obj, "memory_key") orelse json.stringField(obj, "summary_key")) |summary_key| {
        return std.fmt.allocPrint(allocator, "{s}.fact.", .{summary_key});
    }
    if (nullableStringFieldAlias(obj, "session_id", "session")) |sid| {
        return std.fmt.allocPrint(allocator, "summary.session.{s}.fact.", .{sid});
    }
    return ids.make(allocator, "summary.fact.");
}

fn lifecycleSemanticFactMetadataJson(allocator: std.mem.Allocator, summary_provider: []const u8, index: usize) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"summary_provider\":");
    try json.appendString(&out, allocator, summary_provider);
    try out.appendSlice(allocator, ",\"semantic_fact_index\":");
    try out.print(allocator, "{d}", .{index});
    try out.appendSlice(allocator, ",\"extracted_from\":\"summary\"}");
    return out.toOwnedSlice(allocator);
}

fn lifecycleSummaryMetadataJson(
    allocator: std.mem.Allocator,
    summary_provider: []const u8,
    message_count: usize,
    sections_json: []const u8,
    quality_json: []const u8,
    profile: summarizer.Profile,
    strategy: []const u8,
    segment_count: usize,
) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"summary_provider\":");
    try json.appendString(&out, allocator, summary_provider);
    try out.appendSlice(allocator, ",\"profile\":");
    try json.appendString(&out, allocator, profile.name());
    try out.appendSlice(allocator, ",\"summary_strategy\":");
    try json.appendString(&out, allocator, strategy);
    try out.appendSlice(allocator, ",\"message_count\":");
    try out.print(allocator, "{d}", .{message_count});
    try out.appendSlice(allocator, ",\"segment_count\":");
    try out.print(allocator, "{d}", .{segment_count});
    try out.appendSlice(allocator, ",\"quality\":");
    try json.appendRawJsonObject(&out, allocator, quality_json);
    try out.appendSlice(allocator, ",\"sections\":");
    try json.appendRawJsonObject(&out, allocator, sections_json);
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn lifecycleRollout(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const policy_name = stringFieldAny(obj, &.{ "policy_name", "rollout_policy", "rollout_policy_name" });
    const record = if (policy_name) |name| loadRolloutPolicyRecord(ctx, name) catch return serverError(ctx) else null;
    if (policy_name != null and record == null) return rolloutPolicyNotFound(ctx);
    const feature = json.stringField(obj, "feature") orelse if (record) |r| r.feature else json.stringField(obj, "name") orelse "memory";
    const key = json.stringField(obj, "key") orelse json.stringField(obj, "rollout_key") orelse feature;
    const session_id = json.nullableStringField(obj, "session_id");
    const base = if (record) |r| r.policy else blk: {
        var policy = rolloutPolicyBase(feature);
        policy.shadow_percent = 100;
        break :blk policy;
    };
    const policy = rolloutPolicyFromObject(ctx, obj, base) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        else => return serverError(ctx),
    };
    const result = lifecycle.evaluateRollout(policy, .{
        .key = key,
        .actor_id = ctx.actor_id,
        .session_id = session_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
    });
    const policy_artifact_id = if (record) |r| r.artifact.id else null;
    auditRolloutDecision(ctx, policy_artifact_id orelse feature, feature, key, session_id, policy, result, if (policy_artifact_id != null) "named_policy" else "ad_hoc") catch return serverError(ctx);
    return rolloutDecisionResponse(ctx, feature, key, session_id, policy, result, policy_artifact_id);
}

fn clampPercent(value: i64) u8 {
    return @intCast(@max(@as(i64, 0), @min(@as(i64, 100), value)));
}

fn ask(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (obj.get("llm_base_url") != null or obj.get("llm_api_key") != null or obj.get("llm_model") != null or obj.get("timeout_secs") != null or obj.get("llm_allow_insecure_http") != null or obj.get("allow_insecure_http") != null) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Provider overrides are not allowed; configure providers on the server");
    }
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "question") orelse "";
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    var input = buildSearchInput(ctx, obj, query, searchLimit(json.intField(obj, "limit"), 6), false, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    input.scopes_json = scopes_json;
    const include_conflicts = json.boolField(obj, "include_conflicts") orelse true;
    const scan_conflicts = json.boolField(obj, "scan_conflicts") orelse false;
    if (scan_conflicts and !hasCapability(ctx, "verify") and !hasCapability(ctx, "write")) return forbidden(ctx);
    const use_cache = json.boolField(obj, "use_cache") orelse true;
    const use_semantic_cache = json.boolField(obj, "use_semantic_cache") orelse false;
    const use_llm = json.boolField(obj, "use_llm") orelse false;
    const cache_ttl_ms = json.intField(obj, "cache_ttl_ms") orelse 0;
    const cache_key = api_cache_keys.responseKey(ctx, "ask", body, input) catch return serverError(ctx);
    const semantic_embedding = if (use_semantic_cache) api_cache.optionalSemanticEmbedding(ctx, obj, query) else null;
    const semantic_cache_graph_salt = if (use_semantic_cache)
        graphSemanticCacheSalt(ctx, obj, query) catch |err| switch (err) {
            error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
            else => return serverError(ctx),
        }
    else
        null;
    const semantic_cache_prefix = if (use_semantic_cache) blk: {
        var semantic_input = input;
        if (semantic_embedding) |embedding| {
            semantic_input.query_embedding_provider = embedding.provider;
            semantic_input.embedding_dimensions = embedding.dimensions;
        }
        break :blk api_cache_keys.semanticPrefix(ctx, "ask", semantic_input, include_conflicts, use_llm, semantic_cache_graph_salt.?) catch return serverError(ctx);
    } else null;
    if (use_cache and !scan_conflicts) {
        if (ctx.store.getResponseCacheForScopes(ctx.allocator, cache_key, ids.nowMs(), scopes_json, ctx.actor_id) catch return serverError(ctx)) |hit| {
            return .{ .status = "200 OK", .body = hit.response_json };
        }
        if (use_semantic_cache) {
            if (semantic_embedding) |embedding| {
                if (ctx.store.searchSemanticCache(ctx.allocator, .{
                    .embedding_json = embedding.embedding_json,
                    .embedding_provider = embedding.provider,
                    .embedding_model = embedding.model,
                    .embedding_dimensions = embedding.dimensions,
                    .scopes_json = scopes_json,
                    .actor_id = ctx.actor_id,
                    .cache_key_prefix = semantic_cache_prefix,
                    .min_score = @floatCast(json.floatField(obj, "semantic_cache_min_score") orelse 0.94),
                    .candidate_limit = api_cache.semanticCacheCandidateLimit(obj, "semantic_cache_candidate_limit"),
                }) catch return serverError(ctx)) |hit| {
                    return .{ .status = "200 OK", .body = hit.response_json };
                }
            }
        }
    }
    const pipeline = runSearchPipeline(ctx, obj, query, input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const results = pipeline.results;
    const conflicts = if (include_conflicts)
        (if (scan_conflicts)
            ctx.store.scanConflicts(ctx.allocator, .{ .scopes_json = scopes_json, .status = "open", .limit = 10 }) catch return serverError(ctx)
        else
            ctx.store.listConflicts(ctx.allocator, .{ .scopes_json = scopes_json, .status = "open", .limit = 10 }) catch return serverError(ctx))
    else
        ctx.allocator.alloc(store_mod.KnowledgeConflict, 0) catch return serverError(ctx);

    var answer: std.ArrayListUnmanaged(u8) = .empty;
    var answer_provider: []const u8 = "extractive";
    if (results.len == 0) {
        if (conflicts.len == 0) {
            answer.appendSlice(ctx.allocator, "I don't know based on the accessible NullPantry knowledge.") catch return serverError(ctx);
        } else {
            answer.appendSlice(ctx.allocator, "Accessible NullPantry knowledge contains potential conflicts: ") catch return serverError(ctx);
            for (conflicts, 0..) |conflict, i| {
                if (i > 0) answer.appendSlice(ctx.allocator, " ") catch return serverError(ctx);
                answer.appendSlice(ctx.allocator, conflict.summary) catch return serverError(ctx);
                answer.appendSlice(ctx.allocator, " [") catch return serverError(ctx);
                answer.appendSlice(ctx.allocator, conflict.id) catch return serverError(ctx);
                answer.appendSlice(ctx.allocator, "]") catch return serverError(ctx);
            }
        }
    } else {
        if (use_llm) {
            const prompt = buildAskPrompt(ctx, query, results) catch return serverError(ctx);
            defer ctx.allocator.free(prompt);
            if (providers.completeAnswer(ctx.allocator, .{
                .base_url = ctx.provider.completion.base_url,
                .api_key = ctx.provider.completion.api_key,
                .model = ctx.provider.completion.model,
                .timeout_secs = ctx.provider.completion.timeout_secs,
                .max_response_bytes = ctx.provider.completion.max_response_bytes,
                .allow_insecure_http = ctx.provider.completion.allow_insecure_http,
                .runtime = ctx.provider.runtime(),
            }, prompt)) |completion| {
                var owned_completion = completion;
                defer providers.freeCompletionResult(ctx.allocator, &owned_completion);
                if (answerCitationsValid(ctx, completion.content, results) catch false) {
                    answer_provider = completion.provider;
                    answer.appendSlice(ctx.allocator, completion.content) catch return serverError(ctx);
                } else {
                    answer_provider = "extractive_citation_guard";
                    writeExtractiveAnswer(ctx, &answer, results) catch return serverError(ctx);
                }
            } else |_| {
                writeExtractiveAnswer(ctx, &answer, results) catch return serverError(ctx);
            }
        } else {
            writeExtractiveAnswer(ctx, &answer, results) catch return serverError(ctx);
        }
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"answer\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, answer.items) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"answer_provider\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, answer_provider) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"confidence\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (results.len == 0 and conflicts.len == 0) "0" else if (results.len == 0) "0.3" else "0.7") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"warnings\":") catch return serverError(ctx);
    appendAskWarnings(ctx, &out, results, conflicts) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"results\":") catch return serverError(ctx);
    appendSearchArray(ctx, &out, results) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"conflicts\":") catch return serverError(ctx);
    appendConflictsArray(ctx, &out, conflicts) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    const response_body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx);
    if (cache_ttl_ms > 0 and hasCapability(ctx, "write") and !scan_conflicts) {
        ctx.store.putResponseCache(.{ .cache_key = cache_key, .response_json = response_body, .scopes_json = scopes_json, .actor_id = ctx.actor_id, .ttl_ms = cache_ttl_ms, .token_count = api_cache.estimateTokenCount(response_body), .max_entries = api_cache.maxEntries(obj, "cache_max_entries") }) catch return serverError(ctx);
        if (use_semantic_cache) {
            if (semantic_embedding) |embedding| {
                const semantic_cache_key = if (semantic_cache_prefix) |prefix|
                    std.fmt.allocPrint(ctx.allocator, "{s}{s}", .{ prefix, cache_key }) catch return serverError(ctx)
                else
                    cache_key;
                ctx.store.putSemanticCache(.{
                    .cache_key = semantic_cache_key,
                    .query = query,
                    .response_json = response_body,
                    .embedding_json = embedding.embedding_json,
                    .embedding_provider = embedding.provider,
                    .embedding_model = embedding.model,
                    .embedding_dimensions = embedding.dimensions,
                    .scopes_json = scopes_json,
                    .actor_id = ctx.actor_id,
                    .ttl_ms = cache_ttl_ms,
                    .token_count = api_cache.estimateTokenCount(response_body),
                    .max_entries = api_cache.maxEntries(obj, "cache_max_entries"),
                }) catch return serverError(ctx);
            }
        }
    }
    return .{ .status = "200 OK", .body = response_body };
}

fn writeExtractiveAnswer(ctx: *Context, out: *std.ArrayListUnmanaged(u8), results: []domain.SearchResult) !void {
    try out.appendSlice(ctx.allocator, "Based on accessible NullPantry evidence: ");
    for (results, 0..) |result, i| {
        if (i > 0) try out.appendSlice(ctx.allocator, " ");
        try appendResultStorePrefix(ctx, out, result);
        try out.appendSlice(ctx.allocator, result.text);
        try out.appendSlice(ctx.allocator, " [");
        const label = try citationLabel(ctx, result);
        defer ctx.allocator.free(label);
        try out.appendSlice(ctx.allocator, label);
        try out.appendSlice(ctx.allocator, "]");
    }
}

fn appendResultStorePrefix(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult) !void {
    if (result.store.len == 0) return;
    try out.appendSlice(ctx.allocator, "[store:");
    try out.appendSlice(ctx.allocator, result.store);
    try out.appendSlice(ctx.allocator, "] ");
}

fn buildAskPrompt(ctx: *Context, query: []const u8, results: []const domain.SearchResult) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    var redactor = redaction.Redactor.init(ctx.allocator, .{});
    defer redactor.deinit();
    const safe_query = try redactor.redact(ctx.allocator, query);
    defer ctx.allocator.free(safe_query);
    try out.appendSlice(ctx.allocator, "Question:\n");
    try out.appendSlice(ctx.allocator, safe_query);
    try out.appendSlice(ctx.allocator, "\n\nAccessible context with citations:\n");
    for (results) |result| {
        const safe_status = try redactor.redact(ctx.allocator, result.status);
        defer ctx.allocator.free(safe_status);
        const safe_store = try redactor.redact(ctx.allocator, result.store);
        defer ctx.allocator.free(safe_store);
        const safe_title = try redactor.redact(ctx.allocator, result.title);
        defer ctx.allocator.free(safe_title);
        const safe_text = try redactor.redact(ctx.allocator, result.text);
        defer ctx.allocator.free(safe_text);
        try out.appendSlice(ctx.allocator, "- [");
        const label = try citationLabel(ctx, result);
        defer ctx.allocator.free(label);
        try out.appendSlice(ctx.allocator, label);
        try out.appendSlice(ctx.allocator, "] ");
        try out.appendSlice(ctx.allocator, result.result_type);
        try out.appendSlice(ctx.allocator, " status=");
        try out.appendSlice(ctx.allocator, safe_status);
        if (safe_store.len > 0) {
            try out.appendSlice(ctx.allocator, " store=");
            try out.appendSlice(ctx.allocator, safe_store);
        }
        try out.appendSlice(ctx.allocator, " title=");
        try out.appendSlice(ctx.allocator, safe_title);
        try out.appendSlice(ctx.allocator, "\n  ");
        try out.appendSlice(ctx.allocator, safe_text);
        try out.appendSlice(ctx.allocator, "\n");
    }
    try out.appendSlice(ctx.allocator, "\nAnswer only from accessible context. Every substantive answer line must include one or more citations in square brackets. Use I don't know when evidence is insufficient.");
    return out.toOwnedSlice(ctx.allocator);
}

const LlmRerankOutcome = struct {
    results: []domain.SearchResult,
    attempted: bool,
    applied: bool,
};

fn maybeLlmRerankResults(ctx: *Context, query: []const u8, results: []domain.SearchResult, input: store_mod.SearchInput) !LlmRerankOutcome {
    if (!input.allow_reranker or results.len <= 1 or ctx.provider.completion.base_url == null or ctx.provider.completion.model == null) {
        return .{ .results = results, .attempted = false, .applied = false };
    }
    const prompt = try llm_reranker.buildSearchResultRerankPrompt(ctx.allocator, query, results, input.rerank_candidate_limit);
    defer ctx.allocator.free(prompt);
    var completion = providers.completeWithSystem(
        ctx.allocator,
        .{
            .base_url = ctx.provider.completion.base_url,
            .api_key = ctx.provider.completion.api_key,
            .model = ctx.provider.completion.model,
            .timeout_secs = ctx.provider.completion.timeout_secs,
            .max_response_bytes = ctx.provider.completion.max_response_bytes,
            .allow_insecure_http = ctx.provider.completion.allow_insecure_http,
            .runtime = ctx.provider.runtime(),
        },
        "You are a retrieval reranker. Return only valid JSON using one of these schemas: [\"candidate_id\"] or {\"ranked_ids\":[\"candidate_id\"]}. Do not include explanations.",
        prompt,
    ) catch |err| {
        if (input.strict_reranker) return err;
        return .{ .results = results, .attempted = true, .applied = false };
    };
    defer providers.freeCompletionResult(ctx.allocator, &completion);
    const reranked = llm_reranker.rerankSearchResultsDetailed(ctx.allocator, completion.content, results) catch |err| {
        if (input.strict_reranker) return err;
        return .{ .results = results, .attempted = true, .applied = false };
    };
    return .{ .results = reranked.results, .attempted = true, .applied = reranked.applied };
}

fn citationLabel(ctx: *Context, result: domain.SearchResult) ![]const u8 {
    const parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, result.source_ids_json, .{}) catch return try ctx.allocator.dupe(u8, result.id);
    defer parsed.deinit();
    if (parsed.value != .array) return try ctx.allocator.dupe(u8, result.id);
    for (parsed.value.array.items) |item| {
        if (item == .string and item.string.len > 0) return try ctx.allocator.dupe(u8, item.string);
    }
    return try ctx.allocator.dupe(u8, result.id);
}

fn answerCitationsValid(ctx: *Context, answer: []const u8, results: []const domain.SearchResult) !bool {
    var grounded_lines: usize = 0;
    var unknown_lines: usize = 0;
    var line_it = std.mem.splitScalar(u8, answer, '\n');
    while (line_it.next()) |raw_line| {
        const line = std.mem.trim(u8, raw_line, " \t\r\n");
        if (line.len == 0) continue;

        const citations = try answerCitationState(ctx, line, results);
        if (citations.invalid) return false;
        if (citations.valid) {
            grounded_lines += 1;
            continue;
        }
        if (answerLineCanOmitCitation(line)) continue;
        if (answerExplicitUnknown(line)) {
            unknown_lines += 1;
            continue;
        }
        return false;
    }
    return grounded_lines > 0 or unknown_lines > 0;
}

const CitationState = struct {
    valid: bool = false,
    invalid: bool = false,
};

fn answerCitationState(ctx: *Context, line: []const u8, results: []const domain.SearchResult) !CitationState {
    var state = CitationState{};
    var start: usize = 0;
    while (std.mem.indexOfScalarPos(u8, line, start, '[')) |open| {
        const close = std.mem.indexOfScalarPos(u8, line, open + 1, ']') orelse {
            state.invalid = true;
            return state;
        };
        const body = std.mem.trim(u8, line[open + 1 .. close], " \t\r\n");
        if (body.len == 0) {
            state.invalid = true;
            return state;
        }
        var tokens = std.mem.tokenizeAny(u8, body, ",; \t\r\n");
        var token_count: usize = 0;
        var citation_token_count: usize = 0;
        while (tokens.next()) |token| {
            token_count += 1;
            if (!looksLikeCitationToken(token)) continue;
            citation_token_count += 1;
            if (!(try citationTokenAllowed(ctx, token, results))) {
                state.invalid = true;
                return state;
            }
        }
        if (citation_token_count > 0 and citation_token_count != token_count) {
            state.invalid = true;
            return state;
        }
        if (citation_token_count > 0) state.valid = true;
        start = close + 1;
    }
    return state;
}

fn answerLineCanOmitCitation(line: []const u8) bool {
    const normalized = trimAnswerListMarker(line);
    if (normalized.len == 0 or normalized.len > 100) return false;
    if (normalized[0] == '#') return true;
    return normalized[normalized.len - 1] == ':';
}

fn trimAnswerListMarker(line: []const u8) []const u8 {
    const normalized = std.mem.trim(u8, line, " \t\r\n");
    if (normalized.len >= 2 and (std.mem.startsWith(u8, normalized, "- ") or std.mem.startsWith(u8, normalized, "* "))) {
        return std.mem.trim(u8, normalized[2..], " \t\r\n");
    }
    var i: usize = 0;
    while (i < normalized.len and std.ascii.isDigit(normalized[i])) : (i += 1) {}
    if (i > 0 and i + 1 < normalized.len and normalized[i] == '.' and normalized[i + 1] == ' ') {
        return std.mem.trim(u8, normalized[i + 2 ..], " \t\r\n");
    }
    return normalized;
}

fn answerExplicitUnknown(line: []const u8) bool {
    return containsFold(line, "i don't know") or
        containsFold(line, "insufficient evidence") or
        containsFold(line, "not enough evidence") or
        containsFold(line, "no supported") or
        containsFold(line, "no source-grounded");
}

fn containsFold(haystack: []const u8, needle: []const u8) bool {
    if (needle.len == 0) return true;
    if (needle.len > haystack.len) return false;
    var i: usize = 0;
    while (i + needle.len <= haystack.len) : (i += 1) {
        if (std.ascii.eqlIgnoreCase(haystack[i .. i + needle.len], needle)) return true;
    }
    return false;
}

fn looksLikeCitationToken(token: []const u8) bool {
    const prefixes = [_][]const u8{ "src_", "art_", "mem_", "ent_", "rel_", "ctx_", "spc_", "pol_", "agm_", "agent_memory:", "policy:", "feed:", "session:" };
    inline for (prefixes) |prefix| {
        if (std.mem.startsWith(u8, token, prefix)) return true;
    }
    return false;
}

fn citationTokenAllowed(ctx: *Context, token: []const u8, results: []const domain.SearchResult) !bool {
    for (results) |result| {
        if (std.mem.eql(u8, token, result.id)) return true;
        if (try citationSourceTokenAllowed(ctx, token, result.source_ids_json)) return true;
    }
    return false;
}

fn citationSourceTokenAllowed(ctx: *Context, token: []const u8, source_ids_json: []const u8) !bool {
    const parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, source_ids_json, .{}) catch return false;
    defer parsed.deinit();
    if (parsed.value != .array) return false;
    for (parsed.value.array.items) |item| {
        if (item == .string and std.mem.eql(u8, token, item.string)) return true;
    }
    return false;
}

fn appendAskWarnings(ctx: *Context, out: *std.ArrayListUnmanaged(u8), results: []domain.SearchResult, conflicts: []store_mod.KnowledgeConflict) !void {
    try out.append(ctx.allocator, '[');
    var first = true;
    for (results) |result| {
        if (std.mem.eql(u8, result.status, "stale") or std.mem.eql(u8, result.status, "deprecated") or std.mem.eql(u8, result.status, "superseded")) {
            if (!first) try out.append(ctx.allocator, ',');
            first = false;
            try out.appendSlice(ctx.allocator, "{\"type\":\"stale_or_deprecated\",\"object_id\":");
            try json.appendString(out, ctx.allocator, result.id);
            try out.appendSlice(ctx.allocator, ",\"status\":");
            try json.appendString(out, ctx.allocator, result.status);
            try out.append(ctx.allocator, '}');
        }
    }
    if (conflicts.len > 0) {
        if (!first) try out.append(ctx.allocator, ',');
        try out.appendSlice(ctx.allocator, "{\"type\":\"potential_conflicts\",\"count\":");
        try out.print(ctx.allocator, "{d}", .{conflicts.len});
        try out.append(ctx.allocator, '}');
    }
    try out.append(ctx.allocator, ']');
}

fn appendConflictsArray(ctx: *Context, out: *std.ArrayListUnmanaged(u8), conflicts: []store_mod.KnowledgeConflict) !void {
    try out.append(ctx.allocator, '[');
    for (conflicts, 0..) |conflict, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try conflict.writeJson(ctx.allocator, out);
    }
    try out.append(ctx.allocator, ']');
}

fn contextPack(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "task") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing query");
    const persist = json.boolField(obj, "persist") orelse (hasCapability(ctx, "write") or hasCapability(ctx, "propose"));
    if (persist and !hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    const search_input = buildSearchInput(ctx, obj, query, searchLimit(json.intField(obj, "limit"), 40), false, route_query) catch |err| switch (err) {
        error.InvalidRolloutMode, error.InvalidRolloutPolicy, error.InvalidRawJson => return badJson(ctx),
        error.RolloutPolicyNotFound => return rolloutPolicyNotFound(ctx),
        error.InvalidStorageSelector => return storageRouteError(ctx, err),
        else => return serverError(ctx),
    };
    const pipeline = runSearchPipeline(ctx, obj, query, search_input) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        error.Forbidden => return forbidden(ctx),
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const context_pack_route = if (api_storage_route.includesKg(search_input.agent_memory_route))
        api_storage_route.withoutKgOrNative(ctx.allocator, search_input.agent_memory_route) catch return serverError(ctx)
    else
        search_input.agent_memory_route;
    const preselected_results = pipeline.results;
    const pack = ctx.store.createContextPack(ctx.allocator, .{
        .purpose = json.stringField(obj, "purpose") orelse "task",
        .target = json.stringField(obj, "target") orelse "agent",
        .query = query,
        .token_budget = json.intField(obj, "token_budget") orelse 12000,
        .scopes_json = search_input.scopes_json,
        .query_embedding_json = search_input.query_embedding_json,
        .query_embedding_provider = search_input.query_embedding_provider,
        .embedding_dimensions = search_input.embedding_dimensions,
        .persist = persist,
        .include_sessions = search_input.include_sessions,
        .session_id = search_input.session_id,
        .retrieval_limit = search_input.limit,
        .include_deprecated = search_input.include_deprecated,
        .use_vector = search_input.use_vector,
        .adaptive_retrieval = search_input.adaptive_retrieval,
        .adaptive_keyword_max_tokens = search_input.adaptive_keyword_max_tokens,
        .adaptive_vector_min_tokens = search_input.adaptive_vector_min_tokens,
        .use_temporal_decay = search_input.use_temporal_decay,
        .use_mmr = search_input.use_mmr,
        .mmr_lambda = search_input.mmr_lambda,
        .mmr_candidate_multiplier = search_input.mmr_candidate_multiplier,
        .allow_reranker = search_input.allow_reranker,
        .rerank_candidate_limit = search_input.rerank_candidate_limit,
        .strict_reranker = search_input.strict_reranker,
        .min_relevance = search_input.min_relevance,
        .rrf_k = search_input.rrf_k,
        .rrf_weight = search_input.rrf_weight,
        .raw_score_weight = search_input.raw_score_weight,
        .rrf_window_multiplier = search_input.rrf_window_multiplier,
        .actor_id = ctx.actor_id,
        .actor_capabilities_json = search_input.actor_capabilities_json,
        .agent_memory_route = context_pack_route,
        .preselected_results = preselected_results,
        .preserve_result_order = pipeline.rerank_applied,
    }) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (pack.persisted) {
        if (ctx.store.vectorObjectAcl(ctx.allocator, "context_pack", pack.id, ctx.actor_id) catch null) |acl_value| {
            var acl = acl_value;
            defer store_mod.freeVectorObjectAcl(ctx.allocator, &acl);
            const text = vector_text.contextPack(ctx.allocator, pack) catch return serverError(ctx);
            _ = upsertAutoVector(ctx, "context_pack", pack.id, text, acl.scope, acl.permissions_json) catch 0;
        }
    }
    return contextPackResponse(ctx, pack);
}

fn listContextPacks(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const input = primitiveListInputFromQuery(ctx, query) catch |err| return rawJsonRequestError(ctx, err);
    if (input.limit == 0) return emptyPrimitiveList(ctx, "context_packs", "context_packs", input);
    const packs = ctx.store.listContextPacksVisible(ctx.allocator, input) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"context_packs\":[") catch return serverError(ctx);
    for (packs, 0..) |pack, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        const status = ctx.store.primitiveLifecycleStatus(ctx.allocator, "context_pack", pack.id) catch return serverError(ctx);
        appendContextPackJson(ctx, &out, pack, status) catch return serverError(ctx);
    }
    appendPrimitiveListMeta(ctx, &out, "context_packs", packs.len, input) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn getContextPack(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    _ = (ctx.store.contextPackLifecycleTarget(ctx.allocator, id, ctx.actor_id, ctx.actor_scopes_json) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    const pack = (ctx.store.contextPackById(ctx.allocator, id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    return contextPackResponse(ctx, pack);
}

fn patchContextPack(ctx: *Context, id: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const status = json.stringField(parsed.value.object, "status") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing status");
    if (!validPrimitiveLifecycleStatus(status)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid context pack status");
    const target = (ctx.store.contextPackLifecycleTarget(ctx.allocator, id, ctx.actor_id, ctx.actor_scopes_json) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    if (!canChangeGraphPrimitiveStatus(ctx, target.scope, target.permissions_json, status)) return forbidden(ctx);
    const payload_json = primitiveLifecycleInputPayloadJson(ctx, parsed.value.object) catch return badJson(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "context_pack", target.object_id, status, ctx.actor_id, payload_json) catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    const operation = primitiveLifecycleOperationForStatus(status);
    const event_payload_json = primitiveLifecyclePayloadJson(ctx, operation, status, json.stringField(parsed.value.object, "reason"), payload_json, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "context_pack", target.object_id, target.scope, target.permissions_json, operation, event_payload_json) catch return serverError(ctx);
    const pack = (ctx.store.contextPackById(ctx.allocator, target.object_id) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    return contextPackResponse(ctx, pack);
}

fn deleteContextPack(ctx: *Context, id: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const target = (ctx.store.contextPackLifecycleTarget(ctx.allocator, id, ctx.actor_id, ctx.actor_scopes_json) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    if (!canChangeGraphPrimitiveStatus(ctx, target.scope, target.permissions_json, "deprecated")) return forbidden(ctx);
    const changed = ctx.store.patchPrimitiveLifecycleActor(ctx.allocator, "context_pack", target.object_id, "deprecated", ctx.actor_id, "{\"deleted\":true}") catch return serverError(ctx);
    if (!changed) return json.errorResponse(ctx.allocator, 404, "not_found", "Context pack not found");
    const payload_json = primitiveLifecyclePayloadJson(ctx, "delete", "deprecated", null, null, null) catch return serverError(ctx);
    appendPrimitiveLifecycleFeedEvent(ctx, "context_pack", target.object_id, target.scope, target.permissions_json, "delete", payload_json) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"status\":\"deprecated\"}");
}

fn contextPackResponse(ctx: *Context, pack: store_mod.ContextPackResult) HttpResponse {
    const status = if (pack.persisted)
        (ctx.store.primitiveLifecycleStatus(ctx.allocator, "context_pack", pack.id) catch return serverError(ctx))
    else
        "preview";
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"context_pack\":") catch return serverError(ctx);
    appendContextPackJson(ctx, &out, pack, status) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendContextPackJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), pack: store_mod.ContextPackResult, status: []const u8) !void {
    try out.appendSlice(ctx.allocator, "{\"id\":");
    try json.appendString(out, ctx.allocator, pack.id);
    try out.appendSlice(ctx.allocator, ",\"purpose\":");
    try json.appendString(out, ctx.allocator, pack.purpose);
    try out.appendSlice(ctx.allocator, ",\"target\":");
    try json.appendString(out, ctx.allocator, pack.target);
    try out.appendSlice(ctx.allocator, ",\"query\":");
    try json.appendString(out, ctx.allocator, pack.query);
    try out.appendSlice(ctx.allocator, ",\"persisted\":");
    try out.appendSlice(ctx.allocator, if (pack.persisted) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(out, ctx.allocator, status);
    try appendRawJsonArrayField(ctx.allocator, out, "included_sources", pack.included_sources_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_artifacts", pack.included_artifacts_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_memory_atoms", pack.included_memory_atoms_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_result_refs", pack.included_result_refs_json);
    try out.appendSlice(ctx.allocator, ",\"generated_summary\":");
    try json.appendString(out, ctx.allocator, pack.generated_summary);
    try appendRawJsonObjectField(ctx.allocator, out, "sections", pack.sections_json);
    try appendRawJsonArrayField(ctx.allocator, out, "citations", pack.citations_json);
    try appendRawJsonArrayField(ctx.allocator, out, "forbidden_assumptions", pack.forbidden_assumptions_json);
    try appendRawJsonArrayField(ctx.allocator, out, "suggested_next_steps", pack.suggested_next_steps_json);
    try out.print(ctx.allocator, ",\"token_budget\":{d},\"created_at_ms\":{d}", .{ pack.token_budget, pack.created_at_ms });
    try out.append(ctx.allocator, '}');
}

fn appendRawJsonArrayField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, raw: []const u8) !void {
    try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendRawJsonArray(out, allocator, raw);
}

fn appendRawJsonObjectField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, raw: []const u8) !void {
    try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendRawJsonObject(out, allocator, raw);
}

test "api context pack response preserves raw JSON fields" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);

    try appendContextPackJson(&ctx, &out, .{
        .id = "ctx_raw",
        .purpose = "task",
        .target = "agent",
        .query = "raw context",
        .generated_summary = "raw summary",
        .sections_json = "{\"decisions\":[\"ship\"]}",
        .citations_json = "[\"src_1\"]",
        .forbidden_assumptions_json = "[\"guessing\"]",
        .suggested_next_steps_json = "[\"verify\"]",
        .included_sources_json = "[\"src_1\"]",
        .included_artifacts_json = "[\"art_1\"]",
        .included_memory_atoms_json = "[\"mem_1\"]",
        .included_result_refs_json = "[{\"id\":\"mem_1\"}]",
        .required_scopes_json = "[\"public\"]",
        .token_budget = 12000,
        .created_at_ms = 1,
        .persisted = true,
    }, "active");

    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"sections\":{\"decisions\":[\"ship\"]}") != null);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"included_result_refs\":[{\"id\":\"mem_1\"}]") != null);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"citations\":[\"src_1\"]") != null);
}

test "api context pack response rejects malformed raw JSON fields" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    const pack = store_mod.ContextPackResult{
        .id = "ctx_bad_raw",
        .purpose = "task",
        .target = "agent",
        .query = "bad raw context",
        .generated_summary = "bad raw summary",
        .sections_json = "{}",
        .citations_json = "[]",
        .forbidden_assumptions_json = "[]",
        .suggested_next_steps_json = "[]",
        .included_sources_json = "[]",
        .included_artifacts_json = "[]",
        .included_memory_atoms_json = "[]",
        .included_result_refs_json = "[]",
        .required_scopes_json = "[\"public\"]",
        .token_budget = 12000,
        .created_at_ms = 1,
    };

    var bad_sections = pack;
    bad_sections.sections_json = "[]";
    var sections_out: std.ArrayListUnmanaged(u8) = .empty;
    defer sections_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendContextPackJson(&ctx, &sections_out, bad_sections, "active"));

    var bad_sources = pack;
    bad_sources.included_sources_json = "{}";
    var sources_out: std.ArrayListUnmanaged(u8) = .empty;
    defer sources_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendContextPackJson(&ctx, &sources_out, bad_sources, "active"));
}

fn agentMemoryStoreBody(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const key = json.stringField(parsed.value.object, "key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing key");
    return agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx, key, parsed.value.object, "core", route_query);
}

fn agentMemoryStoreKey(ctx: *Context, key: []const u8, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    return agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx, key, parsed.value.object, "core", route_query);
}

fn agentMemoryStoreParsed(ctx: *Context, key: []const u8, obj: std.json.ObjectMap) HttpResponse {
    return agentMemoryStoreParsedWithDefaultCategory(ctx, key, obj, "core");
}

fn agentMemoryStoreParsedWithDefaultCategory(ctx: *Context, key: []const u8, obj: std.json.ObjectMap, default_category: []const u8) HttpResponse {
    return agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx, key, obj, default_category, "");
}

fn agentMemoryStoreParsedWithDefaultCategoryAndRoute(ctx: *Context, key: []const u8, obj: std.json.ObjectMap, default_category: []const u8, route_query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return forbidden(ctx);
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryStoreEntry(ctx, key, obj, default_category) catch |err| return kgMemoryErrorResponse(ctx, err);
        return agentMemoryEntryResponse(ctx, "memory", entry);
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);

    const operation = domain.AgentMemoryOperation.parse(json.stringField(obj, "operation") orelse "put");
    const content = switch (operation) {
        .put => json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing content"),
        .merge_string_set => agent_memory_reducer.stringSetPatchFromObject(ctx.allocator, obj) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid string-set merge payload"),
        .merge_object => agent_memory_reducer.objectPatchFromObject(ctx.allocator, obj) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid object merge payload"),
    };
    const session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
    }
    const permissions = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    const scope = json.nullableStringField(obj, "scope");
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = content, .scope = requested_scope, .permissions_json = permissions, .created_by = "agent", .actor_id = ctx.actor_id })) return forbidden(ctx);
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return forbidden(ctx);
    }
    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx);
    defer ctx.allocator.free(owner_actor_id);
    var kg_entry: ?domain.AgentMemory = null;
    if (route_includes_kg) {
        kg_entry = kgMemoryStoreEntry(ctx, key, obj, default_category) catch |err| return kgMemoryErrorResponse(ctx, err);
    }
    if (non_kg_storage_target) |route| {
        const entry = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
            .key = key,
            .content = content,
            .category = json.stringField(obj, "category") orelse default_category,
            .session_id = session_id,
            .scope = scope,
            .permissions_json = permissions,
            .metadata_json = agentMemoryObjectJson(ctx, obj, &.{"metadata"}, "{}") catch |err| return rawJsonRequestError(ctx, err),
            .actor_id = owner_actor_id,
            .writer_actor_id = ctx.actor_id,
            .actor_scopes_json = ctx.actor_scopes_json,
            .actor_capabilities_json = ctx.actor_capabilities_json,
            .operation = operation,
        }, route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        _ = upsertAutoVector(ctx, "agent_memory", entry.id, entry.content, entry.scope, entry.permissions_json) catch 0;
        return agentMemoryEntryResponse(ctx, "memory", entry);
    }
    if (kg_entry) |entry| return agentMemoryEntryResponse(ctx, "memory", entry);
    return agentMemoryStorageUnavailable(ctx);
}

fn agentMemoryPermissionsJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawArrayFieldAny(ctx.allocator, obj, names, fallback);
}

fn agentMemoryObjectJson(ctx: *Context, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]const u8 {
    return rawObjectFieldAny(ctx.allocator, obj, names, fallback);
}

fn agentMemoryGet(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return agentMemoryEntryResponse(ctx, "memory", entry.?);
    }
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    if (!requestedAgentMemoryScopeReadable(ctx, requested_scope)) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    var entry = if (non_kg_storage_target) |route| (if (requested_scope) |scope| blk: {
        const owner_actor_id = access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx);
        defer ctx.allocator.free(owner_actor_id);
        break :blk api_agent_memory_store.getByInput(ctx, .{
            .key = key,
            .route = route,
            .session_id = session_id,
            .owner_actor_id = owner_actor_id,
            .access = .exact_owner,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    } else api_agent_memory_store.getByInput(ctx, .{
        .key = key,
        .route = route,
        .session_id = session_id,
    }) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    }) else null;
    if (entry == null and session_id == null and requested_scope == null and queryBool(query, "include_sessions", false)) {
        if (non_kg_storage_target) |route| {
            entry = api_agent_memory_store.getByInput(ctx, .{
                .key = key,
                .route = route,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        }
    }
    if (entry == null and api_storage_route.includesKg(storage_target)) {
        entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
    }
    if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    defer if (entry) |*loaded| agent_memory_runtime.freeAgentMemory(ctx.allocator, loaded);
    if (!agentMemoryEntryVisible(ctx, entry.?)) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return agentMemoryEntryResponse(ctx, "memory", entry.?);
}

fn agentMemoryList(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const category = json.queryParamDecoded(ctx.allocator, query, "category") catch return serverError(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const include_global = queryBool(query, "include_global", false);
    const include_sessions = queryBool(query, "include_sessions", false);
    const include_internal = queryBool(query, "include_internal", false);
    const include_content = queryBool(query, "include_content", true);
    const limit = parseLimit(json.queryParam(query, "limit"), std.math.maxInt(usize));
    const offset = parseLimit(json.queryParam(query, "offset"), 0);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.targetsKg(storage_target)) {
        const entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        return agentMemoryEntriesResponseFilteredWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    if (!requestedAgentMemoryScopeReadable(ctx, requested_scope)) {
        return agentMemoryEntriesResponseFilteredWithContent(ctx, &[_]domain.AgentMemory{}, include_internal, include_content, limit, offset);
    }
    const exact_owner = if (requested_scope) |scope| access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx) else null;
    defer if (exact_owner) |owner| ctx.allocator.free(owner);
    if (!route_includes_kg and !include_global and agentMemoryListSupportsDirectWindow(storage_target)) {
        const windowed = loadAgentMemoryListRoutedFilteredWindow(ctx, category, session_id, exact_owner, storage_target, include_sessions, include_internal, limit, offset) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return agentMemoryEntriesResponseFilteredWithContent(ctx, windowed, true, include_content, std.math.maxInt(usize), 0);
    }
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (non_kg_storage_target) |route| {
        const auth = api_agent_memory_store.contextAuth(ctx);
        const primary = if (exact_owner) |owner|
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .session_id = session_id,
                .owner_actor_id = owner,
                .access = .exact_owner,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else if (session_id == null and include_sessions)
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .auth = auth,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else
            api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .session_id = session_id,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    }
    if (include_global and session_id != null) {
        if (non_kg_storage_target) |route| {
            const auth = api_agent_memory_store.contextAuth(ctx);
            const global = if (exact_owner) |owner| api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .owner_actor_id = owner,
                .access = .exact_owner,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            } else api_agent_memory_store.listByInput(ctx, .{
                .route = route,
                .category = category,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
        }
    }
    if (route_includes_kg) {
        const kg_entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, kg_entries) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    return agentMemoryEntriesResponseFilteredWithContent(ctx, entries.items, include_internal, include_content, limit, offset);
}

fn agentMemorySearch(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
    }
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "";
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const limit = agentMemorySearchLimit(json.intField(obj, "limit"), 10);
    const offset = searchOffset(json.intField(obj, "offset") orelse queryInt(route_query, "offset"));
    const search_limit = agentMemorySearchWindowLimit(limit, offset);
    const include_global = json.boolField(obj, "include_global") orelse false;
    const include_sessions = json.boolField(obj, "include_sessions") orelse false;
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_content = json.boolField(obj, "include_content") orelse true;
    const graph_entries = graphCommandAgentMemoryEntriesFromObject(ctx, obj, query, search_limit) catch |err| switch (err) {
        error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
        error.InvalidGraphCommand => return badJson(ctx),
        else => return serverError(ctx),
    };
    if (graph_entries) |entries| {
        recordReturnedAgentMemoryRecallSignals(ctx, query, entries, include_internal, limit, offset);
        return agentMemoryEntriesResponseFilteredWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (non_kg_storage_target) |route| {
        const auth = api_agent_memory_store.scopedAuth(ctx, scopes_json);
        const primary = if (session_id == null and include_sessions)
            api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .auth = auth,
                .access = .any_visible,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }
        else
            api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .session_id = session_id,
                .auth = auth,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
        appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    }
    if (include_global and session_id != null) {
        if (non_kg_storage_target) |route| {
            const global = api_agent_memory_store.searchByInput(ctx, .{
                .query = query,
                .route = route,
                .limit = search_limit,
                .auth = api_agent_memory_store.scopedAuth(ctx, scopes_json),
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
        }
    }
    if (route_includes_kg) {
        const kg_entries = kgMemorySearchEntries(ctx, obj, query, search_limit) catch |err| switch (err) {
            else => return kgMemoryErrorResponse(ctx, err),
        };
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, kg_entries) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    recordReturnedAgentMemoryRecallSignals(ctx, query, entries.items, include_internal, limit, offset);
    return agentMemoryEntriesResponseFilteredWithContent(ctx, entries.items, include_internal, include_content, limit, offset);
}

fn memoryPrefetch(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const explicit_context = json.stringField(obj, "context") orelse json.stringField(obj, "text");
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse json.stringField(obj, "message") orelse "";
    const title = json.stringField(obj, "title") orelse "Recalled Memory";
    const limit = agentMemorySearchLimit(json.intField(obj, "limit"), 10);
    const include_internal = json.boolField(obj, "include_internal") orelse false;

    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (explicit_context == null and std.mem.trim(u8, query, " \t\r\n").len > 0) {
        const session_id = nullableStringFieldAliasWithCurrentSession(obj, "session_id", "session");
        if (session_id) |sid| {
            if (!api_session_access.readAllowed(ctx, sid)) return forbidden(ctx);
        }
        const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
        const include_global = json.boolField(obj, "include_global") orelse false;
        const include_sessions = json.boolField(obj, "include_sessions") orelse false;
        const graph_entries = graphCommandAgentMemoryEntriesFromObject(ctx, obj, query, limit) catch |err| switch (err) {
            error.EngineNotCompiled => return engineNotCompiled(ctx, "kg"),
            error.InvalidGraphCommand => return badJson(ctx),
            else => return serverError(ctx),
        };
        if (graph_entries) |items| {
            appendAgentMemoryEntries(ctx.allocator, &entries, items) catch return serverError(ctx);
        } else {
            const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
            const route_includes_kg = api_storage_route.includesKg(storage_target);
            const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
            if (non_kg_storage_target) |route| {
                const auth = api_agent_memory_store.scopedAuth(ctx, scopes_json);
                const primary = if (session_id == null and include_sessions)
                    api_agent_memory_store.searchByInput(ctx, .{
                        .query = query,
                        .route = route,
                        .limit = limit,
                        .auth = auth,
                        .access = .any_visible,
                    }) catch |err| switch (err) {
                        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                        else => return serverError(ctx),
                    }
                else
                    api_agent_memory_store.searchByInput(ctx, .{
                        .query = query,
                        .route = route,
                        .limit = limit,
                        .session_id = session_id,
                        .auth = auth,
                    }) catch |err| switch (err) {
                        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                        else => return serverError(ctx),
                    };
                appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
            }
            if (include_global and session_id != null) {
                if (non_kg_storage_target) |route| {
                    const global = api_agent_memory_store.searchByInput(ctx, .{
                        .query = query,
                        .route = route,
                        .limit = limit,
                        .auth = api_agent_memory_store.scopedAuth(ctx, scopes_json),
                    }) catch |err| switch (err) {
                        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                        else => return serverError(ctx),
                    };
                    appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
                }
            }
            if (route_includes_kg) {
                const kg_entries = kgMemorySearchEntries(ctx, obj, query, limit) catch |err| switch (err) {
                    else => return kgMemoryErrorResponse(ctx, err),
                };
                appendMissingAgentMemoryEntries(ctx.allocator, &entries, kg_entries) catch return serverError(ctx);
            }
            dedupeAgentMemoryEntries(ctx.allocator, &entries);
        }
    }

    var visible_entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    for (entries.items) |entry| {
        if (!agentMemoryEntryVisible(ctx, entry)) continue;
        if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
        visible_entries.append(ctx.allocator, entry) catch return serverError(ctx);
    }
    recordReturnedAgentMemoryRecallSignals(ctx, query, visible_entries.items, true, limit, 0);

    const formatted = if (explicit_context) |raw|
        agent_memory_providers.sanitizeContext(ctx.allocator, raw) catch return serverError(ctx)
    else
        agent_memory_providers.formatPrefetchContext(ctx.allocator, visible_entries.items, title, limit) catch return serverError(ctx);
    defer ctx.allocator.free(formatted);
    const block = agent_memory_providers.buildMemoryContextBlock(ctx.allocator, formatted) catch return serverError(ctx);
    defer ctx.allocator.free(block);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"context\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, formatted) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"block\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, block) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"count\":{d},\"fence\":\"memory-context\",\"fenced\":true}}", .{visible_entries.items.len}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

const curated_memory_delimiter = "\n\xc2\xa7\n";
const curated_memory_limit: usize = 2200;
const curated_user_limit: usize = 1375;

const CuratedTarget = struct {
    target: []const u8,
    filename: []const u8,
    key: []const u8,
    limit: usize,
};

fn memoryCurated(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const action = json.stringField(obj, "action") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing action");
    const target_name = json.stringField(obj, "target") orelse "memory";
    const target = curatedTarget(target_name) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "target must be memory or user");
    const requested_scope = json.nullableStringField(obj, "scope");
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);

    if (std.ascii.eqlIgnoreCase(action, "read")) {
        if (!hasCapability(ctx, "read")) return forbidden(ctx);
        const existing = loadAgentMemoryForRequest(ctx, target.key, null, requested_scope, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return curatedMemoryResponse(ctx, target, action, if (existing) |entry| entry.content else "", false, null);
    }

    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return forbidden(ctx);
    const existing = loadAgentMemoryForRequest(ctx, target.key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const current = if (existing) |entry| entry.content else "";
    const updated = if (std.ascii.eqlIgnoreCase(action, "add"))
        curatedMemoryAdd(ctx, current, json.stringField(obj, "content") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing content")) catch |err| return curatedMemoryMutationError(ctx, err)
    else if (std.ascii.eqlIgnoreCase(action, "replace"))
        curatedMemoryReplace(ctx, current, json.stringField(obj, "old_text") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing old_text"), json.stringField(obj, "content") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing content")) catch |err| return curatedMemoryMutationError(ctx, err)
    else if (std.ascii.eqlIgnoreCase(action, "remove"))
        curatedMemoryRemove(ctx, current, json.stringField(obj, "old_text") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing old_text")) catch |err| return curatedMemoryMutationError(ctx, err)
    else
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported curated memory action");

    if (updated.content.len > target.limit) {
        return json.errorResponse(ctx.allocator, 413, "memory_full", "Curated memory target would exceed its configured byte limit");
    }
    if (curatedMemoryThreatReason(updated.content)) |reason| {
        return json.errorResponse(ctx.allocator, 400, "memory_rejected", reason);
    }

    const permissions = agentMemoryPermissionsJson(ctx, obj, &.{"permissions"}, "[]") catch |err| return rawJsonRequestError(ctx, err);
    if (requested_scope) |scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = updated.content, .scope = scope, .permissions_json = permissions, .created_by = "agent", .actor_id = ctx.actor_id })) return forbidden(ctx);
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return forbidden(ctx);
    }
    const owner_actor_id = access.agentMemoryOwner(ctx.allocator, ctx.actor_id, requested_scope) catch return serverError(ctx);
    defer if (requested_scope != null) ctx.allocator.free(owner_actor_id);
    _ = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
        .key = target.key,
        .content = updated.content,
        .category = "core",
        .scope = requested_scope,
        .permissions_json = permissions,
        .metadata_json = "{\"curated\":true,\"snapshot\":\"session_start\"}",
        .actor_id = owner_actor_id,
        .writer_actor_id = ctx.actor_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
    }, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    return curatedMemoryResponse(ctx, target, action, updated.content, updated.duplicate, updated.matched_old_text);
}

const CuratedMutation = struct {
    content: []const u8,
    duplicate: bool = false,
    matched_old_text: ?[]const u8 = null,
};

fn curatedTarget(name: []const u8) ?CuratedTarget {
    if (std.ascii.eqlIgnoreCase(name, "memory")) return .{ .target = "memory", .filename = "MEMORY.md", .key = "__bootstrap.prompt.MEMORY.md", .limit = curated_memory_limit };
    if (std.ascii.eqlIgnoreCase(name, "user") or std.ascii.eqlIgnoreCase(name, "user_profile")) return .{ .target = "user", .filename = "USER.md", .key = "__bootstrap.prompt.USER.md", .limit = curated_user_limit };
    return null;
}

fn curatedMemoryAdd(ctx: *Context, current: []const u8, raw_content: []const u8) !CuratedMutation {
    const entry = std.mem.trim(u8, raw_content, " \t\r\n");
    if (entry.len == 0) return error.EmptyCuratedEntry;
    var it = std.mem.splitSequence(u8, current, curated_memory_delimiter);
    while (it.next()) |part| {
        if (std.mem.eql(u8, std.mem.trim(u8, part, " \t\r\n"), entry)) {
            return .{ .content = current, .duplicate = true };
        }
    }
    if (std.mem.trim(u8, current, " \t\r\n").len == 0) {
        return .{ .content = try ctx.allocator.dupe(u8, entry) };
    }
    return .{ .content = try std.fmt.allocPrint(ctx.allocator, "{s}{s}{s}", .{ current, curated_memory_delimiter, entry }) };
}

fn curatedMemoryReplace(ctx: *Context, current: []const u8, old_text: []const u8, raw_content: []const u8) !CuratedMutation {
    const replacement = std.mem.trim(u8, raw_content, " \t\r\n");
    if (replacement.len == 0) return error.EmptyCuratedEntry;
    const match = try curatedMemoryFindUnique(ctx, current, old_text);
    const out = try curatedMemoryRewrite(ctx, current, match.index, replacement);
    return .{ .content = out, .matched_old_text = match.entry };
}

fn curatedMemoryRemove(ctx: *Context, current: []const u8, old_text: []const u8) !CuratedMutation {
    const match = try curatedMemoryFindUnique(ctx, current, old_text);
    const out = try curatedMemoryRewrite(ctx, current, match.index, null);
    return .{ .content = out, .matched_old_text = match.entry };
}

const CuratedMatch = struct {
    index: usize,
    entry: []const u8,
};

fn curatedMemoryFindUnique(ctx: *Context, current: []const u8, old_text_raw: []const u8) !CuratedMatch {
    _ = ctx;
    const old_text = std.mem.trim(u8, old_text_raw, " \t\r\n");
    if (old_text.len == 0) return error.EmptyCuratedNeedle;
    var it = std.mem.splitSequence(u8, current, curated_memory_delimiter);
    var index: usize = 0;
    var found: ?CuratedMatch = null;
    while (it.next()) |part| : (index += 1) {
        const entry = std.mem.trim(u8, part, " \t\r\n");
        if (entry.len == 0) continue;
        if (std.mem.indexOf(u8, entry, old_text) == null) continue;
        if (found != null) return error.AmbiguousCuratedNeedle;
        found = .{ .index = index, .entry = entry };
    }
    return found orelse error.CuratedEntryNotFound;
}

fn curatedMemoryRewrite(ctx: *Context, current: []const u8, target_index: usize, replacement: ?[]const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    var it = std.mem.splitSequence(u8, current, curated_memory_delimiter);
    var index: usize = 0;
    var written: usize = 0;
    while (it.next()) |part| : (index += 1) {
        const entry = std.mem.trim(u8, part, " \t\r\n");
        if (entry.len == 0) continue;
        const next_entry = if (index == target_index) replacement else entry;
        if (next_entry) |value| {
            if (written > 0) try out.appendSlice(ctx.allocator, curated_memory_delimiter);
            try out.appendSlice(ctx.allocator, value);
            written += 1;
        }
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn curatedMemoryMutationError(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.EmptyCuratedEntry => json.errorResponse(ctx.allocator, 400, "bad_request", "Curated memory content is empty"),
        error.EmptyCuratedNeedle => json.errorResponse(ctx.allocator, 400, "bad_request", "old_text is empty"),
        error.CuratedEntryNotFound => json.errorResponse(ctx.allocator, 404, "not_found", "No curated memory entry matches old_text"),
        error.AmbiguousCuratedNeedle => json.errorResponse(ctx.allocator, 409, "ambiguous_match", "old_text matches more than one curated memory entry"),
        else => serverError(ctx),
    };
}

fn curatedMemoryThreatReason(content: []const u8) ?[]const u8 {
    if (std.ascii.indexOfIgnoreCase(content, "<memory-context") != null or
        std.ascii.indexOfIgnoreCase(content, "</memory-context") != null)
    {
        return "Curated memory cannot contain memory-context fence tags";
    }
    if (std.ascii.indexOfIgnoreCase(content, "ignore previous instructions") != null or
        std.ascii.indexOfIgnoreCase(content, "disregard previous instructions") != null or
        std.ascii.indexOfIgnoreCase(content, "reveal system prompt") != null or
        std.ascii.indexOfIgnoreCase(content, "exfiltrate") != null)
    {
        return "Curated memory content looks like prompt-injection or exfiltration text";
    }
    for (content) |byte| {
        if (byte < 0x20 and byte != '\n' and byte != '\r' and byte != '\t') return "Curated memory cannot contain control characters";
    }
    if (std.mem.indexOf(u8, content, "\xe2\x80\x8b") != null or
        std.mem.indexOf(u8, content, "\xe2\x80\x8c") != null or
        std.mem.indexOf(u8, content, "\xe2\x80\x8d") != null or
        std.mem.indexOf(u8, content, "\xef\xbb\xbf") != null)
    {
        return "Curated memory cannot contain invisible Unicode markers";
    }
    return null;
}

fn curatedMemoryResponse(ctx: *Context, target: CuratedTarget, action: []const u8, content: []const u8, duplicate: bool, matched_old_text: ?[]const u8) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"success\":true,\"action\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, action) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, target.target) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"filename\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, target.filename) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, target.key) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"usage\":{{\"bytes\":{d},\"limit\":{d},\"percent\":{d}}},\"duplicate\":{s},\"snapshot\":\"session_start\",\"entries\":[", .{
        content.len,
        target.limit,
        if (target.limit == 0) @as(usize, 0) else (content.len * 100) / target.limit,
        if (duplicate) "true" else "false",
    }) catch return serverError(ctx);
    var it = std.mem.splitSequence(u8, content, curated_memory_delimiter);
    var written: usize = 0;
    while (it.next()) |part| {
        const entry = std.mem.trim(u8, part, " \t\r\n");
        if (entry.len == 0) continue;
        if (written > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, entry) catch return serverError(ctx);
        written += 1;
    }
    out.append(ctx.allocator, ']') catch return serverError(ctx);
    if (matched_old_text) |matched| {
        out.appendSlice(ctx.allocator, ",\"matched_old_text\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, matched) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memorySessionSearch(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const session_id = json.stringField(obj, "session_id");
    const around_message_id = json.intField(obj, "around_message_id") orelse json.intField(obj, "around");
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q");
    if (session_id != null and around_message_id != null) return memorySessionSearchScroll(ctx, obj, route_query, session_id.?, around_message_id.?);
    if (query) |q| {
        if (std.mem.trim(u8, q, " \t\r\n").len > 0) return memorySessionSearchDiscovery(ctx, obj, route_query, q);
    }
    return memorySessionSearchBrowse(ctx, obj, route_query);
}

fn memorySessionSearchBrowse(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8) HttpResponse {
    if (!api_session_access.allReadAllowed(ctx)) return forbidden(ctx);
    const limit = positiveBounded(json.intField(obj, "limit"), 10, 100);
    const offset = positiveBounded(json.intField(obj, "offset"), 0, 1_000_000);
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const result = ctx.store.listSessionsRoutedWithAuth(ctx.allocator, limit, offset, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"success\":true,\"mode\":\"browse\",\"results\":[") catch return serverError(ctx);
    for (result.sessions, 0..) |session, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendSessionSummaryJson(ctx, &out, session, storage_target) catch return serverError(ctx);
    }
    out.print(ctx.allocator, "],\"count\":{d},\"total\":{d},\"limit\":{d},\"offset\":{d}}}", .{ result.sessions.len, result.total, limit, offset }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memorySessionSearchDiscovery(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8, query: []const u8) HttpResponse {
    if (!api_session_access.allReadAllowed(ctx)) return forbidden(ctx);
    const limit = positiveBounded(json.intField(obj, "limit"), 5, 50);
    const window = positiveBounded(json.intField(obj, "window"), 5, 20);
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const search_results = ctx.store.search(ctx.allocator, .{
        .query = query,
        .limit = memorySessionDiscoverySearchLimit(limit),
        .scopes_json = scopes_json,
        .include_sessions = true,
        .use_vector = false,
        .use_mmr = false,
        .use_temporal_decay = false,
        .actor_id = ctx.actor_id,
        .actor_capabilities_json = ctx.actor_capabilities_json,
        .agent_memory_route = storage_target,
    }) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    var sessions: std.ArrayListUnmanaged([]const u8) = .empty;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"success\":true,\"mode\":\"discovery\",\"query\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, query) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"results\":[") catch return serverError(ctx);
    var written: usize = 0;
    for (search_results) |result| {
        if (!std.mem.eql(u8, result.result_type, "session_message")) continue;
        const sid = result.session_id orelse continue;
        if (sessionIdSeen(sessions.items, sid)) continue;
        if (!api_session_access.readAllowed(ctx, sid)) continue;
        if (written >= limit) break;
        sessions.append(ctx.allocator, sid) catch return serverError(ctx);
        const history = ctx.store.historyRoutedWithAuth(ctx.allocator, sid, 5000, 0, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        const anchor = sessionAnchorIndex(history.messages, result.created_at_ms, query);
        if (written > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendSessionDiscoveryJson(ctx, &out, sid, result, history, anchor, window) catch return serverError(ctx);
        written += 1;
    }
    out.print(ctx.allocator, "],\"count\":{d}}}", .{written}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memorySessionDiscoverySearchLimit(limit: usize) usize {
    return @max(bounded_int.saturatingUsizeMul(limit, 4), @as(usize, 20));
}

test "api memory session discovery search limit is bounded" {
    try std.testing.expectEqual(@as(usize, 20), memorySessionDiscoverySearchLimit(0));
    try std.testing.expectEqual(@as(usize, 20), memorySessionDiscoverySearchLimit(5));
    try std.testing.expectEqual(@as(usize, 200), memorySessionDiscoverySearchLimit(50));
    try std.testing.expectEqual(std.math.maxInt(usize), memorySessionDiscoverySearchLimit(std.math.maxInt(usize)));
}

fn memorySessionSearchScroll(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8, session_id: []const u8, around_message_id: i64) HttpResponse {
    if (!api_session_access.readAllowed(ctx, session_id)) return forbidden(ctx);
    if (around_message_id <= 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "around_message_id must be a positive 1-based message id");
    const window = positiveBounded(json.intField(obj, "window"), 5, 20);
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query) catch |err| return storageRouteError(ctx, err);
    const anchor_index: usize = @intCast(around_message_id - 1);
    const offset = if (anchor_index > window) anchor_index - window else 0;
    const limit = sessionMessageAroundLimit(window);
    const history = ctx.store.historyRoutedWithAuth(ctx.allocator, session_id, limit, offset, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"success\":true,\"mode\":\"scroll\",\"session_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"around_message_id\":{d},\"window\":{d},\"total\":{d},\"messages\":[", .{ around_message_id, window, history.total }) catch return serverError(ctx);
    appendSessionMessageWindow(ctx, &out, history.messages, offset, anchor_index) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendSessionSummaryJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), session: store_mod.SessionInfo, route: store_mod.AgentMemoryStorageRoute) !void {
    try out.appendSlice(ctx.allocator, "{\"session_id\":");
    try json.appendString(out, ctx.allocator, session.session_id);
    try out.print(ctx.allocator, ",\"message_count\":{d},\"started_at\":\"{d}\",\"last_active\":\"{d}\",\"preview\":", .{ session.message_count, session.first_message_at, session.last_message_at });
    const preview = ctx.store.historyRoutedWithAuth(ctx.allocator, session.session_id, 1, 0, actorFilter(ctx), ctx.actor_capabilities_json, route) catch |err| switch (err) {
        else => return err,
    };
    if (preview.messages.len > 0) {
        try json.appendString(out, ctx.allocator, preview.messages[0].content);
    } else {
        try json.appendString(out, ctx.allocator, "");
    }
    try out.append(ctx.allocator, '}');
}

fn sessionMessageAroundLimit(window: usize) usize {
    const doubled = bounded_int.saturatingUsizeMul(window, 2);
    return bounded_int.saturatingUsizeAdd(doubled, 1);
}

fn sessionMessageWindowEnd(total: usize, anchor: usize, window: usize) usize {
    const anchor_plus_window = bounded_int.saturatingUsizeAdd(anchor, window);
    const exclusive_end = bounded_int.saturatingUsizeAdd(anchor_plus_window, 1);
    return @min(total, exclusive_end);
}

fn sessionMessageIndexAdd(base_index: usize, offset: usize) usize {
    return bounded_int.saturatingUsizeAdd(base_index, offset);
}

fn sessionMessageOutputId(zero_based_index: usize) usize {
    return bounded_int.saturatingUsizeAdd(zero_based_index, 1);
}

fn appendSessionDiscoveryJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), session_id: []const u8, result: domain.SearchResult, history: store_mod.HistoryShow, anchor: usize, window: usize) !void {
    try out.appendSlice(ctx.allocator, "{\"session_id\":");
    try json.appendString(out, ctx.allocator, session_id);
    try out.appendSlice(ctx.allocator, ",\"snippet\":");
    try json.appendString(out, ctx.allocator, result.text);
    try out.print(ctx.allocator, ",\"score\":{d},\"anchor_message_id\":{d},\"messages\":[", .{ result.score, sessionMessageOutputId(anchor) });
    const total = history.messages.len;
    const start = if (anchor > window) anchor - window else 0;
    const end = sessionMessageWindowEnd(total, anchor, window);
    appendSessionMessageWindow(ctx, out, history.messages[start..end], start, anchor) catch return error.OutOfMemory;
    try out.appendSlice(ctx.allocator, "],\"bookend_start\":[");
    appendSessionMessageWindow(ctx, out, history.messages[0..@min(total, @as(usize, 3))], 0, anchor) catch return error.OutOfMemory;
    try out.appendSlice(ctx.allocator, "],\"bookend_end\":[");
    const tail_start = if (total > 3) total - 3 else 0;
    appendSessionMessageWindow(ctx, out, history.messages[tail_start..total], tail_start, anchor) catch return error.OutOfMemory;
    try out.appendSlice(ctx.allocator, "]}");
}

fn appendSessionMessageWindow(ctx: *Context, out: *std.ArrayListUnmanaged(u8), messages: []const store_mod.Message, base_index: usize, anchor_index: usize) !void {
    for (messages, 0..) |message, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        const id = sessionMessageOutputId(sessionMessageIndexAdd(base_index, i));
        try out.appendSlice(ctx.allocator, "{\"id\":");
        try out.print(ctx.allocator, "{d}", .{id});
        try out.appendSlice(ctx.allocator, ",\"role\":");
        try json.appendString(out, ctx.allocator, message.role);
        try out.appendSlice(ctx.allocator, ",\"content\":");
        try json.appendString(out, ctx.allocator, message.content);
        try out.print(ctx.allocator, ",\"timestamp\":\"{d}\"", .{message.created_at_ms});
        if (base_index + i == anchor_index) try out.appendSlice(ctx.allocator, ",\"anchor\":true");
        try out.append(ctx.allocator, '}');
    }
}

fn sessionAnchorIndex(messages: []const store_mod.Message, created_at_ms: i64, query: []const u8) usize {
    for (messages, 0..) |message, i| {
        if (message.created_at_ms == created_at_ms) return i;
    }
    for (messages, 0..) |message, i| {
        if (std.ascii.indexOfIgnoreCase(message.content, query) != null) return i;
    }
    return 0;
}

fn sessionIdSeen(items: []const []const u8, session_id: []const u8) bool {
    for (items) |item| {
        if (std.mem.eql(u8, item, session_id)) return true;
    }
    return false;
}

fn memoryToolCall(ctx: *Context, body: []const u8, route_query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const tool_name = json.stringField(obj, "tool_name") orelse json.stringField(obj, "name") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing tool_name");
    const args_value = obj.get("arguments") orelse obj.get("args") orelse std.json.Value{ .object = obj };
    if (args_value != .object) return json.errorResponse(ctx.allocator, 400, "bad_request", "arguments must be an object");
    const args_body = json.jsonFromValue(ctx.allocator, args_value) catch return serverError(ctx);
    const response = if (std.mem.eql(u8, tool_name, "memory_store"))
        memoryCommandStoreBody(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_update"))
        memoryCommandUpdateBody(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_delete"))
        memoryCommandDeleteBody(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_get"))
        memoryToolCallGet(ctx, args_value.object, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_list"))
        memoryToolCallList(ctx, args_value.object, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_export_jsonl"))
        memoryCommandExportJsonl(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_recall") or std.mem.eql(u8, tool_name, "memory_search"))
        nullClawAgentMemorySearch(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_curate"))
        memoryCurated(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "session_search"))
        memorySessionSearch(ctx, args_body, route_query)
    else if (std.mem.eql(u8, tool_name, "memory_stats"))
        memoryStats(ctx)
    else
        return json.errorResponse(ctx.allocator, 501, "tool_not_supported", "Only native NullPantry memory tools can be dispatched by this endpoint");
    return memoryToolCallResponse(ctx, tool_name, response);
}

fn memoryToolCallGet(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8) HttpResponse {
    const key = json.stringField(obj, "key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing key");
    const query = memoryToolReadQuery(ctx, obj, route_query) catch return serverError(ctx);
    return nullClawAgentMemoryGet(ctx, key, query);
}

fn memoryToolCallList(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8) HttpResponse {
    const query = memoryToolReadQuery(ctx, obj, route_query) catch return serverError(ctx);
    return nullClawAgentMemoryList(ctx, query);
}

fn memoryToolReadQuery(ctx: *Context, obj: std.json.ObjectMap, route_query: []const u8) ![]u8 {
    const fields = [_][]const u8{
        "category",
        "session_id",
        "session",
        "scope",
        "limit",
        "offset",
        "include_global",
        "include_sessions",
        "include_internal",
        "include_content",
        "current_session_id",
        "thread_session_id",
        "storage",
        "store",
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    var first = true;
    if (route_query.len > 0) {
        try out.appendSlice(ctx.allocator, route_query);
        first = false;
    }
    for (fields) |field| {
        if (obj.get(field)) |value| {
            try appendMemoryToolQueryValue(ctx.allocator, &out, &first, field, value);
        }
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn appendMemoryToolQueryValue(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), first: *bool, name: []const u8, value: std.json.Value) !void {
    switch (value) {
        .string => |text| try appendMemoryToolQueryParam(allocator, out, first, name, text),
        .integer => |n| {
            const text = try std.fmt.allocPrint(allocator, "{d}", .{n});
            defer allocator.free(text);
            try appendMemoryToolQueryParam(allocator, out, first, name, text);
        },
        .float => |f| {
            const n = json.safeFloatToI64(f) orelse return;
            const text = try std.fmt.allocPrint(allocator, "{d}", .{n});
            defer allocator.free(text);
            try appendMemoryToolQueryParam(allocator, out, first, name, text);
        },
        .bool => |b| try appendMemoryToolQueryParam(allocator, out, first, name, if (b) "true" else "false"),
        else => {},
    }
}

fn appendMemoryToolQueryParam(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), first: *bool, name: []const u8, value: []const u8) !void {
    const encoded_name = try net_security.percentEncodePathSegment(allocator, name);
    defer allocator.free(encoded_name);
    const encoded_value = try net_security.percentEncodePathSegment(allocator, value);
    defer allocator.free(encoded_value);
    if (!first.*) {
        try out.append(allocator, '&');
    } else {
        first.* = false;
    }
    try out.appendSlice(allocator, encoded_name);
    try out.append(allocator, '=');
    try out.appendSlice(allocator, encoded_value);
}

fn memoryToolCallResponse(ctx: *Context, tool_name: []const u8, response: HttpResponse) HttpResponse {
    if (!std.mem.eql(u8, response.status, "200 OK")) return response;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"tool_name\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, tool_name) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"provider\":\"native\",\"result\":") catch return serverError(ctx);
    if (std.json.validate(ctx.allocator, response.body) catch false) {
        out.appendSlice(ctx.allocator, response.body) catch return serverError(ctx);
    } else {
        json.appendString(&out, ctx.allocator, response.body) catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn agentMemoryDelete(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    const session_id = queryParamDecodedAliasWithCurrentSession(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!api_session_access.writeAllowed(ctx, sid)) return forbidden(ctx);
    }
    const owner_actor_id = if (requested_scope) |scope|
        access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx)
    else
        ctx.actor_id;
    defer if (requested_scope != null) ctx.allocator.free(owner_actor_id);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.kgMemoryRequest(key, storage_target)) {
        const deleted = kgMemoryDeleteKey(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return ok(ctx, "{\"ok\":true}");
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    if (!requestedAgentMemoryScopeReadable(ctx, requested_scope)) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    var deleted = false;
    if (route_includes_kg) {
        deleted = (kgMemoryDeleteKey(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err)) or deleted;
    }
    if (non_kg_storage_target) |route| {
        const entry = api_agent_memory_store.getByInput(ctx, .{
            .key = key,
            .route = route,
            .session_id = session_id,
            .owner_actor_id = owner_actor_id,
            .access = .exact_owner,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (entry) |loaded| {
            if (!agentMemoryEntryVisible(ctx, loaded)) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
            if (!agentMemoryEntryDeletable(ctx, loaded)) return forbidden(ctx);
            deleted = (api_agent_memory_store.delete(ctx, .{
                .key = key,
                .session_id = session_id,
                .owner_actor_id = owner_actor_id,
                .route = route,
            }) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            }) or deleted;
        }
    }
    if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return ok(ctx, "{\"ok\":true}");
}

fn agentMemoryCount(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    if (api_storage_route.targetsKg(storage_target)) {
        const category = json.queryParamDecoded(ctx.allocator, query, "category") catch return serverError(ctx);
        const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
        const entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        const body = std.fmt.allocPrint(ctx.allocator, "{{\"count\":{d}}}", .{entries.len}) catch return serverError(ctx);
        return .{ .status = "200 OK", .body = body };
    }
    const route_includes_kg = api_storage_route.includesKg(storage_target);
    const non_kg_storage_target = api_storage_route.withoutKg(ctx.allocator, storage_target) catch return serverError(ctx);
    var count: usize = 0;
    if (non_kg_storage_target) |route| {
        count += ctx.store.agentMemoryCountByInput(.{
            .actor_id = ctx.actor_id,
            .scopes_json = ctx.actor_scopes_json,
            .capabilities_json = ctx.actor_capabilities_json,
            .route = route,
        }) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    }
    if (route_includes_kg) {
        const category = json.queryParamDecoded(ctx.allocator, query, "category") catch return serverError(ctx);
        const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
        const entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        count += entries.len;
    }
    const body = std.fmt.allocPrint(ctx.allocator, "{{\"count\":{d}}}", .{count}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn agentMemoryListSupportsDirectWindow(route: storage_routes.Route) bool {
    return route.target != .subset and route.target != .all;
}

fn loadAgentMemoryListRoutedWindow(ctx: *Context, category: ?[]const u8, session_id: ?[]const u8, exact_owner: ?[]const u8, route: storage_routes.Route, include_sessions_when_sessionless: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
    if (exact_owner) |owner| {
        return api_agent_memory_store.listByInput(ctx, .{
            .route = route,
            .category = category,
            .session_id = session_id,
            .owner_actor_id = owner,
            .access = .exact_owner,
            .limit = limit,
            .offset = offset,
        });
    }
    const auth = api_agent_memory_store.contextAuth(ctx);
    if (session_id == null and include_sessions_when_sessionless) {
        return api_agent_memory_store.listByInput(ctx, .{
            .route = route,
            .category = category,
            .auth = auth,
            .access = .any_visible,
            .limit = limit,
            .offset = offset,
        });
    }
    return api_agent_memory_store.listByInput(ctx, .{
        .route = route,
        .category = category,
        .session_id = session_id,
        .auth = auth,
        .limit = limit,
        .offset = offset,
    });
}

fn loadAgentMemoryListRoutedFilteredWindow(ctx: *Context, category: ?[]const u8, session_id: ?[]const u8, exact_owner: ?[]const u8, route: storage_routes.Route, include_sessions_when_sessionless: bool, include_internal: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
    if (include_internal) {
        return loadAgentMemoryListRoutedWindow(ctx, category, session_id, exact_owner, route, include_sessions_when_sessionless, limit, offset);
    }
    if (limit == 0) return ctx.allocator.alloc(domain.AgentMemory, 0);

    var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer {
        for (out.items) |*entry| agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
        out.deinit(ctx.allocator);
    }

    const fetch_limit = agentMemoryFilteredWindowFetchLimit(limit);
    var raw_offset: usize = 0;
    var filtered_offset_seen: usize = 0;
    while (true) {
        const page = try loadAgentMemoryListRoutedWindow(ctx, category, session_id, exact_owner, route, include_sessions_when_sessionless, fetch_limit, raw_offset);
        const fetched = page.len;
        if (fetched == 0) {
            ctx.allocator.free(page);
            break;
        }

        for (page) |*entry| {
            if (!agentMemoryEntryVisible(ctx, entry.*) or domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) {
                agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
                continue;
            }
            if (filtered_offset_seen < offset) {
                filtered_offset_seen += 1;
                agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
                continue;
            }
            if (out.items.len >= limit) {
                agent_memory_runtime.freeAgentMemory(ctx.allocator, entry);
                continue;
            }
            try out.append(ctx.allocator, entry.*);
            detachAgentMemoryEntryForMove(entry);
        }
        ctx.allocator.free(page);

        if (out.items.len >= limit or fetched < fetch_limit) break;
        raw_offset = agentMemoryFilteredWindowOffsetAfterFetch(raw_offset, fetched) orelse break;
    }

    return out.toOwnedSlice(ctx.allocator);
}

fn agentMemoryFilteredWindowFetchLimit(limit: usize) usize {
    if (limit == 0) return 0;
    if (limit == std.math.maxInt(usize)) return 512;
    return @min(@as(usize, 512), @max(@as(usize, 64), limit));
}

fn agentMemoryFilteredWindowOffsetAfterFetch(raw_offset: usize, fetched: usize) ?usize {
    if (fetched == 0) return null;
    const next = bounded_int.saturatingUsizeAdd(raw_offset, fetched);
    if (next == raw_offset) return null;
    return next;
}

fn detachAgentMemoryEntryForMove(entry: *domain.AgentMemory) void {
    entry.id = "";
    entry.key = "";
    entry.content = "";
    entry.category = "";
    entry.timestamp = "";
    entry.session_id = null;
    entry.actor_id = "";
    entry.writer_actor_id = "";
    entry.scope = "";
    entry.permissions_json = "";
    entry.status = "";
    entry.store = "";
    entry.score = null;
}

fn appendAgentMemoryEntries(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), entries: []domain.AgentMemory) !void {
    for (entries) |entry| try out.append(allocator, entry);
}

fn recordReturnedAgentMemoryRecallSignals(ctx: *Context, query: []const u8, entries: []const domain.AgentMemory, include_internal: bool, limit: usize, offset: usize) void {
    if (std.mem.trim(u8, query, " \t\r\n").len == 0) return;
    var visible_seen: usize = 0;
    var recorded: usize = 0;
    for (entries) |entry| {
        if (!agentMemoryEntryVisible(ctx, entry)) continue;
        if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
        if (visible_seen < offset) {
            visible_seen += 1;
            continue;
        }
        visible_seen += 1;
        if (recorded >= limit) break;
        if (entry.id.len == 0 or entry.key.len == 0) continue;
        ctx.store.recordMemoryRecallSignal(.{
            .object_type = "agent_memory",
            .object_id = entry.id,
            .object_key = entry.key,
            .scope = entry.scope,
            .permissions_json = entry.permissions_json,
            .actor_id = entry.actor_id,
            .session_id = entry.session_id,
            .store = if (entry.store.len > 0) entry.store else null,
            .query = query,
            .score = entry.score orelse 0,
        }) catch {};
        recorded += 1;
    }
}

fn appendMissingAgentMemoryEntries(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), entries: []domain.AgentMemory) !void {
    for (entries) |entry| {
        if (agentMemoryContains(out.items, entry)) {
            var skipped = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &skipped);
            continue;
        }
        try out.append(allocator, entry);
    }
}

fn dedupeAgentMemoryEntries(allocator: std.mem.Allocator, entries: *std.ArrayListUnmanaged(domain.AgentMemory)) void {
    var write: usize = 0;
    for (entries.items, 0..) |entry, read| {
        if (agentMemoryContains(entries.items[0..write], entry)) {
            var duplicate = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &duplicate);
            continue;
        }
        if (write != read) entries.items[write] = entry;
        write += 1;
    }
    entries.shrinkRetainingCapacity(write);
}

fn agentMemoryContains(entries: []const domain.AgentMemory, needle: domain.AgentMemory) bool {
    for (entries) |entry| {
        if (!std.mem.eql(u8, entry.key, needle.key)) continue;
        if (!std.mem.eql(u8, entry.actor_id, needle.actor_id)) continue;
        if (!optionalStringEql(entry.session_id, needle.session_id)) continue;
        if (!std.mem.eql(u8, entry.scope, needle.scope)) continue;
        if (!std.mem.eql(u8, entry.store, needle.store)) continue;
        return true;
    }
    return false;
}

fn optionalStringEql(a: ?[]const u8, b: ?[]const u8) bool {
    if (a == null and b == null) return true;
    if (a == null or b == null) return false;
    return std.mem.eql(u8, a.?, b.?);
}

fn actorFilter(ctx: *Context) ?[]const u8 {
    return if (domain.hasActorScope(ctx.actor_scopes_json, "admin")) null else ctx.actor_id;
}

fn saveMessage(ctx: *Context, session_id: []const u8, body: []const u8, query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const role = sessionMessageRoleField(obj) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing role");
    const content = json.stringField(obj, "content") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing content");
    const created_at_ms = json.intField(obj, "created_at_ms") orelse ids.nowMs();
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch |err| return storageRouteError(ctx, err);
    ctx.store.saveMessageRoutedAtWithAuth(session_id, role, content, created_at_ms, ctx.actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn loadMessages(ctx: *Context, session_id: []const u8, query: []const u8) HttpResponse {
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    const messages = ctx.store.loadMessagesRoutedWithAuth(ctx.allocator, session_id, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const body = session_responses.renderMessages(ctx.allocator, messages, .{}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn saveUsage(ctx: *Context, session_id: []const u8, body: []const u8, query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const total = json.intField(obj, "total_tokens") orelse 0;
    const storage_target = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch |err| return storageRouteError(ctx, err);
    ctx.store.saveUsageRoutedWithAuth(session_id, agentSessionTotalTokensFromSigned(total), ctx.actor_id, ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn loadUsage(ctx: *Context, session_id: []const u8, query: []const u8) HttpResponse {
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch |err| return storageRouteError(ctx, err);
    const total_opt = ctx.store.loadUsageRoutedWithAuth(session_id, actorFilter(ctx), ctx.actor_capabilities_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const total = total_opt orelse return json.errorResponse(ctx.allocator, 404, "not_found", "No usage for session");
    const body = std.fmt.allocPrint(ctx.allocator, "{{\"total_tokens\":{d}}}", .{total}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn agentSessionTotalTokensFromSigned(total: i64) u64 {
    return bounded_int.nonNegativeI64ToU64(total);
}

