fn appendSearchArray(ctx: *Context, out: *std.ArrayListUnmanaged(u8), results: []domain.SearchResult) !void {
    try out.append(ctx.allocator, '[');
    for (results, 0..) |result, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try result.writeJson(ctx.allocator, out);
    }
    try out.append(ctx.allocator, ']');
}

fn appendSnapshotObjects(ctx: *Context, out: *std.ArrayListUnmanaged(u8), results: []domain.SearchResult) !void {
    try out.append(ctx.allocator, '[');
    for (results, 0..) |result, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try appendSnapshotObject(ctx, out, result);
    }
    try out.append(ctx.allocator, ']');
}

fn appendFullSnapshotObjects(ctx: *Context, out: *std.ArrayListUnmanaged(u8), input: store_mod.PrimitiveListInput, obj: std.json.ObjectMap, route_query: []const u8, counts: *SnapshotTypeCounts) !void {
    try out.append(ctx.allocator, '[');
    var first = true;
    const limit = input.limit;

    if (snapshotExportWantsType(obj, "policy_scope")) {
        const policies = try ctx.store.listPolicyScopes(ctx.allocator, input.scopes_json, limit);
        for (policies) |policy| {
            if (counts.total() >= limit) break;
            if (!recordVisibleToActor(ctx, policy.scope, policy.permissions_json)) continue;
            try appendSnapshotWrappedPolicy(ctx, out, &first, policy);
            counts.add("policy_scope");
        }
    }
    if (snapshotExportWantsType(obj, "space")) {
        const spaces = try ctx.store.listSpaces(ctx.allocator, input.scopes_json, limit);
        for (spaces) |space| {
            if (counts.total() >= limit) break;
            if (!recordVisibleToActor(ctx, space.scope, space.permissions_json)) continue;
            try appendSnapshotWrappedValue(ctx, out, &first, "space", space);
            counts.add("space");
        }
    }
    if (snapshotExportWantsType(obj, "source")) {
        const sources = try ctx.store.listSourcesVisible(ctx.allocator, input);
        for (sources) |source| {
            if (counts.total() >= limit) break;
            try appendSnapshotWrappedValue(ctx, out, &first, "source", source);
            counts.add("source");
        }
    }
    if (snapshotExportWantsType(obj, "entity")) {
        const entities = try ctx.store.listEntitiesVisible(ctx.allocator, input);
        for (entities) |entity| {
            if (counts.total() >= limit) break;
            try appendSnapshotWrappedValue(ctx, out, &first, "entity", entity);
            counts.add("entity");
        }
    }
    if (snapshotExportWantsType(obj, "artifact")) {
        const artifacts_list = try ctx.store.listArtifactsVisible(ctx.allocator, input);
        for (artifacts_list) |artifact| {
            if (counts.total() >= limit) break;
            var copy = artifact;
            copy.source_ids_json = try sanitizeSourceIdsForActor(ctx, artifact.source_ids_json);
            try appendSnapshotWrappedValue(ctx, out, &first, "artifact", copy);
            counts.add("artifact");
        }
    }
    if (snapshotExportWantsType(obj, "memory_atom")) {
        const atoms = try ctx.store.listMemoryAtomsVisible(ctx.allocator, .{
            .limit = limit,
            .scopes_json = input.scopes_json,
            .scope_filter_empty = input.scope_filter_empty,
            .actor_id = input.actor_id,
            .include_deprecated = input.include_deprecated,
        });
        for (atoms) |atom| {
            if (counts.total() >= limit) break;
            var copy = atom;
            copy.source_ids_json = try sanitizeSourceIdsForActor(ctx, atom.source_ids_json);
            try appendSnapshotWrappedValue(ctx, out, &first, "memory_atom", copy);
            counts.add("memory_atom");
        }
    }
    if (snapshotExportWantsType(obj, "relation")) {
        const relations = try ctx.store.listRelationsVisible(ctx.allocator, input);
        for (relations) |relation| {
            if (counts.total() >= limit) break;
            var copy = relation;
            copy.source_ids_json = try sanitizeSourceIdsForActor(ctx, relation.source_ids_json);
            try appendSnapshotWrappedValue(ctx, out, &first, "relation", copy);
            counts.add("relation");
        }
    }
    if (snapshotExportWantsType(obj, "agent_memory")) {
        const include_internal = json.boolField(obj, "include_internal") orelse false;
        const include_sessions = json.boolField(obj, "include_sessions") orelse true;
        const storage_route = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query);
        const auth = api_agent_memory_store.scopedAuth(ctx, input.scopes_json);
        const entries = if (include_sessions)
            try api_agent_memory_store.listByInput(ctx, .{
                .route = storage_route,
                .auth = auth,
                .access = .any_visible,
            })
        else
            try api_agent_memory_store.listByInput(ctx, .{
                .route = storage_route,
                .auth = auth,
            });
        for (entries) |entry| {
            if (counts.total() >= limit) break;
            if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
            if (!agentMemoryEntryVisible(ctx, entry)) continue;
            try appendSnapshotWrappedAgentMemory(ctx, out, &first, entry);
            counts.add("agent_memory");
        }
    }
    if (snapshotExportWantsType(obj, "context_pack")) {
        const packs = try ctx.store.listContextPacksVisible(ctx.allocator, input);
        for (packs) |pack| {
            if (counts.total() >= limit) break;
            try appendSnapshotWrappedContextPack(ctx, out, &first, pack);
            counts.add("context_pack");
        }
    }
    try out.append(ctx.allocator, ']');
}

fn snapshotExportWantsType(obj: std.json.ObjectMap, object_type: []const u8) bool {
    const value = obj.get("object_types") orelse obj.get("types") orelse return true;
    if (value == .array) {
        for (value.array.items) |item| {
            if (item == .string and std.mem.eql(u8, item.string, object_type)) return true;
        }
        return false;
    }
    if (value == .string) return std.mem.eql(u8, value.string, object_type) or std.mem.eql(u8, value.string, "all");
    return true;
}

fn appendSnapshotWrappedValue(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, object_type: []const u8, value: anytype) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try out.appendSlice(ctx.allocator, "{\"object_type\":");
    try json.appendString(out, ctx.allocator, object_type);
    try out.appendSlice(ctx.allocator, ",\"record\":");
    try value.writeJson(ctx.allocator, out);
    try out.append(ctx.allocator, '}');
}

fn appendSnapshotWrappedAgentMemory(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, entry: domain.AgentMemory) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try out.appendSlice(ctx.allocator, "{\"object_type\":\"agent_memory\",\"record\":");
    try entry.writeJsonWithOptions(ctx.allocator, out, .{ .include_storage_alias = false });
    try out.append(ctx.allocator, '}');
}

fn appendSnapshotWrappedPolicy(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, policy: store_mod.PolicyScope) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try out.appendSlice(ctx.allocator, "{\"object_type\":\"policy_scope\",\"record\":");
    try policy.writeJson(ctx.allocator, out);
    try out.append(ctx.allocator, '}');
}

fn appendSnapshotWrappedContextPack(ctx: *Context, out: *std.ArrayListUnmanaged(u8), first: *bool, pack: store_mod.ContextPackResult) !void {
    if (!first.*) try out.append(ctx.allocator, ',');
    first.* = false;
    try out.appendSlice(ctx.allocator, "{\"object_type\":\"context_pack\",\"record\":");
    try appendContextPackSnapshotRecord(ctx, out, pack);
    try out.append(ctx.allocator, '}');
}

const snapshot_package_default_limit: usize = 1000;
const snapshot_package_max_limit: usize = 5000;

fn snapshotPackageLimit(value: ?i64) usize {
    const raw = value orelse return snapshot_package_default_limit;
    if (raw <= 0) return 0;
    return bounded_int.positiveI64ToUsizeBounded(raw, snapshot_package_max_limit);
}

test "api snapshot package limit preserves defaults and caps request values" {
    try std.testing.expectEqual(snapshot_package_default_limit, snapshotPackageLimit(null));
    try std.testing.expectEqual(@as(usize, 0), snapshotPackageLimit(-1));
    try std.testing.expectEqual(@as(usize, 0), snapshotPackageLimit(0));
    try std.testing.expectEqual(@as(usize, 42), snapshotPackageLimit(42));
    try std.testing.expectEqual(snapshot_package_max_limit, snapshotPackageLimit(std.math.maxInt(i64)));
}

fn snapshotPackageChecksum(allocator: std.mem.Allocator, objects_json: []const u8) ![]const u8 {
    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
    hasher.update("nullpantry.snapshot.v1\n");
    hasher.update(objects_json);
    var digest: [32]u8 = undefined;
    hasher.final(&digest);
    const hex_chars = "0123456789abcdef";
    var hex: [64]u8 = undefined;
    for (digest, 0..) |byte, i| {
        hex[i * 2] = hex_chars[byte >> 4];
        hex[i * 2 + 1] = hex_chars[byte & 0x0f];
    }
    return std.fmt.allocPrint(allocator, "sha256:{s}", .{hex[0..]});
}

fn snapshotFullSummaryJson(ctx: *Context, scopes_json: []const u8, object_count: usize, truncated: bool, counts_json: []const u8, checksum: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);

    try out.appendSlice(ctx.allocator, "{\"mode\":\"full\",\"scopes\":");
    try json.appendRawJsonArray(&out, ctx.allocator, scopes_json);
    try out.print(ctx.allocator, ",\"object_count\":{d},\"truncated\":{s},\"counts\":", .{ object_count, if (truncated) "true" else "false" });
    try json.appendRawJsonObject(&out, ctx.allocator, counts_json);
    try out.appendSlice(ctx.allocator, ",\"package_checksum\":");
    try json.appendString(&out, ctx.allocator, checksum);
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn appendSnapshotManifest(ctx: *Context, out: *std.ArrayListUnmanaged(u8), mode: []const u8, snapshot_id: []const u8, snapshot_type: []const u8, scopes_json: []const u8, object_count: usize, truncated: bool, summary_json: []const u8, checksum: ?[]const u8) !void {
    try out.appendSlice(ctx.allocator, "{\"schema_version\":\"nullpantry.snapshot.v1\",\"snapshot_id\":");
    try json.appendString(out, ctx.allocator, snapshot_id);
    try out.appendSlice(ctx.allocator, ",\"snapshot_type\":");
    try json.appendString(out, ctx.allocator, snapshot_type);
    try out.appendSlice(ctx.allocator, ",\"mode\":");
    try json.appendString(out, ctx.allocator, mode);
    try out.appendSlice(ctx.allocator, ",\"scopes\":");
    try json.appendRawJsonArray(out, ctx.allocator, scopes_json);
    try out.print(ctx.allocator, ",\"object_count\":{d},\"truncated\":{s}", .{ object_count, if (truncated) "true" else "false" });
    try out.appendSlice(ctx.allocator, ",\"object_types\":[\"policy_scope\",\"space\",\"source\",\"entity\",\"artifact\",\"memory_atom\",\"relation\",\"agent_memory\",\"context_pack\"],\"covered_state\":[\"knowledge_primitives\",\"agent_memory\",\"context_packs\"],\"unsupported_state\":[\"vector_chunks\",\"external_vector_store_state\",\"response_cache\",\"semantic_cache\",\"embedding_cache\",\"feed_events\",\"feed_checkpoints\",\"jobs\",\"connector_cursors\",\"sessions\",\"usage\",\"conflicts\",\"analytics_projection\",\"lifecycle_snapshot_records\",\"attachments_blob_payloads\"],\"hydrate_order\":[\"policy_scope\",\"space\",\"source\",\"entity\",\"artifact\",\"memory_atom\",\"relation\",\"agent_memory\",\"context_pack\"],\"import_contract\":{\"idempotent\":true,\"default_conflict_policy\":\"skip\",\"atomic_multi_type\":false,\"atomic_memory_atom_batch\":true,\"post_hydrate_reindex_required\":true},\"summary\":");
    try json.appendRawJsonObject(out, ctx.allocator, summary_json);
    if (checksum) |value| {
        try out.appendSlice(ctx.allocator, ",\"package_checksum\":");
        try json.appendString(out, ctx.allocator, value);
    }
    try out.append(ctx.allocator, '}');
}

test "api snapshot summary and manifest preserve raw JSON fields" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    const summary = try snapshotFullSummaryJson(&ctx, "[\"project:alpha\"]", 3, false, "{\"memory_atom\":2,\"source\":1}", "sha256:test");
    defer std.testing.allocator.free(summary);
    try std.testing.expect(std.mem.indexOf(u8, summary, "\"scopes\":[\"project:alpha\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, summary, "\"counts\":{\"memory_atom\":2,\"source\":1}") != null);

    var manifest: std.ArrayListUnmanaged(u8) = .empty;
    defer manifest.deinit(std.testing.allocator);
    try appendSnapshotManifest(&ctx, &manifest, "full", "snap_1", "full_export", "[\"project:alpha\"]", 3, false, summary, "sha256:test");
    try std.testing.expect(std.mem.indexOf(u8, manifest.items, "\"scopes\":[\"project:alpha\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, manifest.items, "\"summary\":{\"mode\":\"full\"") != null);
}

test "api snapshot summary and manifest reject malformed raw JSON fields" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };

    try std.testing.expectError(error.InvalidRawJson, snapshotFullSummaryJson(&ctx, "{\"scope\":\"project:alpha\"}", 1, false, "{}", "sha256:test"));
    try std.testing.expectError(error.InvalidRawJson, snapshotFullSummaryJson(&ctx, "[]", 1, false, "[]", "sha256:test"));

    var bad_scopes: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_scopes.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendSnapshotManifest(&ctx, &bad_scopes, "query", "snap_bad", "export", "{\"scope\":\"project:alpha\"}", 1, false, "{}", null));

    var bad_summary: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_summary.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendSnapshotManifest(&ctx, &bad_summary, "query", "snap_bad", "export", "[]", 1, false, "[]", null));
}

fn exportResultIsInternal(result: domain.SearchResult) bool {
    if (std.mem.eql(u8, result.result_type, "agent_memory")) {
        return domain.isInternalMemoryEntryKeyOrContent(result.title, result.text);
    }
    if (std.mem.eql(u8, result.result_type, "session_message")) {
        const sep = std.mem.lastIndexOfScalar(u8, result.title, ':') orelse return false;
        const role = result.title[sep + 1 ..];
        return domain.isAutosaveSessionRole(role) or !domain.sessionMessageVisibleInHistory(role);
    }
    return false;
}

fn appendJsonlExportRecord(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult, include_pii: bool) !void {
    if (std.mem.eql(u8, result.result_type, "agent_memory")) {
        if (try routedAgentMemorySnapshotEntry(ctx, result)) |entry| {
            try appendAgentMemoryDatasetJsonlRecord(ctx, out, result, entry, include_pii);
            return;
        }
    }

    const title = if (include_pii) result.title else try redactExportText(ctx.allocator, result.title);
    const content = if (include_pii) result.text else try redactExportText(ctx.allocator, result.text);
    try out.appendSlice(ctx.allocator, "{\"schema_version\":\"nullpantry.memory_jsonl.v1\",\"id\":");
    try json.appendString(out, ctx.allocator, result.id);
    try out.appendSlice(ctx.allocator, ",\"key\":");
    try json.appendString(out, ctx.allocator, result.id);
    try out.appendSlice(ctx.allocator, ",\"object_type\":");
    try json.appendString(out, ctx.allocator, result.result_type);
    try out.appendSlice(ctx.allocator, ",\"category\":");
    try json.appendString(out, ctx.allocator, result.result_type);
    try out.appendSlice(ctx.allocator, ",\"title\":");
    try json.appendString(out, ctx.allocator, title);
    try out.appendSlice(ctx.allocator, ",\"content\":");
    try json.appendString(out, ctx.allocator, content);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, result.scope);
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(out, ctx.allocator, result.status);
    try out.print(ctx.allocator, ",\"timestamp\":{d},\"created_at_ms\":{d},\"score\":{d},\"confidence\":{d},\"actor_isolated\":{s}", .{ result.created_at_ms, result.created_at_ms, result.score, result.confidence, if (result.actor_isolated) "true" else "false" });
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(out, ctx.allocator, exportResultSessionId(result));
    if (result.store.len > 0) {
        try out.appendSlice(ctx.allocator, ",\"store\":");
        try json.appendString(out, ctx.allocator, result.store);
        try out.appendSlice(ctx.allocator, ",\"storage\":");
        try json.appendString(out, ctx.allocator, result.store);
    }
    try appendJsonlResultAccessFields(ctx, out, result);
    try out.appendSlice(ctx.allocator, ",\"pii_redacted\":");
    try out.appendSlice(ctx.allocator, if (include_pii) "false" else "true");
    try out.append(ctx.allocator, '}');
}

fn appendAgentMemoryDatasetJsonlRecord(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult, entry: domain.AgentMemory, include_pii: bool) !void {
    const key = if (include_pii) entry.key else try redactExportText(ctx.allocator, entry.key);
    const title = if (include_pii) result.title else try redactExportText(ctx.allocator, result.title);
    const content = if (include_pii) entry.content else try redactExportText(ctx.allocator, entry.content);
    const timestamp_ms = std.fmt.parseInt(i64, entry.timestamp, 10) catch result.created_at_ms;
    try out.appendSlice(ctx.allocator, "{\"schema_version\":\"nullpantry.memory_jsonl.v1\",\"id\":");
    try json.appendString(out, ctx.allocator, result.id);
    try out.appendSlice(ctx.allocator, ",\"key\":");
    try json.appendString(out, ctx.allocator, key);
    try out.appendSlice(ctx.allocator, ",\"object_type\":\"agent_memory\",\"category\":");
    try json.appendString(out, ctx.allocator, entry.category);
    try out.appendSlice(ctx.allocator, ",\"title\":");
    try json.appendString(out, ctx.allocator, title);
    try out.appendSlice(ctx.allocator, ",\"content\":");
    try json.appendString(out, ctx.allocator, content);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, entry.scope);
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(out, ctx.allocator, if (entry.status.len > 0) entry.status else result.status);
    try out.print(ctx.allocator, ",\"timestamp\":{d},\"created_at_ms\":{d},\"score\":{d},\"confidence\":{d},\"actor_isolated\":{s}", .{ timestamp_ms, timestamp_ms, result.score, result.confidence, if (result.actor_isolated) "true" else "false" });
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(out, ctx.allocator, entry.session_id);
    try out.appendSlice(ctx.allocator, ",\"owner_id\":");
    try json.appendString(out, ctx.allocator, entry.actor_id);
    try out.appendSlice(ctx.allocator, ",\"created_by_actor_id\":");
    try json.appendString(out, ctx.allocator, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
    if (entry.store.len > 0) {
        try out.appendSlice(ctx.allocator, ",\"store\":");
        try json.appendString(out, ctx.allocator, entry.store);
        try out.appendSlice(ctx.allocator, ",\"storage\":");
        try json.appendString(out, ctx.allocator, entry.store);
    } else if (result.store.len > 0) {
        try out.appendSlice(ctx.allocator, ",\"store\":");
        try json.appendString(out, ctx.allocator, result.store);
        try out.appendSlice(ctx.allocator, ",\"storage\":");
        try json.appendString(out, ctx.allocator, result.store);
    }
    try appendJsonlResultAccessFields(ctx, out, result);
    try out.appendSlice(ctx.allocator, ",\"pii_redacted\":");
    try out.appendSlice(ctx.allocator, if (include_pii) "false" else "true");
    try out.append(ctx.allocator, '}');
}

fn appendJsonlResultAccessFields(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult) !void {
    try out.appendSlice(ctx.allocator, ",\"required_scopes\":");
    try json.appendRawJsonArray(out, ctx.allocator, result.required_scopes_json);
    try out.appendSlice(ctx.allocator, ",\"citations\":");
    try json.appendRawJsonArray(out, ctx.allocator, result.source_ids_json);
}

test "api jsonl export records preserve and reject raw access arrays" {
    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = undefined,
    };
    const result = domain.SearchResult{
        .id = "mem_1",
        .result_type = "memory_atom",
        .title = "Decision",
        .text = "Decision: export access metadata.",
        .scope = "public",
        .status = "verified",
        .score = 1.0,
        .source_ids_json = "[\"src_1\"]",
        .required_scopes_json = "[\"public\"]",
        .created_at_ms = 42,
        .confidence = 0.9,
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(std.testing.allocator);
    try appendJsonlExportRecord(&ctx, &out, result, true);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"required_scopes\":[\"public\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, out.items, "\"citations\":[\"src_1\"]") != null);

    var bad_required = result;
    bad_required.required_scopes_json = "{\"scope\":\"public\"}";
    var bad_required_out: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_required_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendJsonlExportRecord(&ctx, &bad_required_out, bad_required, true));

    var bad_citations = result;
    bad_citations.source_ids_json = "{\"id\":\"src_1\"}";
    var bad_citations_out: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_citations_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendJsonlExportRecord(&ctx, &bad_citations_out, bad_citations, true));

    const entry = domain.AgentMemory{
        .id = "agm_1",
        .key = "pref.export",
        .content = "Exported agent memory",
        .category = "core",
        .timestamp = "42",
        .session_id = null,
        .actor_id = "agent:owner",
        .scope = "public",
        .status = "active",
    };
    var agent_out: std.ArrayListUnmanaged(u8) = .empty;
    defer agent_out.deinit(std.testing.allocator);
    try appendAgentMemoryDatasetJsonlRecord(&ctx, &agent_out, result, entry, true);
    try std.testing.expect(std.mem.indexOf(u8, agent_out.items, "\"key\":\"pref.export\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, agent_out.items, "\"required_scopes\":[\"public\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, agent_out.items, "\"citations\":[\"src_1\"]") != null);

    var bad_agent_required = result;
    bad_agent_required.required_scopes_json = "{\"scope\":\"public\"}";
    var bad_agent_required_out: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_agent_required_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendAgentMemoryDatasetJsonlRecord(&ctx, &bad_agent_required_out, bad_agent_required, entry, true));

    var bad_agent_citations = result;
    bad_agent_citations.source_ids_json = "{\"id\":\"src_1\"}";
    var bad_agent_citations_out: std.ArrayListUnmanaged(u8) = .empty;
    defer bad_agent_citations_out.deinit(std.testing.allocator);
    try std.testing.expectError(error.InvalidRawJson, appendAgentMemoryDatasetJsonlRecord(&ctx, &bad_agent_citations_out, bad_agent_citations, entry, true));
}

fn exportResultSessionId(result: domain.SearchResult) ?[]const u8 {
    if (!std.mem.eql(u8, result.result_type, "session_message")) return null;
    const sep = std.mem.lastIndexOfScalar(u8, result.title, ':') orelse return null;
    if (sep == 0) return null;
    return result.title[0..sep];
}

fn redactExportText(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < text.len) {
        if (std.ascii.isWhitespace(text[i])) {
            try out.append(allocator, text[i]);
            i += 1;
            continue;
        }
        const start = i;
        while (i < text.len and !std.ascii.isWhitespace(text[i])) : (i += 1) {}
        const token = text[start..i];
        if (looksLikeEmailToken(token)) {
            try out.appendSlice(allocator, "[REDACTED_EMAIL]");
        } else if (looksLikeSecretToken(token)) {
            try out.appendSlice(allocator, "[REDACTED_SECRET]");
        } else {
            try out.appendSlice(allocator, token);
        }
    }
    return out.toOwnedSlice(allocator);
}

fn looksLikeEmailToken(token: []const u8) bool {
    const trimmed = std.mem.trim(u8, token, ".,;:()[]{}<>\"'");
    const at = std.mem.indexOfScalar(u8, trimmed, '@') orelse return false;
    if (at == 0 or at + 1 >= trimmed.len) return false;
    const local = trimmed[0..at];
    const domain_part = trimmed[at + 1 ..];
    if (std.mem.indexOfScalar(u8, domain_part, '.') == null) return false;
    if (std.mem.indexOfAny(u8, local, "/\\") != null) return false;
    if (std.mem.indexOfAny(u8, domain_part, "/\\") != null) return false;
    return true;
}

fn looksLikeSecretToken(token: []const u8) bool {
    const trimmed = std.mem.trim(u8, token, ".,;:()[]{}<>\"'");
    if (trimmed.len == 0) return false;
    if (std.ascii.startsWithIgnoreCase(trimmed, "sk-")) return true;
    if (std.ascii.startsWithIgnoreCase(trimmed, "ghp_")) return true;
    if (std.ascii.startsWithIgnoreCase(trimmed, "github_pat_")) return true;
    if (std.ascii.startsWithIgnoreCase(trimmed, "xoxb-")) return true;
    if (std.ascii.startsWithIgnoreCase(trimmed, "xoxp-")) return true;
    if (std.ascii.startsWithIgnoreCase(trimmed, "pat_")) return true;
    if (std.ascii.indexOfIgnoreCase(trimmed, "api_key=") != null) return true;
    if (std.ascii.indexOfIgnoreCase(trimmed, "apikey=") != null) return true;
    if (std.ascii.indexOfIgnoreCase(trimmed, "password=") != null) return true;
    if (std.ascii.indexOfIgnoreCase(trimmed, "token=") != null) return true;
    if (std.ascii.indexOfIgnoreCase(trimmed, "secret=") != null) return true;
    if (trimmed.len < 24) return false;
    var has_alpha = false;
    var has_digit = false;
    var has_secret_symbol = false;
    for (trimmed) |ch| {
        if (std.ascii.isAlphabetic(ch)) has_alpha = true;
        if (std.ascii.isDigit(ch)) has_digit = true;
        if (ch == '_' or ch == '-' or ch == '.') has_secret_symbol = true;
    }
    return has_alpha and has_digit and has_secret_symbol;
}

fn appendSnapshotObject(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult) !void {
    try out.appendSlice(ctx.allocator, "{\"object_type\":");
    try json.appendString(out, ctx.allocator, result.result_type);
    try out.appendSlice(ctx.allocator, ",\"record\":");
    const wrote_record = try appendSnapshotFullRecord(ctx, out, result);
    if (!wrote_record) try result.writeJson(ctx.allocator, out);
    try out.appendSlice(ctx.allocator, ",\"search_result\":");
    try result.writeJson(ctx.allocator, out);
    try out.append(ctx.allocator, '}');
}

fn appendSnapshotFullRecord(ctx: *Context, out: *std.ArrayListUnmanaged(u8), result: domain.SearchResult) !bool {
    if (std.mem.eql(u8, result.result_type, "source")) {
        const source = (try ctx.store.getSource(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return false;
        try source.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "artifact")) {
        var artifact = (try ctx.store.getArtifact(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return false;
        artifact.source_ids_json = try sanitizeSourceIdsForActor(ctx, artifact.source_ids_json);
        try artifact.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "memory_atom")) {
        var atom = (try ctx.store.getMemoryAtom(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, atom.scope, atom.permissions_json)) return false;
        atom.source_ids_json = try sanitizeSourceIdsForActor(ctx, atom.source_ids_json);
        try atom.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "entity")) {
        const entity = (try ctx.store.getEntity(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, entity.scope, entity.permissions_json)) return false;
        try entity.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "relation")) {
        var relation = (try ctx.store.getRelation(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, relation.scope, relation.permissions_json)) return false;
        relation.source_ids_json = try sanitizeSourceIdsForActor(ctx, relation.source_ids_json);
        try relation.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "space")) {
        const space = (try ctx.store.getSpace(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, space.scope, space.permissions_json)) return false;
        try space.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "policy_scope")) {
        const policy = (try ctx.store.getPolicyScope(ctx.allocator, result.id)) orelse return false;
        if (!recordVisibleToActor(ctx, policy.scope, policy.permissions_json)) return false;
        try policy.writeJson(ctx.allocator, out);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "context_pack")) {
        const pack = (try ctx.store.contextPackById(ctx.allocator, result.id)) orelse return false;
        _ = (try ctx.store.contextPackLifecycleTarget(ctx.allocator, result.id, ctx.actor_id, ctx.actor_scopes_json)) orelse return false;
        try appendContextPackSnapshotRecord(ctx, out, pack);
        return true;
    }
    if (std.mem.eql(u8, result.result_type, "agent_memory")) {
        const entry = (try ctx.store.agentMemoryById(ctx.allocator, result.id)) orelse
            (try routedAgentMemorySnapshotEntry(ctx, result) orelse return false);
        if (!agentMemoryEntryVisible(ctx, entry)) return false;
        if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) return false;
        try entry.writeJson(ctx.allocator, out);
        return true;
    }
    return false;
}

fn routedAgentMemorySnapshotEntry(ctx: *Context, result: domain.SearchResult) !?domain.AgentMemory {
    const key = try agentMemoryKeyFromSearchResult(ctx.allocator, result);
    defer ctx.allocator.free(key);
    var route = storage_routes.Route.parse(if (result.store.len > 0) result.store else null);
    defer route.deinit(ctx.allocator);
    return ctx.store.agentMemoryGetByInput(ctx.allocator, .{
        .key = key,
        .session_id = result.session_id,
        .actor_id = ctx.actor_id,
        .scopes_json = ctx.actor_scopes_json,
        .capabilities_json = ctx.actor_capabilities_json,
        .route = route,
        .access = .visible,
    });
}

