fn agentMemoryKeyFromSearchResult(allocator: std.mem.Allocator, result: domain.SearchResult) ![]const u8 {
    if (std.mem.startsWith(u8, result.title, "agent_memory:") and result.title.len > "agent_memory:".len) {
        return allocator.dupe(u8, result.title["agent_memory:".len..]);
    }
    if (std.mem.startsWith(u8, result.id, "agent_memory:")) {
        const rest = result.id["agent_memory:".len..];
        if (std.mem.indexOfScalar(u8, rest, ':')) |store_sep| {
            if (store_sep + 1 < rest.len) return allocator.dupe(u8, rest[store_sep + 1 ..]);
        }
        if (rest.len > 0) return allocator.dupe(u8, rest);
    }
    return allocator.dupe(u8, result.title);
}

fn appendContextPackSnapshotRecord(ctx: *Context, out: *std.ArrayListUnmanaged(u8), pack: store_mod.ContextPackResult) !void {
    const scope = try contextPackSnapshotScope(ctx.allocator, pack);
    defer ctx.allocator.free(scope);
    const permissions = try contextPackSnapshotPermissions(ctx.allocator, pack);
    defer ctx.allocator.free(permissions);
    try out.appendSlice(ctx.allocator, "{\"id\":");
    try json.appendString(out, ctx.allocator, pack.id);
    try out.appendSlice(ctx.allocator, ",\"object_type\":\"context_pack\",\"purpose\":");
    try json.appendString(out, ctx.allocator, pack.purpose);
    try out.appendSlice(ctx.allocator, ",\"target\":");
    try json.appendString(out, ctx.allocator, pack.target);
    try out.appendSlice(ctx.allocator, ",\"query\":");
    try json.appendString(out, ctx.allocator, pack.query);
    try out.appendSlice(ctx.allocator, ",\"task\":");
    try json.appendString(out, ctx.allocator, pack.query);
    try out.appendSlice(ctx.allocator, ",\"generated_summary\":");
    try json.appendString(out, ctx.allocator, pack.generated_summary);
    try appendRawJsonObjectField(ctx.allocator, out, "sections", pack.sections_json);
    try appendRawJsonArrayField(ctx.allocator, out, "citations", pack.citations_json);
    try appendRawJsonArrayField(ctx.allocator, out, "forbidden_assumptions", pack.forbidden_assumptions_json);
    try appendRawJsonArrayField(ctx.allocator, out, "suggested_next_steps", pack.suggested_next_steps_json);
    try out.appendSlice(ctx.allocator, ",\"token_budget\":");
    try out.print(ctx.allocator, "{d}", .{pack.token_budget});
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, scope);
    try appendRawJsonArrayField(ctx.allocator, out, "permissions", permissions);
    try appendRawJsonArrayField(ctx.allocator, out, "scopes", pack.required_scopes_json);
    try appendRawJsonArrayField(ctx.allocator, out, "required_scopes", pack.required_scopes_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_sources", pack.included_sources_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_artifacts", pack.included_artifacts_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_memory_atoms", pack.included_memory_atoms_json);
    try appendRawJsonArrayField(ctx.allocator, out, "included_result_refs", pack.included_result_refs_json);
    try out.appendSlice(ctx.allocator, ",\"actor_id\":");
    try json.appendNullableString(out, ctx.allocator, pack.actor_id);
    try out.appendSlice(ctx.allocator, ",\"actor_isolated\":");
    try out.appendSlice(ctx.allocator, if (pack.actor_isolated) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"created_at_ms\":");
    try out.print(ctx.allocator, "{d}", .{pack.created_at_ms});
    try out.append(ctx.allocator, '}');
}

fn contextPackSnapshotScope(allocator: std.mem.Allocator, pack: store_mod.ContextPackResult) ![]const u8 {
    if (pack.actor_isolated) {
        if (pack.actor_id) |actor| return domain.defaultAgentMemoryScope(allocator, actor);
    }
    return access.scopeFromRequiredScopesJson(allocator, pack.required_scopes_json);
}

fn contextPackSnapshotPermissions(allocator: std.mem.Allocator, pack: store_mod.ContextPackResult) ![]const u8 {
    if (pack.actor_isolated) {
        if (pack.actor_id) |actor| return domain.actorGrantJson(allocator, actor);
    }
    const scope = try contextPackSnapshotScope(allocator, pack);
    defer allocator.free(scope);
    return access.permissionsJsonFromRequiredAccessJson(allocator, scope, pack.required_scopes_json);
}

test "api context pack snapshot separates scope from permissions" {
