    try out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"next_local_origin_sequence\":{d},\"visible_events\":{d},\"pending_events\":{d},\"applying_events\":{d},\"applied_events\":{d}}}", .{
        status.cursor_floor,
        status.cursor_floor,
        oldest_available_sequence,
        status.max_event_id,
        status.max_event_id,
        next_local_origin_sequence,
        status.visible_events,
        status.pending_events,
        status.applying_events,
        status.applied_events,
    });
}

const FeedWireMode = enum {
    native,
    nullclaw_agent_memory,
};

fn appendFeedEventsForActor(ctx: *Context, out: *std.ArrayListUnmanaged(u8), events: []store_mod.FeedEvent) !usize {
    return appendFeedEventsForActorMode(ctx, out, events, .native);
}

fn appendFeedEventsForActorMode(ctx: *Context, out: *std.ArrayListUnmanaged(u8), events: []store_mod.FeedEvent, mode: FeedWireMode) !usize {
    var written: usize = 0;
    for (events) |event| {
        if (!feedRecordVisibleToActor(ctx, event.scope, event.permissions_json)) continue;
        if (!try feedEventRenderableInMode(ctx, event, mode)) continue;
        if (written > 0) try out.append(ctx.allocator, ',');
        try appendFeedEventForActorMode(ctx, out, event, mode);
        written += 1;
    }
    return written;
}

fn feedEventRenderableInMode(ctx: *Context, event: store_mod.FeedEvent, mode: FeedWireMode) !bool {
    if (mode != .nullclaw_agent_memory) return true;
    if (!std.mem.eql(u8, event.object_type, "agent_memory")) return false;
    const wire_operation = feed_contract.wireOperation(event.object_type, event.operation, true);
    if (!feed_contract.nullClawMemoryOperationSupported(wire_operation)) return false;
    const payload_json = try feedPayloadForActor(ctx, event);
    if (try feed_contract.payloadIsRedacted(ctx.allocator, payload_json)) return false;
    var parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{}) catch return false;
    defer parsed.deinit();
    return parsed.value == .object;
}

fn appendFeedEventForActor(ctx: *Context, out: *std.ArrayListUnmanaged(u8), event: store_mod.FeedEvent) !void {
    return appendFeedEventForActorMode(ctx, out, event, .native);
}

fn appendFeedEventForActorMode(ctx: *Context, out: *std.ArrayListUnmanaged(u8), event: store_mod.FeedEvent, mode: FeedWireMode) !void {
    const payload_json = try feedPayloadForActor(ctx, event);
    const origin = feed_contract.originIdentity(event.dedupe_key, ctx.feed_instance_id, event.id);
    const timestamp_ms = try feed_contract.timestampMsFromCausality(ctx.allocator, event.causality_json, event.created_at_ms);
    const wire_operation = feed_contract.wireOperation(event.object_type, event.operation, mode == .nullclaw_agent_memory);
    try out.print(ctx.allocator, "{{\"id\":{d},\"event_type\":", .{event.id});
    try json.appendString(out, ctx.allocator, event.event_type);
    try out.print(ctx.allocator, ",\"sequence\":{d},\"origin_instance_id\":", .{event.id});
    try json.appendString(out, ctx.allocator, origin.instance_id);
    try out.print(ctx.allocator, ",\"origin_sequence\":{d}", .{origin.sequence});
    try out.print(ctx.allocator, ",\"schema_version\":1,\"timestamp_ms\":{d}", .{timestamp_ms});
    try out.appendSlice(ctx.allocator, ",\"operation\":");
    try json.appendString(out, ctx.allocator, wire_operation);
    try out.appendSlice(ctx.allocator, ",\"object_type\":");
    try json.appendString(out, ctx.allocator, event.object_type);
    try out.appendSlice(ctx.allocator, ",\"object_id\":");
    try json.appendString(out, ctx.allocator, event.object_id);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, event.scope);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonArray(out, ctx.allocator, event.permissions_json);
    try out.appendSlice(ctx.allocator, ",\"actor_id\":");
    try json.appendNullableString(out, ctx.allocator, event.actor_id);
    try out.appendSlice(ctx.allocator, ",\"dedupe_key\":");
    try json.appendNullableString(out, ctx.allocator, event.dedupe_key);
    try out.appendSlice(ctx.allocator, ",\"causality\":");
    try json.appendRawJsonObject(out, ctx.allocator, event.causality_json);
    try out.appendSlice(ctx.allocator, ",\"payload\":");
    try json.appendRawJsonObject(out, ctx.allocator, payload_json);
    try feed_contract.appendAgentMemoryCompatFields(ctx.allocator, out, event.object_type, event.object_id, payload_json, wire_operation);
    try out.appendSlice(ctx.allocator, ",\"status\":");
    try json.appendString(out, ctx.allocator, event.status);
    try out.print(ctx.allocator, ",\"created_at_ms\":{d},\"applied_at_ms\":", .{event.created_at_ms});
    if (event.applied_at_ms) |v| try out.print(ctx.allocator, "{d}", .{v}) else try out.appendSlice(ctx.allocator, "null");
    try out.appendSlice(ctx.allocator, ",\"compacted_at_ms\":");
    if (event.compacted_at_ms) |v| try out.print(ctx.allocator, "{d}", .{v}) else try out.appendSlice(ctx.allocator, "null");
    try out.append(ctx.allocator, '}');
}

