fn feedPayloadJson(allocator: std.mem.Allocator, obj: std.json.ObjectMap) ![]const u8 {
    if (obj.get("payload")) |value| {
        if (try memoryEventPayloadObjectJsonField(allocator, "payload", value)) |payload_json| return payload_json;
    }
    if (obj.get("payload_json")) |value| {
        if (try memoryEventPayloadObjectJsonField(allocator, "payload_json", value)) |payload_json| return payload_json;
    }
    return allocator.dupe(u8, "{}");
}

fn normalizeArtifactFieldsJson(ctx: *Context, obj: std.json.ObjectMap, artifact_type: []const u8) ![]const u8 {
    const fields_obj = try artifactFieldsObject(obj);
    const required = artifacts.requiredFields(artifact_type);
    for (required) |field| {
        const value = artifactFieldValue(obj, fields_obj, field) orelse return error.MissingRequiredField;
        if (!artifactFieldUsable(value)) return error.MissingRequiredField;
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '{');
    var first = true;
    if (fields_obj) |fields| {
        var iterator = fields.iterator();
        while (iterator.next()) |entry| {
            if (!first) try out.append(ctx.allocator, ',');
            first = false;
            try json.appendString(&out, ctx.allocator, entry.key_ptr.*);
            try out.append(ctx.allocator, ':');
            try appendJsonValue(ctx.allocator, &out, entry.value_ptr.*);
        }
    }
    for (required) |field| {
        if (fields_obj != null and objectHasField(fields_obj.?, field)) continue;
        const value = obj.get(field) orelse continue;
        if (!first) try out.append(ctx.allocator, ',');
        first = false;
        try json.appendString(&out, ctx.allocator, field);
        try out.append(ctx.allocator, ':');
        try appendJsonValue(ctx.allocator, &out, value);
    }
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn artifactFieldsObject(obj: std.json.ObjectMap) !?std.json.ObjectMap {
    const value = obj.get("fields") orelse return null;
    return switch (value) {
        .object => |fields| fields,
        .null => null,
        else => error.InvalidPayload,
    };
}

fn artifactFieldValue(obj: std.json.ObjectMap, fields_obj: ?std.json.ObjectMap, name: []const u8) ?std.json.Value {
    if (fields_obj) |fields| {
        if (fields.get(name)) |value| return value;
    }
    return obj.get(name);
}

fn artifactFieldUsable(value: std.json.Value) bool {
    return switch (value) {
        .null => false,
        .string => |text| std.mem.trim(u8, text, " \t\r\n").len > 0,
        else => true,
    };
}

fn objectHasField(obj: std.json.ObjectMap, name: []const u8) bool {
    return obj.get(name) != null;
}

fn appendJsonValue(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), value: std.json.Value) !void {
    const encoded = try json.jsonFromValue(allocator, value);
    defer allocator.free(encoded);
    try out.appendSlice(allocator, encoded);
}

fn dupOptional(allocator: std.mem.Allocator, value: ?[]const u8) !?[]const u8 {
    return if (value) |v| try allocator.dupe(u8, v) else null;
}

fn graphSemanticCacheSalt(ctx: *Context, obj: std.json.ObjectMap, query: []const u8) ![]const u8 {
    const command_opt = try graph_mod.parseCommand(ctx.allocator, query);
    if (command_opt == null) return try ctx.allocator.dupe(u8, "none");
    var command = command_opt.?;
    defer command.deinit(ctx.allocator);

    var options = try graphTraversalOptions(ctx, obj);
    if (command.kind == .traverse and json.stringField(obj, "direction") == null) {
        options.direction = .outbound;
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.appendSlice(ctx.allocator, "command;");
    try appendSemanticSaltField(ctx.allocator, &out, "kind", @tagName(command.kind));
    switch (command.kind) {
        .traverse, .relations => try appendSemanticSaltField(ctx.allocator, &out, "entity", command.entity_id orelse return error.InvalidGraphCommand),
        .path => {
            try appendSemanticSaltField(ctx.allocator, &out, "from", command.from_entity_id orelse return error.InvalidGraphCommand);
            try appendSemanticSaltField(ctx.allocator, &out, "to", command.to_entity_id orelse return error.InvalidGraphCommand);
        },
    }
    const depth_text = try std.fmt.allocPrint(ctx.allocator, "{d}", .{graphDepthFromSize(command.max_depth)});
    defer ctx.allocator.free(depth_text);
    try appendSemanticSaltField(ctx.allocator, &out, "depth", depth_text);
    try appendSemanticSaltField(ctx.allocator, &out, "direction", graph_mod.directionName(options.direction));
    try appendSemanticSaltField(ctx.allocator, &out, "include_deprecated", if (options.include_deprecated) "true" else "false");
    const confidence_text = try std.fmt.allocPrint(ctx.allocator, "{d:.12}", .{options.min_confidence});
    defer ctx.allocator.free(confidence_text);
    try appendSemanticSaltField(ctx.allocator, &out, "min_confidence", confidence_text);
    try appendSemanticSaltList(ctx.allocator, &out, "relation_types", options.relation_types);
    try appendSemanticSaltList(ctx.allocator, &out, "entity_types", options.entity_types);
    return try out.toOwnedSlice(ctx.allocator);
}

fn appendSemanticSaltField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: []const u8) !void {
    try out.appendSlice(allocator, name);
    try out.append(allocator, '=');
    try out.print(allocator, "{d}:", .{value.len});
    try out.appendSlice(allocator, value);
    try out.append(allocator, ';');
}

fn appendSemanticSaltList(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, values: []const []const u8) !void {
    try out.appendSlice(allocator, name);
    try out.append(allocator, '[');
    for (values) |value| {
        try out.print(allocator, "{d}:", .{value.len});
        try out.appendSlice(allocator, value);
        try out.append(allocator, ',');
    }
    try out.appendSlice(allocator, "];");
}

fn minRelevanceFromObject(obj: std.json.ObjectMap) f64 {
    const raw = json.floatField(obj, "min_relevance") orelse json.floatField(obj, "min_score") orelse 0;
    if (std.math.isNan(raw) or raw < 0) return 0;
    return raw;
}

fn rrfConfigFromObject(obj: std.json.ObjectMap) retrieval.RrfConfig {
    const k = floatFieldAny(obj, &.{ "rrf_k", "rrf_rank_constant", "rank_fusion_k" }) orelse retrieval.default_rrf_k;
    const rrf_weight = floatFieldAny(obj, &.{ "rrf_weight", "rank_fusion_weight" }) orelse retrieval.default_rrf_weight;
    const raw_score_weight = floatFieldAny(obj, &.{ "raw_score_weight", "rrf_raw_score_weight", "rank_fusion_raw_weight" }) orelse retrieval.default_rrf_raw_score_weight;
    const raw_window = intFieldAny(obj, &.{ "rrf_window_multiplier", "rank_fusion_window_multiplier", "fusion_window_multiplier" }) orelse @as(i64, @intCast(retrieval.default_rrf_window_multiplier));
    const window_multiplier: usize = if (raw_window < 1)
        retrieval.default_rrf_window_multiplier
    else
        bounded_int.positiveI64ToUsizeBounded(raw_window, retrieval.max_rrf_window_multiplier);
    return retrieval.normalizeRrfConfig(.{
        .k = k,
        .rrf_weight = rrf_weight,
        .raw_score_weight = raw_score_weight,
        .window_multiplier = window_multiplier,
    });
}

fn mmrLambdaFromObject(obj: std.json.ObjectMap) f64 {
    return retrieval.normalizeMmrLambda(floatFieldAny(obj, &.{ "mmr_lambda", "mmr_relevance_weight" }) orelse retrieval.default_mmr_lambda);
}

fn mmrCandidateMultiplierFromObject(obj: std.json.ObjectMap) usize {
    const raw_window = intFieldAny(obj, &.{ "mmr_candidate_multiplier", "mmr_window_multiplier", "mmr_candidates_multiplier" }) orelse @as(i64, @intCast(retrieval.default_mmr_candidate_multiplier));
    const multiplier: usize = if (raw_window < 1)
        retrieval.default_mmr_candidate_multiplier
    else
        bounded_int.positiveI64ToUsizeBounded(raw_window, retrieval.max_mmr_candidate_multiplier);
    return retrieval.normalizeMmrCandidateMultiplier(multiplier);
}

fn rerankCandidateLimitFromObject(obj: std.json.ObjectMap) u32 {
    const raw_limit = intFieldAny(obj, &.{ "rerank_candidate_limit", "llm_rerank_limit", "reranker_candidate_limit", "quality_rerank_limit" }) orelse @as(i64, retrieval.default_rerank_candidate_limit);
    const limit: u32 = if (raw_limit < 1)
        retrieval.default_rerank_candidate_limit
    else
        bounded_int.positiveI64ToU32Bounded(raw_limit, retrieval.max_rerank_candidate_limit);
    return retrieval.normalizeRerankCandidateLimit(limit);
}

fn strictRerankerFromObject(obj: std.json.ObjectMap) bool {
    return boolFieldAny(obj, &.{ "strict_reranker", "strict_llm_rerank", "strict_rerank" }) orelse false;
}

fn applyRrfConfigToPlan(plan: *retrieval.RetrievalPlan, config: retrieval.RrfConfig) void {
    const normalized = retrieval.normalizeRrfConfig(config);
    plan.rrf_k = normalized.k;
    plan.rrf_weight = normalized.rrf_weight;
    plan.raw_score_weight = normalized.raw_score_weight;
    plan.rrf_window_multiplier = normalized.window_multiplier;
}

fn adaptiveRetrievalFromObject(obj: std.json.ObjectMap) bool {
    return json.boolField(obj, "adaptive_retrieval") orelse
        json.boolField(obj, "use_adaptive_retrieval") orelse
        json.boolField(obj, "adaptive") orelse
        true;
}

fn adaptiveTokenThresholdFromObject(obj: std.json.ObjectMap, names: []const []const u8, default_value: u32, normalize: *const fn (u32) u32) u32 {
    const raw = intFieldAny(obj, names) orelse return normalize(default_value);
    if (raw < 0) return normalize(default_value);
    const value = bounded_int.positiveI64ToU32Bounded(raw, retrieval.max_adaptive_token_threshold);
    return normalize(value);
}

fn adaptiveConfigFromObject(ctx: *Context, obj: std.json.ObjectMap) retrieval.AdaptiveConfig {
    return retrieval.normalizeAdaptiveConfig(.{
        .enabled = adaptiveRetrievalFromObject(obj),
        .keyword_max_tokens = adaptiveTokenThresholdFromObject(obj, &.{ "adaptive_keyword_max_tokens", "retrieval_adaptive_keyword_max_tokens", "adaptive_keyword_tokens" }, ctx.adaptive_keyword_max_tokens, retrieval.normalizeAdaptiveKeywordMaxTokens),
        .vector_min_tokens = adaptiveTokenThresholdFromObject(obj, &.{ "adaptive_vector_min_tokens", "retrieval_adaptive_vector_min_tokens", "adaptive_vector_tokens" }, ctx.adaptive_vector_min_tokens, retrieval.normalizeAdaptiveVectorMinTokens),
    });
}

test "api retrieval numeric options preserve defaults and clamp request values" {
    var defaults = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{}", .{});
    defer defaults.deinit();
    const defaults_obj = defaults.value.object;
    try std.testing.expectEqual(retrieval.default_rrf_window_multiplier, rrfConfigFromObject(defaults_obj).window_multiplier);
    try std.testing.expectEqual(retrieval.default_mmr_candidate_multiplier, mmrCandidateMultiplierFromObject(defaults_obj));
    try std.testing.expectEqual(retrieval.default_rerank_candidate_limit, rerankCandidateLimitFromObject(defaults_obj));
    try std.testing.expectEqual(
        retrieval.default_adaptive_keyword_max_tokens,
        adaptiveTokenThresholdFromObject(defaults_obj, &.{"adaptive_keyword_max_tokens"}, retrieval.default_adaptive_keyword_max_tokens, retrieval.normalizeAdaptiveKeywordMaxTokens),
    );

    const capped_payload =
        \\{
        \\  "rrf_window_multiplier": 9223372036854775807,
        \\  "mmr_candidate_multiplier": 9223372036854775807,
        \\  "rerank_candidate_limit": 9223372036854775807,
        \\  "adaptive_keyword_max_tokens": 9223372036854775807,
        \\  "adaptive_vector_min_tokens": 0
        \\}
    ;
    var capped = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, capped_payload, .{});
    defer capped.deinit();
    const capped_obj = capped.value.object;
    try std.testing.expectEqual(retrieval.max_rrf_window_multiplier, rrfConfigFromObject(capped_obj).window_multiplier);
    try std.testing.expectEqual(retrieval.max_mmr_candidate_multiplier, mmrCandidateMultiplierFromObject(capped_obj));
    try std.testing.expectEqual(retrieval.max_rerank_candidate_limit, rerankCandidateLimitFromObject(capped_obj));
    try std.testing.expectEqual(
        retrieval.max_adaptive_token_threshold,
        adaptiveTokenThresholdFromObject(capped_obj, &.{"adaptive_keyword_max_tokens"}, retrieval.default_adaptive_keyword_max_tokens, retrieval.normalizeAdaptiveKeywordMaxTokens),
    );
    try std.testing.expectEqual(
        @as(u32, 1),
        adaptiveTokenThresholdFromObject(capped_obj, &.{"adaptive_vector_min_tokens"}, retrieval.default_adaptive_vector_min_tokens, retrieval.normalizeAdaptiveVectorMinTokens),
    );

    const fallback_payload =
        \\{
        \\  "rrf_window_multiplier": 0,
        \\  "mmr_candidate_multiplier": 0,
        \\  "rerank_candidate_limit": 0,
        \\  "adaptive_keyword_max_tokens": -1
        \\}
    ;
    var fallback = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, fallback_payload, .{});
    defer fallback.deinit();
    const fallback_obj = fallback.value.object;
    try std.testing.expectEqual(retrieval.default_rrf_window_multiplier, rrfConfigFromObject(fallback_obj).window_multiplier);
    try std.testing.expectEqual(retrieval.default_mmr_candidate_multiplier, mmrCandidateMultiplierFromObject(fallback_obj));
    try std.testing.expectEqual(retrieval.default_rerank_candidate_limit, rerankCandidateLimitFromObject(fallback_obj));
    try std.testing.expectEqual(
        retrieval.default_adaptive_keyword_max_tokens,
        adaptiveTokenThresholdFromObject(fallback_obj, &.{"adaptive_keyword_max_tokens"}, retrieval.default_adaptive_keyword_max_tokens, retrieval.normalizeAdaptiveKeywordMaxTokens),
    );
}

fn stringFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?[]const u8 {
    for (names) |name| {
        if (json.stringField(obj, name)) |value| return value;
    }
    return null;
}

fn nullableStringFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?[]const u8 {
    for (names) |name| {
        if (json.nullableStringField(obj, name)) |value| return value;
    }
    return null;
}

fn intFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?i64 {
    for (names) |name| {
        if (json.intField(obj, name)) |value| return value;
    }
    return null;
}

fn floatFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?f64 {
    for (names) |name| {
        if (json.floatField(obj, name)) |value| return value;
    }
    return null;
}

fn boolFieldAny(obj: std.json.ObjectMap, names: []const []const u8) ?bool {
    for (names) |name| {
        if (json.boolField(obj, name)) |value| return value;
    }
    return null;
}

fn resolveRetrievalRolloutPolicy(ctx: *Context, obj: std.json.ObjectMap) !lifecycle.RolloutPolicy {
    var policy = ctx.retrieval_rollout_policy;
    if (stringFieldAny(obj, &.{ "retrieval_rollout_policy", "retrieval_rollout_policy_name", "rollout_policy", "rollout_policy_name", "policy_name" })) |name| {
        const record = try loadRolloutPolicyRecord(ctx, name);
        if (record == null) return error.RolloutPolicyNotFound;
        policy = record.?.policy;
    }
    const percent_raw = intFieldAny(obj, &.{ "retrieval_rollout_percent", "rollout_percent", "canary_percent" });
    const shadow_percent_raw = intFieldAny(obj, &.{ "retrieval_shadow_percent", "retrieval_rollout_shadow_percent", "rollout_shadow_percent", "shadow_percent", "shadow_hybrid_percent" });
    if (stringFieldAny(obj, &.{ "retrieval_rollout_mode", "rollout_mode" })) |mode| {
        policy.mode = try lifecycle.RolloutMode.parse(mode, percent_raw != null);
    } else if (percent_raw != null) {
        policy.mode = try lifecycle.RolloutMode.parse(null, true);
    }
    if (percent_raw) |value| policy.percent = clampPercent(value);
    if (shadow_percent_raw) |value| policy.shadow_percent = clampPercent(value);
    if (stringFieldAny(obj, &.{ "retrieval_rollout_salt", "rollout_salt" })) |salt| policy.salt = salt;
    if (boolFieldAny(obj, &.{ "retrieval_rollout_disabled", "rollout_disabled", "kill_switch" })) |disabled| policy.disabled = policy.disabled or disabled;
    policy.required_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "retrieval_rollout_required_scopes", "rollout_required_scopes" }, policy.required_scopes_json);
    policy.blocked_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "retrieval_rollout_blocked_scopes", "rollout_blocked_scopes" }, policy.blocked_scopes_json);
    policy.target_scopes_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "retrieval_rollout_target_scopes", "rollout_target_scopes" }, policy.target_scopes_json);
    policy.required_capabilities_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "retrieval_rollout_required_capabilities", "rollout_required_capabilities" }, policy.required_capabilities_json);
    policy.blocked_capabilities_json = try rawArrayFieldAny(ctx.allocator, obj, &.{ "retrieval_rollout_blocked_capabilities", "rollout_blocked_capabilities" }, policy.blocked_capabilities_json);
    try policy.validateUsable();
    return policy;
}

fn evaluateRetrievalRollout(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, session_id: ?[]const u8) !lifecycle.RolloutResult {
    const policy = try resolveRetrievalRolloutPolicy(ctx, obj);
    const key = stringFieldAny(obj, &.{ "retrieval_rollout_key", "rollout_key" }) orelse
        stringFieldAny(obj, &.{ "retrieval_rollout_feature", "rollout_feature" }) orelse
        if (query.len > 0) query else "retrieval";
    return lifecycle.evaluateRollout(policy, .{
        .key = key,
        .actor_id = ctx.actor_id,
        .session_id = session_id,
        .actor_scopes_json = ctx.actor_scopes_json,
        .actor_capabilities_json = ctx.actor_capabilities_json,
    });
}

fn buildSearchInput(ctx: *Context, obj: std.json.ObjectMap, query: []const u8, limit: usize, include_sessions_default: bool, route_query: []const u8) !store_mod.SearchInput {
    var use_vector = json.boolField(obj, "use_vector") orelse true;
    const strict_vector = json.boolField(obj, "strict_vector") orelse false;
    const adaptive_config = adaptiveConfigFromObject(ctx, obj);
    const adaptive_retrieval = adaptive_config.enabled;
    const rrf_config = rrfConfigFromObject(obj);
    const agent_memory_route = try storage_routes.fromObjectOrQuery(ctx.allocator, obj, route_query);
    const min_relevance = minRelevanceFromObject(obj);
    const rerank_candidate_limit = rerankCandidateLimitFromObject(obj);
    const strict_reranker = strictRerankerFromObject(obj);
    const session_id = nullableStringFieldAny(obj, &.{"session_id"});
    const offset = searchOffset(json.intField(obj, "offset") orelse queryInt(route_query, "offset"));
    const rollout = try evaluateRetrievalRollout(ctx, obj, query, session_id);
    const rollout_vector_requested = use_vector;
    if (use_vector and !rollout.enabled) use_vector = false;
    var query_embedding_json: ?[]const u8 = null;
    var query_embedding_provider: []const u8 = "none";
    var embedding_dimensions = vector_mod.boundedEmbeddingDimensions(null, ctx.provider.embedding.dimensions);
    const analysis = retrieval.analyzeQuery(query, adaptive_config);
    if (adaptive_retrieval and !strict_vector and analysis.recommended_strategy == .keyword_only) {
        use_vector = false;
        query_embedding_provider = "adaptive_keyword_only";
    }
    if (use_vector and query.len > 0) {
        const embedding_result = embedTextCachedForPurpose(ctx, embeddingConfigFromContext(ctx, embedding_dimensions), query, embedding_dimensions, json.boolField(obj, "use_embedding_cache") orelse true, embeddingCacheMaxEntries(obj), .query) catch |err| {
            if (strict_vector) return err;
            use_vector = false;
            query_embedding_provider = "unavailable";
            query_embedding_json = null;
            return .{
                .query = query,
                .limit = limit,
                .offset = offset,
                .scopes_json = try effectiveScopes(ctx, obj),
                .include_deprecated = json.boolField(obj, "include_deprecated") orelse false,
                .include_sessions = json.boolField(obj, "include_sessions") orelse include_sessions_default,
                .session_id = session_id,
                .use_vector = false,
                .adaptive_retrieval = adaptive_retrieval,
                .adaptive_keyword_max_tokens = adaptive_config.keyword_max_tokens,
                .adaptive_vector_min_tokens = adaptive_config.vector_min_tokens,
                .strict_vector = false,
                .use_temporal_decay = json.boolField(obj, "use_temporal_decay") orelse true,
                .use_mmr = json.boolField(obj, "use_mmr") orelse true,
                .mmr_lambda = mmrLambdaFromObject(obj),
                .mmr_candidate_multiplier = mmrCandidateMultiplierFromObject(obj),
                .allow_reranker = json.boolField(obj, "allow_reranker") orelse false,
                .rerank_candidate_limit = rerank_candidate_limit,
                .strict_reranker = strict_reranker,
                .min_relevance = min_relevance,
                .half_life_days = json.floatField(obj, "half_life_days") orelse 30,
                .rrf_k = rrf_config.k,
                .rrf_weight = rrf_config.rrf_weight,
                .raw_score_weight = rrf_config.raw_score_weight,
                .rrf_window_multiplier = rrf_config.window_multiplier,
                .query_embedding_json = null,
                .query_embedding_provider = query_embedding_provider,
                .embedding_dimensions = embedding_dimensions,
                .actor_id = ctx.actor_id,
                .actor_capabilities_json = ctx.actor_capabilities_json,
                .agent_memory_route = agent_memory_route,
                .rollout_mode = rollout.mode,
                .rollout_decision = rollout.decision,
                .rollout_reason = rollout.reason,
                .rollout_bucket = rollout.bucket,
                .rollout_vector_requested = rollout_vector_requested,
                .rollout_shadow_vector = rollout.shadow and rollout_vector_requested,
            };
        };
        query_embedding_json = try vector_mod.embeddingToJson(ctx.allocator, embedding_result.embedding);
        query_embedding_provider = embedding_result.provider;
        embedding_dimensions = embedding_result.embedding.len;
    }
    return .{
        .query = query,
        .limit = limit,
        .offset = offset,
        .scopes_json = try effectiveScopes(ctx, obj),
        .include_deprecated = json.boolField(obj, "include_deprecated") orelse false,
        .include_sessions = json.boolField(obj, "include_sessions") orelse include_sessions_default,
        .session_id = session_id,
        .use_vector = use_vector,
        .adaptive_retrieval = adaptive_retrieval,
        .adaptive_keyword_max_tokens = adaptive_config.keyword_max_tokens,
        .adaptive_vector_min_tokens = adaptive_config.vector_min_tokens,
        .strict_vector = strict_vector,
        .use_temporal_decay = json.boolField(obj, "use_temporal_decay") orelse true,
        .use_mmr = json.boolField(obj, "use_mmr") orelse true,
        .mmr_lambda = mmrLambdaFromObject(obj),
        .mmr_candidate_multiplier = mmrCandidateMultiplierFromObject(obj),
        .allow_reranker = json.boolField(obj, "allow_reranker") orelse false,
        .rerank_candidate_limit = rerank_candidate_limit,
        .strict_reranker = strict_reranker,
        .min_relevance = min_relevance,
        .half_life_days = json.floatField(obj, "half_life_days") orelse 30,
        .rrf_k = rrf_config.k,
        .rrf_weight = rrf_config.rrf_weight,
        .raw_score_weight = rrf_config.raw_score_weight,
        .rrf_window_multiplier = rrf_config.window_multiplier,
        .query_embedding_json = query_embedding_json,
        .query_embedding_provider = query_embedding_provider,
        .embedding_dimensions = embedding_dimensions,
        .actor_id = ctx.actor_id,
        .actor_capabilities_json = ctx.actor_capabilities_json,
        .agent_memory_route = agent_memory_route,
        .rollout_mode = rollout.mode,
        .rollout_decision = rollout.decision,
        .rollout_reason = rollout.reason,
        .rollout_bucket = rollout.bucket,
        .rollout_vector_requested = rollout_vector_requested,
        .rollout_shadow_vector = rollout.shadow and rollout_vector_requested,
    };
}

fn ensureMemoryProvenance(ctx: *Context, input: store_mod.MemoryAtomInput) !store_mod.MemoryAtomInput {
    var out = input;
    const has_source = jsonArrayHasStringItems(ctx.allocator, out.source_ids_json);
    if (has_source) {
        if (!sourceIdsCanBackRecord(ctx, out.source_ids_json, out.scope, out.permissions_json)) return error.Forbidden;
        if (!jsonArrayHasStringItems(ctx.allocator, out.evidence_ranges_json) and !jsonArrayHasObjectItems(ctx.allocator, out.evidence_ranges_json)) {
            const first_source = try firstJsonStringDup(ctx.allocator, out.source_ids_json);
            out.evidence_ranges_json = try evidenceJson(ctx.allocator, first_source orelse "", out.text.len, "provided_source");
        }
        return out;
    }

    const source_type: []const u8 = if (std.mem.eql(u8, input.created_by, "agent")) "agent_observation" else "manual";
    const title = try memorySourceTitle(ctx.allocator, input.text);
    const source = try ctx.store.createSource(ctx.allocator, .{
        .source_type = source_type,
        .title = title,
        .content = input.text,
        .author = input.owner,
        .permissions_json = input.permissions_json,
        .scope = input.scope,
        .metadata_json = "{\"generated_for\":\"memory_atom\"}",
        .actor_id = ctx.actor_id,
        .storage_route = input.storage_route,
    });
    out.source_ids_json = try singleStringArrayJson(ctx.allocator, source.id);
    out.evidence_ranges_json = try evidenceJson(ctx.allocator, source.id, input.text.len, "generated_source");
    return out;
}

fn prepareAppliedMemoryProvenance(ctx: *Context, input: store_mod.MemoryAtomInput) !store_mod.PreparedMemoryImport {
    var out = input;
    const has_source = jsonArrayHasStringItems(ctx.allocator, out.source_ids_json);
    if (has_source) {
        if (!sourceIdsCanBackRecord(ctx, out.source_ids_json, out.scope, out.permissions_json)) return error.Forbidden;
        if (!jsonArrayHasStringItems(ctx.allocator, out.evidence_ranges_json) and !jsonArrayHasObjectItems(ctx.allocator, out.evidence_ranges_json)) {
            const first_source = try firstJsonStringDup(ctx.allocator, out.source_ids_json);
            out.evidence_ranges_json = try evidenceJson(ctx.allocator, first_source orelse "", out.text.len, "provided_source");
        }
        return .{ .atom = out };
    }

    const source_type: []const u8 = if (std.mem.eql(u8, input.created_by, "agent")) "agent_observation" else "manual";
    return .{
        .atom = out,
        .generated_source = .{
            .source_type = source_type,
            .title = try memorySourceTitle(ctx.allocator, input.text),
            .content = input.text,
            .author = input.owner,
            .permissions_json = input.permissions_json,
            .scope = input.scope,
            .metadata_json = "{\"generated_for\":\"memory_feed_apply\"}",
            .actor_id = ctx.actor_id,
            .storage_route = input.storage_route,
        },
    };
}

fn jsonArrayHasStringItems(allocator: std.mem.Allocator, value: []const u8) bool {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, value, .{}) catch return false;
    defer parsed.deinit();
    if (parsed.value != .array) return false;
    for (parsed.value.array.items) |item| {
        if (item == .string) return true;
    }
    return false;
}

fn jsonArrayHasObjectItems(allocator: std.mem.Allocator, value: []const u8) bool {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, value, .{}) catch return false;
    defer parsed.deinit();
    if (parsed.value != .array) return false;
    for (parsed.value.array.items) |item| {
        if (item == .object) return true;
    }
    return false;
}

fn firstJsonStringDup(allocator: std.mem.Allocator, value: []const u8) !?[]const u8 {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, value, .{}) catch return null;
    defer parsed.deinit();
    if (parsed.value != .array) return null;
    for (parsed.value.array.items) |item| {
        if (item == .string) return try allocator.dupe(u8, item.string);
    }
    return null;
}

fn singleStringArrayJson(allocator: std.mem.Allocator, value: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.append(allocator, '[');
    try json.appendString(&out, allocator, value);
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn evidenceJson(allocator: std.mem.Allocator, source_id: []const u8, text_len: usize, kind: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.appendSlice(allocator, "[{\"source_id\":");
    try json.appendString(&out, allocator, source_id);
    try out.appendSlice(allocator, ",\"start\":0,\"end\":");
    try out.print(allocator, "{d}", .{text_len});
    try out.appendSlice(allocator, ",\"kind\":");
    try json.appendString(&out, allocator, kind);
    try out.appendSlice(allocator, "}]");
    return out.toOwnedSlice(allocator);
}

fn memorySourceTitle(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    const trimmed = std.mem.trim(u8, text, " \t\r\n");
    const max_len = @min(trimmed.len, @as(usize, 72));
    if (max_len == 0) return allocator.dupe(u8, "Memory source");
    return try std.fmt.allocPrint(allocator, "Memory source: {s}", .{trimmed[0..max_len]});
}

fn sourceIdsVisible(ctx: *Context, source_ids_json: []const u8) bool {
    const parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, source_ids_json, .{}) catch return false;
    defer parsed.deinit();
    const arr = switch (parsed.value) {
        .array => |a| a,
        else => return false,
    };
    for (arr.items) |item| {
        const source_id = switch (item) {
            .string => |s| s,
            else => return false,
        };
        const source = (ctx.store.getSource(ctx.allocator, source_id) catch return false) orelse return false;
        if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return false;
    }
    return true;
}

fn sourceIdsCanBackRecord(ctx: *Context, source_ids_json: []const u8, target_scope: []const u8, target_permissions_json: []const u8) bool {
    const parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, source_ids_json, .{}) catch return false;
    defer parsed.deinit();
    const arr = switch (parsed.value) {
        .array => |a| a,
        else => return false,
    };
    for (arr.items) |item| {
        const source_id = switch (item) {
            .string => |s| s,
            else => return false,
        };
        const source = (ctx.store.getSource(ctx.allocator, source_id) catch return false) orelse return false;
        if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) return false;
        if (!sourceAclCoversTarget(ctx.allocator, source.scope, source.permissions_json, target_scope, target_permissions_json)) return false;
    }
    return true;
}

fn entityCanBackRecord(ctx: *Context, entity_id: []const u8, target_scope: []const u8, target_permissions_json: []const u8) bool {
    const entity = (ctx.store.getEntity(ctx.allocator, entity_id) catch return false) orelse return false;
    if (!recordVisibleToActor(ctx, entity.scope, entity.permissions_json)) return false;
    return sourceAclCoversTarget(ctx.allocator, entity.scope, entity.permissions_json, target_scope, target_permissions_json);
}

fn spaceCanContainRecord(ctx: *Context, space_id: ?[]const u8, target_scope: []const u8, target_permissions_json: []const u8) bool {
    const id = space_id orelse return true;
    const space = (ctx.store.getSpace(ctx.allocator, id) catch return false) orelse return false;
    if (!recordVisibleToActor(ctx, space.scope, space.permissions_json)) return false;
    return sourceAclCoversTarget(ctx.allocator, space.scope, space.permissions_json, target_scope, target_permissions_json);
}

fn artifactCanBackRecord(ctx: *Context, artifact_id: ?[]const u8, target_scope: []const u8, target_permissions_json: []const u8) bool {
    const id = artifact_id orelse return true;
    const artifact = (ctx.store.getArtifact(ctx.allocator, id) catch return false) orelse return false;
    if (!recordVisibleToActor(ctx, artifact.scope, artifact.permissions_json)) return false;
    return sourceAclCoversTarget(ctx.allocator, artifact.scope, artifact.permissions_json, target_scope, target_permissions_json);
}

const sourceAclCoversTarget = access.aclCoversTarget;
const permissionsOpen = access.permissionsOpen;

fn sanitizeSourceIdsForActor(ctx: *Context, source_ids_json: []const u8) ![]const u8 {
    const parsed = std.json.parseFromSlice(std.json.Value, ctx.allocator, source_ids_json, .{}) catch return try ctx.allocator.dupe(u8, "[]");
    defer parsed.deinit();
    const arr = switch (parsed.value) {
        .array => |a| a,
        else => return try ctx.allocator.dupe(u8, "[]"),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '[');
    var first = true;
    for (arr.items) |item| {
        const source_id = switch (item) {
            .string => |s| s,
            else => continue,
        };
        const source = (try ctx.store.getSource(ctx.allocator, source_id)) orelse continue;
        if (!recordVisibleToActor(ctx, source.scope, source.permissions_json)) continue;
        if (!first) try out.append(ctx.allocator, ',');
        first = false;
        try json.appendString(&out, ctx.allocator, source_id);
    }
    try out.append(ctx.allocator, ']');
    return out.toOwnedSlice(ctx.allocator);
}

fn canCreateMemoryAtom(ctx: *Context, input: store_mod.MemoryAtomInput) bool {
    const status = input.status orelse domain.defaultMemoryStatus(input.created_by, input.scope);
    if (std.mem.eql(u8, status, "proposed")) return canProposeRecord(ctx, input.scope, input.permissions_json);
    if (std.mem.eql(u8, status, "verified")) {
        return hasCapability(ctx, "verify") and
            domain.scopeVerifiable(input.scope, ctx.actor_scopes_json) and
            canWriteRecord(ctx, input.scope, input.permissions_json);
    }
    return canWriteRecord(ctx, input.scope, input.permissions_json);
}

fn memoryAtomWritable(ctx: *Context, id: []const u8) bool {
    const atom = ctx.store.getMemoryAtom(ctx.allocator, id) catch return false;
    const existing = atom orelse return false;
    return canWriteRecord(ctx, existing.scope, existing.permissions_json);
}

fn canChangeMemoryStatus(ctx: *Context, id: []const u8, status: []const u8) bool {
    const atom = ctx.store.getMemoryAtom(ctx.allocator, id) catch return false;
    const existing = atom orelse return false;
    if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return false;
    const policy = ctx.store.getPolicyScope(ctx.allocator, existing.scope) catch return false;
    if (policy) |p| {
        if (!domain.permissionsWritable(p.permissions_json, ctx.actor_scopes_json)) return false;
    }
    if (std.mem.eql(u8, status, "verified")) return hasCapability(ctx, "verify") and domain.scopeVerifiable(existing.scope, ctx.actor_scopes_json) and domain.permissionsWritable(existing.permissions_json, ctx.actor_scopes_json);
    if (std.mem.eql(u8, status, "deprecated") or std.mem.eql(u8, status, "rejected")) return hasCapability(ctx, "delete") and domain.scopeDeletable(existing.scope, ctx.actor_scopes_json) and domain.permissionsWritable(existing.permissions_json, ctx.actor_scopes_json);
    if (std.mem.eql(u8, status, "stale") or std.mem.eql(u8, status, "superseded")) return hasCapability(ctx, "verify") and domain.scopeVerifiable(existing.scope, ctx.actor_scopes_json) and domain.permissionsWritable(existing.permissions_json, ctx.actor_scopes_json);
    return memoryAtomWritable(ctx, id);
}

fn canChangeGraphPrimitiveStatus(ctx: *Context, scope: []const u8, permissions_json: []const u8, status: []const u8) bool {
    const policy = ctx.store.getPolicyScope(ctx.allocator, scope) catch return false;
    if (policy) |p| {
        if (!domain.permissionsWritable(p.permissions_json, ctx.actor_scopes_json)) return false;
    }
    if (std.mem.eql(u8, status, "verified") or std.mem.eql(u8, status, "accepted")) {
        return hasCapability(ctx, "verify") and domain.scopeVerifiable(scope, ctx.actor_scopes_json) and domain.permissionsWritable(permissions_json, ctx.actor_scopes_json);
    }
    if (std.mem.eql(u8, status, "deprecated") or std.mem.eql(u8, status, "rejected")) {
        return hasCapability(ctx, "delete") and domain.scopeDeletable(scope, ctx.actor_scopes_json) and domain.permissionsWritable(permissions_json, ctx.actor_scopes_json);
    }
    if (std.mem.eql(u8, status, "stale") or std.mem.eql(u8, status, "superseded")) {
        return hasCapability(ctx, "verify") and domain.scopeVerifiable(scope, ctx.actor_scopes_json) and domain.permissionsWritable(permissions_json, ctx.actor_scopes_json);
    }
    return hasCapability(ctx, "write") and domain.scopeWritable(scope, ctx.actor_scopes_json) and domain.permissionsWritable(permissions_json, ctx.actor_scopes_json);
}

fn canApplyFeed(ctx: *Context) bool {
    return hasCapability(ctx, "feed_apply") or hasCapability(ctx, "write");
}

fn resolveVectorAcl(ctx: *Context, object_type: []const u8, object_id: []const u8, requested_scope: []const u8, requested_permissions: []const u8) !store_mod.VectorObjectAcl {
    _ = requested_scope;
    _ = requested_permissions;
    var acl = (try ctx.store.vectorObjectAcl(ctx.allocator, object_type, object_id, ctx.actor_id)) orelse return error.NotFound;
    errdefer store_mod.freeVectorObjectAcl(ctx.allocator, &acl);
    if (!canWriteRecord(ctx, acl.scope, acl.permissions_json)) return error.Forbidden;
    return acl;
}

const HygieneDuplicateStats = struct {
    groups: usize = 0,
    extra_entries: usize = 0,
};

const HygieneDedupEntry = struct {
    object_type: []const u8,
    scope: []const u8,
    category: []const u8,
    session_id: ?[]const u8,
    store: []const u8,
    content: []const u8,
};

fn tryAddHygieneDedupEntry(
    allocator: std.mem.Allocator,
    exact_map: *std.StringHashMapUnmanaged(usize),
    normalized_map: *std.StringHashMapUnmanaged(usize),
    entry: HygieneDedupEntry,
) !void {
    const trimmed = std.mem.trim(u8, entry.content, " \t\r\n");
    if (trimmed.len == 0) return;
    const exact_key = try hygieneDedupKey(allocator, entry, trimmed);
    try putHygieneDedupKey(allocator, exact_map, exact_key);
    const normalized = try normalizeHygieneDedupContent(allocator, trimmed);
    defer allocator.free(normalized);
    if (normalized.len == 0) return;
    const normalized_key = try hygieneDedupKey(allocator, entry, normalized);
    try putHygieneDedupKey(allocator, normalized_map, normalized_key);
}

fn hygieneDedupKey(allocator: std.mem.Allocator, entry: HygieneDedupEntry, content: []const u8) ![]u8 {
    return try std.fmt.allocPrint(
        allocator,
        "{s}\x1f{s}\x1f{s}\x1f{s}\x1f{s}\x1f{s}",
        .{ entry.object_type, entry.store, entry.scope, entry.category, entry.session_id orelse "", content },
    );
}

fn normalizeHygieneDedupContent(allocator: std.mem.Allocator, content: []const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    var pending_space = false;
    for (content) |ch| {
        if (std.ascii.isWhitespace(ch)) {
            pending_space = true;
            continue;
        }
        if (out.items.len > 0 and pending_space) try out.append(allocator, ' ');
        pending_space = false;
        try out.append(allocator, std.ascii.toLower(ch));
    }
    return out.toOwnedSlice(allocator);
}

fn putHygieneDedupKey(allocator: std.mem.Allocator, map: *std.StringHashMapUnmanaged(usize), key: []u8) !void {
    errdefer allocator.free(key);
    const entry = try map.getOrPut(allocator, key);
    if (entry.found_existing) {
        allocator.free(key);
        entry.value_ptr.* += 1;
    } else {
        entry.key_ptr.* = key;
        entry.value_ptr.* = 1;
    }
}

fn duplicateStats(map: *const std.StringHashMapUnmanaged(usize)) HygieneDuplicateStats {
    var stats = HygieneDuplicateStats{};
    var it = map.iterator();
    while (it.next()) |entry| {
        if (entry.value_ptr.* > 1) {
            stats.groups += 1;
            stats.extra_entries += entry.value_ptr.* - 1;
        }
    }
    return stats;
}

fn freeStringCountMap(allocator: std.mem.Allocator, map: *std.StringHashMapUnmanaged(usize)) void {
    var it = map.iterator();
    while (it.next()) |entry| allocator.free(entry.key_ptr.*);
    map.deinit(allocator);
}

fn freeHygieneMemoryAtom(allocator: std.mem.Allocator, atom: *domain.MemoryAtom) void {
    allocator.free(atom.id);
    if (atom.subject_entity_id) |value| allocator.free(value);
    allocator.free(atom.predicate);
    allocator.free(atom.object);
    allocator.free(atom.text);
    allocator.free(atom.scope);
    allocator.free(atom.status);
    allocator.free(atom.source_ids_json);
    allocator.free(atom.evidence_ranges_json);
    allocator.free(atom.created_by);
    if (atom.owner) |value| allocator.free(value);
    allocator.free(atom.permissions_json);
    allocator.free(atom.tags_json);
}

const api_positive_limit_max: usize = 500;
const api_search_limit_max: usize = 500;
const api_search_offset_max: usize = 1_000_000;
const api_result_limit_max: usize = 500;
const api_agent_memory_search_limit_max: usize = 5000;

fn positiveLimit(value: ?i64, default_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return default_value;
    return bounded_int.positiveI64ToUsizeBounded(raw, api_positive_limit_max);
}

fn queryFloat(query: []const u8, name: []const u8, default_value: f64) f64 {
    const raw = json.queryParam(query, name) orelse return default_value;
    return std.fmt.parseFloat(f64, raw) catch default_value;
}

fn searchLimit(value: ?i64, default_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return 0;
    return bounded_int.positiveI64ToUsizeBounded(raw, api_search_limit_max);
}

fn searchOffset(value: ?i64) usize {
    const raw = value orelse return 0;
    if (raw <= 0) return 0;
    return bounded_int.positiveI64ToUsizeBounded(raw, api_search_offset_max);
}

fn resultLimit(value: ?i64, default_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return 0;
    return bounded_int.positiveI64ToUsizeBounded(raw, api_result_limit_max);
}

fn agentMemorySearchLimit(value: ?i64, default_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return 0;
    return bounded_int.positiveI64ToUsizeBounded(raw, api_agent_memory_search_limit_max);
}

fn agentMemorySearchWindowLimit(limit: usize, offset: usize) usize {
    return api_search_window.boundedWindowEnd(limit, offset, 5000);
}

test "api search and result limit helpers preserve defaults and cap request values" {
    try std.testing.expectEqual(@as(usize, 1000), positiveLimit(null, 1000));
    try std.testing.expectEqual(@as(usize, 1000), positiveLimit(-1, 1000));
    try std.testing.expectEqual(@as(usize, 42), positiveLimit(42, 1000));
    try std.testing.expectEqual(api_positive_limit_max, positiveLimit(std.math.maxInt(i64), 1000));

    try std.testing.expectEqual(@as(usize, 1000), searchLimit(null, 1000));
    try std.testing.expectEqual(@as(usize, 0), searchLimit(0, 1000));
    try std.testing.expectEqual(api_search_limit_max, searchLimit(std.math.maxInt(i64), 1000));

    try std.testing.expectEqual(@as(usize, 0), searchOffset(null));
    try std.testing.expectEqual(@as(usize, 0), searchOffset(-1));
    try std.testing.expectEqual(api_search_offset_max, searchOffset(std.math.maxInt(i64)));

    try std.testing.expectEqual(@as(usize, 50), resultLimit(null, 50));
    try std.testing.expectEqual(@as(usize, 0), resultLimit(0, 50));
    try std.testing.expectEqual(api_result_limit_max, resultLimit(std.math.maxInt(i64), 50));

    try std.testing.expectEqual(@as(usize, 10), agentMemorySearchLimit(null, 10));
    try std.testing.expectEqual(@as(usize, 0), agentMemorySearchLimit(0, 10));
    try std.testing.expectEqual(api_agent_memory_search_limit_max, agentMemorySearchLimit(std.math.maxInt(i64), 10));
}

test "api filtered agent memory window offset advances safely" {
    try std.testing.expectEqual(@as(?usize, 15), agentMemoryFilteredWindowOffsetAfterFetch(10, 5));
    try std.testing.expectEqual(@as(?usize, null), agentMemoryFilteredWindowOffsetAfterFetch(10, 0));
    try std.testing.expectEqual(@as(?usize, std.math.maxInt(usize)), agentMemoryFilteredWindowOffsetAfterFetch(std.math.maxInt(usize) - 1, 4));
    try std.testing.expectEqual(@as(?usize, null), agentMemoryFilteredWindowOffsetAfterFetch(std.math.maxInt(usize), 1));
}

test "api session usage totals clamp signed request values" {
    try std.testing.expectEqual(@as(u64, 0), agentSessionTotalTokensFromSigned(-1));
    try std.testing.expectEqual(@as(u64, 0), agentSessionTotalTokensFromSigned(0));
    try std.testing.expectEqual(@as(u64, 42), agentSessionTotalTokensFromSigned(42));
    try std.testing.expectEqual(@as(u64, @intCast(std.math.maxInt(i64))), agentSessionTotalTokensFromSigned(std.math.maxInt(i64)));
}

fn optionalJsonObjectBody(body: []const u8) []const u8 {
    return if (std.mem.trim(u8, body, " \t\r\n").len == 0) "{}" else body;
}

fn queryParamDecodedAlias(ctx: *Context, query: []const u8, primary: []const u8, alias: []const u8) !?[]const u8 {
    if (try json.queryParamDecoded(ctx.allocator, query, primary)) |value| return value;
    return try json.queryParamDecoded(ctx.allocator, query, alias);
}

fn queryParamDecodedAliasWithCurrentSession(ctx: *Context, query: []const u8, primary: []const u8, alias: []const u8) !?[]const u8 {
    if (try json.queryParamDecoded(ctx.allocator, query, primary)) |value| {
        if (value.len > 0) return value;
        return try queryCurrentSessionId(ctx, query);
    }
    if (try json.queryParamDecoded(ctx.allocator, query, alias)) |value| {
        if (value.len > 0) return value;
        return try queryCurrentSessionId(ctx, query);
    }
    return null;
}

fn queryCurrentSessionId(ctx: *Context, query: []const u8) !?[]const u8 {
    const names = [_][]const u8{ "current_session_id", "thread_session_id" };
    for (names) |name| {
        if (try json.queryParamDecoded(ctx.allocator, query, name)) |value| {
            if (value.len > 0) return value;
        }
    }
    return null;
}

fn nullableStringFieldAlias(obj: std.json.ObjectMap, primary: []const u8, alias: []const u8) ?[]const u8 {
    return json.nullableStringField(obj, primary) orelse json.nullableStringField(obj, alias);
}

fn nullableStringFieldAliasWithCurrentSession(obj: std.json.ObjectMap, primary: []const u8, alias: []const u8) ?[]const u8 {
    if (obj.get(primary)) |value| {
        switch (value) {
            .string => |text| if (text.len > 0) return text,
            else => {},
        }
        return currentSessionField(obj);
    }
    if (obj.get(alias)) |value| {
        switch (value) {
            .string => |text| if (text.len > 0) return text,
            else => {},
        }
        return currentSessionField(obj);
    }
    return null;
}

fn currentSessionField(obj: std.json.ObjectMap) ?[]const u8 {
    const names = [_][]const u8{ "current_session_id", "thread_session_id" };
    for (names) |name| {
        if (json.stringField(obj, name)) |value| {
            if (value.len > 0) return value;
        }
    }
    return null;
}

fn queryDeleteAll(query: []const u8) bool {
    return queryBool(query, "all_sessions", false) or queryBool(query, "delete_all", false);
}

fn storageRouteError(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.InvalidStorageSelector => json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid storage selector"),
        else => serverError(ctx),
    };
}

fn rawJsonRequestError(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.InvalidRawJson => badJson(ctx),
        else => serverError(ctx),
    };
}

fn extractJsonString(allocator: std.mem.Allocator, body: []const u8, marker: []const u8) ![]const u8 {
    const start_marker = std.mem.indexOf(u8, body, marker) orelse return error.MissingMarker;
    const start = start_marker + marker.len;
    const end_rel = std.mem.indexOfScalar(u8, body[start..], '"') orelse return error.MissingMarker;
    return allocator.dupe(u8, body[start .. start + end_rel]);
}

