test "api source and artifact lifecycle endpoints append feed events" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const source = handleRequest(&ctx, "POST", "/v1/sources", "{\"title\":\"Lifecycle Source\",\"type\":\"transcript\",\"content\":\"source lifecycle body\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", source.status);
    const source_id = try extractJsonString(alloc, source.body, "\"id\":\"");
    const source_path = try std.fmt.allocPrint(alloc, "/v1/sources/{s}", .{source_id});
    const bad_source_patch = handleRequest(&ctx, "PATCH", source_path, "{\"status\":\"stale\",\"payload\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_source_patch.status);
    const source_patch = handleRequest(&ctx, "PATCH", source_path, "{\"status\":\"stale\",\"reason\":\"source review\",\"payload\":{\"reviewed\":true}}", "");
    try std.testing.expectEqualStrings("200 OK", source_patch.status);
    try std.testing.expect(std.mem.indexOf(u8, source_patch.body, "\"status\":\"stale\"") != null);

    const artifact = handleRequest(&ctx, "POST", "/v1/artifacts", "{\"type\":\"page\",\"title\":\"Lifecycle Artifact\",\"body\":\"artifact lifecycle body\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", artifact.status);
    const artifact_id = try extractJsonString(alloc, artifact.body, "\"id\":\"");
    const artifact_path = try std.fmt.allocPrint(alloc, "/v1/artifacts/{s}", .{artifact_id});
    const artifact_patch = handleRequest(&ctx, "PATCH", artifact_path, "{\"status\":\"verified\",\"reason\":\"artifact review\"}", "");
    try std.testing.expectEqualStrings("200 OK", artifact_patch.status);
    try std.testing.expect(std.mem.indexOf(u8, artifact_patch.body, "\"status\":\"verified\"") != null);
    const artifact_delete = handleRequest(&ctx, "DELETE", artifact_path, "", "");
    try std.testing.expectEqualStrings("200 OK", artifact_delete.status);

    const feed = handleRequest(&ctx, "GET", "/v1/memory/events?limit=100", "", "");
    try std.testing.expectEqualStrings("200 OK", feed.status);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"event_type\":\"source.mark_stale\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"event_type\":\"artifact.verify\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"event_type\":\"artifact.delete\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"payload\":{\"reviewed\":true}") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, source_id) != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, artifact_id) != null);
}

test "api memory atom lifecycle response uses typed result field" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_scopes_json = "[\"public\",\"verify:public\"]",
        .actor_capabilities_json = "[\"read\",\"verify\"]",
    };

    const atom = try store.createMemoryAtom(alloc, .{
        .text = "Lifecycle response memory",
        .scope = "public",
        .created_by = "human",
    });
    const bad_body = try std.fmt.allocPrint(alloc, "{{\"id\":\"{s}\",\"payload\":[]}}", .{atom.id});
    const bad_resp = handleRequest(&ctx, "POST", "/v1/verify", bad_body, "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_resp.status);

    const body = try std.fmt.allocPrint(alloc, "{{\"id\":\"{s}\",\"payload\":{{\"reviewed\":true}}}}", .{atom.id});
