}

test "api agent memory writes reject malformed raw JSON roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:memory-raw-roots",
        .actor_scopes_json = "[\"public\",\"write:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"propose\"]",
    };

    const bad_permissions = handleRequest(&ctx, "PUT", "/v1/agent-memory/bad.permissions", "{\"content\":\"bad permissions\",\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_permissions.status);

    const bad_metadata = handleRequest(&ctx, "PUT", "/v1/agent-memory/bad.metadata", "{\"content\":\"bad metadata\",\"scope\":\"public\",\"metadata\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_metadata.status);

    const bad_adapter_permissions = handleRequest(&ctx, "PUT", "/v1/agent/memories/bad.adapter.permissions", "{\"content\":\"bad adapter permissions\",\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_adapter_permissions.status);

    const missing_permissions = handleRequest(&ctx, "GET", "/v1/agent-memory/bad.permissions?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_permissions.status);
    const missing_metadata = handleRequest(&ctx, "GET", "/v1/agent-memory/bad.metadata?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_metadata.status);
    const missing_adapter = handleRequest(&ctx, "GET", "/v1/agent/memories/bad.adapter.permissions?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_adapter.status);

    const accepted = handleRequest(&ctx, "PUT", "/v1/agent-memory/shaped.memory", "{\"content\":\"shaped native memory\",\"scope\":\"public\",\"permissions\":[],\"metadata\":{\"source\":\"test\"}}", "");
    try std.testing.expectEqualStrings("200 OK", accepted.status);
    try std.testing.expect(std.mem.indexOf(u8, accepted.body, "\"permissions\":[]") != null);
}

