test "api canonical nullclaw engine contract works with shared bearer token" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store, .required_token = "shared-api-key" };
    const auth_header = "Authorization: Bearer shared-api-key\r\n";

    const health_resp = handleRequest(&ctx, "GET", "/v1/health", "", "GET /v1/health HTTP/1.1\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", health_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, health_resp.body, "\"schema_ok\":true") != null);

    const put_raw = "PUT /v1/agent-memory/nullclaw.api.live.pref HTTP/1.1\r\n" ++ auth_header ++ "\r\n{}";
    const put_resp = handleRequest(&ctx, "PUT", "/v1/agent-memory/nullclaw.api.live.pref", "{\"content\":\"live API contract memory\",\"category\":\"core\",\"session_id\":null}", put_raw);
    try std.testing.expectEqualStrings("200 OK", put_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, put_resp.body, "\"memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, put_resp.body, "\"entry\"") == null);

    const get_resp = handleRequest(&ctx, "GET", "/v1/agent-memory/nullclaw.api.live.pref", "", "GET /v1/agent-memory/nullclaw.api.live.pref HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", get_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, get_resp.body, "\"memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, get_resp.body, "live API contract memory") != null);

    const search_resp = handleRequest(&ctx, "POST", "/v1/agent-memory/search", "{\"query\":\"live API contract\",\"limit\":5,\"session_id\":null}", "POST /v1/agent-memory/search HTTP/1.1\r\n" ++ auth_header ++ "\r\n{}");
    try std.testing.expectEqualStrings("200 OK", search_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"memories\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"entries\"") == null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "live API contract memory") != null);

    const count_resp = handleRequest(&ctx, "GET", "/v1/agent-memory/count", "", "GET /v1/agent-memory/count HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", count_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, count_resp.body, "\"count\":1") != null);

    const save_msg = handleRequest(&ctx, "POST", "/v1/agent-sessions/nullclaw-api-live-session/messages", "{\"role\":\"user\",\"content\":\"Hello from NullClaw ApiMemory\"}", "POST /v1/agent-sessions/nullclaw-api-live-session/messages HTTP/1.1\r\n" ++ auth_header ++ "\r\n{}");
    try std.testing.expectEqualStrings("200 OK", save_msg.status);

    const messages_resp = handleRequest(&ctx, "GET", "/v1/agent-sessions/nullclaw-api-live-session/messages", "", "GET /v1/agent-sessions/nullclaw-api-live-session/messages HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", messages_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, messages_resp.body, "\"messages\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, messages_resp.body, "Hello from NullClaw ApiMemory") != null);

    const save_usage = handleRequest(&ctx, "PUT", "/v1/agent-sessions/nullclaw-api-live-session/usage", "{\"total_tokens\":77}", "PUT /v1/agent-sessions/nullclaw-api-live-session/usage HTTP/1.1\r\n" ++ auth_header ++ "\r\n{}");
    try std.testing.expectEqualStrings("200 OK", save_usage.status);
    const usage_resp = handleRequest(&ctx, "GET", "/v1/agent-sessions/nullclaw-api-live-session/usage", "", "GET /v1/agent-sessions/nullclaw-api-live-session/usage HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", usage_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, usage_resp.body, "\"total_tokens\":77") != null);

    const history_resp = handleRequest(&ctx, "GET", "/v1/agent-sessions?limit=10&offset=0", "", "GET /v1/agent-sessions?limit=10&offset=0 HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", history_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, history_resp.body, "\"session_id\":\"nullclaw-api-live-session\"") != null);

    const history_show_resp = handleRequest(&ctx, "GET", "/v1/agent-sessions/nullclaw-api-live-session?limit=10&offset=0", "", "GET /v1/agent-sessions/nullclaw-api-live-session?limit=10&offset=0 HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", history_show_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, history_show_resp.body, "\"created_at_ms\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, history_show_resp.body, "Hello from NullClaw ApiMemory") != null);

    const delete_usage = handleRequest(&ctx, "DELETE", "/v1/agent-sessions/nullclaw-api-live-session/usage", "", "DELETE /v1/agent-sessions/nullclaw-api-live-session/usage HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", delete_usage.status);
    const delete_memory = handleRequest(&ctx, "DELETE", "/v1/agent-memory/nullclaw.api.live.pref", "", "DELETE /v1/agent-memory/nullclaw.api.live.pref HTTP/1.1\r\n" ++ auth_header ++ "\r\n");
    try std.testing.expectEqualStrings("200 OK", delete_memory.status);
}

test "api canonical agent memory list is unbounded when limit is omitted for nullclaw engine parity" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
