    const alloc = arena.allocator();
    const principals =
        \\{"agent-list":{"actor_id":"agent:list","scopes":["public"],"capabilities":["read","write"]}}
    ;
    var ctx = Context{ .allocator = alloc, .store = &store, .token_principals_json = principals };

    for (0..125) |i| {
        const key = try std.fmt.allocPrint(alloc, "nullclaw.list.{d}", .{i});
        const content = try std.fmt.allocPrint(alloc, "NullClaw list contract memory {d}", .{i});
        var entry = try store.agentMemoryStore(alloc, .{ .key = key, .content = content, .actor_id = "agent:list" });
        agent_memory_runtime.freeAgentMemory(alloc, &entry);
    }

    const raw = "GET /v1/agent-memory HTTP/1.1\r\nAuthorization: Bearer agent-list\r\n\r\n";
    const full = handleRequest(&ctx, "GET", "/v1/agent-memory", "", raw);
    try std.testing.expectEqualStrings("200 OK", full.status);
    var parsed_full = try std.json.parseFromSlice(std.json.Value, alloc, full.body, .{});
    defer parsed_full.deinit();
    try std.testing.expectEqual(@as(usize, 125), parsed_full.value.object.get("memories").?.array.items.len);

    const limited = handleRequest(&ctx, "GET", "/v1/agent-memory?limit=10", "", "GET /v1/agent-memory?limit=10 HTTP/1.1\r\nAuthorization: Bearer agent-list\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", limited.status);
    var parsed_limited = try std.json.parseFromSlice(std.json.Value, alloc, limited.body, .{});
    defer parsed_limited.deinit();
    try std.testing.expectEqual(@as(usize, 10), parsed_limited.value.object.get("memories").?.array.items.len);

    const empty = handleRequest(&ctx, "GET", "/v1/agent-memory?limit=0", "", "GET /v1/agent-memory?limit=0 HTTP/1.1\r\nAuthorization: Bearer agent-list\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", empty.status);
    var parsed_empty = try std.json.parseFromSlice(std.json.Value, alloc, empty.body, .{});
    defer parsed_empty.deinit();
    try std.testing.expectEqual(@as(usize, 0), parsed_empty.value.object.get("memories").?.array.items.len);

    const window = handleRequest(&ctx, "GET", "/v1/agent-memory?limit=2&offset=3", "", "GET /v1/agent-memory?limit=2&offset=3 HTTP/1.1\r\nAuthorization: Bearer agent-list\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", window.status);
    var parsed_window = try std.json.parseFromSlice(std.json.Value, alloc, window.body, .{});
    defer parsed_window.deinit();
    const window_items = parsed_window.value.object.get("memories").?.array.items;
    try std.testing.expectEqual(@as(usize, 2), window_items.len);
    try std.testing.expectEqualStrings("nullclaw.list.121", window_items[0].object.get("key").?.string);
    try std.testing.expectEqualStrings("nullclaw.list.120", window_items[1].object.get("key").?.string);

    const metadata_only = handleRequest(&ctx, "GET", "/v1/agent-memory?limit=1&include_content=false", "", "GET /v1/agent-memory?limit=1&include_content=false HTTP/1.1\r\nAuthorization: Bearer agent-list\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", metadata_only.status);
    var parsed_metadata = try std.json.parseFromSlice(std.json.Value, alloc, metadata_only.body, .{});
    defer parsed_metadata.deinit();
    const metadata_item = parsed_metadata.value.object.get("memories").?.array.items[0].object;
    try std.testing.expect(metadata_item.get("content") == null);
    try std.testing.expect(metadata_item.get("key") != null);
    try std.testing.expect(metadata_item.get("created_by_actor_id") != null);
}

