test "api bootstrap prompt memory stores known nullclaw prompt documents" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    try std.testing.expect(domain.promptBootstrapMemoryKey("AGENTS.md") != null);
    try std.testing.expect(domain.promptBootstrapMemoryKey("README.md") == null);
    try std.testing.expect(!domain.usesWorkspaceBootstrapFiles("redis"));
    try std.testing.expect(domain.usesWorkspaceBootstrapFiles("markdown"));
    const route_cases = [_]struct {
        method: []const u8,
        path: []const u8,
        operation: api_routes.Operation,
    }{
        .{ .method = "GET", .path = "/v1/bootstrap/prompts", .operation = .bootstrapPromptsList },
        .{ .method = "GET", .path = "/v1/bootstrap/prompts/fingerprint", .operation = .bootstrapPromptsFingerprint },
        .{ .method = "POST", .path = "/v1/bootstrap/prompts/import-directory", .operation = .bootstrapPromptsImportDirectory },
        .{ .method = "POST", .path = "/v1/bootstrap/prompts/reset", .operation = .bootstrapPromptsReset },
        .{ .method = "GET", .path = "/v1/bootstrap/prompts/AGENTS.md/exists", .operation = .bootstrapPromptExists },
        .{ .method = "GET", .path = "/v1/bootstrap/prompts/AGENTS.md", .operation = .bootstrapPromptGet },
        .{ .method = "PUT", .path = "/v1/bootstrap/prompts/AGENTS.md", .operation = .bootstrapPromptPut },
        .{ .method = "POST", .path = "/v1/bootstrap/prompts/AGENTS.md", .operation = .bootstrapPromptPost },
        .{ .method = "DELETE", .path = "/v1/bootstrap/prompts/AGENTS.md", .operation = .bootstrapPromptDelete },
    };
    for (route_cases) |case| {
        try std.testing.expectEqual(case.operation, switch (api_routes.matchRequest(case.method, case.path)) {
            .operation => |operation| operation,
            else => return error.MissingCatalogOperation,
        });
    }

    const listed_empty = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts", "", "");
    try std.testing.expectEqualStrings("200 OK", listed_empty.status);
    try std.testing.expect(std.mem.indexOf(u8, listed_empty.body, "\"filename\":\"AGENTS.md\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, listed_empty.body, "\"exists\":false") != null);

    const put = handleRequest(&ctx, "PUT", "/v1/bootstrap/prompts/AGENTS.md", "{\"content\":\"Agent bootstrap instructions\"}", "");
    try std.testing.expectEqualStrings("200 OK", put.status);
    try std.testing.expect(std.mem.indexOf(u8, put.body, "\"memory_key\":\"__bootstrap.prompt.AGENTS.md\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, put.body, "Agent bootstrap instructions") != null);

    const get = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/AGENTS.md", "", "");
    try std.testing.expectEqualStrings("200 OK", get.status);
    try std.testing.expect(std.mem.indexOf(u8, get.body, "\"prompt\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, get.body, "Agent bootstrap instructions") != null);
    try std.testing.expect(std.mem.indexOf(u8, get.body, "\"truncated\":false") != null);

    const exists = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/AGENTS.md/exists", "", "");
    try std.testing.expectEqualStrings("200 OK", exists.status);
    try std.testing.expect(std.mem.indexOf(u8, exists.body, "\"exists\":true") != null);

    const excerpt = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/AGENTS.md?max_bytes=10", "", "");
    try std.testing.expectEqualStrings("200 OK", excerpt.status);
    try std.testing.expect(std.mem.indexOf(u8, excerpt.body, "\"truncated\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, excerpt.body, "Agent bootstrap instructions") == null);

    const fingerprint = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/fingerprint", "", "");
    try std.testing.expectEqualStrings("200 OK", fingerprint.status);
    try std.testing.expect(std.mem.indexOf(u8, fingerprint.body, "\"present\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, fingerprint.body, "\"total\":9") != null);

    const adapter_get = handleRequest(&ctx, "GET", "/v1/agent/memories/__bootstrap.prompt.AGENTS.md", "", "");
    try std.testing.expectEqualStrings("200 OK", adapter_get.status);
    try std.testing.expect(std.mem.indexOf(u8, adapter_get.body, "\"entry\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, adapter_get.body, "Agent bootstrap instructions") != null);

    const missing = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/README.md", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing.status);
}

test "api bootstrap reset stores bundled nullclaw workspace templates" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const reset = handleRequest(&ctx, "POST", "/v1/bootstrap/prompts/reset", "{\"include_bootstrap\":true}", "");
    try std.testing.expectEqualStrings("200 OK", reset.status);
    try std.testing.expect(std.mem.indexOf(u8, reset.body, "\"rewritten_count\":8") != null);

    const agents = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/AGENTS.md", "", "");
    try std.testing.expectEqualStrings("200 OK", agents.status);
    try std.testing.expect(std.mem.indexOf(u8, agents.body, "Source of Truth by Backend") != null);
    try std.testing.expect(std.mem.indexOf(u8, agents.body, "lancedb") != null);

    const bootstrap = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/BOOTSTRAP.md", "", "");
    try std.testing.expectEqualStrings("200 OK", bootstrap.status);
    try std.testing.expect(std.mem.indexOf(u8, bootstrap.body, "Delete this file with `file_delete`") != null);
}

test "api bootstrap prompt import-directory hydrates workspace bootstrap files" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const tmp_path = "zig-cache/tmp/nullpantry-bootstrap-test";
    std.Io.Dir.cwd().deleteTree(compat.io(), tmp_path) catch {};
    try std.Io.Dir.cwd().createDirPath(compat.io(), tmp_path);
    defer std.Io.Dir.cwd().deleteTree(compat.io(), tmp_path) catch {};
    const agents_path = try std.fs.path.join(alloc, &.{ tmp_path, "AGENTS.md" });
    const memory_path = try std.fs.path.join(alloc, &.{ tmp_path, "MEMORY.md" });
    try std.Io.Dir.cwd().writeFile(compat.io(), .{ .sub_path = agents_path, .data = "Workspace agents prompt" });
    try std.Io.Dir.cwd().writeFile(compat.io(), .{ .sub_path = memory_path, .data = "Workspace memory prompt" });

    const import_body = try std.fmt.allocPrint(alloc, "{{\"path\":\"{s}\",\"scope\":\"team:bootstrap\",\"permissions\":[\"team:bootstrap\"]}}", .{tmp_path});
    const imported = handleRequest(&ctx, "POST", "/v1/bootstrap/prompts/import-directory", import_body, "");
    try std.testing.expectEqualStrings("200 OK", imported.status);
    try std.testing.expect(std.mem.indexOf(u8, imported.body, "\"imported_count\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, imported.body, "\"filename\":\"AGENTS.md\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, imported.body, "\"filename\":\"MEMORY.md\"") != null);

    const get_shared = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/MEMORY.md?scope=team:bootstrap", "", "");
    try std.testing.expectEqualStrings("200 OK", get_shared.status);
    try std.testing.expect(std.mem.indexOf(u8, get_shared.body, "Workspace memory prompt") != null);
}

test "api bootstrap prompt boundaries reject malformed raw JSON roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const bad_reset = handleRequest(&ctx, "POST", "/v1/bootstrap/prompts/reset", "{\"include_bootstrap\":true,\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_reset.status);

    const tmp_path = "zig-cache/tmp/nullpantry-bootstrap-raw-roots-test";
    std.Io.Dir.cwd().deleteTree(compat.io(), tmp_path) catch {};
    try std.Io.Dir.cwd().createDirPath(compat.io(), tmp_path);
    defer std.Io.Dir.cwd().deleteTree(compat.io(), tmp_path) catch {};
    const agents_path = try std.fs.path.join(alloc, &.{ tmp_path, "AGENTS.md" });
    try std.Io.Dir.cwd().writeFile(compat.io(), .{ .sub_path = agents_path, .data = "Bad bootstrap import should not store" });

    const bad_import_permissions = try std.fmt.allocPrint(alloc, "{{\"path\":\"{s}\",\"permissions\":{{\"scope\":\"public\"}}}}", .{tmp_path});
    const import_permissions = handleRequest(&ctx, "POST", "/v1/bootstrap/prompts/import-directory", bad_import_permissions, "");
    try std.testing.expectEqualStrings("400 Bad Request", import_permissions.status);

    const bad_import_stores = try std.fmt.allocPrint(alloc, "{{\"path\":\"{s}\",\"permissions\":[],\"stores\":{{\"store\":\"scratch\"}}}}", .{tmp_path});
    const import_stores = handleRequest(&ctx, "POST", "/v1/bootstrap/prompts/import-directory", bad_import_stores, "");
    try std.testing.expectEqualStrings("400 Bad Request", import_stores.status);

    const agents_after_rejections = handleRequest(&ctx, "GET", "/v1/bootstrap/prompts/AGENTS.md", "", "");
    try std.testing.expectEqualStrings("404 Not Found", agents_after_rejections.status);
}

test "api native agent memory list paginates past native prefilter window" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    const principals =
        \\{"agent-page":{"actor_id":"agent:page","scopes":["public"],"capabilities":["read","write"]}}
    ;
    var ctx = Context{ .allocator = alloc, .store = &store, .token_principals_json = principals };

    for (0..505) |i| {
        const key = try std.fmt.allocPrint(alloc, "paged.{d}", .{i});
        const content = try std.fmt.allocPrint(alloc, "Paged memory {d}", .{i});
        var entry = try store.agentMemoryStore(alloc, .{ .key = key, .content = content, .actor_id = "agent:page" });
        agent_memory_runtime.freeAgentMemory(alloc, &entry);
    }

    const page = handleRequest(&ctx, "GET", "/v1/agent-memory?limit=10&offset=500", "", "GET /v1/agent-memory?limit=10&offset=500 HTTP/1.1\r\nAuthorization: Bearer agent-page\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", page.status);
    var parsed = try std.json.parseFromSlice(std.json.Value, alloc, page.body, .{});
    defer parsed.deinit();
    const memories = parsed.value.object.get("memories").?.array.items;
    try std.testing.expectEqual(@as(usize, 5), memories.len);
}

test "api agent memory supports explicit storage routing" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    const principals =
        \\{"agent-route":{"actor_id":"agent:route","scopes":["public"],"capabilities":["read","write","delete"]}}
    ;
    var ctx = Context{ .allocator = alloc, .store = &store, .token_principals_json = principals };
    const raw = "PUT /v1/agent-memory/routed.native HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}";

    const native_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/routed.native", "{\"content\":\"Native routed value\",\"store\":\"native\"}", raw);
    try std.testing.expectEqualStrings("200 OK", native_put.status);
    const native_get = handleRequest(&ctx, "GET", "/v1/agent-memory/routed.native?store=native", "", "GET /v1/agent-memory/routed.native?store=native HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", native_get.status);
    try std.testing.expect(std.mem.indexOf(u8, native_get.body, "Native routed value") != null);

    const runtime_get = handleRequest(&ctx, "GET", "/v1/agent-memory/routed.native?store=runtime", "", "GET /v1/agent-memory/routed.native?store=runtime HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("400 Bad Request", runtime_get.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_get.body, "storage_unavailable") != null);

    const runtime_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/routed.runtime", "{\"content\":\"Runtime requested value\",\"store\":\"runtime\"}", raw);
    try std.testing.expectEqualStrings("400 Bad Request", runtime_put.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_put.body, "storage_unavailable") != null);

    const all_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/routed.all", "{\"content\":\"All routed value\",\"store\":\"all\"}", raw);
    try std.testing.expectEqualStrings("200 OK", all_put.status);
    const all_search = handleRequest(&ctx, "POST", "/v1/agent-memory/search", "{\"query\":\"routed value\",\"store\":\"all\",\"limit\":10}", "POST /v1/agent-memory/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", all_search.status);
    try std.testing.expect(std.mem.indexOf(u8, all_search.body, "Native routed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, all_search.body, "All routed value") != null);

    const all_count = handleRequest(&ctx, "GET", "/v1/agent-memory/count?store=all", "", "GET /v1/agent-memory/count?store=all HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", all_count.status);
    try std.testing.expect(std.mem.indexOf(u8, all_count.body, "\"count\":2") != null);
}

test "api agent memory supports named stores and federated runtime reads" {
    if (!localPrimitiveRouteTestsEnabled()) return error.SkipZigTest;

    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{ .backend = .memory_lru },
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    const principals =
        \\{"agent-route":{"actor_id":"agent:route","scopes":["public","write:public","session:*","write:session:*"],"capabilities":["read","write","delete"]}}
    ;
    var ctx = Context{ .allocator = alloc, .store = &store, .token_principals_json = principals };
    const raw = "PUT /v1/agent-memory/named.scratch HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}";

    const scratch_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.scratch", "{\"content\":\"Named Scratch Unique\",\"store\":\"scratch\"}", raw);
    try std.testing.expectEqualStrings("200 OK", scratch_put.status);
    const archive_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.archive", "{\"content\":\"Named Archive Unique\",\"store\":\"archive\"}", raw);
    try std.testing.expectEqualStrings("200 OK", archive_put.status);
    const runtime_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.runtime", "{\"content\":\"Named Default Runtime Unique\",\"store\":\"runtime\"}", raw);
    try std.testing.expectEqualStrings("200 OK", runtime_put.status);
    const native_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.native", "{\"content\":\"Named Native Unique\",\"store\":\"native\"}", raw);
    try std.testing.expectEqualStrings("200 OK", native_put.status);
    const scratch_session_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.session", "{\"content\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"session_id\":\"sess_route\"}", raw);
    try std.testing.expectEqualStrings("200 OK", scratch_session_put.status);

    const runtime_session_hidden_search = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":false,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"limit\":10}", "POST /v1/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_hidden_search.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_hidden_search.body, "Named Scratch Session Unique") == null);
    const runtime_session_visible_search = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":true,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"limit\":10}", "POST /v1/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_visible_search.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_visible_search.body, "Named Scratch Session Unique") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_visible_search.body, "\"store\":\"scratch\"") != null);
    const runtime_session_retrieval = handleRequest(&ctx, "POST", "/v1/retrieval/search", "{\"query\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":true,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"limit\":10}", "POST /v1/retrieval/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_retrieval.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_retrieval.body, "Named Scratch Session Unique") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_retrieval.body, "\"store\":\"scratch\"") != null);
    const runtime_session_hidden_ask = handleRequest(&ctx, "POST", "/v1/ask", "{\"query\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":false,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"use_cache\":false}", "POST /v1/ask HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_hidden_ask.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_hidden_ask.body, "Named Scratch Session Unique") == null);
    const runtime_session_visible_ask = handleRequest(&ctx, "POST", "/v1/ask", "{\"query\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":true,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"use_cache\":false}", "POST /v1/ask HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_visible_ask.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_visible_ask.body, "[store:scratch] Named Scratch Session Unique") != null);
    const runtime_session_context = handleRequest(&ctx, "POST", "/v1/context-packs", "{\"task\":\"Named Scratch Session Unique\",\"store\":\"scratch\",\"scopes\":[\"session:sess_route\"],\"include_sessions\":true,\"use_vector\":false,\"use_temporal_decay\":false,\"use_mmr\":false,\"limit\":10,\"persist\":false}", "POST /v1/context-packs HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_session_context.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_session_context.body, "[store:scratch] Named Scratch Session Unique") != null);

    const scratch_count = handleRequest(&ctx, "GET", "/v1/agent-memory/count?store=scratch", "", "GET /v1/agent-memory/count?store=scratch HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_count.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_count.body, "\"count\":2") != null);
    const subset_count = handleRequest(&ctx, "GET", "/v1/agent-memory/count?stores=scratch,archive", "", "GET /v1/agent-memory/count?stores=scratch,archive HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", subset_count.status);
    try std.testing.expect(std.mem.indexOf(u8, subset_count.body, "\"count\":3") != null);
    const federated_count = handleRequest(&ctx, "GET", "/v1/agent-memory/count?store=all", "", "GET /v1/agent-memory/count?store=all HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", federated_count.status);
    try std.testing.expect(std.mem.indexOf(u8, federated_count.body, "\"count\":5") != null);

    for (0..3) |i| {
        const page_body = try std.fmt.allocPrint(alloc, "{{\"content\":\"Window Scratch Page {d}\",\"store\":\"scratch\"}}", .{i});
        const page_target = try std.fmt.allocPrint(alloc, "/v1/agent-memory/window.page.{d}", .{i});
        const page_put = handleRequest(&ctx, "PUT", page_target, page_body, raw);
        try std.testing.expectEqualStrings("200 OK", page_put.status);
    }
    const scratch_page_one = handleRequest(&ctx, "GET", "/v1/agent-memory?store=scratch&include_internal=true&limit=1", "", "GET /v1/agent-memory?store=scratch&include_internal=true&limit=1 HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_page_one.status);
    var scratch_page_one_parsed = try std.json.parseFromSlice(std.json.Value, alloc, scratch_page_one.body, .{});
    defer scratch_page_one_parsed.deinit();
    const scratch_page_one_items = scratch_page_one_parsed.value.object.get("memories").?.array.items;
    try std.testing.expectEqual(@as(usize, 1), scratch_page_one_items.len);

    const scratch_page_two = handleRequest(&ctx, "GET", "/v1/agent-memory?store=scratch&include_internal=true&limit=1&offset=1", "", "GET /v1/agent-memory?store=scratch&include_internal=true&limit=1&offset=1 HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_page_two.status);
    var scratch_page_two_parsed = try std.json.parseFromSlice(std.json.Value, alloc, scratch_page_two.body, .{});
    defer scratch_page_two_parsed.deinit();
    const scratch_page_two_items = scratch_page_two_parsed.value.object.get("memories").?.array.items;
    try std.testing.expectEqual(@as(usize, 1), scratch_page_two_items.len);
    try std.testing.expect(!std.mem.eql(u8, scratch_page_one_items[0].object.get("key").?.string, scratch_page_two_items[0].object.get("key").?.string));

    const scratch_internal_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/autosave_window_scratch", "{\"content\":\"Window Scratch Internal Hidden\",\"store\":\"scratch\"}", raw);
    try std.testing.expectEqualStrings("200 OK", scratch_internal_put.status);
    const scratch_internal_hidden = handleRequest(&ctx, "GET", "/v1/agent-memory?store=scratch&limit=3", "", "GET /v1/agent-memory?store=scratch&limit=3 HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_internal_hidden.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_internal_hidden.body, "Window Scratch Internal Hidden") == null);
    var scratch_internal_hidden_parsed = try std.json.parseFromSlice(std.json.Value, alloc, scratch_internal_hidden.body, .{});
    defer scratch_internal_hidden_parsed.deinit();
    try std.testing.expectEqual(@as(usize, 3), scratch_internal_hidden_parsed.value.object.get("memories").?.array.items.len);

    const scratch_internal_visible = handleRequest(&ctx, "GET", "/v1/agent-memory?store=scratch&include_internal=true&limit=10", "", "GET /v1/agent-memory?store=scratch&include_internal=true&limit=10 HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_internal_visible.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_internal_visible.body, "Window Scratch Internal Hidden") != null);

    const runtime_route_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.runtime.route", "{\"content\":\"Named Runtime Route Unique\",\"store\":\"runtime\"}", raw);
    try std.testing.expectEqualStrings("200 OK", runtime_route_put.status);
    const runtime_route_get = handleRequest(&ctx, "GET", "/v1/agent-memory/named.runtime.route?store=runtime", "", "GET /v1/agent-memory/named.runtime.route?store=runtime HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", runtime_route_get.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_route_get.body, "Named Runtime Route Unique") != null);
    const runtime_route_search = handleRequest(&ctx, "POST", "/v1/agent-memory/search?store=runtime", "{\"query\":\"Named Runtime Route\",\"limit\":10}", "POST /v1/agent-memory/search?store=runtime HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", runtime_route_search.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_route_search.body, "Named Runtime Route Unique") != null);

    const scratch_get = handleRequest(&ctx, "GET", "/v1/agent-memory/named.scratch?store=scratch", "", "GET /v1/agent-memory/named.scratch?store=scratch HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("200 OK", scratch_get.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_get.body, "Named Scratch Unique") != null);

    const wrong_store_get = handleRequest(&ctx, "GET", "/v1/agent-memory/named.scratch?store=archive", "", "GET /v1/agent-memory/named.scratch?store=archive HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n");
    try std.testing.expectEqualStrings("404 Not Found", wrong_store_get.status);

    const named_search = handleRequest(&ctx, "POST", "/v1/agent-memory/search", "{\"query\":\"Named Scratch Unique\",\"store\":\"scratch\",\"limit\":10}", "POST /v1/agent-memory/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", named_search.status);
    try std.testing.expect(std.mem.indexOf(u8, named_search.body, "Named Scratch Unique") != null);
    try std.testing.expect(std.mem.indexOf(u8, named_search.body, "Named Archive Unique") == null);

    const query_routed_key_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.query.key?store=scratch", "{\"content\":\"Named Query Key Scratch Unique\"}", "PUT /v1/agent-memory/named.query.key?store=scratch HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", query_routed_key_put.status);
    const query_routed_body_put = handleRequest(&ctx, "POST", "/v1/agent-memory?store=archive", "{\"key\":\"named.query.body\",\"content\":\"Named Query Body Archive Unique\"}", "POST /v1/agent-memory?store=archive HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", query_routed_body_put.status);
    const query_wins_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/named.query.query_wins?store=archive", "{\"content\":\"Named Query Wins Archive Unique\",\"store\":\"scratch\"}", "PUT /v1/agent-memory/named.query.query_wins?store=archive HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", query_wins_put.status);

    const query_scratch_search = handleRequest(&ctx, "POST", "/v1/agent-memory/search?store=scratch", "{\"query\":\"Named Query\",\"limit\":10}", "POST /v1/agent-memory/search?store=scratch HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
    try std.testing.expectEqualStrings("200 OK", query_scratch_search.status);
