test "api nullclaw memory feed routes named stores independently" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{ .backend = .memory_lru },
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:nullclaw-routed-feed",
        .actor_scopes_json = "[\"public\",\"write:public\",\"actor:agent:nullclaw-routed-feed\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const scratch_put = handleRequest(&ctx, "POST", "/v1/agent/memory/apply?store=scratch", "{\"origin_instance_id\":\"nullclaw-routed\",\"origin_sequence\":1,\"timestamp_ms\":100,\"operation\":\"put\",\"key\":\"route.scratch.pref\",\"content\":\"scratch routed feed value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_put.status);
    const archive_put = handleRequest(&ctx, "POST", "/v1/agent/memory/apply?store=archive", "{\"origin_instance_id\":\"nullclaw-routed\",\"origin_sequence\":2,\"timestamp_ms\":200,\"operation\":\"put\",\"key\":\"route.archive.pref\",\"content\":\"archive routed feed value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", archive_put.status);
    const scratch_native_event = handleRequest(&ctx, "POST", "/v1/memory/events?store=scratch", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"route_scratch_native_atom\",\"scope\":\"public\",\"payload\":{\"text\":\"scratch native route event\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_native_event.status);

    const scratch_feed = handleRequest(&ctx, "GET", "/v1/agent/memory/events?store=scratch&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_feed.body, "scratch routed feed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_feed.body, "archive routed feed value") == null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_feed.body, "\"store\":\"scratch\"") != null);

    const archive_feed = handleRequest(&ctx, "GET", "/v1/agent/memory/events?store=archive&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", archive_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_feed.body, "archive routed feed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, archive_feed.body, "scratch routed feed value") == null);
    try std.testing.expect(std.mem.indexOf(u8, archive_feed.body, "\"store\":\"archive\"") != null);

    const scratch_status = handleRequest(&ctx, "GET", "/v1/agent/memory/status?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_status.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_status.body, "\"visible_events\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_status.body, "\"last_sequence\":3") != null);

    const scratch_checkpoint = handleRequest(&ctx, "GET", "/v1/agent/memory/checkpoint?store=scratch&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_checkpoint.body, "scratch routed feed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_checkpoint.body, "archive routed feed value") == null);

    const compact_scratch = handleRequest(&ctx, "POST", "/v1/agent/memory/compact?store=scratch", "{\"through_sequence\":1}", "");
    try std.testing.expectEqualStrings("200 OK", compact_scratch.status);
    try std.testing.expect(std.mem.indexOf(u8, compact_scratch.body, "\"projection\":\"storage_route\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, compact_scratch.body, "\"name\":\"scratch\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, compact_scratch.body, "\"cursor_floor\":1") != null);

    const scratch_ndjson = handleRequest(&ctx, "GET", "/v1/agent/memory/checkpoint?format=ndjson&store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_ndjson.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_ndjson.body, "\"kind\":\"meta\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_ndjson.body, "\"compacted_through_sequence\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_ndjson.body, "scratch routed feed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_ndjson.body, "archive routed feed value") == null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_ndjson.body, "scratch native route event") == null);

    const expired_scratch = handleRequest(&ctx, "GET", "/v1/agent/memory/events?store=scratch&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("410 Gone", expired_scratch.status);
    const native_scratch_after_nullclaw_compact = handleRequest(&ctx, "GET", "/v1/memory/events?store=scratch&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", native_scratch_after_nullclaw_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, native_scratch_after_nullclaw_compact.body, "scratch native route event") != null);
    try std.testing.expect(std.mem.indexOf(u8, native_scratch_after_nullclaw_compact.body, "archive routed feed value") == null);
    const archive_after_scratch_compact = handleRequest(&ctx, "GET", "/v1/agent/memory/events?store=archive&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", archive_after_scratch_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_after_scratch_compact.body, "archive routed feed value") != null);
    try std.testing.expect(std.mem.indexOf(u8, archive_after_scratch_compact.body, "scratch routed feed value") == null);

    const scratch_frontier_seed =
        \\{"kind":"meta","schema_version":1,"last_sequence":7,"last_timestamp_ms":700,"compacted_through_sequence":0}
        \\{"kind":"frontier","origin_instance_id":"remote-scratch","origin_sequence":7}
    ;
    const seeded_frontier = handleRequest(&ctx, "POST", "/v1/agent/memory/checkpoint?store=scratch", scratch_frontier_seed, "");
    try std.testing.expectEqualStrings("200 OK", seeded_frontier.status);
    const stale_scratch_replay = handleRequest(&ctx, "POST", "/v1/agent/memory/apply?store=scratch", "{\"origin_instance_id\":\"remote-scratch\",\"origin_sequence\":6,\"timestamp_ms\":600,\"operation\":\"put\",\"key\":\"route.frontier.scratch\",\"content\":\"stale scratch frontier replay\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", stale_scratch_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, stale_scratch_replay.body, "\"skipped\":true") != null);
    const stale_scratch_get = handleRequest(&ctx, "GET", "/v1/agent-memory/route.frontier.scratch?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", stale_scratch_get.status);
    const archive_same_origin_replay = handleRequest(&ctx, "POST", "/v1/agent/memory/apply?store=archive", "{\"origin_instance_id\":\"remote-scratch\",\"origin_sequence\":6,\"timestamp_ms\":600,\"operation\":\"put\",\"key\":\"route.frontier.archive\",\"content\":\"archive frontier is independent\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", archive_same_origin_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_same_origin_replay.body, "\"skipped\":true") == null);
    const archive_same_origin_get = handleRequest(&ctx, "GET", "/v1/agent-memory/route.frontier.archive?store=archive&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", archive_same_origin_get.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_same_origin_get.body, "archive frontier is independent") != null);

    const body_store_apply = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"store\":\"scratch\",\"origin_instance_id\":\"body-store-origin\",\"origin_sequence\":1,\"timestamp_ms\":800,\"operation\":\"put\",\"key\":\"route.body_store.pref\",\"content\":\"body store routed value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", body_store_apply.status);
    const body_store_scratch_get = handleRequest(&ctx, "GET", "/v1/agent-memory/route.body_store.pref?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", body_store_scratch_get.status);
    try std.testing.expect(std.mem.indexOf(u8, body_store_scratch_get.body, "body store routed value") != null);
    const body_store_default_get = handleRequest(&ctx, "GET", "/v1/agent-memory/route.body_store.pref?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", body_store_default_get.status);
}

test "api nullclaw memory feed respects global cursor floor" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:nullclaw-floor",
        .actor_scopes_json = "[\"public\",\"write:public\",\"actor:agent:nullclaw-floor\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"export\",\"feed_apply\"]",
    };

    const apply_body =
        \\{"origin_instance_id":"nullclaw-global-floor","origin_sequence":1,"timestamp_ms":321,"operation":"put","key":"api.global_floor","category":"core","content":"Agent memory before global compact","scope":"public"}
    ;
    const apply = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", apply_body, "");
    try std.testing.expectEqualStrings("200 OK", apply.status);
    const non_agent = handleRequest(&ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory.note\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"global_floor_non_agent\",\"scope\":\"public\",\"payload\":{\"text\":\"Non-agent feed before global compact\"}}", "");
    try std.testing.expectEqualStrings("200 OK", non_agent.status);

    const feed_before_compact = handleRequest(&ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", feed_before_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, feed_before_compact.body, "api.global_floor") != null);

    const compact = handleRequest(&ctx, "POST", "/v1/memory/compact", "{}", "");
    try std.testing.expectEqualStrings("200 OK", compact.status);
    try std.testing.expect(std.mem.indexOf(u8, compact.body, "\"cursor_floor\":2") != null);

    const expired_feed = handleRequest(&ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("410 Gone", expired_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, expired_feed.body, "cursor_expired") != null);

    const status = handleRequest(&ctx, "GET", "/v1/agent/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", status.status);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"cursor_floor\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"visible_events\":0") != null);

    const checkpoint = handleRequest(&ctx, "GET", "/v1/agent/memory/checkpoint?after=0&limit=10", "", "");
