    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"cursor_floor\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "api.global_floor") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "Non-agent feed before global compact") == null);
}

test "api nullclaw memory checkpoint supports ndjson export restore and apply" {
    var source_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer source_store.deinit();
    var target_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer target_store.deinit();
    var source_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer source_arena.deinit();
    var target_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer target_arena.deinit();
    var source_ctx = Context{
        .allocator = source_arena.allocator(),
        .store = &source_store,
        .actor_id = "agent:nullclaw-ndjson",
        .actor_scopes_json = "[\"public\",\"write:public\",\"delete:public\",\"session:s1\",\"write:session:s1\",\"actor:agent:nullclaw-ndjson\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };
    var target_ctx = Context{
        .allocator = target_arena.allocator(),
        .store = &target_store,
        .actor_id = "agent:nullclaw-ndjson",
        .actor_scopes_json = "[\"public\",\"write:public\",\"delete:public\",\"session:s1\",\"write:session:s1\",\"actor:agent:nullclaw-ndjson\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const put_global = handleRequest(&source_ctx, "PUT", "/v1/agent-memory/ndjson.pref", "{\"content\":\"NDJSON exported value\",\"scope\":\"public\",\"permissions\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", put_global.status);
    const put_session = handleRequest(&source_ctx, "PUT", "/v1/agent-memory/ndjson.session", "{\"content\":\"NDJSON session value\",\"scope\":\"public\",\"permissions\":[\"public\"],\"session_id\":\"s1\"}", "");
    try std.testing.expectEqualStrings("200 OK", put_session.status);

    const ndjson = handleRequest(&source_ctx, "GET", "/v1/agent/memory/checkpoint?format=ndjson", "", "");
    try std.testing.expectEqualStrings("200 OK", ndjson.status);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "\"kind\":\"meta\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "\"kind\":\"state\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "\"events\"") == null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "NDJSON exported value") != null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "NDJSON session value") != null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "\"scope\":\"public\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, ndjson.body, "\"permissions\":[]") != null);

    const restore = handleRequest(&target_ctx, "POST", "/v1/agent/memory/checkpoint", ndjson.body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    const restored_global = handleRequest(&target_ctx, "GET", "/v1/agent-memory/ndjson.pref", "", "");
    try std.testing.expectEqualStrings("200 OK", restored_global.status);
    try std.testing.expect(std.mem.indexOf(u8, restored_global.body, "NDJSON exported value") != null);
    const restored_session = handleRequest(&target_ctx, "GET", "/v1/agent-memory/ndjson.session?session_id=s1", "", "");
    try std.testing.expectEqualStrings("200 OK", restored_session.status);
    try std.testing.expect(std.mem.indexOf(u8, restored_session.body, "NDJSON session value") != null);

    const scoped_tombstone =
        \\{"kind":"meta","schema_version":1,"last_sequence":3,"last_timestamp_ms":300,"compacted_through_sequence":0}
        \\{"kind":"state","key":"ndjson.deleted","session_id":"s1","category":"core","value_kind":null,"content":"should be deleted","timestamp_ms":100,"origin_instance_id":"nullclaw-local","origin_sequence":1,"scope":"public","permissions":["public"]}
        \\{"kind":"scoped_tombstone","key":"s:2:s1:ndjson.deleted","timestamp_ms":200,"origin_instance_id":"nullclaw-local","origin_sequence":2,"scope":"public","permissions":["public"]}
    ;
    const apply_restore = handleRequest(&target_ctx, "POST", "/v1/agent/memory/apply", scoped_tombstone, "");
    try std.testing.expectEqualStrings("200 OK", apply_restore.status);
    const deleted_session = handleRequest(&target_ctx, "GET", "/v1/agent-memory/ndjson.deleted?session_id=s1", "", "");
    try std.testing.expectEqualStrings("404 Not Found", deleted_session.status);

    const key_tombstone =
        \\{"kind":"meta","schema_version":1,"last_sequence":6,"last_timestamp_ms":600,"compacted_through_sequence":0}
        \\{"kind":"state","key":"ndjson.delete_all","session_id":null,"category":"core","value_kind":null,"content":"delete all global","timestamp_ms":400,"origin_instance_id":"nullclaw-local","origin_sequence":4,"scope":"public","permissions":["public"]}
        \\{"kind":"state","key":"ndjson.delete_all","session_id":"s1","category":"core","value_kind":null,"content":"delete all session","timestamp_ms":500,"origin_instance_id":"nullclaw-local","origin_sequence":5,"scope":"public","permissions":["public"]}
        \\{"kind":"key_tombstone","key":"g:ndjson.delete_all","timestamp_ms":600,"origin_instance_id":"nullclaw-local","origin_sequence":6,"scope":"public","permissions":["public"]}
    ;
    const delete_all_restore = handleRequest(&target_ctx, "POST", "/v1/memory/apply", key_tombstone, "");
    try std.testing.expectEqualStrings("200 OK", delete_all_restore.status);
    const deleted_global = handleRequest(&target_ctx, "GET", "/v1/agent-memory/ndjson.delete_all", "", "");
    try std.testing.expectEqualStrings("404 Not Found", deleted_global.status);
    const deleted_all_session = handleRequest(&target_ctx, "GET", "/v1/agent-memory/ndjson.delete_all?session_id=s1", "", "");
    try std.testing.expectEqualStrings("404 Not Found", deleted_all_session.status);

    const frontier_only =
        \\{"kind":"meta","schema_version":1,"last_sequence":10,"last_timestamp_ms":1000,"compacted_through_sequence":10}
        \\{"kind":"frontier","origin_instance_id":"nullclaw-frontier","origin_sequence":10}
    ;
    const frontier_restore = handleRequest(&target_ctx, "POST", "/v1/agent/memory/checkpoint", frontier_only, "");
    try std.testing.expectEqualStrings("200 OK", frontier_restore.status);

    const old_replay = handleRequest(&target_ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-frontier\",\"origin_sequence\":5,\"operation\":\"put\",\"key\":\"frontier.old\",\"category\":\"core\",\"content\":\"must not apply\",\"scope\":\"public\",\"permissions\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", old_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, old_replay.body, "\"skipped\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, old_replay.body, "\"origin_frontier\"") != null);
    const old_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/frontier.old", "", "");
    try std.testing.expectEqualStrings("404 Not Found", old_get.status);

    const new_replay = handleRequest(&target_ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-frontier\",\"origin_sequence\":11,\"operation\":\"put\",\"key\":\"frontier.old\",\"category\":\"core\",\"content\":\"new replay applies\",\"scope\":\"public\",\"permissions\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", new_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, new_replay.body, "\"skipped\":true") == null);
    const new_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/frontier.old", "", "");
    try std.testing.expectEqualStrings("200 OK", new_get.status);
    try std.testing.expect(std.mem.indexOf(u8, new_get.body, "new replay applies") != null);
    const frontier_export = handleRequest(&target_ctx, "GET", "/v1/agent/memory/checkpoint?format=ndjson", "", "");
    try std.testing.expectEqualStrings("200 OK", frontier_export.status);
    try std.testing.expect(std.mem.indexOf(u8, frontier_export.body, "\"kind\":\"frontier\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, frontier_export.body, "\"origin_instance_id\":\"nullclaw-frontier\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, frontier_export.body, "\"origin_sequence\":11") != null);

    const local_frontier_only =
        \\{"kind":"meta","schema_version":1,"last_sequence":20,"last_timestamp_ms":2000,"compacted_through_sequence":20}
        \\{"kind":"frontier","origin_instance_id":"nullpantry","origin_sequence":20}
    ;
    const local_frontier_restore = handleRequest(&target_ctx, "POST", "/v1/agent/memory/checkpoint", local_frontier_only, "");
    try std.testing.expectEqualStrings("200 OK", local_frontier_restore.status);
    const frontier_status = handleRequest(&target_ctx, "GET", "/v1/agent/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", frontier_status.status);
    try std.testing.expect(std.mem.indexOf(u8, frontier_status.body, "\"instance_id\":\"nullpantry\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, frontier_status.body, "\"next_local_origin_sequence\":21") != null);

    const stale_local_replay = handleRequest(&target_ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullpantry\",\"origin_sequence\":19,\"operation\":\"put\",\"key\":\"frontier.local\",\"category\":\"core\",\"content\":\"stale local replay\",\"scope\":\"public\",\"permissions\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", stale_local_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, stale_local_replay.body, "\"skipped\":true") != null);
    const stale_local_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/frontier.local", "", "");
    try std.testing.expectEqualStrings("404 Not Found", stale_local_get.status);

    const next_local_replay = handleRequest(&target_ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullpantry\",\"origin_sequence\":21,\"operation\":\"put\",\"key\":\"frontier.local\",\"category\":\"core\",\"content\":\"next local replay\",\"scope\":\"public\",\"permissions\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", next_local_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, next_local_replay.body, "\"skipped\":true") == null);
    const next_local_status = handleRequest(&target_ctx, "GET", "/v1/agent/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", next_local_status.status);
    try std.testing.expect(std.mem.indexOf(u8, next_local_status.body, "\"next_local_origin_sequence\":22") != null);
}

test "api nullclaw top-level feed apply deletes scoped and all session variants" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
