}

test "api all-store session message feed apply tombstones protect native and runtime stores" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{.{ .name = "scratch", .config = .{ .backend = .memory_lru } }},
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:message-tombstone",
        .actor_scopes_json = "[\"session:messages\",\"write:session:messages\",\"actor:agent:message-tombstone\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const put = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":20,\"timestamp_ms\":200,\"payload\":{\"session_id\":\"messages\",\"role\":\"user\",\"content\":\"live message\",\"created_at_ms\":17}}", "");
    try std.testing.expectEqualStrings("200 OK", put.status);
    const delete = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.delete\",\"operation\":\"delete\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":21,\"timestamp_ms\":300,\"payload\":{\"session_id\":\"messages\"}}", "");
    try std.testing.expectEqualStrings("200 OK", delete.status);
    const stale_put = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":19,\"timestamp_ms\":100,\"payload\":{\"session_id\":\"messages\",\"role\":\"user\",\"content\":\"stale message\",\"created_at_ms\":19}}", "");
    try std.testing.expectEqualStrings("200 OK", stale_put.status);

    const native_after_stale = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=native", "", "");
    try std.testing.expectEqualStrings("200 OK", native_after_stale.status);
    try std.testing.expect(std.mem.indexOf(u8, native_after_stale.body, "live message") == null);
    try std.testing.expect(std.mem.indexOf(u8, native_after_stale.body, "stale message") == null);
    const runtime_after_stale = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_after_stale.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_after_stale.body, "live message") == null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_after_stale.body, "stale message") == null);

    const newer_put = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":22,\"timestamp_ms\":400,\"payload\":{\"session_id\":\"messages\",\"role\":\"assistant\",\"content\":\"newer message\",\"created_at_ms\":22}}", "");
    try std.testing.expectEqualStrings("200 OK", newer_put.status);
    const native_after_newer = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=native", "", "");
    try std.testing.expectEqualStrings("200 OK", native_after_newer.status);
    try std.testing.expect(std.mem.indexOf(u8, native_after_newer.body, "newer message") != null);
    const runtime_after_newer = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_after_newer.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_after_newer.body, "newer message") != null);

    const newest_put = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":30,\"timestamp_ms\":500,\"payload\":{\"session_id\":\"messages\",\"role\":\"assistant\",\"content\":\"latest message\",\"created_at_ms\":30}}", "");
    try std.testing.expectEqualStrings("200 OK", newest_put.status);
    const older_put = handleRequest(&ctx, "POST", "/v1/memory/apply?store=all", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"origin_instance_id\":\"message-tombstone\",\"origin_sequence\":29,\"timestamp_ms\":450,\"payload\":{\"session_id\":\"messages\",\"role\":\"assistant\",\"content\":\"older message\",\"created_at_ms\":29}}", "");
    try std.testing.expectEqualStrings("200 OK", older_put.status);
    const native_after_older = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=native", "", "");
    try std.testing.expectEqualStrings("200 OK", native_after_older.status);
    const native_older_index = std.mem.indexOf(u8, native_after_older.body, "older message") orelse return error.TestUnexpectedResult;
    const native_latest_index = std.mem.indexOf(u8, native_after_older.body, "latest message") orelse return error.TestUnexpectedResult;
    try std.testing.expect(native_older_index < native_latest_index);
    const runtime_after_older = handleRequest(&ctx, "GET", "/v1/agent-sessions/messages/messages?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_after_older.status);
    const runtime_older_index = std.mem.indexOf(u8, runtime_after_older.body, "older message") orelse return error.TestUnexpectedResult;
    const runtime_latest_index = std.mem.indexOf(u8, runtime_after_older.body, "latest message") orelse return error.TestUnexpectedResult;
    try std.testing.expect(runtime_older_index < runtime_latest_index);
}

