    };

    const queued = handleRequest(&ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"payload.root.queue\",\"scope\":\"public\",\"payload\":[]}", "");
