    const applied = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"payload.root.apply\",\"origin_instance_id\":\"payload-root-api\",\"origin_sequence\":1,\"scope\":\"public\",\"payload_json\":\"[]\"}", "");
