    const checkpoint =
        \\{"events":[
        \\{"origin_instance_id":"payload-root-api","origin_sequence":2,"event_type":"memory_atom.put","operation":"put","object_type":"memory_atom","object_id":"payload.root.checkpoint","scope":"public","actor_id":"agent:payload-root-api","payload":[]}
        \\]}
