test "api memory feed endpoints honor named runtime route selection" {
    if (!localPrimitiveRouteTestsEnabled()) return error.SkipZigTest;

    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:route",
        .actor_scopes_json = "[\"public\",\"write:public\",\"session:*\",\"write:session:*\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const local_status = handleRequest(&ctx, "GET", "/v1/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", local_status.status);
    try std.testing.expect(std.mem.indexOf(u8, local_status.body, "\"instance_id\"") != null);

    const named_apply = handleRequest(&ctx, "POST", "/v1/memory/apply?store=scratch", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"feed.routed\",\"content\":\"Scratch routed feed apply\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", named_apply.status);

    const scratch_get = handleRequest(&ctx, "GET", "/v1/agent-memory/feed.routed?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_get.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_get.body, "Scratch routed feed apply") != null);

    const native_get = handleRequest(&ctx, "GET", "/v1/agent-memory/feed.routed?storage=native&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", native_get.status);

    const query_override_apply = handleRequest(&ctx, "POST", "/v1/memory/apply?store=scratch", "{\"storage\":\"native\",\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"feed.route.query_override\",\"content\":\"Query route overrides body selector\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", query_override_apply.status);
    const query_override_scratch = handleRequest(&ctx, "GET", "/v1/agent-memory/feed.route.query_override?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", query_override_scratch.status);
    try std.testing.expect(std.mem.indexOf(u8, query_override_scratch.body, "Query route overrides body selector") != null);
    const query_override_native = handleRequest(&ctx, "GET", "/v1/agent-memory/feed.route.query_override?storage=native&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", query_override_native.status);

    const payload_override_apply = handleRequest(&ctx, "POST", "/v1/memory/apply?store=scratch", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"feed.route.payload_override\",\"content\":\"Query route overrides payload selector\",\"scope\":\"public\",\"store\":\"archive\"}}", "");
    try std.testing.expectEqualStrings("200 OK", payload_override_apply.status);
    const payload_override_scratch = handleRequest(&ctx, "GET", "/v1/agent-memory/feed.route.payload_override?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", payload_override_scratch.status);
    try std.testing.expect(std.mem.indexOf(u8, payload_override_scratch.body, "Query route overrides payload selector") != null);
