test "api storage-route central feed respects global cursor floor" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{.{ .name = "scratch", .config = .{ .backend = .memory_lru } }},
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:route-floor",
        .actor_scopes_json = "[\"public\",\"write:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const scratch_event = handleRequest(&ctx, "POST", "/v1/memory/events?store=scratch", "{\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"ami_route_floor_scratch\",\"scope\":\"public\",\"payload\":{\"key\":\"route.floor.scratch\",\"content\":\"Scratch event before global compact\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_event.status);
    const native_event = handleRequest(&ctx, "POST", "/v1/memory/events?storage=native", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"route_floor_native\",\"scope\":\"public\",\"payload\":{\"text\":\"Native event before global compact\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", native_event.status);

    const scratch_before_compact = handleRequest(&ctx, "GET", "/v1/memory/events?store=scratch&after=0", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_before_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_before_compact.body, "Scratch event before global compact") != null);

    const compact = handleRequest(&ctx, "POST", "/v1/memory/compact", "{}", "");
    try std.testing.expectEqualStrings("200 OK", compact.status);
    try std.testing.expect(std.mem.indexOf(u8, compact.body, "\"cursor_floor\":2") != null);

    const expired_scratch_feed = handleRequest(&ctx, "GET", "/v1/memory/events?store=scratch&after=0", "", "");
    try std.testing.expectEqualStrings("410 Gone", expired_scratch_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, expired_scratch_feed.body, "cursor_expired") != null);

    const scratch_status = handleRequest(&ctx, "GET", "/v1/memory/status?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_status.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_status.body, "\"cursor_floor\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_status.body, "\"visible_events\":0") != null);

    const recovery_checkpoint = handleRequest(&ctx, "GET", "/v1/memory/checkpoint?store=scratch&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", recovery_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, recovery_checkpoint.body, "\"cursor_floor\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, recovery_checkpoint.body, "Scratch event before global compact") != null);
    try std.testing.expect(std.mem.indexOf(u8, recovery_checkpoint.body, "Native event before global compact") == null);
}

test "api central runtime feed projection covers native agent memory sessions and usage" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var target_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer target_store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var target_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer target_arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:central-runtime",
        .actor_scopes_json = "[\"public\",\"write:public\",\"session:central-runtime\",\"write:session:central-runtime\",\"actor:agent:central-runtime\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };
    var target_ctx = Context{
        .allocator = target_arena.allocator(),
        .store = &target_store,
        .actor_id = "agent:central-runtime",
        .actor_scopes_json = "[\"public\",\"write:public\",\"session:central-runtime\",\"write:session:central-runtime\",\"actor:agent:central-runtime\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const memory_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/central.runtime.pref", "{\"content\":\"Central native runtime memory\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", memory_put.status);
    const message_put = handleRequest(&ctx, "POST", "/v1/agent-sessions/central-runtime/messages", "{\"role\":\"assistant\",\"content\":\"Central native runtime session message\"}", "");
    try std.testing.expectEqualStrings("200 OK", message_put.status);
    const usage_put = handleRequest(&ctx, "PUT", "/v1/agent-sessions/central-runtime/usage", "{\"total_tokens\":321}", "");
    try std.testing.expectEqualStrings("200 OK", usage_put.status);
    const knowledge_event = handleRequest(&ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"central_runtime_knowledge\",\"scope\":\"public\",\"payload\":{\"text\":\"Knowledge event must not be in runtime projection\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", knowledge_event.status);
    const rejected_runtime_queue = handleRequest(&ctx, "POST", "/v1/memory/events?feed_backend=runtime", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"runtime_reject_queue\",\"scope\":\"public\",\"payload\":{\"text\":\"must reject queue\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", rejected_runtime_queue.status);
    try std.testing.expect(std.mem.indexOf(u8, rejected_runtime_queue.body, "Runtime feed backend only supports agent runtime object types") != null);
    const rejected_runtime_apply = handleRequest(&ctx, "POST", "/v1/memory/apply?feed_backend=runtime", "{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"runtime_reject_apply\",\"scope\":\"public\",\"payload\":{\"text\":\"must reject apply\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", rejected_runtime_apply.status);
    try std.testing.expect(std.mem.indexOf(u8, rejected_runtime_apply.body, "Runtime feed backend only supports agent runtime object types") != null);
    const rejected_runtime_restore = handleRequest(&target_ctx, "POST", "/v1/memory/checkpoint?feed_backend=runtime", "{\"events\":[{\"event_type\":\"memory_atom.put\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"runtime_reject_restore\",\"scope\":\"public\",\"payload\":{\"text\":\"must reject restore\",\"scope\":\"public\"}}]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", rejected_runtime_restore.status);
    try std.testing.expect(std.mem.indexOf(u8, rejected_runtime_restore.body, "Runtime feed backend only supports agent runtime object types") != null);

    const runtime_feed = handleRequest(&ctx, "GET", "/v1/memory/events?feed_backend=runtime&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "\"object_type\":\"agent_memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "\"object_type\":\"agent_session_message\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "\"object_type\":\"agent_session_usage\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "Central native runtime memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "Central native runtime session message") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "\"total_tokens\":321") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_feed.body, "Knowledge event must not be in runtime projection") == null);

    const runtime_status = handleRequest(&ctx, "GET", "/v1/memory/status?feed_backend=runtime", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_status.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_status.body, "\"feed_object_types\":[\"agent_memory\",\"agent_session_message\",\"agent_session_usage\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_status.body, "\"visible_events\":3") != null);

    const runtime_checkpoint = handleRequest(&ctx, "GET", "/v1/memory/checkpoint?feed_backend=runtime&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", runtime_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_checkpoint.body, "\"feed_object_types\":[\"agent_memory\",\"agent_session_message\",\"agent_session_usage\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_checkpoint.body, "Central native runtime memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_checkpoint.body, "Central native runtime session message") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_checkpoint.body, "\"total_tokens\":321") != null);
    try std.testing.expect(std.mem.indexOf(u8, runtime_checkpoint.body, "Knowledge event must not be in runtime projection") == null);

    const runtime_compact = handleRequest(&ctx, "POST", "/v1/memory/compact?feed_backend=runtime", "{}", "");
    try std.testing.expectEqualStrings("200 OK", runtime_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, runtime_compact.body, "\"projection\":\"runtime_object_types\"") != null);
    const expired_runtime_feed = handleRequest(&ctx, "GET", "/v1/memory/events?feed_backend=runtime&after=0", "", "");
    try std.testing.expectEqualStrings("410 Gone", expired_runtime_feed.status);
    const global_feed_after_runtime_compact = handleRequest(&ctx, "GET", "/v1/memory/events?after=0", "", "");
    try std.testing.expectEqualStrings("200 OK", global_feed_after_runtime_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, global_feed_after_runtime_compact.body, "Knowledge event must not be in runtime projection") != null);

    const compacted_checkpoint = handleRequest(&ctx, "GET", "/v1/memory/checkpoint?feed_backend=runtime&after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", compacted_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, compacted_checkpoint.body, "\"cursor_floor\":") != null);
    const restore = handleRequest(&target_ctx, "POST", "/v1/memory/apply?feed_backend=runtime", compacted_checkpoint.body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    const target_expired_runtime_feed = handleRequest(&target_ctx, "GET", "/v1/memory/events?feed_backend=runtime&after=0", "", "");
    try std.testing.expectEqualStrings("410 Gone", target_expired_runtime_feed.status);
    const target_global_feed = handleRequest(&target_ctx, "GET", "/v1/memory/events?after=0", "", "");
    try std.testing.expectEqualStrings("200 OK", target_global_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, target_global_feed.body, "Knowledge event must not be in runtime projection") == null);
}

