test "api runtime feed apply requires mutation rights beyond feed_apply" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{.{ .name = "scratch", .config = .{ .backend = .memory_lru } }},
    });
    defer store.deinit();

    var read_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer read_arena.deinit();
    var write_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer write_arena.deinit();
    var feed_only_ctx = Context{
        .allocator = read_arena.allocator(),
        .store = &store,
        .actor_id = "agent:runtime-feed-auth",
        .actor_scopes_json = "[\"public\"]",
        .actor_capabilities_json = "[\"read\",\"feed_apply\"]",
    };
    var write_ctx = Context{
        .allocator = write_arena.allocator(),
        .store = &store,
        .actor_id = "agent:runtime-feed-auth",
        .actor_scopes_json = "[\"public\",\"write:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"feed_apply\"]",
    };
    var delete_arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer delete_arena.deinit();
    var delete_ctx = Context{
        .allocator = delete_arena.allocator(),
        .store = &store,
        .actor_id = "agent:runtime-feed-auth",
        .actor_scopes_json = "[\"public\",\"write:public\",\"delete:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"feed_apply\"]",
    };

    const denied_put = handleRequest(&feed_only_ctx, "POST", "/v1/memory/apply?store=scratch&runtime_feed=true", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"origin_instance_id\":\"runtime-feed-auth\",\"origin_sequence\":1,\"payload\":{\"key\":\"runtime.feed.auth\",\"content\":\"must not apply with feed_apply only\",\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("403 Forbidden", denied_put.status);
    const missing_after_denied = handleRequest(&write_ctx, "GET", "/v1/agent-memory/runtime.feed.auth?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_after_denied.status);

    const denied_checkpoint = handleRequest(&feed_only_ctx, "POST", "/v1/memory/checkpoint?store=scratch&runtime_feed=true", "{\"events\":[{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"origin_instance_id\":\"runtime-feed-auth\",\"origin_sequence\":2,\"actor_id\":\"agent:runtime-feed-auth\",\"payload\":{\"key\":\"runtime.feed.auth.checkpoint\",\"content\":\"checkpoint must not apply with feed_apply only\",\"scope\":\"public\",\"owner_id\":\"shared:public\"}}]}", "");
    try std.testing.expectEqualStrings("403 Forbidden", denied_checkpoint.status);

    const allowed_put = handleRequest(&write_ctx, "POST", "/v1/memory/apply?store=scratch&runtime_feed=true", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"origin_instance_id\":\"runtime-feed-auth\",\"origin_sequence\":3,\"actor_id\":\"agent:runtime-feed-auth\",\"payload\":{\"key\":\"runtime.feed.auth\",\"content\":\"allowed with write scope\",\"scope\":\"public\",\"owner_id\":\"shared:public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", allowed_put.status);
    const restored = handleRequest(&write_ctx, "GET", "/v1/agent-memory/runtime.feed.auth?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", restored.status);
    try std.testing.expect(std.mem.indexOf(u8, restored.body, "allowed with write scope") != null);

    const denied_delete = handleRequest(&write_ctx, "POST", "/v1/memory/apply?store=scratch&runtime_feed=true", "{\"event_type\":\"agent_memory.delete\",\"operation\":\"delete\",\"object_type\":\"agent_memory\",\"origin_instance_id\":\"runtime-feed-auth\",\"origin_sequence\":4,\"actor_id\":\"agent:runtime-feed-auth\",\"payload\":{\"key\":\"runtime.feed.auth\",\"scope\":\"public\",\"owner_id\":\"shared:public\"}}", "");
    try std.testing.expectEqualStrings("403 Forbidden", denied_delete.status);
    const still_present = handleRequest(&write_ctx, "GET", "/v1/agent-memory/runtime.feed.auth?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", still_present.status);
    try std.testing.expect(std.mem.indexOf(u8, still_present.body, "allowed with write scope") != null);

    const allowed_delete = handleRequest(&delete_ctx, "POST", "/v1/memory/apply?store=scratch&runtime_feed=true", "{\"event_type\":\"agent_memory.delete\",\"operation\":\"delete\",\"object_type\":\"agent_memory\",\"origin_instance_id\":\"runtime-feed-auth\",\"origin_sequence\":5,\"actor_id\":\"agent:runtime-feed-auth\",\"payload\":{\"key\":\"runtime.feed.auth\",\"scope\":\"public\",\"owner_id\":\"shared:public\"}}", "");
    try std.testing.expectEqualStrings("200 OK", allowed_delete.status);
    const deleted = handleRequest(&delete_ctx, "GET", "/v1/agent-memory/runtime.feed.auth?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", deleted.status);
}

test "api memory feed apply requires delete rights for agent memory deletes" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
