    const team_a = handleRequest(&ctx, "PUT", "/v1/agent-memory/team.pref", "{\"content\":\"team alpha value v1\",\"scope\":\"team:alpha\"}", raw_a);
    try std.testing.expectEqualStrings("200 OK", team_a.status);
