test "api memory session-search window helpers use checked sizing" {
    const max = std.math.maxInt(usize);

    try std.testing.expectEqual(@as(usize, 1), sessionMessageAroundLimit(0));
    try std.testing.expectEqual(@as(usize, 11), sessionMessageAroundLimit(5));
    try std.testing.expectEqual(max, sessionMessageAroundLimit(max));

    try std.testing.expectEqual(@as(usize, 16), sessionMessageWindowEnd(100, 10, 5));
    try std.testing.expectEqual(@as(usize, 12), sessionMessageWindowEnd(12, 10, 5));
    try std.testing.expectEqual(@as(usize, 50), sessionMessageWindowEnd(50, max, 20));

    try std.testing.expectEqual(@as(usize, 4), sessionMessageIndexAdd(1, 3));
    try std.testing.expectEqual(max, sessionMessageIndexAdd(max - 1, 2));
    try std.testing.expectEqual(@as(usize, 1), sessionMessageOutputId(0));
    try std.testing.expectEqual(max, sessionMessageOutputId(max));
}

