test "api memory search supports offset beyond native hundred result window" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    for (0..105) |i| {
        const key = try std.fmt.allocPrint(alloc, "paged.search.{d}", .{i});
        const content = try std.fmt.allocPrint(alloc, "DeepSearchToken shared memory result {d}", .{i});
        var entry = try store.agentMemoryStore(alloc, .{
            .key = key,
            .content = content,
            .category = "conversation",
            .actor_id = ctx.actor_id,
        });
        agent_memory_runtime.freeAgentMemory(alloc, &entry);
    }

    const compat_page = handleRequest(&ctx, "POST", "/v1/memory/search?offset=100", "{\"query\":\"DeepSearchToken\",\"limit\":1,\"include_content\":false}", "");
    try std.testing.expectEqualStrings("200 OK", compat_page.status);
    var compat_parsed = try std.json.parseFromSlice(std.json.Value, alloc, compat_page.body, .{});
    defer compat_parsed.deinit();
    try std.testing.expectEqual(@as(usize, 1), compat_parsed.value.object.get("entries").?.array.items.len);

    const direct_page = handleRequest(&ctx, "POST", "/v1/agent-memory/search", "{\"query\":\"DeepSearchToken\",\"limit\":1,\"offset\":100,\"include_content\":false}", "");
    try std.testing.expectEqualStrings("200 OK", direct_page.status);
    var direct_parsed = try std.json.parseFromSlice(std.json.Value, alloc, direct_page.body, .{});
    defer direct_parsed.deinit();
    try std.testing.expectEqual(@as(usize, 1), direct_parsed.value.object.get("memories").?.array.items.len);
}

test "api rejects invalid explicit storage selectors" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{ .backend = .memory_lru },
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{ .allocator = arena.allocator(), .store = &store };

    const empty_query = handleRequest(&ctx, "POST", "/v1/memory/search?store=", "{\"query\":\"anything\"}", "");
    try std.testing.expectEqualStrings("400 Bad Request", empty_query.status);
    try std.testing.expect(std.mem.indexOf(u8, empty_query.body, "\"bad_request\"") != null);

    const invalid_array = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"anything\",\"stores\":[\"scratch\",false],\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("400 Bad Request", invalid_array.status);
    try std.testing.expect(std.mem.indexOf(u8, invalid_array.body, "Invalid storage selector") != null);

    const wrong_type = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"anything\",\"store\":false,\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("400 Bad Request", wrong_type.status);

    const body_conflict = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"anything\",\"store\":\"scratch\",\"stores\":[\"scratch\"],\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("400 Bad Request", body_conflict.status);

    const query_conflict = handleRequest(&ctx, "POST", "/v1/memory/search?store=scratch&stores=scratch", "{\"query\":\"anything\"}", "");
    try std.testing.expectEqualStrings("400 Bad Request", query_conflict.status);

    const empty_stores = handleRequest(&ctx, "POST", "/v1/agent-memory", "{\"key\":\"bad.route\",\"content\":\"bad\",\"stores\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", empty_stores.status);
}

test "api memory command surface honors query storage selectors" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{ .backend = .memory_lru },
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const scratch_store = handleRequest(&ctx, "POST", "/v1/memory/store/cmd.route?store=scratch", "{\"content\":\"Command Query Scratch\",\"session\":\"cmd-route\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_store.status);
    const archive_store = handleRequest(&ctx, "POST", "/v1/memory/store?store=archive", "{\"key\":\"cmd.route.archive\",\"content\":\"Command Query Archive\",\"session\":\"cmd-route\"}", "");
    try std.testing.expectEqualStrings("200 OK", archive_store.status);
    const query_wins_update = handleRequest(&ctx, "POST", "/v1/memory/update/cmd.route?store=scratch", "{\"content\":\"Command Query Scratch Updated\",\"session\":\"cmd-route\",\"store\":\"archive\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_wins_update.status);

    const scratch_search = handleRequest(&ctx, "POST", "/v1/memory/search?store=scratch", "{\"query\":\"Command Query\",\"session\":\"cmd-route\",\"limit\":10}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_search.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_search.body, "Command Query Scratch Updated") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_search.body, "Command Query Archive") == null);
    const archive_search = handleRequest(&ctx, "POST", "/v1/memory/search?store=archive", "{\"query\":\"Command Query\",\"session\":\"cmd-route\",\"limit\":10}", "");
    try std.testing.expectEqualStrings("200 OK", archive_search.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_search.body, "Command Query Archive") != null);
    try std.testing.expect(std.mem.indexOf(u8, archive_search.body, "Command Query Scratch") == null);

    const archive_export = handleRequest(&ctx, "POST", "/v1/memory/export-jsonl?store=archive", "{\"session\":\"cmd-route\",\"include_pii\":true}", "");
    try std.testing.expectEqualStrings("200 OK", archive_export.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_export.body, "\"key\":\"cmd.route.archive\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, archive_export.body, "\"key\":\"cmd.route\"") == null);

    const scratch_hygiene = handleRequest(&ctx, "POST", "/v1/memory/hygiene-report?store=scratch", "{\"session\":\"cmd-route\",\"include_memory_atoms\":false}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_hygiene.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_hygiene.body, "\"agent_memory_scanned\":1") != null);

    const scratch_dup_a = handleRequest(&ctx, "POST", "/v1/memory/store/cmd.route.dedupe.a?store=scratch", "{\"content\":\"Command Query Duplicate\",\"session\":\"cmd-route\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_dup_a.status);
    const scratch_dup_b = handleRequest(&ctx, "POST", "/v1/memory/store/cmd.route.dedupe.b?store=scratch", "{\"content\":\"command   query duplicate\",\"session\":\"cmd-route\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_dup_b.status);
    const scratch_hygiene_mutate = handleRequest(&ctx, "POST", "/v1/memory/hygiene?store=scratch", "{\"session\":\"cmd-route\",\"category\":\"conversation\",\"dedupe_agent_memory\":true,\"stale_after_ms\":31536000000,\"archive_after_ms\":31536000000}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_hygiene_mutate.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_hygiene_mutate.body, "\"agent_memory_dedupe_groups\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_hygiene_mutate.body, "\"agent_memory_dedupe_deprecated\":1") != null);
    const scratch_dup_a_get = handleRequest(&ctx, "GET", "/v1/memory/get/cmd.route.dedupe.a?store=scratch&session=cmd-route", "", "");
    const scratch_dup_b_get = handleRequest(&ctx, "GET", "/v1/memory/get/cmd.route.dedupe.b?store=scratch&session=cmd-route", "", "");
    const scratch_dup_a_visible = std.mem.eql(u8, scratch_dup_a_get.status, "200 OK");
    const scratch_dup_b_visible = std.mem.eql(u8, scratch_dup_b_get.status, "200 OK");
    try std.testing.expect(scratch_dup_a_visible != scratch_dup_b_visible);

    const archive_delete = handleRequest(&ctx, "POST", "/v1/memory/delete?store=archive", "{\"key\":\"cmd.route.archive\",\"session\":\"cmd-route\"}", "");
    try std.testing.expectEqualStrings("200 OK", archive_delete.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_delete.body, "\"deleted\":true") != null);
    const archive_after_delete = handleRequest(&ctx, "GET", "/v1/memory/get/cmd.route.archive?store=archive&session=cmd-route", "", "");
    try std.testing.expectEqualStrings("404 Not Found", archive_after_delete.status);
    const scratch_after_delete = handleRequest(&ctx, "GET", "/v1/memory/get/cmd.route?store=scratch&session=cmd-route", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_after_delete.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_after_delete.body, "Command Query Scratch Updated") != null);

    const adapter_scratch = handleRequest(&ctx, "PUT", "/v1/agent/memories/adapter.route?store=scratch", "{\"content\":\"Adapter Query Scratch\"}", "");
    try std.testing.expectEqualStrings("200 OK", adapter_scratch.status);
    const adapter_archive = handleRequest(&ctx, "PUT", "/v1/agent/memories/adapter.route?store=archive", "{\"content\":\"Adapter Query Archive\"}", "");
    try std.testing.expectEqualStrings("200 OK", adapter_archive.status);
    const adapter_scratch_search = handleRequest(&ctx, "POST", "/v1/agent/memories/search?store=scratch", "{\"query\":\"Adapter Query\",\"limit\":10}", "");
    try std.testing.expectEqualStrings("200 OK", adapter_scratch_search.status);
    try std.testing.expect(std.mem.indexOf(u8, adapter_scratch_search.body, "Adapter Query Scratch") != null);
    try std.testing.expect(std.mem.indexOf(u8, adapter_scratch_search.body, "Adapter Query Archive") == null);
    const adapter_archive_search = handleRequest(&ctx, "POST", "/v1/agent/memories/search?store=archive", "{\"query\":\"Adapter Query\",\"limit\":10}", "");
    try std.testing.expectEqualStrings("200 OK", adapter_archive_search.status);
    try std.testing.expect(std.mem.indexOf(u8, adapter_archive_search.body, "Adapter Query Archive") != null);
    try std.testing.expect(std.mem.indexOf(u8, adapter_archive_search.body, "Adapter Query Scratch") == null);
}

