    try std.testing.expect(std.mem.indexOf(u8, jsonl_imported_archive_agent.body, "Snapshot routed agent memory") != null);
    const wrapped_jsonl =
        \\{"jsonl":"{\"schema_version\":\"nullpantry.memory_jsonl.v1\",\"object_type\":\"agent_memory\",\"key\":\"snapshot.routed.wrapper\",\"content\":\"Snapshot routed wrapper memory\",\"category\":\"core\",\"scope\":\"public\",\"owner_id\":\"shared:public\",\"store\":\"scratch\"}"}
