    const wrapped_imported_scratch_agent = handleRequest(&ctx, "GET", "/v1/agent-memory/snapshot.routed.wrapper?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", wrapped_imported_scratch_agent.status);
    const snapshot_archive = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"snapshot routed source body snapshot routed atom body\",\"store\":\"archive\",\"use_vector\":false,\"limit\":10}", "");
    try std.testing.expectEqualStrings("200 OK", snapshot_archive.status);
