test "api analytics export rejects malformed cursor permissions JSON roots before backend use" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:analytics-cursor",
        .actor_scopes_json = "[\"admin\"]",
        .actor_capabilities_json = "[\"read\",\"export\"]",
    };

    const bad_permissions = handleRequest(&ctx, "POST", "/v1/lifecycle/analytics/export", "{\"limit\":10,\"cursor_permissions\":{\"scope\":\"admin\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_permissions.status);
    try std.testing.expect(std.mem.indexOf(u8, bad_permissions.body, "\"invalid_json\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, bad_permissions.body, "Analytics backend is not configured") == null);

    const valid_permissions = handleRequest(&ctx, "POST", "/v1/lifecycle/analytics/export", "{\"limit\":10,\"cursor_permissions\":[\"admin\"]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", valid_permissions.status);
    try std.testing.expect(std.mem.indexOf(u8, valid_permissions.body, "Analytics backend is not configured") != null);
}

