test "api lifecycle full snapshot package verifies manifest and conflict policy" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:snapshot-full",
        .actor_scopes_json = "[\"public\",\"write:public\",\"verify:public\",\"session:*\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"propose\",\"verify\",\"export\"]",
    };

    const seed =
        \\{"objects":[
        \\  {"object_type":"policy_scope","record":{"scope":"public","visibility":"workspace","permissions":[],"owner":"full-snapshot-owner","metadata":{"marker":"full snapshot policy"}}},
        \\  {"object_type":"source","record":{"id":"src_snapshot_full","type":"manual","title":"Full Snapshot Source","content":"full snapshot source evidence","scope":"public","permissions":[]}},
        \\  {"object_type":"memory_atom","record":{"id":"mem_snapshot_full","predicate":"decision","object":"full snapshot","text":"Full snapshot atom survives package hydrate.","status":"verified","scope":"public","permissions":[],"source_ids":["src_snapshot_full"]}},
        \\  {"object_type":"agent_memory","record":{"key":"full_snapshot_pref","content":"full snapshot agent memory survives package hydrate","category":"preference","scope":"public","permissions":[]}}
        \\]}
    ;
    const seeded = handleRequest(&ctx, "POST", "/v1/lifecycle/snapshot/hydrate", seed, "");
    try std.testing.expectEqualStrings("200 OK", seeded.status);

    const exported = handleRequest(&ctx, "POST", "/v1/lifecycle/snapshot/export", "{\"mode\":\"full\",\"scopes\":[\"public\"],\"limit\":25,\"persist\":false}", "");
    try std.testing.expectEqualStrings("200 OK", exported.status);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"schema_version\":\"nullpantry.snapshot.v1\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"mode\":\"full\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"package_checksum\":\"sha256:") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"covered_state\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"unsupported_state\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"object_type\":\"source\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"object_type\":\"memory_atom\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"object_type\":\"agent_memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"storage\":") == null);

    const strict_hydrate = handleRequest(&ctx, "POST", "/v1/lifecycle/snapshot/hydrate?strict_manifest=true", exported.body, "");
    try std.testing.expectEqualStrings("200 OK", strict_hydrate.status);
    try std.testing.expect(std.mem.indexOf(u8, strict_hydrate.body, "\"import_plan\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, strict_hydrate.body, "\"manifest_checksum_supported\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, strict_hydrate.body, "\"reindex_required\":false") != null);

    const conflict = handleRequest(&ctx, "POST", "/v1/lifecycle/snapshot/hydrate?strict_manifest=true&conflict_policy=fail", exported.body, "");
    try std.testing.expectEqualStrings("409 Conflict", conflict.status);
    try std.testing.expect(std.mem.indexOf(u8, conflict.body, "\"error\":\"snapshot_conflict\"") != null);
}

test "api retrieval search fuses keyword and vector results" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const keyword_atom = try store.createMemoryAtom(alloc, .{ .text = "hybrid keyword decision", .scope = "public", .created_by = "human" });
    _ = keyword_atom;
    const vector_atom = try store.createMemoryAtom(alloc, .{ .text = "semantic only pantry payload", .scope = "public", .created_by = "human" });
    const hybrid_query = "hybrid vector context retrieval pipeline";
    const embedding = try vector_mod.deterministicEmbedding(alloc, hybrid_query, 64);
    const embedding_json = try vector_mod.embeddingToJson(alloc, embedding);
    _ = try store.upsertVectorChunk(alloc, .{
        .object_id = vector_atom.id,
        .text = "hybrid vector context",
        .scope = "public",
        .embedding_json = embedding_json,
        .dimensions = 64,
    });

    const resp_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"scopes\":[\"public\"],\"limit\":5}}", .{hybrid_query});
    const resp = handleRequest(&ctx, "POST", "/v1/retrieval/search", resp_body, "");
    try std.testing.expectEqualStrings("200 OK", resp.status);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"strategy\":\"hybrid\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"rollout\":{\"mode\":\"on\",\"decision\":\"enabled\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"vector_allowed\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"vector_served\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"vector_ann\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"rrf\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"citation_assembly\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"llm_rerank\"") == null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"quality_rerank\"") == null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"groups\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, vector_atom.id) != null);

    const off_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"scopes\":[\"public\"],\"limit\":5,\"retrieval_rollout_mode\":\"off\"}}", .{hybrid_query});
    const off = handleRequest(&ctx, "POST", "/v1/retrieval/search", off_body, "");
    try std.testing.expectEqualStrings("200 OK", off.status);
    try std.testing.expect(std.mem.indexOf(u8, off.body, "\"rollout\":{\"mode\":\"off\",\"decision\":\"disabled\"") != null);
