    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };
    const results = [_]domain.SearchResult{
        .{ .id = "mem_1", .result_type = "memory_atom", .title = "Decision", .text = "Decision: cite evidence.", .scope = "public", .status = "verified", .score = 1, .source_ids_json = "[\"src_1\"]" },
        .{ .id = "agent_memory:scratch:agm_1", .result_type = "agent_memory", .title = "Preference", .text = "Agent memory from scratch.", .scope = "agent:agent:a", .status = "active", .score = 1, .source_ids_json = "[]", .store = "scratch" },
        .{ .id = "mem_multi", .result_type = "memory_atom", .title = "Multi", .text = "Decision cites multiple sources.", .scope = "public", .status = "verified", .score = 1, .source_ids_json = "[\"src_multi_a\",\"src_multi_b\"]" },
    };

    try std.testing.expect(try answerCitationsValid(&ctx, "Use the cited decision [src_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "Use the cited decision [mem_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "Use combined evidence [src_1, mem_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "Use routed memory [agent_memory:scratch:agm_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "Use the second visible citation [src_multi_b].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "Evidence:\nUse the cited decision [src_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "## Evidence\nUse the cited decision [src_1].", &results));
    try std.testing.expect(try answerCitationsValid(&ctx, "I don't know based on the accessible evidence.", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use the cited decision.", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use mixed citation syntax [src_1 notes].", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use empty citation syntax [].", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use broken citation syntax [src_1.", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use the cited decision [src_1].\nAlso use an uncited invented fact.", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "- Evidence:\n- Use the cited decision [src_1].\n- Also use an uncited invented fact.", &results));
    try std.testing.expect(!try answerCitationsValid(&ctx, "Use the hidden decision [src_secret].", &results));
}

