test "api jobs reject malformed raw JSON roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();

    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
    };

    const rejected = [_][]const u8{
        "{\"type\":\"memory_reindex\",\"permissions\":{\"scope\":\"admin\"},\"input\":{\"limit\":10}}",
        "{\"type\":\"memory_reindex\",\"permissions\":[],\"input\":[\"limit\"]}",
    };

    for (rejected) |body| {
        const response = handleRequest(&ctx, "POST", "/v1/jobs", body, "");
        try std.testing.expectEqualStrings("400 Bad Request", response.status);
    }

    const jobs_after_rejections = handleRequest(&ctx, "GET", "/v1/jobs?status=queued", "", "");
    try std.testing.expectEqualStrings("200 OK", jobs_after_rejections.status);
    try std.testing.expect(std.mem.indexOf(u8, jobs_after_rejections.body, "\"jobs\":[]") != null);

    const accepted = handleRequest(&ctx, "POST", "/v1/jobs", "{\"type\":\"memory_reindex\",\"permissions\":[],\"input\":{\"limit\":10}}", "");
    try std.testing.expectEqualStrings("200 OK", accepted.status);
    try std.testing.expect(std.mem.indexOf(u8, accepted.body, "\"type\":\"memory_reindex\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, accepted.body, "\"input_redacted\":true") != null);
}

