    const stale_replay = handleRequest(&target_ctx, "POST", "/v1/memory/apply", "{\"origin_instance_id\":\"json-remote\",\"origin_sequence\":6,\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"json.frontier.pref\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"key\":\"json.frontier.pref\",\"content\":\"stale replay\",\"category\":\"core\",\"scope\":\"public\",\"permissions\":[\"public\"]}}", "");
    try std.testing.expectEqualStrings("200 OK", stale_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, stale_replay.body, "\"skipped\":true") != null);
    const stale_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/json.frontier.pref", "", "");
    try std.testing.expectEqualStrings("404 Not Found", stale_get.status);

    const next_replay = handleRequest(&target_ctx, "POST", "/v1/memory/apply", "{\"origin_instance_id\":\"json-remote\",\"origin_sequence\":8,\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"json.frontier.pref\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"key\":\"json.frontier.pref\",\"content\":\"json frontier value\",\"category\":\"core\",\"scope\":\"public\",\"permissions\":[\"public\"]}}", "");
    try std.testing.expectEqualStrings("200 OK", next_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, next_replay.body, "\"skipped\":true") == null);
    const next_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/json.frontier.pref", "", "");
    try std.testing.expectEqualStrings("200 OK", next_get.status);
    try std.testing.expect(std.mem.indexOf(u8, next_get.body, "json frontier value") != null);

    const checkpoint = handleRequest(&target_ctx, "GET", "/v1/memory/checkpoint?limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"frontiers\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"projection\":\"agent_memory:actor:agent:json-frontier\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"origin_instance_id\":\"json-remote\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"origin_sequence\":8") != null);

    var hydrate_ctx = Context{
        .allocator = alloc,
        .store = &hydrate_store,
        .actor_id = "agent:json-frontier",
        .actor_scopes_json = "[\"public\",\"write:public\",\"actor:agent:json-frontier\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };
