    try std.testing.expectEqualStrings("200 OK", hydrate.status);
    try std.testing.expect(std.mem.indexOf(u8, hydrate.body, "\"restored_frontiers\":") != null);
    const hydrated_stale_replay = handleRequest(&hydrate_ctx, "POST", "/v1/memory/apply", "{\"origin_instance_id\":\"json-remote\",\"origin_sequence\":8,\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"json.frontier.pref\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"key\":\"json.frontier.pref\",\"content\":\"hydrated stale replay\",\"category\":\"core\",\"scope\":\"public\",\"permissions\":[\"public\"]}}", "");
    try std.testing.expectEqualStrings("200 OK", hydrated_stale_replay.status);
    try std.testing.expect(std.mem.indexOf(u8, hydrated_stale_replay.body, "\"skipped\":true") != null);
    const hydrated_get = handleRequest(&hydrate_ctx, "GET", "/v1/agent-memory/json.frontier.pref", "", "");
    try std.testing.expectEqualStrings("200 OK", hydrated_get.status);
    try std.testing.expect(std.mem.indexOf(u8, hydrated_get.body, "json frontier value") != null);
    try std.testing.expect(std.mem.indexOf(u8, hydrated_get.body, "hydrated stale replay") == null);

    const forbidden_frontier = handleRequest(&target_ctx, "POST", "/v1/memory/checkpoint", "{\"frontiers\":[{\"projection\":\"agent_memory:actor:agent:other\",\"origin_instance_id\":\"json-remote\",\"origin_sequence\":1}],\"events\":[]}", "");
    try std.testing.expectEqualStrings("403 Forbidden", forbidden_frontier.status);
}

