    try std.testing.expect(std.mem.indexOf(u8, stale_replay.body, "\"skipped\":true") != null);
    const stale_get = handleRequest(&target_ctx, "GET", "/v1/agent-memory/route.frontier.pref?store=scratch&scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", stale_get.status);

    const next_replay = handleRequest(&target_ctx, "POST", "/v1/memory/apply?store=scratch", "{\"origin_instance_id\":\"scratch-remote\",\"origin_sequence\":13,\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"route.frontier.pref\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"key\":\"route.frontier.pref\",\"content\":\"fresh scratch replay\",\"category\":\"core\",\"scope\":\"public\",\"permissions\":[\"public\"]}}", "");
