test "api memory checkpoint origin identity is instance specific" {
    var source_a_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer source_a_store.deinit();
    var source_b_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer source_b_store.deinit();
    var target_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer target_store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var source_a_ctx = Context{ .allocator = alloc, .store = &source_a_store, .actor_id = "agent:origin", .feed_instance_id = "pantry-a" };
    var source_b_ctx = Context{ .allocator = alloc, .store = &source_b_store, .actor_id = "agent:origin", .feed_instance_id = "pantry-b" };
    const put_a = handleRequest(&source_a_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"origin.a\",\"content\":\"from a\"}}", "");
    try std.testing.expectEqualStrings("200 OK", put_a.status);
    const put_b = handleRequest(&source_b_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"origin.b\",\"content\":\"from b\"}}", "");
    try std.testing.expectEqualStrings("200 OK", put_b.status);

    const checkpoint_a = handleRequest(&source_a_ctx, "GET", "/v1/memory/checkpoint?limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint_a.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint_a.body, "\"instance_id\":\"pantry-a\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint_a.body, "\"origin_instance_id\":\"pantry-a\"") != null);
    const checkpoint_b = handleRequest(&source_b_ctx, "GET", "/v1/memory/checkpoint?limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint_b.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint_b.body, "\"instance_id\":\"pantry-b\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint_b.body, "\"origin_instance_id\":\"pantry-b\"") != null);

    var target_ctx = Context{ .allocator = alloc, .store = &target_store, .actor_id = "agent:origin", .feed_instance_id = "pantry-target" };
    const restore_a = handleRequest(&target_ctx, "POST", "/v1/memory/checkpoint", checkpoint_a.body, "");
    try std.testing.expectEqualStrings("200 OK", restore_a.status);
    const restore_b = handleRequest(&target_ctx, "POST", "/v1/memory/checkpoint", checkpoint_b.body, "");
    try std.testing.expectEqualStrings("200 OK", restore_b.status);

    const restored_a = (try testStoreAgentMemoryGetExact(&target_store, alloc, "origin.a", null, "agent:origin")).?;
    try std.testing.expectEqualStrings("from a", restored_a.content);
    const restored_b = (try testStoreAgentMemoryGetExact(&target_store, alloc, "origin.b", null, "agent:origin")).?;
    try std.testing.expectEqualStrings("from b", restored_b.content);
    const events = try target_store.listFeedEvents(alloc, .{ .scopes_json = "[\"admin\"]", .limit = 10 });
    try std.testing.expectEqual(@as(usize, 2), events.len);
    try std.testing.expect(events[0].dedupe_key != null);
    try std.testing.expect(events[1].dedupe_key != null);
    try std.testing.expect(!std.mem.eql(u8, events[0].dedupe_key.?, events[1].dedupe_key.?));
}

test "api memory checkpoint restore does not compact unrelated target feed history" {
    var source_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer source_store.deinit();
    var target_store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer target_store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var source_ctx = Context{ .allocator = alloc, .store = &source_store };
    var target_ctx = Context{ .allocator = alloc, .store = &target_store };

    const source_first = handleRequest(&source_ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory.note\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"nonempty_restore_source_one\",\"scope\":\"public\",\"payload\":{\"text\":\"one\"}}", "");
    try std.testing.expectEqualStrings("200 OK", source_first.status);
    const source_second = handleRequest(&source_ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory.note\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"nonempty_restore_source_two\",\"scope\":\"public\",\"payload\":{\"text\":\"two\"}}", "");
    try std.testing.expectEqualStrings("200 OK", source_second.status);
    const source_compact = handleRequest(&source_ctx, "POST", "/v1/memory/compact", "{\"through_sequence\":1}", "");
    try std.testing.expectEqualStrings("200 OK", source_compact.status);
    const checkpoint = handleRequest(&source_ctx, "GET", "/v1/memory/checkpoint?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint.status);

    const local_event = handleRequest(&target_ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory.note\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"target_local_history\",\"scope\":\"public\",\"payload\":{\"text\":\"local\"}}", "");
    try std.testing.expectEqualStrings("200 OK", local_event.status);

    const restore = handleRequest(&target_ctx, "POST", "/v1/memory/checkpoint", checkpoint.body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    try std.testing.expect(std.mem.indexOf(u8, restore.body, "\"cursor_floor_restored\":false") != null);
    try std.testing.expect(std.mem.indexOf(u8, restore.body, "\"cursor_floor_restore_skipped\":true") != null);

    const status = handleRequest(&target_ctx, "GET", "/v1/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", status.status);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"cursor_floor\":0") != null);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"last_sequence\":3") != null);

    const local_history = handleRequest(&target_ctx, "GET", "/v1/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", local_history.status);
    try std.testing.expect(std.mem.indexOf(u8, local_history.body, "target_local_history") != null);
    try std.testing.expect(std.mem.indexOf(u8, local_history.body, "nonempty_restore_source_one") != null);
}

test "api memory checkpoint restore preserves actors and session deletes" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var admin_ctx = Context{ .allocator = alloc, .store = &store };

    const restore_body =
        \\{"events":[
        \\{"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","actor_id":"agent:restored","dedupe_key":"restore-agent-1","payload":{"key":"restored.pref","content":"restored owner value"}},
        \\{"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","actor_id":"agent:restored","dedupe_key":"restore-agent-pending","object_id":"restored.pending","status":"pending","payload":{"key":"restored.pending","content":"queued value"}}
        \\]}
    ;
    const restore = handleRequest(&admin_ctx, "POST", "/v1/memory/checkpoint", restore_body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    try std.testing.expect(std.mem.indexOf(u8, restore.body, "\"applied_events\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, restore.body, "\"queued_events\":1") != null);

    const restored = (try testStoreAgentMemoryGetExact(&store, alloc, "restored.pref", null, "agent:restored")).?;
    try std.testing.expectEqualStrings("restored owner value", restored.content);
    try std.testing.expect((try testStoreAgentMemoryGetExact(&store, alloc, "restored.pref", null, "local")) == null);

    const retry = handleRequest(&admin_ctx, "POST", "/v1/memory/checkpoint", restore_body, "");
    try std.testing.expectEqualStrings("200 OK", retry.status);
    const conflicting_pending_restore =
        \\{"events":[
        \\{"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","actor_id":"agent:restored","dedupe_key":"restore-agent-pending","object_id":"restored.pending.changed","status":"pending","payload":{"key":"restored.pending","content":"changed queued value"}}
        \\]}
    ;
    const conflicting_pending = handleRequest(&admin_ctx, "POST", "/v1/memory/checkpoint", conflicting_pending_restore, "");
    try std.testing.expectEqualStrings("409 Conflict", conflicting_pending.status);
    const feed_after_conflict = handleRequest(&admin_ctx, "GET", "/v1/memory/events?limit=100", "", "");
    try std.testing.expectEqualStrings("200 OK", feed_after_conflict.status);
    try std.testing.expect(std.mem.indexOf(u8, feed_after_conflict.body, "changed queued value") == null);
    const events = try store.listFeedEvents(alloc, .{ .scopes_json = "[\"admin\"]", .limit = 100 });
    var dedupe_count: usize = 0;
    for (events) |event| {
        if (event.dedupe_key != null and std.mem.eql(u8, event.dedupe_key.?, "restore-agent-1")) dedupe_count += 1;
    }
    try std.testing.expectEqual(@as(usize, 1), dedupe_count);

    var actor_ctx = Context{ .allocator = alloc, .store = &store, .actor_id = "agent:restored", .actor_scopes_json = "[\"session:s1\",\"write:session:s1\",\"delete:session:s1\"]" };
    const session_put = handleRequest(&actor_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"session.pref\",\"content\":\"session value\",\"session_id\":\"s1\"}}", "");
    try std.testing.expectEqualStrings("200 OK", session_put.status);
    const session_delete = handleRequest(&actor_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.delete\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"session.pref\",\"session_id\":\"s1\"}}", "");
    try std.testing.expectEqualStrings("200 OK", session_delete.status);
    try std.testing.expect((try testStoreAgentMemoryGetExact(&store, alloc, "session.pref", "s1", "agent:restored")) == null);

    const lifecycle_put = handleRequest(&admin_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"actor_id\":\"agent:restored\",\"dedupe_key\":\"restore-agent-forget-put\",\"payload\":{\"key\":\"inferred.forget\",\"content\":\"lifecycle value\"}}", "");
    try std.testing.expectEqualStrings("200 OK", lifecycle_put.status);
    const lifecycle_forget = handleRequest(&admin_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.forget\",\"object_type\":\"agent_memory\",\"actor_id\":\"agent:restored\",\"dedupe_key\":\"restore-agent-forget\",\"payload\":{\"key\":\"inferred.forget\"}}", "");
    try std.testing.expectEqualStrings("200 OK", lifecycle_forget.status);
    try std.testing.expect((try testStoreAgentMemoryGetExact(&store, alloc, "inferred.forget", null, "agent:restored")) == null);
    const lifecycle_events = try store.listFeedEvents(alloc, .{ .scopes_json = "[\"admin\"]", .limit = 100 });
    var saw_inferred_forget = false;
    var saw_inferred_delete = false;
    for (lifecycle_events) |event| {
        if (std.mem.eql(u8, event.object_type, "agent_memory") and std.mem.eql(u8, event.object_id, "inferred.forget")) {
            if (std.mem.eql(u8, event.operation, "forget")) saw_inferred_forget = true;
            if (std.mem.eql(u8, event.operation, "delete")) saw_inferred_delete = true;
        }
    }
    try std.testing.expect(saw_inferred_forget);
    try std.testing.expect(!saw_inferred_delete);

    const all_global_put = handleRequest(&actor_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"delete.all.pref\",\"content\":\"global value\"}}", "");
    try std.testing.expectEqualStrings("200 OK", all_global_put.status);
    const all_session_put = handleRequest(&actor_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"delete.all.pref\",\"content\":\"session value\",\"session_id\":\"s1\"}}", "");
    try std.testing.expectEqualStrings("200 OK", all_session_put.status);
