test "api memory checkpoint restore preserves subset routed session state" {
    var source_store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer source_store.deinit();
    var target_store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer target_store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var source_actor = Context{ .allocator = alloc, .store = &source_store, .actor_id = "agent:subset", .actor_scopes_json = "[\"session:route\",\"write:session:route\"]" };
    var source_admin = Context{ .allocator = alloc, .store = &source_store };

    const keep = handleRequest(&source_actor, "POST", "/v1/agent-sessions/route/messages", "{\"role\":\"user\",\"content\":\"Subset routed kept message\",\"created_at_ms\":501,\"stores\":[\"scratch\",\"archive\"]}", "");
    try std.testing.expectEqualStrings("200 OK", keep.status);
    const draft = handleRequest(&source_actor, "POST", "/v1/agent-sessions/route/messages", "{\"role\":\"autosave_user\",\"content\":\"Subset routed draft cleaned\",\"created_at_ms\":502,\"stores\":[\"scratch\",\"archive\"]}", "");
    try std.testing.expectEqualStrings("200 OK", draft.status);
    const usage = handleRequest(&source_actor, "PUT", "/v1/agent-sessions/route/usage", "{\"total_tokens\":61,\"stores\":[\"scratch\",\"archive\"]}", "");
    try std.testing.expectEqualStrings("200 OK", usage.status);
    const cleanup = handleRequest(&source_actor, "DELETE", "/v1/agent-sessions/auto-saved?session_id=route&stores=scratch,archive", "", "");
    try std.testing.expectEqualStrings("200 OK", cleanup.status);

    const checkpoint = handleRequest(&source_admin, "GET", "/v1/memory/checkpoint?limit=100", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"stores\":[\"scratch\",\"archive\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"operation\":\"delete_autosaved\"") != null);

    var target_admin = Context{ .allocator = alloc, .store = &target_store };
    const restore = handleRequest(&target_admin, "POST", "/v1/memory/checkpoint", checkpoint.body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);

    var target_actor = Context{ .allocator = alloc, .store = &target_store, .actor_id = "agent:subset", .actor_scopes_json = "[\"session:route\",\"write:session:route\"]" };
    const scratch_messages = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/messages?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_messages.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_messages.body, "Subset routed kept message") != null);
    try std.testing.expect(std.mem.indexOf(u8, scratch_messages.body, "Subset routed draft cleaned") == null);
    const archive_messages = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/messages?store=archive", "", "");
    try std.testing.expectEqualStrings("200 OK", archive_messages.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_messages.body, "Subset routed kept message") != null);
    try std.testing.expect(std.mem.indexOf(u8, archive_messages.body, "Subset routed draft cleaned") == null);
    const native_messages = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/messages?storage=native", "", "");
    try std.testing.expectEqualStrings("200 OK", native_messages.status);
    try std.testing.expect(std.mem.indexOf(u8, native_messages.body, "Subset routed kept message") == null);
    try std.testing.expect(std.mem.indexOf(u8, native_messages.body, "Subset routed draft cleaned") == null);
    const subset_messages = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/messages?stores=scratch,archive", "", "");
    try std.testing.expectEqualStrings("200 OK", subset_messages.status);
    try std.testing.expectEqual(@as(usize, 1), std.mem.count(u8, subset_messages.body, "Subset routed kept message"));

    const scratch_usage = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/usage?store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_usage.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_usage.body, "\"total_tokens\":61") != null);
    const archive_usage = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/usage?store=archive", "", "");
    try std.testing.expectEqualStrings("200 OK", archive_usage.status);
    try std.testing.expect(std.mem.indexOf(u8, archive_usage.body, "\"total_tokens\":61") != null);
    const native_usage = handleRequest(&target_actor, "GET", "/v1/agent-sessions/route/usage?storage=native", "", "");
    try std.testing.expectEqualStrings("404 Not Found", native_usage.status);
}

test "api memory feed excludes internal runtime command session payloads" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var actor_ctx = Context{ .allocator = alloc, .store = &store, .actor_id = "agent:runtime", .actor_scopes_json = "[\"session:internal\",\"write:session:internal\"]" };
    const internal_save_body = "{\"role\":\"__runtime_command__\",\"content\":\"runtime command must stay local\",\"created_at_ms\":303}";
    const saved = handleRequest(&actor_ctx, "POST", "/v1/agent-sessions/internal/messages", internal_save_body, "");
    try std.testing.expectEqualStrings("200 OK", saved.status);

    const feed = handleRequest(&actor_ctx, "GET", "/v1/memory/events?limit=50", "", "");
    try std.testing.expectEqualStrings("200 OK", feed.status);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "runtime command must stay local") == null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "__runtime_command__") == null);

    const queued = handleRequest(&actor_ctx, "POST", "/v1/memory/feed", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"payload\":{\"session_id\":\"internal\",\"role\":\"__runtime_command__\",\"content\":\"queued leak\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", queued.status);

    const applied = handleRequest(&actor_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_session_message.put\",\"object_type\":\"agent_session_message\",\"payload\":{\"session_id\":\"internal\",\"role\":\"__runtime_command__\",\"content\":\"applied leak\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", applied.status);

    var admin_ctx = Context{ .allocator = alloc, .store = &store };
    const checkpoint =
        \\{"events":[
        \\{"event_type":"agent_session_message.put","operation":"put","object_type":"agent_session_message","actor_id":"agent:runtime","scope":"session:internal","permissions":["actor:agent:runtime"],"payload":{"session_id":"internal","role":"__runtime_command__","content":"checkpoint leak"}}
        \\]}
    ;
    const restore = handleRequest(&admin_ctx, "POST", "/v1/memory/checkpoint", checkpoint, "");
    try std.testing.expectEqualStrings("400 Bad Request", restore.status);
    const messages = handleRequest(&actor_ctx, "GET", "/v1/agent-sessions/internal/messages", "", "");
    try std.testing.expectEqualStrings("200 OK", messages.status);
    try std.testing.expect(std.mem.indexOf(u8, messages.body, "checkpoint leak") == null);
}

test "api memory checkpoint restore preserves primitive ids and links" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var admin_ctx = Context{ .allocator = alloc, .store = &store };

    const restore_body =
        \\{"events":[
        \\{"event_type":"source.put","operation":"put","object_type":"source","object_id":"src_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"src_restore_fixed","type":"transcript","title":"Fixed Restore Source","content":"restore stable source content","scope":"public","permissions":["public"]}},
        \\{"event_type":"space.put","operation":"put","object_type":"space","object_id":"spc_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"spc_restore_fixed","name":"restore-space","title":"Restore Space","description":"restore stable shelf","scope":"public","permissions":["public"],"metadata":{"topic":"restore"}}},
        \\{"event_type":"policy_scope.put","operation":"put","object_type":"policy_scope","object_id":"project:restore","scope":"project:restore","permissions":["project:restore"],"payload":{"scope":"project:restore","visibility":"project","permissions":["project:restore"],"owner":"agent:restore","ttl_ms":1000,"review_after_ms":2000,"metadata":{"topic":"restore policy"}}},
        \\{"event_type":"artifact.put","operation":"put","object_type":"artifact","object_id":"art_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"art_restore_fixed","type":"decision","title":"Fixed Restore Decision","body":"restore stable decision body","status":"proposed","space_id":"spc_restore_fixed","scope":"public","permissions":["public"],"source_ids":["src_restore_fixed"],"fields":{"context":"restore context","decision":"restore stable decision","alternatives":"none","consequences":"stable ids","owner":"NullPantry","review_date":"2026-06-30"}}},
        \\{"event_type":"entity.put","operation":"put","object_type":"entity","object_id":"ent_restore_a","scope":"public","permissions":["public"],"payload":{"id":"ent_restore_a","type":"project","name":"Restore Project","scope":"public","permissions":["public"]}},
        \\{"event_type":"entity.put","operation":"put","object_type":"entity","object_id":"ent_restore_b","scope":"public","permissions":["public"],"payload":{"id":"ent_restore_b","type":"service","name":"Restore Service","scope":"public","permissions":["public"]}},
        \\{"event_type":"relation.put","operation":"put","object_type":"relation","object_id":"rel_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"rel_restore_fixed","from_entity_id":"ent_restore_a","relation_type":"restore_links_to","to_entity_id":"ent_restore_b","scope":"public","permissions":["public"],"source_ids":["src_restore_fixed"]}},
        \\{"event_type":"memory_atom.put","operation":"put","object_type":"memory_atom","object_id":"mem_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"mem_restore_fixed","subject_entity_id":"ent_restore_a","predicate":"states","object":"stable restore","text":"Restore memory atom keeps fixed ids","scope":"public","permissions":["public"],"status":"verified","source_ids":["src_restore_fixed"]}},
        \\{"event_type":"context_pack.put","operation":"put","object_type":"context_pack","object_id":"ctx_restore_fixed","scope":"public","permissions":["public"],"payload":{"id":"ctx_restore_fixed","purpose":"task","target":"agent","query":"restore stable source content","scopes":["public"],"use_vector":false}}
        \\]}
    ;
    const restore = handleRequest(&admin_ctx, "POST", "/v1/memory/checkpoint", restore_body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    try std.testing.expect(std.mem.indexOf(u8, restore.body, "\"applied_events\":9") != null);

    const source = (try store.getSource(alloc, "src_restore_fixed")).?;
    try std.testing.expectEqualStrings("Fixed Restore Source", source.title);
    const space = (try store.getSpace(alloc, "spc_restore_fixed")).?;
    try std.testing.expectEqualStrings("Restore Space", space.title);
    const policy = (try store.getPolicyScope(alloc, "project:restore")).?;
    try std.testing.expectEqualStrings("agent:restore", policy.owner.?);
    const artifact = (try store.getArtifact(alloc, "art_restore_fixed")).?;
    try std.testing.expectEqualStrings("spc_restore_fixed", artifact.space_id.?);
    try std.testing.expect(std.mem.indexOf(u8, artifact.source_ids_json, "src_restore_fixed") != null);
    try std.testing.expect(std.mem.indexOf(u8, artifact.fields_json, "\"decision\":\"restore stable decision\"") != null);
    const entity = (try store.getEntity(alloc, "ent_restore_a")).?;
    try std.testing.expectEqualStrings("Restore Project", entity.name);
    const atom = (try store.getMemoryAtom(alloc, "mem_restore_fixed")).?;
    try std.testing.expectEqualStrings("ent_restore_a", atom.subject_entity_id.?);
    try std.testing.expect(std.mem.indexOf(u8, atom.source_ids_json, "src_restore_fixed") != null);

    const relation_results = try store.search(alloc, .{ .query = "restore_links_to", .scopes_json = "[\"public\"]", .limit = 20, .use_vector = false });
    var saw_relation = false;
    for (relation_results) |result| {
        if (std.mem.eql(u8, result.id, "rel_restore_fixed")) saw_relation = true;
    }
    try std.testing.expect(saw_relation);

    const context_results = try store.search(alloc, .{ .query = "restore stable source content", .scopes_json = "[\"public\"]", .limit = 20, .use_vector = false });
    var saw_context_pack = false;
    for (context_results) |result| {
        if (std.mem.eql(u8, result.id, "ctx_restore_fixed")) saw_context_pack = true;
    }
    try std.testing.expect(saw_context_pack);

    const space_results = try store.search(alloc, .{ .query = "restore stable shelf", .scopes_json = "[\"public\"]", .limit = 20, .use_vector = false });
    var saw_space = false;
    for (space_results) |result| {
        if (std.mem.eql(u8, result.id, "spc_restore_fixed")) saw_space = true;
    }
    try std.testing.expect(saw_space);
}

test "api memory apply covers pantry primitives and lifecycle reducers" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"public\",\"write:public\",\"verify:public\",\"delete:public\"]" };

    const source_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"source.put\",\"object_type\":\"source\",\"scope\":\"public\",\"dedupe_key\":\"primitive-source-1\",\"payload\":{\"title\":\"Primitive source\",\"content\":\"source evidence\"}}", "");
    try std.testing.expectEqualStrings("200 OK", source_apply.status);
    var source_parsed = try std.json.parseFromSlice(std.json.Value, alloc, source_apply.body, .{});
    defer source_parsed.deinit();
    const source_id = json.stringField(source_parsed.value.object, "object_id").?;

    const artifact_body = try std.fmt.allocPrint(alloc, "{{\"event_type\":\"artifact.put\",\"object_type\":\"artifact\",\"scope\":\"public\",\"dedupe_key\":\"primitive-artifact-1\",\"payload\":{{\"type\":\"decision\",\"title\":\"Primitive decision\",\"body\":\"accepted decision body\",\"status\":\"proposed\",\"source_ids\":[\"{s}\"],\"fields\":{{\"context\":\"primitive context\",\"decision\":\"accepted decision body\",\"alternatives\":\"none\",\"consequences\":\"feed coverage\",\"owner\":\"NullPantry\",\"review_date\":\"2026-06-30\"}}}}}}", .{source_id});
    const artifact_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", artifact_body, "");
    try std.testing.expectEqualStrings("200 OK", artifact_apply.status);
    var artifact_parsed = try std.json.parseFromSlice(std.json.Value, alloc, artifact_apply.body, .{});
    defer artifact_parsed.deinit();
    const artifact_id = json.stringField(artifact_parsed.value.object, "object_id").?;
    const artifact_loaded = (try store.getArtifact(alloc, artifact_id)).?;
    try std.testing.expect(std.mem.indexOf(u8, artifact_loaded.fields_json, "\"decision\":\"accepted decision body\"") != null);

    const invalid_artifact = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"artifact.put\",\"object_type\":\"artifact\",\"scope\":\"public\",\"payload\":{\"type\":\"decision\",\"title\":\"Invalid decision\",\"body\":\"missing structured fields\",\"status\":\"proposed\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", invalid_artifact.status);

    const entity_a = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"entity.put\",\"object_type\":\"entity\",\"scope\":\"public\",\"dedupe_key\":\"primitive-entity-a\",\"payload\":{\"type\":\"project\",\"name\":\"NullPantry Feed Entity\"}}", "");
    try std.testing.expectEqualStrings("200 OK", entity_a.status);
    var entity_a_parsed = try std.json.parseFromSlice(std.json.Value, alloc, entity_a.body, .{});
    defer entity_a_parsed.deinit();
    const entity_a_id = json.stringField(entity_a_parsed.value.object, "object_id").?;

    const entity_b = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"entity.put\",\"object_type\":\"entity\",\"scope\":\"public\",\"dedupe_key\":\"primitive-entity-b\",\"payload\":{\"type\":\"service\",\"name\":\"NullClaw Feed Entity\"}}", "");
    try std.testing.expectEqualStrings("200 OK", entity_b.status);
    var entity_b_parsed = try std.json.parseFromSlice(std.json.Value, alloc, entity_b.body, .{});
    defer entity_b_parsed.deinit();
    const entity_b_id = json.stringField(entity_b_parsed.value.object, "object_id").?;

    const relation_body = try std.fmt.allocPrint(alloc, "{{\"event_type\":\"relation.put\",\"object_type\":\"relation\",\"scope\":\"public\",\"dedupe_key\":\"primitive-relation-1\",\"payload\":{{\"from_entity_id\":\"{s}\",\"relation_type\":\"integrates_with\",\"to_entity_id\":\"{s}\",\"source_ids\":[\"{s}\"]}}}}", .{ entity_a_id, entity_b_id, source_id });
    const relation_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", relation_body, "");
    try std.testing.expectEqualStrings("200 OK", relation_apply.status);
    var relation_parsed = try std.json.parseFromSlice(std.json.Value, alloc, relation_apply.body, .{});
    defer relation_parsed.deinit();
    const relation_id = json.stringField(relation_parsed.value.object, "object_id").?;

    const context_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"context_pack.put\",\"object_type\":\"context_pack\",\"scope\":\"public\",\"payload\":{\"query\":\"Primitive decision\",\"scopes\":[\"public\"],\"use_vector\":false}}", "");
    try std.testing.expectEqualStrings("200 OK", context_apply.status);
    try std.testing.expect(std.mem.indexOf(u8, context_apply.body, "\"object_type\":\"context_pack\"") != null);

    const space_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"space.put\",\"object_type\":\"space\",\"scope\":\"public\",\"dedupe_key\":\"primitive-space-1\",\"payload\":{\"id\":\"spc_primitive_space\",\"name\":\"primitive-space\",\"title\":\"Primitive Space\",\"description\":\"Primitive shelf\",\"permissions\":[\"public\"]}}", "");
    try std.testing.expectEqualStrings("200 OK", space_apply.status);
    const applied_space = (try store.getSpace(alloc, "spc_primitive_space")).?;
    try std.testing.expectEqualStrings("Primitive Space", applied_space.title);

    const space_artifact_body = try std.fmt.allocPrint(alloc, "{{\"event_type\":\"artifact.put\",\"object_type\":\"artifact\",\"scope\":\"public\",\"dedupe_key\":\"primitive-space-artifact-1\",\"payload\":{{\"type\":\"decision\",\"title\":\"Primitive shelf decision\",\"body\":\"space-backed decision body\",\"status\":\"proposed\",\"space_id\":\"spc_primitive_space\",\"source_ids\":[\"{s}\"],\"fields\":{{\"context\":\"primitive shelf context\",\"decision\":\"space-backed decision body\",\"alternatives\":\"none\",\"consequences\":\"space ACL enforced\",\"owner\":\"NullPantry\",\"review_date\":\"2026-07-31\"}}}}}}", .{source_id});
    const space_artifact_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", space_artifact_body, "");
    try std.testing.expectEqualStrings("200 OK", space_artifact_apply.status);
    var space_artifact_parsed = try std.json.parseFromSlice(std.json.Value, alloc, space_artifact_apply.body, .{});
    defer space_artifact_parsed.deinit();
    const space_artifact_id = json.stringField(space_artifact_parsed.value.object, "object_id").?;
    const space_artifact = (try store.getArtifact(alloc, space_artifact_id)).?;
    try std.testing.expectEqualStrings("spc_primitive_space", space_artifact.space_id.?);

    const missing_space_artifact = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"artifact.put\",\"object_type\":\"artifact\",\"scope\":\"public\",\"payload\":{\"type\":\"page\",\"title\":\"Missing space artifact\",\"body\":\"should not attach\",\"space_id\":\"spc_missing\"}}", "");
    try std.testing.expectEqualStrings("403 Forbidden", missing_space_artifact.status);

    const policy_apply = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"policy_scope.put\",\"object_type\":\"policy_scope\",\"object_id\":\"public\",\"scope\":\"public\",\"dedupe_key\":\"primitive-policy-1\",\"payload\":{\"scope\":\"public\",\"visibility\":\"workspace\",\"permissions\":[\"public\"],\"owner\":\"agent:primitive\"}}", "");
    try std.testing.expectEqualStrings("200 OK", policy_apply.status);
    const applied_policy = (try store.getPolicyScope(alloc, "public")).?;
    try std.testing.expectEqualStrings("agent:primitive", applied_policy.owner.?);

    const verify_body = try std.fmt.allocPrint(alloc, "{{\"event_type\":\"artifact.verify\",\"operation\":\"verify\",\"object_type\":\"artifact\",\"object_id\":\"{s}\",\"payload\":{{\"status\":\"accepted\"}}}}", .{artifact_id});
    const verify = handleRequest(&ctx, "POST", "/v1/memory/apply", verify_body, "");
    try std.testing.expectEqualStrings("200 OK", verify.status);
    const artifact = (try store.getArtifact(alloc, artifact_id)).?;
    try std.testing.expectEqualStrings("accepted", artifact.status);

    const stale_relation_body = try std.fmt.allocPrint(alloc, "{{\"event_type\":\"relation.mark_stale\",\"operation\":\"mark_stale\",\"object_type\":\"relation\",\"object_id\":\"{s}\",\"scope\":\"public\",\"payload\":{{\"scope\":\"public\"}}}}", .{relation_id});
    const stale_relation = handleRequest(&ctx, "POST", "/v1/memory/apply", stale_relation_body, "");
    try std.testing.expectEqualStrings("200 OK", stale_relation.status);

    const duplicate_source = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"source.put\",\"object_type\":\"source\",\"scope\":\"public\",\"dedupe_key\":\"primitive-source-1\",\"payload\":{\"title\":\"Primitive source\",\"content\":\"source evidence\"}}", "");
    try std.testing.expectEqualStrings("200 OK", duplicate_source.status);
    const conflicting_source = handleRequest(&ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"source.put\",\"object_type\":\"source\",\"scope\":\"public\",\"dedupe_key\":\"primitive-source-1\",\"payload\":{\"title\":\"duplicate source\",\"content\":\"should not create\"}}", "");
    try std.testing.expectEqualStrings("409 Conflict", conflicting_source.status);
    const events = try store.listFeedEvents(alloc, .{ .scopes_json = "[\"admin\"]", .limit = 100 });
    var source_dedupe_count: usize = 0;
    for (events) |event| {
        if (event.dedupe_key != null and std.mem.eql(u8, event.dedupe_key.?, "primitive-source-1")) source_dedupe_count += 1;
    }
    try std.testing.expectEqual(@as(usize, 1), source_dedupe_count);
}

test "api lifecycle builder delegates direct api missing targets" {
