        .actor_scopes_json = "[\"admin\"]",
    };

    const input = try buildAppliedAgentMemoryLifecycleInput(
        &ctx,
        "verify",
        "{\"key\":\"remote.lifecycle.pref\",\"scope\":\"public\",\"storage\":\"runtime\"}",
        null,
        "agent:remote",
