    const scratch_stale = handleRequest(&ctx, "POST", "/v1/memory/apply?store=scratch", "{\"event_type\":\"agent_memory.mark_stale\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"scratch.lifecycle.pref\",\"scope\":\"public\"}}", "");
