test "api lifecycle endpoints reject malformed agent memory permissions JSON roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:lifecycle-permissions",
        .actor_scopes_json = "[\"admin\"]",
    };

    const put = handleRequest(&ctx, "PUT", "/v1/agent-memory/direct.lifecycle.permissions", "{\"content\":\"Direct lifecycle permissions memory\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put.status);

    const bad_permissions = handleRequest(&ctx, "POST", "/v1/verify", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.permissions\",\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_permissions.status);

    const unchanged = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.permissions?scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", unchanged.status);
    try std.testing.expect(std.mem.indexOf(u8, unchanged.body, "\"status\":\"proposed\"") != null);
}

test "api lifecycle endpoints support routed agent memory" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:lifecycle-direct",
        .actor_scopes_json = "[\"admin\"]",
    };

    const native_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/direct.lifecycle.native", "{\"content\":\"Direct native lifecycle memory\",\"scope\":\"public\",\"storage\":\"native\"}", "");
    try std.testing.expectEqualStrings("200 OK", native_put.status);
    const native_stale = handleRequest(&ctx, "POST", "/v1/mark-stale", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.native\",\"scope\":\"public\",\"storage\":\"native\"}", "");
    try std.testing.expectEqualStrings("200 OK", native_stale.status);
    try std.testing.expect(std.mem.indexOf(u8, native_stale.body, "\"object_type\":\"agent_memory\"") != null);
    const stale_direct = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.native?scope=public&storage=native", "", "");
    try std.testing.expectEqualStrings("200 OK", stale_direct.status);
    try std.testing.expect(std.mem.indexOf(u8, stale_direct.body, "\"status\":\"stale\"") != null);

    const native_verify = handleRequest(&ctx, "POST", "/v1/verify", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.native\",\"scope\":\"public\",\"storage\":\"native\"}", "");
    try std.testing.expectEqualStrings("200 OK", native_verify.status);
    const verified_direct = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.native?scope=public&storage=native", "", "");
    try std.testing.expectEqualStrings("200 OK", verified_direct.status);
    try std.testing.expect(std.mem.indexOf(u8, verified_direct.body, "\"status\":\"verified\"") != null);

    const scratch_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/direct.lifecycle.scratch", "{\"content\":\"Direct scratch lifecycle memory\",\"scope\":\"public\",\"store\":\"scratch\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_put.status);
    const scratch_stale = handleRequest(&ctx, "POST", "/v1/mark-stale", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.scratch\",\"scope\":\"public\",\"store\":\"scratch\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_stale.status);
    const scratch_stale_direct = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.scratch?scope=public&store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", scratch_stale_direct.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_stale_direct.body, "\"status\":\"stale\"") != null);

    const scratch_forget = handleRequest(&ctx, "POST", "/v1/forget", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.scratch\",\"scope\":\"public\",\"store\":\"scratch\"}", "");
    try std.testing.expectEqualStrings("200 OK", scratch_forget.status);
    try std.testing.expect(std.mem.indexOf(u8, scratch_forget.body, "\"status\":\"deprecated\"") != null);
    const scratch_after = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.scratch?scope=public&store=scratch", "", "");
    try std.testing.expectEqualStrings("404 Not Found", scratch_after.status);

    const query_scratch_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/direct.lifecycle.query?store=scratch", "{\"content\":\"Direct query scratch lifecycle memory\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_scratch_put.status);
    const query_archive_put = handleRequest(&ctx, "PUT", "/v1/agent-memory/direct.lifecycle.query?store=archive", "{\"content\":\"Direct query archive lifecycle memory\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_archive_put.status);
    const query_scratch_stale = handleRequest(&ctx, "POST", "/v1/mark-stale?store=scratch", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.query\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_scratch_stale.status);
    const query_scratch_after_stale = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", query_scratch_after_stale.status);
    try std.testing.expect(std.mem.indexOf(u8, query_scratch_after_stale.body, "\"status\":\"stale\"") != null);
    const query_archive_after_stale = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=archive", "", "");
    try std.testing.expectEqualStrings("200 OK", query_archive_after_stale.status);
    try std.testing.expect(std.mem.indexOf(u8, query_archive_after_stale.body, "\"status\":\"stale\"") == null);
    const query_authoritative_verify = handleRequest(&ctx, "POST", "/v1/verify?store=archive", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.query\",\"scope\":\"public\",\"store\":\"scratch\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_authoritative_verify.status);
    const query_scratch_after_verify = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=scratch", "", "");
    try std.testing.expectEqualStrings("200 OK", query_scratch_after_verify.status);
    try std.testing.expect(std.mem.indexOf(u8, query_scratch_after_verify.body, "\"status\":\"stale\"") != null);
    const query_archive_after_verify = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=archive", "", "");
    try std.testing.expectEqualStrings("200 OK", query_archive_after_verify.status);
    try std.testing.expect(std.mem.indexOf(u8, query_archive_after_verify.body, "\"status\":\"verified\"") != null);
    const query_supersede = handleRequest(&ctx, "POST", "/v1/supersede?store=scratch", "{\"object_type\":\"agent_memory\",\"key\":\"direct.lifecycle.query\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", query_supersede.status);
    const query_scratch_after_supersede = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=scratch", "", "");
    try std.testing.expectEqualStrings("404 Not Found", query_scratch_after_supersede.status);
    const query_archive_after_supersede = handleRequest(&ctx, "GET", "/v1/agent-memory/direct.lifecycle.query?scope=public&store=archive", "", "");
    try std.testing.expectEqualStrings("200 OK", query_archive_after_supersede.status);

    const events = try store.listFeedEvents(alloc, .{ .scopes_json = "[\"admin\"]", .limit = 100 });
    var saw_mark_stale = false;
    var saw_verify = false;
    var saw_forget = false;
    var saw_query_mark_stale = false;
    var saw_query_verify = false;
    var saw_query_supersede = false;
    for (events) |event| {
        if (!std.mem.eql(u8, event.object_type, "agent_memory")) continue;
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.native") and std.mem.eql(u8, event.operation, "mark_stale")) {
            saw_mark_stale = true;
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"store\":\"native\"") != null);
        }
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.native") and std.mem.eql(u8, event.operation, "verify")) saw_verify = true;
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.scratch") and std.mem.eql(u8, event.operation, "forget")) {
            saw_forget = true;
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"status\":\"deprecated\"") != null);
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"store\":\"scratch\"") != null);
        }
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.query") and std.mem.eql(u8, event.operation, "mark_stale")) {
            saw_query_mark_stale = true;
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"store\":\"scratch\"") != null);
        }
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.query") and std.mem.eql(u8, event.operation, "verify")) {
            saw_query_verify = true;
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"store\":\"archive\"") != null);
        }
        if (std.mem.eql(u8, event.object_id, "direct.lifecycle.query") and std.mem.eql(u8, event.operation, "supersede")) {
            saw_query_supersede = true;
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"status\":\"superseded\"") != null);
            try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"store\":\"scratch\"") != null);
        }
    }
    try std.testing.expect(saw_mark_stale);
    try std.testing.expect(saw_verify);
    try std.testing.expect(saw_forget);
    try std.testing.expect(saw_query_mark_stale);
    try std.testing.expect(saw_query_verify);
    try std.testing.expect(saw_query_supersede);
}

