    try std.testing.expect(std.mem.indexOf(u8, secret_feed.body, "restricted summary") != null);
    try std.testing.expect(std.mem.indexOf(u8, secret_feed.body, secret_source.id) != null);

    const secret_search = handleRequest(&secret_ctx, "POST", "/v1/search", "{\"query\":\"restricted summary\",\"use_vector\":false,\"limit\":20}", "");
    try std.testing.expectEqualStrings("200 OK", secret_search.status);
    try std.testing.expect(std.mem.indexOf(u8, secret_search.body, "restricted summary") != null);
    try std.testing.expect(std.mem.indexOf(u8, secret_search.body, secret_source.id) != null);
}

