test "api memory feed apply rejects internal agent memory payloads" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var admin_ctx = Context{ .allocator = alloc, .store = &store };

    const direct_apply = handleRequest(&admin_ctx, "POST", "/v1/memory/apply", "{\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"actor_id\":\"agent:sync\",\"payload\":{\"key\":\"autosave_user_1\",\"content\":\"internal autosave should not replay\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", direct_apply.status);
    try std.testing.expect(std.mem.indexOf(u8, direct_apply.body, "Internal agent memory") != null);
    try std.testing.expect((try testStoreAgentMemoryGetExact(&store, alloc, "autosave_user_1", null, "agent:sync")) == null);

    const queued_alias = handleRequest(&admin_ctx, "POST", "/v1/memory/events", "{\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"ami_internal_alias\",\"actor_id\":\"agent:sync\",\"payload\":{\"key\":\"autosave_user_2\",\"content\":\"internal queued alias\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", queued_alias.status);
    try std.testing.expect((try testStoreAgentMemoryGetExact(&store, alloc, "autosave_user_2", null, "agent:sync")) == null);

