    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = &store,
        .actor_id = "agent:feed-http",
        .actor_scopes_json = "[\"public\"]",
    };

    _ = try store.createMemoryAtom(setup, .{
        .id = "mem_http_skip",
        .text = "http skip",
        .scope = "public",
        .permissions_json = "[\"public\"]",
        .created_by = "human",
    });
    _ = try store.appendFeedEvent(.{
        .event_type = "memory_atom.put",
        .object_type = "memory_atom",
        .object_id = "mem_http_skip",
        .scope = "public",
        .permissions_json = "[\"public\"]",
        .payload_json = "{\"text\":\"http skip\"}",
        .status = "applied",
    });
    _ = try store.appendFeedEvent(.{
        .event_type = "agent_memory.runtime_put",
        .object_type = "agent_memory",
        .object_id = "ami_http_scratch",
        .scope = "public",
        .permissions_json = "[\"public\"]",
        .payload_json = "{\"store\":\"scratch\",\"key\":\"http.keep\",\"content\":\"http scratch memory\",\"scope\":\"public\"}",
        .status = "applied",
    });

    const response = handleRequest(&ctx, "GET", "/v1/memory/events?store=scratch&limit=10", "", "");
    defer std.testing.allocator.free(response.body);
    try std.testing.expectEqualStrings("200 OK", response.status);
    try std.testing.expect(std.mem.indexOf(u8, response.body, "http scratch memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, response.body, "http skip") == null);

    const native_response = handleRequest(&ctx, "GET", "/v1/memory/events?limit=10", "", "");
    defer std.testing.allocator.free(native_response.body);
    try std.testing.expectEqualStrings("200 OK", native_response.status);
    try std.testing.expect(std.mem.indexOf(u8, native_response.body, "http scratch memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, native_response.body, "http skip") != null);

    const typed_response = handleRequest(&ctx, "GET", "/v1/memory/events?object_type=agent_memory&limit=10", "", "");
    defer std.testing.allocator.free(typed_response.body);
    try std.testing.expectEqualStrings("200 OK", typed_response.status);
    try std.testing.expect(std.mem.indexOf(u8, typed_response.body, "http scratch memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, typed_response.body, "http skip") == null);

    const compat_response = handleRequest(&ctx, "GET", "/v1/memory/events?compat=nullclaw&limit=10", "", "");
    defer std.testing.allocator.free(compat_response.body);
    try std.testing.expectEqualStrings("200 OK", compat_response.status);
    try std.testing.expect(std.mem.indexOf(u8, compat_response.body, "\"key\":\"http.keep\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, compat_response.body, "\"content\":\"http scratch memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, compat_response.body, "http skip") == null);

    const invalid_compat = handleRequest(&ctx, "GET", "/v1/memory/events?compat=nullclaw&object_type=source&limit=10", "", "");
    defer std.testing.allocator.free(invalid_compat.body);
    try std.testing.expectEqualStrings("400 Bad Request", invalid_compat.status);

    const typed_status = handleRequest(&ctx, "GET", "/v1/memory/status?object_type=agent_memory", "", "");
    defer std.testing.allocator.free(typed_status.body);
    try std.testing.expectEqualStrings("200 OK", typed_status.status);
    try std.testing.expect(std.mem.indexOf(u8, typed_status.body, "\"visible_events\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, typed_status.body, "\"applied_events\":1") != null);

    const typed_checkpoint = handleRequest(&ctx, "GET", "/v1/memory/checkpoint?object_type=agent_memory&limit=10", "", "");
    defer std.testing.allocator.free(typed_checkpoint.body);
    try std.testing.expectEqualStrings("200 OK", typed_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, typed_checkpoint.body, "http scratch memory") != null);
    try std.testing.expect(std.mem.indexOf(u8, typed_checkpoint.body, "http skip") == null);
}

