test "api vector endpoints reject malformed raw JSON roots" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const atom = try store.createMemoryAtom(alloc, .{ .text = "vector root contract", .scope = "public", .created_by = "human" });
    var ctx = Context{ .allocator = alloc, .store = &store };

    const bad_permissions = try std.fmt.allocPrint(alloc, "{{\"object_id\":\"{s}\",\"text\":\"bad permissions\",\"scope\":\"public\",\"permissions\":{{\"scope\":\"public\"}},\"embedding\":[1,0],\"dimensions\":2}}", .{atom.id});
    const bad_heading_path = try std.fmt.allocPrint(alloc, "{{\"object_id\":\"{s}\",\"text\":\"bad heading path\",\"scope\":\"public\",\"heading_path\":{{\"h\":\"Intro\"}},\"embedding\":[1,0],\"dimensions\":2}}", .{atom.id});
    const bad_embedding = try std.fmt.allocPrint(alloc, "{{\"object_id\":\"{s}\",\"text\":\"bad embedding\",\"scope\":\"public\",\"heading_path\":[],\"embedding\":{{\"x\":1}},\"dimensions\":2}}", .{atom.id});
    const rejected = [_]struct {
        path: []const u8,
        body: []const u8,
    }{
        .{ .path = "/v1/vector/upsert", .body = bad_permissions },
        .{ .path = "/v1/vector/upsert", .body = bad_heading_path },
        .{ .path = "/v1/vector/upsert", .body = bad_embedding },
        .{ .path = "/v1/vector/search", .body = "{\"embedding\":{\"x\":1},\"scopes\":[\"public\"]}" },
    };

    for (rejected) |case| {
        const response = handleRequest(&ctx, "POST", case.path, case.body, "");
        try std.testing.expectEqualStrings("400 Bad Request", response.status);
    }

    const empty_search = handleRequest(&ctx, "POST", "/v1/vector/search", "{\"embedding\":[1,0],\"scopes\":[\"public\"],\"limit\":5}", "");
    try std.testing.expectEqualStrings("200 OK", empty_search.status);
    try std.testing.expect(std.mem.indexOf(u8, empty_search.body, "\"matches\":[]") != null);

    const accepted_body = try std.fmt.allocPrint(alloc, "{{\"object_id\":\"{s}\",\"text\":\"vector root contract\",\"scope\":\"public\",\"heading_path\":[\"# Vector\"],\"embedding\":[1,0],\"dimensions\":2}}", .{atom.id});
    const accepted = handleRequest(&ctx, "POST", "/v1/vector/upsert", accepted_body, "");
    try std.testing.expectEqualStrings("200 OK", accepted.status);
    try std.testing.expect(std.mem.indexOf(u8, accepted.body, "\"heading_path\":[\"# Vector\"]") != null);

    const matched = handleRequest(&ctx, "POST", "/v1/vector/search", "{\"embedding\":[1,0],\"scopes\":[\"public\"],\"limit\":5}", "");
    try std.testing.expectEqualStrings("200 OK", matched.status);
    try std.testing.expect(std.mem.indexOf(u8, matched.body, "vector root contract") != null);
}

