test "api context pack read preview does not persist without write capability" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var read_ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"public\"]", .actor_capabilities_json = "[\"read\"]" };
    const preview = handleRequest(&read_ctx, "POST", "/v1/context-packs", "{\"task\":\"Ephemeral Pack Unique\",\"scopes\":[\"public\"]}", "");
    try std.testing.expectEqualStrings("200 OK", preview.status);
    try std.testing.expect(std.mem.indexOf(u8, preview.body, "\"persisted\":false") != null);

    const denied = handleRequest(&read_ctx, "POST", "/v1/context-packs", "{\"task\":\"Ephemeral Pack Unique\",\"persist\":true}", "");
    try std.testing.expectEqualStrings("403 Forbidden", denied.status);

    _ = try store.createMemoryAtom(alloc, .{ .text = "Hidden Pack Unique", .scope = "team:secret", .created_by = "human" });
    _ = try store.createContextPack(alloc, .{ .query = "Hidden Pack Unique", .scopes_json = "[\"team:secret\"]", .use_vector = false, .persist = true });

    var write_ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"public\",\"write:public\",\"verify:public\",\"delete:public\"]", .actor_capabilities_json = "[\"read\",\"write\",\"verify\",\"delete\"]" };
    const persisted = handleRequest(&write_ctx, "POST", "/v1/context-packs", "{\"task\":\"Persistent Pack Unique\",\"scopes\":[\"public\"],\"persist\":true}", "");
    try std.testing.expectEqualStrings("200 OK", persisted.status);
    try std.testing.expect(std.mem.indexOf(u8, persisted.body, "\"persisted\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, persisted.body, "\"status\":\"active\"") != null);
    const pack_id = try extractJsonString(alloc, persisted.body, "\"id\":\"");
    const pack_path = try std.fmt.allocPrint(alloc, "/v1/context-packs/{s}", .{pack_id});

    const fetched = handleRequest(&write_ctx, "GET", pack_path, "", "");
    try std.testing.expectEqualStrings("200 OK", fetched.status);
    try std.testing.expect(std.mem.indexOf(u8, fetched.body, "Persistent Pack Unique") != null);
    try std.testing.expect(std.mem.indexOf(u8, fetched.body, "\"status\":\"active\"") != null);

    const listed = handleRequest(&write_ctx, "GET", "/v1/context-packs?scope=public&limit=20", "", "");
    try std.testing.expectEqualStrings("200 OK", listed.status);
    try std.testing.expect(std.mem.indexOf(u8, listed.body, "\"context_packs\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, listed.body, "Persistent Pack Unique") != null);
    try std.testing.expect(std.mem.indexOf(u8, listed.body, "Ephemeral Pack Unique") == null);
    try std.testing.expect(std.mem.indexOf(u8, listed.body, "Hidden Pack Unique") == null);
    var parsed_list = try std.json.parseFromSlice(std.json.Value, alloc, listed.body, .{});
    defer parsed_list.deinit();
    try std.testing.expect(parsed_list.value.object.get("context_packs") != null);

    const bad_pack_lifecycle = handleRequest(&write_ctx, "PATCH", pack_path, "{\"status\":\"stale\",\"payload\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_pack_lifecycle.status);
    const stale = handleRequest(&write_ctx, "PATCH", pack_path, "{\"status\":\"stale\",\"reason\":\"mise review\",\"payload\":{\"reviewed\":true}}", "");
    try std.testing.expectEqualStrings("200 OK", stale.status);
    try std.testing.expect(std.mem.indexOf(u8, stale.body, "\"status\":\"stale\"") != null);
    const lifecycle_feed = handleRequest(&write_ctx, "GET", "/v1/memory/events?limit=100", "", "");
    try std.testing.expectEqualStrings("200 OK", lifecycle_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, lifecycle_feed.body, "\"event_type\":\"context_pack.mark_stale\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, lifecycle_feed.body, "\"payload\":{\"reviewed\":true}") != null);
    try std.testing.expect(std.mem.indexOf(u8, lifecycle_feed.body, pack_id) != null);

    const search_resp = handleRequest(&write_ctx, "POST", "/v1/search", "{\"query\":\"Persistent Pack Unique\",\"scopes\":[\"public\"],\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("200 OK", search_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"type\":\"context_pack\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "Ephemeral Pack Unique") == null);

    const referenced_atom = try store.createMemoryAtom(alloc, .{ .text = "Referenced Pack Atom Unique", .scope = "public", .created_by = "human" });
    const referenced_pack = try store.createContextPack(alloc, .{ .query = "Referenced Pack Atom Unique", .scopes_json = "[\"public\"]", .use_vector = false, .persist = true });
    try std.testing.expect(std.mem.indexOf(u8, referenced_pack.included_memory_atoms_json, referenced_atom.id) != null);
    const listed_with_referenced_pack = handleRequest(&write_ctx, "GET", "/v1/context-packs?scope=public&limit=20", "", "");
    try std.testing.expectEqualStrings("200 OK", listed_with_referenced_pack.status);
    try std.testing.expect(std.mem.indexOf(u8, listed_with_referenced_pack.body, "Referenced Pack Atom Unique") != null);
    try std.testing.expect(try store.patchMemoryAtomStatusActor(referenced_atom.id, "deprecated", false, "agent:test"));
    const listed_after_atom_deprecated = handleRequest(&write_ctx, "GET", "/v1/context-packs?scope=public&limit=20", "", "");
    try std.testing.expectEqualStrings("200 OK", listed_after_atom_deprecated.status);
