    try std.testing.expectEqualStrings("404 Not Found", hidden_session_metadata_from_other_actor.status);
    const hidden_kv_from_other_actor = handleRequest(&other_ctx, "GET", "/v1/agent-memory/brain.last_hygiene_at", "", "");
    try std.testing.expectEqualStrings("404 Not Found", hidden_kv_from_other_actor.status);

    const shared_body = try std.fmt.allocPrint(alloc, "{{\"path\":\"{s}\",\"key_prefix\":\"shared.\",\"scope\":\"public\",\"permissions\":[]}}", .{path});
