    const relations_min_filtered_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"kg:relations:{s}\",\"limit\":20,\"min_score\":0.95}}", .{b.id});
    const relations_min_filtered = handleRequest(&ctx, "POST", "/v1/search", relations_min_filtered_body, "");
