    const secret_entity = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_secret", "{\"content\":\"Needle secret content\",\"category\":\"project\",\"scope\":\"project:secret\",\"permissions\":[\"project:secret\"]}", "");
