test "api kg memory writes reject malformed raw JSON roots" {
    if (!build_options.enable_engine_kg) return error.SkipZigTest;

    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:kg-raw-roots",
        .actor_scopes_json = "[\"public\",\"write:public\",\"verify:public\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"propose\",\"verify\"]",
    };

    const bad_permissions = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_bad_permissions", "{\"content\":\"bad permissions\",\"store\":\"kg\",\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_permissions.status);

    const bad_metadata = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_bad_metadata", "{\"content\":\"bad metadata\",\"store\":\"kg\",\"scope\":\"public\",\"metadata\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_metadata.status);

    const bad_relation_permissions = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:rel:kg_bad_a:links:kg_bad_b", "{\"store\":\"kg\",\"scope\":\"public\",\"permissions\":{\"scope\":\"public\"}}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_relation_permissions.status);

    const missing_entity = handleRequest(&ctx, "GET", "/v1/entities/kg_bad_permissions", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_entity.status);
    const missing_relation = handleRequest(&ctx, "GET", "/v1/relations/kg_bad_a:links:kg_bad_b", "", "");
    try std.testing.expectEqualStrings("404 Not Found", missing_relation.status);

    const accepted = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_shaped", "{\"content\":\"shaped kg memory\",\"store\":\"kg\",\"scope\":\"public\",\"permissions\":[],\"metadata\":{\"source\":\"test\"}}", "");
    try std.testing.expectEqualStrings("200 OK", accepted.status);
    const entity = handleRequest(&ctx, "GET", "/v1/entities/kg_shaped", "", "");
    try std.testing.expectEqualStrings("200 OK", entity.status);
    try std.testing.expect(std.mem.indexOf(u8, entity.body, "\"source\":\"test\"") != null);

    const bad_lifecycle_payload = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_shaped", "{\"operation\":\"verify\",\"scope\":\"public\",\"payload\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_lifecycle_payload.status);

    const bad_lifecycle_causality = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_shaped", "{\"operation\":\"verify\",\"scope\":\"public\",\"causality\":[]}", "");
    try std.testing.expectEqualStrings("400 Bad Request", bad_lifecycle_causality.status);

    const accepted_lifecycle = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:kg_shaped", "{\"operation\":\"verify\",\"scope\":\"public\",\"payload\":{\"reviewed\":true},\"causality\":{\"origin_timestamp_ms\":123}}", "");
    try std.testing.expectEqualStrings("200 OK", accepted_lifecycle.status);
    try std.testing.expect(std.mem.indexOf(u8, accepted_lifecycle.body, "\"status\":\"verified\"") != null);

    const lifecycle_feed = handleRequest(&ctx, "GET", "/v1/memory/events?limit=20", "", "");
    try std.testing.expectEqualStrings("200 OK", lifecycle_feed.status);
    try std.testing.expect(std.mem.indexOf(u8, lifecycle_feed.body, "\"payload\":{\"reviewed\":true}") != null);
    try std.testing.expect(std.mem.indexOf(u8, lifecycle_feed.body, "\"causality\":{\"origin_timestamp_ms\":123}") != null);
}

