test "api kg compat helpers round-trip reserved graph identifiers" {
    if (!build_options.enable_engine_kg) return error.SkipZigTest;

    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var ctx = Context{ .allocator = alloc, .store = &store };
    const alpha_put = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:alpha:1", "{\"content\":\"Alpha reserved content\",\"category\":\"concept\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", alpha_put.status);
    const beta_put = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:entity:beta<2", "{\"content\":\"Beta reserved content\",\"category\":\"concept\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", beta_put.status);

    const relation_key = try kg_compat.relationStoreKey(alloc, "alpha:1", "links:<to>", "beta<2");
    const relation_path_segment = try kg_compat.keyPathSegment(alloc, relation_key);
    const relation_path = try std.fmt.allocPrint(alloc, "/v1/agent/memories/{s}", .{relation_path_segment});
    const relation_put = handleRequest(&ctx, "PUT", relation_path, "{\"store\":\"kg\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", relation_put.status);
    try std.testing.expect(std.mem.indexOf(u8, relation_put.body, relation_key) != null);
    try std.testing.expect(std.mem.indexOf(u8, relation_put.body, "alpha:1 --links:<to>--> beta<2") != null);

    const relation_get_path = try std.fmt.allocPrint(alloc, "/v1/agent/memories/{s}?store=kg", .{relation_path_segment});
    const relation_get = handleRequest(&ctx, "GET", relation_get_path, "", "");
    try std.testing.expectEqualStrings("200 OK", relation_get.status);
    try std.testing.expect(std.mem.indexOf(u8, relation_get.body, "alpha:1 --links:<to>--> beta<2") != null);

    const relations_query = try kg_compat.relationsQuery(alloc, "alpha:1");
    const relations_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"limit\":10}}", .{relations_query});
    const relations_resp = handleRequest(&ctx, "POST", "/v1/agent/memories/search", relations_body, "");
    try std.testing.expectEqualStrings("200 OK", relations_resp.status);
    const graph_relation_id = try std.fmt.allocPrint(alloc, "graph:relation:{s}", .{kg_compat.relationIdForKey(relation_key)});
    try std.testing.expect(std.mem.indexOf(u8, relations_resp.body, graph_relation_id) != null);
    try std.testing.expect(std.mem.indexOf(u8, relations_resp.body, "links:<to>") != null);

    const path_query = try kg_compat.pathQuery(alloc, "alpha:1", "beta<2", 3);
    const path_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"limit\":10}}", .{path_query});
    const path_resp = handleRequest(&ctx, "POST", "/v1/search", path_body, "");
    try std.testing.expectEqualStrings("200 OK", path_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, path_resp.body, "Alpha reserved content") != null);
    try std.testing.expect(std.mem.indexOf(u8, path_resp.body, "Beta reserved content") != null);

    const traverse_query = try kg_compat.traverseQuery(alloc, "alpha:1", 3);
    const traverse_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"limit\":10}}", .{traverse_query});
    const traverse_resp = handleRequest(&ctx, "POST", "/v1/search", traverse_body, "");
    try std.testing.expectEqualStrings("200 OK", traverse_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, traverse_resp.body, "Beta reserved content") != null);
}

test "api kg relation-prefixed keys do not collide with entity ids" {
