    const relation_put = handleRequest(&ctx, "PUT", "/v1/agent/memories/__kg:rel:kg_collision:links:kg_target", "{\"store\":\"kg\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", relation_put.status);

